source:
import type { AiNode, PathConfig } from '@/shared/contracts/ai-paths';
import { validationError } from '@/shared/errors/app-error';
import { upgradeStarterWorkflowPathConfig } from '@/shared/lib/ai-paths/core/starter-workflows';
import { createDefaultPathConfig } from '@/shared/lib/ai-paths/core/utils/factory';
import { stableStringify } from '@/shared/lib/ai-paths/core/utils/runtime';
import { resolvePortablePathInput } from '@/shared/lib/ai-paths/portable-engine';

import { normalizeLoadedPathName, sanitizeTriggerPathConfig } from './trigger-normalization';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

const createStoredPathConfigFallback = (pathId: string): PathConfig => {
  const baseConfig = createDefaultPathConfig(pathId);
  return {
    ...baseConfig,
    nodes: [],
    edges: [],
    parserSamples: {},
    updaterSamples: {},
    runtimeState: { inputs: {}, outputs: {} },
    uiState: {
      selectedNodeId: null,
      configOpen: false,
    },
    lastRunAt: null,
    runCount: 0,
  };
};

const toObjectRecord = (value: unknown): Record<string, unknown> | null =>
  value && typeof value === 'object' && !Array.isArray(value) ? (value as Record<string, unknown>) : null;

const resolveStoredUiStateRecord = (
  parsedConfig: Record<string, unknown> | null
): Record<string, unknown> | null => toObjectRecord(parsedConfig?.['uiState']);

const resolveStoredSelectedNodeIdValue = (
  rawUiState: Record<string, unknown> | null
): string | null => {
  if (!rawUiState) {
    return null;
  }

  const rawSelectedNodeId = rawUiState['selectedNodeId'];
  return typeof rawSelectedNodeId === 'string'
    ? rawSelectedNodeId.trim() || null
    : rawSelectedNodeId === null
      ? null
      : null;
};

const resolveStoredConfigOpenValue = (
  rawUiState: Record<string, unknown> | null
): boolean | undefined => (typeof rawUiState?.['configOpen'] === 'boolean' ? rawUiState['configOpen'] : undefined);

const resolveStoredUiState = (args: {
  parsedConfig: Record<string, unknown> | null;
  resolvedUiState: PathConfig['uiState'] | undefined;
  baseUiState: PathConfig['uiState'];
}): PathConfig['uiState'] => {
  const { parsedConfig, resolvedUiState, baseUiState } = args;
  const fallbackUiState = baseUiState ?? {
    selectedNodeId: null,
    configOpen: false,
  };
  const rawUiState = resolveStoredUiStateRecord(parsedConfig);
  const rawSelectedNodeId = resolveStoredSelectedNodeIdValue(rawUiState);
  const rawConfigOpen = resolveStoredConfigOpenValue(rawUiState);

  return {
    ...(resolvedUiState && typeof resolvedUiState === 'object' ? resolvedUiState : {}),
    selectedNodeId: rawSelectedNodeId ?? fallbackUiState.selectedNodeId ?? null,
    configOpen: rawConfigOpen ?? resolvedUiState?.configOpen ?? fallbackUiState.configOpen ?? false,
  };
};

const hasNodeWithId = (nodes: AiNode[] | undefined, selectedNodeId: string | null | undefined): boolean =>
  Boolean(selectedNodeId && (nodes ?? []).some((node: AiNode): boolean => node.id === selectedNodeId));

const normalizeSelectedNodeIdOverrideValue = (
  value: string | null | undefined,
  nodes: AiNode[] | undefined
): string | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  return hasNodeWithId(nodes, value) ? value : null;
};

const applySelectedNodeIdOverrideForSanitization = (args: {
  config: PathConfig;
  selectedNodeIdOverride?: string | null | undefined;
}): PathConfig => {
  const normalizedSelectedNodeId = normalizeSelectedNodeIdOverrideValue(
    args.selectedNodeIdOverride,
    args.config.nodes,
  );
  if (normalizedSelectedNodeId === undefined) {
    return args.config;
  }

  return {
    ...args.config,
    uiState: {
      ...(toObjectRecord(args.config.uiState) ?? {}),
      selectedNodeId: normalizedSelectedNodeId,
      configOpen:
        typeof args.config.uiState?.configOpen === 'boolean' ? args.config.uiState.configOpen : false,
    },
  };
};

const resolveSelectedNodeIdOverride = (
  parsedConfig: Record<string, unknown> | null
): string | null | undefined => {
  if (!parsedConfig) {
    return undefined;
  }

  return resolveStoredSelectedNodeIdValue(resolveStoredUiStateRecord(parsedConfig));
};

const normalizeResolvedTriggerConfig = (args: {
  pathId: string;
  fallbackName?: string | null | undefined;
  config: PathConfig;
  selectedNodeIdOverride?: string | null | undefined;
}): PathConfig => {
  const selectedNodeIdOverride =
    args.selectedNodeIdOverride === undefined
      ? undefined
      : typeof args.selectedNodeIdOverride === 'string'
        ? args.selectedNodeIdOverride.trim() || null
        : null;
  const preSanitizedConfig = applySelectedNodeIdOverrideForSanitization({
    config: args.config,
    selectedNodeIdOverride,
  });
  const resolvedConfig = resolvePortablePathInput(preSanitizedConfig, {
    includeConnections: false,
    signingPolicyTelemetrySurface: 'product',
    nodeCodeObjectHashVerificationMode: 'warn',
  });
  const candidateConfig = resolvedConfig.ok ? resolvedConfig.value.pathConfig : preSanitizedConfig;
  const normalizedConfig = sanitizeTriggerPathConfig(candidateConfig);
  const normalizedId = typeof normalizedConfig.id === 'string' ? normalizedConfig.id.trim() : '';
  if (!normalizedId || normalizedId !== args.pathId) {
    throw validationError('AI Path config id does not match index entry.', {
      source: 'ai_paths.trigger_payload',
      reason: 'config_id_mismatch',
      expectedPathId: args.pathId,
      actualPathId: normalizedId || null,
    });
  }

  const normalizedName =
    normalizeLoadedPathName(args.pathId, normalizedConfig.name) ||
    normalizeLoadedPathName(args.pathId, args.fallbackName);
  if (!normalizedName) {
    throw validationError('AI Path config name is required.', {
      source: 'ai_paths.trigger_payload',
      reason: 'missing_path_name',
      pathId: args.pathId,
    });
  }

  const normalizedSelectedNodeId = normalizeSelectedNodeIdOverrideValue(
    selectedNodeIdOverride,
    normalizedConfig.nodes,
  );

  return {
    ...normalizedConfig,
    id: args.pathId,
    name: normalizedName,
    ...(normalizedSelectedNodeId === undefined
      ? {}
      : {
          uiState: {
            ...(normalizedConfig.uiState && typeof normalizedConfig.uiState === 'object'
              ? normalizedConfig.uiState
              : {}),
            selectedNodeId: normalizedSelectedNodeId,
            configOpen: normalizedConfig.uiState?.configOpen ?? false,
          },
        }),
  };
};

const didStoredTriggerConfigPersistedValueChange = (
  rawParsedConfig: PathConfig | null,
  normalizedConfig: PathConfig
): boolean => {
  if (!rawParsedConfig) {
    return true;
  }

  return stableStringify(rawParsedConfig) !== stableStringify(normalizedConfig);
};

export const materializeStoredTriggerPathConfig = (args: {
  pathId: string;
  rawConfig: string;
  fallbackName?: string | null | undefined;
  applyStarterWorkflowUpgrade?: boolean | undefined;
}): {
  config: PathConfig;
  changed: boolean;
} => {
  const { pathId, rawConfig, fallbackName } = args;
  try {
    let parsedConfig: unknown;
    try {
      parsedConfig = JSON.parse(rawConfig) as unknown;
    } catch (error) {
      logClientError(error);
      throw validationError('Invalid AI Path config payload.', {
        source: 'ai_paths.trigger_payload',
        reason: 'config_invalid_json',
        pathId,
        cause: error instanceof Error ? error.message : 'unknown_error',
      });
    }

    const rawParsedConfig =
      parsedConfig && typeof parsedConfig === 'object' && !Array.isArray(parsedConfig)
        ? (parsedConfig as PathConfig)
        : null;
    const rawStarterUpgrade =
      rawParsedConfig && args.applyStarterWorkflowUpgrade !== false
        ? upgradeStarterWorkflowPathConfig(rawParsedConfig)
        : null;
    const configForResolution = rawStarterUpgrade?.config ?? parsedConfig;

    const resolvedConfig = resolvePortablePathInput(configForResolution, {
      includeConnections: false,
      signingPolicyTelemetrySurface: 'product',
      nodeCodeObjectHashVerificationMode: 'warn',
    });
    const resolvedConfigError = resolvedConfig.ok ? null : resolvedConfig.error;
    const baseConfig = createStoredPathConfigFallback(pathId);
    const mergedConfig =
      resolvedConfig.ok
        ? ({
            ...resolvedConfig.value.pathConfig,
            uiState: resolveStoredUiState({
              parsedConfig: rawParsedConfig ? (rawParsedConfig as Record<string, unknown>) : null,
              resolvedUiState: resolvedConfig.value.pathConfig.uiState,
              baseUiState: baseConfig.uiState,
            }),
            ...(
              parsedConfig &&
              typeof parsedConfig === 'object' &&
              !Array.isArray(parsedConfig) &&
              (parsedConfig as { extensions?: unknown }).extensions &&
              typeof (parsedConfig as { extensions?: unknown }).extensions === 'object' &&
              !Array.isArray((parsedConfig as { extensions?: unknown }).extensions)
                ? {
                    extensions: {
                      ...((parsedConfig as { extensions: Record<string, unknown> }).extensions ?? {}),
                      ...(
                        resolvedConfig.value.pathConfig.extensions &&
                        typeof resolvedConfig.value.pathConfig.extensions === 'object' &&
                        !Array.isArray(resolvedConfig.value.pathConfig.extensions)
                          ? resolvedConfig.value.pathConfig.extensions
                          : {}
                      ),
                    },
                  }
                : {}
            ),
          } as PathConfig)
        : parsedConfig && typeof parsedConfig === 'object' && !Array.isArray(parsedConfig)
          ? ({
              ...baseConfig,
              ...(configForResolution as Partial<PathConfig>),
              id:
                typeof (configForResolution as { id?: unknown }).id === 'string'
                  ? ((configForResolution as { id: string }).id.trim() || pathId)
                  : pathId,
              name:
                typeof (configForResolution as { name?: unknown }).name === 'string'
                  ? (configForResolution as { name: string }).name
                  : baseConfig.name,
            } as PathConfig)
          : null;

    if (!mergedConfig) {
      throw validationError('Invalid AI Path config payload.', {
        source: 'ai_paths.trigger_payload',
        reason: 'config_invalid_payload',
        pathId,
        cause: resolvedConfigError,
      });
    }

    const normalizedConfig = normalizeResolvedTriggerConfig({
      pathId,
      fallbackName,
      config: mergedConfig,
      selectedNodeIdOverride: resolveSelectedNodeIdOverride(rawParsedConfig as Record<string, unknown> | null),
    });

    return {
      config: normalizedConfig,
      changed: didStoredTriggerConfigPersistedValueChange(rawParsedConfig, normalizedConfig),
    };
  } catch (error) {
    logClientError(error);
    throw error;
  }
};

import {
  aiNodeSchema,
  edgeSchema,
  type AiNode,
  type Edge,
  type PathConfig,
  type PathMeta,
} from '@/shared/contracts/ai-paths';
import { validationError } from '@/shared/errors/app-error';

import { palette } from '../definitions';
import { backfillPathConfigNodeContracts } from './normalization.helpers';
import { normalizeNodes } from './normalization.nodes';
import {
  AI_PATHS_HISTORY_RETENTION_DEFAULT,
  AI_PATHS_HISTORY_RETENTION_KEY,
  AI_PATHS_HISTORY_RETENTION_MAX,
  AI_PATHS_HISTORY_RETENTION_MIN,
} from '../constants';
import { findPathConfigCollectionAliasIssues } from '../utils/collection-names';
import { sanitizeEdges } from '../utils/graph.edges';
import {
  findRemovedLegacyTriggerContextModesInPathConfig,
  formatRemovedLegacyTriggerContextModesMessage,
} from '../utils/legacy-trigger-context-mode';
import { validateCanonicalPathNodeIdentities } from '../utils/node-identity';
import { normalizeAiPathFolderPath } from '../utils/path-folders';
import { stableStringify } from '../utils/runtime';

export const normalizeLoadedPathName = (_pathId: string, name: unknown): string => {
  return typeof name === 'string' ? name.trim() : '';
};

export const normalizeLoadedPathMetas = (metas: PathMeta[]): PathMeta[] => {
  const byId = new Map<string, PathMeta>();
  metas.forEach((meta: PathMeta) => {
    const id = typeof meta.id === 'string' ? meta.id.trim() : '';
    if (!id) return;
    const normalizedName = normalizeLoadedPathName(id, meta.name) || `Path ${id.slice(0, 6)}`;
    const fallbackTimestamp = new Date().toISOString();
    const normalizedCreatedAt =
      typeof meta.createdAt === 'string' && meta.createdAt.trim().length > 0
        ? meta.createdAt
        : fallbackTimestamp;
    const normalizedUpdatedAt =
      typeof meta.updatedAt === 'string' && meta.updatedAt.trim().length > 0
        ? meta.updatedAt
        : normalizedCreatedAt;
    const normalizedMeta: PathMeta = {
      ...meta,
      id,
      name: normalizedName,
      folderPath: normalizeAiPathFolderPath(meta.folderPath),
      createdAt: normalizedCreatedAt,
      updatedAt: normalizedUpdatedAt,
    };
    const existing = byId.get(id);
    if (!existing) {
      byId.set(id, normalizedMeta);
      return;
    }
    const existingUpdatedAt = Date.parse(existing.updatedAt || '') || 0;
    const nextUpdatedAt = Date.parse(normalizedMeta.updatedAt || '') || 0;
    if (nextUpdatedAt >= existingUpdatedAt) {
      byId.set(id, normalizedMeta);
    }
  });
  return Array.from(byId.values()).sort((a: PathMeta, b: PathMeta): number =>
    b.updatedAt.localeCompare(a.updatedAt)
  );
};

export const normalizeHistoryRetentionPasses = (value: unknown): number => {
  const parsed =
    typeof value === 'number' ? value : Number.parseInt(typeof value === 'string' ? value : '', 10);
  if (!Number.isFinite(parsed) || parsed < AI_PATHS_HISTORY_RETENTION_MIN) {
    return AI_PATHS_HISTORY_RETENTION_DEFAULT;
  }
  return Math.min(
    AI_PATHS_HISTORY_RETENTION_MAX,
    Math.max(AI_PATHS_HISTORY_RETENTION_MIN, Math.trunc(parsed))
  );
};

export const resolveHistoryRetentionPasses = (
  settingsData: Array<{ key: string; value: string }>
): number => {
  const raw = settingsData.find(
    (item: { key: string; value: string }) => item.key === AI_PATHS_HISTORY_RETENTION_KEY
  )?.value;
  return normalizeHistoryRetentionPasses(raw);
};

const assertNoUnsupportedTriggerDatabaseConfig = (node: AiNode): void => {
  if (node.type !== 'database' || !node.config || typeof node.config !== 'object') return;
  const configRecord = node.config as Record<string, unknown>;
  const databaseConfig =
    configRecord['database'] && typeof configRecord['database'] === 'object'
      ? (configRecord['database'] as Record<string, unknown>)
      : null;
  if (!databaseConfig) return;

  if (Object.prototype.hasOwnProperty.call(databaseConfig, 'schemaSnapshot')) {
    throw validationError('AI Path trigger payload contains unsupported database schemaSnapshot.', {
      source: 'ai_paths.trigger_payload',
      reason: 'unsupported_database_schema_snapshot',
      nodeId: node.id,
    });
  }

  const queryConfig =
    databaseConfig['query'] && typeof databaseConfig['query'] === 'object'
      ? (databaseConfig['query'] as Record<string, unknown>)
      : null;
  if (queryConfig?.['provider'] === 'all') {
    throw validationError(
      'AI Path trigger payload contains unsupported database query provider "all".',
      {
        source: 'ai_paths.trigger_payload',
        reason: 'unsupported_database_query_provider',
        nodeId: node.id,
        provider: queryConfig['provider'],
      }
    );
  }

  const parameterInferenceGuard =
    databaseConfig['parameterInferenceGuard'] &&
    typeof databaseConfig['parameterInferenceGuard'] === 'object' &&
    !Array.isArray(databaseConfig['parameterInferenceGuard'])
      ? (databaseConfig['parameterInferenceGuard'] as Record<string, unknown>)
      : null;
  if (parameterInferenceGuard) {
    const targetPath =
      typeof parameterInferenceGuard['targetPath'] === 'string'
        ? parameterInferenceGuard['targetPath'].trim()
        : '';
    if (targetPath.length > 0 && targetPath !== 'parameters') {
      throw validationError(
        'AI Path config contains unsupported parameter inference target path.',
        {
          source: 'ai_paths.trigger_payload',
          reason: 'unsupported_parameter_inference_target_path',
          nodeId: node.id,
          targetPath,
        }
      );
    }
  }

  const localizedParameterMerge =
    databaseConfig['localizedParameterMerge'] &&
    typeof databaseConfig['localizedParameterMerge'] === 'object' &&
    !Array.isArray(databaseConfig['localizedParameterMerge'])
      ? (databaseConfig['localizedParameterMerge'] as Record<string, unknown>)
      : null;
  if (localizedParameterMerge) {
    const targetPath =
      typeof localizedParameterMerge['targetPath'] === 'string'
        ? localizedParameterMerge['targetPath'].trim()
        : '';
    if (targetPath.length > 0 && targetPath !== 'parameters') {
      throw validationError(
        'AI Path config contains unsupported localized parameter merge target path.',
        {
          source: 'ai_paths.trigger_payload',
          reason: 'unsupported_localized_parameter_merge_target_path',
          nodeId: node.id,
          targetPath,
        }
      );
    }
  }
};

const UNSUPPORTED_TRIGGER_DATA_PORTS = new Set(['context', 'meta', 'entityId', 'entityType']);

const resolveEdgeSourceNodeId = (edge: Record<string, unknown>): string => {
  const from = typeof edge['from'] === 'string' ? edge['from'].trim() : '';
  return from;
};

const resolveEdgeSourcePort = (edge: Record<string, unknown>): string => {
  const fromPort = typeof edge['fromPort'] === 'string' ? edge['fromPort'].trim() : '';
  return fromPort;
};

const assertNoUnsupportedTriggerDataGraph = (nodes: AiNode[], edges: Edge[]): void => {
  const nodeById = new Map<string, AiNode>(
    nodes.map((node: AiNode): [string, AiNode] => [node.id, node])
  );

  nodes.forEach((node: AiNode): void => {
    if (node.type !== 'trigger') return;
    const outputs = Array.isArray(node.outputs) ? node.outputs : [];
    const unsupportedPorts = outputs.filter((port: string): boolean =>
      UNSUPPORTED_TRIGGER_DATA_PORTS.has(port)
    );
    if (unsupportedPorts.length === 0) return;
    throw validationError('AI Path config contains unsupported trigger output ports.', {
      source: 'ai_paths.trigger_payload',
      reason: 'unsupported_trigger_outputs',
      nodeId: node.id,
      outputs: unsupportedPorts,
    });
  });

  edges.forEach((edge: Edge, index: number): void => {
    const sourceNodeId = resolveEdgeSourceNodeId(edge as Record<string, unknown>);
    const sourcePort = resolveEdgeSourcePort(edge as Record<string, unknown>);
    if (!sourceNodeId || !sourcePort) return;
    const sourceNode = nodeById.get(sourceNodeId);
    if (sourceNode?.type !== 'trigger') return;
    if (!UNSUPPORTED_TRIGGER_DATA_PORTS.has(sourcePort)) return;
    throw validationError('AI Path config contains unsupported trigger data edges.', {
      source: 'ai_paths.trigger_payload',
      reason: 'unsupported_trigger_data_edge',
      edgeIndex: index,
      edgeId: typeof edge.id === 'string' ? edge.id : null,
      sourceNodeId,
      sourcePort,
    });
  });
};

export const sanitizeTriggerPathConfig = (config: PathConfig): PathConfig => {
  const removedTriggerContextModes = findRemovedLegacyTriggerContextModesInPathConfig(config);
  if (removedTriggerContextModes.length > 0) {
    throw validationError(
      formatRemovedLegacyTriggerContextModesMessage(removedTriggerContextModes, {
        surface: 'trigger payload',
      }),
      {
        source: 'ai_paths.trigger_payload',
        reason: 'removed_trigger_context_mode',
        pathId: config.id,
        removedModes: removedTriggerContextModes,
      }
    );
  }

  const collectionAliasIssues = findPathConfigCollectionAliasIssues(config);
  if (collectionAliasIssues.length > 0) {
    throw validationError('AI Path config contains unsupported collection aliases.', {
      source: 'ai_paths.trigger_payload',
      reason: 'unsupported_collection_aliases',
      pathId: config.id,
      issues: collectionAliasIssues,
    });
  }

  const contractBackfilledConfig = backfillPathConfigNodeContracts(config).config;
  const graphNodes = (
    Array.isArray(contractBackfilledConfig.nodes) ? contractBackfilledConfig.nodes : []
  ).map((node: AiNode, index: number): AiNode => {
    assertNoUnsupportedTriggerDatabaseConfig(node);
    const parsedNode = aiNodeSchema.safeParse(node);
    if (!parsedNode.success) {
      throw validationError('Invalid AI Path trigger node payload.', {
        source: 'ai_paths.trigger_payload',
        reason: 'invalid_node',
        index,
        issues: parsedNode.error.flatten(),
      });
    }
    return parsedNode.data;
  });

  const parsedEdges = (
    Array.isArray(contractBackfilledConfig.edges) ? contractBackfilledConfig.edges : []
  ).map((edge: unknown, index: number) => {
    const parsedEdge = edgeSchema.safeParse(edge);
    if (!parsedEdge.success) {
      throw validationError('Invalid AI Path trigger edge payload.', {
        source: 'ai_paths.trigger_payload',
        reason: 'invalid_edge',
        index,
        issues: parsedEdge.error.flatten(),
      });
    }
    return parsedEdge.data;
  });

  const normalizedGraphNodes = normalizeNodes(graphNodes);
  assertNoUnsupportedTriggerDataGraph(normalizedGraphNodes, parsedEdges);
  const identityIssues = validateCanonicalPathNodeIdentities(
    {
      ...contractBackfilledConfig,
      nodes: normalizedGraphNodes,
    },
    { palette }
  );
  if (identityIssues.length > 0) {
    throw validationError('AI Path config contains unsupported node identities.', {
      source: 'ai_paths.trigger_payload',
      reason: 'unsupported_node_identities',
      pathId: config.id,
      issues: identityIssues,
    });
  }
  const graphEdges = sanitizeEdges(normalizedGraphNodes, parsedEdges);
  if (stableStringify(graphEdges) !== stableStringify(parsedEdges)) {
    throw validationError('AI Path config contains invalid or non-canonical edges.', {
      source: 'ai_paths.trigger_payload',
      reason: 'invalid_edges',
      pathId: config.id,
    });
  }

  return {
    ...contractBackfilledConfig,
    nodes: normalizedGraphNodes,
    edges: graphEdges,
  };
};

import type { PlaywrightCaptureRoute } from '@/shared/contracts/playwright';

const DEFAULT_WAIT_FOR_SELECTOR_MS = 15_000;
const DEFAULT_NAVIGATION_TIMEOUT_MS = 45_000;
const DEFAULT_CAPTURE_RETRY_DELAY_MS = 1_000;
const DEFAULT_CAPTURE_MAX_ATTEMPTS = 2;

export const PLAYWRIGHT_CAPTURE_TIMEOUT_MS = 240_000;

export const PLAYWRIGHT_DEFAULT_CAPTURE_SCRIPT = `
export default async function run({ page, input, artifacts, helpers, emit, log }) {
  const captures = Array.isArray(input.captures) ? input.captures : [];
  const navigationTimeoutMs = ${DEFAULT_NAVIGATION_TIMEOUT_MS};
  const retryDelayMs = ${DEFAULT_CAPTURE_RETRY_DELAY_MS};
  const maxCaptureAttempts = ${DEFAULT_CAPTURE_MAX_ATTEMPTS};
  const expectedAppearanceMode =
    typeof input.appearanceMode === 'string' ? input.appearanceMode.trim() : '';
  const expectedAppearanceSelector = expectedAppearanceMode
    ? 'html[data-kangur-appearance-mode="' + expectedAppearanceMode + '"], ' +
      'body[data-kangur-appearance-mode="' + expectedAppearanceMode + '"], ' +
      '#app-content[data-kangur-appearance-mode="' + expectedAppearanceMode + '"]'
    : '';
  const results = [];
  let successCount = 0;
  let failureCount = 0;
  const totalCount = captures.length;
  const describeError = (error) => {
    if (error instanceof Error && typeof error.message === 'string' && error.message.trim()) {
      return error.message.trim();
    }
    if (typeof error === 'string' && error.trim()) {
      return error.trim();
    }
    if (error && typeof error === 'object') {
      const maybeName =
        typeof error.name === 'string' && error.name.trim() ? error.name.trim() : '';
      const maybeMessage =
        typeof error.message === 'string' && error.message.trim() ? error.message.trim() : '';
      if (maybeName || maybeMessage) {
        return [maybeName, maybeMessage].filter(Boolean).join(': ');
      }
      try {
        const serialized = JSON.stringify(error);
        if (typeof serialized === 'string' && serialized.length > 2) {
          return serialized;
        }
      } catch {}
    }
    return 'capture_failed';
  };

  const describeWaitReason = (reason) => {
    switch (reason) {
      case 'route_shell':
        return 'Waiting for Kangur route shell.';
      case 'transition_skeleton':
        return 'Waiting for transition skeleton to finish.';
      case 'transition_phase':
        return 'Waiting for route transition to become idle.';
      case 'route_content':
        return 'Waiting for route content to mount.';
      case 'capture_ready':
        return 'Waiting for route capture-ready flag.';
      case 'appearance_mode':
        return 'Waiting for expected appearance mode.';
      default:
        return 'Waiting for page readiness.';
    }
  };

  const emitProgress = (payload = {}) => {
    const processedCount = successCount + failureCount;
    emit('capture_progress', {
      processedCount,
      completedCount: successCount,
      failureCount,
      remainingCount: Math.max(totalCount - processedCount, 0),
      totalCount,
      ...payload,
    });
  };

  const buildCaptureResult = ({
    id,
    title,
    status,
    reason = null,
    resolvedUrl = null,
    attemptCount = null,
    stage = null,
    durationMs = 0,
  }) => ({
    id,
    title,
    status,
    reason,
    resolvedUrl,
    attemptCount,
    durationMs: Math.max(Math.floor(durationMs), 0),
    stage,
  });

  for (let index = 0; index < captures.length; index += 1) {
    const capture = captures[index] || {};
    const id = typeof capture.id === 'string' ? capture.id : \`capture-\${index + 1}\`;
    const title =
      typeof capture.title === 'string' && capture.title.trim().length > 0
        ? capture.title.trim()
        : id;
    const url = typeof capture.url === 'string' ? capture.url : '';
    const selector = typeof capture.selector === 'string' ? capture.selector.trim() : '';
    const selectorRole =
      typeof capture.selectorRole === 'string' ? capture.selectorRole.trim() : '';
    const waitForMs = Number.isFinite(capture.waitForMs) ? Number(capture.waitForMs) : 2000;
    const waitForSelectorMs = Number.isFinite(capture.waitForSelectorMs)
      ? Number(capture.waitForSelectorMs)
      : 15000;
    const captureStartedAt = Date.now();
    let captureStage = 'starting';
    let resolvedUrl = url || null;
    let usedFallbackCapture = false;

    emitProgress({
      currentCaptureId: id,
      currentCaptureTitle: title,
      currentCaptureStatus: 'starting',
      message: \`[\${id}] Opening \${title}.\`,
    });

    if (!url) {
      failureCount += 1;
      captureStage = 'validation';
      results.push(
        buildCaptureResult({
          id,
          title,
          status: 'skipped',
          reason: 'missing_url',
          resolvedUrl: null,
          durationMs: Date.now() - captureStartedAt,
          stage: captureStage,
        })
      );
      emitProgress({
        currentCaptureId: id,
        currentCaptureTitle: title,
        currentCaptureStatus: 'failed',
        lastCaptureId: id,
        lastCaptureStatus: 'skipped',
        message: \`[\${id}] Skipped because the capture URL is missing.\`,
      });
      continue;
    }

    let captureCompleted = false;
    for (let attempt = 1; attempt <= maxCaptureAttempts; attempt += 1) {
      try {
        captureStage = 'navigating';
        log(
          \`[\${id}] Attempt \${attempt}/\${maxCaptureAttempts}: navigating to \${url}\${
            selectorRole ? \` (selector role: \${selectorRole})\` : ''
          }\`
        );
        await page.goto(url, { waitUntil: 'load', timeout: navigationTimeoutMs });
        resolvedUrl = page.url() || url;
        log(\`[\${id}] Load event fired — current URL: \${page.url()}\`);

        {
          captureStage = 'waiting_for_page_ready';
          const pollDeadline = Date.now() + waitForSelectorMs;
          let pageReady = false;
          let lastWaitReason = '';
          let lastWaitProgressAt = 0;
          log(\`[\${id}] Polling for page readiness (shell + no skeleton + transition idle + capture ready)\`);
          while (Date.now() < pollDeadline) {
            let waitReason = '';
            const hasShell = await page.$('[data-testid="kangur-route-shell"]');
            if (!hasShell) {
              waitReason = 'route_shell';
            } else {
              const skeletonCount = await page
                .locator('[data-testid="kangur-page-transition-skeleton"]')
                .count();
              if (skeletonCount > 0) {
                waitReason = 'transition_skeleton';
              } else {
                const phaseEl = await page.$('[data-route-transition-phase]');
                if (phaseEl) {
                  const phase = await phaseEl.getAttribute('data-route-transition-phase');
                  const busy = await phaseEl.getAttribute('aria-busy');
                  if ((phase && phase !== 'idle') || busy === 'true') {
                    waitReason = 'transition_phase';
                  }
                }
              }
            }

            if (!waitReason) {
              const routeContent = await page.$('[data-testid="kangur-route-content"]');
              if (!routeContent) {
                waitReason = 'route_content';
              } else {
                const captureReady = await routeContent.getAttribute('data-route-capture-ready');
                if (captureReady !== 'true') {
                  waitReason = 'capture_ready';
                } else if (expectedAppearanceSelector) {
                  const appearanceApplied = await page.$(expectedAppearanceSelector);
                  if (!appearanceApplied) {
                    waitReason = 'appearance_mode';
                  } else {
                    pageReady = true;
                    break;
                  }
                } else {
                  pageReady = true;
                  break;
                }
              }
            }

            const now = Date.now();
            if (waitReason !== lastWaitReason || now - lastWaitProgressAt >= 2000) {
              lastWaitReason = waitReason;
              lastWaitProgressAt = now;
              emitProgress({
                currentCaptureId: id,
                currentCaptureTitle: title,
                currentCaptureStatus: 'waiting_for_page_ready',
                message: \`[\${id}] \${describeWaitReason(waitReason)}\`,
              });
            }
            await helpers.sleep(400);
          }
          log(pageReady
            ? \`[\${id}] Page ready — shell stable and capture-ready\`
            : \`[\${id}] Page readiness timeout — capturing current state\`);
          if (!pageReady) {
            captureStage = 'capturing_fallback';
            usedFallbackCapture = true;
            emitProgress({
              currentCaptureId: id,
              currentCaptureTitle: title,
              currentCaptureStatus: 'capturing_fallback',
              message: \`[\${id}] Page readiness timed out. Capturing the current state.\`,
            });
          }
        }

        if (selector) {
          captureStage = 'waiting_for_selector';
          log(\`[\${id}] Waiting for target selector: \${selector}\`);
          emitProgress({
            currentCaptureId: id,
            currentCaptureTitle: title,
            currentCaptureStatus: 'waiting_for_selector',
            message: \`[\${id}] Waiting for selector \${selector}.\`,
          });
          await page.waitForSelector(selector, { state: 'visible', timeout: waitForSelectorMs });
        }

        const settleMs = Math.max(waitForMs, 3000);
        captureStage = 'settling';
        log(\`[\${id}] Waiting \${settleMs}ms for content to settle\`);
        emitProgress({
          currentCaptureId: id,
          currentCaptureTitle: title,
          currentCaptureStatus: 'settling',
          message: \`[\${id}] Settling for \${settleMs}ms before capture.\`,
        });
        await helpers.sleep(settleMs);

        captureStage = 'capturing';
        const buffer = selector
          ? await page.locator(selector).screenshot({ type: 'png' })
          : await page.screenshot({ fullPage: true, type: 'png' });

        await artifacts.file(id, buffer, {
          extension: 'png',
          mimeType: 'image/png',
          kind: 'screenshot',
        });

        log(\`[\${id}] Captured successfully\`);
        successCount += 1;
        captureStage = usedFallbackCapture ? 'captured_fallback' : 'captured';
        results.push(
          buildCaptureResult({
            id,
            title,
            status: 'ok',
            resolvedUrl,
            attemptCount: attempt,
            durationMs: Date.now() - captureStartedAt,
            stage: captureStage,
          })
        );
        emitProgress({
          currentCaptureId: id,
          currentCaptureTitle: title,
          currentCaptureStatus: 'captured',
          lastCaptureId: id,
          lastCaptureStatus: 'ok',
          message:
            attempt > 1
              ? \`[\${id}] Captured \${title} on retry.\`
              : \`[\${id}] Captured \${title}.\`,
        });
        captureCompleted = true;
        break;
      } catch (error) {
        const message = describeError(error);
        if (attempt < maxCaptureAttempts) {
          log(\`[\${id}] Attempt \${attempt}/\${maxCaptureAttempts} failed: \${message}\`);
          emitProgress({
            currentCaptureId: id,
            currentCaptureTitle: title,
            currentCaptureStatus: 'retrying',
            message: \`[\${id}] Capture attempt \${attempt} failed: \${message}. Retrying.\`,
          });
          try {
            await page.goto('about:blank', { waitUntil: 'load', timeout: 15000 });
          } catch (resetError) {
            log(\`[\${id}] Retry reset failed: \${describeError(resetError)}\`);
          }
          await helpers.sleep(retryDelayMs);
          continue;
        }

        log(\`Capture failed for \${id}: \${message}\`);
        failureCount += 1;
        results.push(
          buildCaptureResult({
            id,
            title,
            status: 'failed',
            reason: message,
            resolvedUrl,
            attemptCount: attempt,
            durationMs: Date.now() - captureStartedAt,
            stage: captureStage,
          })
        );
        emitProgress({
          currentCaptureId: id,
          currentCaptureTitle: title,
          currentCaptureStatus: 'failed',
          lastCaptureId: id,
          lastCaptureStatus: 'failed',
          message: \`[\${id}] Capture failed: \${message}\`,
        });
      }
    }

    if (!captureCompleted) {
      continue;
    }
  }

  emit('capture_results', results);
}
`;

/**
 * Build an absolute capture URL from a base URL and a route path.
 * Returns null when the path is empty or the combination cannot be resolved.
 */
export const buildCaptureRouteUrl = (baseUrl: string, path: string): string | null => {
  const normalizedPath = path.trim();
  if (!normalizedPath) return null;
  if (/^https?:\/\//i.test(normalizedPath)) return normalizedPath;
  const normalizedBase = baseUrl.trim().replace(/\/+$/, '');
  if (!normalizedBase) return null;
  return `${normalizedBase}${normalizedPath.startsWith('/') ? normalizedPath : `/${normalizedPath}`}`;
};

