export type RunExecutionLoopArgs = {
  state: EngineStateManager;
  options: EvaluateGraphOptions;
  resolvedRunId: string;
  resolvedRunStartedAt: string;
  maxIterationsLimit: number;
  orderedNodes: AiNode[];
  scopedNodeIds: Set<string>;
  nodeById: Map<string, AiNode>;
  incomingEdgesByNode: Map<string, Edge[]>;
  outgoingEdgesByNode: Map<string, Edge[]>;
  triggerContext: Record<string, unknown> | null;
  internalCheckTriggerProvenance: () => boolean;
  telemetryResolver: { resolve: (type: string) => RuntimeNodeResolutionTelemetry | null };
  seedHashes: Record<string, string>;
  nodes: AiNode[];
  sanitizedEdges: Edge[];
  emitHalt: (reason: 'blocked' | 'max_iterations' | 'completed' | 'failed') => Promise<void>;
  executed: {
    notification: Set<string>;
    updater: Set<string>;
    http: Set<string>;
    delay: Set<string>;
    poll: Set<string>;
    ai: Set<string>;
    schema: Set<string>;
    mapper: Set<string>;
  };
};

export const runExecutionLoop = async (args: RunExecutionLoopArgs): Promise<void> => {
  const {
    state,
    options,
    resolvedRunId,
    resolvedRunStartedAt,
    maxIterationsLimit,
    orderedNodes,
    scopedNodeIds,
    nodeById,
    incomingEdgesByNode,
    outgoingEdgesByNode,
    triggerContext,
    internalCheckTriggerProvenance,
    telemetryResolver,
    seedHashes,
    nodes,
    sanitizedEdges,
    emitHalt,
    executed,
  } = args;

  let iteration = 0;
  let changedInLastIteration = true;

  try {
    while (changedInLastIteration && iteration < maxIterationsLimit) {
      if (options.abortSignal?.aborted) {
        throw new GraphExecutionCancelled(
          resolveAbortSignalMessage(options.abortSignal, 'Run cancelled.'),
          state.buildRuntimeStateSnapshot(state.inputs)
        );
      }

      iteration += 1;
      changedInLastIteration = false;

      // Warn at 80% of max iterations
      const warningThreshold = Math.floor(maxIterationsLimit * 0.8);
      if (iteration === warningThreshold && options.onIterationLimitWarning) {
        await options.onIterationLimitWarning({
          runId: resolvedRunId,
          iteration,
          maxIterations: maxIterationsLimit,
          remaining: maxIterationsLimit - iteration,
        });
      }

      if (options.onIteration) {
        await options.onIteration({
          runId: resolvedRunId,
          iteration,
          activeNodes: Array.from(state.activeNodes),
        });
      }

      const readyNodes = orderedNodes.filter((node) => {
      if (!scopedNodeIds.has(node.id)) return false;
      if (state.finishedNodes.has(node.id) || state.errorNodes.has(node.id)) return false;

      if (state.blockedNodes.has(node.id) && state.outputs[node.id]?.['status'] === 'blocked') {
        return false;
      }

      const rawInputs = state.inputs[node.id] ?? {};
      const nodeInputs = deriveNodeInputs({
        node,
        rawInputs,
        triggerContext,
        checkTriggerProvenance: internalCheckTriggerProvenance,
      });
      const runtimeTelemetry = telemetryResolver.resolve(node.type);

      const readiness = evaluateInputReadiness(
        node,
        nodeInputs,
        incomingEdgesByNode.get(node.id) ?? [],
        nodeById,
        (id) => {
          if (state.errorNodes.has(id)) {
            return 'failed';
          }
          if (state.finishedNodes.has(id)) {
            return resolveDeclaredNodeStatus(state.outputs[id]) ?? 'completed';
          }
          if (state.activeNodes.has(id)) {
            return 'running';
          }
          if (state.blockedNodes.has(id)) {
            return resolveBlockedNodeStatus(state.outputs[id]);
          }
          return 'pending';
        },
        (id) => state.outputs[id] ?? {}
      );

      if (!readiness.ready) {
        const blockedStatus =
          readiness.waitingOnDetails.length > 0
            ? resolveMissingInputStatus({
              waitingOnDetails: readiness.waitingOnDetails,
            })
            : 'blocked';
        let message =
          readiness.waitingOnPorts.length > 0
            ? `Upstream waiting diagnostics: Waiting on ports: ${readiness.waitingOnPorts.join(', ')}`
            : 'Upstream waiting diagnostics: Blocked by upstream nodes';

        if (readiness.waitingOnDetails && readiness.waitingOnDetails.length > 0) {
          const detailsMsg = readiness.waitingOnDetails
            .map((d) => {
              const upstreamNodes = d.upstream
                .map((u) => `${u.nodeTitle || u.nodeId} (${u.status})`)
                .join(', ');
              return `Upstream status for ${d.port}: ${upstreamNodes}`;
            })
            .join('; ');
          message = `Upstream waiting diagnostics: ${detailsMsg}`;
        }

        const previousStatus =
          typeof state.outputs[node.id]?.['status'] === 'string'
            ? String(state.outputs[node.id]?.['status']).trim().toLowerCase()
            : null;
        const previousMessage =
          typeof state.outputs[node.id]?.['message'] === 'string'
            ? String(state.outputs[node.id]?.['message'])
            : null;
        const previousWaitingPorts = Array.isArray(state.outputs[node.id]?.['waitingOnPorts'])
          ? (state.outputs[node.id]?.['waitingOnPorts'] as unknown[])
          : [];
        const previousWaitingDetails = Array.isArray(state.outputs[node.id]?.['waitingOnDetails'])
          ? (state.outputs[node.id]?.['waitingOnDetails'] as unknown[])
          : [];
        const waitingPortsChanged =
          JSON.stringify(previousWaitingPorts) !== JSON.stringify(readiness.waitingOnPorts);
        const waitingDetailsChanged =
          JSON.stringify(previousWaitingDetails) !== JSON.stringify(readiness.waitingOnDetails);

        const statusChanged = previousStatus !== blockedStatus;
        const messageChanged = previousMessage !== message;

        if (statusChanged || messageChanged || waitingPortsChanged || waitingDetailsChanged) {
          const attempt = state.getNodeAttempt(node.id);
          const spanId = buildSpanId(node.id, attempt, iteration);
          const blockedOutputs = {
            status: blockedStatus,
            skipReason: 'missing_inputs',
            blockedReason: 'missing_inputs',
            message,
            requiredPorts: readiness.requiredPorts,
            optionalPorts: readiness.optionalPorts,
            waitingOnPorts: readiness.waitingOnPorts,
            waitingOnDetails: readiness.waitingOnDetails,
          };
          state.outputs[node.id] = {
            ...blockedOutputs,
          };
          state.blockedNodes.add(node.id);

          if (options['recordHistory']) {
            const entries = state.history.get(node.id) ?? [];
            entries.push({
              timestamp: new Date().toISOString(),
              pathId: options.pathId ?? null,
              pathName: options.pathName ?? null,
              traceId: resolvedRunId,
              spanId,
              nodeId: node.id,
              nodeType: node.type,
              nodeTitle: node.title ?? null,
              status: blockedStatus,
              iteration,
              attempt,
              inputs: cloneValue(nodeInputs),
              outputs: cloneValue(state.outputs[node.id] ?? {}),
              inputHash: null,
              skipReason: 'missing_inputs',
              requiredPorts: readiness.requiredPorts,
              optionalPorts: readiness.optionalPorts,
              waitingOnPorts: readiness.waitingOnPorts,
              inputsFrom: buildInputLinks(
                node.id,
                sanitizedEdges,
                nodeById,
                nodeInputs
              ),
              outputsTo: [],
              durationMs: 0,
              ...buildRuntimeTelemetryFields(runtimeTelemetry),
            } as RuntimeHistoryEntry);
            state.history.set(node.id, entries);
          }

          if (options.profile?.onEvent) {
            options.profile.onEvent({
              type: 'node',
              runId: resolvedRunId,
              runStartedAt: resolvedRunStartedAt,
              nodeId: node.id,
              nodeType: node.type,
              iteration,
              status: 'skipped',
              durationMs: 0,
              reason: 'missing_inputs',
              requiredPorts: readiness.requiredPorts,
              optionalPorts: readiness.optionalPorts,
              waitingOnPorts: readiness.waitingOnPorts,
              ...buildRuntimeTelemetryFields(runtimeTelemetry),
            });
          }

          if (
            options.onToast &&
            statusChanged &&
            (blockedStatus === 'blocked' || (blockedStatus as string) === 'failed')
          ) {
            void options.onToast({
              runId: resolvedRunId,
              nodeId: node.id,
              message: `Node ${node.title || node.id} blocked: ${message}`,
              options: { variant: 'error' },
            });
          }

          const onNodeStatus = options.onNodeStatus;
          if (onNodeStatus) {
            void onNodeStatus({
              runId: resolvedRunId,
              traceId: resolvedRunId,
              spanId,
              node,
              iteration,
              attempt,
              status: blockedStatus,
              message,
              waitingOnPorts: readiness.waitingOnPorts,
              ...buildRuntimeTelemetryFields(runtimeTelemetry),
            });
          }

          if (options.onNodeBlocked) {
            void options.onNodeBlocked({
              runId: resolvedRunId,
              traceId: resolvedRunId,
              spanId,
              node,
              iteration,
              attempt,
              reason: 'missing_inputs',
              status: blockedStatus,
              message,
              waitingOnPorts: readiness.waitingOnPorts,
              waitingOnDetails: readiness.waitingOnDetails,
              ...buildRuntimeTelemetryFields(runtimeTelemetry),
            });
          }
        }
        return false;
      }

      return true;
    });

      if (readyNodes.length > 0) {
        await Promise.all(
          readyNodes.map(async (node) => {
            const changed = await runNode({
              node,
              iteration,
              state,
              options,
              resolvedRunId,
              resolvedRunStartedAt,
              triggerContext,
              internalCheckTriggerProvenance,
              telemetryResolver,
              seedHashes,
              nodes,
              sanitizedEdges,
              outgoingEdgesByNode,
              nodeById,
              executed,
            });
            if (changed) changedInLastIteration = true;
          })
        );
      }
    }
  } catch (error) {
    if (error instanceof GraphExecutionCancelled) {
      await emitHalt('failed');
    }
    throw error;
  }

  if (iteration >= maxIterationsLimit) {
    await emitHalt('max_iterations');
    throw new GraphExecutionError(
      `Graph execution exceeded maximum iterations (${maxIterationsLimit}).`,
      state.buildRuntimeStateSnapshot(state.inputs)
    );
  }
};

import { type AiNode, type Edge, type RuntimePortValues } from '@/shared/contracts/ai-paths';
import {
  type NodeHandlerContext,
  type RuntimeHistoryEntry,
} from '@/shared/contracts/ai-paths-runtime';

import {
  isAbortError,
  nowMs,
  resolveAbortSignalMessage,
  resolveNodeTimeoutMs,
  withTimeout,
  withRetries,
} from '../execution-helpers';
import { cloneValue } from '../utils';
import { buildSpanId } from './engine-execution-context';
import { resolveNodeHandlerOrThrow } from './engine-execution-handlers';
import { buildRuntimeTelemetryFields } from './engine-execution-telemetry';
import { buildNodeInputHash, buildNodeHash, resolveCacheScopeFingerprint } from './engine-hashing';
import { deriveNodeInputs } from './engine-node-input-deriver';
import {
  applyCachedNodeRuntimeStatus,
  readRuntimeRetryPolicy,
  resolveRecoverableNodeWaitState,
} from './engine-runtime-status';
import { type EngineStateManager } from './engine-state-manager';
import {
  GraphExecutionCancelled,
  GraphExecutionError,
  type EvaluateGraphOptions,
  type RuntimeNodeBlockedReason,
  type RuntimeNodeResolutionTelemetry,
} from './engine-types';
import {
  buildInputLinks,
  buildOutputLinks,
  collectNodeInputs,
  resolveEdgeToNodeId,
} from './engine-utils';
import { applyValidationBlockedNodeState, runRuntimeValidation } from './engine-validation-helpers';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const EXECUTED_STATE_KEY = '__executed_state__';
const createExecutedState = (): NodeHandlerContext['executed'] => ({
  notification: new Set<string>(),
  updater: new Set<string>(),
  http: new Set<string>(),
  delay: new Set<string>(),
  poll: new Set<string>(),
  ai: new Set<string>(),
  schema: new Set<string>(),
  mapper: new Set<string>(),
});

const normalizeBlockedReason = (value: unknown): RuntimeNodeBlockedReason => {
  if (typeof value !== 'string') return 'flow_control';
  const normalized = value.trim().toLowerCase();
  switch (normalized) {
    case 'missing_inputs':
    case 'flow_control':
    case 'validation':
    case 'error':
    case 'waiting_callback':
      return normalized;
    default:
      return 'flow_control';
  }
};

export type RunNodeArgs = {
  node: AiNode;
  iteration: number;
  state: EngineStateManager;
  options: EvaluateGraphOptions;
  resolvedRunId: string;
  resolvedRunStartedAt: string;
  triggerContext: Record<string, unknown> | null;
  internalCheckTriggerProvenance: () => boolean;
  telemetryResolver: { resolve: (type: string) => RuntimeNodeResolutionTelemetry | null };
  seedHashes: Record<string, string>;
  nodes: AiNode[];
  sanitizedEdges: Edge[];
  outgoingEdgesByNode: Map<string, Edge[]>;
  nodeById: Map<string, AiNode>;
  executed: NodeHandlerContext['executed'];
};

import {
  getDefaultSideEffectPolicy,
  isEffectNodeType,
} from '../../node-handler-registry';

const EFFECT_EXECUTED_BUCKET_BY_NODE_TYPE = new Map<string, keyof NodeHandlerContext['executed']>([
  ['agent', 'ai'],
  ['api_advanced', 'http'],
  ['database', 'updater'],
  ['http', 'http'],
  ['learner_agent', 'ai'],
  ['model', 'ai'],
  ['notification', 'notification'],
  ['playwright', 'ai'],
]);

const resolveNodeSideEffectPolicy = (node: AiNode): 'per_run' | 'per_activation' | undefined => {
  const configured = node.config?.runtime?.sideEffectPolicy;
  if (configured === 'per_run' || configured === 'per_activation') {
    return configured;
  }
  return getDefaultSideEffectPolicy(node.type);
};

const resolveNodeIdempotencyKey = (input: {
  node: AiNode;
  runId: string;
  activationHash: string | null;
  policy?: 'per_run' | 'per_activation';
}): string | null => {
  if (!input.policy) return null;

  const explicitPolicy = input.node.config?.runtime?.sideEffectPolicy;
  const hasAdvancedApiIdempotency = Boolean(
    String(input.node.type) === 'api_advanced' || String(input.node.type) === 'advanced_api'
      ? input.node.config?.apiAdvanced?.idempotencyEnabled ||
          (input.node.config?.apiAdvanced?.idempotencyKeyTemplate ?? '').trim().length > 0
      : false
  );
  if (
    explicitPolicy !== 'per_run' &&
    explicitPolicy !== 'per_activation' &&
    !hasAdvancedApiIdempotency
  ) {
    return null;
  }

  const activationScope = input.activationHash ?? 'activation';
  return input.policy === 'per_run'
    ? `${input.runId}:${input.node.id}:${activationScope}`
    : `${input.node.id}:${activationScope}`;
};

const resolveSourceSpanId = (input: {
  state: EngineStateManager;
  options: EvaluateGraphOptions;
  nodeId: string;
  nodeHash: string | null;
  activationHash: string | null;
  preferSeedHistory: boolean;
}): string | null => {
  const readEntries = (value: unknown): RuntimeHistoryEntry[] => {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return [];
    const entries = (value as Record<string, unknown>)[input.nodeId];
    return Array.isArray(entries) ? (entries as RuntimeHistoryEntry[]) : [];
  };

  const findMatch = (entries: RuntimeHistoryEntry[]): RuntimeHistoryEntry | null => {
    for (let index = entries.length - 1; index >= 0; index -= 1) {
      const entry = entries[index];
      if (!entry) continue;
      if (input.nodeHash && entry.inputHash === input.nodeHash) return entry;
      if (input.activationHash && entry.activationHash === input.activationHash) return entry;
    }
    return entries.at(-1) ?? null;
  };

  const entries = input.preferSeedHistory
    ? readEntries(input.options['seedHistory'])
    : (input.state.history.get(input.nodeId) ?? []);
  const matched = findMatch(entries);
  return typeof matched?.spanId === 'string' ? matched.spanId : null;
};

const appendNodeHistoryEntry = (input: {
  state: EngineStateManager;
  options: EvaluateGraphOptions;
  resolvedRunId: string;
  spanId: string;
  node: AiNode;
  status: 'executed' | 'cached' | 'failed';
  iteration: number;
  attempt: number;
  nodeInputs: RuntimePortValues;
  nodeOutputs: RuntimePortValues;
  nodeById: Map<string, AiNode>;
  sanitizedEdges: Edge[];
  inputHash?: string | null;
  activationHash?: string | null;
  cacheDecision?: 'hit' | 'miss' | 'disabled' | 'seed';
  sideEffectPolicy?: 'per_run' | 'per_activation';
  sideEffectDecision?: string;
  idempotencyKey?: string | null;
  effectSourceSpanId?: string | null;
  error?: string | null;
  durationMs?: number;
  runtimeTelemetry?: RuntimeNodeResolutionTelemetry | null;
}): void => {
  if (!input.options['recordHistory']) return;
  const entries = input.state.history.get(input.node.id) ?? [];
  entries.push({
    timestamp: new Date().toISOString(),
    pathId: input.options.pathId ?? null,
    pathName: input.options.pathName ?? null,
    traceId: input.resolvedRunId,
    spanId: input.spanId,
    nodeId: input.node.id,
    nodeType: input.node.type,
    nodeTitle: input.node.title ?? null,
    status: input.status,
    iteration: input.iteration,
    attempt: input.attempt,
    inputs: cloneValue(input.nodeInputs),
    outputs: cloneValue(input.nodeOutputs),
    inputHash: input.inputHash ?? null,
    activationHash: input.activationHash ?? null,
    cacheDecision: input.cacheDecision,
    sideEffectPolicy: input.sideEffectPolicy,
    sideEffectDecision: input.sideEffectDecision,
    idempotencyKey: input.idempotencyKey ?? null,
    effectSourceSpanId: input.effectSourceSpanId ?? null,
    error: input.error ?? undefined,
    inputsFrom: buildInputLinks(
      input.node.id,
      input.sanitizedEdges,
      input.nodeById,
      input.nodeInputs
    ),
    outputsTo: buildOutputLinks(
      input.node.id,
      input.sanitizedEdges,
      input.nodeById,
      input.nodeOutputs
    ),
    durationMs: input.durationMs ?? 0,
    ...buildRuntimeTelemetryFields(input.runtimeTelemetry ?? null),
  } as RuntimeHistoryEntry);
  input.state.history.set(input.node.id, entries);
};

export const runNode = async (args: RunNodeArgs): Promise<boolean> => {
  const {
    node,
    iteration,
    state,
    options,
    resolvedRunId,
    resolvedRunStartedAt,
    triggerContext,
    internalCheckTriggerProvenance,
    telemetryResolver,
    seedHashes,
    nodes,
    sanitizedEdges,
    outgoingEdgesByNode,
    nodeById,
    executed: executedState,
  } = args;

  const rawInputs = state.inputs[node.id] ?? {};
  const nodeInputs = deriveNodeInputs({
    node,
    rawInputs,
    triggerContext,
    checkTriggerProvenance: internalCheckTriggerProvenance,
  });
  const runtimeTelemetry = telemetryResolver.resolve(node.type);
  const activationHash = buildNodeInputHash(node, nodeInputs, {
    iteration,
  });

  // --- Cache Check Start ---
  const nodeHash = buildNodeHash(
    node,
    nodeInputs,
    resolveCacheScopeFingerprint({ node, runId: resolvedRunId, triggerContext })
  );

  if (nodeHash) {
    state.nodeHashes.set(node.id, nodeHash);
  }

  const prevOutputs = state.outputs[node.id] ?? null;
  const cachedOutputs = nodeHash ? state.effectiveCache?.get(nodeHash) : null;
  const seedOutputs = options.seedOutputs?.[node.id] ?? null;
  const isSeedMatch = Boolean(
    nodeHash && seedHashes[node.id] === nodeHash && seedOutputs
  );

  const isEntryNode = node.id === options.triggerNodeId;
  const isImplicitTriggerNode = node.type === 'trigger' && !options.triggerNodeId;
  const cacheMode = node.config?.runtime?.cache?.mode ?? 'auto';
  const isCacheDisabled = cacheMode === 'disabled';
  const isEffectNode = isEffectNodeType(node.type);
  const sideEffectPolicy = resolveNodeSideEffectPolicy(node);
  const effectExecutedBucket = EFFECT_EXECUTED_BUCKET_BY_NODE_TYPE.get(node.type);
  const idempotencyKey = resolveNodeIdempotencyKey({
    node,
    runId: resolvedRunId,
    activationHash,
    policy: sideEffectPolicy,
  });

  let validCacheHit = false;
  let cacheSource: RuntimePortValues | null = null;

  if (!isEntryNode && !isImplicitTriggerNode && !isCacheDisabled) {
    if (isSeedMatch && seedOutputs) {
      cacheSource = seedOutputs;
      validCacheHit = true;
    } else if (cachedOutputs) {
      cacheSource = cachedOutputs;
      validCacheHit = true;
    }

    if (validCacheHit && cacheSource) {
      const hasData = Object.keys(cacheSource).some((k) => k !== 'status' && k !== 'context');
      const expectsData = (node.outputs ?? []).length > 0;
      if (!hasData && expectsData) {
        validCacheHit = false;
        cacheSource = null;
      }
    }
  }

  if (validCacheHit && cacheSource) {
    const attempt = state.reserveNodeAttempt(node.id);
    const spanId = buildSpanId(node.id, attempt, iteration);
    const out = cacheSource;
    const effectSourceSpanId = isEffectNode
      ? resolveSourceSpanId({
        state,
        options,
        nodeId: node.id,
        nodeHash,
        activationHash,
        preferSeedHistory: isSeedMatch,
      })
      : null;
    state.outputs[node.id] = cloneValue(out) ?? {};

    applyCachedNodeRuntimeStatus(state, node.id, out);

    appendNodeHistoryEntry({
      state,
      options,
      resolvedRunId,
      spanId,
      node,
      status: 'cached',
      iteration,
      attempt,
      nodeInputs,
      nodeOutputs: state.outputs[node.id] ?? {},
      nodeById,
      sanitizedEdges,
      inputHash: nodeHash,
      activationHash,
      cacheDecision: isSeedMatch ? 'seed' : 'hit',
      sideEffectPolicy,
      sideEffectDecision: isEffectNode ? 'skipped_duplicate' : undefined,
      idempotencyKey,
      effectSourceSpanId,
      runtimeTelemetry,
    });

    if (options.profile?.onEvent) {
      options.profile.onEvent({
        type: 'node',
        runId: resolvedRunId,
        runStartedAt: resolvedRunStartedAt,
        nodeId: node.id,
        nodeType: node.type,
        iteration,
        status: 'cached',
        durationMs: 0,
        sideEffectPolicy,
        sideEffectDecision: isEffectNode ? 'skipped_duplicate' : undefined,
        activationHash: activationHash ?? undefined,
        ...(idempotencyKey ? { idempotencyKey } : {}),
        ...buildRuntimeTelemetryFields(runtimeTelemetry),
      });
    }
    const onNodeFinish = options.onNodeFinish;
    if (onNodeFinish) {
      await onNodeFinish({
        runId: resolvedRunId,
        traceId: resolvedRunId,
        spanId,
        runStartedAt: resolvedRunStartedAt,
        node,
        nodeInputs,
        prevOutputs,
        nextOutputs: state.outputs[node.id] ?? {},
        changed: false,
        iteration,
        attempt,
        cached: true,
        cacheDecision: isSeedMatch ? 'seed' : 'hit',
        sideEffectPolicy,
        sideEffectDecision: isEffectNode ? 'skipped_duplicate' : undefined,
        activationHash,
        idempotencyKey,
        effectSourceSpanId,
        ...buildRuntimeTelemetryFields(runtimeTelemetry),
      });
    }
    return false;
  }
  // --- Cache Check End ---

  const nodeStartedAt = nowMs();
  state.activeNodes.add(node.id);
  state.blockedNodes.delete(node.id);

  const attempt = state.incrementNodeAttempt(node.id);
  const spanId = buildSpanId(node.id, attempt, iteration);
  const existingExecutedState = state.variables[EXECUTED_STATE_KEY];
  const executed =
    executedState && typeof executedState === 'object'
      ? executedState
      : existingExecutedState && typeof existingExecutedState === 'object'
        ? (existingExecutedState as NodeHandlerContext['executed'])
        : createExecutedState();
  state.variables[EXECUTED_STATE_KEY] = executed;

  try {
    const preExecuteValidation = await runRuntimeValidation({
      stage: 'node_pre_execute',
      iteration,
      node,
      nodeInputs,
      nodeOutputs: prevOutputs ?? undefined,
      runtimeTelemetry,
      options,
      resolvedRunId,
      resolvedRunStartedAt,
      nodes,
      sanitizedEdges,
    });
    if (preExecuteValidation?.decision === 'block') {
      const nodeDurationMs = nowMs() - nodeStartedAt;
      state.nodeDurationsMap.set(node.id, nodeDurationMs);
      state.activeNodes.delete(node.id);
      await applyValidationBlockedNodeState({
        node,
        nodeInputs,
        iteration,
        attempt,
        nodeDurationMs,
        runtimeTelemetry,
        stage: 'node_pre_execute',
        message: preExecuteValidation.message,
        issues: preExecuteValidation.issues,
        state,
        options,
        resolvedRunId,
        resolvedRunStartedAt,
        sanitizedEdges,
        nodeById,
        activationHash,
      });
      return true;
    }

    const handler = await resolveNodeHandlerOrThrow({
      node,
      options,
      state,
      resolvedRunId,
      resolvedRunStartedAt,
      iteration,
      attempt,
      spanId,
      nodeInputs,
      prevOutputs: prevOutputs ?? {},
      runtimeTelemetry,
    });

    const retryPolicy = readRuntimeRetryPolicy(node);

    const sideEffectDecision: 'executed' | 'skipped_policy' | undefined =
      isEffectNode && effectExecutedBucket && executed[effectExecutedBucket].has(node.id)
        ? 'skipped_policy'
        : isEffectNode
          ? 'executed'
          : undefined;

    const ctx: NodeHandlerContext = {
      node,
      nodeId: node.id,
      nodeTitle: node.title,
      nodeInputs,
      prevOutputs: prevOutputs ?? {},
      edges: sanitizedEdges,
      nodes,
      nodeById,
      runId: resolvedRunId,
      runStartedAt: resolvedRunStartedAt,
      timeoutMs: resolveNodeTimeoutMs(node),
      runMeta:
        (options['runMeta'] as Record<string, unknown> | undefined) ??
        (options['meta'] as Record<string, unknown> | undefined) ??
        {},
      activePathId: options.pathId ?? null,
      contextRegistry: options.contextRegistry ?? null,
      iteration,
      attempt,
      spanId,
      triggerNodeId: options.triggerNodeId ?? undefined,
      triggerEvent: options.triggerEvent ?? undefined,
      triggerContext: options.triggerContext ?? null,
      deferPoll: Boolean(options.deferPoll),
      skipAiJobs: Boolean(options.skipAiJobs),
      isDryRun: Boolean(options['isDryRun']),
      sideEffectDecision,
      sideEffectControl: sideEffectPolicy
        ? {
          policy: sideEffectPolicy,
          decision: sideEffectDecision === 'skipped_policy' ? 'skipped_policy' : 'executed',
          activationHash,
          idempotencyKey,
        }
        : undefined,
      now: new Date().toISOString(),
      abortSignal: options.abortSignal,
      allOutputs: state.outputs,
      allInputs: state.inputs,
      fetchEntityCached:
        options.fetchEntityCached ?? options.fetchEntityByType ?? (async () => null),
      reportAiPathsError: options.reportAiPathsError,
      toast: (message, toastOptions) => {
        options.toast?.(message, toastOptions);
        if (options.onToast) {
          void options.onToast({
            runId: resolvedRunId,
            nodeId: node.id,
            message,
            options: toastOptions,
          });
        }
      },
      simulationEntityType: (triggerContext?.['entityType'] as string) ?? null,
      simulationEntityId:
        (triggerContext?.['entityId'] as string) ??
        (triggerContext?.['productId'] as string) ??
        null,
      resolvedEntity: null,
      fallbackEntityId: null,
      strictFlowMode: Boolean(options.strictFlowMode),
      runtimeTelemetry: buildRuntimeTelemetryFields(runtimeTelemetry),
      executed,
      variables: state.variables,
      setVariable: (key, value) => {
        state.variables[key] = value;
      },
    };

    if (options.onNodeStart) {
      await options.onNodeStart({
        runId: resolvedRunId,
        traceId: resolvedRunId,
        spanId,
        runStartedAt: resolvedRunStartedAt,
        node,
        nodeInputs,
        prevOutputs,
        iteration,
        attempt,
        ...buildRuntimeTelemetryFields(runtimeTelemetry),
      });
    }

    const nodeResult = await withRetries(
      () =>
        withTimeout(Promise.resolve(handler(ctx)), ctx.timeoutMs, `Node ${node.title || node.id}`),
      retryPolicy.enabled ? retryPolicy.attempts : 1,
      retryPolicy.backoffMs,
      `Node ${node.title || node.id}`,
      options.abortSignal
    );

    const nextOutputs = cloneValue(nodeResult) ?? {};
    const postExecuteValidation = await runRuntimeValidation({
      stage: 'node_post_execute',
      iteration,
      node,
      nodeInputs,
      nodeOutputs: nextOutputs,
      runtimeTelemetry,
      options,
      resolvedRunId,
      resolvedRunStartedAt,
      nodes,
      sanitizedEdges,
    });
    if (postExecuteValidation?.decision === 'block') {
      const nodeDurationMs = nowMs() - nodeStartedAt;
      state.nodeDurationsMap.set(node.id, nodeDurationMs);
      state.activeNodes.delete(node.id);
      await applyValidationBlockedNodeState({
        node,
        nodeInputs,
        iteration,
        attempt,
        nodeDurationMs,
        runtimeTelemetry,
        stage: 'node_post_execute',
        message: postExecuteValidation.message,
        issues: postExecuteValidation.issues,
        state,
        options,
        resolvedRunId,
        resolvedRunStartedAt,
        sanitizedEdges,
        nodeById,
        activationHash,
      });
      return true;
    }

    // Detect handler-declared blocked status (e.g. model returning { status: 'blocked', reason: 'missing_prompt' }).
    // Route through the blocked-node path so downstream nodes wait instead of processing garbage data.
    const handlerDeclaredBlocked =
      typeof nextOutputs?.['status'] === 'string' &&
      nextOutputs['status'].trim().toLowerCase() === 'blocked';

    if (handlerDeclaredBlocked) {
      const blockedReason = normalizeBlockedReason(nextOutputs['reason']);
      const nodeDurationMs = nowMs() - nodeStartedAt;
      state.nodeDurationsMap.set(node.id, nodeDurationMs);
      state.activeNodes.delete(node.id);
      state.blockedNodes.add(node.id);
      state.outputs[node.id] = nextOutputs;

      appendNodeHistoryEntry({
        state,
        options,
        resolvedRunId,
        spanId,
        node,
        status: 'executed',
        iteration,
        attempt,
        nodeInputs,
        nodeOutputs: nextOutputs,
        nodeById,
        sanitizedEdges,
        inputHash: nodeHash,
        activationHash,
        cacheDecision: isCacheDisabled ? 'disabled' : 'miss',
        sideEffectPolicy,
        sideEffectDecision,
        idempotencyKey,
        durationMs: nodeDurationMs,
        runtimeTelemetry,
      });

      if (options.profile?.onEvent) {
        options.profile.onEvent({
          type: 'node',
          runId: resolvedRunId,
          runStartedAt: resolvedRunStartedAt,
          nodeId: node.id,
          nodeType: node.type,
          iteration,
          status: 'skipped',
          durationMs: nodeDurationMs,
          reason: blockedReason,
          ...buildRuntimeTelemetryFields(runtimeTelemetry),
        });
      }

      if (options.onNodeBlocked) {
        void options.onNodeBlocked({
          runId: resolvedRunId,
          traceId: resolvedRunId,
          spanId,
          node,
          iteration,
          attempt,
          reason: blockedReason,
          status: 'blocked',
          message: `Node ${node.title || node.id} blocked: ${String(nextOutputs['reason'] ?? 'handler declared blocked status')}`,
          waitingOnPorts: Array.isArray(nextOutputs['waitingOnPorts'])
            ? (nextOutputs['waitingOnPorts'] as string[])
            : [],
          waitingOnDetails: [],
          ...buildRuntimeTelemetryFields(runtimeTelemetry),
        });
      }

      return true;
    }

    const nodeDurationMs = nowMs() - nodeStartedAt;
    state.nodeDurationsMap.set(node.id, nodeDurationMs);
    state.finishedNodes.add(node.id);
    state.activeNodes.delete(node.id);
    state.errorNodes.delete(node.id);
    state.outputs[node.id] = nextOutputs;

    if (effectExecutedBucket === 'notification' && sideEffectDecision === 'executed') {
      executed.notification.add(node.id);
    }

    if (nodeHash && state.effectiveCache) {
      state.effectiveCache.set(nodeHash, nextOutputs);
    }

    appendNodeHistoryEntry({
      state,
      options,
      resolvedRunId,
      spanId,
      node,
      status: 'executed',
      iteration,
      attempt,
      nodeInputs,
      nodeOutputs: nextOutputs,
      nodeById,
      sanitizedEdges,
      inputHash: nodeHash,
      activationHash,
      cacheDecision: isCacheDisabled ? 'disabled' : 'miss',
      sideEffectPolicy,
      sideEffectDecision,
      idempotencyKey,
      durationMs: nodeDurationMs,
      runtimeTelemetry,
    });

    if (options.profile?.onEvent) {
      options.profile.onEvent({
        type: 'node',
        runId: resolvedRunId,
        runStartedAt: resolvedRunStartedAt,
        nodeId: node.id,
        nodeType: node.type,
        iteration,
        status: 'executed',
        durationMs: nodeDurationMs,
        sideEffectPolicy,
        sideEffectDecision,
        activationHash: activationHash ?? undefined,
        ...(idempotencyKey ? { idempotencyKey } : {}),
        ...buildRuntimeTelemetryFields(runtimeTelemetry),
      });
    }

    const onNodeFinish = options.onNodeFinish;
    if (onNodeFinish) {
      await onNodeFinish({
        runId: resolvedRunId,
        traceId: resolvedRunId,
        spanId,
        runStartedAt: resolvedRunStartedAt,
        node,
        nodeInputs,
        prevOutputs,
        nextOutputs,
        changed: true,
        iteration,
        attempt,
        cacheDecision: isCacheDisabled ? 'disabled' : 'miss',
        sideEffectPolicy,
        sideEffectDecision,
        activationHash,
        idempotencyKey,
        ...buildRuntimeTelemetryFields(runtimeTelemetry),
      });
    }

    const onNodeSuccess = options.onNodeSuccess;
    if (onNodeSuccess) {
      await onNodeSuccess({
        runId: resolvedRunId,
        traceId: resolvedRunId,
        spanId,
        runStartedAt: resolvedRunStartedAt,
        node,
        nodeInputs,
        prevOutputs,
        outputs: nextOutputs,
        iteration,
        attempt,
        durationMs: nodeDurationMs,
        ...buildRuntimeTelemetryFields(runtimeTelemetry),
      });
    }


    // Dependency Propagation
    const outgoingEdges = outgoingEdgesByNode.get(node.id) ?? [];
    outgoingEdges.forEach((edge) => {
      const toNodeId = resolveEdgeToNodeId(edge);
      if (!toNodeId) return;
      const targetNode = nodeById.get(toNodeId);
      if (!targetNode) return;

      const targetInputs = collectNodeInputs(toNodeId, state.outputs, state.incomingEdgesByNode);
      const changed = JSON.stringify(state.inputs[toNodeId]) !== JSON.stringify(targetInputs);

      if (changed) {
        state.inputs[toNodeId] = cloneValue(targetInputs);
        if (state.finishedNodes.has(toNodeId)) {
          const previousHash = state.nodeHashes.get(toNodeId) ?? null;
          const nextHash = buildNodeHash(
            targetNode,
            targetInputs,
            resolveCacheScopeFingerprint({ node: targetNode, runId: resolvedRunId, triggerContext })
          );
          if (previousHash && nextHash && previousHash !== nextHash) {
            state.finishedNodes.delete(toNodeId);
          }
        }
      }
    });

    return true;
  } catch (error) {
    logClientError(error);
    const recoverableWaitState = resolveRecoverableNodeWaitState(node, error);
    if (recoverableWaitState) {
      state.activeNodes.delete(node.id);
      state.blockedNodes.add(node.id);
      state.outputs[node.id] = {
        ...state.outputs[node.id],
        status: 'waiting_callback',
        message: recoverableWaitState.message,
        waitingOnPorts: recoverableWaitState.waitingOnPorts,
      };

      const onNodeStatus = options.onNodeStatus;
      if (onNodeStatus) {
        void onNodeStatus({
          runId: resolvedRunId,
          traceId: resolvedRunId,
          spanId,
          node,
          iteration,
          attempt,
          status: 'waiting_callback',
          message: recoverableWaitState.message,
          waitingOnPorts: recoverableWaitState.waitingOnPorts,
          ...buildRuntimeTelemetryFields(runtimeTelemetry),
        });
      }

      if (options.onNodeBlocked) {
        void options.onNodeBlocked({
          runId: resolvedRunId,
          traceId: resolvedRunId,
          spanId,
          node,
          iteration,
          attempt,
          reason: 'waiting_callback',
          status: 'waiting_callback',
          message: recoverableWaitState.message,
          waitingOnPorts: recoverableWaitState.waitingOnPorts,
          waitingOnDetails: [],
          ...buildRuntimeTelemetryFields(runtimeTelemetry),
        });
      }

      return false;
    }

    if (isAbortError(error) || options.abortSignal?.aborted) {
      state.activeNodes.delete(node.id);
      state.finishedNodes.delete(node.id);
      state.blockedNodes.delete(node.id);
      throw new GraphExecutionCancelled(
        resolveAbortSignalMessage(options.abortSignal, 'Run cancelled.'),
        state.buildRuntimeStateSnapshot(state.inputs),
        node.id,
        error instanceof Error ? error : undefined
      );
    }

    state.activeNodes.delete(node.id);
    state.errorNodes.add(node.id);
    state.finishedNodes.delete(node.id);
    state.blockedNodes.delete(node.id);
    if (error instanceof Error && error.message.includes('timed out')) {
      state.timeoutNodes.add(node.id);
    }

    const nodeDurationMs = nowMs() - nodeStartedAt;
    state.nodeDurationsMap.set(node.id, nodeDurationMs);

    const errorMessage = error instanceof Error ? error.message : String(error);
    state.outputs[node.id] = {
      status: 'failed',
      error: errorMessage,
    };
    const errorSnapshot = state.buildRuntimeStateSnapshot(state.inputs);
    const graphError = new GraphExecutionError(
      errorMessage,
      errorSnapshot,
      node.id,
      error instanceof Error ? error : undefined
    );

    appendNodeHistoryEntry({
      state,
      options,
      resolvedRunId,
      spanId,
      node,
      status: 'failed',
      iteration,
      attempt,
      nodeInputs,
      nodeOutputs: {
        status: 'failed',
        error: graphError.message,
      },
      nodeById,
      sanitizedEdges,
      inputHash: nodeHash,
      activationHash,
      cacheDecision: isCacheDisabled ? 'disabled' : 'miss',
      sideEffectPolicy,
      sideEffectDecision: sideEffectPolicy ? 'failed' : undefined,
      idempotencyKey,
      error: graphError.message,
      durationMs: nodeDurationMs,
      runtimeTelemetry,
    });

    if (options.profile?.onEvent) {
      options.profile.onEvent({
        type: 'node',
        runId: resolvedRunId,
        runStartedAt: resolvedRunStartedAt,
        nodeId: node.id,
        nodeType: node.type,
        iteration,
        status: 'error',
        durationMs: nodeDurationMs,
        reason: graphError.message,
        sideEffectPolicy,
        sideEffectDecision: sideEffectPolicy ? 'failed' : undefined,
        activationHash: activationHash ?? undefined,
        ...(idempotencyKey ? { idempotencyKey } : {}),
        ...buildRuntimeTelemetryFields(runtimeTelemetry),
      });
    }

    const shouldNotifyNodeError =
      !(graphError instanceof GraphExecutionError) ||
      !graphError.message.startsWith('No handler found for node type:');
    const onNodeError = options.onNodeError;
    if (shouldNotifyNodeError && onNodeError) {
      await onNodeError({
        runId: resolvedRunId,
        traceId: resolvedRunId,
        spanId,
        runStartedAt: resolvedRunStartedAt,
        node,
        nodeInputs,
        prevOutputs: prevOutputs ?? {},
        error: graphError,
        iteration,
        attempt,
        ...buildRuntimeTelemetryFields(runtimeTelemetry),
      });
    }

    throw graphError;
  }
};

import { type AiNode, type Edge } from '@/shared/contracts/ai-paths';

import { resolveScopedNodeIds } from './engine-reachability';
import {
  resolveEdgeFromNodeId,
  resolveEdgeToNodeId,
  orderNodesByDependencies,
} from './engine-utils';
import { compileGraph, sanitizeEdges } from '../../utils';

export type GraphPreparationResult = {
  sanitizedEdges: Edge[];
  nodeById: Map<string, AiNode>;
  incomingEdgesByNode: Map<string, Edge[]>;
  outgoingEdgesByNode: Map<string, Edge[]>;
  orderedNodes: AiNode[];
  scopedNodeIds: Set<string>;
  unsupportedCycleMessage: string | null;
};

export const prepareGraphForExecution = (args: {
  nodes: AiNode[];
  edges: Edge[];
  triggerNodeId?: string | null;
  seedHashes?: Record<string, string>;
}): GraphPreparationResult => {
  const { nodes, edges, triggerNodeId, seedHashes = {} } = args;
  const nodeById = new Map(nodes.map((n) => [n.id, n]));
  const incomingEdgesByNodeAll = new Map<string, Edge[]>();
  const outgoingEdgesByNodeAll = new Map<string, Edge[]>();

  const sanitizedEdges = sanitizeEdges(nodes, edges);
  sanitizedEdges.forEach((edge) => {
    const fromNodeId = resolveEdgeFromNodeId(edge);
    const toNodeId = resolveEdgeToNodeId(edge);
    if (!fromNodeId || !toNodeId) return;
    if (!incomingEdgesByNodeAll.has(toNodeId)) incomingEdgesByNodeAll.set(toNodeId, []);
    incomingEdgesByNodeAll.get(toNodeId)!.push(edge);
    if (!outgoingEdgesByNodeAll.has(fromNodeId)) outgoingEdgesByNodeAll.set(fromNodeId, []);
    outgoingEdgesByNodeAll.get(fromNodeId)!.push(edge);
  });

  const orderedNodes = orderNodesByDependencies(nodes, sanitizedEdges);
  const compileReport = compileGraph(nodes, sanitizedEdges);
  const unsupportedCycleMessage =
    compileReport.findings.find((finding) => finding.code === 'unsupported_cycle')?.message ?? null;

  const scopedNodeIds = resolveScopedNodeIds({
    nodes,
    triggerNodeId: triggerNodeId ?? undefined,
    nodeById,
    outgoingEdgesByNode: outgoingEdgesByNodeAll,
    incomingEdgesByNode: incomingEdgesByNodeAll,
    seedHashes,
  });

  const incomingEdgesByNode = new Map<string, Edge[]>();
  const outgoingEdgesByNode = new Map<string, Edge[]>();
  sanitizedEdges.forEach((edge) => {
    const fromNodeId = resolveEdgeFromNodeId(edge);
    const toNodeId = resolveEdgeToNodeId(edge);
    if (!fromNodeId || !toNodeId) return;
    if (!scopedNodeIds.has(fromNodeId) || !scopedNodeIds.has(toNodeId)) return;
    if (!incomingEdgesByNode.has(toNodeId)) incomingEdgesByNode.set(toNodeId, []);
    incomingEdgesByNode.get(toNodeId)!.push(edge);
    if (!outgoingEdgesByNode.has(fromNodeId)) outgoingEdgesByNode.set(fromNodeId, []);
    outgoingEdgesByNode.get(fromNodeId)!.push(edge);
  });

  return {
    sanitizedEdges,
    nodeById,
    incomingEdgesByNode,
    outgoingEdgesByNode,
    orderedNodes,
    scopedNodeIds,
    unsupportedCycleMessage,
  };
};

import { type AiNode } from '@/shared/contracts/ai-paths';

import { type EngineStateManager } from './engine-state-manager';
import {
  checkContextMatchesSimulation,
  hasValuableSimulationContext,
  isSimulationCapableFetcher,
} from './engine-utils';

export type TriggerProvenanceContext = {
  scopedNodeIds: Set<string>;
  nodeById: Map<string, AiNode>;
  state: EngineStateManager;
  triggerContext: Record<string, unknown> | null;
  triggerSource: AiNode | null;
};

export const checkTriggerProvenance = (ctx: TriggerProvenanceContext): boolean => {
  const { scopedNodeIds, nodeById, state, triggerContext } = ctx;
  const simulationNodesInScope = Array.from(scopedNodeIds)
    .map((id) => nodeById.get(id))
    .filter((n): n is AiNode => n != null && (n.type === 'simulation' || isSimulationCapableFetcher(n)));
  const finishedSimulationNodes = simulationNodesInScope.filter((n) =>
    state.finishedNodes.has(n.id)
  );
  const simulationOutputs = finishedSimulationNodes.map((n) => state.outputs[n.id]).filter(Boolean);

  const hasLiveProvenance = triggerContext && checkContextMatchesSimulation(triggerContext);
  const hasSimNodeProvenance = simulationOutputs.some(
    (out) => out && hasValuableSimulationContext((out['context'] as Record<string, unknown>) ?? {})
  );

  if (hasLiveProvenance || hasSimNodeProvenance) {
    return true;
  }

  const hasPotentialSimNode = simulationNodesInScope.some((n) => !state.finishedNodes.has(n.id));
  return hasPotentialSimNode;
};

export const validateTriggerProvenanceFeasibility = (ctx: TriggerProvenanceContext): void => {
  void ctx;
};

import { type EvaluateGraphOptions, type RuntimeNodeResolutionTelemetry } from './engine-types';

export const buildRuntimeTelemetryFields = (
  telemetry: RuntimeNodeResolutionTelemetry | null
): {
  runtimeStrategy?: RuntimeNodeResolutionTelemetry['runtimeStrategy'];
  runtimeResolutionSource?: RuntimeNodeResolutionTelemetry['runtimeResolutionSource'];
  runtimeCodeObjectId?: string | null;
} =>
  telemetry
    ? {
      runtimeStrategy: telemetry.runtimeStrategy,
      runtimeResolutionSource: telemetry.runtimeResolutionSource,
      runtimeCodeObjectId: telemetry.runtimeCodeObjectId ?? null,
    }
    : {};

export class RuntimeTelemetryResolver {
  private cache = new Map<string, RuntimeNodeResolutionTelemetry | null>();

  constructor(private options: EvaluateGraphOptions) {}

  resolve(nodeTypeInput: string): RuntimeNodeResolutionTelemetry | null {
    const nodeType = typeof nodeTypeInput === 'string' ? nodeTypeInput.trim() : '';
    if (!nodeType) return null;
    if (this.cache.has(nodeType)) {
      return this.cache.get(nodeType) ?? null;
    }
    const telemetry = this.options.resolveHandlerTelemetry
      ? this.options.resolveHandlerTelemetry(nodeType)
      : null;
    this.cache.set(nodeType, telemetry ?? null);
    return telemetry ?? null;
  }
}

import type { AiNode } from '@/shared/contracts/ai-paths';
import type { RuntimePortValues } from '@/shared/contracts/ai-paths-runtime';

import { DEFAULT_DB_QUERY } from '../../constants';
import { coerceInput, hashRuntimeValue } from '../../utils';
import { buildDbQueryPayload } from '../utils';
import { resolveNodeCacheScope } from './engine-state-manager';
import { pickString } from './engine-utils';

export const CACHE_VERSION = 2;

export const resolveCacheScopeFingerprint = (args: {
  node: AiNode;
  runId: string;
  triggerContext: Record<string, unknown> | null;
}): Record<string, unknown> | undefined => {
  const { node, runId, triggerContext } = args;
  const cacheScope = resolveNodeCacheScope(node);
  if (cacheScope === 'run') {
    return { runId };
  }
  if (cacheScope === 'session' || cacheScope === 'activation') {
    const entityId =
      pickString(triggerContext?.['entityId']) ?? pickString(triggerContext?.['productId']);
    if (entityId) {
      return { entityId };
    }
  }
  return undefined;
};

export const buildNodeInputHash = (
  node: AiNode,
  nodeInputs: RuntimePortValues,
  cacheScopeFingerprint?: Record<string, unknown>
): string =>
  hashRuntimeValue({
    v: CACHE_VERSION,
    id: node.id,
    type: node.type,
    title: node.title ?? null,
    config: node.config ?? null,
    inputs: nodeInputs,
    inputPorts: node.inputs ?? [],
    outputPorts: node.outputs ?? [],
    ...(cacheScopeFingerprint ? { cacheScope: cacheScopeFingerprint } : {}),
  });

export const buildDatabaseInputHash = (
  node: AiNode,
  nodeInputs: RuntimePortValues,
  cacheScopeFingerprint?: Record<string, unknown>
): string => {
  const dbConfig = node.config?.database ?? { operation: 'query' };
  const operation = dbConfig.operation ?? 'query';
  const queryConfig = {
    ...DEFAULT_DB_QUERY,
    ...(dbConfig.query ?? {}),
  };
  const mappings = Array.isArray(dbConfig.mappings)
    ? dbConfig.mappings.map((mapping) => ({
      sourcePort: mapping?.sourcePort ?? null,
      sourcePath: mapping?.sourcePath ?? null,
      targetPath: mapping?.targetPath ?? null,
    }))
    : [];
  const baseConfig = {
    operation,
    entityType: dbConfig.entityType ?? 'product',
    idField: dbConfig.idField ?? 'entityId',
    mode: dbConfig.mode ?? 'replace',
    updateStrategy: dbConfig.updateStrategy ?? 'one',
    useMongoActions: dbConfig.useMongoActions ?? false,
    actionCategory: dbConfig.actionCategory ?? null,
    action: dbConfig.action ?? null,
    distinctField: dbConfig.distinctField ?? '',
    updateTemplate: dbConfig.updateTemplate ?? '',
    writeSource: dbConfig.writeSource ?? 'bundle',
    writeSourcePath: dbConfig.writeSourcePath ?? '',
    dryRun: dbConfig.dryRun ?? false,
    query: {
      provider: queryConfig.provider,
      collection: queryConfig.collection,
      mode: queryConfig.mode,
      preset: queryConfig.preset,
      field: queryConfig.field,
      idType: queryConfig.idType,
      queryTemplate: queryConfig.queryTemplate,
      limit: queryConfig.limit,
      sort: queryConfig.sort,
      projection: queryConfig.projection,
      single: queryConfig.single,
    },
    ...(mappings.length ? { mappings } : {}),
  };
  const inputs: Record<string, unknown> = {};
  const includeInput = (key: string): void => {
    if (nodeInputs[key] === undefined) return;
    inputs[key] = coerceInput(nodeInputs[key]);
  };
  if (operation === 'query') {
    const payload = buildDbQueryPayload(nodeInputs, queryConfig);
    return hashRuntimeValue({
      v: CACHE_VERSION,
      id: node.id,
      type: node.type,
      config: baseConfig,
      query: payload,
      ...(cacheScopeFingerprint ? { cacheScope: cacheScopeFingerprint } : {}),
    });
  }
  if (operation === 'update') {
    const sourcePorts = mappings.length
      ? mappings
        .map((mapping) => mapping.sourcePort)
        .filter((port): port is string => typeof port === 'string' && port.trim().length > 0)
      : [];
    sourcePorts.forEach(includeInput);
    includeInput('entityId');
    includeInput('productId');
    includeInput('entityType');
    includeInput('value');
    includeInput('query');
    includeInput('queryCallback');
    includeInput('aiQuery');
    includeInput('jobId');
    if ((dbConfig.updateStrategy ?? 'one') === 'many') {
      const payload = buildDbQueryPayload(nodeInputs, queryConfig);
      inputs['queryPayload'] = payload;
    }
    return hashRuntimeValue({
      v: CACHE_VERSION,
      id: node.id,
      type: node.type,
      config: baseConfig,
      inputs,
      ...(cacheScopeFingerprint ? { cacheScope: cacheScopeFingerprint } : {}),
    });
  }
  if (operation === 'action') {
    includeInput('entityId');
    includeInput('productId');
    includeInput('entityType');
    includeInput('value');
    includeInput('payload');
    includeInput('params');
    return hashRuntimeValue({
      v: CACHE_VERSION,
      id: node.id,
      type: node.type,
      config: baseConfig,
      inputs,
      ...(cacheScopeFingerprint ? { cacheScope: cacheScopeFingerprint } : {}),
    });
  }
  if (operation === 'distinct') {
    const payload = buildDbQueryPayload(nodeInputs, queryConfig);
    return hashRuntimeValue({
      v: CACHE_VERSION,
      id: node.id,
      type: node.type,
      config: baseConfig,
      query: payload,
      ...(cacheScopeFingerprint ? { cacheScope: cacheScopeFingerprint } : {}),
    });
  }
  return hashRuntimeValue({
    v: CACHE_VERSION,
    id: node.id,
    type: node.type,
    config: baseConfig,
    inputs: nodeInputs,
    ...(cacheScopeFingerprint ? { cacheScope: cacheScopeFingerprint } : {}),
  });
};

export const buildModelInputHash = (
  node: AiNode,
  nodeInputs: RuntimePortValues,
  cacheScopeFingerprint?: Record<string, unknown>
): string =>
  hashRuntimeValue({
    v: CACHE_VERSION,
    id: node.id,
    type: node.type,
    title: node.title ?? null,
    config: node.config ?? null,
    inputs: nodeInputs,
    inputPorts: node.inputs ?? [],
    outputPorts: node.outputs ?? [],
    ...(cacheScopeFingerprint ? { cacheScope: cacheScopeFingerprint } : {}),
  });

export const buildPromptInputHash = (
  node: AiNode,
  nodeInputs: RuntimePortValues,
  cacheScopeFingerprint?: Record<string, unknown>
): string =>
  hashRuntimeValue({
    v: CACHE_VERSION,
    id: node.id,
    type: node.type,
    title: node.title ?? null,
    config: node.config ?? null,
    inputs: nodeInputs,
    inputPorts: node.inputs ?? [],
    outputPorts: node.outputs ?? [],
    ...(cacheScopeFingerprint ? { cacheScope: cacheScopeFingerprint } : {}),
  });

export const buildNodeHash = (
  node: AiNode,
  nodeInputs: RuntimePortValues,
  cacheScopeFingerprint?: Record<string, unknown>
): string => {
  return node.type === 'database'
    ? buildDatabaseInputHash(node, nodeInputs, cacheScopeFingerprint)
    : node.type === 'model'
      ? buildModelInputHash(node, nodeInputs, cacheScopeFingerprint)
      : node.type === 'prompt'
        ? buildPromptInputHash(node, nodeInputs, cacheScopeFingerprint)
        : buildNodeInputHash(node, nodeInputs, cacheScopeFingerprint);
};

import { type AiNode, type Edge } from '@/shared/contracts/ai-paths';
import { type RuntimePortValues } from '@/shared/contracts/ai-paths-runtime';

import {
  appendInputValue,
  getPortDataTypes,
  getResolvedNodeInputPortContract,
  isValueCompatibleWithTypes,
} from '../utils';
import { resolveEdgeFromNodeId, resolveEdgeFromPort, resolveEdgeToPort } from './engine-utils';

export function collectNodeInputs(
  node: AiNode,
  currentOutputs: Record<string, RuntimePortValues>,
  incomingEdgesByNode: Map<string, Edge[]>
): RuntimePortValues {
  const incoming = incomingEdgesByNode.get(node.id) ?? [];
  if (incoming.length === 0) return {};
  const collected: RuntimePortValues = {};
  incoming.forEach((edge: Edge) => {
    const fromNodeId = resolveEdgeFromNodeId(edge);
    if (!fromNodeId) return;
    const fromOutput = currentOutputs[fromNodeId];
    const fromPort = resolveEdgeFromPort(edge);
    const toPort = resolveEdgeToPort(edge);
    if (!fromOutput || !fromPort || !toPort) return;
    const value = fromOutput[fromPort];
    if (value === undefined) return;
    const inputContract = getResolvedNodeInputPortContract(node, toPort);
    const hasExplicitRuntimeContract =
      inputContract.kind !== 'unknown' ||
      inputContract.schema !== undefined ||
      inputContract.schemaRef !== undefined;
    if (!hasExplicitRuntimeContract) {
      const expectedTypes = getPortDataTypes(toPort);
      if (!isValueCompatibleWithTypes(value, expectedTypes)) return;
    }
    const existing = collected[toPort];
    collected[toPort] = appendInputValue(existing, value);
  });
  return collected;
}

import { type AiNode } from '@/shared/contracts/ai-paths';
import { type RuntimePortValues } from '@/shared/contracts/ai-paths-runtime';

import { pickString, readEntityIdFromContext, readEntityTypeFromContext } from './engine-utils';

export function deriveNodeInputs(args: {
  node: AiNode;
  rawInputs: RuntimePortValues;
  triggerContext: Record<string, unknown> | null;
  checkTriggerProvenance: () => boolean;
}): RuntimePortValues {
  const { node, rawInputs, triggerContext, checkTriggerProvenance } = args;
  const next = { ...rawInputs };
  if (node.type === 'database') {
    if (!pickString(next['entityId'])) {
      const triggerEntityId =
        pickString(triggerContext?.['productId']) ?? pickString(triggerContext?.['entityId']);
      if (triggerEntityId) {
        next['entityId'] = triggerEntityId;
      }
    }
    if (!pickString(next['entityType'])) {
      const triggerEntityType =
        pickString(triggerContext?.['entityType']) ??
        (pickString(triggerContext?.['productId']) ? 'product' : undefined);
      if (triggerEntityType) {
        next['entityType'] = triggerEntityType;
      }
    }
  }
  if (node.type === 'model' || node.type === 'prompt') {
    const contextEntityId = readEntityIdFromContext(next);
    const contextEntityType = readEntityTypeFromContext(next);
    if (contextEntityId && contextEntityType && checkTriggerProvenance()) {
      const inheritedContextSource =
        typeof triggerContext?.['contextSource'] === 'string'
          ? triggerContext['contextSource']
          : null;
      const currentContext = (next['context'] as Record<string, unknown>) ?? {};
      next['context'] = {
        ...currentContext,
        entityId: contextEntityId,
        entityType: contextEntityType,
        contextSource: inheritedContextSource ?? 'simulation',
        provenance: 'trigger_simulation',
      };
    }
  }
  return next;
}

import { type AiNode, type Edge } from '@/shared/contracts/ai-paths';

import { resolveEdgeToNodeId } from './engine-utils';

export function resolveScopedNodeIds(args: {
  nodes: AiNode[];
  triggerNodeId: string | null | undefined;
  nodeById: Map<string, AiNode>;
  outgoingEdgesByNode: Map<string, Edge[]>;
  incomingEdgesByNode: Map<string, Edge[]>;
  seedHashes: Record<string, string>;
}): Set<string> {
  const { nodes, triggerNodeId, nodeById, outgoingEdgesByNode } = args;

  if (!triggerNodeId || !nodeById.has(triggerNodeId)) {
    return new Set(nodes.map((node) => node.id));
  }

  const reachable = new Set<string>();
  const stack = [triggerNodeId];

  // Forward reachability
  while (stack.length > 0) {
    const current = stack.pop();
    if (!current || reachable.has(current)) continue;
    reachable.add(current);
    const outgoing = outgoingEdgesByNode.get(current) ?? [];
    outgoing.forEach((edge) => {
      const toNodeId = resolveEdgeToNodeId(edge);
      if (toNodeId && !reachable.has(toNodeId)) {
        stack.push(toNodeId);
      }
    });
  }

  // Include seeded nodes
  Object.keys(args.seedHashes).forEach((nodeId) => {
    reachable.add(nodeId);
  });

  return reachable;
}

import { type AiNode } from '@/shared/contracts/ai-paths';
import { type RuntimePortValues } from '@/shared/contracts/ai-paths-runtime';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { DEFAULT_RETRY_BACKOFF_MS } from '../execution-helpers';
import { type EngineStateManager } from './engine-state-manager';

export type RuntimeRetryPolicy = {
  enabled: boolean;
  attempts: number;
  backoffMs: number;
};

export const readRuntimeRetryPolicy = (node: AiNode): RuntimeRetryPolicy => {
  const runtimeConfig = node.config?.runtime;
  if (!isObjectRecord(runtimeConfig)) {
    return {
      enabled: false,
      attempts: 1,
      backoffMs: DEFAULT_RETRY_BACKOFF_MS,
    };
  }

  const retryConfig = runtimeConfig['retry'];
  if (!isObjectRecord(retryConfig)) {
    return {
      enabled: false,
      attempts: 1,
      backoffMs: DEFAULT_RETRY_BACKOFF_MS,
    };
  }

  const attemptsValue =
    typeof retryConfig['attempts'] === 'number' && Number.isFinite(retryConfig['attempts'])
      ? Math.max(1, Math.trunc(retryConfig['attempts']))
      : 1;
  const backoffValue =
    typeof retryConfig['backoffMs'] === 'number' && Number.isFinite(retryConfig['backoffMs'])
      ? Math.max(0, Math.trunc(retryConfig['backoffMs']))
      : DEFAULT_RETRY_BACKOFF_MS;
  const isRetryEnabled = attemptsValue > 1;

  return {
    enabled: isRetryEnabled,
    attempts: attemptsValue,
    backoffMs: backoffValue,
  };
};

export const resolveRecoverableNodeWaitState = (
  node: AiNode,
  error: unknown
): { message: string; waitingOnPorts: string[] } | null => {
  if (node.type !== 'fetcher') return null;
  const message = error instanceof Error ? error.message : String(error ?? '');
  if (!message) return null;
  const normalizedMessage = message.trim();
  if (!normalizedMessage) return null;

  if (
    normalizedMessage.includes('Simulated entity by ID') &&
    normalizedMessage.includes('no entity ID is configured')
  ) {
    return {
      message: normalizedMessage,
      waitingOnPorts: ['entityId'],
    };
  }

  if (
    normalizedMessage.toLowerCase().includes('could not hydrate') &&
    normalizedMessage.toLowerCase().includes('fetcher')
  ) {
    return {
      message: normalizedMessage,
      waitingOnPorts: ['entityId', 'entityType'],
    };
  }

  return null;
};

export const resolveBlockedNodeStatus = (
  outputs: RuntimePortValues | undefined
): 'blocked' | 'waiting_callback' => {
  const rawStatus =
    typeof outputs?.['status'] === 'string' ? String(outputs['status']).trim().toLowerCase() : '';
  return rawStatus === 'waiting_callback' || rawStatus === 'advance_pending'
    ? 'waiting_callback'
    : 'blocked';
};

export const resolveDeclaredNodeStatus = (
  outputs: RuntimePortValues | undefined
): string | null => {
  const rawStatus =
    typeof outputs?.['status'] === 'string' ? String(outputs['status']).trim().toLowerCase() : '';
  if (!rawStatus) return null;
  if (rawStatus === 'cancelled') return 'canceled';
  if (rawStatus === 'advance_pending') return 'waiting_callback';
  if (rawStatus === 'error') return 'failed';
  return rawStatus;
};

export const applyCachedNodeRuntimeStatus = (
  state: EngineStateManager,
  nodeId: string,
  outputs: RuntimePortValues
): void => {
  const rawStatus =
    typeof outputs['status'] === 'string' ? String(outputs['status']).trim().toLowerCase() : '';

  if (rawStatus === 'failed' || rawStatus === 'timeout' || rawStatus === 'error') {
    state.errorNodes.add(nodeId);
    if (rawStatus === 'timeout') {
      state.timeoutNodes.add(nodeId);
    } else {
      state.timeoutNodes.delete(nodeId);
    }
    state.finishedNodes.delete(nodeId);
    state.blockedNodes.delete(nodeId);
    return;
  }

  if (
    rawStatus === 'blocked' ||
    rawStatus === 'waiting_callback' ||
    rawStatus === 'advance_pending'
  ) {
    state.blockedNodes.add(nodeId);
    state.finishedNodes.delete(nodeId);
    state.errorNodes.delete(nodeId);
    state.timeoutNodes.delete(nodeId);
    return;
  }

  state.finishedNodes.add(nodeId);
  state.blockedNodes.delete(nodeId);
  state.errorNodes.delete(nodeId);
  state.timeoutNodes.delete(nodeId);
};

import { type AiNode, type Edge, type NodeCacheScope } from '@/shared/contracts/ai-paths';
