const resolveEdgeNodeId = (value: string | undefined): string | null => {
  const normalized = typeof value === 'string' ? value.trim() : '';
  return normalized.length > 0 ? normalized : null;
};

export const pickString = (val: unknown): string | undefined =>
  typeof val === 'string' && val.trim().length > 0 ? val.trim() : undefined;

export const readEntityTypeFromContext = (context: Record<string, unknown>): string | null => {
  const type = pickString(context['entityType']);
  if (type) return type;
  if (pickString(context['productId'])) return 'product';
  return null;
};

export const readEntityIdFromContext = (context: Record<string, unknown>): string | null =>
  pickString(context['productId']) ?? pickString(context['entityId']) ?? null;

export const resolveEdgeFromNodeId = (edge: Edge): string | null => resolveEdgeNodeId(edge.from);

export const resolveEdgeToNodeId = (edge: Edge): string | null => resolveEdgeNodeId(edge.to);

const resolveEdgePort = (value: string | null | undefined): string | null => {
  const normalized = typeof value === 'string' ? normalizePortName(value) : '';
  return normalized.length > 0 ? normalized : null;
};

export const resolveEdgeFromPort = (edge: Edge): string | null => resolveEdgePort(edge.fromPort);

export const resolveEdgeToPort = (edge: Edge): string | null => resolveEdgePort(edge.toPort);

export const checkContextMatchesSimulation = (context: Record<string, unknown>): boolean => {
  const contextSource = context['contextSource'];
  if (
    typeof contextSource === 'string' &&
    contextSource.trim().toLowerCase().startsWith('simulation')
  ) {
    return true;
  }
  const source = context['source'];
  if (typeof source === 'string' && source.trim().toLowerCase() === 'simulation') {
    return true;
  }
  return false;
};

export const hasValuableSimulationContext = (context: Record<string, unknown>): boolean => {
  return Boolean(readEntityIdFromContext(context) && readEntityTypeFromContext(context));
};

export const isSimulationCapableFetcher = (node: AiNode): boolean => {
  if (node.type !== 'fetcher') return false;
  const mode = node.config?.fetcher?.sourceMode;
  return mode === 'simulation_id' || mode === 'live_then_simulation';
};

export const hasMeaningfulValue = (value: unknown): boolean => {
  if (value === undefined || value === null) return false;
  if (typeof value === 'string') return value.trim().length > 0;
  if (Array.isArray(value)) return value.length > 0;
  if (typeof value === 'object') return Object.keys(value as Record<string, unknown>).length > 0;
  return true;
};

export const orderNodesByDependencies = (nodes: AiNode[], edges: Edge[]): AiNode[] => {
  const nodeById = new Map(nodes.map((n) => [n.id, n]));
  const adj = new Map<string, string[]>();
  const inDegree = new Map<string, number>();

  nodes.forEach((n) => {
    adj.set(n.id, []);
    inDegree.set(n.id, 0);
  });

  edges.forEach((e) => {
    const fromNodeId = resolveEdgeFromNodeId(e);
    const toNodeId = resolveEdgeToNodeId(e);
    if (!fromNodeId || !toNodeId) return;
    if (nodeById.has(fromNodeId) && nodeById.has(toNodeId)) {
      adj.get(fromNodeId)?.push(toNodeId);
      inDegree.set(toNodeId, (inDegree.get(toNodeId) ?? 0) + 1);
    }
  });

  const queue: string[] = [];
  inDegree.forEach((degree, id) => {
    if (degree === 0) queue.push(id);
  });

  const result: AiNode[] = [];
  while (queue.length > 0) {
    const u = queue.shift()!;
    const node = nodeById.get(u);
    if (node) result.push(node);

    adj.get(u)?.forEach((v) => {
      const nextDegree = (inDegree.get(v) ?? 0) - 1;
      inDegree.set(v, nextDegree);
      if (nextDegree === 0) queue.push(v);
    });
  }

  if (result.length !== nodes.length) {
    const missing = nodes.filter((n) => !result.find((r) => r.id === n.id));
    return [...result, ...missing];
  }

  return result;
};

export const buildInputLinks = (
  nodeId: string,
  edges: Edge[],
  nodeById: Map<string, AiNode>,
  nodeInputs: Record<string, unknown>
): RuntimeHistoryLink[] => {
  const incoming = edges.filter((e) => resolveEdgeToNodeId(e) === nodeId);
  const hasInputs = Object.keys(nodeInputs).length > 0;
  return incoming
    .map((edge: Edge): RuntimeHistoryLink | null => {
      const fromNodeId = resolveEdgeFromNodeId(edge);
      if (!fromNodeId) return null;
      const toPort = resolveEdgeToPort(edge);
      const isPresent = toPort ? nodeInputs[toPort] !== undefined : hasInputs;
      if (!isPresent) return null;
      const fromNode = nodeById.get(fromNodeId);
      return {
        nodeId: fromNodeId,
        nodeType: fromNode?.type ?? null,
        nodeTitle: fromNode?.title ?? null,
        fromPort: resolveEdgeFromPort(edge),
        toPort,
      };
    })
    .filter((link: RuntimeHistoryLink | null): link is RuntimeHistoryLink => Boolean(link));
};

export const buildOutputLinks = (
  nodeId: string,
  edges: Edge[],
  nodeById: Map<string, AiNode>,
  nodeOutputs: Record<string, unknown>
): RuntimeHistoryLink[] => {
  const outgoing = edges.filter((e) => resolveEdgeFromNodeId(e) === nodeId);
  const hasOutputs = Object.keys(nodeOutputs).length > 0;
  return outgoing
    .map((edge: Edge): RuntimeHistoryLink | null => {
      const toNodeId = resolveEdgeToNodeId(edge);
      if (!toNodeId) return null;
      const fromPort = resolveEdgeFromPort(edge);
      const isPresent = fromPort ? nodeOutputs[fromPort] !== undefined : hasOutputs;
      if (!isPresent) return null;
      const toNode = nodeById.get(toNodeId);
      return {
        nodeId: toNodeId,
        nodeType: toNode?.type ?? null,
        nodeTitle: toNode?.title ?? null,
        fromPort,
        toPort: resolveEdgeToPort(edge),
      };
    })
    .filter((link: RuntimeHistoryLink | null): link is RuntimeHistoryLink => Boolean(link));
};

export const resolveConfiguredRequiredInputPorts = (
  node: AiNode,
  connectedPorts: Set<string>
): string[] => {
  const configuredPorts = new Set<string>([
    ...Object.keys(node.inputContracts ?? {}),
    ...Object.keys(node.config?.runtime?.inputContracts ?? {}),
    ...Array.from(connectedPorts),
  ]);
  (node.inputs ?? []).forEach((port: string): void => {
    configuredPorts.add(port);
  });
  const explicitRequired = Array.from(configuredPorts).filter(
    (port: string): boolean => getNodeInputPortContract(node, port).required === true
  );
  return explicitRequired;
};

const PROMPT_TEMPLATE_TOKEN_PATTERN = /{{\s*([^}]+)\s*}}|\[\s*([A-Za-z0-9_.$:-]+)\s*\]/g;

const createPromptTemplateTokenPattern = (): RegExp =>
  new RegExp(PROMPT_TEMPLATE_TOKEN_PATTERN.source, PROMPT_TEMPLATE_TOKEN_PATTERN.flags);

const extractPromptTemplateTokens = (template: string): string[] =>
  Array.from(template.matchAll(createPromptTemplateTokenPattern()))
    .map((match) => String(match[1] ?? match[2] ?? '').trim())
    .filter((token: string): boolean => token.length > 0);

const resolveTemplateRootPorts = (template: string, connectedPorts: Set<string>): string[] => {
  const roots = extractPromptTemplateTokens(template)
    .map((token: string): string => token.split(/[.\[\]:]/)[0]?.trim() ?? '')
    .filter((root: string): boolean => root.length > 0 && connectedPorts.has(root));
  return Array.from(new Set(roots));
};

const resolvePromptTemplateTopLevelPort = (token: string): string =>
  normalizePortName(token.split('.')[0] ?? token);

const hasPromptTemplateTokens = (template: string): boolean =>
  createPromptTemplateTokenPattern().test(template);

const resolvePromptTemplateRequiredPorts = (
  template: string,
  connectedPorts: Set<string>
): string[] => {
  if (!template.trim()) return [];

  return Array.from(
    new Set<string>(
      extractPromptTemplateTokens(template)
        .map(resolvePromptTemplateTopLevelPort)
        .filter((port: string): boolean => port.length > 0 && connectedPorts.has(port))
    )
  );
};

export const buildWaitingOnDetails = (
  _node: AiNode,
  waitingPorts: Set<string>,
  incomingEdges: Edge[],
  nodeById: Map<string, AiNode>,
  nodeStatusGetter: (id: string) => string,
  nodeOutputsGetter: (id: string) => Record<string, unknown>
): NodeInputReadiness['waitingOnDetails'] => {
  if (waitingPorts.size === 0) return [];
  const detailsByPort = new Map<
    string,
    {
      port: string;
      upstream: Array<{
        nodeId: string;
        nodeType: string | null;
        nodeTitle: string | null;
        sourcePort: string | null;
        status: string;
        blockedReason?: string;
        waitingOnPorts?: string[];
      }>;
    }
  >();

  waitingPorts.forEach((port) => {
    detailsByPort.set(port, { port, upstream: [] });
  });

  incomingEdges.forEach((edge) => {
    const port = resolveEdgeToPort(edge);
    if (!port || !waitingPorts.has(port)) return;
    const detail = detailsByPort.get(port);
    if (!detail) return;

    const sourceNodeId = resolveEdgeFromNodeId(edge);
    if (!sourceNodeId) return;
    const sourceNode = nodeById.get(sourceNodeId);
    const status = nodeStatusGetter(sourceNodeId);
    const sourceOutputs = nodeOutputsGetter(sourceNodeId);
    const rawWaitingOnPorts = sourceOutputs['waitingOnPorts'];

    detail.upstream.push({
      nodeId: sourceNodeId,
      nodeType: sourceNode?.type ?? null,
      nodeTitle: sourceNode?.title ?? null,
      sourcePort: resolveEdgeFromPort(edge),
      status,
      ...(typeof sourceOutputs['blockedReason'] === 'string'
        ? { blockedReason: sourceOutputs['blockedReason'] }
        : {}),
      ...(Array.isArray(rawWaitingOnPorts)
        ? {
          waitingOnPorts: rawWaitingOnPorts
            .filter((p: unknown): p is string => typeof p === 'string')
            .map((p: string): string => p.trim())
            .filter((p: string): boolean => p.length > 0),
        }
        : {}),
    });
  });

  return Array.from(detailsByPort.values()).map((detail) => ({
    ...detail,
    upstream: detail.upstream.sort((left, right) => left.nodeId.localeCompare(right.nodeId)),
  }));
};

export const resolveMissingInputStatus = (input: {
  waitingOnDetails: Array<{
    upstream: Array<{
      status: string;
      blockedReason?: string;
      waitingOnPorts?: string[];
    }>;
  }>;
}): 'blocked' | 'waiting_callback' => {
  const hasTransientUpstream = input.waitingOnDetails.some((detail) =>
    detail.upstream.some((upstream) => {
      const status = upstream.status.trim().toLowerCase();
      if (TRANSIENT_UPSTREAM_WAIT_STATUSES.has(status)) {
        return true;
      }
      if (status !== 'blocked') {
        return false;
      }
      const blockedReason =
        typeof upstream.blockedReason === 'string'
          ? upstream.blockedReason.trim().toLowerCase()
          : '';
      const hasWaitingPorts =
        Array.isArray(upstream.waitingOnPorts) &&
        upstream.waitingOnPorts.some(
          (port: unknown): boolean => typeof port === 'string' && port.trim().length > 0
        );
      return blockedReason === 'missing_inputs' || hasWaitingPorts;
    })
  );
  return hasTransientUpstream ? 'waiting_callback' : 'blocked';
};

export const evaluateInputReadiness = (
  node: AiNode,
  rawInputs: RuntimePortValues,
  incomingEdges: Edge[],
  nodeById: Map<string, AiNode>,
  nodeStatusGetter: (id: string) => string,
  nodeOutputsGetter: (id: string) => Record<string, unknown>
): NodeInputReadiness => {
  const buildWaitingDetails = (ports: Set<string>) =>
    buildWaitingOnDetails(
      node,
      ports,
      incomingEdges,
      nodeById,
      nodeStatusGetter,
      nodeOutputsGetter
    );

  if (incomingEdges.length === 0) {
    const requiredPorts = resolveConfiguredRequiredInputPorts(node, new Set<string>());
    if (requiredPorts.length > 0) {
      const waitingOnPorts = requiredPorts.filter(
        (port: string): boolean => rawInputs[port] === undefined
      );
      return {
        ready: waitingOnPorts.length === 0,
        requiredPorts,
        optionalPorts: [],
        waitingOnPorts,
        waitingOnDetails: buildWaitingDetails(new Set(waitingOnPorts)),
      };
    }
    return {
      ready: true,
      requiredPorts: [],
      optionalPorts: [],
      waitingOnPorts: [],
      waitingOnDetails: [],
    };
  }

  const connectedPorts = new Set<string>();
  incomingEdges.forEach((edge: Edge) => {
    const port = resolveEdgeToPort(edge);
    if (port) connectedPorts.add(port);
  });
  const connectedPortList = Array.from(connectedPorts);

  if (connectedPorts.size === 0) {
    const requiredPorts = resolveConfiguredRequiredInputPorts(node, connectedPorts);
    if (requiredPorts.length > 0) {
      const waitingOnPorts = requiredPorts.filter(
        (port: string): boolean => rawInputs[port] === undefined
      );
      return {
        ready: waitingOnPorts.length === 0,
        requiredPorts,
        optionalPorts: [],
        waitingOnPorts,
        waitingOnDetails: buildWaitingDetails(new Set(waitingOnPorts)),
      };
    }
    return {
      ready: true,
      requiredPorts: [],
      optionalPorts: [],
      waitingOnPorts: [],
      waitingOnDetails: [],
    };
  }

  const explicitRequiredPorts = resolveConfiguredRequiredInputPorts(node, connectedPorts);

  if (node.type === 'prompt' && explicitRequiredPorts.length === 0) {
    const promptTemplate =
      typeof node.config?.prompt?.template === 'string' ? node.config.prompt.template.trim() : '';
    const templateRequiredPorts = resolvePromptTemplateRequiredPorts(
      promptTemplate,
      connectedPorts
    );
    const hasDynamicTemplateToken = hasPromptTemplateTokens(promptTemplate);
    if (templateRequiredPorts.length > 0) {
      const requiredPortSet = new Set<string>(templateRequiredPorts);
      const optionalPorts = connectedPortList.filter(
        (port: string): boolean => !requiredPortSet.has(port)
      );
      const waitingOnPorts = templateRequiredPorts.filter(
        (port: string): boolean => rawInputs[port] === undefined
      );
      return {
        ready: waitingOnPorts.length === 0,
        requiredPorts: templateRequiredPorts,
        optionalPorts,
        waitingOnPorts,
        waitingOnDetails: buildWaitingDetails(new Set(waitingOnPorts)),
      };
    }

    const hasAnyConnectedValue = connectedPortList.some((port: string): boolean =>
      hasMeaningfulValue(coerceInput(rawInputs[port]))
    );

    if (hasAnyConnectedValue) {
      return {
        ready: true,
        requiredPorts: [],
        optionalPorts: connectedPortList,
        waitingOnPorts: [],
        waitingOnDetails: [],
      };
    }

    // Prompt nodes with upstream wiring should not execute on empty placeholder data.
    // Wait when there is no template or when the template depends on runtime tokens.
    if (!promptTemplate || hasDynamicTemplateToken) {
      const waitingOnPorts = new Set<string>(connectedPortList);
      return {
        ready: false,
        requiredPorts: connectedPortList,
        optionalPorts: [],
        waitingOnPorts: Array.from(waitingOnPorts),
        waitingOnDetails: buildWaitingDetails(waitingOnPorts),
      };
    }

    // Static templates are allowed to run without upstream values.
    return {
      ready: true,
      requiredPorts: [],
      optionalPorts: connectedPortList,
      waitingOnPorts: [],
      waitingOnDetails: [],
    };
  }

  const requiredPorts =
    explicitRequiredPorts.length > 0 ? explicitRequiredPorts : connectedPortList;
  const requiredPortSet = new Set(requiredPorts);
  const optionalPorts = connectedPortList.filter(
    (port: string): boolean => !requiredPortSet.has(port)
  );
  const waitingOnPorts = new Set<string>();

  const toReadiness = (ready: boolean): NodeInputReadiness => ({
    ready,
    requiredPorts,
    optionalPorts,
    waitingOnPorts: Array.from(waitingOnPorts),
    waitingOnDetails: buildWaitingDetails(waitingOnPorts),
  });

  if (explicitRequiredPorts.length > 0) {
    explicitRequiredPorts.forEach((port: string): void => {
      const value = rawInputs[port];
      if (value === undefined) {
        waitingOnPorts.add(port);
      }
    });
    if (waitingOnPorts.size > 0) {
      return toReadiness(false);
    }
  }

  if (node.type !== 'database') {
    requiredPorts.forEach((port: string): void => {
      if (rawInputs[port] === undefined) {
        waitingOnPorts.add(port);
      }
    });
    return toReadiness(waitingOnPorts.size === 0);
  }

  const dbConfig = node.config?.database ?? { operation: 'query' };
  const operation = dbConfig.operation ?? 'query';
  const hasAnyValue = (ports: string[]): boolean =>
    ports.some((port: string) => hasMeaningfulValue(coerceInput(rawInputs[port])));
  const anyConnected = (ports: string[]): boolean =>
    ports.some((port: string) => connectedPorts.has(port));
  const allConnectedHaveValues = (ports: string[]): boolean =>
    ports.every(
      (port: string) =>
        !connectedPorts.has(port) || hasMeaningfulValue(coerceInput(rawInputs[port]))
    );
  const markWaitingPorts = (ports: string[], connectedOnly: boolean): void => {
    ports.forEach((port: string): void => {
      if (connectedOnly && !connectedPorts.has(port)) return;
      if (!hasMeaningfulValue(coerceInput(rawInputs[port]))) {
        waitingOnPorts.add(port);
      }
    });
  };

  if (operation === 'query') {
    const queryPorts = ['aiQuery', 'query', 'queryCallback'];
    if (anyConnected(queryPorts) && !hasAnyValue(queryPorts)) {
      markWaitingPorts(queryPorts, true);
    }
    const nonQueryPorts = Array.from(connectedPorts).filter(
      (port: string) => !queryPorts.includes(port)
    );
    if (!allConnectedHaveValues(nonQueryPorts)) {
      markWaitingPorts(nonQueryPorts, true);
    }
    return toReadiness(waitingOnPorts.size === 0);
  }

  if (operation === 'delete') {
    const idPorts = ['entityId', 'productId', 'value'];
    if (anyConnected(idPorts) && !hasAnyValue(idPorts)) {
      markWaitingPorts(idPorts, true);
    }
    return toReadiness(waitingOnPorts.size === 0);
  }

  if (operation === 'insert') {
    const templatePayload =
      typeof dbConfig.query?.queryTemplate === 'string' ? dbConfig.query.queryTemplate.trim() : '';
    const hasTemplatePayload = templatePayload.length > 0;
    if (hasTemplatePayload) {
      const templateRequiredPorts = resolveTemplateRootPorts(templatePayload, connectedPorts);
      if (templateRequiredPorts.length > 0) {
        markWaitingPorts(templateRequiredPorts, false);
        return toReadiness(waitingOnPorts.size === 0);
      }
      return toReadiness(true);
    }
    const payloadPorts = ['value', 'payload'];
    if (anyConnected(payloadPorts) && !hasAnyValue(payloadPorts)) {
      markWaitingPorts(payloadPorts, true);
    }
    return toReadiness(waitingOnPorts.size === 0);
  }

  if (operation === 'update' || operation === 'action') {
    const idPorts = ['entityId', 'productId'];
    if (anyConnected(idPorts) && !hasAnyValue(idPorts)) {
      markWaitingPorts(idPorts, true);
    }
    const payloadPorts = ['value', 'payload', 'params', 'query', 'queryCallback', 'aiQuery'];
    const mappings = Array.isArray(dbConfig.mappings) ? dbConfig.mappings : [];
    const sourcePorts = mappings
      .map((m) => m?.sourcePort)
      .filter((p): p is string => typeof p === 'string' && p.trim().length > 0);

    const allPayloadPorts = [...payloadPorts, ...sourcePorts];
    if (anyConnected(allPayloadPorts) && !hasAnyValue(allPayloadPorts)) {
      markWaitingPorts(allPayloadPorts, true);
    }
    return toReadiness(waitingOnPorts.size === 0);
  }

  return toReadiness(true);
};

export function collectNodeInputs(
  toNodeId: string,
  outputs: Record<string, RuntimePortValues>,
  incomingEdgesByNode: Map<string, Edge[]>
): RuntimePortValues {
  const incoming = incomingEdgesByNode.get(toNodeId) ?? [];
  const collected: RuntimePortValues = {};
  incoming.forEach((edge) => {
    const fromId = edge.from || edge.source;
    if (!fromId) return;
    const fromPort = edge.fromPort || 'result';
    const toPort = edge.toPort || 'value';
    const out = outputs[fromId];
    if (out?.[fromPort] !== undefined) {
      collected[toPort] = out[fromPort];
    } else if (out && !edge.fromPort) {
      // Heuristic fallback: when no explicit fromPort was specified and the default 'result'
      // missed, try a fallback ONLY when the source has exactly one non-metadata output key
      // (unambiguous case). This handles handlers that output on ports like 'trigger', 'context',
      // 'prompt' instead of 'result'.
      const STATUS_KEYS = new Set(['status', 'skipReason', 'blockedReason', 'message', 'error']);
      const candidateKeys = Object.keys(out).filter((k) => !STATUS_KEYS.has(k) && out[k] !== undefined);
      if (candidateKeys.length === 1) {
        collected[toPort] = out[candidateKeys[0]!];
        if (AI_PATHS_TRACE_INPUT_COLLECTION) {
          logClientError(
            new Error(
              `[ai-paths:input-collection] Port fallback: node=${toNodeId} fromNode=${fromId} defaultPort=result -> fallbackPort=${candidateKeys[0]} toPort=${toPort}`
            )
          );
        }
      } else if (AI_PATHS_TRACE_INPUT_COLLECTION) {
        const availableKeys = Object.keys(out).join(', ');
        logClientError(
          new Error(
            `[ai-paths:input-collection] Edge miss (ambiguous fallback, ${candidateKeys.length} candidates): node=${toNodeId} fromNode=${fromId} fromPort=${fromPort} toPort=${toPort}. Available output keys: ${availableKeys}`
          )
        );
      }
    } else if (AI_PATHS_TRACE_INPUT_COLLECTION) {
      const availableKeys = out ? Object.keys(out).join(', ') : '(no outputs)';
      logClientError(
        new Error(
          `[ai-paths:input-collection] Edge miss: node=${toNodeId} fromNode=${fromId} fromPort=${fromPort} toPort=${toPort}. Available output keys: ${availableKeys}`
        )
      );
    }
  });
  return collected;
}

import { type AiNode, type Edge, type RuntimePortValues } from '@/shared/contracts/ai-paths';
import { type RuntimeHistoryEntry } from '@/shared/contracts/ai-paths-runtime';

import { cloneValue } from '../utils';
import { type EngineStateManager } from './engine-state-manager';
import {
  type EvaluateGraphOptions,
  type RuntimeValidationIssue,
  type RuntimeValidationResult,
  type RuntimeValidationStage,
  type RuntimeNodeResolutionTelemetry,
} from './engine-types';
import { buildInputLinks } from './engine-utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const buildRuntimeTelemetryFields = (
  telemetry: RuntimeNodeResolutionTelemetry | null
): {
  runtimeStrategy?: RuntimeNodeResolutionTelemetry['runtimeStrategy'];
  runtimeResolutionSource?: RuntimeNodeResolutionTelemetry['runtimeResolutionSource'];
  runtimeCodeObjectId?: string | null;
} =>
  telemetry
    ? {
      runtimeStrategy: telemetry.runtimeStrategy,
      runtimeResolutionSource: telemetry.runtimeResolutionSource,
      runtimeCodeObjectId: telemetry.runtimeCodeObjectId ?? null,
    }
    : {};

export const normalizeRuntimeValidationIssues = (
  issues: RuntimeValidationIssue[] | undefined,
  stage: RuntimeValidationStage,
  node: AiNode | null
): RuntimeValidationIssue[] => {
  if (!Array.isArray(issues)) return [];
  return issues
    .filter((issue: RuntimeValidationIssue | null | undefined): issue is RuntimeValidationIssue => {
      if (!issue) return false;
      return typeof issue.message === 'string' && issue.message.trim().length > 0;
    })
    .map(
      (issue: RuntimeValidationIssue): RuntimeValidationIssue => ({
        ...issue,
        stage,
        nodeId: issue.nodeId ?? node?.id ?? null,
        nodeTitle: issue.nodeTitle ?? node?.title ?? null,
      })
    );
};

export type RunRuntimeValidationArgs = {
  stage: RuntimeValidationStage;
  iteration: number;
  node?: AiNode | null;
  nodeInputs?: RuntimePortValues;
  nodeOutputs?: RuntimePortValues;
  runtimeTelemetry?: RuntimeNodeResolutionTelemetry | null;
  options: EvaluateGraphOptions;
  resolvedRunId: string;
  resolvedRunStartedAt: string;
  nodes: AiNode[];
  sanitizedEdges: Edge[];
};

type RuntimeValidationMiddlewareResult = RuntimeValidationResult | null | undefined;

const executeRuntimeValidationMiddleware = async (
  args: RunRuntimeValidationArgs,
  validationMiddleware: NonNullable<EvaluateGraphOptions['validationMiddleware']>
): Promise<RuntimeValidationMiddlewareResult> => {
  const {
    stage,
    node = null,
    resolvedRunId,
    resolvedRunStartedAt,
    nodes,
    sanitizedEdges,
  } = args;
  const context: Parameters<NonNullable<EvaluateGraphOptions['validationMiddleware']>>[0] = {
    stage,
    runId: resolvedRunId,
    runStartedAt: resolvedRunStartedAt,
    iteration: args.iteration,
    node,
    nodeInputs: args.nodeInputs,
    nodeOutputs: args.nodeOutputs,
    nodes,
    edges: sanitizedEdges,
  };

  try {
    return await validationMiddleware(context);
  } catch (error) {
    logClientError(error);
    args.options.reportAiPathsError(error, {
      action: 'runtime_validation_middleware',
      stage,
      nodeId: node?.id ?? null,
      iteration: args.iteration,
      runId: resolvedRunId,
    });
    throw error;
  }
};

const resolveRuntimeValidationDecision = (
  validationResult: Exclude<RuntimeValidationMiddlewareResult, null | undefined>
): 'warn' | 'block' => (validationResult.decision === 'block' ? 'block' : 'warn');

const buildRuntimeValidationFallbackMessage = (args: {
  decision: 'warn' | 'block';
  node: AiNode | null;
  stage: RuntimeValidationStage;
}): string =>
  args.decision === 'block'
    ? `Runtime validation blocked ${args.node ? `node ${args.node.id}` : 'graph'} at stage ${args.stage}.`
    : `Runtime validation warning for ${args.node ? `node ${args.node.id}` : 'graph'} at stage ${args.stage}.`;

const resolveRuntimeValidationMessage = (args: {
  validationResult: Exclude<RuntimeValidationMiddlewareResult, null | undefined>;
  decision: 'warn' | 'block';
  issues: RuntimeValidationIssue[];
  node: AiNode | null;
  stage: RuntimeValidationStage;
}): string => {
  const message = args.validationResult.message;
  if (typeof message === 'string' && message.trim().length > 0) {
    return message.trim();
  }

  return (
    args.issues[0]?.message ??
    buildRuntimeValidationFallbackMessage({
      decision: args.decision,
      node: args.node,
      stage: args.stage,
    })
  );
};

const notifyRuntimeValidation = async (args: {
  options: EvaluateGraphOptions;
  resolvedRunId: string;
  resolvedRunStartedAt: string;
  iteration: number;
  stage: RuntimeValidationStage;
  decision: 'warn' | 'block';
  node: AiNode | null;
  nodeInputs?: RuntimePortValues;
  nodeOutputs?: RuntimePortValues;
  message: string;
  issues: RuntimeValidationIssue[];
  runtimeTelemetry?: RuntimeNodeResolutionTelemetry | null;
}): Promise<void> => {
  if (!args.options.onRuntimeValidation) {
    return;
  }

  try {
    await args.options.onRuntimeValidation({
      runId: args.resolvedRunId,
      runStartedAt: args.resolvedRunStartedAt,
      iteration: args.iteration,
      stage: args.stage,
      decision: args.decision,
      node: args.node,
      nodeInputs: args.nodeInputs,
      nodeOutputs: args.nodeOutputs,
      message: args.message,
      issues: args.issues,
      ...buildRuntimeTelemetryFields(args.runtimeTelemetry ?? null),
    });
  } catch (error) {
    logClientError(error);
    args.options.reportAiPathsError(error, {
      action: 'onRuntimeValidation',
      stage: args.stage,
      nodeId: args.node?.id ?? null,
      iteration: args.iteration,
      runId: args.resolvedRunId,
    });
  }
};

export const runRuntimeValidation = async (
  args: RunRuntimeValidationArgs
): Promise<{
  decision: 'warn' | 'block';
  message: string;
  issues: RuntimeValidationIssue[];
} | null> => {
  const {
    options,
    stage,
    node = null,
    resolvedRunId,
    resolvedRunStartedAt,
  } = args;
  if (!options.validationMiddleware) return null;

  const validationResult = await executeRuntimeValidationMiddleware(
    args,
    options.validationMiddleware
  );
  if (!validationResult || validationResult.decision === 'pass') {
    return null;
  }

  const decision = resolveRuntimeValidationDecision(validationResult);
  const issues = normalizeRuntimeValidationIssues(validationResult.issues, stage, node);
  const message = resolveRuntimeValidationMessage({
    validationResult,
    decision,
    issues,
    node,
    stage,
  });

  await notifyRuntimeValidation({
    options,
    resolvedRunId,
    resolvedRunStartedAt,
    iteration: args.iteration,
    stage,
    decision,
    node,
    nodeInputs: args.nodeInputs,
    nodeOutputs: args.nodeOutputs,
    message,
    issues,
    runtimeTelemetry: args.runtimeTelemetry ?? null,
  });

  return {
    decision,
    message,
    issues,
  };
};

export type ApplyValidationBlockedNodeStateArgs = {
  node: AiNode;
  nodeInputs: RuntimePortValues;
  iteration: number;
  attempt: number;
  nodeDurationMs: number;
  runtimeTelemetry: RuntimeNodeResolutionTelemetry | null;
  stage: RuntimeValidationStage;
  message: string;
  issues: RuntimeValidationIssue[];
  state: EngineStateManager;
  options: EvaluateGraphOptions;
  resolvedRunId: string;
  resolvedRunStartedAt: string;
  sanitizedEdges: Edge[];
  nodeById: Map<string, AiNode>;
  activationHash?: string | null;
};

export const applyValidationBlockedNodeState = async (
  args: ApplyValidationBlockedNodeStateArgs
): Promise<void> => {
  const {
    node,
    nodeInputs,
    iteration,
    attempt,
    nodeDurationMs,
    runtimeTelemetry,
    stage,
    message,
    issues,
    state,
    options,
    resolvedRunId,
    resolvedRunStartedAt,
    sanitizedEdges,
    nodeById,
    activationHash = null,
  } = args;
  const spanId = `${node.id}:${attempt}:${iteration}`;
  const blockedOutputs: RuntimePortValues = {
    status: 'blocked',
    skipReason: 'validation',
    blockedReason: 'validation',
    message,
    validationStage: stage,
    validationIssues: cloneValue(issues),
  };
  state.blockedNodes.add(node.id);
  state.errorNodes.delete(node.id);
  state.timeoutNodes.delete(node.id);
  state.finishedNodes.delete(node.id);
  state.outputs[node.id] = blockedOutputs;

  if (options['recordHistory']) {
    const entries = state.history.get(node.id) ?? [];
    entries.push({
      timestamp: new Date().toISOString(),
      pathId: options.pathId ?? null,
      pathName: options.pathName ?? null,
      traceId: resolvedRunId,
      spanId,
      nodeId: node.id,
      nodeType: node.type,
      nodeTitle: node.title ?? null,
      status: 'blocked',
      iteration,
      attempt,
      inputs: cloneValue(nodeInputs),
      outputs: cloneValue(blockedOutputs),
      inputHash: activationHash,
      skipReason: 'validation',
      error: message,
      inputsFrom: buildInputLinks(node.id, sanitizedEdges, nodeById, nodeInputs),
      outputsTo: [],
      durationMs: nodeDurationMs,
      ...buildRuntimeTelemetryFields(runtimeTelemetry),
    } as RuntimeHistoryEntry);
    state.history.set(node.id, entries);
  }

  if (options.profile?.onEvent) {
    options.profile.onEvent({
      type: 'node',
      runId: resolvedRunId,
      runStartedAt: resolvedRunStartedAt,
      nodeId: node.id,
      nodeType: node.type,
      iteration,
      status: 'skipped',
      durationMs: nodeDurationMs,
      reason: 'validation',
      ...buildRuntimeTelemetryFields(runtimeTelemetry),
    });
  }

  if (options.onNodeBlocked) {
    await options.onNodeBlocked({
      runId: resolvedRunId,
      traceId: resolvedRunId,
      spanId,
      node,
      iteration,
      attempt,
      reason: 'validation',
      status: 'blocked',
      message,
      waitingOnPorts: [],
      waitingOnDetails: [],
      ...buildRuntimeTelemetryFields(runtimeTelemetry),
    });
  }
};

