  type GraphModelQueuedPayload,
  productAiJobEnqueueRequestSchema,
  type ProductAiJobEnqueueRequest,
} from '@/shared/contracts/jobs';

import { hashRuntimeValue } from '../utils';

const toTrimmedNonEmptyString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

export const buildGraphModelJobPayload = (input: {
  prompt: string;
  imageUrls?: string[];
  modelId?: string | null;
  temperature?: number;
  maxTokens?: number;
  vision?: boolean;
  systemPrompt?: string | null;
  activePathId?: string | null;
  nodeId: string;
  nodeTitle?: string | null;
  runId: string;
  contextRegistry?: ContextRegistryConsumerEnvelope | null;
  extraPayload?: Record<string, unknown>;
}): GraphModelJobEnqueuePayload => {
  const prompt = toTrimmedNonEmptyString(input.prompt);
  const nodeId = toTrimmedNonEmptyString(input.nodeId);
  const runId = toTrimmedNonEmptyString(input.runId);
  const requestedModelId = toTrimmedNonEmptyString(input.modelId);
  const systemPrompt = toTrimmedNonEmptyString(input.systemPrompt);
  const activePathId = toTrimmedNonEmptyString(input.activePathId);
  const nodeTitle = toTrimmedNonEmptyString(input.nodeTitle);

  if (!prompt) {
    throw new Error('Graph model payload requires a non-empty prompt.');
  }
  if (!nodeId) {
    throw new Error('Graph model payload requires a non-empty node id.');
  }
  if (!runId) {
    throw new Error('Graph model payload requires a non-empty run id.');
  }

  return graphModelJobEnqueuePayloadSchema.parse({
    prompt,
    ...(input.imageUrls !== undefined ? { imageUrls: input.imageUrls } : {}),
    ...(requestedModelId ? { modelId: requestedModelId } : {}),
    ...(typeof input.temperature === 'number' ? { temperature: input.temperature } : {}),
    ...(typeof input.maxTokens === 'number' ? { maxTokens: input.maxTokens } : {}),
    ...(typeof input.vision === 'boolean' ? { vision: input.vision } : {}),
    ...(systemPrompt ? { systemPrompt } : {}),
    source: 'ai_paths',
    graph: {
      pathId: activePathId ?? undefined,
      nodeId,
      nodeTitle: nodeTitle ?? undefined,
      ...(requestedModelId ? { requestedModelId } : {}),
      runId,
    },
    ...(input.contextRegistry ? { contextRegistry: input.contextRegistry } : {}),
    ...(input.extraPayload ?? {}),
  });
};

export const buildGraphModelJobEnqueueRequest = (input: {
  productId: string;
  payload: GraphModelJobEnqueuePayload;
}): ProductAiJobEnqueueRequest => {
  const productId = toTrimmedNonEmptyString(input.productId);
  if (!productId) {
    throw new Error('Graph model enqueue request requires a non-empty product id.');
  }

  return productAiJobEnqueueRequestSchema.parse({
    productId,
    type: 'graph_model',
    payload: input.payload,
  });
};

export const buildGraphModelJobCacheMetadata = (input: {
  payload: GraphModelJobPayload;
  runId: string;
  runStartedAt?: string | number | Date | null;
}): {
  cacheKey: string;
  payloadHash: string;
} => {
  const cacheKey = hashRuntimeValue(input.payload);
  const payloadHash = hashRuntimeValue(
    input.runStartedAt === undefined || input.runStartedAt === null
      ? { payload: input.payload, runId: input.runId }
      : { payload: input.payload, runId: input.runId, runStartedAt: input.runStartedAt }
  );

  return {
    cacheKey,
    payloadHash,
  };
};

export const buildGraphModelQueuedPayload = (input: {
  payload: GraphModelJobEnqueuePayload;
  runId: string;
  runStartedAt?: string | number | Date | null;
}): GraphModelQueuedPayload =>
  graphModelQueuedPayloadSchema.parse({
    ...input.payload,
    ...buildGraphModelJobCacheMetadata(input),
  });

export const buildQueuedGraphModelJobEnqueueRequest = (input: {
  productId: string;
  payload: GraphModelJobEnqueuePayload;
  runId: string;
  runStartedAt?: string | number | Date | null;
}): {
  payload: GraphModelQueuedPayload;
  request: ProductAiJobEnqueueRequest;
} => {
  const payload = buildGraphModelQueuedPayload({
    payload: input.payload,
    runId: input.runId,
    runStartedAt: input.runStartedAt,
  });

  return {
    payload,
    request: buildGraphModelJobEnqueueRequest({
      productId: input.productId,
      payload,
    }),
  };
};

export const readEnqueuedGraphModelJobId = (value: {
  data?: {
    jobId?: unknown;
  };
}): string => {
  const jobId = toTrimmedNonEmptyString(value.data?.jobId);
  if (!jobId) {
    throw new Error('AI job enqueue response did not include a valid job id.');
  }
  return jobId;
};

import { type AdvancedApiConfig, type RuntimePortValues } from '@/shared/contracts/ai-paths';
import { fetchWithOutboundUrlPolicy } from '@/shared/lib/security/outbound-url-policy';

import { toObject } from './utils';
import { renderTemplate } from '../../utils';

type AuthResolutionContext = {
  config: AdvancedApiConfig;
  nodeInputs: RuntimePortValues;
  headers: Record<string, string>;
  queryParams: Record<string, string>;
};

type AuthResolutionResult = Promise<{
  headers: Record<string, string>;
  queryParams: Record<string, string>;
}>;

const cloneAuthResolutionContext = ({
  headers,
  queryParams,
}: AuthResolutionContext): { headers: Record<string, string>; queryParams: Record<string, string> } => ({
  headers: { ...headers },
  queryParams: { ...queryParams },
});

const resolveNoneAuth = async (context: AuthResolutionContext) => cloneAuthResolutionContext(context);

const resolveApiKeyAuth = async (
  context: AuthResolutionContext
): AuthResolutionResult => {
  const { config, nodeInputs } = context;
  const next = cloneAuthResolutionContext(context);
  const name = (config.apiKeyName ?? '').trim();
  const value = renderTemplate(config.apiKeyValueTemplate ?? '', nodeInputs, '').trim();

  if (!name || !value) {
    return next;
  }

  if ((config.apiKeyPlacement ?? 'header') === 'query') {
    next.queryParams[name] = value;
    return next;
  }

  next.headers[name] = value;
  return next;
};

const resolveBearerAuth = async (
  context: AuthResolutionContext
): AuthResolutionResult => {
  const { config, nodeInputs } = context;
  const next = cloneAuthResolutionContext(context);
  const token = renderTemplate(config.bearerTokenTemplate ?? '', nodeInputs, '').trim();

  if (token) {
    next.headers['Authorization'] = `Bearer ${token}`;
  }

  return next;
};

const resolveBasicAuth = async (
  context: AuthResolutionContext
): AuthResolutionResult => {
  const { config, nodeInputs } = context;
  const next = cloneAuthResolutionContext(context);
  const username = renderTemplate(config.basicUsernameTemplate ?? '', nodeInputs, '');
  const password = renderTemplate(config.basicPasswordTemplate ?? '', nodeInputs, '');
  const token = btoa(`${username}:${password}`);

  next.headers['Authorization'] = `Basic ${token}`;
  return next;
};

const resolveOauthClientCredentialsInput = (
  config: AdvancedApiConfig,
  nodeInputs: RuntimePortValues
): {
  clientId: string;
  clientSecret: string;
  scope: string;
  tokenUrl: string;
} => ({
  clientId: renderTemplate(config.oauthClientIdTemplate ?? '', nodeInputs, ''),
  clientSecret: renderTemplate(config.oauthClientSecretTemplate ?? '', nodeInputs, ''),
  scope: renderTemplate(config.oauthScopeTemplate ?? '', nodeInputs, ''),
  tokenUrl: renderTemplate(config.oauthTokenUrl ?? '', nodeInputs, '').trim(),
});

const resolveOauthClientCredentialsAuth = async (
  context: AuthResolutionContext
): AuthResolutionResult => {
  const { config, nodeInputs } = context;
  const next = cloneAuthResolutionContext(context);
  const { clientId, clientSecret, scope, tokenUrl } = resolveOauthClientCredentialsInput(
    config,
    nodeInputs
  );

  if (!tokenUrl || !clientId || !clientSecret) {
    return next;
  }

  const body = new URLSearchParams({
    grant_type: 'client_credentials',
    client_id: clientId,
    client_secret: clientSecret,
    ...(scope.trim() ? { scope } : {}),
  });
  const tokenResponse = await fetchWithOutboundUrlPolicy(tokenUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body,
    maxRedirects: 3,
  });
  const tokenPayload = toObject(await tokenResponse.json().catch(() => ({})));
  const accessToken = String(tokenPayload['access_token'] ?? '').trim();

  if (accessToken) {
    next.headers['Authorization'] = `Bearer ${accessToken}`;
  }

  return next;
};

const resolveConnectionAuth = async (
  context: AuthResolutionContext
): AuthResolutionResult => {
  const { config, nodeInputs } = context;
  const next = cloneAuthResolutionContext(context);
  const connectionHeaderName = (config.connectionHeaderName ?? '').trim() || 'X-Connection-Id';
  const connectionId = renderTemplate(config.connectionIdTemplate ?? '', nodeInputs, '').trim();

  if (connectionId) {
    next.headers[connectionHeaderName] = connectionId;
  }

  return next;
};

const AUTH_MODE_RESOLVERS = {
  api_key: resolveApiKeyAuth,
  basic: resolveBasicAuth,
  bearer: resolveBearerAuth,
  connection: resolveConnectionAuth,
  none: resolveNoneAuth,
  oauth2_client_credentials: resolveOauthClientCredentialsAuth,
} as const;

export const resolveAuthHeaders = async (
  config: AdvancedApiConfig,
  nodeInputs: RuntimePortValues,
  headers: Record<string, string>,
  queryParams: Record<string, string>
): Promise<{ headers: Record<string, string>; queryParams: Record<string, string> }> => {
  const authMode = config.authMode ?? 'none';
  const resolver = AUTH_MODE_RESOLVERS[authMode] ?? resolveNoneAuth;

  return resolver({
    config,
    headers,
    nodeInputs,
    queryParams,
  });
};

import { type AdvancedApiConfig, type RuntimePortValues } from '@/shared/contracts/ai-paths';
import { type NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';

import { type AdvancedApiErrorRoute } from './config';
import { parseJsonWithTemplates, toStringRecord, toNumberArray } from './utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const parseErrorRoutes = (
  config: AdvancedApiConfig,
  nodeInputs: RuntimePortValues,
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'],
  nodeId: string
): AdvancedApiErrorRoute[] =>
  parseJsonWithTemplates<unknown[]>(
    config.errorRoutesJson,
    nodeInputs,
    [],
    reportAiPathsError,
    {
      action: 'parseAdvancedApiErrorRoutes',
      nodeId,
    }
  ).filter((entry: unknown): entry is AdvancedApiErrorRoute => {
    if (!entry || typeof entry !== 'object') return false;
    const record = entry as AdvancedApiErrorRoute;
    return (
      record.when === 'status' ||
      record.when === 'status_range' ||
      record.when === 'body_regex' ||
      record.when === 'timeout' ||
      record.when === 'network'
    );
  });

export const evaluateErrorRoute = (
  routes: AdvancedApiErrorRoute[],
  payload: {
    status: number;
    responseText: string;
    timedOut: boolean;
    networkError: boolean;
  }
): AdvancedApiErrorRoute | null => {
  for (const route of routes) {
    if (route.when === 'status') {
      if (typeof route.status === 'number' && Math.trunc(route.status) === payload.status) {
        return route;
      }
      continue;
    }
    if (route.when === 'status_range') {
      if (
        typeof route.minStatus === 'number' &&
        typeof route.maxStatus === 'number' &&
        payload.status >= route.minStatus &&
        payload.status <= route.maxStatus
      ) {
        return route;
      }
      continue;
    }
    if (route.when === 'body_regex') {
      if (typeof route.pattern !== 'string' || route.pattern.trim().length === 0) {
        continue;
      }
      try {
        const regex = new RegExp(route.pattern, route.flags ?? '');
        if (regex.test(payload.responseText)) {
          return route;
        }
      } catch (error) {
        logClientError(error);

        // Ignore malformed regex and continue checking other routes.
      }
      continue;
    }
    if (route.when === 'timeout' && payload.timedOut) {
      return route;
    }
    if (route.when === 'network' && payload.networkError) {
      return route;
    }
  }
  return null;
};

export const resolveRetryStatuses = (
  config: AdvancedApiConfig,
  nodeInputs: RuntimePortValues,
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'],
  nodeId: string
): Set<number> => {
  const parsed = parseJsonWithTemplates<unknown[]>(
    config.retryOnStatusJson,
    nodeInputs,
    [],
    reportAiPathsError,
    { action: 'parseAdvancedApiRetryStatuses', nodeId }
  );
  return new Set<number>(toNumberArray(parsed));
};

export const parseOutputMappings = (
  config: AdvancedApiConfig,
  nodeInputs: RuntimePortValues,
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'],
  nodeId: string
): Record<string, string> =>
  toStringRecord(
    parseJsonWithTemplates<Record<string, unknown>>(
      config.outputMappingsJson,
      nodeInputs,
      {},
      reportAiPathsError,
      {
        action: 'parseAdvancedApiOutputMappings',
        nodeId,
      }
    )
  );

import { type RuntimePortValues, type AdvancedApiConfig } from '@/shared/contracts/ai-paths';
import { type NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';

import { type JsonRecord } from './config';
import { getValueAtMappingPath, safeStringify } from '../../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const toObject = (value: unknown): JsonRecord => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
  return value as JsonRecord;
};

export const toStringRecord = (value: unknown): Record<string, string> => {
  const source = toObject(value);
  const result: Record<string, string> = {};
  Object.entries(source).forEach(([key, entry]) => {
    if (!key.trim()) return;
    if (entry === null || entry === undefined) return;
    result[key] = String(entry);
  });
  return result;
};

export const toNumberArray = (value: unknown): number[] => {
  if (!Array.isArray(value)) return [];
  return value
    .map((entry: unknown) =>
      typeof entry === 'number'
        ? entry
        : Number.parseInt(typeof entry === 'string' ? entry : '', 10)
    )
    .filter((entry: number): entry is number => Number.isFinite(entry))
    .map((entry: number) => Math.trunc(entry));
};

export const parseJsonWithTemplates = <T>(
  raw: string | undefined,
  nodeInputs: RuntimePortValues,
  fallback: T,
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'],
  meta: Record<string, unknown>
): T => {
  if (typeof raw !== 'string' || raw.trim().length === 0) return fallback;
  const renderedWithValue = raw.replace(
    /{{\s*([^}]+)\s*}}/g,
    (_match: string, token: string): string => {
      const key = String(token).trim();
      if (!key) return '';
      if (key === 'value' || key === 'current') {
        return safeStringify(nodeInputs['value']);
      }
      return safeStringify(getValueAtMappingPath(nodeInputs, key));
    }
  );
  try {
    return JSON.parse(renderedWithValue) as T;
  } catch (error) {
    logClientError(error);
    reportAiPathsError(error, meta, 'Invalid advanced API JSON config:');
    return fallback;
  }
};

export const applyPathParams = (url: string, params: Record<string, string>): string => {
  let next = url;
  Object.entries(params).forEach(([key, value]) => {
    if (!key) return;
    const encoded = encodeURIComponent(value);
    next = next.replaceAll(`:${key}`, encoded).replaceAll(`{${key}}`, encoded);
  });
  return next;
};

export const appendQueryParams = (url: string, queryParams: Record<string, string>): string => {
  const entries = Object.entries(queryParams).filter(
    ([key, value]) => key.trim().length > 0 && value.length > 0
  );
  if (entries.length === 0) return url;
  const hasQuery = url.includes('?');
  const params = new URLSearchParams(hasQuery ? url.slice(url.indexOf('?') + 1) : '');
  entries.forEach(([key, value]) => {
    params.set(key, value);
  });
  const base = hasQuery ? url.slice(0, url.indexOf('?')) : url;
  const query = params.toString();
  return query.length > 0 ? `${base}?${query}` : base;
};

export const sleep = async (ms: number): Promise<void> => {
  if (!Number.isFinite(ms) || ms <= 0) return;
  await new Promise<void>((resolve) => {
    setTimeout(resolve, ms);
  });
};

const normalizeRetryDelayBase = (config: AdvancedApiConfig): number =>
  Math.max(0, Math.trunc(config.retryBackoffMs ?? 0));

const normalizeRetryDelayMax = (base: number, config: AdvancedApiConfig): number =>
  Math.max(base, Math.trunc(config.retryMaxBackoffMs ?? base));

const resolveRetryDelayStep = (
  attempt: number,
  base: number,
  max: number,
  strategy: AdvancedApiConfig['retryBackoff']
): number => {
  if (strategy !== 'exponential') return base;
  return Math.min(max, base * Math.pow(2, Math.max(0, attempt - 1)));
};

const normalizeRetryJitterRatio = (config: AdvancedApiConfig): number =>
  Math.max(0, Math.min(1, config.retryJitterRatio ?? 0));

export const resolveRetryDelay = (attempt: number, config: AdvancedApiConfig): number => {
  const base = normalizeRetryDelayBase(config);
  if (base <= 0) return 0;
  const max = normalizeRetryDelayMax(base, config);
  const step = resolveRetryDelayStep(attempt, base, max, config.retryBackoff ?? 'fixed');
  const jitterRatio = normalizeRetryJitterRatio(config);
  if (jitterRatio <= 0) return step;
  const jitter = Math.round(step * jitterRatio * Math.random());
  return Math.min(max, step + jitter);
};

export const buildMappedOutputs = (
  outputMappings: Record<string, string>,
  envelope: JsonRecord
): RuntimePortValues => {
  const outputs: RuntimePortValues = {};
  Object.entries(outputMappings).forEach(([port, path]) => {
    if (!port.trim() || typeof path !== 'string' || !path.trim()) return;
    const value = getValueAtMappingPath(envelope, path);
    outputs[port] = value;
  });
  return outputs;
};

export type SignalControl = {
  signal: AbortSignal | undefined;
  wasTimeout: () => boolean;
  cleanup: () => void;
};

export const createSignalControl = (
  baseSignal: AbortSignal | undefined,
  timeoutMs: number | undefined
): SignalControl => {
  const normalizedTimeout = Number.isFinite(timeoutMs ?? NaN)
    ? Math.max(0, Math.trunc(timeoutMs as number))
    : 0;

  if (!baseSignal && normalizedTimeout <= 0) {
    return {
      signal: undefined,
      wasTimeout: () => false,
      cleanup: () => undefined,
    };
  }

  const controller = new AbortController();
  let timeoutTriggered = false;
  let timeoutHandle: ReturnType<typeof setTimeout> | null = null;
  const handleBaseAbort = (): void => {
    controller.abort();
  };

  if (baseSignal) {
    if (baseSignal.aborted) {
      controller.abort();
    } else {
      baseSignal.addEventListener('abort', handleBaseAbort);
    }
  }

  if (normalizedTimeout > 0) {
    timeoutHandle = setTimeout(() => {
      timeoutTriggered = true;
      controller.abort();
    }, normalizedTimeout);
  }

  return {
    signal: controller.signal,
    wasTimeout: () => timeoutTriggered,
    cleanup: () => {
      if (baseSignal) {
        baseSignal.removeEventListener('abort', handleBaseAbort);
      }
      if (timeoutHandle) {
        clearTimeout(timeoutHandle);
      }
    },
  };
};

import {
  AGENT_PERSONA_SETTINGS_KEY,
  DEFAULT_AGENT_PERSONA_SETTINGS,
} from '@/shared/contracts/agents';
import type { AgentPersona } from '@/shared/contracts/agents';
import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import type { ChatMessage } from '@/shared/contracts/chatbot';
import { agentApi, learnerAgentsApi, settingsApi } from '@/shared/lib/ai-paths/api';
import type { AgentEnqueuePayload } from '@/shared/lib/ai-paths/api';

import { coerceInput, formatRuntimeValue, hashRuntimeValue, parseJsonSafe } from '../../utils';
import { buildPromptOutput, coercePayloadObject } from '../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';



type AgentRunRecord = {
  id?: string;
  status?: string;
  errorMessage?: string | null;
  logLines?: string[];
  planState?: unknown;
};

type AiTerminalStatus = 'blocked' | 'skipped';

type PersonaModelSettings = {
  executorModel?: string;
  plannerModel?: string;
  selfCheckModel?: string;
  extractionValidationModel?: string;
  toolRouterModel?: string;
  memoryValidationModel?: string;
  memorySummarizationModel?: string;
  loopGuardModel?: string;
  approvalGateModel?: string;
  selectorInferenceModel?: string;
  outputNormalizationModel?: string;
};

const AGENT_PROMPT_INPUT_KEYS = [
  'prompt',
  'value',
  'result',
  'bundle',
  'context',
  'entityJson',
  'title',
  'content_en',
] as const;

const toOptionalModelSetting = (
  settings: Record<string, unknown>,
  key: keyof PersonaModelSettings
): string | undefined => {
  const value = settings[key];
  return typeof value === 'string' && value.trim().length > 0 ? value.trim() : undefined;
};

const toPersonaModelSettings = (value: unknown): PersonaModelSettings => {
  const settingsRecord = coercePayloadObject(value) ?? {};
  return {
    executorModel: toOptionalModelSetting(settingsRecord, 'executorModel'),
    plannerModel: toOptionalModelSetting(settingsRecord, 'plannerModel'),
    selfCheckModel: toOptionalModelSetting(settingsRecord, 'selfCheckModel'),
    extractionValidationModel: toOptionalModelSetting(settingsRecord, 'extractionValidationModel'),
    toolRouterModel: toOptionalModelSetting(settingsRecord, 'toolRouterModel'),
    memoryValidationModel: toOptionalModelSetting(settingsRecord, 'memoryValidationModel'),
    memorySummarizationModel: toOptionalModelSetting(settingsRecord, 'memorySummarizationModel'),
    loopGuardModel: toOptionalModelSetting(settingsRecord, 'loopGuardModel'),
    approvalGateModel: toOptionalModelSetting(settingsRecord, 'approvalGateModel'),
    selectorInferenceModel: toOptionalModelSetting(settingsRecord, 'selectorInferenceModel'),
    outputNormalizationModel: toOptionalModelSetting(settingsRecord, 'outputNormalizationModel'),
  };
};

const toLearnerChatResult = (value: unknown): { message: string; sources: unknown[] } => {
  const data = coercePayloadObject(value) ?? {};
  const message = typeof data['message'] === 'string' ? data['message'] : '';
  const sources = Array.isArray(data['sources']) ? data['sources'] : [];
  return { message, sources };
};

const buildAiTerminalOutputs = (options: {
  status: AiTerminalStatus;
  reason: string;
  details?: RuntimePortValues;
}): RuntimePortValues => {
  const base: RuntimePortValues = {
    status: options.status,
    skipReason: options.reason,
    result: '',
  };
  if (options.status === 'blocked') {
    base['blockedReason'] = options.reason;
  }
  return {
    ...base,
    ...(options.details ?? {}),
  };
};

const parseAgentPersonas = (value: unknown): AgentPersona[] => {
  if (!value) return [];
  if (Array.isArray(value)) {
    return value as AgentPersona[];
  }
  if (typeof value === 'string') {
    const parsed = parseJsonSafe(value);
    return Array.isArray(parsed) ? (parsed as AgentPersona[]) : [];
  }
  return [];
};

const fetchAgentPersonas = async (): Promise<AgentPersona[]> => {
  const response = await settingsApi.list('heavy' as const);
  if (!response.ok) return [];
  const record = response.data.find(
    (item: { key: string }) => item.key === AGENT_PERSONA_SETTINGS_KEY
  );
  if (!record) return [];
  return parseAgentPersonas(record.value);
};

const AGENT_TERMINAL_POLL_STATUSES = new Set(['completed', 'waiting_human']);
const AGENT_FAILED_POLL_STATUSES = new Set(['failed', 'stopped']);

const assertAgentPollResponse = (
  response: Awaited<ReturnType<typeof agentApi.poll>>
): AgentRunRecord => {
  if (!response.ok) {
    throw new Error(response.error || 'Failed to poll agent run.');
  }

  return (response.data.run as AgentRunRecord | undefined) ?? {};
};

const sleepForAgentPoll = async (intervalMs: number): Promise<void> => {
  await new Promise<void>((resolve: (value: void | PromiseLike<void>) => void) =>
    setTimeout(resolve, intervalMs)
  );
};

const shouldPollAgentAgain = (attempt: number, maxAttempts: number): boolean =>
  attempt < maxAttempts - 1;

export const pollAgentRun = async (
  runId: string,
  options?: { intervalMs?: number; maxAttempts?: number }
): Promise<{ run?: AgentRunRecord; status?: string }> => {
  const maxAttempts = options?.maxAttempts ?? 60;
  const intervalMs = options?.intervalMs ?? 2000;

  for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
    const run = assertAgentPollResponse(await agentApi.poll(runId));
    const status = run?.status ?? '';

    if (AGENT_TERMINAL_POLL_STATUSES.has(status)) {
      return { run, status };
    }

    if (AGENT_FAILED_POLL_STATUSES.has(status)) {
      throw new Error(run?.errorMessage || 'Agent run failed.');
    }

    if (shouldPollAgentAgain(attempt, maxAttempts)) {
      await sleepForAgentPoll(intervalMs);
    }
  }

  throw new Error('Agent run timed out.');
};

const resolveAgentPromptValue = (nodeInputs: RuntimePortValues): unknown => {
  for (const key of AGENT_PROMPT_INPUT_KEYS) {
    const value = coerceInput(nodeInputs[key]);

    if (value !== undefined && value !== null) {
      return value;
    }
  }

  return undefined;
};

const resolveAgentPrompt = (args: {
  promptTemplate?: string | null;
  nodeInputs: RuntimePortValues;
}): string => {
  const template = args.promptTemplate?.trim();
  const rawPrompt = template?.length
    ? buildPromptOutput({ template }, args.nodeInputs).promptOutput
    : resolveAgentPromptValue(args.nodeInputs);

  return typeof rawPrompt === 'string' ? rawPrompt.trim() : formatRuntimeValue(rawPrompt);
};

const buildLearnerAgentMessages = (args: {
  prompt: string;
  runId: string;
}): ChatMessage[] => [
  {
    id: `msg_${args.runId}_${Date.now()}`,
    sessionId: args.runId,
    role: 'user',
    content: args.prompt,
    timestamp: new Date().toISOString(),
  },
];

export const handleAgent: NodeHandler = async ({
  node,
  nodeInputs,
  prevOutputs,
  contextRegistry,
  skipAiJobs,
  executed,
  toast,
  reportAiPathsError,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  if (skipAiJobs) {
    return buildAiTerminalOutputs({
      status: 'skipped',
      reason: 'ai_jobs_disabled',
      details: {
        bundle: {
          status: 'skipped',
        },
      },
    });
  }
  if (executed.ai.has(node.id)) return prevOutputs;

  const agentConfig = node.config?.agent ?? {
    personaId: '',
    promptTemplate: '',
    waitForResult: true,
  };

  const prompt = resolveAgentPrompt({
    promptTemplate: agentConfig.promptTemplate,
    nodeInputs,
  });

  if (!prompt || prompt === '—') {
    return buildAiTerminalOutputs({
      status: 'blocked',
      reason: 'missing_prompt',
      details: {
        bundle: {
          status: 'blocked',
        },
      },
    });
  }

  let personas: AgentPersona[];
  try {
    personas = await fetchAgentPersonas();
  } catch (error) {
    logClientError(error);
    personas = [];
  }
  const persona = agentConfig.personaId
    ? personas.find((item: { id: string }) => item.id === agentConfig.personaId)
    : undefined;
  const settings = toPersonaModelSettings(persona?.settings ?? DEFAULT_AGENT_PERSONA_SETTINGS);

  const payload: AgentEnqueuePayload = {
    prompt,
    ...(settings.executorModel ? { model: settings.executorModel } : {}),
    ...(settings.plannerModel ? { plannerModel: settings.plannerModel } : {}),
    ...(settings.selfCheckModel ? { selfCheckModel: settings.selfCheckModel } : {}),
    ...(settings.extractionValidationModel
      ? { extractionValidationModel: settings.extractionValidationModel }
      : {}),
    ...(settings.toolRouterModel ? { toolRouterModel: settings.toolRouterModel } : {}),
    ...(settings.memoryValidationModel
      ? { memoryValidationModel: settings.memoryValidationModel }
      : {}),
    ...(settings.memorySummarizationModel
      ? { memorySummarizationModel: settings.memorySummarizationModel }
      : {}),
    ...(settings.loopGuardModel ? { loopGuardModel: settings.loopGuardModel } : {}),
    ...(settings.approvalGateModel ? { approvalGateModel: settings.approvalGateModel } : {}),
    ...(settings.selectorInferenceModel
      ? { selectorInferenceModel: settings.selectorInferenceModel }
      : {}),
    ...(settings.outputNormalizationModel
      ? { outputNormalizationModel: settings.outputNormalizationModel }
      : {}),
    ...(contextRegistry ? { contextRegistry } : {}),
  };

  let runId: string | undefined;
  try {
    const enqueueResult = await agentApi.enqueue(payload);
    if (!enqueueResult.ok) {
      throw new Error(enqueueResult.error || 'Failed to enqueue agent run.');
    }
    const runIdRaw = enqueueResult.data.runId;
    if (typeof runIdRaw !== 'string' || runIdRaw.trim().length === 0) {
      throw new Error('Agent run enqueue response did not include a valid run id.');
    }
    runId = runIdRaw;
    executed.ai.add(node.id);
    toast('Agent run queued.', { variant: 'success' });

    if (agentConfig.waitForResult === false) {
      return {
        jobId: runId,
        status: 'queued',
        bundle: {
          runId,
          status: 'queued',
          personaId: persona?.id ?? null,
          personaName: persona?.name ?? null,
          model: settings.executorModel ?? null,
        },
      };
    }

    const { run, status } = await pollAgentRun(runId);
    const planState =
      run?.planState && typeof run.planState === 'object'
        ? (run.planState as Record<string, unknown>)
        : (coercePayloadObject(run?.planState) ?? null);
    const checkpointBrief =
      typeof planState?.['checkpointBrief'] === 'string' ? planState['checkpointBrief'] : '';
    const logLines = Array.isArray(run?.logLines) ? run?.logLines : [];
    const lastLog = logLines.length > 0 ? (logLines[logLines.length - 1] ?? '') : '';
    const result = checkpointBrief || lastLog || run?.errorMessage || '';

    return {
      result,
      jobId: runId,
      status: status ?? run?.status ?? 'completed',
      bundle: {
        runId,
        status: status ?? run?.status ?? 'completed',
        personaId: persona?.id ?? null,
        personaName: persona?.name ?? null,
        model: settings.executorModel ?? null,
        run,
      },
    };
  } catch (error) {
    logClientError(error);
    reportAiPathsError(error, { action: 'agentRun', nodeId: node.id }, 'Agent run failed:');
    const errorMessage = error instanceof Error ? error.message : 'Agent run failed';
    toast(errorMessage, { variant: 'error' });
    executed.ai.add(node.id);
    return {
      result: '',
      jobId: runId,
      status: 'failed',
      bundle: {
        runId,
        status: 'failed',
        personaId: persona?.id ?? null,
        personaName: persona?.name ?? null,
        model: settings.executorModel ?? null,
      },
    };
  }
};

export const handleLearnerAgent: NodeHandler = async ({
  node,
  nodeInputs,
  prevOutputs,
  skipAiJobs,
  executed,
  toast,
  reportAiPathsError,
  runId,
  runStartedAt,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  if (node.type !== 'learner_agent') return prevOutputs;
  if (skipAiJobs) {
    return buildAiTerminalOutputs({
      status: 'skipped',
      reason: 'ai_jobs_disabled',
      details: {
        sources: [],
        bundle: {
          status: 'skipped',
        },
      },
    });
  }

  const learnerConfig = node.config?.learnerAgent ?? {
    agentId: '',
    promptTemplate: '',
    includeSources: true,
  };

  const agentId = learnerConfig.agentId?.trim();
  if (!agentId) {
    return buildAiTerminalOutputs({
      status: 'blocked',
      reason: 'missing_agent_id',
      details: {
        sources: [],
        bundle: {
          status: 'blocked',
        },
      },
    });
  }

  const prompt = resolveAgentPrompt({
    promptTemplate: learnerConfig.promptTemplate,
    nodeInputs,
  });

  if (!prompt || prompt === '—') {
    return buildAiTerminalOutputs({
      status: 'blocked',
      reason: 'missing_prompt',
      details: {
        sources: [],
        bundle: {
          agentId,
          status: 'blocked',
        },
      },
    });
  }

  const messages = buildLearnerAgentMessages({ prompt, runId });
  const payload = { agentId, messages };
  const payloadHash = hashRuntimeValue({ payload, runId, runStartedAt });
  const prevPayloadHash =
    typeof prevOutputs['payloadHash'] === 'string' ? prevOutputs['payloadHash'] : '';
  if (prevPayloadHash && prevPayloadHash === payloadHash) {
    return prevOutputs;
  }

  if (executed.ai.has(node.id)) return prevOutputs;

  try {
    const response = await learnerAgentsApi.chat(payload);
    if (!response.ok) {
      throw new Error(response.error || 'Learner agent chat failed.');
    }
    const chatResult = toLearnerChatResult(response.data);
    executed.ai.add(node.id);

    const includeSources = learnerConfig.includeSources !== false;
    return {
      result: chatResult.message,
      sources: includeSources ? chatResult.sources : [],
      status: 'completed',
      bundle: {
        agentId,
        message: chatResult.message,
        sources: includeSources ? chatResult.sources : [],
      },
      payloadHash,
    };
  } catch (error) {
    logClientError(error);
    reportAiPathsError(
      error,
      { action: 'learnerAgent', nodeId: node.id, agentId },
      'Learner agent node failed:'
    );
    toast('Learner agent failed.', { variant: 'error' });
    executed.ai.add(node.id);
    return {
      result: '',
      sources: [],
      status: 'failed',
      bundle: {
        agentId,
        status: 'failed',
        error: error instanceof Error ? error.message : 'Learner agent failed',
      },
      payloadHash,
    };
  }
};

import type { AudioWaveform } from '@/shared/contracts/ai-paths-core/base';
import type { RuntimePortValues } from '@/shared/contracts/ai-paths-runtime';
import type { NodeHandler, NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { coerceInput } from '../../utils';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

type OscillatorSignal = {
  kind: 'oscillator';
  waveform: AudioWaveform;
  frequencyHz: number;
  gain: number;
  durationMs: number;
};

type ActivePlayback = {
  oscillator: OscillatorNode;
  gainNode: GainNode;
};

type AudioPlaybackState = {
  context: AudioContext | null;
  activeByNode: Map<string, ActivePlayback>;
};

const AUDIO_STATE_KEY = '__AI_PATHS_AUDIO_PLAYBACK_STATE__';

const DEFAULT_OSCILLATOR_SIGNAL: OscillatorSignal = {
  kind: 'oscillator',
  waveform: 'sine',
  frequencyHz: 440,
  gain: 0.25,
  durationMs: 400,
};

const WAVES: AudioWaveform[] = ['sine', 'square', 'triangle', 'sawtooth'];

const clampNumber = (value: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, value));

const toFiniteNumber = (value: unknown, fallback: number): number => {
  if (typeof value === 'number' && Number.isFinite(value)) return value;
  if (typeof value === 'string') {
    const parsed = Number.parseFloat(value);
    if (Number.isFinite(parsed)) return parsed;
  }
  return fallback;
};

const normalizeWaveform = (value: unknown, fallback: AudioWaveform = 'sine'): AudioWaveform => {
  if (typeof value !== 'string') return fallback;
  const normalized = value.trim().toLowerCase();
  if (!normalized) return fallback;
  if (WAVES.includes(normalized as AudioWaveform)) {
    return normalized as AudioWaveform;
  }
  return fallback;
};

const buildOscillatorSignal = (
  raw: Partial<OscillatorSignal> | null | undefined,
  fallback: OscillatorSignal = DEFAULT_OSCILLATOR_SIGNAL
): OscillatorSignal => {
  const waveform = normalizeWaveform(raw?.waveform, fallback.waveform);
  const frequencyHz = clampNumber(
    toFiniteNumber(raw?.frequencyHz, fallback.frequencyHz),
    20,
    20_000
  );
  const gain = clampNumber(toFiniteNumber(raw?.gain, fallback.gain), 0, 1);
  const durationMs = clampNumber(toFiniteNumber(raw?.durationMs, fallback.durationMs), 30, 10_000);
  return {
    kind: 'oscillator',
    waveform,
    frequencyHz,
    gain,
    durationMs,
  };
};

const parseOscillatorSignal = (value: unknown): OscillatorSignal | null => {
  if (!isObjectRecord(value)) return null;
  const maybeKind = value['kind'];
  if (typeof maybeKind === 'string' && maybeKind !== 'oscillator') return null;
  return buildOscillatorSignal({
    waveform: normalizeWaveform(value['waveform']),
    frequencyHz: toFiniteNumber(value['frequencyHz'], DEFAULT_OSCILLATOR_SIGNAL.frequencyHz),
    gain: toFiniteNumber(value['gain'], DEFAULT_OSCILLATOR_SIGNAL.gain),
    durationMs: toFiniteNumber(value['durationMs'], DEFAULT_OSCILLATOR_SIGNAL.durationMs),
  });
};

type GlobalAudioConstructors = {
  AudioContext?: typeof AudioContext;
  webkitAudioContext?: typeof AudioContext;
};

const resolveGlobalAudioConstructors = (): GlobalAudioConstructors => {
  const root = globalThis as Record<string, unknown>;
  const audioContext = root['AudioContext'];
  const webkitAudioContext = root['webkitAudioContext'];
  return {
    ...(typeof audioContext === 'function'
      ? { AudioContext: audioContext as typeof AudioContext }
      : {}),
    ...(typeof webkitAudioContext === 'function'
      ? { webkitAudioContext: webkitAudioContext as typeof AudioContext }
      : {}),
  };
};

const isAudioPlaybackState = (value: unknown): value is AudioPlaybackState =>
  isObjectRecord(value) && value['activeByNode'] instanceof Map;

const hasWebAudio = (): boolean => {
  if (typeof globalThis === 'undefined') return false;
  const candidate = resolveGlobalAudioConstructors();
  return (
    typeof candidate.AudioContext === 'function' ||
    typeof candidate.webkitAudioContext === 'function'
  );
};

const getAudioState = (): AudioPlaybackState => {
  const root = globalThis as Record<string, unknown>;
  const current = root[AUDIO_STATE_KEY];
  if (isAudioPlaybackState(current)) return current;
  const created: AudioPlaybackState = {
    context: null,
    activeByNode: new Map<string, ActivePlayback>(),
  };
  root[AUDIO_STATE_KEY] = created;
  return created;
};

const resolveAudioContextCtor = (): typeof AudioContext | null => {
  if (!hasWebAudio()) return null;
  const globalAudio = resolveGlobalAudioConstructors();
  const Ctor = globalAudio.AudioContext ?? globalAudio.webkitAudioContext;
  return Ctor ?? null;
};

const ensureAudioContextInstance = (
  state: AudioPlaybackState,
  Ctor: typeof AudioContext
): AudioContext => {
  if (!state.context || state.context.state === 'closed') {
    state.context = new Ctor();
  }
  return state.context;
};

const resumeAudioContextIfNeeded = async (context: AudioContext): Promise<void> => {
  if (context.state !== 'suspended') {
    return;
  }

  try {
    await context.resume();
  } catch (error) {
    logClientCatch(error, {
      source: 'ai-paths.audio',
      action: 'resolveAudioContext.resume',
    });

    // Ignore; caller decides fallback status.
  }
};

const resolveAudioContext = async (): Promise<AudioContext | null> => {
  const Ctor = resolveAudioContextCtor();
  if (!Ctor) return null;
  const state = getAudioState();
  const context = ensureAudioContextInstance(state, Ctor);
  await resumeAudioContextIfNeeded(context);
  return context;
};

const stopActivePlayback = (nodeId: string): void => {
  const state = getAudioState();
  const active = state.activeByNode.get(nodeId);
  if (!active) return;
  try {
    active.oscillator.stop();
  } catch (error) {
    logClientCatch(error, {
      source: 'ai-paths.audio',
      action: 'stopActivePlayback.stopOscillator',
      nodeId,
    });

    // Oscillator might already be stopped.
  }
  try {
    active.oscillator.disconnect();
    active.gainNode.disconnect();
  } catch (error) {
    logClientCatch(error, {
      source: 'ai-paths.audio',
      action: 'stopActivePlayback.disconnect',
      nodeId,
    });

    // Ignore disconnect errors on closed context.
  }
  state.activeByNode.delete(nodeId);
};

const playSignalOnMonoSpeaker = async (
  nodeId: string,
  signal: OscillatorSignal,
  speakerGain: number,
  stopPrevious: boolean
): Promise<'playing' | 'blocked' | 'unsupported'> => {
  const context = await resolveAudioContext();
  if (!context) return 'unsupported';
  if (context.state !== 'running') {
    return 'blocked';
  }
  const state = getAudioState();
  if (stopPrevious) {
    stopActivePlayback(nodeId);
  }
  const oscillator = context.createOscillator();
  const gainNode = context.createGain();
  const now = context.currentTime;
  const effectiveGain = clampNumber(signal.gain * speakerGain, 0, 1);

  oscillator.type = signal.waveform;
  oscillator.frequency.setValueAtTime(signal.frequencyHz, now);
  gainNode.gain.setValueAtTime(effectiveGain, now);

  oscillator.connect(gainNode);
  gainNode.connect(context.destination);

  oscillator.onended = (): void => {
    const current = state.activeByNode.get(nodeId);
    if (current?.oscillator !== oscillator) return;
    state.activeByNode.delete(nodeId);
    try {
      oscillator.disconnect();
      gainNode.disconnect();
    } catch (error) {
      logClientCatch(error, {
        source: 'ai-paths.audio',
        action: 'playSignalOnMonoSpeaker.onended.disconnect',
        nodeId,
      });

      // Ignore teardown errors.
    }
  };

  state.activeByNode.set(nodeId, { oscillator, gainNode });
  oscillator.start(now);
  oscillator.stop(now + signal.durationMs / 1000);
  return 'playing';
};

export const handleAudioOscillator: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const configRaw = node.config?.['audioOscillator'];
  const config = buildOscillatorSignal(isObjectRecord(configRaw) ? configRaw : undefined);
  const triggerValue = coerceInput(nodeInputs['trigger']);
  const armed = triggerValue === undefined ? true : Boolean(triggerValue);

  const signal = buildOscillatorSignal({
    waveform: normalizeWaveform(coerceInput(nodeInputs['waveform']), config.waveform),
    frequencyHz: toFiniteNumber(coerceInput(nodeInputs['frequency']), config.frequencyHz),
    gain: toFiniteNumber(coerceInput(nodeInputs['gain']), config.gain),
    durationMs: toFiniteNumber(coerceInput(nodeInputs['durationMs']), config.durationMs),
  });

  if (!armed) {
    return {
      status: 'idle',
      frequency: signal.frequencyHz,
      waveform: signal.waveform,
      gain: signal.gain,
      durationMs: signal.durationMs,
    };
  }

  return {
    audioSignal: signal,
    frequency: signal.frequencyHz,
    waveform: signal.waveform,
    gain: signal.gain,
    durationMs: signal.durationMs,
    status: 'ready',
  };
};

export const handleAudioSpeaker: NodeHandler = async ({
  node,
  nodeInputs,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  const configRaw = node.config?.['audioSpeaker'];
  const config = (
    isObjectRecord(configRaw)
      ? configRaw
      : {
        enabled: true,
        autoPlay: true,
        gain: 1,
        stopPrevious: true,
      }
  ) as Record<string, unknown>;

  if (config['enabled'] === false) {
    stopActivePlayback(node.id);
    return { status: 'disabled' };
  }

  const triggerValue = coerceInput(nodeInputs['trigger']);
  const armed = triggerValue === undefined ? true : Boolean(triggerValue);
  if (!armed) {
    return { status: 'armed' };
  }

  const providedSignal = parseOscillatorSignal(coerceInput(nodeInputs['audioSignal']));
  const fallbackSignal = buildOscillatorSignal({
    waveform: normalizeWaveform(coerceInput(nodeInputs['waveform'])),
    frequencyHz: toFiniteNumber(
      coerceInput(nodeInputs['frequency']),
      DEFAULT_OSCILLATOR_SIGNAL.frequencyHz
    ),
    gain: toFiniteNumber(coerceInput(nodeInputs['gain']), DEFAULT_OSCILLATOR_SIGNAL.gain),
    durationMs: toFiniteNumber(
      coerceInput(nodeInputs['durationMs']),
      DEFAULT_OSCILLATOR_SIGNAL.durationMs
    ),
  });
  const hasExplicitSignal =
    providedSignal !== null ||
    nodeInputs['frequency'] !== undefined ||
    nodeInputs['waveform'] !== undefined ||
    nodeInputs['gain'] !== undefined ||
    nodeInputs['durationMs'] !== undefined;
  if (!hasExplicitSignal) {
    return { status: 'idle' };
  }
  const signal = providedSignal ?? fallbackSignal;
  const speakerGain = clampNumber(toFiniteNumber(config['gain'], 1), 0, 1);

  if (config['autoPlay'] === false) {
    return {
      status: 'ready',
      audioSignal: signal,
      frequency: signal.frequencyHz,
      waveform: signal.waveform,
    };
  }

  const playbackStatus = await playSignalOnMonoSpeaker(
    node.id,
    signal,
    speakerGain,
    Boolean(config['stopPrevious'] ?? true)
  );

  const statusLabel =
    playbackStatus === 'playing'
      ? 'playing'
      : playbackStatus === 'blocked'
        ? 'blocked_by_browser'
        : 'unsupported_environment';

  return {
    status: statusLabel,
    audioSignal: signal,
    frequency: signal.frequencyHz,
    waveform: signal.waveform,
    gain: signal.gain,
    durationMs: signal.durationMs,
  };
};

import type {
  LogicalConditionConfig,
  LogicalConditionOperator,
} from '@/shared/contracts/ai-paths-core/nodes';
import { logicalConditionConfigSchema } from '@/shared/contracts/ai-paths-core/nodes';
import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';

import { DELAY_OUTPUT_PORTS, ROUTER_OUTPUT_PORTS } from '../../constants';
import { coerceInput, coerceInputArray, safeStringify } from '../../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const handleConstant: NodeHandler = ({ node }: NodeHandlerContext): RuntimePortValues => {
  const constantConfig = node.config?.['constant'] ?? {
    valueType: 'string',
    value: '',
  };
  const config = constantConfig as Record<string, unknown>;
  let value: unknown = config['value'] ?? '';
  if (config['valueType'] === 'number') {
    value = Number(config['value'] ?? 0);
  } else if (config['valueType'] === 'boolean') {
    value = String(config['value'] ?? 'false') === 'true';
  } else if (config['valueType'] === 'json') {
    // using a simple parse here as safeParseJson is in utils and we can't easily import everything
    try {
      value = JSON.parse(String(config['value'] ?? '')) as unknown;
    } catch (error) {
      logClientError(error);
      value = null;
    }
  }
  return { value };
};

export const handleMath: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const inputValue = coerceInput(nodeInputs['value']);
  const numeric = Number(inputValue);
  const mathConfig = (node.config?.['math'] ?? { operation: 'add', operand: 0 }) as Record<
    string,
    unknown
  >;
  const operand = (mathConfig['operand'] as number) ?? 0;
  if (!Number.isFinite(numeric)) {
    return { value: inputValue };
  }
  let result: number;
  const operation = mathConfig['operation'] as string;
  switch (operation) {
    case 'add':
      result = numeric + operand;
      break;
    case 'subtract':
      result = numeric - operand;
      break;
    case 'multiply':
      result = numeric * operand;
      break;
    case 'divide':
      result = operand === 0 ? numeric : numeric / operand;
      break;
    case 'round':
      result = Math.round(numeric);
      break;
    case 'ceil':
      result = Math.ceil(numeric);
      break;
    case 'floor':
      result = Math.floor(numeric);
      break;
    default:
      result = numeric;
  }
  return { value: result };
};

export const handleCompare: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const compareConfig = (node.config?.['compare'] ?? {
    operator: 'eq',
    compareTo: '',
    caseSensitive: false,
    message: 'Comparison failed',
  }) as Record<string, unknown>;
  const currentValue = coerceInput(nodeInputs['value']);
  const compareTo = (compareConfig['compareTo'] as string) ?? '';
  const base = safeStringify(currentValue);
  const target = String(compareTo ?? '');
  const value = compareConfig['caseSensitive'] ? base : base.toLowerCase();
  const targetValue = compareConfig['caseSensitive'] ? target : target.toLowerCase();
  let valid: boolean;
  switch (compareConfig['operator'] as string) {
    case 'eq':
      valid = value === targetValue;
      break;
    case 'neq':
      valid = value !== targetValue;
      break;
    case 'gt':
      valid = Number(value) > Number(targetValue);
      break;
    case 'gte':
      valid = Number(value) >= Number(targetValue);
      break;
    case 'lt':
      valid = Number(value) < Number(targetValue);
      break;
    case 'lte':
      valid = Number(value) <= Number(targetValue);
      break;
    case 'contains':
      valid = value.includes(targetValue);
      break;
    case 'startsWith':
      valid = value.startsWith(targetValue);
      break;
    case 'endsWith':
      valid = value.endsWith(targetValue);
      break;
    case 'isEmpty':
      valid = value.trim() === '';
      break;
    case 'notEmpty':
      valid = value.trim() !== '';
      break;
    default:
      valid = false;
  }
  return {
    value: currentValue,
    valid,
    errors: valid ? [] : [(compareConfig['message'] as string) ?? 'Comparison failed'],
  };
};

type LogicalInputPort = 'value' | 'result' | 'context' | 'bundle';

const normalizeLogicalInputPort = (value: unknown): LogicalInputPort => {
  if (value === 'value' || value === 'result' || value === 'context' || value === 'bundle') {
    return value;
  }
  return 'value';
};

const resolveLogicalConditionInput = (
  inputPort: LogicalInputPort,
  fieldPath: string | undefined,
  nodeInputs: RuntimePortValues
): unknown => {
  const raw = coerceInput(nodeInputs[inputPort]);
  if (!fieldPath?.trim()) return raw;
  const parts = fieldPath.split('.');
  let cursor: unknown = raw;
  for (const part of parts) {
    if (cursor === null || cursor === undefined || typeof cursor !== 'object') {
      return undefined;
    }
    cursor = (cursor as Record<string, unknown>)[part];
  }
  return cursor;
};

const evaluateLogicalConditionItem = (
  value: unknown,
  operator: LogicalConditionOperator,
  compareTo: string | undefined,
  caseSensitive: boolean | undefined
): boolean => {
  const asString = safeStringify(value ?? '');
  const normalized = caseSensitive ? asString : asString.toLowerCase();
  const target = caseSensitive ? String(compareTo ?? '') : String(compareTo ?? '').toLowerCase();

  switch (operator) {
    case 'truthy':
      return Boolean(value);
    case 'falsy':
      return !value;
    case 'equals':
      return normalized === target;
    case 'notEquals':
      return normalized !== target;
    case 'contains':
      return normalized.includes(target);
    case 'notContains':
      return !normalized.includes(target);
    case 'startsWith':
      return normalized.startsWith(target);
    case 'endsWith':
      return normalized.endsWith(target);
    case 'isEmpty':
      return normalized.trim() === '' || normalized.trim() === '[]' || normalized.trim() === '{}';
    case 'notEmpty':
      return normalized.trim() !== '' && normalized.trim() !== '[]' && normalized.trim() !== '{}';
    case 'greaterThan':
      return Number(asString) > Number(compareTo ?? 0);
    case 'lessThan':
      return Number(asString) < Number(compareTo ?? 0);
    case 'greaterThanOrEqual':
      return Number(asString) >= Number(compareTo ?? 0);
    case 'lessThanOrEqual':
      return Number(asString) <= Number(compareTo ?? 0);
    default:
      return false;
  }
};

export const handleLogicalCondition: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const parsedConfig = logicalConditionConfigSchema.safeParse(node.config?.['logicalCondition']);
  const config: LogicalConditionConfig = parsedConfig.success
    ? parsedConfig.data
    : {
      combinator: 'and',
      conditions: [],
    };
  const { combinator, conditions: rawConditions } = config;
  const conditions = rawConditions ?? [];

  const primaryPort = normalizeLogicalInputPort(conditions[0]?.inputPort);
  const primaryValue = coerceInput(nodeInputs[primaryPort]);

  if (!conditions || conditions.length === 0) {
    return { value: primaryValue, valid: true, errors: [] };
  }

  const errors: string[] = [];
  let valid: boolean;

  if (combinator === 'and') {
    valid = true;
    for (const condition of conditions) {
      const val = resolveLogicalConditionInput(
        normalizeLogicalInputPort(condition.inputPort),
        condition.fieldPath,
        nodeInputs
      );
      const result = evaluateLogicalConditionItem(
        val,
        condition.operator,
        condition.compareTo,
        condition.caseSensitive
      );
      if (!result) {
        errors.push(`Condition failed: [${condition.inputPort}] ${condition.operator}`);
        valid = false;
        break;
      }
    }
  } else {
    valid = false;
    for (const condition of conditions) {
      const val = resolveLogicalConditionInput(
        normalizeLogicalInputPort(condition.inputPort),
        condition.fieldPath,
        nodeInputs
      );
      const result = evaluateLogicalConditionItem(
        val,
        condition.operator,
        condition.compareTo,
        condition.caseSensitive
      );
      if (result) {
        valid = true;
        break;
      }
      errors.push(`Condition did not match: [${condition.inputPort}] ${condition.operator}`);
    }
    if (valid) {
      errors.length = 0;
    }
  }

  return {
    value: primaryValue,
    valid,
    errors,
  };
};

export const handleRouter: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const configRaw = node.config?.['router'] ?? {
    mode: 'valid',
    matchMode: 'truthy',
    compareTo: '',
  };
  const config = configRaw as Record<string, unknown>;
  const valueCandidate =
    config['mode'] === 'valid'
      ? coerceInput(nodeInputs['valid'])
      : coerceInput(nodeInputs['value']);
  const compareTarget = (config['compareTo'] as string) ?? '';
  const asString = safeStringify(valueCandidate);
  let shouldPass: boolean;
  switch (config['matchMode'] as string) {
    case 'truthy':
      shouldPass = Boolean(valueCandidate);
      break;
    case 'falsy':
      shouldPass = !valueCandidate;
      break;
    case 'equals':
      shouldPass = asString === String(compareTarget);
      break;
    case 'contains':
      shouldPass = asString.includes(String(compareTarget));
      break;
    default:
      shouldPass = Boolean(valueCandidate);
  }
  const next: Record<string, unknown> = {
    valid: shouldPass,
    errors: shouldPass ? [] : ['Router blocked'],
  };
  if (shouldPass) {
    ROUTER_OUTPUT_PORTS.forEach((port: string) => {
      if (port === 'valid' || port === 'errors') return;
      if (nodeInputs[port] !== undefined) {
        next[port] = nodeInputs[port];
      }
    });
  }
  return next;
};

export const handleGate: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const contextValue = coerceInput(nodeInputs['context']) as Record<string, unknown> | undefined;
  const validInput = coerceInput(nodeInputs['valid']);
  const errorsInput = coerceInputArray(nodeInputs['errors']);
  const configRaw = node.config?.['gate'] ?? { mode: 'block', failMessage: 'Gate blocked' };
  const config = configRaw as Record<string, unknown>;
  const isValid = typeof validInput === 'boolean' ? validInput : Boolean(validInput);
  if (!isValid && config['mode'] === 'block') {
    return {
      context: null,
      valid: false,
      errors: errorsInput.length
        ? errorsInput
        : [(config['failMessage'] as string) ?? 'Gate blocked'],
    };
  }
  return {
    context: contextValue,
    valid: isValid,
    errors: errorsInput,
  };
};

export const handleBundle: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const configRaw = node.config?.['bundle'] ?? { includePorts: [] };
  const config = configRaw as Record<string, unknown>;
  const includePorts = (config['includePorts'] as string[])?.length
    ? (config['includePorts'] as string[])
    : node.inputs;
  const bundle = includePorts.reduce<Record<string, unknown>>(
    (acc: Record<string, unknown>, port: string) => {
      if (nodeInputs[port] !== undefined) {
        acc[port] = nodeInputs[port];
      }
      return acc;
    },
    {}
  );
  return { bundle };
};

export const handleDelay: NodeHandler = async ({
  node,
  nodeInputs,
  executed,
  abortSignal,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  if (!executed.delay.has(node.id)) {
    const configRaw = node.config?.['delay'];
    const config = (configRaw as Record<string, unknown>) ?? { ms: 300 };
    const delayMs = (config['ms'] as number) ?? 300;
    if (abortSignal?.aborted) {
      const abortError = new Error('Operation aborted.');
      (abortError as { name?: string }).name = 'AbortError';
      throw abortError;
    }
    await new Promise<void>((resolve, reject) => {
      if (!abortSignal) {
        setTimeout(resolve, Math.max(0, delayMs));
        return;
      }
      const onAbort = (): void => {
        clearTimeout(timer);
        const abortError = new Error('Operation aborted.');
        (abortError as { name?: string }).name = 'AbortError';
        reject(abortError);
      };
      const timer = setTimeout(
        () => {
          abortSignal.removeEventListener('abort', onAbort);
          resolve();
        },
        Math.max(0, delayMs)
      );
      abortSignal.addEventListener('abort', onAbort, { once: true });
    });
    executed.delay.add(node.id);
  }
  const delayed: Record<string, unknown> = {};
  DELAY_OUTPUT_PORTS.forEach((port: string) => {
    if (nodeInputs[port] !== undefined) {
      delayed[port] = nodeInputs[port];
    }
  });
  return delayed;
};

export const handleViewer: NodeHandler = ({
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  return { ...nodeInputs };
};

import { getValueAtMappingPath, parseJsonSafe } from '../../utils';

export type ParameterDefinitionRecord = {
  id: string;
  selectorType: string;
  optionLabels: string[];
};

export const SELECTOR_TYPES_REQUIRING_OPTIONS = new Set<string>([
  'radio',
  'select',
  'dropdown',
  'checklist',
]);

export const MULTI_VALUE_DELIMITER = '|';

export const normalizeNonEmptyString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

export const normalizeValueTokenCase = (value: string): string => {
  const compact = value.replace(/\s+/g, ' ').trim();
  if (!compact) return '';

  const hasLowerCaseLetters = compact !== compact.toLocaleUpperCase();
  const hasUpperCaseLetters = compact !== compact.toLocaleLowerCase();
  if (hasLowerCaseLetters && hasUpperCaseLetters) {
    return compact;
  }

  return compact.replace(/\p{L}[\p{L}\p{M}]*/gu, (token: string): string => {
    if (token.length <= 3 && token === token.toLocaleUpperCase()) {
      return token;
    }
    const letters = Array.from(token);
    const first = letters[0] ?? '';
    const rest = letters.slice(1).join('');
    return `${first.toLocaleUpperCase()}${rest.toLocaleLowerCase()}`;
  });
};

export const normalizeMultiValueDelimiter = (value: string): string => {
  const trimmed = value.trim();
  if (!trimmed) return trimmed;
  const tokens = trimmed
    .split(/\s*\|\s*|\s*;\s*|\s*\r?\n+\s*|\s*,\s*/)
    .map((entry: string) => normalizeValueTokenCase(entry))
    .filter(Boolean);
  if (tokens.length <= 1) {
    return tokens[0] ?? normalizeValueTokenCase(trimmed);
  }
  const seen = new Set<string>();
  const canonicalTokens: string[] = [];
  tokens.forEach((entry: string) => {
    const key = entry.toLocaleLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    canonicalTokens.push(entry);
  });
  return canonicalTokens.join(MULTI_VALUE_DELIMITER);
};

export const parseChecklistValues = (value: string): string[] => {
  const seen = new Set<string>();
  return value
    .split(/[|,;\n]/)
    .map((entry: string) => entry.trim())
    .filter((entry: string) => {
      if (!entry) return false;
      const key = entry.toLowerCase();
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
};

export const coerceArrayLike = (value: unknown): unknown[] => {
  if (Array.isArray(value)) return value;
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    const record = value as Record<string, unknown>;
    const nested = record['items'] ?? record['rows'] ?? record['results'] ?? record['data'];
    if (Array.isArray(nested)) return nested;
  }
  if (typeof value === 'string') {
    const parsed = parseJsonSafe(value);
    if (Array.isArray(parsed)) return parsed;
    return [];
  }
  return [];
};

export const resolveParameterValue = (value: unknown): string | null => {
  if (typeof value === 'string') return normalizeNonEmptyString(value);
  if (typeof value === 'number' || typeof value === 'boolean') {
    return String(value);
  }
  if (Array.isArray(value)) {
    for (const item of value) {
      const resolved = resolveParameterValue(item);
      if (resolved) return resolved;
    }
    return null;
  }
  if (!value || typeof value !== 'object') return null;
  const record = value as Record<string, unknown>;
  const direct =
    resolveParameterValue(record['value']) ??
    resolveParameterValue(record['value_en']) ??
    resolveParameterValue(record['en']) ??
    resolveParameterValue(record['english']) ??
    resolveParameterValue(record['label']);
  if (direct) return direct;
  const valuesByLanguage = record['valuesByLanguage'];
  if (valuesByLanguage && typeof valuesByLanguage === 'object') {
    const localized = valuesByLanguage as Record<string, unknown>;
    return (
      resolveParameterValue(localized['en']) ??
      resolveParameterValue(localized['en-US']) ??
      resolveParameterValue(localized['english']) ??
      null
    );
  }
  return null;
};

export const resolveChecklistValue = (raw: unknown): string | null => {
  const arrayLike = coerceArrayLike(raw)
    .map((entry: unknown): string | null => normalizeNonEmptyString(entry))
    .filter((entry: string | null): entry is string => Boolean(entry));
  if (arrayLike.length > 0) {
    return normalizeMultiValueDelimiter(arrayLike.join(MULTI_VALUE_DELIMITER));
  }
  const resolved = resolveParameterValue(raw);
  return resolved ? normalizeMultiValueDelimiter(resolved) : null;
};

export const toRecord = (value: unknown): Record<string, unknown> | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  return value as Record<string, unknown>;
};

export const resolveObjectPathValue = (
  source: Record<string, unknown> | null,
  path: string
): unknown => {
  if (!source) return undefined;
  if (!path) return undefined;
  if (Object.prototype.hasOwnProperty.call(source, path)) {
    return source[path];
  }
  return getValueAtMappingPath(source, path);
};

export const coerceParameterInferenceCandidates = (
  value: unknown
): { candidates: unknown[]; repaired: boolean } => {
  if (Array.isArray(value)) {
    return { candidates: value, repaired: false };
  }
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    const nested = coerceArrayLike(value);
    if (nested.length > 0) {
      return { candidates: nested, repaired: false };
    }
  }
  if (typeof value !== 'string') {
    return { candidates: [], repaired: false };
  }
  const direct = parseJsonSafe(value);
  if (Array.isArray(direct)) {
    return { candidates: direct, repaired: false };
  }
  const openIndex = value.indexOf('[');
  const closeIndex = value.lastIndexOf(']');
  if (openIndex < 0 || closeIndex <= openIndex) {
    return { candidates: [], repaired: false };
  }
  const repairedCandidate = value.slice(openIndex, closeIndex + 1);
  const repaired = parseJsonSafe(repairedCandidate);
  if (Array.isArray(repaired)) {
    return { candidates: repaired, repaired: true };
  }
  return { candidates: [], repaired: false };
};

export const resolveParameterDefinitionRows = (
  definitionsValue: unknown,
  definitionsPath: string
): unknown[] => {
  let source: unknown = definitionsValue;
  if (definitionsPath && source && typeof source === 'object' && !Array.isArray(source)) {
    const resolved = getValueAtMappingPath(source, definitionsPath);
    source = resolved ?? source;
  }
  if (source && typeof source === 'object' && !Array.isArray(source)) {
    const nested =
      (source as Record<string, unknown>)['items'] ??
      (source as Record<string, unknown>)['rows'] ??
      (source as Record<string, unknown>)['results'] ??
      (source as Record<string, unknown>)['data'];
    if (Array.isArray(nested)) return nested;
  }
  return coerceArrayLike(source);
};

export const normalizeParameterDefinitions = (
  definitionsValue: unknown,
  definitionsPath: string
): Map<string, ParameterDefinitionRecord> => {
  const map = new Map<string, ParameterDefinitionRecord>();
  const rows = resolveParameterDefinitionRows(definitionsValue, definitionsPath);
  rows.forEach((row: unknown) => {
    if (!row || typeof row !== 'object') return;
    const record = row as Record<string, unknown>;
    const id =
      normalizeNonEmptyString(record['id']) ??
      normalizeNonEmptyString(record['_id']) ??
      normalizeNonEmptyString(record['parameterId']);
    if (!id) return;
    const selectorType = normalizeNonEmptyString(record['selectorType'])?.toLowerCase() ?? 'text';
    const optionLabels = coerceArrayLike(record['optionLabels'])
      .map((option: unknown): string | null => normalizeNonEmptyString(option))
      .filter((option: string | null): option is string => Boolean(option));
    map.set(id, {
      id,
      selectorType,
      optionLabels,
    });
  });
  return map;
};

