const resolveImageUrlForOutboundPolicy = (rawUrl: string): string => {
  const trimmed = rawUrl.trim();
  if (!trimmed) return trimmed;

  if (trimmed.startsWith('//')) {
    return `https:${trimmed}`;
  }

  try {
    new URL(trimmed);
    return trimmed;
  } catch (error) {
    logClientError(error);

    // Resolve relative URLs against a known app base when possible.
  }

  const baseCandidates: string[] = [];
  if (typeof window !== 'undefined') {
    const browserOrigin = window.location?.origin;
    if (typeof browserOrigin === 'string' && browserOrigin.trim().length > 0) {
      baseCandidates.push(browserOrigin.trim());
    }
  }

  const envBaseCandidates = [
    process.env['AI_PATHS_ASSET_BASE_URL'],
    process.env['NEXT_PUBLIC_APP_URL'],
    process.env['NEXTAUTH_URL'],
    process.env['VERCEL_URL'] ? `https://${process.env['VERCEL_URL']}` : null,
  ];
  envBaseCandidates.forEach((candidate) => {
    if (typeof candidate === 'string' && candidate.trim().length > 0) {
      baseCandidates.push(candidate.trim());
    }
  });

  for (const baseCandidate of baseCandidates) {
    const normalizedBase = /^[a-zA-Z][a-zA-Z\d+\-.]*:/.test(baseCandidate)
      ? baseCandidate
      : baseCandidate.startsWith('//')
        ? `https:${baseCandidate}`
        : `https://${baseCandidate.replace(/^\/+/, '')}`;
    try {
      return new URL(trimmed, normalizedBase).toString();
    } catch (error) {
      logClientError(error);
      continue;
    }
  }

  return trimmed;
};

const filterImageUrlsByOutboundPolicy = (input: {
  imageUrls: string[];
  nodeId: string;
  action: 'graphModel';
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
}): string[] => {
  if (input.imageUrls.length === 0) return [];

  const allowed: string[] = [];
  const blocked: Array<{
    url: string;
    resolvedUrl: string;
    reason: string | null;
    hostname: string | null;
  }> = [];

  input.imageUrls.forEach((url: string): void => {
    const trimmedUrl = url.trim();
    const resolvedUrl = resolveImageUrlForOutboundPolicy(trimmedUrl);

    // Relative URLs (e.g. /uploads/products/…) are self-hosted assets on this server.
    // Resolving them via the outbound policy would block them in development when the app
    // base URL is localhost.  We resolve them to absolute form so the model can fetch them,
    // but skip the outbound policy check — they cannot reach external or private networks.
    if (trimmedUrl.startsWith('/') || trimmedUrl.startsWith('./') || trimmedUrl.startsWith('../')) {
      allowed.push(resolvedUrl);
      return;
    }

    const decision = evaluateOutboundUrlPolicy(resolvedUrl);
    if (decision.allowed) {
      allowed.push(resolvedUrl);
      return;
    }
    blocked.push({
      url,
      resolvedUrl,
      reason: decision.reason,
      hostname: decision.hostname,
    });
  });

  if (blocked.length > 0) {
    const reasons = Array.from(new Set(blocked.map((entry) => entry.reason ?? 'policy_violation')))
      .slice(0, 3)
      .join(', ');
    const summary = `Blocked ${blocked.length} image URL${blocked.length === 1 ? '' : 's'} by outbound policy (${reasons}).`;
    input.reportAiPathsError(
      new Error(summary),
      {
        action: input.action,
        nodeId: input.nodeId,
        blockedImageUrlCount: blocked.length,
        blockedImageUrls: blocked.slice(0, 5),
      },
      summary
    );
    input.toast(
      `Blocked ${blocked.length} image URL${blocked.length === 1 ? '' : 's'} by outbound policy.`,
      { variant: 'warning' }
    );
  }

  return allowed;
};

type ModelTerminalStatus = 'blocked' | 'skipped';

const buildModelTerminalOutputs = (options: {
  status: ModelTerminalStatus;
  reason: string;
  details?: RuntimePortValues;
}): RuntimePortValues => {
  const base: RuntimePortValues = {
    status: options.status,
    skipReason: options.reason,
    result: '',
  };
  if (options.status === 'blocked') {
    base['blockedReason'] = options.reason;
  }
  return {
    ...base,
    ...(options.details ?? {}),
  };
};

export const handleModel: NodeHandler = async ({
  node,
  nodeInputs,
  prevOutputs,
  allOutputs,
  allInputs,
  edges,
  nodes,
  nodeById,
  runId,
  runStartedAt,
  activePathId,
  contextRegistry,
  simulationEntityType,
  simulationEntityId,
  skipAiJobs,
  executed,
  toast,
  reportAiPathsError,
  abortSignal,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  const parseIntWithMin = (raw: string | undefined, fallback: number, min: number): number => {
    const parsed = Number.parseInt(raw ?? '', 10);
    if (!Number.isFinite(parsed)) return fallback;
    return Math.max(min, parsed);
  };
  const defaultModelPollIntervalMs = parseIntWithMin(
    process.env['AI_PATHS_MODEL_POLL_INTERVAL_MS'],
    2000,
    500
  );
  const defaultModelPollTimeoutMs = parseIntWithMin(
    process.env['AI_PATHS_MODEL_POLL_TIMEOUT_MS'],
    300_000,
    30_000
  );
  const defaultModelEnqueueRetryAttempts = parseIntWithMin(
    process.env['AI_PATHS_MODEL_ENQUEUE_RETRY_ATTEMPTS'],
    3,
    1
  );
  const defaultModelEnqueueRetryBackoffMs = parseIntWithMin(
    process.env['AI_PATHS_MODEL_ENQUEUE_RETRY_BACKOFF_MS'],
    400,
    50
  );

  const sleepWithAbort = async (ms: number): Promise<void> => {
    if (!Number.isFinite(ms) || ms <= 0) return;
    await new Promise<void>((resolve, reject) => {
      if (!abortSignal) {
        setTimeout(resolve, ms);
        return;
      }
      if (abortSignal.aborted) {
        const abortError = new Error('Operation aborted.');
        (abortError as { name?: string }).name = 'AbortError';
        reject(abortError);
        return;
      }
      const onAbort = (): void => {
        clearTimeout(timer);
        const abortError = new Error('Operation aborted.');
        (abortError as { name?: string }).name = 'AbortError';
        reject(abortError);
      };
      const timer = setTimeout((): void => {
        abortSignal.removeEventListener('abort', onAbort);
        resolve();
      }, ms);
      abortSignal.addEventListener('abort', onAbort, { once: true });
    });
  };

  const isRetryableEnqueueError = (message: string): boolean => {
    const normalized = message.trim().toLowerCase();
    if (!normalized) return false;
    return (
      normalized.includes('request failed with status 404') ||
      normalized.includes('request failed with status 429') ||
      normalized.includes('request failed with status 500') ||
      normalized.includes('request failed with status 502') ||
      normalized.includes('request failed with status 503') ||
      normalized.includes('request failed with status 504') ||
      normalized.includes('request timeout') ||
      normalized.includes('network') ||
      normalized.includes('fetch failed') ||
      normalized.includes('econnreset') ||
      normalized.includes('econnrefused')
    );
  };

  if (skipAiJobs) {
    return buildModelTerminalOutputs({
      status: 'skipped',
      reason: 'ai_jobs_disabled',
    });
  }
  if (executed.ai.has(node.id)) return prevOutputs;
  const promptInputs = coerceInputArray(nodeInputs['prompt']);
  const hasMeaningfulValue = (value: unknown): boolean => {
    if (value === undefined || value === null) return false;
    if (typeof value === 'string') return value.trim().length > 0;
    if (Array.isArray(value)) return value.length > 0;
    if (typeof value === 'object') return Object.keys(value).length > 0;
    return true;
  };
  const firstMeaningfulValue = (values: unknown[]): unknown =>
    values.find((value: unknown): boolean => hasMeaningfulValue(value));
  const promptCandidates = edges
    .filter((edge: Edge) => edge.to === node.id && edge.toPort === 'prompt')
    .map((edge: Edge): PromptCandidate => {
      const fromNodeId = edge.from;
      const fromNode = fromNodeId
        ? (nodeById?.get(fromNodeId) ?? nodes.find((item: AiNode) => item.id === fromNodeId))
        : undefined;
      const sourceOutputs = fromNodeId ? (allOutputs[fromNodeId] ?? {}) : {};
      const sourceInputs = fromNodeId ? (allInputs[fromNodeId] ?? {}) : {};
      const edgeValue = sourceOutputs[edge.fromPort ?? 'prompt'];
      const promptValue = sourceOutputs['prompt'];
      const promptTemplate =
        typeof fromNode?.config?.prompt?.template === 'string'
          ? fromNode.config.prompt.template.trim()
          : '';
      const hasSourceInputValue = Object.values(sourceInputs).some(hasMeaningfulValue);
      const shouldDerivePrompt = promptTemplate.length > 0 || hasSourceInputValue;
      const derivedPromptValue =
        fromNode?.type === 'prompt' && shouldDerivePrompt
          ? buildPromptOutput(fromNode.config?.prompt, sourceInputs).promptOutput
          : undefined;
      return {
        edge,
        fromNode,
        edgeValue,
        promptValue,
        derivedPromptValue,
        sourceOutputs,
      };
    })
    .filter((entry: PromptCandidate): boolean => entry.fromNode?.type === 'prompt');
  const promptCandidate = promptCandidates.find(
    (entry: PromptCandidate): boolean =>
      hasMeaningfulValue(entry.edgeValue) ||
      hasMeaningfulValue(entry.promptValue) ||
      hasMeaningfulValue(entry.derivedPromptValue)
  );
  const promptSourceNode = promptCandidate?.fromNode ?? promptCandidates[0]?.fromNode ?? null;
  const promptSourceInputs = promptSourceNode ? (allInputs[promptSourceNode.id] ?? {}) : {};
  const promptSourceTemplate =
    typeof promptSourceNode?.config?.prompt?.template === 'string'
      ? promptSourceNode.config.prompt.template.trim()
      : '';
  const promptSourceHasInputs = Object.values(promptSourceInputs).some(hasMeaningfulValue);
  const derivedPrompt =
    promptSourceNode && (promptSourceTemplate.length > 0 || promptSourceHasInputs)
      ? buildPromptOutput(promptSourceNode.config?.prompt, promptSourceInputs)
      : null;
  const promptSourceOutput =
    firstMeaningfulValue([
      promptCandidate?.edgeValue,
      promptCandidate?.promptValue,
      promptCandidate?.derivedPromptValue,
      promptSourceNode ? allOutputs[promptSourceNode.id]?.['prompt'] : undefined,
      derivedPrompt?.promptOutput,
    ]) ?? undefined;
  const promptInput =
    firstMeaningfulValue([promptSourceOutput, ...[...promptInputs].reverse()]) ?? undefined;
  const modelConfig = node.config?.model ?? {
    temperature: 0.7,
    maxTokens: 800,
    vision: node.inputs.includes('images'),
  };
  if (promptInput === undefined || promptInput === null) {
    const promptSourceWaitingOnPorts = promptCandidates.flatMap(
      (entry: PromptCandidate): string[] => {
        const waitingOnPorts = entry.sourceOutputs['waitingOnPorts'];
        if (!Array.isArray(waitingOnPorts)) return [];
        return waitingOnPorts
          .filter((port: unknown): port is string => typeof port === 'string')
          .map((port: string): string => port.trim())
          .filter((port: string): boolean => port.length > 0);
      }
    );
    return buildModelTerminalOutputs({
      status: 'blocked',
      reason: 'missing_prompt',
      details: {
        requiredPorts: ['prompt'],
        optionalPorts: [],
        waitingOnPorts: ['prompt'],
        promptSourceNodeId: promptSourceNode?.id ?? null,
        promptSourceNodeIds: promptCandidates
          .map((entry: PromptCandidate): string | null => entry.fromNode?.id ?? null)
          .filter((value: string | null): value is string => Boolean(value)),
        ...(promptSourceWaitingOnPorts.length > 0
          ? { promptSourceWaitingOnPorts: Array.from(new Set(promptSourceWaitingOnPorts)) }
          : {}),
      },
    });
  }
  const hasResultConsumers = edges.some(
    (edge: Edge): boolean =>
      edge.from === node.id &&
      (edge.fromPort === 'result' || (edge.fromPort === undefined && edge.toPort === 'result'))
  );
  const hasPollConsumer = edges.some((edge: Edge): boolean => {
    if (edge.from !== node.id) return false;
    if (edge.fromPort && edge.fromPort !== 'jobId') return false;
    const targetNodeId = edge.to;
    if (!targetNodeId) return false;
    const targetNode =
      nodeById?.get(targetNodeId) ?? nodes.find((item: AiNode) => item.id === targetNodeId);
    return targetNode?.type === 'poll';
  });
  const waitPreference = modelConfig.waitForResult;
  let shouldWait = !hasPollConsumer && (waitPreference ?? hasResultConsumers);
  if (!hasPollConsumer && waitPreference === false && hasResultConsumers) {
    shouldWait = true;
  }
  if (waitPreference === true) {
    shouldWait = true;
  }
  const prompt =
    typeof promptInput === 'string' ? promptInput.trim() : formatRuntimeValue(promptInput);
  if (!prompt || prompt === '—') {
    return buildModelTerminalOutputs({
      status: 'blocked',
      reason: 'empty_prompt',
    });
  }
  const imageEdge = edges
    .filter((edge: Edge): boolean => edge.to === node.id && edge.toPort === 'images')
    .map((edge: Edge): { edge: Edge; fromNode: AiNode | undefined; value: unknown } => {
      const fromNodeId = edge.from;
      const fromNode = fromNodeId
        ? (nodeById?.get(fromNodeId) ?? nodes.find((item: AiNode) => item.id === fromNodeId))
        : undefined;
      const value = fromNodeId ? allOutputs[fromNodeId]?.[edge.fromPort ?? 'images'] : undefined;
      return {
        edge,
        fromNode,
        value,
      };
    })
    .find(
      (entry): boolean =>
        entry.fromNode?.type === 'prompt' && entry.value !== undefined && entry.value !== null
    );
  const promptImageOutput = promptSourceNode?.id
    ? (derivedPrompt?.imagesValue ?? allOutputs[promptSourceNode.id]?.['images'])
    : undefined;
  const imageSource =
    promptImageOutput ??
    imageEdge?.value ??
    nodeInputs['images'] ??
    nodeInputs['bundle'] ??
    nodeInputs['context'] ??
    nodeInputs['entityJson'] ??
    nodeInputs['value'] ??
    nodeInputs['result'];
  const imageUrls =
    modelConfig.vision === true
      ? filterImageUrlsByOutboundPolicy({
          imageUrls: extractImageUrls(imageSource),
          nodeId: node.id,
          action: 'graphModel',
          reportAiPathsError,
          toast,
        })
      : [];
  const payload = buildGraphModelJobPayload({
    prompt,
    ...(imageUrls.length > 0 ? { imageUrls } : {}),
    modelId: modelConfig.modelId?.trim() ?? null,
    temperature: modelConfig.temperature,
    maxTokens: modelConfig.maxTokens,
    vision: modelConfig.vision,
    systemPrompt: modelConfig.systemPrompt?.trim() ?? null,
    activePathId,
    nodeId: node.id,
    nodeTitle: node.title,
    // Keep graph-model cache scoped to a single run so repeated manual runs
    // do not silently reuse completed jobs from older runs.
    runId,
    contextRegistry,
  });
  const productId = resolveJobProductId(
    nodeInputs,
    simulationEntityType,
    simulationEntityId,
    activePathId
  );
  const { payload: enqueuePayload, request } = buildQueuedGraphModelJobEnqueueRequest({
    productId,
    payload,
    runId,
    runStartedAt,
  });
  const { cacheKey, payloadHash } = enqueuePayload;

  // Idempotency across evaluateGraph calls (seeded outputs): if we already enqueued a job for the same payload,
  // don't enqueue again. This prevents accidental duplicate jobs when the graph is re-evaluated during polling
  // or iterator auto-continue.
  const prevJobId = typeof prevOutputs['jobId'] === 'string' ? prevOutputs['jobId'].trim() : '';
  const prevPayloadHash =
    typeof prevOutputs['payloadHash'] === 'string' ? prevOutputs['payloadHash'] : '';
  if (prevJobId && prevPayloadHash === payloadHash) {
    return { ...prevOutputs, payloadHash };
  }
  let enqueuedJobId: string | undefined;
  try {
    let enqueueResult: Awaited<ReturnType<typeof aiJobsApi.enqueue>> | null = null;
    let enqueueErrorMessage: string | null = null;
    for (
      let enqueueAttempt = 1;
      enqueueAttempt <= defaultModelEnqueueRetryAttempts;
      enqueueAttempt += 1
    ) {
      enqueueResult = await aiJobsApi.enqueue(request);
      if (enqueueResult.ok) {
        enqueueErrorMessage = null;
        break;
      }
      enqueueErrorMessage = enqueueResult.error || 'Failed to enqueue AI job.';
      const shouldRetry =
        enqueueAttempt < defaultModelEnqueueRetryAttempts &&
        isRetryableEnqueueError(enqueueErrorMessage);
      if (!shouldRetry) {
        break;
      }
      await sleepWithAbort(defaultModelEnqueueRetryBackoffMs * enqueueAttempt);
    }
    if (!enqueueResult?.ok) {
      throw new Error(enqueueErrorMessage || 'Failed to enqueue AI job.');
    }
    enqueuedJobId = readEnqueuedGraphModelJobId(enqueueResult);
    toast('AI model job queued.', { variant: 'success' });
    executed.ai.add(node.id);
    if (!shouldWait) {
      return {
        jobId: enqueuedJobId,
        status: 'queued',
        debugPayload: payload,
        cacheKey,
        payloadHash,
      };
    }
    const configuredTimeoutMs =
      typeof node.config?.runtime?.timeoutMs === 'number' &&
      Number.isFinite(node.config.runtime.timeoutMs) &&
      node.config.runtime.timeoutMs > 0
        ? Math.max(1000, Math.floor(node.config.runtime.timeoutMs))
        : defaultModelPollTimeoutMs;
    const pollMaxAttempts = Math.max(
      1,
      Math.ceil(configuredTimeoutMs / defaultModelPollIntervalMs)
    );
    const result = await pollGraphJob(enqueuedJobId, {
      intervalMs: defaultModelPollIntervalMs,
      maxAttempts: pollMaxAttempts,
      ...(abortSignal ? { signal: abortSignal } : {}),
    });
    return {
      result,
      jobId: enqueuedJobId,
      status: 'completed',
      debugPayload: payload,
      cacheKey,
      payloadHash,
    };
  } catch (error) {
    logClientError(error);
    if (abortSignal?.aborted || (error instanceof Error && error.name === 'AbortError')) {
      throw error;
    }
    const errorMessage = error instanceof Error ? error.message : String(error);
    const normalizedErrorMessage = errorMessage.toLowerCase();
    const isOllamaConnectionError =
      normalizedErrorMessage.includes('could not connect to ollama server') ||
      (normalizedErrorMessage.includes('ollama') &&
        (normalizedErrorMessage.includes('econnrefused') ||
          normalizedErrorMessage.includes('fetch failed') ||
          normalizedErrorMessage.includes('failed to fetch')));
    const isHardFailure =
      isOllamaConnectionError ||
      normalizedErrorMessage.includes('ai job timed out') ||
      normalizedErrorMessage.includes('connection error after') ||
      normalizedErrorMessage.includes('job not found');

    // Unwrap "Connection error after N attempts: [real cause]" so the real cause is surfaced.
    const connectionWrapperMatch = errorMessage.match(
      /^connection error after \d+ attempts[^:]*:\s*(.+)$/is
    );
    const unwrappedErrorMessage = connectionWrapperMatch?.[1]?.trim() || errorMessage;
    const normalizedUnwrapped = unwrappedErrorMessage.toLowerCase();

    const isNoModelConfigured =
      normalizedUnwrapped.includes('no model assigned') ||
      (normalizedUnwrapped.includes('model') && normalizedUnwrapped.includes('did not select'));

    let toastMessage: string;
    if (isOllamaConnectionError) {
      toastMessage = errorMessage;
    } else if (isNoModelConfigured) {
      toastMessage =
        'No AI model configured: Select a model on the Model node in your AI Path.';
    } else if (connectionWrapperMatch) {
      toastMessage = `AI model job failed: ${unwrappedErrorMessage}`;
    } else {
      toastMessage = errorMessage.length > 0 ? errorMessage : 'AI model job failed.';
    }

    // Use the unwrapped error for classification so the toast shows the right suggested action.
    const errorForClassification =
      connectionWrapperMatch && !(error instanceof Error && error.message === unwrappedErrorMessage)
        ? new Error(unwrappedErrorMessage)
        : error instanceof Error
          ? error
          : new Error(errorMessage);

    reportAiPathsError(
      error,
      { action: 'graphModel', nodeId: node.id, ...(enqueuedJobId ? { jobId: enqueuedJobId } : {}) },
      'AI model job failed:'
    );
    toast(toastMessage, { variant: 'error', error: errorForClassification });
    executed.ai.add(node.id);
    if (isHardFailure) {
      throw error instanceof Error ? error : new Error(errorMessage);
    }
    return {
      result: '',
      jobId: enqueuedJobId,
      status: 'failed',
      error: errorMessage,
      message: errorMessage,
      debugPayload: payload,
      cacheKey,
      payloadHash,
    };
  }
};

import type { AdvancedApiConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandler, NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import {
  evaluateOutboundUrlPolicy,
  fetchWithOutboundUrlPolicy,
  OutboundUrlPolicyError,
} from '@/shared/lib/security/outbound-url-policy';

import { getValueAtMappingPath, renderTemplate, safeStringify } from '../../utils';
import { resolveAuthHeaders } from './advanced-api/auth';
import { DEFAULT_ADVANCED_API_CONFIG, type JsonRecord } from './advanced-api/config';
import {
  parseErrorRoutes,
  evaluateErrorRoute,
  resolveRetryStatuses,
  parseOutputMappings,
} from './advanced-api/routing';
import {
  toStringRecord,
  applyPathParams,
  appendQueryParams,
  sleep,
  resolveRetryDelay,
  buildMappedOutputs,
  createSignalControl,
} from './advanced-api/utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const handleAdvancedApi: NodeHandler = async ({
  node,
  nodeInputs,
  prevOutputs,
  executed,
  reportAiPathsError,
  abortSignal,
  sideEffectControl,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  if (executed.http.has(node.id)) return prevOutputs;

  const config: AdvancedApiConfig = {
    ...DEFAULT_ADVANCED_API_CONFIG,
    ...(node.config?.apiAdvanced ?? {}),
  };

  const baseUrl = renderTemplate(config.url ?? '', nodeInputs, '').trim();
  if (!baseUrl) {
    return {
      value: null,
      bundle: {
        ok: false,
        status: 0,
        error: 'Missing URL',
        route: 'missing_url',
      },
      status: 0,
      error: 'Missing URL',
      route: 'missing_url',
      success: false,
    };
  }
  const baseOutboundPolicy = evaluateOutboundUrlPolicy(baseUrl);
  if (!baseOutboundPolicy.allowed) {
    return {
      value: null,
      bundle: {
        ok: false,
        status: 0,
        error: `Blocked outbound URL (${baseOutboundPolicy.reason ?? 'policy_violation'})`,
        route: 'blocked_outbound_url',
      },
      status: 0,
      error: `Blocked outbound URL (${baseOutboundPolicy.reason ?? 'policy_violation'})`,
      route: 'blocked_outbound_url',
      success: false,
    };
  }

  const parsedPathParams = toStringRecord(
    parseJsonWithTemplates<Record<string, unknown>>(
      config.pathParamsJson,
      nodeInputs,
      {},
      reportAiPathsError,
      {
        action: 'parseAdvancedApiPathParams',
        nodeId: node.id,
      }
    )
  );
  const parsedQueryParams = toStringRecord(
    parseJsonWithTemplates<Record<string, unknown>>(
      config.queryParamsJson,
      nodeInputs,
      {},
      reportAiPathsError,
      {
        action: 'parseAdvancedApiQueryParams',
        nodeId: node.id,
      }
    )
  );
  const parsedHeaders = toStringRecord(
    parseJsonWithTemplates<Record<string, unknown>>(
      config.headersJson,
      nodeInputs,
      {},
      reportAiPathsError,
      {
        action: 'parseAdvancedApiHeaders',
        nodeId: node.id,
      }
    )
  );
  const outputMappings = parseOutputMappings(config, nodeInputs, reportAiPathsError, node.id);
  const retryStatuses = resolveRetryStatuses(config, nodeInputs, reportAiPathsError, node.id);
  const errorRoutes = parseErrorRoutes(config, nodeInputs, reportAiPathsError, node.id);

  const maxPages = Math.max(1, Math.trunc(config.maxPages ?? 1));
  const pageParam = (config.pageParam ?? 'page').trim() || 'page';
  const limitParam = (config.limitParam ?? 'limit').trim() || 'limit';
  const cursorParam = (config.cursorParam ?? 'cursor').trim() || 'cursor';
  const paginationMode = config.paginationMode ?? 'none';
  const aggregateMode = config.paginationAggregateMode ?? 'first_page';
  const pageSize = Math.max(1, Math.trunc(config.pageSize ?? 50));
  const startPage = Math.max(1, Math.trunc(config.startPage ?? 1));
  const itemsPath = (config.itemsPath ?? '').trim();
  const cursorPath = (config.cursorPath ?? '').trim();

  const rateLimitEnabled = Boolean(config.rateLimitEnabled);
  const rateLimitRequests = Math.max(1, Math.trunc(config.rateLimitRequests ?? 1));
  const rateLimitIntervalMs = Math.max(1, Math.trunc(config.rateLimitIntervalMs ?? 1000));
  const minRequestGapMs = Math.ceil(rateLimitIntervalMs / rateLimitRequests);
  let lastRequestAt = 0;

  const retryEnabled = config.retryEnabled !== false;
  const retryAttempts = Math.max(1, Math.trunc(config.retryAttempts ?? 1));
  const retryOnNetworkError = config.retryOnNetworkError !== false;

  const generatedIdempotencyKey = sideEffectControl?.idempotencyKey?.trim() ?? '';
  const idempotencyEnabled =
    Boolean(config.idempotencyEnabled) || generatedIdempotencyKey.length > 0;
  const idempotencyHeaderName = (config.idempotencyHeaderName ?? '').trim() || 'Idempotency-Key';
  const configuredIdempotencyKey = renderTemplate(
    config.idempotencyKeyTemplate ?? '',
    nodeInputs,
    ''
  ).trim();
  const idempotencyKey = configuredIdempotencyKey || generatedIdempotencyKey;

  const baseResolvedUrl = applyPathParams(baseUrl, parsedPathParams);
  const aggregateItems: unknown[] = [];

  let page = startPage;
  let cursor = '';
  let pageCount = 0;
  let lastEnvelope: JsonRecord | null = null;

  const executeRequest = async (
    requestUrl: string,
    queryParams: Record<string, string>,
    headers: Record<string, string>,
    attempt: number
  ): Promise<{
    envelope: JsonRecord;
    responseText: string;
    status: number;
    ok: boolean;
    route: unknown;
    timedOut: boolean;
    networkError: boolean;
    responseData: unknown;
  }> => {
    const withAuth = await resolveAuthHeaders(config, nodeInputs, headers, queryParams);
    const finalUrl = appendQueryParams(requestUrl, withAuth.queryParams);
    const finalHeaders: Record<string, string> = { ...withAuth.headers };
    const outboundPolicy = evaluateOutboundUrlPolicy(finalUrl);
    if (!outboundPolicy.allowed) {
      return {
        envelope: {
          ok: false,
          status: 0,
          url: finalUrl,
          method: config.method,
          headers: {},
          data: null,
          value: null,
          attempt,
          page,
          cursor,
          route: 'blocked_outbound_url',
          error: `Blocked outbound URL (${outboundPolicy.reason ?? 'policy_violation'})`,
          timedOut: false,
          networkError: false,
        },
        responseText: '',
        status: 0,
        ok: false,
        route: null,
        timedOut: false,
        networkError: false,
        responseData: null,
      };
    }

    if (idempotencyEnabled && idempotencyHeaderName && idempotencyKey) {
      finalHeaders[idempotencyHeaderName] = idempotencyKey;
    }

    let body: BodyInit | undefined;
    const bodyMode = config.bodyMode ?? 'none';
    if (config.method !== 'GET' && config.method !== 'DELETE' && bodyMode !== 'none') {
      const renderedBody = renderTemplate(config.bodyTemplate ?? '', nodeInputs, '');
      if (renderedBody.trim()) {
        if (bodyMode === 'json') {
          body = renderedBody;
          if (!finalHeaders['Content-Type']) {
            finalHeaders['Content-Type'] = 'application/json';
          }
        } else {
          body = renderedBody;
          if (!finalHeaders['Content-Type']) {
            finalHeaders['Content-Type'] = 'text/plain';
          }
        }
      }
    }

    const signalControl = createSignalControl(abortSignal, config.timeoutMs);
    try {
      const response = await fetchWithOutboundUrlPolicy(finalUrl, {
        method: config.method,
        headers: finalHeaders,
        ...(body !== undefined ? { body } : {}),
        ...(signalControl.signal ? { signal: signalControl.signal } : {}),
        maxRedirects: 5,
      });
      const responseText = await response.text();
      const responseHeaders = Object.fromEntries(response.headers.entries());

      let responseData: unknown = null;
      const responseMode = config.responseMode ?? 'json';
      if (responseMode === 'status') {
        responseData = response.status;
      } else if (responseMode === 'text') {
        responseData = responseText;
      } else {
        try {
          responseData = responseText.trim().length > 0 ? JSON.parse(responseText) : null;
        } catch (error) {
          logClientError(error);
          responseData = responseText;
        }
      }

      const baseValue = config.responsePath
        ? getValueAtMappingPath(responseData, config.responsePath)
        : responseData;
      const resolvedValue = baseValue === undefined ? responseData : baseValue;

      const route = evaluateErrorRoute(errorRoutes, {
        status: response.status,
        responseText,
        timedOut: false,
        networkError: false,
      });

      return {
        envelope: {
          ok: response.ok,
          status: response.status,
          url: finalUrl,
          method: config.method,
          headers: responseHeaders,
          data: responseData,
          value: resolvedValue,
          attempt,
          page,
          cursor,
          route: route?.id ?? null,
        },
        responseText,
        status: response.status,
        ok: response.ok,
        route,
        timedOut: false,
        networkError: false,
        responseData,
      };
    } catch (error) {
      logClientError(error);
      if (error instanceof OutboundUrlPolicyError) {
        return {
          envelope: {
            ok: false,
            status: 0,
            url: finalUrl,
            method: config.method,
            headers: {},
            data: null,
            value: null,
            attempt,
            page,
            cursor,
            route: 'blocked_outbound_url',
            error: `Blocked outbound URL (${error.decision.reason ?? 'policy_violation'})`,
            timedOut: false,
            networkError: false,
          },
          responseText: '',
          status: 0,
          ok: false,
          route: null,
          timedOut: false,
          networkError: false,
          responseData: null,
        };
      }

      const timedOut = signalControl.wasTimeout();
      const route = evaluateErrorRoute(errorRoutes, {
        status: 0,
        responseText: '',
        timedOut,
        networkError: !timedOut,
      });

      return {
        envelope: {
          ok: false,
          status: 0,
          url: finalUrl,
          method: config.method,
          headers: {},
          data: null,
          value: null,
          attempt,
          page,
          cursor,
          route: route?.id ?? (timedOut ? 'timeout' : 'network_error'),
          error: timedOut
            ? 'Request timed out'
            : error instanceof Error
              ? error.message
              : 'Network error',
          timedOut,
          networkError: !timedOut,
        },
        responseText: '',
        status: 0,
        ok: false,
        route,
        timedOut,
        networkError: !timedOut,
        responseData: null,
      };
    } finally {
      signalControl.cleanup();
    }
  };

  while (pageCount < maxPages) {
    const queryParams = { ...parsedQueryParams };
    if (paginationMode === 'page') {
      queryParams[pageParam] = String(page);
      if (limitParam) queryParams[limitParam] = String(pageSize);
    } else if (paginationMode === 'cursor' && cursor) {
      queryParams[cursorParam] = cursor;
      if (limitParam) queryParams[limitParam] = String(pageSize);
    }

    let attempt = 0;
    let result: Awaited<ReturnType<typeof executeRequest>> | null = null;

    while (attempt < retryAttempts) {
      attempt += 1;

      if (rateLimitEnabled) {
        const now = Date.now();
        const elapsedSinceLast = now - lastRequestAt;
        if (elapsedSinceLast < minRequestGapMs) {
          await sleep(minRequestGapMs - elapsedSinceLast);
        }
      }

      lastRequestAt = Date.now();
      result = await executeRequest(baseResolvedUrl, queryParams, parsedHeaders, attempt);

      if (result.ok && !result.route) break;

      const shouldRetry =
        retryEnabled &&
        attempt < retryAttempts &&
        (retryStatuses.has(result.status) || (retryOnNetworkError && result.networkError));

      if (!shouldRetry) break;

      const delay = resolveRetryDelay(attempt, config);
      if (delay > 0) await sleep(delay);
    }

    if (!result) break; // Should not happen

    lastEnvelope = result.envelope;
    const responseData = result.responseData;

    if (paginationMode !== 'none') {
      const rawItems: unknown =
        Array.isArray(responseData)
          ? responseData
          : itemsPath
            ? getValueAtMappingPath(responseData, itemsPath)
            : [];
      const items: unknown[] = Array.isArray(rawItems) ? rawItems : [];

      for (const item of items) {
        aggregateItems.push(item);
      }

      if (paginationMode === 'page') {
        page += 1;
      } else if (paginationMode === 'cursor') {
        const nextCursor = cursorPath
          ? (getValueAtMappingPath(responseData, cursorPath) as string)
          : null;
        if (!nextCursor || nextCursor === cursor) break;
        cursor = nextCursor;
      }

      if (!Array.isArray(items) || items.length < pageSize) break;
    }

    pageCount += 1;
    if (result.route || !result.ok) break;
  }

  if (!lastEnvelope) {
    throw new Error('Advanced API execution failed to produce an envelope');
  }

  const finalEnvelope: JsonRecord = {
    ...lastEnvelope,
    ...(paginationMode !== 'none' ? { items: aggregateItems, pageCount } : {}),
  };

  const outputs = buildMappedOutputs(outputMappings, finalEnvelope);
  const envelopeStatus = typeof finalEnvelope['status'] === 'number' ? finalEnvelope['status'] : 0;
  const envelopeOk = finalEnvelope['ok'] === true;
  const envelopeError = typeof finalEnvelope['error'] === 'string' ? finalEnvelope['error'] : null;
  const envelopeRoute = typeof finalEnvelope['route'] === 'string' ? finalEnvelope['route'] : null;

  return {
    ...outputs,
    value:
      paginationMode !== 'none' && (aggregateMode as string) === 'all_pages'
        ? aggregateItems
        : finalEnvelope['value'],
    bundle: finalEnvelope,
    status: envelopeStatus,
    ok: envelopeOk,
    error: envelopeError,
    success: envelopeOk,
    route: envelopeRoute,
  };
};

function parseJsonWithTemplates<T>(
  raw: string | undefined,
  nodeInputs: RuntimePortValues,
  fallback: T,
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'],
  meta: Record<string, unknown>
): T {
  if (typeof raw !== 'string' || raw.trim().length === 0) return fallback;
  const renderedWithValue = raw.replace(
    /{{\s*([^}]+)\s*}}/g,
    (_match: string, token: string): string => {
      const key = String(token).trim();
      if (!key) return '';
      if (key === 'value' || key === 'current') {
        return safeStringify(nodeInputs['value']);
      }
      return safeStringify(getValueAtMappingPath(nodeInputs, key));
    }
  );
  try {
    return JSON.parse(renderedWithValue) as T;
  } catch (error) {
    logClientError(error);
    reportAiPathsError(error, meta, 'Invalid advanced API JSON config:');
    return fallback;
  }
}

import type { DatabaseConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import { entityApi } from '@/shared/lib/ai-paths/api';

import { resolveEntityIdFromInputs } from '../utils';

export type HandleDatabaseDeleteOperationInput = {
  node: NodeHandlerContext['node'];
  nodeInputs: RuntimePortValues;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  simulationEntityType: string | null;
  simulationEntityId: string | null;
  dbConfig: DatabaseConfig;
  dryRun: boolean;
  aiPrompt: string;
};

type DeleteEntityResult = { ok: boolean; error?: string };

const buildDeleteOperationResult = (
  deleteResult: Record<string, unknown>,
  aiPrompt: string
): RuntimePortValues => ({
  result: deleteResult,
  bundle: deleteResult,
  aiPrompt,
});

const buildMissingEntityIdResult = (aiPrompt: string): RuntimePortValues => ({
  result: null,
  bundle: { error: 'Missing entity id' },
  aiPrompt,
});

const reportMissingEntityId = (
  nodeId: string,
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'],
  toast: NodeHandlerContext['toast']
): void => {
  reportAiPathsError(
    new Error('Database delete missing entity id'),
    { action: 'deleteEntity', nodeId },
    'Database delete missing entity id:'
  );
  toast('Database delete needs an entity ID input.', { variant: 'error' });
};

const reportDeleteFailure = (input: {
  nodeId: string;
  entityType: string;
  entityId: string;
  error: string | undefined;
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
}): void => {
  input.reportAiPathsError(
    new Error(input.error),
    {
      action: 'deleteEntity',
      entityType: input.entityType,
      entityId: input.entityId,
      nodeId: input.nodeId,
    },
    'Database delete failed:'
  );
  input.toast(`Failed to delete ${input.entityType}.`, { variant: 'error' });
};

const reportDeleteSuccess = (
  entityType: string,
  entityId: string,
  toast: NodeHandlerContext['toast']
): void => {
  toast(`Deleted ${entityType} ${entityId}`, { variant: 'success' });
};

const buildUnsupportedDeleteResult = (entityId: string, aiPrompt: string): RuntimePortValues =>
  ({
    result: { ok: false },
    bundle: { ok: false, entityId },
    aiPrompt,
  });

const getDeleteEntityOperation = (
  entityType: string
): ((entityId: string) => Promise<DeleteEntityResult>) | null => {
  if (entityType === 'product') return entityApi.deleteProduct;
  if (entityType === 'note') return entityApi.deleteNote;
  return null;
};

export async function handleDatabaseDeleteOperation(
  input: HandleDatabaseDeleteOperationInput
): Promise<RuntimePortValues> {
  const {
    node,
    nodeInputs,
    executed,
    reportAiPathsError,
    toast,
    simulationEntityType,
    simulationEntityId,
    dbConfig,
    dryRun,
    aiPrompt,
  } = input;
  const entityType = (dbConfig.entityType ?? 'product').trim().toLowerCase();
  const idField = dbConfig.idField ?? 'entityId';
  const entityId = resolveEntityIdFromInputs(
    nodeInputs,
    idField,
    simulationEntityType,
    simulationEntityId
  );
  if (!entityId) {
    reportMissingEntityId(node.id, reportAiPathsError, toast);
    return buildMissingEntityIdResult(aiPrompt);
  }

  const defaultDeleteResult: Record<string, unknown> = { ok: false };
  if (executed.updater.has(node.id)) {
    return buildDeleteOperationResult(defaultDeleteResult, aiPrompt);
  }

  if (dryRun) {
    executed.updater.add(node.id);
    return buildDeleteOperationResult({ ok: true, dryRun: true, entityId, entityType }, aiPrompt);
  }

  const deleteEntity = getDeleteEntityOperation(entityType);
  if (!deleteEntity) {
    toast('Custom deletes are not supported yet.', { variant: 'error' });
    executed.updater.add(node.id);
    return buildUnsupportedDeleteResult(entityId, aiPrompt);
  }

  const deleteResult = await deleteEntity(entityId);
  executed.updater.add(node.id);
  if (!deleteResult.ok) {
    reportDeleteFailure({
      nodeId: node.id,
      entityType,
      entityId,
      error: deleteResult.error,
      reportAiPathsError,
      toast,
    });
    return buildDeleteOperationResult(defaultDeleteResult, aiPrompt);
  }

  reportDeleteSuccess(entityType, entityId, toast);
  return buildDeleteOperationResult({ ok: true, entityId }, aiPrompt);
}

import type {
  DatabaseConfig,
  DatabaseWriteOutcome,
  DbQueryConfig,
  RuntimePortValues,
  DatabaseOperation,
} from '@/shared/contracts/ai-paths';
import type { NodeHandler, NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import type { SchemaResponse } from '@/shared/lib/ai-paths/api/client';
import {
  extractAiPathsCollectionMapFromRunMeta,
  withAiPathsCollectionMapInput,
} from '@/shared/lib/ai-paths/core/utils/collection-mapping';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { ParameterInferenceGateError } from './database-parameter-inference';
import { resolveDatabaseInputs } from './integration-database-input-resolution';
import { handleDatabaseMongoAction } from './integration-database-mongo-actions';
import { handleDatabaseStandardOperation } from './integration-database-operations';
import { prepareDatabaseTemplateContext } from './integration-database-template-context';
import { getCachedSchema } from './integration-schema-handler';
import { DEFAULT_DB_QUERY } from '../../constants';
import { logClientError } from '@/shared/utils/observability/client-error-logger';



const WRITE_ACTION_CATEGORIES = new Set<string>(['create', 'update', 'delete']);
const WRITE_ACTIONS = new Set<string>([
  'insertone',
  'insertmany',
  'create',
  'createone',
  'createmany',
  'updateone',
  'updatemany',
  'findoneandupdate',
  'replaceone',
  'update',
  'deleteone',
  'deletemany',
  'findoneanddelete',
  'delete',
]);

type DatabaseTerminalError = Error & {
  nodeOutput?: RuntimePortValues;
};

const createDatabaseTerminalError = (
  message: string,
  nodeOutput?: RuntimePortValues
): DatabaseTerminalError => {
  const error = new Error(message) as DatabaseTerminalError;
  if (nodeOutput) {
    error.nodeOutput = nodeOutput;
  }
  return error;
};

const isWriteDatabaseOperation = (config: DatabaseConfig): boolean => {
  const operation: DatabaseOperation = config.operation ?? 'query';
  if (operation === 'insert' || operation === 'update' || operation === 'delete') {
    return true;
  }
  const actionCategory = config.actionCategory ?? null;
  return Boolean(
    config.useMongoActions &&
    (actionCategory === 'create' || actionCategory === 'update' || actionCategory === 'delete')
  );
};

const isWriteResultOperation = (config: DatabaseConfig, result: RuntimePortValues): boolean => {
  if (isWriteDatabaseOperation(config)) return true;

  const debugPayload = result['debugPayload'];
  if (isObjectRecord(debugPayload)) {
    const actionCategory = debugPayload['actionCategory'];
    if (
      typeof actionCategory === 'string' &&
      WRITE_ACTION_CATEGORIES.has(actionCategory.toLowerCase())
    ) {
      return true;
    }
    const action = debugPayload['action'];
    if (typeof action === 'string' && WRITE_ACTIONS.has(action.toLowerCase())) {
      return true;
    }
  }

  const bundle = result['bundle'];
  if (isObjectRecord(bundle)) {
    const action = bundle['action'];
    if (typeof action === 'string' && WRITE_ACTIONS.has(action.toLowerCase())) {
      return true;
    }
    if (
      bundle['modifiedCount'] !== undefined ||
      bundle['matchedCount'] !== undefined ||
      bundle['upsertedCount'] !== undefined ||
      bundle['deletedCount'] !== undefined ||
      bundle['insertedCount'] !== undefined
    ) {
      return true;
    }
  }

  return false;
};

const readDatabaseErrorText = (value: unknown): string | null =>
  typeof value === 'string' && value.trim().length > 0 ? value.trim() : null;

const readDatabaseErrorFromRecord = (value: unknown): string | null => {
  if (!isObjectRecord(value)) {
    return null;
  }
  return readDatabaseErrorText(value['error']);
};

const DATABASE_ERROR_RESULT_KEYS = ['bundle', 'result'] as const;

const extractDatabaseError = (result: RuntimePortValues): string | null => {
  const directError = readDatabaseErrorText(result['error']);
  if (directError) {
    return directError;
  }

  for (const key of DATABASE_ERROR_RESULT_KEYS) {
    const nestedError = readDatabaseErrorFromRecord(result[key]);
    if (nestedError) {
      return nestedError;
    }
  }

  return null;
};

const extractWriteOutcome = (result: RuntimePortValues): DatabaseWriteOutcome | null => {
  const direct = result['writeOutcome'];
  if (isObjectRecord(direct)) {
    return direct as DatabaseWriteOutcome;
  }
  const bundle = result['bundle'];
  if (isObjectRecord(bundle) && isObjectRecord(bundle['writeOutcome'])) {
    return bundle['writeOutcome'] as DatabaseWriteOutcome;
  }
  return null;
};

const extractGuardrailSeverity = (result: RuntimePortValues): 'warning' | 'error' | null => {
  const directMeta = result['guardrailMeta'];
  if (isObjectRecord(directMeta)) {
    const severity = directMeta['severity'];
    if (severity === 'warning' || severity === 'error') {
      return severity;
    }
  }
  const bundle = result['bundle'];
  if (isObjectRecord(bundle) && isObjectRecord(bundle['guardrailMeta'])) {
    const severity = bundle['guardrailMeta']['severity'];
    if (severity === 'warning' || severity === 'error') {
      return severity;
    }
  }
  return null;
};

const shouldTreatWriteErrorAsTerminal = (result: RuntimePortValues): boolean => {
  const writeOutcome = extractWriteOutcome(result);
  if (writeOutcome?.status === 'failed') return true;
  if (writeOutcome?.status === 'warning') return false;
  const guardrailSeverity = extractGuardrailSeverity(result);
  if (guardrailSeverity === 'error') return true;
  if (guardrailSeverity === 'warning') return false;
  return true;
};

const shouldLoadDatabaseSchema = ({
  aiPromptTemplate,
  dbConfig,
  queryConfig,
}: {
  aiPromptTemplate: string;
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
}): boolean => {
  const templateSources: string[] = [
    aiPromptTemplate,
    queryConfig.queryTemplate ?? '',
    dbConfig.updateTemplate ?? '',
  ].filter((value: string): boolean => value.trim().length > 0);

  return templateSources.some((value: string) => value.includes('{{Collection:'));
};

const resolveDatabaseSchemaInput = async (
  resolvedInputs: Record<string, unknown>
): Promise<SchemaResponse | null> => {
  const schemaInput = resolvedInputs['schema'];
  if (
    schemaInput &&
    typeof schemaInput === 'object' &&
    'collections' in (schemaInput as Record<string, unknown>)
  ) {
    return schemaInput as SchemaResponse;
  }

  const schemaResult = await getCachedSchema();
  if (schemaResult.ok) {
    return schemaResult.data as SchemaResponse;
  }
  return null;
};

const resolveDatabaseSchemaData = async ({
  aiPromptTemplate,
  dbConfig,
  queryConfig,
  resolvedInputs,
}: {
  aiPromptTemplate: string;
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  resolvedInputs: Record<string, unknown>;
}): Promise<SchemaResponse | null> => {
  if (!shouldLoadDatabaseSchema({ aiPromptTemplate, dbConfig, queryConfig })) {
    return null;
  }

  return await resolveDatabaseSchemaInput(resolvedInputs);
};

const handleWriteOperationResult = ({
  dbConfig,
  result,
  writeOperationDetected,
}: {
  dbConfig: DatabaseConfig;
  result: RuntimePortValues;
  writeOperationDetected: boolean;
}): {
  result: RuntimePortValues;
  terminalError: DatabaseTerminalError | null;
  writeOperationDetected: boolean;
} => {
  const nextWriteOperationDetected =
    writeOperationDetected || isWriteResultOperation(dbConfig, result);
  const operationError = extractDatabaseError(result);

  return {
    result,
    terminalError:
      nextWriteOperationDetected &&
      operationError &&
      shouldTreatWriteErrorAsTerminal(result)
        ? createDatabaseTerminalError(operationError, result)
        : null,
    writeOperationDetected: nextWriteOperationDetected,
  };
};

const handleDatabaseUnexpectedFailure = ({
  error,
  nodeId,
  reportAiPathsError,
  writeOperationDetected,
}: {
  error: unknown;
  nodeId: string;
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  writeOperationDetected: boolean;
}): RuntimePortValues => {
  if (error instanceof ParameterInferenceGateError) {
    throw error;
  }
  reportAiPathsError(
    error,
    { action: 'handleDatabase', nodeId },
    'Unexpected database node failure:'
  );
  if (writeOperationDetected) {
    if (error instanceof Error) {
      throw error;
    }
    throw createDatabaseTerminalError(
      typeof error === 'string' ? error : 'Database write failed'
    );
  }
  return {
    result: null,
    bundle: { error: error instanceof Error ? error.message : 'Unknown database error' },
  };
};

export const handleDatabase: NodeHandler = async ({
  node,
  nodeInputs,
  prevOutputs,
  executed,
  reportAiPathsError,
  toast,
  fetchEntityCached,
  simulationEntityType,
  simulationEntityId,
  triggerContext,
  fallbackEntityId,
  strictFlowMode = true,
  runMeta,
  runId,
  runStartedAt,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  const defaultQuery: DbQueryConfig = DEFAULT_DB_QUERY;
  const dbConfig: DatabaseConfig = (node.config?.database as DatabaseConfig) ?? {
    operation: 'query',
    entityType: 'product',
    idField: 'entityId',
    mode: 'replace',
    mappings: [],
    query: defaultQuery,
    writeSource: 'bundle',
    writeSourcePath: '',
    dryRun: false,
    writeOutcomePolicy: {
      onZeroAffected: 'fail',
    },
  };
  let writeOperationDetected = isWriteDatabaseOperation(dbConfig);

  try {
    const resolvedInputsBase: Record<string, unknown> = resolveDatabaseInputs({
      nodeInputs,
      triggerContext,
      fallbackEntityId,
      simulationEntityType,
      strictFlowMode,
    });
    const collectionMap = extractAiPathsCollectionMapFromRunMeta(runMeta);
    const resolvedInputs: Record<string, unknown> = withAiPathsCollectionMapInput(
      resolvedInputsBase,
      collectionMap
    );
    const nodeInputPorts: string[] = Array.isArray(node.inputs) ? node.inputs : [];
    const operation: DatabaseOperation = dbConfig.operation ?? 'query';
    const queryConfig: DbQueryConfig = { ...defaultQuery, ...(dbConfig.query ?? {}) };
    const dryRun: boolean = dbConfig.dryRun ?? false;
    const writeSourcePath: string = dbConfig.writeSourcePath?.trim() ?? '';
    const aiPromptTemplate: string = dbConfig.aiPrompt ?? '';
    const useMongoActions: boolean = Boolean(
      dbConfig.useMongoActions && dbConfig.actionCategory && dbConfig.action
    );

    const schemaData = await resolveDatabaseSchemaData({
      aiPromptTemplate,
      dbConfig,
      queryConfig,
      resolvedInputs,
    });
    const {
      templateInputValue,
      templateInputs,
      templateContext,
      aiPrompt,
      ensureExistingParameterTemplateContext,
    } = prepareDatabaseTemplateContext({
      resolvedInputs,
      dbConfig,
      aiPromptTemplate,
      runId,
      runStartedAt,
      simulationEntityType,
      fallbackEntityId,
      fetchEntityCached,
      schemaData,
      strictFlowMode,
    });

    if (useMongoActions) {
      const mongoActionResult = await handleDatabaseMongoAction({
        node,
        nodeInputs,
        prevOutputs,
        executed,
        reportAiPathsError,
        toast,
        simulationEntityType,
        simulationEntityId,
        resolvedInputs,
        nodeInputPorts,
        dbConfig,
        queryConfig,
        dryRun,
        templateInputValue,
        templateInputs,
        templateContext,
        aiPrompt,
        ensureExistingParameterTemplateContext,
        strictFlowMode,
        });
      if (mongoActionResult) {
        const mongoResult = handleWriteOperationResult({
          dbConfig,
          result: mongoActionResult,
          writeOperationDetected,
        });
        writeOperationDetected = mongoResult.writeOperationDetected;
        if (mongoResult.terminalError) {
          throw mongoResult.terminalError;
        }
        return mongoResult.result;
      }
    }

    const operationResult = await handleDatabaseStandardOperation({
      operation,
      node,
      nodeInputs,
      prevOutputs,
      executed,
      reportAiPathsError,
      toast,
      simulationEntityType,
      simulationEntityId,
      resolvedInputs,
      nodeInputPorts,
      dbConfig,
      queryConfig,
      dryRun,
      writeSourcePath,
      templateInputValue,
      templateInputs,
      templateContext,
      aiPrompt,
      ensureExistingParameterTemplateContext,
      strictFlowMode,
    });
    const standardResult = handleWriteOperationResult({
      dbConfig,
      result: operationResult,
      writeOperationDetected,
    });
    writeOperationDetected = standardResult.writeOperationDetected;
    if (standardResult.terminalError) {
      throw standardResult.terminalError;
    }
    return standardResult.result;
  } catch (error) {
    logClientError(error);
    return handleDatabaseUnexpectedFailure({
      error,
      nodeId: node.id,
      reportAiPathsError,
      writeOperationDetected,
    });
  }
};

import { coerceInput } from '../../utils/runtime';

export type ResolveDatabaseInputsInput = {
  nodeInputs: Record<string, unknown>;
  triggerContext: unknown;
  fallbackEntityId: string | null;
  simulationEntityType: string | null;
  strictFlowMode?: boolean;
};

export function resolveDatabaseInputs({
  nodeInputs,
  triggerContext,
  fallbackEntityId,
  simulationEntityType,
  strictFlowMode = true,
}: ResolveDatabaseInputsInput): Record<string, unknown> {
  const next: Record<string, unknown> = { ...nodeInputs };
  const pickString = (value: unknown): string | undefined =>
    typeof value === 'string' && value.trim().length > 0 ? value.trim() : undefined;
  const pickCatalogId = (
    record: Record<string, unknown> | null | undefined
  ): string | undefined => {
    if (!record || typeof record !== 'object') return undefined;
    return pickString(record['catalogId']);
  };
  const pickFromContext = (ctx: Record<string, unknown> | null | undefined): void => {
    if (!ctx || typeof ctx !== 'object') return;
    const entityId: string | undefined =
      pickString(ctx['entityId']) ??
      pickString(ctx['productId']) ??
      pickString(ctx['id']) ??
      pickString(ctx['_id']);
    const productId: string | undefined =
      pickString(ctx['productId']) ??
      pickString(ctx['entityId']) ??
      pickString(ctx['id']) ??
      pickString(ctx['_id']);
    const entityType: string | undefined = pickString(ctx['entityType']);
    const catalogId: string | undefined = pickCatalogId(ctx);
    if (next['entityId'] === undefined && entityId) next['entityId'] = entityId;
    if (next['productId'] === undefined && productId) next['productId'] = productId;
    if (next['entityType'] === undefined && entityType) {
      next['entityType'] = entityType;
    }
    if (next['catalogId'] === undefined && catalogId) {
      next['catalogId'] = catalogId;
    }
  };
  const applyFromObject = (record: Record<string, unknown>): void => {
    const entityId: string | undefined =
      pickString(record['entityId']) ??
      pickString(record['productId']) ??
      pickString(record['id']) ??
      pickString(record['_id']);
    const productId: string | undefined =
      pickString(record['productId']) ??
      pickString(record['entityId']) ??
      pickString(record['id']) ??
      pickString(record['_id']);
    const entityType: string | undefined = pickString(record['entityType']);
    const catalogId: string | undefined = pickCatalogId(record);
    if (next['entityId'] === undefined && entityId) next['entityId'] = entityId;
    if (next['productId'] === undefined && productId) next['productId'] = productId;
    if (next['entityType'] === undefined && entityType) {
      next['entityType'] = entityType;
    }
    if (next['catalogId'] === undefined && catalogId) {
      next['catalogId'] = catalogId;
    }
  };
  const contextValue: unknown = coerceInput(nodeInputs['context']);
  if (contextValue && typeof contextValue === 'object') {
    applyFromObject(contextValue as Record<string, unknown>);
  }
  const metaValue: unknown = coerceInput(nodeInputs['meta']);
  if (metaValue && typeof metaValue === 'object') {
    applyFromObject(metaValue as Record<string, unknown>);
  }
  const bundleValue: unknown = coerceInput(nodeInputs['bundle']);
  if (bundleValue && typeof bundleValue === 'object') {
    applyFromObject(bundleValue as Record<string, unknown>);
  }
  if (!strictFlowMode) {
    pickFromContext(triggerContext as Record<string, unknown>);
    if (next['entityId'] === undefined && fallbackEntityId) {
      next['entityId'] = fallbackEntityId;
    }
    if (next['productId'] === undefined && next['entityId']) {
      next['productId'] = next['entityId'];
    }
    if (next['entityType'] === undefined && simulationEntityType) {
      next['entityType'] = simulationEntityType;
    }
    if (next['value'] === undefined) {
      const fallbackValue =
        (typeof next['entityId'] === 'string' && next['entityId'].trim()
          ? next['entityId']
          : undefined) ??
        (typeof next['productId'] === 'string' && next['productId'].trim()
          ? next['productId']
          : undefined);
      if (fallbackValue) {
        next['value'] = fallbackValue;
      }
    }
  }
  return next;
}

import type {
  DatabaseConfig,
  DatabaseWriteOutcome,
  DbQueryConfig,
} from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import type { HttpResult } from '@/shared/contracts/http';
import { dbApi, entityApi } from '@/shared/lib/ai-paths/api';

import { buildDbQueryPayload, buildFormData } from '../utils';
import {
  evaluateWriteOutcome,
  resolveWriteOutcomePolicy,
} from './integration-database-write-guardrails';

export type ExecuteDatabaseInsertInput = {
  node: NodeHandlerContext['node'];
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  templateContext: Record<string, unknown>;
  dryRun: boolean;
  payload: Record<string, unknown>;
  entityType: string;
  configuredCollection: string;
  forceCollectionInsert: boolean;
};

export async function executeDatabaseInsert({
  node,
  executed,
  reportAiPathsError,
  toast,
  dbConfig,
  queryConfig,
  templateContext,
  dryRun,
  payload,
  entityType,
  configuredCollection,
  forceCollectionInsert,
}: ExecuteDatabaseInsertInput): Promise<unknown> {
  let insertResult: unknown = payload;
  let writeOutcome: DatabaseWriteOutcome = {
    status: 'success',
    operation: 'insert',
  };

  const applyInsertWriteOutcome = (
    action: string,
    resultPayload: unknown,
    context: Record<string, unknown>
  ): void => {
    const outcome = evaluateWriteOutcome({
      operation: 'insert',
      action,
      result: resultPayload,
      policy: resolveWriteOutcomePolicy(dbConfig),
    });
    writeOutcome = outcome.writeOutcome;
    if (!outcome.isZeroAffected) return;
    const message =
      outcome.writeOutcome.message ?? `Database write affected 0 records for insert (${action}).`;
    if (outcome.writeOutcome.status === 'failed') {
      reportAiPathsError(
        new Error(message),
        {
          action: 'dbWriteOutcome',
          nodeId: node.id,
          ...context,
          writeOutcome: outcome.writeOutcome,
        },
        'Database insert failed:'
      );
      toast(message, { variant: 'error' });
      throw new Error(message);
    }
    toast(message, { variant: 'warning' });
  };

  if (!executed.updater.has(node.id)) {
    if (dryRun) {
      insertResult = {
        dryRun: true,
        entityType,
        ...(configuredCollection ? { collection: configuredCollection } : {}),
        payload,
      };
      writeOutcome = {
        status: 'success',
        operation: 'insert',
      };
      executed.updater.add(node.id);
    } else if (forceCollectionInsert) {
      const queryPayload = buildDbQueryPayload(templateContext, queryConfig);
      const collection = queryPayload.collection?.trim() || configuredCollection || entityType;
      const customInsertPayload = {
        ...(queryPayload.provider
          ? {
            provider: queryPayload.provider,
          }
          : {}),
        ...(queryPayload.collectionMap
          ? {
            collectionMap: queryPayload.collectionMap,
          }
          : {}),
        action: 'insertOne' as const,
        collection,
        document: payload,
      };
      const customInsertResult: HttpResult<unknown> = await dbApi.action(customInsertPayload);
      executed.updater.add(node.id);
      if (!customInsertResult.ok) {
        reportAiPathsError(
          new Error(customInsertResult.error),
          {
            action: 'insertEntity',
            entityType,
            collection,
            nodeId: node.id,
          },
          'Database insert failed:'
        );
        toast(customInsertResult.error || `Failed to insert ${collection}.`, {
          variant: 'error',
        });
      } else {
        insertResult = customInsertResult.data;
        applyInsertWriteOutcome('insertOne', customInsertResult.data, {
          collection,
        });
        if (writeOutcome.status !== 'warning') {
          toast(`Inserted ${collection}`, { variant: 'success' });
        }
      }
    } else if (entityType === 'product') {
      const productResult: HttpResult<unknown> = await entityApi.createProduct(
        buildFormData(payload)
      );
      executed.updater.add(node.id);
      if (!productResult.ok) {
        reportAiPathsError(
          new Error(productResult.error),
          { action: 'insertEntity', entityType, nodeId: node.id },
          'Database insert failed:'
        );
        toast(`Failed to insert ${entityType}.`, { variant: 'error' });
      } else {
        insertResult = productResult.data;
        applyInsertWriteOutcome('entityCreate', productResult.data, {
          entityType,
        });
        if (writeOutcome.status !== 'warning') {
          toast(`Inserted ${entityType}`, { variant: 'success' });
        }
      }
    } else if (entityType === 'note') {
      const noteResult: HttpResult<unknown> = await entityApi.createNote(payload);
      executed.updater.add(node.id);
      if (!noteResult.ok) {
        reportAiPathsError(
          new Error(noteResult.error),
          { action: 'insertEntity', entityType, nodeId: node.id },
          'Database insert failed:'
        );
        toast(`Failed to insert ${entityType}.`, { variant: 'error' });
      } else {
        insertResult = noteResult.data;
        applyInsertWriteOutcome('entityCreate', noteResult.data, {
          entityType,
        });
        if (writeOutcome.status !== 'warning') {
          toast(`Inserted ${entityType}`, { variant: 'success' });
        }
      }
    } else {
      const queryPayload = buildDbQueryPayload(templateContext, queryConfig);
      const collection =
        queryPayload.collection?.trim() || queryConfig.collection?.trim() || entityType;
      const customInsertPayload = {
        ...(queryPayload.provider
          ? {
            provider: queryPayload.provider,
          }
          : {}),
        ...(queryPayload.collectionMap
          ? {
            collectionMap: queryPayload.collectionMap,
          }
          : {}),
        action: 'insertOne' as const,
        collection,
        document: payload,
      };
      const customInsertResult: HttpResult<unknown> = await dbApi.action(customInsertPayload);
      executed.updater.add(node.id);
      if (!customInsertResult.ok) {
        reportAiPathsError(
          new Error(customInsertResult.error),
          {
            action: 'insertEntity',
            entityType,
            collection,
            nodeId: node.id,
          },
          'Database insert failed:'
        );
        toast(customInsertResult.error || `Failed to insert ${collection}.`, {
          variant: 'error',
        });
      } else {
        insertResult = customInsertResult.data;
        applyInsertWriteOutcome('insertOne', customInsertResult.data, {
          collection,
        });
        if (writeOutcome.status !== 'warning') {
          toast(`Inserted ${collection}`, { variant: 'success' });
        }
      }
    }
  }

  if (insertResult && typeof insertResult === 'object' && !Array.isArray(insertResult)) {
    return {
      ...(insertResult as Record<string, unknown>),
      writeOutcome,
    };
  }
  return insertResult;
}

import type { DatabaseConfig, DbQueryConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';

import { executeDatabaseInsert } from './integration-database-insert-execution';
import { resolveDatabaseInsertPayload } from './integration-database-insert-payload';

export type HandleDatabaseInsertOperationInput = {
  node: NodeHandlerContext['node'];
  nodeInputs: RuntimePortValues;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  dryRun: boolean;
  writeSourcePath: string;
  templateInputValue: unknown;
  templateContext: Record<string, unknown>;
  aiPrompt: string;
};

export async function handleDatabaseInsertOperation({
  node,
  nodeInputs,
  executed,
  reportAiPathsError,
  toast,
  dbConfig,
  queryConfig,
  dryRun,
  writeSourcePath,
  templateInputValue,
  templateContext,
  aiPrompt,
}: HandleDatabaseInsertOperationInput): Promise<RuntimePortValues> {
  const resolution = resolveDatabaseInsertPayload({
    node,
    nodeInputs,
    reportAiPathsError,
    toast,
    dbConfig,
    queryConfig,
    writeSourcePath,
    templateInputValue,
    templateContext,
    aiPrompt,
  });

  if ('output' in resolution) {
    return resolution.output;
  }

  const insertResult = await executeDatabaseInsert({
    node,
    executed,
    reportAiPathsError,
    toast,
    dbConfig,
    queryConfig,
    templateContext,
    dryRun,
    payload: resolution.payload,
    entityType: resolution.entityType,
    configuredCollection: resolution.configuredCollection,
    forceCollectionInsert: resolution.forceCollectionInsert,
  });
  const writeOutcome =
    insertResult && typeof insertResult === 'object' && !Array.isArray(insertResult)
      ? (insertResult as Record<string, unknown>)['writeOutcome']
      : undefined;

  return {
    result: insertResult,
    bundle: insertResult as Record<string, unknown>,
    ...(writeOutcome !== undefined ? { writeOutcome } : {}),
    content_en:
      typeof (insertResult as Record<string, unknown>)?.['content_en'] === 'string'
        ? ((insertResult as Record<string, unknown>)['content_en'] as string)
        : undefined,
    aiPrompt,
  };
}

import type { DatabaseConfig, DbQueryConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';

import {
  createWriteTemplateGuardrailOutput,
  resolveWriteTemplateGuardrail,
} from './integration-database-write-guardrails';
import { coerceInput, getValueAtMappingPath, parseJsonSafe, renderJsonTemplate } from '../../utils';

export type ResolveDatabaseInsertPayloadInput = {
  node: NodeHandlerContext['node'];
  nodeInputs: RuntimePortValues;
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  writeSourcePath: string;
  templateInputValue: unknown;
  templateContext: Record<string, unknown>;
  aiPrompt: string;
};

export type ResolveDatabaseInsertPayloadResult =
  | { output: RuntimePortValues }
  | {
      payload: Record<string, unknown>;
      entityType: string;
      configuredCollection: string;
      forceCollectionInsert: boolean;
    };

export function resolveDatabaseInsertPayload({
  node,
  nodeInputs,
  reportAiPathsError,
  toast,
  dbConfig,
  queryConfig,
  writeSourcePath,
  templateInputValue,
  templateContext,
  aiPrompt,
}: ResolveDatabaseInsertPayloadInput): ResolveDatabaseInsertPayloadResult {
  const entityType = (dbConfig.entityType ?? 'product').trim().toLowerCase();
  const configuredCollection = queryConfig.collection?.trim() ?? '';
  const configuredCollectionKey = configuredCollection.toLowerCase();
  const forceCollectionInsert =
    configuredCollection.length > 0 &&
    !['product', 'products', 'note', 'notes'].includes(configuredCollectionKey);
  const writeSource = dbConfig.writeSource ?? 'bundle';

  // Resolve queryTemplate first (config-based payload with {{placeholder}} support),
  // falling back to the writeSource port value.
  const insertTemplate: string = queryConfig.queryTemplate?.trim() ?? '';
  if (insertTemplate) {
    const templateGuardrail = resolveWriteTemplateGuardrail({
      templates: [{ name: 'insertTemplate', template: insertTemplate }],
      templateContext,
      currentValue: templateInputValue,
      allowEmptyArrays: true,
    });
    if (!templateGuardrail.ok) {
      const errorMessage = templateGuardrail.message;
      reportAiPathsError(
        new Error(errorMessage),
        {
          action: 'insertEntity',
          nodeId: node.id,
          guardrailMeta: templateGuardrail.guardrailMeta,
        },
        'Database insert blocked:'
      );
      toast(errorMessage, { variant: 'error' });
      return {
        output: createWriteTemplateGuardrailOutput({
          aiPrompt,
          message: errorMessage,
          guardrailMeta: templateGuardrail.guardrailMeta,
        }),
      };
    }
  }
  const parsedTemplatePayload: unknown = insertTemplate
    ? parseJsonSafe(renderJsonTemplate(insertTemplate, templateContext, templateInputValue ?? ''))
    : null;
  const templatePayload: unknown =
    parsedTemplatePayload &&
    typeof parsedTemplatePayload === 'object' &&
    !Array.isArray(parsedTemplatePayload)
      ? parsedTemplatePayload
      : null;
  const rawPayload = templatePayload ?? coerceInput(nodeInputs[writeSource]);
  const callbackInput = coerceInput(nodeInputs['queryCallback']);

  const coercePayloadObject = (value: unknown): Record<string, unknown> | null => {
    if (!value) return null;
    if (typeof value === 'string') {
      const parsed: unknown = parseJsonSafe(value);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed as Record<string, unknown>;
      }
      return null;
    }
    if (typeof value === 'object' && !Array.isArray(value)) {
      return value as Record<string, unknown>;
    }
    return null;
  };

  let payload = coercePayloadObject(rawPayload);
  if (payload && writeSourcePath) {
    const resolved = getValueAtMappingPath(payload, writeSourcePath);
    payload = coercePayloadObject(resolved);
  }

  // Callback injection for insert: if callback is an object, merge it or use it as payload.
  if (callbackInput && typeof callbackInput === 'object' && !Array.isArray(callbackInput)) {
    payload = {
      ...(payload ?? {}),
      ...(callbackInput as Record<string, unknown>),
    };
  }

  if (!payload) {
    const nodeTitle = node.title?.trim();
    const nodeLabel = nodeTitle ? `"${nodeTitle}"` : `node ${node.id}`;
    const writeSourceLabel = writeSourcePath ? `${writeSource}.${writeSourcePath}` : writeSource;
    reportAiPathsError(
      new Error('Database insert missing payload'),
      {
        action: 'insertEntity',
        nodeId: node.id,
        nodeTitle: nodeTitle ?? null,
        writeSource,
        writeSourcePath,
      },
      'Database insert missing payload:'
    );
    toast(`Database insert payload missing for ${nodeLabel} (write source: ${writeSourceLabel}).`, {
      variant: 'error',
    });
    return {
      output: {
        result: null,
        bundle: { error: 'Missing payload' },
        aiPrompt,
      },
    };
  }

  return {
    payload,
    entityType,
    configuredCollection,
    forceCollectionInsert,
  };
}

import type {
  DatabaseAction,
  DatabaseActionCategory,
  DatabaseConfig,
  DbQueryConfig,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import { getUnsupportedProviderActionMessage } from '@/shared/lib/ai-paths/core/utils/provider-actions';

import { parseJsonSafe, renderJsonTemplate } from '../../utils';
import { buildDbQueryPayload } from '../utils';
import { handleDatabaseMongoCreateAction } from './integration-database-mongo-create-action';
import { handleDatabaseMongoDeleteAction } from './integration-database-mongo-delete-action';
import { handleDatabaseMongoReadAction } from './integration-database-mongo-read-action';
import { handleDatabaseMongoUpdateAction } from './integration-database-mongo-update-action';

export type HandleDatabaseMongoActionInput = {
  node: NodeHandlerContext['node'];
  nodeInputs: RuntimePortValues;
  prevOutputs: RuntimePortValues;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  simulationEntityType: string | null;
  simulationEntityId: string | null;
  resolvedInputs: Record<string, unknown>;
  nodeInputPorts: string[];
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  dryRun: boolean;
  templateInputValue: unknown;
  templateInputs: RuntimePortValues;
  templateContext: Record<string, unknown>;
  aiPrompt: string;
  ensureExistingParameterTemplateContext: (
    targetPath: string,
    options?: { forceHydrateRichParameters?: boolean }
  ) => Promise<void>;
  strictFlowMode?: boolean;
};

export async function handleDatabaseMongoAction({
  node,
  nodeInputs,
  prevOutputs,
  executed,
  reportAiPathsError,
  toast,
  simulationEntityType,
  simulationEntityId,
  resolvedInputs,
  nodeInputPorts,
  dbConfig,
  queryConfig,
  dryRun,
  templateInputValue,
  templateInputs,
  templateContext,
  aiPrompt,
  ensureExistingParameterTemplateContext,
}: HandleDatabaseMongoActionInput): Promise<RuntimePortValues | null> {
  const actionCategory: DatabaseActionCategory = dbConfig.actionCategory ?? 'read';
  const action: DatabaseAction = dbConfig.action ?? 'find';
  const inputValue: unknown = templateInputValue;
  const queryPayload = buildDbQueryPayload(templateContext, queryConfig);
  const actionProvider =
    queryPayload['provider'] === 'mongodb' ? queryPayload['provider'] : null;
  const actionSupportError = actionProvider
    ? getUnsupportedProviderActionMessage(actionProvider, action)
    : null;
  if (actionSupportError) {
    toast(actionSupportError, { variant: 'error' });
    return {
      result: null,
      bundle: {
        error: 'Unsupported provider action',
        provider: actionProvider,
        action,
      },
      aiPrompt,
    };
  }

  const filter = queryPayload['filter'] ?? {};
  const projection = queryPayload['projection'];
  const sort = queryPayload['sort'];
  const limit = queryPayload['limit'];
  const idType = queryPayload['idType'];
  const collection = String(queryPayload['collection'] ?? '');
  const distinctField: string | undefined = dbConfig.distinctField?.trim() || undefined;
  const updateTemplate: string = dbConfig.updateTemplate?.trim() ?? '';

  const parseJsonTemplate = (template: string): unknown =>
    parseJsonSafe(renderJsonTemplate(template, templateContext, inputValue ?? ''));

  if (actionCategory === 'read' || actionCategory === 'aggregate') {
    return await handleDatabaseMongoReadAction({
      action,
      collection,
      filter,
      projection,
      sort,
      limit,
      idType,
      distinctField,
      queryPayload,
      queryConfig,
      dryRun,
      templateInputs,
      parseJsonTemplate,
      toast,
      aiPrompt,
    });
  }

  if (actionCategory === 'create') {
    return await handleDatabaseMongoCreateAction({
      action,
      node,
      prevOutputs,
      executed,
      reportAiPathsError,
      toast,
      resolvedInputs,
      dbConfig,
      queryConfig,
      dryRun,
      collection,
      queryPayload,
      templateInputs,
      templateInputValue,
      parseJsonTemplate,
      aiPrompt,
    });
  }

  if (actionCategory === 'update') {
    return await handleDatabaseMongoUpdateAction({
      actionCategory,
      action,
      node,
      nodeInputs,
      prevOutputs,
      executed,
      reportAiPathsError,
      toast,
      simulationEntityType,
      simulationEntityId,
      resolvedInputs,
      nodeInputPorts,
      dbConfig,
      queryConfig,
      dryRun,
      templateInputs,
      queryPayload,
      collection,
      filter,
      idType,
      updateTemplate,
      parseJsonTemplate,
      ensureExistingParameterTemplateContext,
      aiPrompt,
    });
  }

  if (actionCategory === 'delete') {
    return await handleDatabaseMongoDeleteAction({
      action,
      node,
      prevOutputs,
      executed,
      reportAiPathsError,
      toast,
      dbConfig,
      dryRun,
      collection,
      filter,
      idType,
      queryPayload,
      queryConfig,
      templateInputs,
      templateInputValue,
      aiPrompt,
    });
  }

  return null;
}

import type {
  DatabaseAction,
  DatabaseConfig,
  DbQueryConfig,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import type { HttpResult } from '@/shared/contracts/http';
import { dbApi } from '@/shared/lib/ai-paths/api';

import {
  createWriteTemplateGuardrailOutput,
  evaluateWriteOutcome,
  resolveWriteTemplateGuardrail,
  resolveWriteOutcomePolicy,
} from './integration-database-write-guardrails';
import { coerceInput, parseJsonSafe } from '../../utils';

export type HandleDatabaseMongoCreateActionInput = {
  action: DatabaseAction;
  node: NodeHandlerContext['node'];
  prevOutputs: RuntimePortValues;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  resolvedInputs: Record<string, unknown>;
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  dryRun: boolean;
  collection: string;
  queryPayload: Record<string, unknown>;
  templateInputs: RuntimePortValues;
  templateInputValue: unknown;
  parseJsonTemplate: (template: string) => unknown;
  aiPrompt: string;
};

export async function handleDatabaseMongoCreateAction({
  action,
  node,
  prevOutputs,
  executed,
  reportAiPathsError,
  toast,
  resolvedInputs,
  dbConfig,
  queryConfig,
  dryRun,
  collection,
  queryPayload,
  templateInputs,
  templateInputValue,
  parseJsonTemplate,
  aiPrompt,
}: HandleDatabaseMongoCreateActionInput): Promise<RuntimePortValues> {
  const payloadTemplate: string = queryConfig.queryTemplate?.trim() ?? '';
  if (payloadTemplate) {
    const templateGuardrail = resolveWriteTemplateGuardrail({
      templates: [{ name: 'insertTemplate', template: payloadTemplate }],
      templateContext: templateInputs,
      currentValue: templateInputValue,
      allowEmptyArrays: true,
    });
    if (!templateGuardrail.ok) {
      const errorMessage = templateGuardrail.message;
      reportAiPathsError(
        new Error(errorMessage),
        {
          action: 'dbInsert',
          collection,
          nodeId: node.id,
          guardrailMeta: templateGuardrail.guardrailMeta,
        },
        'Database insert blocked:'
      );
      toast(errorMessage, { variant: 'error' });
      return createWriteTemplateGuardrailOutput({
        aiPrompt,
        message: errorMessage,
        guardrailMeta: templateGuardrail.guardrailMeta,
      });
    }
  }
  const parsedPayload: unknown = payloadTemplate ? parseJsonTemplate(payloadTemplate) : null;
  if (
    payloadTemplate &&
    (!parsedPayload || (typeof parsedPayload !== 'object' && !Array.isArray(parsedPayload)))
  ) {
    toast('Insert template must be valid JSON.', {
      variant: 'error',
    });
    return {
      result: null,
      bundle: { error: 'Invalid insert template' },
      aiPrompt,
    };
  }
  const payloadFromTemplate: unknown =
    parsedPayload && typeof parsedPayload === 'object' ? parsedPayload : null;
  const rawPayload: unknown =
    payloadFromTemplate ?? coerceInput(resolvedInputs[dbConfig.writeSource ?? 'bundle']);
  const coercePayloadObject = (value: unknown): Record<string, unknown> | null => {
    if (!value) return null;
    if (typeof value === 'string') {
      const parsed: unknown = parseJsonSafe(value);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed as Record<string, unknown>;
      }
      return null;
    }
    if (typeof value === 'object' && !Array.isArray(value)) {
      return value as Record<string, unknown>;
    }
    return null;
  };
  const payloadObject: Record<string, unknown> | null = coercePayloadObject(rawPayload);
  const payloadArray: unknown[] | null = Array.isArray(rawPayload)
    ? (rawPayload as unknown[])
    : null;
  const payload: unknown[] | Record<string, unknown> | null = payloadArray ?? payloadObject;
  if (!payload) {
    toast('Insert requires a JSON payload.', { variant: 'error' });
    return { result: null, bundle: { error: 'Missing payload' }, aiPrompt };
  }
  if (action === 'insertOne' && !payloadObject) {
    toast('insertOne requires a single JSON object.', { variant: 'error' });
    return { result: null, bundle: { error: 'Invalid payload' }, aiPrompt };
  }
  if (executed.updater.has(node.id)) {
    return prevOutputs;
  }
  if (dryRun) {
    executed.updater.add(node.id);
    return {
      result: payload,
      bundle: { dryRun: true, action, collection, payload } as RuntimePortValues,
      aiPrompt,
    };
  }
  const insertActionPayload = {
    ...(queryPayload['provider']
      ? { provider: queryPayload['provider'] as 'auto' | 'mongodb' }
      : {}),
    ...(queryPayload['collectionMap']
      ? { collectionMap: queryPayload['collectionMap'] as Record<string, string> }
      : {}),
    action,
    collection,
    ...(action === 'insertOne' && payloadObject ? { document: payloadObject } : {}),
    ...(action === 'insertMany' ? { documents: Array.isArray(payload) ? payload : [payload] } : {}),
  };
  const insertResult: HttpResult<unknown> = await dbApi.action(insertActionPayload);
  executed.updater.add(node.id);
  if (!insertResult.ok) {
    reportAiPathsError(
      new Error(insertResult.error),
      { action: 'dbInsert', collection, nodeId: node.id },
      'Database insert failed:'
    );
    toast(insertResult.error || 'Database insert failed.', { variant: 'error' });
    return { result: null, bundle: { error: 'Insert failed' }, aiPrompt };
  }
  const insertedCount: number =
    typeof (insertResult.data as Record<string, unknown> | null)?.['insertedCount'] === 'number'
      ? ((insertResult.data as Record<string, unknown>)['insertedCount'] as number)
      : 1;
  const writeOutcomeEvaluation = evaluateWriteOutcome({
    operation: 'insert',
    action,
    result: insertResult.data,
    policy: resolveWriteOutcomePolicy(dbConfig),
  });
  const writeOutcome = writeOutcomeEvaluation.writeOutcome;
  if (writeOutcomeEvaluation.isZeroAffected) {
    const message =
      writeOutcome.message ?? `Database write affected 0 records for insert (${action}).`;
    if (writeOutcome.status === 'failed') {
      reportAiPathsError(
        new Error(message),
        {
          action: 'dbWriteOutcome',
          collection,
          nodeId: node.id,
          writeOutcome,
        },
        'Database insert failed:'
      );
      toast(message, { variant: 'error' });
      throw new Error(message);
    }
    toast(message, { variant: 'warning' });
  } else {
    toast(
      `Entity created in ${collection} (${insertedCount} row${insertedCount === 1 ? '' : 's'}).`,
      { variant: 'success' }
    );
  }
  return {
    result: insertResult.data,
    bundle: {
      ...(insertResult.data as Record<string, unknown>),
      writeOutcome,
    },
    writeOutcome,
    aiPrompt,
  };
}

import type {
  DatabaseAction,
  DatabaseConfig,
  DbQueryConfig,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import type { HttpResult } from '@/shared/contracts/http';
import { dbApi } from '@/shared/lib/ai-paths/api';

import {
  createWriteTemplateGuardrailOutput,
  evaluateWriteOutcome,
  resolveWriteTemplateGuardrail,
  resolveWriteOutcomePolicy,
} from './integration-database-write-guardrails';

export type HandleDatabaseMongoDeleteActionInput = {
  action: DatabaseAction;
  node: NodeHandlerContext['node'];
  prevOutputs: RuntimePortValues;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  dbConfig: DatabaseConfig;
  dryRun: boolean;
  collection: string;
  filter: Record<string, unknown>;
  idType: unknown;
  queryPayload: Record<string, unknown>;
  queryConfig: DbQueryConfig;
  templateInputs: RuntimePortValues;
  templateInputValue: unknown;
  aiPrompt: string;
};

export async function handleDatabaseMongoDeleteAction({
  action,
  node,
  prevOutputs,
  executed,
  reportAiPathsError,
  toast,
  dbConfig,
  dryRun,
  collection,
  filter,
  idType,
  queryPayload,
  queryConfig,
  templateInputs,
  templateInputValue,
  aiPrompt,
}: HandleDatabaseMongoDeleteActionInput): Promise<RuntimePortValues> {
  const queryTemplate = queryConfig.queryTemplate?.trim() ?? '';
  if (queryTemplate) {
    const templateGuardrail = resolveWriteTemplateGuardrail({
      templates: [{ name: 'queryTemplate', template: queryTemplate }],
      templateContext: templateInputs,
      currentValue: templateInputValue,
    });
    if (!templateGuardrail.ok) {
      const errorMessage = templateGuardrail.message;
      reportAiPathsError(
        new Error(errorMessage),
        {
          action: 'dbDelete',
          collection,
          nodeId: node.id,
          guardrailMeta: templateGuardrail.guardrailMeta,
        },
        'Database delete blocked:'
      );
      toast(errorMessage, { variant: 'error' });
      return createWriteTemplateGuardrailOutput({
        aiPrompt,
        message: errorMessage,
        guardrailMeta: templateGuardrail.guardrailMeta,
      });
    }
  }
  if (executed.updater.has(node.id)) {
    return prevOutputs;
  }
  if (dryRun) {
    executed.updater.add(node.id);
    const dryRunWriteOutcome = evaluateWriteOutcome({
      operation: 'delete',
      action,
      result: { deletedCount: 1 },
      policy: resolveWriteOutcomePolicy(dbConfig),
    }).writeOutcome;
    return {
      result: { dryRun: true, action, collection, filter },
      bundle: { dryRun: true, writeOutcome: dryRunWriteOutcome } as RuntimePortValues,
      writeOutcome: dryRunWriteOutcome,
      aiPrompt,
    };
  }
  const deleteResult: HttpResult<unknown> = await dbApi.action({
    ...(queryPayload['provider']
      ? { provider: queryPayload['provider'] as 'auto' | 'mongodb' }
      : {}),
    ...(queryPayload['collectionMap']
      ? { collectionMap: queryPayload['collectionMap'] as Record<string, string> }
      : {}),
    action,
    collection,
    filter,
    ...(idType !== undefined ? { idType: idType as string } : {}),
  });
  executed.updater.add(node.id);
  if (!deleteResult.ok) {
    reportAiPathsError(
      new Error(deleteResult.error),
      { action: 'dbDelete', collection, nodeId: node.id },
      'Database delete failed:'
    );
    toast(deleteResult.error || 'Database delete failed.', { variant: 'error' });
    return { result: null, bundle: { error: 'Delete failed' }, aiPrompt };
  }
  const writeOutcomeEvaluation = evaluateWriteOutcome({
    operation: 'delete',
    action,
    result: deleteResult.data,
    policy: resolveWriteOutcomePolicy(dbConfig),
  });
  const writeOutcome = writeOutcomeEvaluation.writeOutcome;
  if (writeOutcomeEvaluation.isZeroAffected) {
    const message =
      writeOutcome.message ?? `Database write affected 0 records for delete (${action}).`;
    if (writeOutcome.status === 'failed') {
      reportAiPathsError(
        new Error(message),
        {
          action: 'dbWriteOutcome',
          collection,
          nodeId: node.id,
          writeOutcome,
        },
        'Database delete failed:'
      );
      toast(message, { variant: 'error' });
      throw new Error(message);
    }
    toast(message, { variant: 'warning' });
  } else {
    toast('Delete completed.', { variant: 'success' });
  }
  return {
    result: deleteResult.data,
    bundle: {
      ...(deleteResult.data as Record<string, unknown>),
      writeOutcome,
    },
    writeOutcome,
    aiPrompt,
  };
}

import type { DatabaseAction, DbQueryConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import type { HttpResult } from '@/shared/contracts/http';
import { dbApi } from '@/shared/lib/ai-paths/api';

interface DbActionResult {
  items?: unknown[];
  item?: unknown;
  values?: unknown[];
  count?: number;
  modifiedCount?: number;
  matchedCount?: number;
}

export type HandleDatabaseMongoReadActionInput = {
  action: DatabaseAction;
  collection: string;
  filter: Record<string, unknown>;
  projection: unknown;
  sort: unknown;
  limit: unknown;
  idType: unknown;
  distinctField?: string | undefined;
  queryPayload: Record<string, unknown>;
  queryConfig: DbQueryConfig;
  dryRun: boolean;
  templateInputs: RuntimePortValues;
  parseJsonTemplate: (template: string) => unknown;
  toast: NodeHandlerContext['toast'];
  aiPrompt: string;
};

export async function handleDatabaseMongoReadAction({
  action,
  collection,
  filter,
  projection,
  sort,
  limit,
  idType,
  distinctField,
  queryPayload,
  queryConfig: _queryConfig,
  dryRun,
  templateInputs: _templateInputs,
  parseJsonTemplate,
  toast,
  aiPrompt,
}: HandleDatabaseMongoReadActionInput): Promise<RuntimePortValues> {
  if (action === 'distinct' && !distinctField) {
    toast('Distinct requires a field name.', { variant: 'error' });
    return {
      result: null,
      bundle: { error: 'Missing distinct field' },
      aiPrompt,
    };
  }
  if (action === 'aggregate') {
    const parsedPipeline: unknown = parseJsonTemplate(_queryConfig.queryTemplate ?? '[]');
    if (!Array.isArray(parsedPipeline)) {
      toast('Aggregation pipeline must be a JSON array.', {
        variant: 'error',
      });
      return {
        result: null,
        bundle: { error: 'Invalid pipeline' },
        aiPrompt,
      };
    }
    if (dryRun) {
      return {
        result: parsedPipeline,
        bundle: {
          dryRun: true,
          action,
          collection,
          pipeline: parsedPipeline,
        },
        aiPrompt,
      };
    }
    const aggResult: HttpResult<DbActionResult> = await dbApi.action<DbActionResult>({
      ...(queryPayload['provider']
        ? { provider: queryPayload['provider'] as 'auto' | 'mongodb' }
        : {}),
      action,
      collection,
      ...(queryPayload['collectionMap']
        ? { collectionMap: queryPayload['collectionMap'] as Record<string, string> }
        : {}),
      pipeline: parsedPipeline,
    });
    if (!aggResult.ok) {
      toast('Aggregation failed.', { variant: 'error' });
      return {
        result: null,
        bundle: { error: 'Aggregation failed' },
        aiPrompt,
      };
    }
    return {
      result: (aggResult.data as Record<string, unknown>)?.['items'] ?? [],
      bundle: {
        count:
          (aggResult.data as Record<string, unknown>)?.['count'] ??
          (Array.isArray((aggResult.data as Record<string, unknown>)?.['items'])
            ? ((aggResult.data as Record<string, unknown>)?.['items'] as unknown[]).length
            : 0),
        collection,
      },
      aiPrompt,
    };
  }

  if (dryRun) {
    return {
      result: filter,
      bundle: {
        dryRun: true,
        action,
        collection,
        filter,
        projection,
        sort,
        limit,
      },
      aiPrompt,
    };
  }
  const readResult: HttpResult<DbActionResult> = await dbApi.action<DbActionResult>({
    ...(queryPayload['provider']
      ? { provider: queryPayload['provider'] as 'auto' | 'mongodb' }
      : {}),
    action,
    collection,
    ...(queryPayload['collectionMap']
      ? { collectionMap: queryPayload['collectionMap'] as Record<string, string> }
      : {}),
    filter,
    ...(projection !== undefined ? { projection: projection as Record<string, unknown> } : {}),
    ...(sort !== undefined ? { sort: sort as Record<string, unknown> } : {}),
    ...(limit !== undefined ? { limit: limit as number } : {}),
    ...(idType !== undefined ? { idType: idType as string } : {}),
    ...(action === 'distinct' && distinctField ? { distinctField } : {}),
  });
  if (!readResult.ok) {
    toast(readResult.error || 'Database read failed.', { variant: 'error' });
    return { result: null, bundle: { error: 'Read failed' }, aiPrompt };
  }
  const data: DbActionResult = readResult.data;
  const result: unknown = data['item'] ?? data['items'] ?? data['values'] ?? data['count'] ?? [];
  const count: number =
    (data['count'] as number) ??
    (Array.isArray(result) ? (result as unknown[]).length : result ? 1 : 0);
  toast(`Database query succeeded for ${collection} (${count} result${count === 1 ? '' : 's'}).`, {
    variant: 'success',
  });
  return {
    result,
    bundle: {
      count,
      collection,
      filter,
    },
    aiPrompt,
  };
}

import type {
  DatabaseAction,
  DatabaseActionCategory,
  DatabaseConfig,
  DbQueryConfig,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';

import { executeMongoCollectionUpdate } from './integration-database-mongo-update-collection-executor';
import { buildMongoUpdatePlan } from './integration-database-mongo-update-plan';

export type HandleDatabaseMongoUpdateActionInput = {
  actionCategory: DatabaseActionCategory;
  action: DatabaseAction;
  node: NodeHandlerContext['node'];
  nodeInputs: RuntimePortValues;
  prevOutputs: RuntimePortValues;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  simulationEntityType: string | null;
  simulationEntityId: string | null;
  resolvedInputs: Record<string, unknown>;
  nodeInputPorts: string[];
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  dryRun: boolean;
  templateInputs: RuntimePortValues;
  queryPayload: Record<string, unknown>;
  collection: string;
  filter: Record<string, unknown>;
  idType: unknown;
  updateTemplate: string;
  parseJsonTemplate: (template: string) => unknown;
  ensureExistingParameterTemplateContext: (
    targetPath: string,
    options?: { forceHydrateRichParameters?: boolean }
  ) => Promise<void>;
  aiPrompt: string;
};

export async function handleDatabaseMongoUpdateAction(
  input: HandleDatabaseMongoUpdateActionInput
): Promise<RuntimePortValues> {
  const {
    actionCategory,
    action,
    node,
    nodeInputs,
    prevOutputs,
    executed,
    reportAiPathsError,
    toast,
    simulationEntityType: _simulationEntityType,
    simulationEntityId: _simulationEntityId,
    resolvedInputs,
    nodeInputPorts,
    dbConfig,
    queryConfig,
    dryRun,
    templateInputs,
    queryPayload,
    collection,
    filter,
    idType,
    updateTemplate,
    parseJsonTemplate,
    ensureExistingParameterTemplateContext,
    aiPrompt,
  } = input;
  const planResult = await buildMongoUpdatePlan({
    actionCategory,
    action,
    node,
    prevOutputs,
    reportAiPathsError,
    toast,
    resolvedInputs,
    nodeInputPorts,
    dbConfig,
    queryConfig,
    collection,
    filter,
    idType,
    updateTemplate,
    templateInputs,
    parseJsonTemplate,
    ensureExistingParameterTemplateContext,
    aiPrompt,
  });

  if ('output' in planResult) {
    return planResult.output;
  }

  const { resolvedFilter, debugPayload, parameterTargetPath, updates, primaryTarget, updateDoc } =
    planResult.plan;

  if (executed.updater.has(node.id)) {
    return prevOutputs;
  }

  if (dryRun) {
    executed.updater.add(node.id);
    return {
      result: updateDoc as Record<string, unknown>,
      bundle: {
        dryRun: true,
        action,
        collection,
        filter: resolvedFilter,
        update: updateDoc,
      } as RuntimePortValues,
      debugPayload,
      aiPrompt,
    };
  }

  const updatePayloadMode = dbConfig.updatePayloadMode ?? 'custom';

  if (
    updatePayloadMode !== 'custom' &&
    updatePayloadMode !== 'mapping' &&
    (updatePayloadMode as string) !== 'mongo'
  ) {
    const error =
      'Unsupported update mode. Configure explicit filter and update document or use mappings.';
    reportAiPathsError(
      new Error(error),
      {
        action: 'dbUpdateGuardrail',
        nodeId: node.id,
        updatePayloadMode,
      },
      'Database update blocked:'
    );
    toast(error, { variant: 'error' });
    return {
      result: null,
      bundle: {
        error,
        guardrail: 'update-mode-explicit-only',
      },
      debugPayload: {
        ...debugPayload,
        guardrail: 'update-mode-explicit-only',
      },
      aiPrompt,
    };
  }

  return await executeMongoCollectionUpdate({
    action,
    node,
    nodeInputs,
    executed,
    reportAiPathsError,
    toast,
    dbConfig,
    queryPayload,
    collection,
    idType,
    debugPayload,
    parameterTargetPath,
    updates,
    primaryTarget,
    resolvedFilter,
    updateDoc,
    aiPrompt,
  });
}

import type {
  DatabaseAction,
  DatabaseConfig,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import type { HttpResult } from '@/shared/contracts/http';
import { dbApi } from '@/shared/lib/ai-paths/api';

import { coerceArrayLike } from './database-parameter-inference';
import {
  evaluateWriteOutcome,
  resolveWriteOutcomePolicy,
} from './integration-database-write-guardrails';

export type ExecuteMongoCollectionUpdateInput = {
  action: DatabaseAction;
  node: NodeHandlerContext['node'];
  nodeInputs: RuntimePortValues;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  dbConfig: DatabaseConfig;
  queryPayload: Record<string, unknown>;
  collection: string;
  idType: unknown;
  debugPayload: Record<string, unknown>;
  parameterTargetPath: string;
  updates: Record<string, unknown>;
  primaryTarget: string;
  resolvedFilter: Record<string, unknown>;
  updateDoc: unknown;
  aiPrompt: string;
};

export async function executeMongoCollectionUpdate({
  action,
  node,
  nodeInputs,
  executed,
  reportAiPathsError,
  toast,
  dbConfig,
  queryPayload,
  collection,
  idType,
  debugPayload,
  parameterTargetPath,
  updates,
  primaryTarget,
  resolvedFilter,
  updateDoc,
  aiPrompt,
}: ExecuteMongoCollectionUpdateInput): Promise<RuntimePortValues> {
  const nextResolvedFilter: Record<string, unknown> = resolvedFilter;

  if (action === 'updateOne') {
    if (!nextResolvedFilter || Object.keys(nextResolvedFilter).length === 0) {
      reportAiPathsError(
        new Error('Database update missing filter'),
        { action: 'dbUpdate', collection, nodeId: node.id, provider: queryPayload['provider'] },
        'Database update skipped:'
      );
      toast('Database update skipped: missing query filter.', { variant: 'error' });
      return {
        result: null,
        bundle: { error: 'Missing query filter' },
        debugPayload,
        aiPrompt,
      };
    }
  }

  const updateResult: HttpResult<unknown> = await dbApi.action({
    ...(queryPayload['provider']
      ? { provider: queryPayload['provider'] as 'auto' | 'mongodb' }
      : {}),
    ...(queryPayload['collectionMap']
      ? { collectionMap: queryPayload['collectionMap'] as Record<string, string> }
      : {}),
    action,
    collection,
    filter: nextResolvedFilter,
    update: updateDoc,
    ...(idType !== undefined ? { idType: idType as string } : {}),
    ...(dbConfig.upsert !== undefined ? { upsert: dbConfig.upsert } : {}),
    ...(action === 'findOneAndUpdate' ? { returnDocument: 'after' as const } : {}),
    ...(dbConfig.returnDocument !== undefined ? { returnDocument: dbConfig.returnDocument } : {}),
  });
  executed.updater.add(node.id);
  if (!updateResult.ok) {
    const updateErrorMessage =
      typeof updateResult.error === 'string' && updateResult.error.trim().length > 0
        ? updateResult.error.trim()
        : 'Update failed';
    reportAiPathsError(
      new Error(updateErrorMessage),
      { action: 'dbUpdate', collection, nodeId: node.id },
      'Database update failed:'
    );
    toast(updateErrorMessage || 'Database update failed.', { variant: 'error' });
    return {
      result: null,
      bundle: { error: updateErrorMessage },
      debugPayload,
      aiPrompt,
    };
  }

  const writeOutcomeEvaluation = evaluateWriteOutcome({
    operation: 'update',
    action,
    result: updateResult.data,
    policy: resolveWriteOutcomePolicy(dbConfig),
  });
  const writeOutcome = writeOutcomeEvaluation.writeOutcome;
  if (writeOutcomeEvaluation.isZeroAffected) {
    const message =
      writeOutcome.message ?? `Database write affected 0 records for update (${action}).`;
    if (writeOutcome.status === 'failed') {
      reportAiPathsError(
        new Error(message),
        {
          action: 'dbWriteOutcome',
          collection,
          nodeId: node.id,
          writeOutcome,
        },
        'Database update failed:'
      );
      toast(message, { variant: 'error' });
      throw new Error(message);
    }
    reportAiPathsError(new Error(message), {
      action: 'dbWriteOutcome',
      collection,
      nodeId: node.id,
      nodeType: node.type,
      nodeTitle: node.title,
      errorCode: 'AI_PATHS_DB_WRITE_ZERO_AFFECTED',
      errorCategory: 'database',
      errorScope: 'node',
      errorSeverity: 'warning',
      writeOutcome,
    });
    toast(message, { variant: 'warning' });
  }

  const modifiedCount: number =
    typeof (updateResult.data as Record<string, unknown> | null)?.['modifiedCount'] === 'number'
      ? ((updateResult.data as Record<string, unknown>)['modifiedCount'] as number)
      : 1;
  const upsertedId = (updateResult.data as Record<string, unknown> | null)?.['upsertedId'];
  const displayAffectedCount =
    modifiedCount > 0 || upsertedId === null || upsertedId === undefined ? modifiedCount : 1;
  if (
    debugPayload['parameterInferenceGuard'] &&
    typeof debugPayload['parameterInferenceGuard'] === 'object'
  ) {
    (debugPayload['parameterInferenceGuard'] as Record<string, unknown>)['written'] = {
      targetPath: parameterTargetPath,
      count: coerceArrayLike(updates[parameterTargetPath]).length,
      modifiedCount: displayAffectedCount,
    };
  }
  if (writeOutcome.status !== 'warning') {
    toast(
      `Entity updated in ${collection} (${displayAffectedCount} row${displayAffectedCount === 1 ? '' : 's'}).`,
      { variant: 'success' }
    );
  }
  const primaryValue: unknown = updates[primaryTarget];
  return {
    content_en:
      primaryTarget === 'content_en'
        ? ((primaryValue as string | undefined) ?? (nodeInputs['content_en'] as string | undefined))
        : (nodeInputs['content_en'] as string | undefined),
    result: updateResult.data,
    bundle: {
      ...(updateResult.data as Record<string, unknown>),
      writeOutcome,
    },
    debugPayload,
    writeOutcome,
    aiPrompt,
  };
}

import type {
  DatabaseAction,
  DatabaseConfig,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import { entityApi } from '@/shared/lib/ai-paths/api';

import {
  coerceArrayLike,
  mergeParameterInferenceUpdates,
  resolveObjectPathValue,
  toRecord,
} from './database-parameter-inference';
import {
  evaluateWriteOutcome,
  resolveWriteOutcomePolicy,
} from './integration-database-write-guardrails';

export type ExecuteMongoEntityUpdateInput = {
  action: DatabaseAction;
  node: NodeHandlerContext['node'];
  nodeInputs: RuntimePortValues;
  prevOutputs: RuntimePortValues;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  dbConfig: DatabaseConfig;
  queryPayload: Record<string, unknown>;
  collection: string;
  templateInputs: RuntimePortValues;
  debugPayload: Record<string, unknown>;
  parameterTargetPath: string;
  updates: Record<string, unknown>;
  primaryTarget: string;
  updateDoc: unknown;
  resolveEntityId: () => string | null;
  aiPrompt: string;
};

export async function executeMongoEntityUpdate({
  node,
  nodeInputs,
  prevOutputs,
  executed,
  reportAiPathsError,
  toast,
  dbConfig,
  queryPayload,
  collection,
  templateInputs,
  debugPayload,
  parameterTargetPath,
  updates,
  primaryTarget,
  updateDoc,
  resolveEntityId,
  aiPrompt,
}: ExecuteMongoEntityUpdateInput): Promise<RuntimePortValues> {
  const updateDocRecord =
    updateDoc && typeof updateDoc === 'object' && !Array.isArray(updateDoc)
      ? (updateDoc as Record<string, unknown>)
      : null;
  const updateSet =
    updateDocRecord?.['$set'] &&
    typeof updateDocRecord['$set'] === 'object' &&
    !Array.isArray(updateDocRecord['$set'])
      ? (updateDocRecord['$set'] as Record<string, unknown>)
      : null;
  const updatePlain =
    updateDocRecord && !Object.keys(updateDocRecord).some((key) => key.startsWith('$'))
      ? updateDocRecord
      : null;
  let updatesForEntity = updateSet ?? updatePlain ?? updates;
  const mergeForEntityResult = mergeParameterInferenceUpdates({
    targetPath: parameterTargetPath,
    updates: updatesForEntity,
    templateInputs,
    languageCode: dbConfig.parameterInferenceGuard?.languageCode,
  });
  if (mergeForEntityResult.applied) {
    updatesForEntity = mergeForEntityResult.updates;
    if (
      debugPayload['parameterInferenceGuard'] &&
      typeof debugPayload['parameterInferenceGuard'] === 'object'
    ) {
      (debugPayload['parameterInferenceGuard'] as Record<string, unknown>)['writePlan'] = {
        ...((debugPayload['parameterInferenceGuard'] as Record<string, unknown>)['writePlan'] as
          | Record<string, unknown>
          | undefined),
        ...(mergeForEntityResult.meta ?? {}),
      };
    }
  }
  if (!updatesForEntity || Object.keys(updatesForEntity).length === 0) {
    return prevOutputs;
  }
  const entityIdValue = resolveEntityId();
  if (!entityIdValue) {
    reportAiPathsError(
      new Error('Database update missing entity id'),
      {
        action: 'updateEntity',
        collection,
        nodeId: node.id,
        provider: queryPayload['provider'],
      },
      'Database update skipped:'
    );
    toast('Database update skipped: missing entity ID.', { variant: 'error' });
    return {
      result: null,
      bundle: { error: 'Missing entity id' },
      debugPayload,
      aiPrompt,
    };
  }
  const updateResult = await entityApi.update({
    entityType: 'product',
    entityId: entityIdValue,
    updates: updatesForEntity,
    mode: dbConfig.mode ?? 'replace',
  });
  executed.updater.add(node.id);
  if (!updateResult.ok) {
    reportAiPathsError(
      new Error(updateResult.error),
      { action: 'updateEntity', collection, nodeId: node.id },
      'Database update failed:'
    );
    toast('Database update failed.', { variant: 'error' });
    return {
      result: null,
      bundle: { error: 'Update failed' },
      debugPayload,
      aiPrompt,
    };
  }
  const writeOutcomeEvaluation = evaluateWriteOutcome({
    operation: 'update',
    action: 'entityUpdate',
    result: updateResult.data,
    policy: resolveWriteOutcomePolicy(dbConfig),
  });
  const writeOutcome = writeOutcomeEvaluation.writeOutcome;
  if (writeOutcomeEvaluation.isZeroAffected) {
    const message = writeOutcome.message ?? 'Database write affected 0 records for update.';
    if (writeOutcome.status === 'failed') {
      reportAiPathsError(
        new Error(message),
        {
          action: 'dbWriteOutcome',
          collection,
          nodeId: node.id,
          writeOutcome,
        },
        'Database update failed:'
      );
      toast(message, { variant: 'error' });
      throw new Error(message);
    }
    reportAiPathsError(new Error(message), {
      action: 'dbWriteOutcome',
      collection,
      nodeId: node.id,
      nodeType: node.type,
      nodeTitle: node.title,
      errorCode: 'AI_PATHS_DB_WRITE_ZERO_AFFECTED',
      errorCategory: 'database',
      errorScope: 'node',
      errorSeverity: 'warning',
      writeOutcome,
    });
    toast(message, { variant: 'warning' });
  }
  const modifiedCount: number =
    typeof (updateResult.data as Record<string, unknown> | null)?.['modifiedCount'] === 'number'
      ? ((updateResult.data as Record<string, unknown>)['modifiedCount'] as number)
      : 1;
  if (
    debugPayload['parameterInferenceGuard'] &&
    typeof debugPayload['parameterInferenceGuard'] === 'object'
  ) {
    const writeTarget = resolveObjectPathValue(toRecord(updatesForEntity), parameterTargetPath);
    (debugPayload['parameterInferenceGuard'] as Record<string, unknown>)['written'] = {
      targetPath: parameterTargetPath,
      count: coerceArrayLike(writeTarget).length,
      modifiedCount,
    };
  }
  if (writeOutcome.status !== 'warning') {
    toast(
      `Entity updated in ${collection} (${modifiedCount} row${modifiedCount === 1 ? '' : 's'}).`,
      { variant: 'success' }
    );
  }
  const primaryValue: unknown = updates[primaryTarget];
  return {
    content_en:
      primaryTarget === 'content_en'
        ? ((primaryValue as string | undefined) ?? (nodeInputs['content_en'] as string | undefined))
        : (nodeInputs['content_en'] as string | undefined),
    result: updateResult.data,
    bundle: {
      ...(updateResult.data as Record<string, unknown>),
      writeOutcome,
    },
    debugPayload,
    writeOutcome,
    aiPrompt,
  };
}

import type {
  DatabaseAction,
  DatabaseActionCategory,
  DatabaseConfig,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths';

export type BuildMongoUpdatesFromMappingsResult = {
  updates: Record<string, unknown>;
  primaryTarget: string;
  missingSourcePorts: string[];
  unresolvedSourcePorts: string[];
};

export function resolveMongoUpdateFilter({
  filter,
  queryTemplate,
  parseJsonTemplate,
}: {
  filter: Record<string, unknown>;
  queryTemplate?: string;
  parseJsonTemplate: (template: string) => unknown;
}): Record<string, unknown> {
  if (!queryTemplate?.trim()) {
    return filter;
  }
  const parsedFilter: unknown = parseJsonTemplate(queryTemplate);
  if (parsedFilter && typeof parsedFilter === 'object' && !Array.isArray(parsedFilter)) {
    return parsedFilter as Record<string, unknown>;
  }
  return filter;
}

export function buildMongoUpdateDebugPayload({
  actionCategory,
  action,
  collection,
  resolvedFilter,
  updateTemplate,
  idType,
  resolvedInputs,
}: {
  actionCategory: DatabaseActionCategory;
  action: DatabaseAction;
  collection: string;
  resolvedFilter: Record<string, unknown>;
  updateTemplate: string;
  idType: unknown;
  resolvedInputs: Record<string, unknown>;
}): Record<string, unknown> {
  return {
    mode: 'mongo',
    actionCategory,
    action,
    collection,
    filter: resolvedFilter,
    updateTemplate: updateTemplate || undefined,
    idType,
    entityId: resolvedInputs['entityId'],
    productId: resolvedInputs['productId'],
    entityType: resolvedInputs['entityType'],
  };
}

export function buildMongoUpdatesFromMappings({
  dbConfig: _dbConfig,
  nodeInputPorts: _nodeInputPorts,
  templateInputs: _templateInputs,
  parameterTargetPath: _parameterTargetPath,
}: {
  dbConfig: DatabaseConfig;
  nodeInputPorts: string[];
  templateInputs: RuntimePortValues;
  parameterTargetPath: string;
}): BuildMongoUpdatesFromMappingsResult {
  throw new Error(
    'Mapping-based database updates are disabled. Use an explicit update template instead.'
  );
}

export function extractMissingTemplatePorts(
  template: string,
  templateInputs: RuntimePortValues
): string[] {
  const missing: Set<string> = new Set<string>();
  // Keep this token parser aligned with renderTemplate to avoid treating
  // JSON array syntax as unresolved placeholder input.
  const tokenRegex: RegExp = /{{\s*([^}]+)\s*}}|\[\s*([A-Za-z0-9_.$:-]+)\s*\]/g;
  let match: RegExpExecArray | null = tokenRegex.exec(template);

  while (match) {
    const token: string = (match[1] ?? match[2] ?? '').trim();
    if (token) {
      const rootPortCandidate: string = token.split('.')[0]?.trim() ?? '';
      const rootPort: string = rootPortCandidate.replace(/\[[^\]]*\]/g, '').trim();
      if (
        rootPort &&
        rootPort !== 'value' &&
        rootPort !== 'current' &&
        templateInputs[rootPort] === undefined
      ) {
        missing.add(rootPort);
      }
    }
    match = tokenRegex.exec(template);
  }

  return Array.from(missing);
}

import type {
  DatabaseAction,
  DatabaseActionCategory,
  DatabaseConfig,
  DbQueryConfig,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';

import {
  applyParameterInferenceGuard,
  mergeLocalizedParameterUpdates,
  materializeParameterInferenceUpdates,
  normalizeNonEmptyString,
  toRecord,
} from './database-parameter-inference';
import {
  applyTopLevelWriteValuePolicies,
  resolveLocalizedParameterMergeConfig,
} from './database-write-policies';
import {
  buildMongoUpdateDebugPayload,
  resolveMongoUpdateFilter,
} from './integration-database-mongo-update-plan-helpers';
import { resolveDatabaseUpdateMappings } from './integration-database-update-mapping-resolution';
import {
  createWriteTemplateGuardrailOutput,
  resolveWriteTemplateGuardrail,
} from './integration-database-write-guardrails';

export type MongoUpdatePlan = {
  resolvedFilter: Record<string, unknown>;
  debugPayload: Record<string, unknown>;
  parameterTargetPath: string;
  updates: Record<string, unknown>;
  primaryTarget: string;
  updateDoc: unknown;
};

export type BuildMongoUpdatePlanResult = { output: RuntimePortValues } | { plan: MongoUpdatePlan };

export type BuildMongoUpdatePlanInput = {
  actionCategory: DatabaseActionCategory;
  action: DatabaseAction;
  node: NodeHandlerContext['node'];
  prevOutputs: RuntimePortValues;
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  resolvedInputs: Record<string, unknown>;
  nodeInputPorts: string[];
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  collection: string;
  filter: Record<string, unknown>;
  idType: unknown;
  updateTemplate: string;
  templateInputs: RuntimePortValues;
  parseJsonTemplate: (template: string) => unknown;
  ensureExistingParameterTemplateContext: (
    targetPath: string,
    options?: { forceHydrateRichParameters?: boolean }
  ) => Promise<void>;
  aiPrompt: string;
};

const patchTargetPathInUpdateDoc = (
  value: unknown,
  targetPath: string,
  nextUpdates: Record<string, unknown>
): unknown => {
  const record = toRecord(value);
  if (!record) return value;
  const hasTarget = Object.prototype.hasOwnProperty.call(nextUpdates, targetPath);
  const nextTargetValue = nextUpdates[targetPath];
  const setRecord = toRecord(record['$set']);
  if (setRecord) {
    const nextSet: Record<string, unknown> = { ...setRecord };
    if (hasTarget) {
      nextSet[targetPath] = nextTargetValue;
    } else {
      delete nextSet[targetPath];
    }
    return { ...record, $set: nextSet };
  }
  const hasOperator = Object.keys(record).some((key: string): boolean => key.startsWith('$'));
  if (hasOperator) return value;
  const nextRecord: Record<string, unknown> = { ...record };
  if (hasTarget) {
    nextRecord[targetPath] = nextTargetValue;
  } else {
    delete nextRecord[targetPath];
  }
  return nextRecord;
};

const isImplicitEmptyArray = (value: unknown): value is unknown[] =>
  Array.isArray(value) && value.length === 0;

const isProductParameterUpdateTarget = (args: {
  collection: string;
  dbConfig: DatabaseConfig;
  targetPath: string;
}): boolean => {
  if (args.targetPath !== 'parameters') return false;
  const collection = args.collection.trim().toLowerCase();
  if (collection === 'products') return true;
  return normalizeNonEmptyString(args.dbConfig.entityType)?.toLowerCase() === 'product';
};

const pruneImplicitEmptyProductParameterUpdate = (args: {
  collection: string;
  dbConfig: DatabaseConfig;
  targetPath: string;
  updates: Record<string, unknown>;
  updateDoc: unknown;
}): {
  updates: Record<string, unknown>;
  updateDoc: unknown;
  pruned: boolean;
  meta?: Record<string, unknown>;
} => {
  if (args.dbConfig.parameterInferenceGuard?.enabled) {
    return {
      updates: args.updates,
      updateDoc: args.updateDoc,
      pruned: false,
    };
  }
  if (
    !isProductParameterUpdateTarget({
      collection: args.collection,
      dbConfig: args.dbConfig,
      targetPath: args.targetPath,
    })
  ) {
    return {
      updates: args.updates,
      updateDoc: args.updateDoc,
      pruned: false,
    };
  }
  if (!Object.prototype.hasOwnProperty.call(args.updates, args.targetPath)) {
    return {
      updates: args.updates,
      updateDoc: args.updateDoc,
      pruned: false,
    };
  }
  if (!isImplicitEmptyArray(args.updates[args.targetPath])) {
    return {
      updates: args.updates,
      updateDoc: args.updateDoc,
      pruned: false,
    };
  }

  const nextUpdates = { ...args.updates };
  delete nextUpdates[args.targetPath];
  return {
    updates: nextUpdates,
    updateDoc: patchTargetPathInUpdateDoc(args.updateDoc, args.targetPath, nextUpdates),
    pruned: true,
    meta: {
      targetPath: args.targetPath,
      reason: 'implicit_empty_parameter_array',
    },
  };
};

const createNoSafeUpdatesOutput = (args: {
  error: string;
  aiPrompt: string;
  collection: string;
  resolvedFilter: Record<string, unknown>;
  unresolvedSourcePorts?: string[];
  localizedParameterMergeMeta?: Record<string, unknown>;
  reportAiPathsError: BuildMongoUpdatePlanInput['reportAiPathsError'];
  toast: BuildMongoUpdatePlanInput['toast'];
  nodeId: string;
  mode?: 'mapping' | 'custom';
}): BuildMongoUpdatePlanResult => {
  args.reportAiPathsError(
    new Error(args.error),
    {
      action: 'dbUpdatePolicy',
      nodeId: args.nodeId,
      ...(args.unresolvedSourcePorts && args.unresolvedSourcePorts.length > 0
        ? { unresolvedSourcePorts: args.unresolvedSourcePorts }
        : {}),
      ...(args.localizedParameterMergeMeta
        ? { localizedParameterMerge: args.localizedParameterMergeMeta }
        : {}),
    },
    'Database update blocked:'
  );
  args.toast(args.error, { variant: 'error' });
  return {
    output: {
      result: null,
      bundle: {
        error: args.error,
        guardrail: 'no-safe-updates',
        guardrailMeta: {
          code: 'no-safe-updates',
          severity: 'error',
          message: args.error,
          ...(args.unresolvedSourcePorts && args.unresolvedSourcePorts.length > 0
            ? { unresolvedSourcePorts: args.unresolvedSourcePorts }
            : {}),
          ...(args.localizedParameterMergeMeta
            ? { localizedParameterMerge: args.localizedParameterMergeMeta }
            : {}),
        },
      },
      debugPayload: {
        mode: args.mode ?? 'mapping',
        collection: args.collection,
        filter: args.resolvedFilter,
        ...(args.unresolvedSourcePorts && args.unresolvedSourcePorts.length > 0
          ? { unresolvedSourcePorts: args.unresolvedSourcePorts }
          : {}),
        ...(args.localizedParameterMergeMeta
          ? { localizedParameterMerge: args.localizedParameterMergeMeta }
          : {}),
      },
      aiPrompt: args.aiPrompt,
    },
  };
};

const createNoParameterUpdatesOutput = (args: {
  aiPrompt: string;
  collection: string;
  resolvedFilter: Record<string, unknown>;
  mode: 'mapping' | 'custom';
  debugMeta?: Record<string, unknown>;
}): BuildMongoUpdatePlanResult => ({
  output: {
    result: null,
    bundle: {
      skipped: true,
      reason: 'no_parameter_updates',
    },
    debugPayload: {
      mode: args.mode,
      collection: args.collection,
      filter: args.resolvedFilter,
      ...(args.debugMeta ?? {}),
    },
    aiPrompt: args.aiPrompt,
  },
});

export async function buildMongoUpdatePlan({
  actionCategory,
  action,
  node,
  prevOutputs: _prevOutputs,
  reportAiPathsError,
  toast,
  resolvedInputs,
  nodeInputPorts,
  dbConfig,
  queryConfig,
  collection,
  filter,
  idType,
  updateTemplate,
  templateInputs,
  parseJsonTemplate,
  ensureExistingParameterTemplateContext,
  aiPrompt,
}: BuildMongoUpdatePlanInput): Promise<BuildMongoUpdatePlanResult> {
  const updatePayloadMode = dbConfig.updatePayloadMode ?? 'custom';
  const currentValueRaw: unknown =
    templateInputs['value'] ?? templateInputs['result'] ?? templateInputs['jobId'] ?? '';
  const currentValue = Array.isArray(currentValueRaw)
    ? (currentValueRaw as unknown[])[0]
    : currentValueRaw;

  if (
    updatePayloadMode !== 'custom' &&
    updatePayloadMode !== 'mapping' &&
    (updatePayloadMode as string) !== 'mongo'
  ) {
    const error =
      'Unsupported update mode. Configure explicit filter and update document or use mappings.';
    reportAiPathsError(
      new Error(error),
      {
        action: 'dbUpdateGuardrail',
        nodeId: node.id,
        updatePayloadMode,
      },
      'Database update blocked:'
    );
    toast(error, { variant: 'error' });
    return {
      output: {
        result: null,
        bundle: {
          error,
          guardrail: 'update-mode-explicit-only',
        },
        debugPayload: {
          mode: updatePayloadMode,
          guardrail: 'update-mode-explicit-only',
        },
        aiPrompt,
      },
    };
  }

  const resolvedFilter: Record<string, unknown> = resolveMongoUpdateFilter({
    filter,
    queryTemplate: queryConfig.queryTemplate,
    parseJsonTemplate,
  });

  const localizedParameterMergeConfig = resolveLocalizedParameterMergeConfig(dbConfig);
  const parameterTargetPath =
    normalizeNonEmptyString(dbConfig.parameterInferenceGuard?.targetPath) ??
    localizedParameterMergeConfig?.targetPath ??
    'parameters';

  let updates: Record<string, unknown> = {};
  let updateDoc: unknown = null;
  let localizedParameterMergeMeta: Record<string, unknown> | undefined;
  let implicitEmptyParameterPruneMeta: Record<string, unknown> | undefined;
  let writeValuePoliciesMeta: Record<string, unknown> | undefined;

  if (updatePayloadMode === 'mapping') {
    const mappingResult = resolveDatabaseUpdateMappings({
      dbConfig,
      nodeInputPorts,
      resolvedInputs,
      parameterTargetPath,
    });
    updates = mappingResult.updates;
    const writePolicyResult = applyTopLevelWriteValuePolicies({ updates, dbConfig });
    updates = writePolicyResult.updates;
    writeValuePoliciesMeta =
      dbConfig.skipEmpty || dbConfig.trimStrings
        ? {
            skipEmpty: dbConfig.skipEmpty === true,
            trimStrings: dbConfig.trimStrings === true,
            changedTargets: writePolicyResult.changedTargets,
          }
        : undefined;

    if (
      localizedParameterMergeConfig &&
      Object.prototype.hasOwnProperty.call(updates, localizedParameterMergeConfig.targetPath)
    ) {
      await ensureExistingParameterTemplateContext(localizedParameterMergeConfig.targetPath, {
        forceHydrateRichParameters: true,
      });
      const localizedMergeResult = mergeLocalizedParameterUpdates({
        targetPath: localizedParameterMergeConfig.targetPath,
        updates,
        templateInputs,
        languageCode: localizedParameterMergeConfig.languageCode,
        requireFullCoverage: localizedParameterMergeConfig.requireFullCoverage,
      });
      if (localizedMergeResult.applied) {
        updates = localizedMergeResult.updates;
        localizedParameterMergeMeta = localizedMergeResult.meta;
      }
    }

    const prunedEmptyParameterUpdate = pruneImplicitEmptyProductParameterUpdate({
      collection,
      dbConfig,
      targetPath: parameterTargetPath,
      updates,
      updateDoc,
    });
    if (prunedEmptyParameterUpdate.pruned) {
      updates = prunedEmptyParameterUpdate.updates;
      implicitEmptyParameterPruneMeta = prunedEmptyParameterUpdate.meta;
    }

    if (Object.keys(updates).length === 0) {
      if (localizedParameterMergeConfig || writeValuePoliciesMeta) {
        return createNoSafeUpdatesOutput({
          error:
            'Database update blocked. No safe write candidates were resolved after applying the configured write policies.',
          aiPrompt,
          collection,
          resolvedFilter,
          unresolvedSourcePorts: Array.from(mappingResult.unresolvedSourcePorts),
          localizedParameterMergeMeta,
          reportAiPathsError,
          toast,
          nodeId: node.id,
          mode: 'mapping',
        });
      }
      if (implicitEmptyParameterPruneMeta) {
        return createNoParameterUpdatesOutput({
          aiPrompt,
          collection,
          resolvedFilter,
          mode: 'mapping',
          debugMeta: {
            parameterWriteGuard: implicitEmptyParameterPruneMeta,
            unresolvedSourcePorts: Array.from(mappingResult.unresolvedSourcePorts),
          },
        });
      }
      return {
        output: {
          result: null,
          bundle: {
            skipped: true,
            reason: 'no_mapping_updates',
            unresolvedSourcePorts: Array.from(mappingResult.unresolvedSourcePorts),
          },
          debugPayload: {
            mode: 'mapping',
            collection,
            filter: resolvedFilter,
            unresolvedSourcePorts: Array.from(mappingResult.unresolvedSourcePorts),
          },
          aiPrompt,
        },
      };
    }
    updateDoc = { $set: updates };
  } else {
    if (!updateTemplate.trim()) {
      const error = 'No explicit update document provided.';
      reportAiPathsError(
        new Error(error),
        {
          action: 'dbUpdateGuardrail',
          nodeId: node.id,
          guardrail: 'missing_update_template',
        },
        'Database update blocked:'
      );
      toast(error, { variant: 'error' });
      return {
        output: {
          result: null,
          bundle: {
            error,
            guardrail: 'missing-update-template',
          },
          debugPayload: {
            mode: 'custom',
            updateStrategy: dbConfig.updateStrategy ?? 'one',
            collection,
            filter: resolvedFilter,
          },
          aiPrompt,
        },
      };
    }

    const templateGuardrail = resolveWriteTemplateGuardrail({
      templates: [
        {
          name: 'queryTemplate',
          template: queryConfig.queryTemplate ?? '',
        },
        {
          name: 'updateTemplate',
          template: updateTemplate,
        },
      ],
      templateContext: templateInputs,
      currentValue,
      allowEmptyArrays: !isProductParameterUpdateTarget({
        collection,
        dbConfig,
        targetPath: parameterTargetPath,
      }),
    });
    if (!templateGuardrail.ok) {
      const hasMappingConfig = Array.isArray(dbConfig.mappings) && dbConfig.mappings.length > 0;
      if (hasMappingConfig) {
        const problemRoots = [
          ...new Set([
            ...(templateGuardrail.guardrailMeta.missingRoots ?? []),
            ...(templateGuardrail.guardrailMeta.emptyRoots ?? []),
            ...(templateGuardrail.guardrailMeta.unparseableRoots ?? []),
          ]),
        ];
        const rootHint =
          problemRoots.length > 0
            ? ` (unresolved port${problemRoots.length > 1 ? 's' : ''}: ${problemRoots.join(', ')})`
            : '';
        const fallbackWarning =
          `Update template has unresolved tokens${rootHint} — falling back to mapping rows automatically. ` +
          'To fix permanently: set Update Payload Mode to "mapping" on the Database node so it always uses the configured mapping rows.';
        toast(fallbackWarning, { variant: 'warning' });
        reportAiPathsError(
          new Error(fallbackWarning),
          {
            action: 'dbUpdateTemplateFallback',
            nodeId: node.id,
            guardrailMeta: templateGuardrail.guardrailMeta,
          },
          'Database update template fallback to mapping mode:'
        );
        return buildMongoUpdatePlan({
          actionCategory,
          action,
          node,
          prevOutputs: _prevOutputs,
          reportAiPathsError,
          toast,
          resolvedInputs,
          nodeInputPorts,
          dbConfig: { ...dbConfig, updatePayloadMode: 'mapping' },
          queryConfig,
          collection,
          filter,
          idType,
          updateTemplate,
          templateInputs,
          parseJsonTemplate,
          ensureExistingParameterTemplateContext,
          aiPrompt,
        });
      }
      const missingRoots = templateGuardrail.guardrailMeta.missingRoots ?? [];
      const portFix =
        missingRoots.length > 0
          ? `Fix: connect port${missingRoots.length > 1 ? 's' : ''} "${missingRoots.join('", "')}" to the Database node input, or add mapping rows and set Update Payload Mode to "mapping".`
          : 'Fix: connect all referenced input ports to the Database node, or add mapping rows and set Update Payload Mode to "mapping".';
      const error = `${templateGuardrail.message} ${portFix}`;
      reportAiPathsError(
        new Error(error),
        {
          action: 'dbUpdateTemplate',
          nodeId: node.id,
          guardrailMeta: templateGuardrail.guardrailMeta,
        },
        'Database update blocked:'
      );
      toast(error, { variant: 'error' });
      return {
        output: createWriteTemplateGuardrailOutput({
          aiPrompt,
          message: error,
          guardrailMeta: templateGuardrail.guardrailMeta,
        }),
      };
    }

    if (!updateDoc) {
      const parsedUpdate: unknown = parseJsonTemplate(updateTemplate);
      if (!parsedUpdate || (typeof parsedUpdate !== 'object' && !Array.isArray(parsedUpdate))) {
        toast('Update template must be valid JSON.', { variant: 'error' });
        return {
          output: {
            result: null,
            bundle: { error: 'Invalid update template' },
            debugPayload: {
              mode: 'custom',
              collection,
              filter: resolvedFilter,
            },
            aiPrompt,
          },
        };
      }
      updateDoc = parsedUpdate;

      const extractUpdates = (value: unknown): Record<string, unknown> => {
        const record = toRecord(value);
        if (!record) return {};
        const setRecord = toRecord(record['$set']);
        if (setRecord) return setRecord;
        const hasOperator = Object.keys(record).some((key: string): boolean => key.startsWith('$'));
        if (hasOperator) return {};
        return record;
      };
      updates = extractUpdates(updateDoc);
      const writePolicyResult = applyTopLevelWriteValuePolicies({ updates, dbConfig });
      updates = writePolicyResult.updates;
      writeValuePoliciesMeta =
        dbConfig.skipEmpty || dbConfig.trimStrings
          ? {
              skipEmpty: dbConfig.skipEmpty === true,
              trimStrings: dbConfig.trimStrings === true,
              changedTargets: writePolicyResult.changedTargets,
            }
          : undefined;
      writePolicyResult.changedTargets.forEach((targetPath: string) => {
        updateDoc = patchTargetPathInUpdateDoc(updateDoc, targetPath, updates);
      });

      if (
        localizedParameterMergeConfig &&
        Object.prototype.hasOwnProperty.call(updates, localizedParameterMergeConfig.targetPath)
      ) {
        await ensureExistingParameterTemplateContext(localizedParameterMergeConfig.targetPath, {
          forceHydrateRichParameters: true,
        });
        const localizedMergeResult = mergeLocalizedParameterUpdates({
          targetPath: localizedParameterMergeConfig.targetPath,
          updates,
          templateInputs,
          languageCode: localizedParameterMergeConfig.languageCode,
          requireFullCoverage: localizedParameterMergeConfig.requireFullCoverage,
        });
        if (localizedMergeResult.applied) {
          updates = localizedMergeResult.updates;
          localizedParameterMergeMeta = localizedMergeResult.meta;
          updateDoc = patchTargetPathInUpdateDoc(
            updateDoc,
            localizedParameterMergeConfig.targetPath,
            updates
          );
        }
      }

      if (
        Object.keys(updates).length === 0 &&
        (localizedParameterMergeConfig || writeValuePoliciesMeta)
      ) {
        return createNoSafeUpdatesOutput({
          error:
            'Database update blocked. No safe write candidates were resolved after applying the configured write policies.',
          aiPrompt,
          collection,
          resolvedFilter,
          localizedParameterMergeMeta,
          reportAiPathsError,
          toast,
          nodeId: node.id,
          mode: 'custom',
        });
      }

      const prunedEmptyParameterUpdate = pruneImplicitEmptyProductParameterUpdate({
        collection,
        dbConfig,
        targetPath: parameterTargetPath,
        updates,
        updateDoc,
      });
      if (prunedEmptyParameterUpdate.pruned) {
        updates = prunedEmptyParameterUpdate.updates;
        updateDoc = prunedEmptyParameterUpdate.updateDoc;
        implicitEmptyParameterPruneMeta = prunedEmptyParameterUpdate.meta;
      }

      if (Object.keys(updates).length === 0 && implicitEmptyParameterPruneMeta) {
        return createNoParameterUpdatesOutput({
          aiPrompt,
          collection,
          resolvedFilter,
          mode: 'custom',
          debugMeta: {
            parameterWriteGuard: implicitEmptyParameterPruneMeta,
          },
        });
      }
    }
  }

  const debugPayload: Record<string, unknown> = buildMongoUpdateDebugPayload({
    actionCategory,
    action,
    collection,
    resolvedFilter,
    updateTemplate,
    idType,
    resolvedInputs,
  });
  if (localizedParameterMergeMeta) {
    debugPayload['localizedParameterMerge'] = localizedParameterMergeMeta;
  }
  if (writeValuePoliciesMeta) {
    debugPayload['writeValuePolicies'] = writeValuePoliciesMeta;
  }
  if (implicitEmptyParameterPruneMeta) {
    debugPayload['parameterWriteGuard'] = implicitEmptyParameterPruneMeta;
  }

  if (!resolvedFilter || Object.keys(resolvedFilter).length === 0) {
    const error = 'No explicit update filter provided.';
    reportAiPathsError(
      new Error(error),
      {
        action: 'dbUpdateGuardrail',
        nodeId: node.id,
        guardrail: 'missing_query_filter',
      },
      'Database update blocked:'
    );
    toast(error, { variant: 'error' });
    return {
      output: {
        result: null,
        bundle: {
          error,
          guardrail: 'missing-query-filter',
        },
        debugPayload: {
          ...debugPayload,
          guardrail: 'missing-query-filter',
        },
        aiPrompt,
      },
    };
  }

  let primaryTarget = Object.keys(updates)[0] ?? 'content_en';

  if (dbConfig.parameterInferenceGuard?.enabled) {
    await ensureExistingParameterTemplateContext(parameterTargetPath);

    const guardResult = applyParameterInferenceGuard({
      dbConfig,
      updates,
      templateInputs,
    });
    if (guardResult.applied && guardResult.meta) {
      const existingMeta = toRecord(debugPayload['parameterInferenceGuard']) ?? {};
      debugPayload['parameterInferenceGuard'] = { ...existingMeta, ...guardResult.meta };
      updates = guardResult.updates;
    }
    if (guardResult.blocked) {
      return {
        output: {
          result: null,
          bundle: {
            error: guardResult.errorMessage ?? 'Parameter inference guard blocked update.',
          },
          debugPayload,
          aiPrompt,
        },
      };
    }

    const definitionsPort =
      normalizeNonEmptyString(dbConfig.parameterInferenceGuard?.definitionsPort) ?? 'result';
    const definitionsPath =
      normalizeNonEmptyString(dbConfig.parameterInferenceGuard?.definitionsPath) ?? '';
    const languageCode =
      normalizeNonEmptyString(dbConfig.parameterInferenceGuard?.languageCode) ?? 'en';
    const materializeResult = materializeParameterInferenceUpdates({
      targetPath: parameterTargetPath,
      updates,
      templateInputs,
      definitionsPort,
      definitionsPath,
      languageCode,
    });
    if (materializeResult.applied) {
      updates = materializeResult.updates;
      if (materializeResult.meta) {
        const existingMeta = toRecord(debugPayload['parameterInferenceGuard']) ?? {};
        const existingWritePlan = toRecord(existingMeta['writePlan']) ?? {};
        debugPayload['parameterInferenceGuard'] = {
          ...existingMeta,
          writePlan: {
            ...existingWritePlan,
            ...materializeResult.meta,
          },
        };
      }
    }

    // Patch updateDoc if it was custom
    if (updatePayloadMode !== 'mapping') {
      updateDoc = patchTargetPathInUpdateDoc(updateDoc, parameterTargetPath, updates);
    } else {
      updateDoc = { $set: updates };
    }

    primaryTarget = Object.keys(updates)[0] ?? 'content_en';

    const isEmptyCustomUpdateDoc = (value: unknown): boolean => {
      const record = toRecord(value);
      if (!record) return true;
      const keys = Object.keys(record);
      if (keys.length === 0) return true;
      const operatorKeys = keys.filter((key: string): boolean => key.startsWith('$'));
      if (operatorKeys.length === 0) return keys.length === 0;
      if (operatorKeys.length === 1 && operatorKeys[0] === '$set') {
        const setRecord = toRecord(record['$set']);
        return !setRecord || Object.keys(setRecord).length === 0;
      }
      return false;
    };

    if (isEmptyCustomUpdateDoc(updateDoc)) {
      return {
        output: {
          result: null,
          bundle: {
            skipped: true,
            reason: 'no_parameter_updates',
          },
          debugPayload,
          aiPrompt,
        },
      };
    }
  }

  debugPayload['updateDoc'] = updateDoc;

  return {
    plan: {
      resolvedFilter,
      debugPayload,
      parameterTargetPath,
      updates,
      primaryTarget,
      updateDoc,
    },
  };
}

import type { DbQueryConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import type { StringRecord } from '@/shared/contracts/base';
import type { HttpResult } from '@/shared/contracts/http';
import { dbApi } from '@/shared/lib/ai-paths/api';
import { isObjectRecord } from '@/shared/utils/object-utils';

import {
  resolveParameterIdsFromInputs,
  shouldRunParameterDefinitionFallback,
} from './database-parameter-inference';
import { parseJsonSafe } from '../../utils';

interface DbQueryResult {
  items?: unknown[];
  item?: unknown;
  count?: number;
  requestedProvider?: 'auto' | 'mongodb';
  resolvedProvider?: 'mongodb';
}

export type ExecuteDatabaseQueryInput = {
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  queryConfig: DbQueryConfig;
  query: Record<string, unknown>;
  querySource?: string;
  collectionMap?: StringRecord;
  templateInputs?: RuntimePortValues;
  dryRun: boolean;
  aiPrompt: string;
};

export async function executeDatabaseQuery({
  reportAiPathsError,
  toast,
  queryConfig,
  query,
  querySource,
  collectionMap,
  templateInputs,
  dryRun,
  aiPrompt,
}: ExecuteDatabaseQueryInput): Promise<RuntimePortValues> {
  const projection: Record<string, unknown> | undefined = parseJsonSafe(
    queryConfig.projection ?? ''
  ) as Record<string, unknown> | undefined;
  const sort: Record<string, unknown> | undefined = parseJsonSafe(queryConfig.sort ?? '') as
    | Record<string, unknown>
    | undefined;

  if (dryRun) {
    const requestedProvider =
      typeof queryConfig.provider === 'string' ? queryConfig.provider : 'auto';
    const resolvedProvider = requestedProvider === 'auto' ? null : requestedProvider;
    return {
      result: query,
      bundle: {
        dryRun: true,
        query,
        collection: queryConfig.collection,
        ...(collectionMap ? { collectionMap } : {}),
        projection,
        sort,
        limit: queryConfig.limit,
        single: queryConfig.single,
        idType: queryConfig.idType,
        requestedProvider,
        resolvedProvider,
        ...(querySource ? { querySource } : {}),
      } as RuntimePortValues,
      aiPrompt,
    };
  }

  const queryResult: HttpResult<DbQueryResult> = await dbApi.query<DbQueryResult>({
    provider: queryConfig.provider,
    collection: queryConfig.collection,
    filter: query,
    projection,
    sort,
    limit: queryConfig.limit,
    single: queryConfig.single,
    ...(collectionMap ? { collectionMap } : {}),
    idType: queryConfig.idType as 'string' | 'objectId' | undefined,
  });

  if (!queryResult.ok) {
    const requestedProvider =
      typeof queryConfig.provider === 'string' ? queryConfig.provider : 'auto';
    reportAiPathsError(
      new Error(queryResult.error),
      { action: 'dbQuery', collection: queryConfig.collection, query },
      'Database query failed:'
    );
    toast(queryResult.error || 'Database query failed.', { variant: 'error' });
    return {
      result: null,
      bundle: {
        count: 0,
        query,
        collection: queryConfig.collection,
        requestedProvider,
        error: 'Query failed',
        ...(querySource ? { querySource } : {}),
      },
      aiPrompt,
    };
  }

  const queryResultData = isObjectRecord(queryResult.data)
    ? queryResult.data
    : ({} as Record<string, unknown>);
  const requestedProvider =
    queryResultData['requestedProvider'] === 'auto' ||
    queryResultData['requestedProvider'] === 'mongodb'
      ? queryResultData['requestedProvider']
      : queryConfig.provider === 'mongodb'
        ? 'mongodb'
        : 'auto';
  const hasResolvedProvider =
    queryResultData['resolvedProvider'] === 'mongodb';
  const resolvedProvider = hasResolvedProvider
    ? queryResultData['resolvedProvider']
    : requestedProvider === 'auto'
      ? null
      : requestedProvider;

  let result: unknown = queryConfig.single
    ? (queryResultData['item'] ?? null)
    : (queryResultData['items'] ?? []);
  let count: number =
    (queryResultData['count'] as number) ??
    (Array.isArray(result) ? (result as unknown[]).length : result ? 1 : 0);
  let fallback: Record<string, unknown> | undefined;

  const fallbackParameterIds =
    templateInputs && !queryConfig.single ? resolveParameterIdsFromInputs(templateInputs) : [];
  if (
    fallbackParameterIds.length > 0 &&
    shouldRunParameterDefinitionFallback({
      collection: queryConfig.collection,
      query,
      count,
      queryTemplate: queryConfig.queryTemplate ?? '',
    })
  ) {
    const parameterIds = Array.from(new Set(fallbackParameterIds));
    const fallbackQuery = {
      id: {
        $in: parameterIds,
      },
    };
    const fallbackQueryResult: HttpResult<DbQueryResult> = await dbApi.query<DbQueryResult>({
      provider: queryConfig.provider,
      collection: queryConfig.collection,
      filter: fallbackQuery,
      projection,
      sort,
      limit: Math.max(queryConfig.limit ?? parameterIds.length, parameterIds.length),
      single: false,
      ...(collectionMap ? { collectionMap } : {}),
      idType: queryConfig.idType as 'string' | 'objectId' | undefined,
    });

    if (!fallbackQueryResult.ok) {
      reportAiPathsError(
        new Error(fallbackQueryResult.error),
        { action: 'dbQueryFallback', collection: queryConfig.collection, query: fallbackQuery },
        'Database fallback query failed:'
      );
      fallback = {
        strategy: 'parameterId',
        query: fallbackQuery,
        parameterIds,
        error: 'Query failed',
      };
    } else {
      const fallbackData = isObjectRecord(fallbackQueryResult.data)
        ? fallbackQueryResult.data
        : ({} as Record<string, unknown>);
      const fallbackResult = fallbackData['items'] ?? [];
      const fallbackCount =
        (fallbackData['count'] as number) ??
        (Array.isArray(fallbackResult) ? fallbackResult.length : fallbackResult ? 1 : 0);

      fallback = {
        strategy: 'parameterId',
        query: fallbackQuery,
        parameterIds,
        count: fallbackCount,
      };

      if (fallbackCount > 0) {
        result = fallbackResult;
        count = fallbackCount;
      }
    }
  }

  const collectionLabel =
    typeof queryConfig.collection === 'string' && queryConfig.collection.trim()
      ? queryConfig.collection
      : 'collection';
  toast(
    `Database query succeeded for ${collectionLabel} (${count} result${count === 1 ? '' : 's'}).`,
    { variant: 'success' }
  );

  return {
    result,
    bundle: {
      count,
      query,
      collection: queryConfig.collection,
      requestedProvider,
      resolvedProvider,
      ...(fallback ? { fallback } : {}),
      ...(querySource ? { querySource } : {}),
    },
    aiPrompt,
  };
}

import type { DbQueryConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { extractMissingTemplatePorts } from './integration-database-mongo-update-plan-helpers';
import { coerceInput, parseJsonSafe, renderJsonTemplate } from '../../utils';

export type QueryResolutionSource = 'aiQuery' | 'input' | 'callback' | 'customTemplate';

export type ResolveDatabaseQueryResult =
  | { output: RuntimePortValues }
  | {
      query: Record<string, unknown>;
      queryConfig: DbQueryConfig;
      querySource: QueryResolutionSource;
    };

export type ResolveDatabaseQueryInput = {
  nodeInputs: RuntimePortValues;
  toast: NodeHandlerContext['toast'];
  simulationEntityType: string | null;
  simulationEntityId: string | null;
  resolvedInputs: Record<string, unknown>;
  queryConfig: DbQueryConfig;
  templateInputValue: unknown;
  templateContext: Record<string, unknown>;
  aiPrompt: string;
};

type QueryTemplateParseResult =
  | { ok: true; query: Record<string, unknown> }
  | { ok: false; error: string };

const buildResolutionErrorOutput = (args: {
  aiPrompt: string;
  collection: string;
  error: string;
  querySource: QueryResolutionSource;
  rawInput?: unknown;
  rawTemplate?: string;
}): ResolveDatabaseQueryResult => ({
  output: {
    result: null,
    bundle: {
      count: 0,
      query: {},
      collection: args.collection,
      error: args.error,
      querySource: args.querySource,
      guardrail: 'query-resolution',
      ...(args.rawInput !== undefined ? { rawInput: args.rawInput } : {}),
      ...(args.rawTemplate !== undefined ? { rawTemplate: args.rawTemplate } : {}),
    },
    aiPrompt: args.aiPrompt,
  },
});

const parseRenderedQueryTemplate = (args: {
  template: string;
  label: string;
  templateContext: Record<string, unknown>;
  inputValue: unknown;
}): QueryTemplateParseResult => {
  const missingPorts = extractMissingTemplatePorts(args.template, args.templateContext);
  if (missingPorts.length > 0) {
    return {
      ok: false,
      error: `${args.label} is missing connected inputs: ${missingPorts.join(', ')}.`,
    };
  }

  const parsed: unknown = parseJsonSafe(
    renderJsonTemplate(args.template, args.templateContext, args.inputValue)
  );

  if (!isObjectRecord(parsed)) {
    return {
      ok: false,
      error: `${args.label} must render to a valid JSON object.`,
    };
  }

  return {
    ok: true,
    query: parsed,
  };
};

const parseQueryInputValue = (args: {
  value: unknown;
  label: string;
  templateContext: Record<string, unknown>;
  inputValue: unknown;
}): QueryTemplateParseResult => {
  if (!args.value) {
    return {
      ok: false,
      error: `${args.label} is empty.`,
    };
  }

  if (isObjectRecord(args.value)) {
    const template = JSON.stringify(args.value);
    return parseRenderedQueryTemplate({
      template,
      label: args.label,
      templateContext: args.templateContext,
      inputValue: args.inputValue,
    });
  }

  if (typeof args.value === 'string') {
    const match: RegExpMatchArray | null = args.value.match(/```(?:json)?\s*([\s\S]*?)```/);
    const jsonStr: string = match ? match[1]!.trim() : args.value.trim();
    return parseRenderedQueryTemplate({
      template: jsonStr,
      label: args.label,
      templateContext: args.templateContext,
      inputValue: args.inputValue,
    });
  }

  return {
    ok: false,
    error: `${args.label} must be a JSON object or JSON string.`,
  };
};

const buildQueryResolutionFailure = (args: {
  toast: NodeHandlerContext['toast'];
  aiPrompt: string;
  collection: string;
  error: string;
  querySource: QueryResolutionSource;
  rawInput?: unknown;
  rawTemplate?: string;
}): ResolveDatabaseQueryResult => {
  args.toast(args.error, { variant: 'error' });
  return buildResolutionErrorOutput({
    aiPrompt: args.aiPrompt,
    collection: args.collection,
    error: args.error,
    querySource: args.querySource,
    ...(args.rawInput !== undefined ? { rawInput: args.rawInput } : {}),
    ...(args.rawTemplate !== undefined ? { rawTemplate: args.rawTemplate } : {}),
  });
};

const resolveParsedInputQuery = (args: {
  value: unknown;
  label: string;
  templateContext: Record<string, unknown>;
  inputValue: unknown;
  toast: NodeHandlerContext['toast'];
  aiPrompt: string;
  collection: string;
  querySource: QueryResolutionSource;
}): ResolveDatabaseQueryResult | { query: Record<string, unknown>; querySource: QueryResolutionSource } => {
  const parsedQuery = parseQueryInputValue({
    value: args.value,
    label: args.label,
    templateContext: args.templateContext,
    inputValue: args.inputValue,
  });

  if (!parsedQuery.ok) {
    return buildQueryResolutionFailure({
      toast: args.toast,
      aiPrompt: args.aiPrompt,
      collection: args.collection,
      error: parsedQuery.error,
      querySource: args.querySource,
      rawInput: args.value,
    });
  }

  return {
    query: parsedQuery.query,
    querySource: args.querySource,
  };
};

const resolveAiQueryPayload = (args: {
  query: Record<string, unknown>;
  queryConfig: DbQueryConfig;
}): { query: Record<string, unknown>; queryConfig: DbQueryConfig } => {
  if (!isObjectRecord(args.query['query'])) {
    return {
      query: args.query,
      queryConfig: args.queryConfig,
    };
  }

  return {
    query: args.query['query'],
    queryConfig:
      typeof args.query['collection'] === 'string'
        ? {
            ...args.queryConfig,
            collection: args.query['collection'],
          }
        : args.queryConfig,
  };
};

const resolveCustomTemplateQuery = (args: {
  queryConfig: DbQueryConfig;
  toast: NodeHandlerContext['toast'];
  aiPrompt: string;
  templateContext: Record<string, unknown>;
  inputValue: unknown;
}): ResolveDatabaseQueryResult | {
  query: Record<string, unknown>;
  queryConfig: DbQueryConfig;
  querySource: QueryResolutionSource;
} => {
  if (args.queryConfig.mode === 'preset') {
    const error =
      'Preset query mode is disabled. Define an explicit query template or connect an explicit query input.';
    return buildQueryResolutionFailure({
      toast: args.toast,
      aiPrompt: args.aiPrompt,
      collection: args.queryConfig.collection,
      error,
      querySource: 'customTemplate',
    });
  }

  const template = args.queryConfig.queryTemplate ?? '';
  if (!template.trim()) {
    const error =
      'No explicit query provided. Define queryTemplate or connect query/queryCallback/aiQuery input.';
    return buildQueryResolutionFailure({
      toast: args.toast,
      aiPrompt: args.aiPrompt,
      collection: args.queryConfig.collection,
      error,
      querySource: 'customTemplate',
      rawTemplate: template,
    });
  }

  const parsedTemplateQuery = parseRenderedQueryTemplate({
    template,
    label: 'Query template',
    templateContext: args.templateContext,
    inputValue: args.inputValue,
  });

  if (!parsedTemplateQuery.ok) {
    return buildQueryResolutionFailure({
      toast: args.toast,
      aiPrompt: args.aiPrompt,
      collection: args.queryConfig.collection,
      error: parsedTemplateQuery.error,
      querySource: 'customTemplate',
      rawTemplate: template,
    });
  }

  return {
    query: parsedTemplateQuery.query,
    queryConfig: args.queryConfig,
    querySource: 'customTemplate',
  };
};

export function resolveDatabaseQuery({
  nodeInputs,
  toast,
  simulationEntityType: _simulationEntityType,
  simulationEntityId: _simulationEntityId,
  resolvedInputs: _resolvedInputs,
  queryConfig,
  templateInputValue,
  templateContext,
  aiPrompt,
}: ResolveDatabaseQueryInput): ResolveDatabaseQueryResult {
  const inputQuery: unknown = coerceInput(nodeInputs['query']);
  const callbackInput: unknown = coerceInput(nodeInputs['queryCallback']);
  const aiQueryInput: unknown = coerceInput(nodeInputs['aiQuery']);

  const inputValue: unknown = templateInputValue;

  if (aiQueryInput !== undefined && aiQueryInput !== null) {
    const resolvedAiQuery = resolveParsedInputQuery({
      value: aiQueryInput,
      label: 'AI query',
      templateContext,
      inputValue,
      toast,
      aiPrompt,
      collection: queryConfig.collection,
      querySource: 'aiQuery',
    });
    if ('output' in resolvedAiQuery) {
      return resolvedAiQuery;
    }

    const aiQueryPayload = resolveAiQueryPayload({
      query: resolvedAiQuery.query,
      queryConfig: { ...queryConfig },
    });
    return {
      query: aiQueryPayload.query,
      queryConfig: aiQueryPayload.queryConfig,
      querySource: resolvedAiQuery.querySource,
    };
  }

  if (inputQuery !== undefined && inputQuery !== null) {
    const resolvedInputQuery = resolveParsedInputQuery({
      value: inputQuery,
      label: 'Query input',
      templateContext,
      inputValue,
      toast,
      aiPrompt,
      collection: queryConfig.collection,
      querySource: 'input',
    });
    if ('output' in resolvedInputQuery) {
      return resolvedInputQuery;
    }

    return {
      query: resolvedInputQuery.query,
      queryConfig: { ...queryConfig },
      querySource: resolvedInputQuery.querySource,
    };
  }

  if (callbackInput !== undefined && callbackInput !== null) {
    const resolvedCallbackQuery = resolveParsedInputQuery({
      value: callbackInput,
      label: 'Query callback',
      templateContext,
      inputValue,
      toast,
      aiPrompt,
      collection: queryConfig.collection,
      querySource: 'callback',
    });
    if ('output' in resolvedCallbackQuery) {
      return resolvedCallbackQuery;
    }

    return {
      query: resolvedCallbackQuery.query,
      queryConfig: { ...queryConfig },
      querySource: resolvedCallbackQuery.querySource,
    };
  }

  const resolvedTemplateQuery = resolveCustomTemplateQuery({
    queryConfig: { ...queryConfig },
    toast,
    aiPrompt,
    templateContext,
    inputValue,
  });
  if ('output' in resolvedTemplateQuery) {
    return resolvedTemplateQuery;
  }

  return {
    query: resolvedTemplateQuery.query,
    queryConfig: resolvedTemplateQuery.queryConfig,
    querySource: resolvedTemplateQuery.querySource,
  };
}

import type { DatabaseConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import type { CollectionSchema } from '@/shared/contracts/database';
import type { SchemaResponse } from '@/shared/lib/ai-paths/api/client';

import {
  normalizeNonEmptyString,
  normalizeParameterEntries,
  resolveExistingParameterValueFromInputs,
  toRecord,
} from './database-parameter-inference';
import { DB_PROVIDER_PLACEHOLDERS } from '../../constants';
import { coerceInput, renderTemplate } from '../../utils';


const toTitleCase = (value: string): string =>
  value
    .replace(/[_-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .split(' ')
    .filter(Boolean)
    .map((part: string) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(' ');

const singularize = (value: string): string => {
  if (value.endsWith('ies') && value.length > 3) {
    return `${value.slice(0, -3)}y`;
  }
  if (value.endsWith('ses') && value.length > 3) {
    return value.slice(0, -2);
  }
  if (value.endsWith('s') && !value.endsWith('ss') && value.length > 1) {
    return value.slice(0, -1);
  }
  return value;
};

const DATABASE_SCHEMA_TYPE_ALIASES: Record<string, string> = {
  string: 'string',
  int: 'number',
  float: 'number',
  decimal: 'number',
  number: 'number',
  boolean: 'boolean',
  bool: 'boolean',
  datetime: 'string',
  date: 'string',
  json: 'Record<string, unknown>',
};

const resolveSchemaTypeAlias = (value: string): string | null => {
  const normalizedValue = value.trim().toLowerCase();
  return DATABASE_SCHEMA_TYPE_ALIASES[normalizedValue] ?? null;
};

const normalizeSchemaType = (value: string): string => {
  const normalized = value.trim();
  return (resolveSchemaTypeAlias(normalized) ?? normalized) || 'unknown';
};

const formatCollectionSchema = (
  collectionName: string,
  fields: Array<{ name: string; type: string }> = []
): string => {
  const interfaceName = toTitleCase(singularize(collectionName));
  if (!fields.length) {
    return `interface ${interfaceName} {}`;
  }
  const lines = fields.map(
    (field: { name: string; type: string }) =>
      `  ${field.name}: ${normalizeSchemaType(field.type)};`
  );
  return `interface ${interfaceName} {\n${lines.join('\n')}\n}`;
};

const isCollectionSchema = (value: unknown): value is CollectionSchema => {
  const record = toRecord(value);
  return Boolean(record && typeof record['name'] === 'string' && Array.isArray(record['fields']));
};

const resolveCollectionList = (value: unknown): CollectionSchema[] => {
  if (Array.isArray(value)) {
    return value.filter((entry: unknown): entry is CollectionSchema => isCollectionSchema(entry));
  }
  const record = toRecord(value);
  if (!record) return [];
  return Object.values(record).filter((entry: unknown): entry is CollectionSchema =>
    isCollectionSchema(entry)
  );
};

const normalizeRuntimeEntityType = (value: string | null | undefined): string => {
  const normalized = normalizeNonEmptyString(value)?.toLowerCase() ?? '';
  if (normalized === 'products') return 'product';
  if (normalized === 'notes') return 'note';
  return normalized;
};

export type PrepareDatabaseTemplateContextInput = {
  resolvedInputs: Record<string, unknown>;
  dbConfig: DatabaseConfig;
  aiPromptTemplate: string;
  runId?: string | undefined;
  runStartedAt?: string | undefined;
  simulationEntityType: string | null;
  fallbackEntityId: string | null;
  fetchEntityCached: NodeHandlerContext['fetchEntityCached'];
  schemaData: SchemaResponse | null;
  strictFlowMode?: boolean;
};

export type PrepareDatabaseTemplateContextResult = {
  templateInputValue: unknown;
  templateInputs: RuntimePortValues;
  templateContext: Record<string, unknown>;
  aiPrompt: string;
  ensureExistingParameterTemplateContext: (
    targetPath: string,
    options?: { forceHydrateRichParameters?: boolean }
  ) => Promise<void>;
};

export function prepareDatabaseTemplateContext({
  resolvedInputs,
  dbConfig,
  aiPromptTemplate,
  runId,
  runStartedAt,
  simulationEntityType,
  fallbackEntityId,
  fetchEntityCached,
  schemaData,
  strictFlowMode = true,
}: PrepareDatabaseTemplateContextInput): PrepareDatabaseTemplateContextResult {
  const templateInputValue: unknown =
    resolvedInputs['value'] ??
    resolvedInputs['result'] ??
    coerceInput(resolvedInputs['jobId']);

  const placeholderContext: Record<string, unknown> = {
    'Date: Current': new Date().toISOString(),
  };
  DB_PROVIDER_PLACEHOLDERS.forEach((provider: string) => {
    placeholderContext[`DB Provider: ${provider}`] = provider;
  });
  const collections = resolveCollectionList(schemaData?.collections);
  if (collections.length) {
    collections.forEach((collection: CollectionSchema) => {
      const schemaText = formatCollectionSchema(collection.name, collection.fields ?? []);
      const displayName = toTitleCase(singularize(collection.name));
      const nameSet = new Set<string>([collection.name, displayName]);
      nameSet.forEach((name: string) => {
        placeholderContext[`Collection: ${name}`] = schemaText;
      });
    });
  }
  const templateInputs: RuntimePortValues = {
    ...resolvedInputs,
  };
  const rawContext = templateInputs['context'];
  const existingContext = toRecord(rawContext);
  const runtimeContextPatch: Record<string, unknown> = {};
  if (runId?.trim()) {
    templateInputs['runId'] ??= runId;
    runtimeContextPatch['runId'] = runId;
  }
  if (runStartedAt?.trim()) {
    templateInputs['runStartedAt'] ??= runStartedAt;
    runtimeContextPatch['runStartedAt'] = runStartedAt;
  }
  if (
    Object.keys(runtimeContextPatch).length > 0 &&
    (rawContext === undefined || rawContext === null || existingContext !== null)
  ) {
    templateInputs['context'] = {
      ...(existingContext ?? {}),
      ...runtimeContextPatch,
    };
  }
  const templateContext: Record<string, unknown> = {
    ...templateInputs,
    ...placeholderContext,
  };

  const ensureExistingParameterTemplateContext = async (
    targetPath: string,
    options?: { forceHydrateRichParameters?: boolean }
  ): Promise<void> => {
    if (!targetPath) return;
    const existingFromInputs = normalizeParameterEntries(
      resolveExistingParameterValueFromInputs(templateInputs, targetPath, {
        includeDerivedPorts: false,
      }),
      { allowEmptyValue: true }
    );
    const forceHydrateRichParameters = options?.forceHydrateRichParameters === true;
    const shouldHydrateRichProductParameters =
      targetPath === 'parameters' &&
      (forceHydrateRichParameters ||
        (existingFromInputs.length > 0 &&
          existingFromInputs.every((entry) => {
            const valuesByLanguage = entry.raw['valuesByLanguage'];
            return !(
              valuesByLanguage &&
              typeof valuesByLanguage === 'object' &&
              !Array.isArray(valuesByLanguage) &&
              Object.keys(valuesByLanguage as Record<string, unknown>).length > 0
            );
          })));
    if (existingFromInputs.length > 0 && !shouldHydrateRichProductParameters) {
      return;
    }

    const entityId =
      normalizeNonEmptyString(templateInputs['entityId']) ??
      normalizeNonEmptyString(templateInputs['productId']) ??
      normalizeNonEmptyString(resolvedInputs['entityId']) ??
      normalizeNonEmptyString(resolvedInputs['productId']) ??
      (!strictFlowMode ? normalizeNonEmptyString(fallbackEntityId) : null) ??
      null;
    if (!entityId) {
      return;
    }

    const entityType = normalizeRuntimeEntityType(
      normalizeNonEmptyString(templateInputs['entityType']) ??
        normalizeNonEmptyString(resolvedInputs['entityType']) ??
        normalizeNonEmptyString(dbConfig.entityType) ??
        simulationEntityType ??
        'product'
    );
    if (!entityType) {
      return;
    }

    const fetchedEntity = await fetchEntityCached(entityType, entityId);
    const fetchedRecord = toRecord(fetchedEntity);
    if (!fetchedRecord) {
      return;
    }

    const contextRecord = toRecord(templateInputs['context']) ?? {};
    templateInputs['context'] = {
      ...contextRecord,
      entity: fetchedRecord,
      entityJson: fetchedRecord,
      ...(entityType === 'product' ? { product: fetchedRecord } : {}),
      entityId: normalizeNonEmptyString(contextRecord['entityId']) ?? entityId,
      productId:
        normalizeNonEmptyString(contextRecord['productId']) ??
        (entityType === 'product' ? entityId : undefined),
      entityType: normalizeNonEmptyString(contextRecord['entityType']) ?? entityType,
    };
    if (templateInputs['entityId'] === undefined) {
      templateInputs['entityId'] = entityId;
    }
    if (templateInputs['productId'] === undefined && entityType === 'product') {
      templateInputs['productId'] = entityId;
    }
    if (templateInputs['entityType'] === undefined) {
      templateInputs['entityType'] = entityType;
    }
    templateContext['context'] = templateInputs['context'];
    templateContext['entityId'] = templateInputs['entityId'];
    templateContext['productId'] = templateInputs['productId'];
    templateContext['entityType'] = templateInputs['entityType'];
  };

  const aiPrompt: string = aiPromptTemplate.trim()
    ? renderTemplate(aiPromptTemplate, templateContext, templateInputValue ?? '')
    : '';

  return {
    templateInputValue,
    templateInputs,
    templateContext,
    aiPrompt,
    ensureExistingParameterTemplateContext,
  };
}

import type {
  DatabaseConfig,
  DbQueryConfig,
  DatabaseWriteOutcome,
} from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import type { HttpResult } from '@/shared/contracts/http';
import { dbApi, entityApi } from '@/shared/lib/ai-paths/api';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { buildDbQueryPayload } from '../utils';
import {
  evaluateWriteOutcome,
  resolveWriteOutcomePolicy,
} from './integration-database-write-guardrails';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


interface DbActionResult {
  items?: unknown[];
  item?: unknown;
  values?: unknown[];
  count?: number;
  modifiedCount?: number;
  matchedCount?: number;
  requestedProvider?: 'auto' | 'mongodb';
  resolvedProvider?: 'mongodb';
}

type ResolveCollectionUpdateContextInput = {
  resolvedInputs: Record<string, unknown>;
  queryConfig: DbQueryConfig;
  configuredCollection: string;
  entityType: string;
};

type ResolveCollectionUpdateContextResult = {
  queryPayload: ReturnType<typeof buildDbQueryPayload>;
  query: Record<string, unknown>;
  collection: string;
};

const resolveCollectionUpdateContext = ({
  resolvedInputs,
  queryConfig,
  configuredCollection,
  entityType,
}: ResolveCollectionUpdateContextInput): ResolveCollectionUpdateContextResult => {
  const queryPayload = buildDbQueryPayload(resolvedInputs, queryConfig);
  const queryFromPayload = isObjectRecord(queryPayload['filter']) ? queryPayload['filter'] : {};
  const query = queryFromPayload;
  const collection =
    (queryPayload['collection'] as string | undefined)?.trim() ||
    configuredCollection ||
    entityType;
  return {
    queryPayload,
    query,
    collection,
  };
};

export type ExecuteDatabaseUpdateInput = {
  nodeId: string;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  dryRun: boolean;
  resolvedInputs: Record<string, unknown>;
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  updates: Record<string, unknown>;
  updateStrategy: 'one' | 'many';
  entityType: string;
  shouldUseEntityUpdate: boolean;
  entityId: string | null;
  configuredCollection: string;
  updatePayloadMode?: 'mapping' | 'custom';
  customFilter?: Record<string, unknown>;
  customUpdateDoc?: unknown;
};

export type ExecuteDatabaseUpdateResult =
  | { skipped: true }
  | {
      skipped: false;
      updateResult: unknown;
      executionMeta: Record<string, unknown>;
      writeOutcome: DatabaseWriteOutcome;
    };

const resolveProviderMeta = (responseData: unknown): Record<string, unknown> => {
  if (!isObjectRecord(responseData)) return {};
  const requestedProvider =
    responseData['requestedProvider'] === 'auto' ||
    responseData['requestedProvider'] === 'mongodb'
      ? responseData['requestedProvider']
      : undefined;
  const resolvedProvider =
    responseData['resolvedProvider'] === 'mongodb'
      ? responseData['resolvedProvider']
      : undefined;
  return {
    ...(requestedProvider ? { requestedProvider } : {}),
    ...(resolvedProvider ? { resolvedProvider } : {}),
  };
};

export async function executeDatabaseUpdate({
  nodeId,
  executed,
  reportAiPathsError,
  toast,
  dryRun,
  resolvedInputs,
  dbConfig,
  queryConfig,
  updates,
  updateStrategy,
  entityType,
  shouldUseEntityUpdate,
  entityId,
  configuredCollection,
  updatePayloadMode = 'mapping',
  customFilter,
  customUpdateDoc,
}: ExecuteDatabaseUpdateInput): Promise<ExecuteDatabaseUpdateResult> {
  const isCustomPayloadMode = updatePayloadMode === 'custom';
  const zeroAffectedPolicy = resolveWriteOutcomePolicy(dbConfig);
  let updateResult: unknown = updates;
  let executionMeta: Record<string, unknown> = {
    mode: updatePayloadMode,
    strategy: updateStrategy,
  };
  let writeOutcome: DatabaseWriteOutcome = {
    status: 'success',
    operation: 'update',
  };

  const applyWriteOutcome = (
    action: string,
    resultPayload: unknown,
    context: Record<string, unknown>
  ): void => {
    const outcome = evaluateWriteOutcome({
      operation: 'update',
      action,
      result: resultPayload,
      policy: zeroAffectedPolicy,
    });
    writeOutcome = outcome.writeOutcome;
    if (!outcome.isZeroAffected) return;
    const outcomeMessage =
      outcome.writeOutcome.message ?? `Database write affected 0 records for update (${action}).`;
    if (outcome.writeOutcome.status === 'failed') {
      reportAiPathsError(
        new Error(outcomeMessage),
        {
          action: 'dbWriteOutcome',
          nodeId,
          policy: zeroAffectedPolicy,
          ...context,
          writeOutcome: outcome.writeOutcome,
        },
        'Database update failed:'
      );
      toast(outcomeMessage, { variant: 'error' });
      throw new Error(outcomeMessage);
    }
    reportAiPathsError(new Error(outcomeMessage), {
      action: 'dbWriteOutcome',
      nodeId,
      errorCode: 'AI_PATHS_DB_WRITE_ZERO_AFFECTED',
      errorCategory: 'database',
      errorScope: 'node',
      errorSeverity: 'warning',
      policy: zeroAffectedPolicy,
      ...context,
      writeOutcome: outcome.writeOutcome,
    });
    toast(outcomeMessage, { variant: 'warning' });
  };

  if (updateStrategy === 'many') {
    const queryPayload = buildDbQueryPayload(resolvedInputs, queryConfig);
    const queryFromPayload = isObjectRecord(queryPayload['filter']) ? queryPayload['filter'] : {};
    const query = isCustomPayloadMode && customFilter ? customFilter : queryFromPayload;
    const hasQuery = query && typeof query === 'object' && Object.keys(query).length > 0;

    executionMeta = {
      ...executionMeta,
      action: isCustomPayloadMode ? 'updateMany' : 'dbUpdateMany',
      collection: queryPayload['collection'],
      filter: query,
      update: isCustomPayloadMode ? customUpdateDoc : updates,
      requestedProvider: queryPayload.provider,
      ...(queryPayload.idType !== undefined ? { idType: queryPayload.idType } : {}),
    };

    if (!isCustomPayloadMode && dbConfig.mode === 'append' && !executed.updater.has(nodeId)) {
      reportAiPathsError(
        new Error('Append mode is not supported for update many'),
        { action: 'updateMany', nodeId },
        'Database update many failed:'
      );
      toast('Update many does not support append mode.', {
        variant: 'error',
      });
      updateResult = {
        error: 'append_not_supported',
        updates,
        query,
        collection: queryPayload['collection'],
      };
      executed.updater.add(nodeId);
    } else if (!hasQuery && !executed.updater.has(nodeId)) {
      reportAiPathsError(
        new Error('Database update missing explicit query filter'),
        {
          action: 'updateMany',
          collection: queryPayload['collection'],
          nodeId,
        },
        'Database update many failed:'
      );
      toast('Database update requires an explicit query filter.', {
        variant: 'error',
      });
      updateResult = {
        error: 'missing_query',
        collection: queryPayload['collection'],
        ...(isCustomPayloadMode ? { update: customUpdateDoc } : { updates }),
      };
      executed.updater.add(nodeId);
    } else if (hasQuery && !executed.updater.has(nodeId)) {
      if (dryRun) {
        updateResult = {
          dryRun: true,
          updateMany: true,
          collection: queryPayload['collection'],
          query,
          update: isCustomPayloadMode ? customUpdateDoc : updates,
          mode: dbConfig.mode ?? 'replace',
          ...executionMeta,
        };
        executed.updater.add(nodeId);
      } else {
        const dbUpdateResult: HttpResult<DbActionResult> = isCustomPayloadMode
          ? await dbApi.action<DbActionResult>({
            provider: queryPayload.provider,
            action: 'updateMany',
            collection: queryPayload.collection,
            ...(queryPayload.collectionMap ? { collectionMap: queryPayload.collectionMap } : {}),
            filter: query,
            update: customUpdateDoc,
            ...(queryPayload.idType !== undefined ? { idType: queryPayload.idType } : {}),
          })
          : await dbApi.update<DbActionResult>({
            provider: queryPayload.provider,
            collection: queryPayload.collection,
            ...(queryPayload.collectionMap ? { collectionMap: queryPayload.collectionMap } : {}),
            filter: query,
            update: updates,
            single: false,
            ...(queryPayload.idType !== undefined ? { idType: queryPayload.idType } : {}),
          });
        executed.updater.add(nodeId);
        if (!dbUpdateResult.ok) {
          reportAiPathsError(
            new Error(dbUpdateResult.error),
            {
              action: 'updateMany',
              collection: queryPayload['collection'],
              nodeId,
            },
            'Database update many failed:'
          );
          toast(`Failed to update ${queryPayload['collection']}.`, {
            variant: 'error',
          });
        } else {
          updateResult = dbUpdateResult.data;
          executionMeta = {
            ...executionMeta,
            ...resolveProviderMeta(dbUpdateResult.data),
          };
          applyWriteOutcome('updateMany', dbUpdateResult.data, {
            collection: queryPayload['collection'],
            strategy: updateStrategy,
          });
          const modified: number =
            ((dbUpdateResult.data as Record<string, unknown>)?.['modifiedCount'] as number) ?? 0;
          const matched: number =
            ((dbUpdateResult.data as Record<string, unknown>)?.['matchedCount'] as number) ?? 0;
          const countLabel = modified || matched;
          if (writeOutcome.status !== 'warning') {
            toast(
              `Updated ${countLabel} document${countLabel === 1 ? '' : 's'} in ${queryPayload['collection']}.`,
              { variant: 'success' }
            );
          }
        }
      }
    }
  } else if (!executed.updater.has(nodeId)) {
    if (dryRun) {
      if (shouldUseEntityUpdate && !isCustomPayloadMode) {
        executionMeta = {
          ...executionMeta,
          action: 'entityUpdate',
          entityType,
          entityId: entityId || undefined,
          requestedProvider: 'entityApi',
          resolvedProvider: 'entityApi',
        };
        updateResult = {
          dryRun: true,
          entityType,
          entityId: entityId || undefined,
          updates,
          mode: dbConfig.mode ?? 'replace',
          ...executionMeta,
        };
      } else {
        const { query, collection, queryPayload } = resolveCollectionUpdateContext({
          resolvedInputs,
          queryConfig,
          configuredCollection,
          entityType,
        });
        const resolvedFilter = isCustomPayloadMode && customFilter ? customFilter : query;
        executionMeta = {
          ...executionMeta,
          action: isCustomPayloadMode ? 'updateOne' : 'dbUpdateOne',
          collection,
          filter: resolvedFilter,
          update: isCustomPayloadMode ? customUpdateDoc : updates,
          requestedProvider: queryPayload.provider,
          ...(queryPayload.idType !== undefined ? { idType: queryPayload.idType } : {}),
        };
        updateResult = {
          dryRun: true,
          updateMany: false,
          collection,
          query: resolvedFilter,
          update: isCustomPayloadMode ? customUpdateDoc : updates,
          mode: dbConfig.mode ?? 'replace',
          ...executionMeta,
        };
      }
      executed.updater.add(nodeId);
    } else if (shouldUseEntityUpdate && !isCustomPayloadMode) {
      if (!entityId) {
        reportAiPathsError(
          new Error('Database update missing explicit entityId'),
          { action: 'updateEntity', entityType, nodeId },
          'Database update failed:'
        );
        toast(`Database update for ${entityType} requires explicit entityId.`, {
          variant: 'error',
        });
        updateResult = {
          error: 'missing_entity_id',
          entityType,
          updates,
        };
        executed.updater.add(nodeId);
        return {
          skipped: false,
          updateResult,
          executionMeta,
          writeOutcome,
        };
      }
      try {
        const entityUpdateResult = await entityApi.update({
          entityType,
          entityId,
          updates,
          mode: dbConfig.mode ?? 'replace',
        });
        if (!entityUpdateResult.ok) {
          throw new Error(entityUpdateResult.error);
        }
        updateResult = entityUpdateResult.data ?? updates;
        executionMeta = {
          ...executionMeta,
          action: 'entityUpdate',
          entityType,
          entityId,
          requestedProvider: 'entityApi',
          resolvedProvider: 'entityApi',
        };
        applyWriteOutcome('entityUpdate', entityUpdateResult.data ?? {}, {
          entityType,
          entityId,
          strategy: updateStrategy,
        });
        executed.updater.add(nodeId);
        const suffix = entityId ? ` ${entityId}` : '';
        if (writeOutcome.status !== 'warning') {
          toast(`Updated ${entityType}${suffix}`, { variant: 'success' });
        }
      } catch (error: unknown) {
        logClientError(error);
        reportAiPathsError(
          error,
          { action: 'updateEntity', entityType, entityId, nodeId },
          'Database update failed:'
        );
        toast(`Failed to update ${entityType}.`, { variant: 'error' });
        executed.updater.add(nodeId);
      }
    } else {
      const { queryPayload, query, collection } = resolveCollectionUpdateContext({
        resolvedInputs,
        queryConfig,
        configuredCollection,
        entityType,
      });
      const resolvedFilter = isCustomPayloadMode && customFilter ? customFilter : query;
      executionMeta = {
        ...executionMeta,
        action: isCustomPayloadMode ? 'updateOne' : 'dbUpdateOne',
        collection,
        filter: resolvedFilter,
        update: isCustomPayloadMode ? customUpdateDoc : updates,
        requestedProvider: queryPayload.provider,
        ...(queryPayload.idType !== undefined ? { idType: queryPayload.idType } : {}),
      };

      if (Object.keys(resolvedFilter).length === 0) {
        reportAiPathsError(
          new Error('Database update missing query filter'),
          {
            action: 'dbUpdateOne',
            collection,
            entityType,
            entityId,
            nodeId,
          },
          'Database update failed:'
        );
        toast('Database update requires a query filter.', { variant: 'error' });
        updateResult = {
          error: 'missing_query',
          collection,
          ...(isCustomPayloadMode ? { update: customUpdateDoc } : { updates }),
        };
        executed.updater.add(nodeId);
      } else {
        const dbUpdateResult: HttpResult<DbActionResult> = isCustomPayloadMode
          ? await dbApi.action<DbActionResult>({
            provider: queryPayload.provider,
            action: 'updateOne',
            collection,
            ...(queryPayload.collectionMap ? { collectionMap: queryPayload.collectionMap } : {}),
            filter: resolvedFilter,
            update: customUpdateDoc,
            ...(queryPayload.idType !== undefined ? { idType: queryPayload.idType } : {}),
          })
          : await dbApi.update<DbActionResult>({
            provider: queryPayload.provider,
            collection,
            ...(queryPayload.collectionMap ? { collectionMap: queryPayload.collectionMap } : {}),
            filter: resolvedFilter,
            update: updates,
            single: true,
            ...(queryPayload.idType !== undefined ? { idType: queryPayload.idType } : {}),
          });
        executed.updater.add(nodeId);
        if (!dbUpdateResult.ok) {
          reportAiPathsError(
            new Error(dbUpdateResult.error),
            {
              action: 'dbUpdateOne',
              collection,
              entityType,
              nodeId,
            },
            'Database update failed:'
          );
          toast(dbUpdateResult.error || `Failed to update ${collection}.`, {
            variant: 'error',
          });
        } else {
          updateResult = dbUpdateResult.data;
          executionMeta = {
            ...executionMeta,
            ...resolveProviderMeta(dbUpdateResult.data),
          };
          applyWriteOutcome('updateOne', dbUpdateResult.data, {
            collection,
            strategy: updateStrategy,
          });
          const modified: number = dbUpdateResult.data?.modifiedCount ?? 0;
          const matched: number = dbUpdateResult.data?.matchedCount ?? 0;
          const countLabel = modified || matched;
          if (writeOutcome.status !== 'warning') {
            toast(
              `Updated ${countLabel} document${countLabel === 1 ? '' : 's'} in ${collection}.`,
              { variant: 'success' }
            );
          }
        }
      }
    }
  }

  return {
    skipped: false,
    updateResult,
    executionMeta,
    writeOutcome,
  };
}

import type { DatabaseConfig } from '@/shared/contracts/ai-paths';
import type { UpdaterMapping } from '@/shared/contracts/ai-paths';

import { getValueAtMappingPath } from '../../utils';

export type ResolveDatabaseUpdateMappingsInput = {
  dbConfig: DatabaseConfig;
  nodeInputPorts: string[];
  resolvedInputs: Record<string, unknown>;
  parameterTargetPath: string;
};

export type ResolveDatabaseUpdateMappingsResult = {
  fallbackTarget: string;
  mappings: UpdaterMapping[];
  updates: Record<string, unknown>;
  requiredSourcePorts: Set<string>;
  unresolvedSourcePorts: Set<string>;
};

const normalizeSourcePath = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const buildSourcePathCandidates = (args: { sourcePath: string; sourcePort: string }): string[] => {
  const { sourcePath, sourcePort } = args;
  const candidates = new Set<string>([sourcePath]);
  if (sourcePath.startsWith(`${sourcePort}.`)) {
    candidates.add(sourcePath.slice(sourcePort.length + 1));
  }
  return Array.from(candidates).filter((candidate) => candidate.length > 0);
};

const resolveValueFromSource = (args: {
  sourceValue: unknown;
  sourcePath: string | null;
  sourcePort: string;
}): unknown => {
  const { sourceValue, sourcePath, sourcePort } = args;
  if (sourcePath === null) {
    return sourceValue;
  }
  const pathCandidates = buildSourcePathCandidates({
    sourcePath,
    sourcePort,
  });
  for (const path of pathCandidates) {
    const value = getValueAtMappingPath(sourceValue, path, {
      jsonIntegrityPolicy: 'repair',
    });
    if (value !== undefined) {
      return value;
    }
  }
  return undefined;
};

export function resolveDatabaseUpdateMappings({
  dbConfig,
  nodeInputPorts,
  resolvedInputs,
  parameterTargetPath,
}: ResolveDatabaseUpdateMappingsInput): ResolveDatabaseUpdateMappingsResult {
  const mappings = dbConfig.mappings ?? [];
  const updates: Record<string, unknown> = {};
  const requiredSourcePorts = new Set<string>();
  const unresolvedSourcePorts = new Set<string>();
  const inputPorts = new Set(nodeInputPorts.map((port) => port.trim()).filter(Boolean));

  mappings.forEach((mapping) => {
    const sourcePort = mapping.sourcePort;
    const targetPath = mapping.targetPath;
    if (!sourcePort || !targetPath) return;

    requiredSourcePorts.add(sourcePort);
    if (!inputPorts.has(sourcePort)) {
      unresolvedSourcePorts.add(sourcePort);
      return;
    }
    const sourcePath = normalizeSourcePath(mapping.sourcePath);
    const sourceValue = resolvedInputs[sourcePort];
    if (sourceValue === undefined) {
      unresolvedSourcePorts.add(sourcePort);
      return;
    }
    const resolvedValue = resolveValueFromSource({
      sourceValue,
      sourcePath,
      sourcePort,
    });
    if (resolvedValue === undefined) {
      unresolvedSourcePorts.add(sourcePort);
      return;
    }
    updates[targetPath] = resolvedValue;
  });

  return {
    fallbackTarget: parameterTargetPath,
    mappings,
    updates,
    requiredSourcePorts,
    unresolvedSourcePorts,
  };
}

import type { DatabaseConfig, DbQueryConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { parseJsonSafe, renderJsonTemplate } from '../../utils';
import { buildDbQueryPayload, resolveEntityIdFromInputs } from '../utils';
import {
  mergeLocalizedParameterUpdates,
  normalizeNonEmptyString,
} from './database-parameter-inference';
import {
  applyTopLevelWriteValuePolicies,
  resolveLocalizedParameterMergeConfig,
} from './database-write-policies';
import { executeDatabaseUpdate } from './integration-database-update-execution';
import { resolveDatabaseUpdateMappings } from './integration-database-update-mapping-resolution';
import {
  createWriteTemplateGuardrailOutput,
  resolveWriteTemplateGuardrail,
} from './integration-database-write-guardrails';

export type HandleDatabaseUpdateOperationInput = {
  node: NodeHandlerContext['node'];
  nodeInputs: RuntimePortValues;
  prevOutputs: RuntimePortValues;
  executed: NodeHandlerContext['executed'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  simulationEntityType: string | null;
  simulationEntityId: string | null;
  resolvedInputs: Record<string, unknown>;
  nodeInputPorts: string[];
  dbConfig: DatabaseConfig;
  queryConfig: DbQueryConfig;
  dryRun: boolean;
  templateInputs: RuntimePortValues;
  aiPrompt: string;
  ensureExistingParameterTemplateContext: (
    targetPath: string,
    options?: { forceHydrateRichParameters?: boolean }
  ) => Promise<void>;
};

const resolveCustomContentEnValue = (customUpdateDoc: unknown): string | undefined => {
  if (!isObjectRecord(customUpdateDoc)) return undefined;
  const directValue = customUpdateDoc['content_en'];
  if (typeof directValue === 'string') return directValue;
  const setDoc = customUpdateDoc['$set'];
  if (!isObjectRecord(setDoc)) return undefined;
  const setValue = setDoc['content_en'];
  return typeof setValue === 'string' ? setValue : undefined;
};

const patchTargetPathInUpdateDoc = (
  value: unknown,
  targetPath: string,
  nextUpdates: Record<string, unknown>
): unknown => {
  if (!isObjectRecord(value)) return value;
  const hasTarget = Object.prototype.hasOwnProperty.call(nextUpdates, targetPath);
  const nextTargetValue = nextUpdates[targetPath];
  const setDoc = value['$set'];
  if (isObjectRecord(setDoc)) {
    const nextSet: Record<string, unknown> = { ...setDoc };
    if (hasTarget) {
      nextSet[targetPath] = nextTargetValue;
    } else {
      delete nextSet[targetPath];
    }
    return { ...value, $set: nextSet };
  }
  const hasOperator = Object.keys(value).some((key: string): boolean => key.startsWith('$'));
  if (hasOperator) return value;
  const nextRecord: Record<string, unknown> = { ...value };
  if (hasTarget) {
    nextRecord[targetPath] = nextTargetValue;
  } else {
    delete nextRecord[targetPath];
  }
  return nextRecord;
};

const createNoSafeUpdatesOutput = (args: {
  error: string;
  aiPrompt: string;
  entityType: string;
  collection: string;
  filter: Record<string, unknown> | null;
  unresolvedSourcePorts?: string[];
  localizedParameterMergeMeta?: Record<string, unknown>;
  reportAiPathsError: HandleDatabaseUpdateOperationInput['reportAiPathsError'];
  toast: HandleDatabaseUpdateOperationInput['toast'];
  nodeId: string;
  mode: 'mapping' | 'custom';
}): RuntimePortValues => {
  args.reportAiPathsError(
    new Error(args.error),
    {
      action: 'dbUpdatePolicy',
      nodeId: args.nodeId,
      ...(args.unresolvedSourcePorts && args.unresolvedSourcePorts.length > 0
        ? { unresolvedSourcePorts: args.unresolvedSourcePorts }
        : {}),
      ...(args.localizedParameterMergeMeta
        ? { localizedParameterMerge: args.localizedParameterMergeMeta }
        : {}),
    },
    'Database update blocked:'
  );
  args.toast(args.error, { variant: 'error' });
  return {
    result: null,
    bundle: {
      error: args.error,
      guardrail: 'no-safe-updates',
      guardrailMeta: {
        code: 'no-safe-updates',
        severity: 'error',
        message: args.error,
        ...(args.unresolvedSourcePorts && args.unresolvedSourcePorts.length > 0
          ? { unresolvedSourcePorts: args.unresolvedSourcePorts }
          : {}),
        ...(args.localizedParameterMergeMeta
          ? { localizedParameterMerge: args.localizedParameterMergeMeta }
          : {}),
      },
    },
    debugPayload: {
      mode: args.mode,
      entityType: args.entityType,
      collection: args.collection || null,
      ...(args.filter ? { filter: args.filter } : {}),
      ...(args.unresolvedSourcePorts && args.unresolvedSourcePorts.length > 0
        ? { unresolvedSourcePorts: args.unresolvedSourcePorts }
        : {}),
      ...(args.localizedParameterMergeMeta
        ? { localizedParameterMerge: args.localizedParameterMergeMeta }
        : {}),
    },
    aiPrompt: args.aiPrompt,
  };
};

export async function handleDatabaseUpdateOperation({
  node,
  nodeInputs,
  prevOutputs,
  executed,
  reportAiPathsError,
  toast,
  simulationEntityType,
  simulationEntityId,
  resolvedInputs,
  nodeInputPorts,
  dbConfig,
  queryConfig,
  dryRun,
  templateInputs,
  aiPrompt,
  ensureExistingParameterTemplateContext,
}: HandleDatabaseUpdateOperationInput): Promise<RuntimePortValues> {
  const updatePayloadMode = dbConfig.updatePayloadMode ?? 'custom';

  const updateStrategy: 'one' | 'many' = dbConfig.updateStrategy ?? 'one';
  const entityType = (dbConfig.entityType ?? 'product').trim().toLowerCase();
  const configuredCollection = queryConfig.collection?.trim() ?? '';
  const configuredCollectionKey = configuredCollection.toLowerCase();
  const forceCollectionUpdate =
    configuredCollection.length > 0 &&
    !['product', 'products', 'note', 'notes'].includes(configuredCollectionKey);
  const shouldUseEntityUpdate =
    !forceCollectionUpdate && (entityType === 'product' || entityType === 'note');
  const idField = dbConfig.idField ?? 'entityId';
  const entityId = resolveEntityIdFromInputs(
    resolvedInputs,
    idField,
    simulationEntityType,
    simulationEntityId
  );
  const localizedParameterMergeConfig = resolveLocalizedParameterMergeConfig(dbConfig);
  const parameterTargetPath =
    normalizeNonEmptyString(dbConfig.parameterInferenceGuard?.targetPath) ??
    localizedParameterMergeConfig?.targetPath ??
    'parameters';

  if (updatePayloadMode === 'mapping') {
    const mappingResult = resolveDatabaseUpdateMappings({
      dbConfig,
      nodeInputPorts,
      resolvedInputs,
      parameterTargetPath,
    });
    const unresolvedSourcePorts = Array.from(mappingResult.unresolvedSourcePorts);
    let updates: Record<string, unknown> = mappingResult.updates;
    const writePolicyResult = applyTopLevelWriteValuePolicies({ updates, dbConfig });
    updates = writePolicyResult.updates;
    let localizedParameterMergeMeta: Record<string, unknown> | undefined;

    if (
      localizedParameterMergeConfig &&
      Object.prototype.hasOwnProperty.call(updates, localizedParameterMergeConfig.targetPath)
    ) {
      await ensureExistingParameterTemplateContext(localizedParameterMergeConfig.targetPath, {
        forceHydrateRichParameters: true,
      });
      const localizedMergeResult = mergeLocalizedParameterUpdates({
        targetPath: localizedParameterMergeConfig.targetPath,
        updates,
        templateInputs,
        languageCode: localizedParameterMergeConfig.languageCode,
        requireFullCoverage: localizedParameterMergeConfig.requireFullCoverage,
      });
      if (localizedMergeResult.applied) {
        updates = localizedMergeResult.updates;
        localizedParameterMergeMeta = localizedMergeResult.meta;
      }
    }

    const writeValuePoliciesMeta =
      dbConfig.skipEmpty || dbConfig.trimStrings
        ? {
            skipEmpty: dbConfig.skipEmpty === true,
            trimStrings: dbConfig.trimStrings === true,
            changedTargets: writePolicyResult.changedTargets,
          }
        : undefined;

    if (Object.keys(updates).length === 0) {
      if (localizedParameterMergeConfig || writeValuePoliciesMeta) {
        return createNoSafeUpdatesOutput({
          error:
            'Database update blocked. No safe write candidates were resolved after applying the configured write policies.',
          aiPrompt,
          entityType,
          collection: configuredCollection,
          filter: entityId ? { id: entityId } : null,
          unresolvedSourcePorts,
          localizedParameterMergeMeta,
          reportAiPathsError,
          toast,
          nodeId: node.id,
          mode: 'mapping',
        });
      }
      return {
        ...prevOutputs,
        result: null,
        bundle: {
          skipped: true,
          reason: 'no_mapping_updates',
          unresolvedSourcePorts,
        },
        debugPayload: {
          mode: 'mapping',
          updateStrategy,
          entityType,
          collection: configuredCollection || null,
          idField,
          entityId,
          mappings: mappingResult.mappings,
          updates,
          unresolvedSourcePorts,
        },
        aiPrompt,
      };
    }

    const debugPayload: Record<string, unknown> = {
      mode: 'mapping',
      updateStrategy,
      entityType,
      collection: configuredCollection || null,
      idField,
      entityId,
      mappings: mappingResult.mappings,
      updates,
      unresolvedSourcePorts,
      ...(localizedParameterMergeMeta
        ? { localizedParameterMerge: localizedParameterMergeMeta }
        : {}),
      ...(writeValuePoliciesMeta ? { writeValuePolicies: writeValuePoliciesMeta } : {}),
    };

    const executionResult = await executeDatabaseUpdate({
      nodeId: node.id,
      executed,
      reportAiPathsError,
      toast,
      dryRun,
      resolvedInputs,
      dbConfig,
      queryConfig,
      updates,
      updateStrategy,
      entityType,
      shouldUseEntityUpdate,
      entityId,
      configuredCollection,
      updatePayloadMode: 'mapping',
    });

    if (executionResult.skipped) {
      return {
        ...prevOutputs,
        result: null,
        bundle: {
          error: 'Database update was skipped.',
          guardrail: 'update-skipped',
        },
        debugPayload,
        aiPrompt,
      };
    }

    return {
      content_en: (nodeInputs['content_en'] as string | undefined) ?? '',
      bundle: {
        updates,
        ...(executionResult.executionMeta ?? {}),
        ...(executionResult.writeOutcome ? { writeOutcome: executionResult.writeOutcome } : {}),
      },
      result: executionResult.updateResult,
      debugPayload: {
        ...debugPayload,
        execution: executionResult.executionMeta,
      },
      ...(executionResult.writeOutcome ? { writeOutcome: executionResult.writeOutcome } : {}),
      aiPrompt,
    };
  }

  const updateTemplate = dbConfig.updateTemplate?.trim() ?? '';
  if (!updateTemplate) {
    const error = 'No explicit update document provided.';
    reportAiPathsError(
      new Error(error),
      {
        action: 'dbUpdateGuardrail',
        nodeId: node.id,
        guardrail: 'missing_update_template',
      },
      'Database update blocked:'
    );
    toast(error, { variant: 'error' });
    return {
      result: null,
      bundle: {
        error,
        guardrail: 'missing-update-template',
      },
      debugPayload: {
        mode: 'custom',
        updateStrategy,
        entityType,
        collection: configuredCollection || null,
        idField,
        entityId,
      },
      aiPrompt,
    };
  }

  const currentValueRaw: unknown =
    templateInputs['value'] ?? templateInputs['result'] ?? templateInputs['jobId'] ?? '';
  const currentValue = Array.isArray(currentValueRaw)
    ? (currentValueRaw as unknown[])[0]
    : currentValueRaw;
  const templateGuardrail = resolveWriteTemplateGuardrail({
    templates: [
      {
        name: 'queryTemplate',
        template: queryConfig.queryTemplate ?? '',
      },
      {
        name: 'updateTemplate',
        template: updateTemplate,
      },
    ],
    templateContext: templateInputs,
    currentValue,
    allowEmptyArrays: true,
  });
  if (!templateGuardrail.ok) {
    const hasMappingConfig = Array.isArray(dbConfig.mappings) && dbConfig.mappings.length > 0;
    if (hasMappingConfig) {
      const problemRoots = [
        ...new Set([
          ...(templateGuardrail.guardrailMeta.missingRoots ?? []),
          ...(templateGuardrail.guardrailMeta.emptyRoots ?? []),
          ...(templateGuardrail.guardrailMeta.unparseableRoots ?? []),
        ]),
      ];
      const rootHint =
        problemRoots.length > 0
          ? ` (unresolved port${problemRoots.length > 1 ? 's' : ''}: ${problemRoots.join(', ')})`
          : '';
      const fallbackWarning =
        `Update template has unresolved tokens${rootHint} — falling back to mapping rows automatically. ` +
        'To fix permanently: set Update Payload Mode to "mapping" on the Database node so it always uses the configured mapping rows.';
      toast(fallbackWarning, { variant: 'warning' });
      reportAiPathsError(
        new Error(fallbackWarning),
        {
          action: 'dbUpdateTemplateFallback',
          nodeId: node.id,
          guardrailMeta: templateGuardrail.guardrailMeta,
        },
        'Database update template fallback to mapping mode:'
      );
      return handleDatabaseUpdateOperation({
        node,
        nodeInputs,
        prevOutputs,
        executed,
        reportAiPathsError,
        toast,
        simulationEntityType,
        simulationEntityId,
        resolvedInputs,
        nodeInputPorts,
        dbConfig: { ...dbConfig, updatePayloadMode: 'mapping' },
        queryConfig,
        dryRun,
        templateInputs,
        aiPrompt,
        ensureExistingParameterTemplateContext,
      });
    }
    const missingRoots = templateGuardrail.guardrailMeta.missingRoots ?? [];
    const portFix =
      missingRoots.length > 0
        ? `Fix: connect port${missingRoots.length > 1 ? 's' : ''} "${missingRoots.join('", "')}" to the Database node input, or add mapping rows and set Update Payload Mode to "mapping".`
        : 'Fix: connect all referenced input ports to the Database node, or add mapping rows and set Update Payload Mode to "mapping".';
    const error = `${templateGuardrail.message} ${portFix}`;
    reportAiPathsError(
      new Error(error),
      {
        action: 'dbUpdateTemplate',
        nodeId: node.id,
        guardrailMeta: templateGuardrail.guardrailMeta,
      },
      'Database update blocked:'
    );
    toast(error, { variant: 'error' });
    return createWriteTemplateGuardrailOutput({
      aiPrompt,
      message: error,
      guardrailMeta: templateGuardrail.guardrailMeta,
    });
  }

  const renderedUpdate = renderJsonTemplate(updateTemplate, templateInputs, currentValue);
  const parsedUpdate = parseJsonSafe(renderedUpdate);
  if (!parsedUpdate || (typeof parsedUpdate !== 'object' && !Array.isArray(parsedUpdate))) {
    const error = 'Update template must be valid JSON.';
    toast(error, { variant: 'error' });
    return {
      result: null,
      bundle: { error: 'Invalid update template' },
      debugPayload: {
        mode: 'custom',
        updateStrategy,
        collection: configuredCollection || null,
        updateTemplate,
      },
      aiPrompt,
    };
  }

  const renderedFilterPayload = buildDbQueryPayload(templateInputs, queryConfig);
  const customFilter = isObjectRecord(renderedFilterPayload.filter)
    ? renderedFilterPayload.filter
    : {};
  if (Object.keys(customFilter).length === 0) {
    const error = 'No explicit update filter provided.';
    reportAiPathsError(
      new Error(error),
      {
        action: 'dbUpdateGuardrail',
        nodeId: node.id,
        guardrail: 'missing_query_filter',
      },
      'Database update blocked:'
    );
    toast(error, { variant: 'error' });
    return {
      result: null,
      bundle: {
        error,
        guardrail: 'missing-query-filter',
      },
      debugPayload: {
        mode: 'custom',
        updateStrategy,
        entityType,
        collection: configuredCollection || null,
        idField,
        entityId,
      },
      aiPrompt,
    };
  }

  let customUpdateDoc: unknown = parsedUpdate;
  const extractUpdates = (value: unknown): Record<string, unknown> => {
    if (!isObjectRecord(value)) return {};
    const setDoc = value['$set'];
    if (isObjectRecord(setDoc)) return setDoc;
    const hasOperator = Object.keys(value).some((key: string): boolean => key.startsWith('$'));
    if (hasOperator) return {};
    return value;
  };
  let updates: Record<string, unknown> = extractUpdates(customUpdateDoc);
  const writePolicyResult = applyTopLevelWriteValuePolicies({ updates, dbConfig });
  updates = writePolicyResult.updates;
  writePolicyResult.changedTargets.forEach((targetPath: string) => {
    customUpdateDoc = patchTargetPathInUpdateDoc(customUpdateDoc, targetPath, updates);
  });
  let localizedParameterMergeMeta: Record<string, unknown> | undefined;

  if (
    localizedParameterMergeConfig &&
    Object.prototype.hasOwnProperty.call(updates, localizedParameterMergeConfig.targetPath)
  ) {
    await ensureExistingParameterTemplateContext(localizedParameterMergeConfig.targetPath, {
      forceHydrateRichParameters: true,
    });
    const localizedMergeResult = mergeLocalizedParameterUpdates({
      targetPath: localizedParameterMergeConfig.targetPath,
      updates,
      templateInputs,
      languageCode: localizedParameterMergeConfig.languageCode,
      requireFullCoverage: localizedParameterMergeConfig.requireFullCoverage,
    });
    if (localizedMergeResult.applied) {
      updates = localizedMergeResult.updates;
      localizedParameterMergeMeta = localizedMergeResult.meta;
      customUpdateDoc = patchTargetPathInUpdateDoc(
        customUpdateDoc,
        localizedParameterMergeConfig.targetPath,
        updates
      );
    }
  }

  const writeValuePoliciesMeta =
    dbConfig.skipEmpty || dbConfig.trimStrings
      ? {
          skipEmpty: dbConfig.skipEmpty === true,
          trimStrings: dbConfig.trimStrings === true,
          changedTargets: writePolicyResult.changedTargets,
        }
      : undefined;

  if (Object.keys(updates).length === 0 && (localizedParameterMergeConfig || writeValuePoliciesMeta)) {
    return createNoSafeUpdatesOutput({
      error:
        'Database update blocked. No safe write candidates were resolved after applying the configured write policies.',
      aiPrompt,
      entityType,
      collection: configuredCollection,
      filter: customFilter,
      localizedParameterMergeMeta,
      reportAiPathsError,
      toast,
      nodeId: node.id,
      mode: 'custom',
    });
  }

  const debugPayload: Record<string, unknown> = {
    mode: 'custom',
    updateStrategy,
    entityType,
    collection: configuredCollection || null,
    forceCollectionUpdate,
    idField,
    entityId,
    filter: customFilter,
    updateDoc: customUpdateDoc,
    queryTemplate: queryConfig.queryTemplate ?? '',
    updateTemplate: dbConfig.updateTemplate ?? '',
    ...(localizedParameterMergeMeta
      ? { localizedParameterMerge: localizedParameterMergeMeta }
      : {}),
    ...(writeValuePoliciesMeta ? { writeValuePolicies: writeValuePoliciesMeta } : {}),
  };

  const executionResult = await executeDatabaseUpdate({
    nodeId: node.id,
    executed,
    reportAiPathsError,
    toast,
    dryRun,
    resolvedInputs,
    dbConfig,
    queryConfig,
    updates: {},
    updateStrategy,
    entityType,
    shouldUseEntityUpdate,
    entityId,
    configuredCollection,
    updatePayloadMode: 'custom',
    customFilter,
    customUpdateDoc,
  });
  if (executionResult.skipped) {
    return {
      ...prevOutputs,
      result: null,
      bundle: {
        error: 'Database update was skipped.',
        guardrail: 'update-skipped',
      },
      debugPayload,
      aiPrompt,
    };
  }

  debugPayload['execution'] = executionResult.executionMeta;

  const updateResult: unknown = executionResult.updateResult;
  const customContentEnValue = resolveCustomContentEnValue(customUpdateDoc);

  return {
    content_en: customContentEnValue ?? (nodeInputs['content_en'] as string | undefined) ?? '',
    bundle: {
      filter: customFilter,
      update: customUpdateDoc,
      ...(executionResult.executionMeta ?? {}),
      ...(executionResult.writeOutcome ? { writeOutcome: executionResult.writeOutcome } : {}),
    },
    result: updateResult,
    debugPayload,
    ...(executionResult.writeOutcome ? { writeOutcome: executionResult.writeOutcome } : {}),
    aiPrompt,
  };
}

import type {
  DatabaseConfig,
  DatabaseGuardrailMeta,
  DatabaseOperation,
  DatabaseWriteOutcome,
  DatabaseWriteZeroAffectedPolicy,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths';

import {
  normalizeJsonLikeValue,
  type JsonIntegrityParseState,
  type JsonIntegrityPolicy,
} from './json-integrity';

type WriteTemplateSource = {
  name: string;
  template: string;
};

type WriteTemplateParseDiagnostic = {
  port?: string;
  token: string;
  rawType: string;
  parseState: JsonIntegrityParseState;
  repairApplied: boolean;
  parseError?: string;
  truncationDetected?: boolean;
  repairSteps?: string[];
};

type WriteTemplateTokenDiagnostic = {
  template: string;
  token: string;
  root: string;
  reason: 'missing' | 'empty' | 'unparseable';
};

type WriteTemplateInspection = {
  missing: WriteTemplateTokenDiagnostic[];
  empty: WriteTemplateTokenDiagnostic[];
  unparseable: WriteTemplateTokenDiagnostic[];
  parseDiagnostics: WriteTemplateParseDiagnostic[];
};

type ResolveWriteTemplateGuardrailInput = {
  templates: WriteTemplateSource[];
  templateContext: Record<string, unknown>;
  currentValue: unknown;
  allowEmptyArrays?: boolean;
};

type ResolveWriteTemplateGuardrailResult =
  | { ok: true }
  | {
      ok: false;
      message: string;
      guardrailMeta: DatabaseGuardrailMeta & {
        code: 'write-template-values';
        severity: 'error';
        details: WriteTemplateTokenDiagnostic[];
      };
    };

type ReadNumericCounters = {
  matchedCount: number | null;
  modifiedCount: number | null;
  deletedCount: number | null;
  insertedCount: number | null;
  upsertedCount: number | null;
  upsertedId: unknown;
  count: number | null;
};

type EvaluateWriteOutcomeInput = {
  operation: DatabaseOperation | string;
  action?: string | null;
  result: unknown;
  policy: DatabaseWriteZeroAffectedPolicy;
};

type EvaluateWriteOutcomeResult = {
  writeOutcome: DatabaseWriteOutcome;
  isZeroAffected: boolean;
};

const TEMPLATE_TOKEN_REGEX: RegExp = /{{\s*([^}]+)\s*}}|\[\s*([A-Za-z0-9_.$:-]+)\s*\]/g;

const SYSTEM_ROOT_PREFIXES = ['Date:', 'DB Provider:', 'Collection:'];

const toRecord = (value: unknown): Record<string, unknown> | null =>
  value && typeof value === 'object' && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : null;

const normalizeOperation = (
  operation: DatabaseOperation | string
): DatabaseOperation | 'unknown' => {
  if (
    operation === 'query' ||
    operation === 'update' ||
    operation === 'insert' ||
    operation === 'delete'
  ) {
    return operation;
  }
  return 'unknown';
};

const normalizeTokenRoot = (token: string): string => {
  const rootCandidate: string = token.split('.')[0]?.trim() ?? '';
  return rootCandidate.replace(/\[[^\]]*\]/g, '').trim();
};

const isSystemRoot = (root: string): boolean =>
  SYSTEM_ROOT_PREFIXES.some((prefix: string): boolean => root.startsWith(prefix));

const isEmptyTemplateValue = (value: unknown, allowEmptyArrays = false): boolean => {
  if (value === undefined || value === null) return true;
  if (typeof value === 'string') return value.trim().length === 0;
  if (Array.isArray(value)) return allowEmptyArrays ? false : value.length === 0;
  if (typeof value === 'object') return Object.keys(value as Record<string, unknown>).length === 0;
  return false;
};

type PathReadResult = {
  value: unknown;
  parseDiagnostic?: {
    rawType: string;
    parseState: JsonIntegrityParseState;
    repairApplied: boolean;
    parseError?: string;
    truncationDetected?: boolean;
    repairSteps?: string[];
  };
};

const readByPath = (source: unknown, path: string, policy: JsonIntegrityPolicy): PathReadResult => {
  const normalized = path
    .replace(/\[(['"]?)([A-Za-z0-9_$-]+)\1\]/g, '.$2')
    .replace(/\[(\d+)\]/g, '.$1')
    .split('.')
    .map((segment: string): string => segment.trim())
    .filter(Boolean);
  if (normalized.length === 0) return { value: source };

  const readBySegments = (cursor: unknown, index: number): PathReadResult => {
    if (cursor === null || cursor === undefined) return { value: undefined };
    if (index >= normalized.length) return { value: cursor };
    const segment = normalized[index];
    if (segment === undefined) return { value: undefined };
    const normalizedCursorResult = normalizeJsonLikeValue(cursor, policy);
    const normalizedCursor = normalizedCursorResult.value;
    const parseDiagnostic =
      normalizedCursorResult.state === 'repaired' || normalizedCursorResult.state === 'unparseable'
        ? {
          rawType: normalizedCursorResult.diagnostic.rawType,
          parseState: normalizedCursorResult.diagnostic.parseState,
          repairApplied: normalizedCursorResult.diagnostic.repairApplied,
          parseError: normalizedCursorResult.diagnostic.parseError,
          truncationDetected: normalizedCursorResult.diagnostic.truncationDetected,
          repairSteps: normalizedCursorResult.diagnostic.repairSteps,
        }
        : undefined;
    if (normalizedCursorResult.state === 'unparseable') {
      return {
        value: undefined,
        ...(parseDiagnostic ? { parseDiagnostic } : {}),
      };
    }

    if (Array.isArray(normalizedCursor)) {
      const numericIndex = Number(segment);
      if (Number.isInteger(numericIndex)) {
        if (numericIndex < 0 || numericIndex >= normalizedCursor.length) {
          return { value: undefined };
        }
        const indexed = readBySegments(normalizedCursor[numericIndex], index + 1);
        if (indexed.parseDiagnostic) return indexed;
        return parseDiagnostic ? { ...indexed, parseDiagnostic } : indexed;
      }
      let firstDiagnostic: PathReadResult['parseDiagnostic'] | undefined;
      for (const item of normalizedCursor) {
        const candidate = readBySegments(item, index);
        if (candidate.value !== undefined) {
          if (candidate.parseDiagnostic) return candidate;
          return parseDiagnostic ? { ...candidate, parseDiagnostic } : candidate;
        }
        if (!firstDiagnostic && candidate.parseDiagnostic) {
          firstDiagnostic = candidate.parseDiagnostic;
        }
      }
      return firstDiagnostic
        ? { value: undefined, parseDiagnostic: firstDiagnostic }
        : parseDiagnostic
          ? { value: undefined, parseDiagnostic }
          : { value: undefined };
    }

    const record = toRecord(normalizedCursor);
    if (!record) {
      return parseDiagnostic ? { value: undefined, parseDiagnostic } : { value: undefined };
    }
    const nested = readBySegments(record[segment], index + 1);
    if (nested.parseDiagnostic) return nested;
    return parseDiagnostic ? { ...nested, parseDiagnostic } : nested;
  };

  return readBySegments(source, 0);
};

type ResolvedTokenValue = {
  value: unknown;
  parseDiagnostic?: WriteTemplateParseDiagnostic;
};

const resolveTokenValue = (
  token: string,
  templateContext: Record<string, unknown>,
  currentValue: unknown,
  policy: JsonIntegrityPolicy
): ResolvedTokenValue => {
  const trimmedToken = token.trim();
  if (!trimmedToken) return { value: undefined };
  if (trimmedToken === 'current') return { value: currentValue };
  if (trimmedToken === 'value') {
    return {
      value: templateContext['value'] !== undefined ? templateContext['value'] : currentValue,
    };
  }
  if (trimmedToken.startsWith('value.')) {
    const nestedPath = trimmedToken.slice('value.'.length);
    const resolvedFromContext = readByPath(templateContext, trimmedToken, policy);
    if (resolvedFromContext.value !== undefined) {
      return {
        value: resolvedFromContext.value,
        ...(resolvedFromContext.parseDiagnostic
          ? {
              parseDiagnostic: {
                port: normalizeTokenRoot(trimmedToken) || undefined,
                token: trimmedToken,
                rawType: resolvedFromContext.parseDiagnostic.rawType,
                parseState: resolvedFromContext.parseDiagnostic.parseState,
                repairApplied: resolvedFromContext.parseDiagnostic.repairApplied,
                parseError: resolvedFromContext.parseDiagnostic.parseError,
                truncationDetected: resolvedFromContext.parseDiagnostic.truncationDetected,
                repairSteps: resolvedFromContext.parseDiagnostic.repairSteps,
              },
            }
          : {}),
      };
    }
    const resolvedFromCurrent = readByPath(currentValue, nestedPath, policy);
    return {
      value: resolvedFromCurrent.value,
      ...(resolvedFromCurrent.parseDiagnostic
        ? {
            parseDiagnostic: {
              token: trimmedToken,
              rawType: resolvedFromCurrent.parseDiagnostic.rawType,
              parseState: resolvedFromCurrent.parseDiagnostic.parseState,
              repairApplied: resolvedFromCurrent.parseDiagnostic.repairApplied,
              parseError: resolvedFromCurrent.parseDiagnostic.parseError,
              truncationDetected: resolvedFromCurrent.parseDiagnostic.truncationDetected,
              repairSteps: resolvedFromCurrent.parseDiagnostic.repairSteps,
            },
          }
        : {}),
    };
  }
  if (trimmedToken.startsWith('current.')) {
    const resolved = readByPath(currentValue, trimmedToken.slice('current.'.length), policy);
    return {
      value: resolved.value,
      ...(resolved.parseDiagnostic
        ? {
          parseDiagnostic: {
            token: trimmedToken,
            rawType: resolved.parseDiagnostic.rawType,
            parseState: resolved.parseDiagnostic.parseState,
            repairApplied: resolved.parseDiagnostic.repairApplied,
            parseError: resolved.parseDiagnostic.parseError,
            truncationDetected: resolved.parseDiagnostic.truncationDetected,
            repairSteps: resolved.parseDiagnostic.repairSteps,
          },
        }
        : {}),
    };
  }
  if (Object.prototype.hasOwnProperty.call(templateContext, trimmedToken)) {
    return {
      value: templateContext[trimmedToken],
    };
  }
  const resolved = readByPath(templateContext, trimmedToken, policy);
  return {
    value: resolved.value,
    ...(resolved.parseDiagnostic
      ? {
        parseDiagnostic: {
          port: normalizeTokenRoot(trimmedToken) || undefined,
          token: trimmedToken,
          rawType: resolved.parseDiagnostic.rawType,
          parseState: resolved.parseDiagnostic.parseState,
          repairApplied: resolved.parseDiagnostic.repairApplied,
          parseError: resolved.parseDiagnostic.parseError,
          truncationDetected: resolved.parseDiagnostic.truncationDetected,
          repairSteps: resolved.parseDiagnostic.repairSteps,
        },
      }
      : {}),
  };
};

const extractTemplateTokens = (template: string): string[] => {
  const tokens: string[] = [];
  TEMPLATE_TOKEN_REGEX.lastIndex = 0;
  let match: RegExpExecArray | null = TEMPLATE_TOKEN_REGEX.exec(template);
  while (match) {
    const token = (match[1] ?? match[2] ?? '').trim();
    if (token) {
      tokens.push(token);
    }
    match = TEMPLATE_TOKEN_REGEX.exec(template);
  }
  return tokens;
};

const inspectWriteTemplates = ({
  templates,
  templateContext,
  currentValue,
  allowEmptyArrays = false,
}: ResolveWriteTemplateGuardrailInput): WriteTemplateInspection => {
  const missing: WriteTemplateTokenDiagnostic[] = [];
  const empty: WriteTemplateTokenDiagnostic[] = [];
  const unparseable: WriteTemplateTokenDiagnostic[] = [];
  const parseDiagnostics: WriteTemplateParseDiagnostic[] = [];
  const policy: JsonIntegrityPolicy = 'repair';

  templates.forEach(({ name, template }: WriteTemplateSource): void => {
    if (!template.trim()) return;
    const tokens = extractTemplateTokens(template);
    const seen = new Set<string>();
    tokens.forEach((token: string): void => {
      const key = `${name}:${token}`;
      if (seen.has(key)) return;
      seen.add(key);
      const root = normalizeTokenRoot(token);
      if (!root || isSystemRoot(root)) return;
      const resolved = resolveTokenValue(token, templateContext, currentValue, policy);
      const value = resolved.value;
      if (resolved.parseDiagnostic) {
        parseDiagnostics.push({
          ...resolved.parseDiagnostic,
          token,
          ...(resolved.parseDiagnostic.port ? {} : { port: root }),
        });
      }
      if (resolved.parseDiagnostic?.parseState === 'unparseable') {
        unparseable.push({
          template: name,
          token,
          root,
          reason: 'unparseable',
        });
        return;
      }
      if (value === undefined) {
        missing.push({
          template: name,
          token,
          root,
          reason: 'missing',
        });
        return;
      }
      if (isEmptyTemplateValue(value, allowEmptyArrays)) {
        empty.push({
          template: name,
          token,
          root,
          reason: 'empty',
        });
      }
    });
  });

  return { missing, empty, unparseable, parseDiagnostics };
};

const formatTokenList = (diagnostics: WriteTemplateTokenDiagnostic[]): string =>
  diagnostics.map((entry: WriteTemplateTokenDiagnostic): string => `{{${entry.token}}}`).join(', ');

const dedupeValues = (values: string[]): string[] =>
  Array.from(new Set(values.filter((value: string): boolean => value.trim().length > 0)));

const buildLikelyCauseFragment = (diagnostics: WriteTemplateParseDiagnostic[]): string | null => {
  const truncationRoots = Array.from(
    new Set(
      diagnostics
        .filter(
          (diagnostic: WriteTemplateParseDiagnostic): boolean =>
            diagnostic.parseState === 'unparseable' && diagnostic.truncationDetected === true
        )
        .map(
          (diagnostic: WriteTemplateParseDiagnostic): string =>
            diagnostic.port?.trim() || normalizeTokenRoot(diagnostic.token)
        )
        .filter((value: string): boolean => value.length > 0)
    )
  );
  if (truncationRoots.length === 0) return null;
  const quotedRoots = truncationRoots.map((root: string): string => `"${root}"`);
  return `likely cause: truncated JSON on root ${quotedRoots.join(', ')}`;
};

const readNumericField = (payload: Record<string, unknown>, field: string): number | null => {
  const value = payload[field];
  if (typeof value === 'number' && Number.isFinite(value)) {
    return value;
  }
  return null;
};

const readWriteCounters = (result: unknown): ReadNumericCounters => {
  const payload = toRecord(result) ?? {};
  return {
    matchedCount: readNumericField(payload, 'matchedCount'),
    modifiedCount: readNumericField(payload, 'modifiedCount'),
    deletedCount: readNumericField(payload, 'deletedCount'),
    insertedCount: readNumericField(payload, 'insertedCount'),
    upsertedCount: readNumericField(payload, 'upsertedCount'),
    upsertedId: payload['upsertedId'],
    count: readNumericField(payload, 'count'),
  };
};

const resolveAffectedCount = (
  operation: DatabaseOperation | 'unknown',
  action: string | null | undefined,
  counters: ReadNumericCounters
): { affectedCount: number | null; isZeroAffected: boolean } => {
  const actionLower = action?.toLowerCase() ?? '';
  const treatAsInsert =
    operation === 'insert' || actionLower.startsWith('insert') || actionLower.startsWith('create');
  if (treatAsInsert) {
    const affectedCount = counters.insertedCount ?? counters.count;
    return {
      affectedCount: affectedCount ?? null,
      isZeroAffected: affectedCount === 0,
    };
  }

  const treatAsDelete =
    operation === 'delete' || actionLower.startsWith('delete') || actionLower.includes('anddelete');
  if (treatAsDelete) {
    const affectedCount = counters.deletedCount ?? counters.count;
    return {
      affectedCount: affectedCount ?? null,
      isZeroAffected: affectedCount === 0,
    };
  }

  const treatAsUpdate =
    operation === 'update' ||
    actionLower.startsWith('update') ||
    actionLower.includes('andupdate') ||
    actionLower.startsWith('replace');
  if (treatAsUpdate) {
    const upsertedCount =
      counters.upsertedCount ?? (counters.upsertedId !== null && counters.upsertedId !== undefined ? 1 : null);
    if (upsertedCount !== null && upsertedCount > 0) {
      return {
        affectedCount: upsertedCount,
        isZeroAffected: false,
      };
    }
    if (counters.modifiedCount !== null) {
      return {
        affectedCount: counters.modifiedCount,
        isZeroAffected: counters.modifiedCount === 0,
      };
    }
    if (counters.matchedCount !== null) {
      return {
        affectedCount: counters.matchedCount,
        isZeroAffected: counters.matchedCount === 0,
      };
    }
    const fallback = counters.count;
    return {
      affectedCount: fallback,
      isZeroAffected: fallback === 0,
    };
  }

  return { affectedCount: null, isZeroAffected: false };
};

export const resolveWriteOutcomePolicy = (
  dbConfig: DatabaseConfig
): DatabaseWriteZeroAffectedPolicy =>
  dbConfig.writeOutcomePolicy?.onZeroAffected === 'warn' ? 'warn' : 'fail';

export const resolveWriteTemplateGuardrail = ({
  templates,
  templateContext,
  currentValue,
  allowEmptyArrays,
}: ResolveWriteTemplateGuardrailInput): ResolveWriteTemplateGuardrailResult => {
  const inspection = inspectWriteTemplates({
    templates,
    templateContext,
    currentValue,
    allowEmptyArrays,
  });
  if (
    inspection.missing.length === 0 &&
    inspection.empty.length === 0 &&
    inspection.unparseable.length === 0
  ) {
    return { ok: true };
  }

  const missingTokens = dedupeValues(
    inspection.missing.map((entry: WriteTemplateTokenDiagnostic): string => entry.token)
  );
  const emptyTokens = dedupeValues(
    inspection.empty.map((entry: WriteTemplateTokenDiagnostic): string => entry.token)
  );
  const unparseableTokens = dedupeValues(
    inspection.unparseable.map((entry: WriteTemplateTokenDiagnostic): string => entry.token)
  );
  const missingRoots = dedupeValues(
    inspection.missing.map((entry: WriteTemplateTokenDiagnostic): string => entry.root)
  );
  const emptyRoots = dedupeValues(
    inspection.empty.map((entry: WriteTemplateTokenDiagnostic): string => entry.root)
  );
  const unparseableRoots = dedupeValues(
    inspection.unparseable.map((entry: WriteTemplateTokenDiagnostic): string => entry.root)
  );
  const templateNames = dedupeValues(
    [...inspection.missing, ...inspection.empty, ...inspection.unparseable].map(
      (entry: WriteTemplateTokenDiagnostic): string => entry.template
    )
  );

  const fragments: string[] = [];
  if (missingTokens.length > 0) {
    fragments.push(`missing tokens: ${formatTokenList(inspection.missing)}`);
  }
  if (emptyTokens.length > 0) {
    fragments.push(`empty tokens: ${formatTokenList(inspection.empty)}`);
  }
  if (unparseableTokens.length > 0) {
    fragments.push(`unparseable JSON tokens: ${formatTokenList(inspection.unparseable)}`);
  }
  const likelyCauseFragment = buildLikelyCauseFragment(inspection.parseDiagnostics);
  if (likelyCauseFragment) {
    fragments.push(likelyCauseFragment);
  }
  const message = `Database write blocked. Template inputs must be connected and non-empty (${fragments.join(
    '; '
  )}).`;

  const parseDiagnostics = Array.from(
    new Map(
      inspection.parseDiagnostics.map((diagnostic: WriteTemplateParseDiagnostic) => {
        const key = [
          diagnostic.token,
          diagnostic.port ?? '',
          diagnostic.rawType,
          diagnostic.parseState,
          diagnostic.repairApplied ? '1' : '0',
          diagnostic.parseError ?? '',
          diagnostic.truncationDetected ? '1' : '0',
          (diagnostic.repairSteps ?? []).join(','),
        ].join('|');
        return [key, diagnostic] as const;
      })
    ).values()
  );

  return {
    ok: false,
    message,
    guardrailMeta: {
      code: 'write-template-values',
      severity: 'error',
      message,
      templates: templateNames,
      missingTokens,
      emptyTokens,
      missingRoots,
      emptyRoots,
      unparseableTokens,
      unparseableRoots,
      parseDiagnostics,
      details: [...inspection.missing, ...inspection.empty, ...inspection.unparseable],
    },
  };
};

export const createWriteTemplateGuardrailOutput = (args: {
  aiPrompt: string;
  message: string;
  guardrailMeta: DatabaseGuardrailMeta;
}): RuntimePortValues => ({
  result: null,
  bundle: {
    error: args.message,
    guardrail: 'write-template-values',
    guardrailMeta: args.guardrailMeta,
  },
  guardrailMeta: args.guardrailMeta,
  writeOutcome: {
    status: 'failed',
    code: 'write_template_values',
    message: args.message,
    zeroAffected: false,
  } satisfies DatabaseWriteOutcome,
  aiPrompt: args.aiPrompt,
});

export const evaluateWriteOutcome = ({
  operation,
  action,
  result,
  policy,
}: EvaluateWriteOutcomeInput): EvaluateWriteOutcomeResult => {
  const normalizedOperation = normalizeOperation(operation);
  const counters = readWriteCounters(result);
  const { affectedCount, isZeroAffected } = resolveAffectedCount(
    normalizedOperation,
    action,
    counters
  );
  const actionLabel = action ? ` (${action})` : '';
  if (!isZeroAffected) {
    return {
      isZeroAffected: false,
      writeOutcome: {
        status: 'success',
        operation: normalizedOperation,
        ...(action ? { action } : {}),
        ...(affectedCount !== null ? { affectedCount } : {}),
        ...(counters.matchedCount !== null ? { matchedCount: counters.matchedCount } : {}),
        ...(counters.modifiedCount !== null ? { modifiedCount: counters.modifiedCount } : {}),
        ...(counters.deletedCount !== null ? { deletedCount: counters.deletedCount } : {}),
        ...(counters.insertedCount !== null ? { insertedCount: counters.insertedCount } : {}),
      },
    };
  }

  const status = policy === 'warn' ? 'warning' : 'failed';
  const message = `Database write affected 0 records for ${normalizedOperation}${actionLabel}.`;
  return {
    isZeroAffected: true,
    writeOutcome: {
      status,
      code: 'zero_affected',
      message,
      policyOnZeroAffected: policy,
      zeroAffected: true,
      operation: normalizedOperation,
      ...(action ? { action } : {}),
      ...(affectedCount !== null ? { affectedCount } : {}),
      ...(counters.matchedCount !== null ? { matchedCount: counters.matchedCount } : {}),
      ...(counters.modifiedCount !== null ? { modifiedCount: counters.modifiedCount } : {}),
      ...(counters.deletedCount !== null ? { deletedCount: counters.deletedCount } : {}),
      ...(counters.insertedCount !== null ? { insertedCount: counters.insertedCount } : {}),
    },
  };
};

import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { coerceInput } from '../../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


type FetcherSourceMode = 'live_context' | 'simulation_id' | 'live_then_simulation';
type FetcherResolvedSource = 'live_context' | 'simulation_id' | 'live_context_override';
type FetcherEntityState = {
  entityId: string | null;
  entityType: string | null;
  entity: Record<string, unknown> | null;
};
type FetcherResolvedState = FetcherEntityState & {
  sourceTag: 'trigger_fetcher' | 'simulation_fetcher';
  resolvedSource: FetcherResolvedSource;
};

const DEFAULT_FETCHER_SOURCE_MODE: FetcherSourceMode = 'live_context';
const ENTITY_OBJECT_CONTEXT_KEYS = ['entity', 'entityJson', 'product'] as const;

const readString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const normalizeEntityType = (value: unknown): string | null => {
  const raw = readString(value);
  if (!raw) return null;
  const normalized = raw.toLowerCase();
  if (normalized === 'products') return 'product';
  if (normalized === 'notes') return 'note';
  return normalized;
};

const readEntityIdFromContext = (
  context: Record<string, unknown> | null | undefined
): string | null => {
  if (!context) return null;
  return readString(context['entityId']) ?? readString(context['productId']) ?? null;
};

const readEntityTypeFromContext = (
  context: Record<string, unknown> | null | undefined
): string | null => {
  if (!context) return null;
  return normalizeEntityType(context['entityType']);
};

const readEntityObjectFromContext = (
  context: Record<string, unknown> | null | undefined
): Record<string, unknown> | null => {
  if (!context) return null;

  for (const key of ENTITY_OBJECT_CONTEXT_KEYS) {
    const candidate = context[key];
    if (isObjectRecord(candidate)) {
      return candidate;
    }
  }

  return null;
};

const readLocationPathnameFromContext = (
  context: Record<string, unknown> | null | undefined
): string | null => {
  if (!context) return null;
  const location = context['location'];
  if (!isObjectRecord(location)) return null;
  return readString(location['pathname']);
};

const readFetcherSourceMode = (node: NodeHandlerContext['node']): FetcherSourceMode => {
  const mode = node.config?.fetcher?.sourceMode;
  if (mode === 'live_context' || mode === 'simulation_id' || mode === 'live_then_simulation') {
    return mode;
  }
  return DEFAULT_FETCHER_SOURCE_MODE;
};

const shouldPreferLiveEntityOverSimulation = (args: {
  liveEntityId: string | null;
  liveEntityType: string | null;
  simulationEntityId: string | null;
  simulationEntityType: string | null;
  incomingContextRecord: Record<string, unknown> | null;
  triggerContextRecord: Record<string, unknown> | null;
}): boolean => {
  if (!args.liveEntityId || !args.liveEntityType) {
    return false;
  }

  if (
    args.liveEntityId === args.simulationEntityId &&
    args.liveEntityType === args.simulationEntityType
  ) {
    return false;
  }

  const pathname =
    readLocationPathnameFromContext(args.incomingContextRecord) ??
    readLocationPathnameFromContext(args.triggerContextRecord);
  if (pathname?.startsWith('/admin/ai-paths')) {
    return false;
  }

  return true;
};

const buildFetcherContextPayload = (args: {
  base: Record<string, unknown>;
  nodeTitle: string;
  nodeId: string;
  now: string;
  sourceTag: 'trigger_fetcher' | 'simulation_fetcher';
  activePathId: string | null;
  entity: Record<string, unknown> | null;
  entityId: string | null;
  entityType: string | null;
}): Record<string, unknown> => {
  const next: Record<string, unknown> = {
    ...args.base,
    source: args.nodeTitle,
    timestamp: args.now,
    pathId: args.activePathId,
    contextSource: args.sourceTag,
    fetcherNodeId: args.nodeId,
    fetcherNodeTitle: args.nodeTitle,
    entityId: args.entityId ?? args.base['entityId'],
    entityType: args.entityType ?? args.base['entityType'],
  };

  appendFetcherEntityAliases(next, args);

  return next;
};

const appendFetcherEntityAliases = (
  target: Record<string, unknown>,
  args: {
    entity: Record<string, unknown> | null;
    entityId: string | null;
    entityType: string | null;
  }
): void => {
  if (args.entityId && args.entityType === 'product') {
    target['productId'] = args.entityId;
  }
  if (!args.entity) {
    return;
  }

  target['entity'] = args.entity;
  target['entityJson'] = args.entity;
  if (args.entityType === 'product') {
    target['product'] = args.entity;
  }
};

const hydrateFetcherEntity = async (args: {
  entityId: string | null;
  entityType: string | null;
  fetchEntityCached: NodeHandlerContext['fetchEntityCached'];
  toast: NodeHandlerContext['toast'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  node: NodeHandlerContext['node'];
  sourceMode: FetcherSourceMode;
  phase: 'live' | 'simulation';
}): Promise<Record<string, unknown> | null> => {
  if (!args.entityId || !args.entityType) return null;

  try {
    const entity = await args.fetchEntityCached(args.entityType, args.entityId);
    if (!entity) {
      args.toast(`No ${args.entityType} data found for ID ${args.entityId}.`, {
        variant: 'error',
      });
    }
    return entity;
  } catch (error) {
    logClientError(error);
    args.reportAiPathsError(
      error,
      {
        service: 'ai-paths-runtime',
        nodeId: args.node.id,
        nodeType: args.node.type,
        fetcherSourceMode: args.sourceMode,
        entityId: args.entityId,
        entityType: args.entityType,
      },
      `Fetcher ${args.phase} hydration failed for ${args.entityType}:${args.entityId}`
    );
    return null;
  }
};

const resolveSimulationEntity = async (args: {
  simulationEntityId: string | null;
  simulationEntityType: string | null;
  fetchEntityCached: NodeHandlerContext['fetchEntityCached'];
  toast: NodeHandlerContext['toast'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  node: NodeHandlerContext['node'];
  sourceMode: FetcherSourceMode;
}): Promise<FetcherEntityState> => ({
  entityId: args.simulationEntityId,
  entityType: args.simulationEntityType,
  entity: await hydrateFetcherEntity({
    entityId: args.simulationEntityId,
    entityType: args.simulationEntityType,
    fetchEntityCached: args.fetchEntityCached,
    toast: args.toast,
    reportAiPathsError: args.reportAiPathsError,
    node: args.node,
    sourceMode: args.sourceMode,
    phase: 'simulation',
  }),
});

const resolveSimulationSourceSelection = async (args: {
  liveEntityId: string | null;
  liveEntityType: string | null;
  liveEntity: Record<string, unknown> | null;
  simulationEntityId: string | null;
  simulationEntityType: string | null;
  incomingContextRecord: Record<string, unknown> | null;
  triggerContextRecord: Record<string, unknown> | null;
  fetchEntityCached: NodeHandlerContext['fetchEntityCached'];
  toast: NodeHandlerContext['toast'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  node: NodeHandlerContext['node'];
  sourceMode: FetcherSourceMode;
}): Promise<FetcherResolvedState> => {
  if (
    shouldPreferLiveEntityOverSimulation({
      liveEntityId: args.liveEntityId,
      liveEntityType: args.liveEntityType,
      simulationEntityId: args.simulationEntityId,
      simulationEntityType: args.simulationEntityType,
      incomingContextRecord: args.incomingContextRecord,
      triggerContextRecord: args.triggerContextRecord,
    })
  ) {
    return {
      entityId: args.liveEntityId,
      entityType: args.liveEntityType,
      entity: args.liveEntity,
      sourceTag: 'trigger_fetcher',
      resolvedSource: 'live_context_override',
    };
  }

  if (!args.simulationEntityId) {
    throw new Error(
      `Fetcher ${args.node.title ?? args.node.id} is set to "Simulated entity by ID" but no entity ID is configured.`
    );
  }

  const simulated = await resolveSimulationEntity(args);
  return {
    ...simulated,
    sourceTag: 'simulation_fetcher',
    resolvedSource: 'simulation_id',
  };
};

const resolveLiveThenSimulationSourceSelection = async (args: {
  liveEntityId: string | null;
  liveEntityType: string | null;
  liveEntity: Record<string, unknown> | null;
  simulationEntityId: string | null;
  simulationEntityType: string | null;
  fetchEntityCached: NodeHandlerContext['fetchEntityCached'];
  toast: NodeHandlerContext['toast'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  node: NodeHandlerContext['node'];
  sourceMode: FetcherSourceMode;
}): Promise<FetcherResolvedState> => {
  const hasLiveReference = Boolean(args.liveEntityId && args.liveEntityType);
  if (!hasLiveReference && args.simulationEntityId) {
    const simulated = await resolveSimulationEntity(args);
    return {
      ...simulated,
      sourceTag: 'simulation_fetcher',
      resolvedSource: 'simulation_id',
    };
  }

  return {
    entityId: args.liveEntityId,
    entityType: args.liveEntityType,
    entity: args.liveEntity,
    sourceTag: 'trigger_fetcher',
    resolvedSource: 'live_context',
  };
};

const resolveFetcherSourceSelection = async (args: {
  sourceMode: FetcherSourceMode;
  liveEntityId: string | null;
  liveEntityType: string | null;
  liveEntity: Record<string, unknown> | null;
  simulationEntityId: string | null;
  simulationEntityType: string | null;
  incomingContextRecord: Record<string, unknown> | null;
  triggerContextRecord: Record<string, unknown> | null;
  fetchEntityCached: NodeHandlerContext['fetchEntityCached'];
  toast: NodeHandlerContext['toast'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  node: NodeHandlerContext['node'];
}): Promise<FetcherResolvedState> => {
  if (args.sourceMode === 'simulation_id') {
    return resolveSimulationSourceSelection(args);
  }
  if (args.sourceMode === 'live_then_simulation') {
    return resolveLiveThenSimulationSourceSelection(args);
  }
  return {
    entityId: args.liveEntityId,
    entityType: args.liveEntityType,
    entity: args.liveEntity,
    sourceTag: 'trigger_fetcher',
    resolvedSource: 'live_context',
  };
};

const hasResolvedFetcherEntity = (entity: unknown): boolean =>
  isObjectRecord(entity) && Object.keys(entity).length > 0;

const shouldFailMissingResolvedSimulationEntity = (args: {
  resolvedSource: FetcherResolvedSource;
  resolvedEntityId: string | null;
  resolvedEntityType: string | null;
  sourceMode: FetcherSourceMode;
  strictFlowMode: boolean;
}): boolean =>
  args.resolvedSource === 'simulation_id' &&
  Boolean(args.resolvedEntityId && args.resolvedEntityType) &&
  (args.sourceMode === 'simulation_id' || args.strictFlowMode);

const buildFetcherMetaPayload = (args: {
  base: Record<string, unknown>;
  now: string;
  sourceMode: FetcherSourceMode;
  resolvedSource: FetcherResolvedSource;
  resolvedEntityId: string | null;
  resolvedEntityType: string | null;
  activePathId: string | null;
}): Record<string, unknown> => ({
  ...args.base,
  fetchedAt: args.now,
  fetcherSourceMode: args.sourceMode,
  fetcherResolvedSource: args.resolvedSource,
  entityId: args.resolvedEntityId,
  entityType: args.resolvedEntityType,
  pathId: args.activePathId,
});

export const handleFetcher: NodeHandler = async ({
  node,
  nodeInputs,
  triggerContext,
  fetchEntityCached,
  reportAiPathsError,
  toast,
  activePathId,
  now,
  strictFlowMode,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  const triggerSignal = coerceInput(nodeInputs['trigger']);
  if (triggerSignal === undefined || triggerSignal === null || triggerSignal === false) {
    toast(
      `Fetcher "${node.title ?? node.id}" skipped: no trigger signal received. Check the edge from the Trigger node.`,
      { variant: 'warning' }
    );
    return {};
  }

  const sourceMode = readFetcherSourceMode(node);
  const triggerContextRecord = isObjectRecord(triggerContext) ? triggerContext : null;
  const incomingContext = coerceInput(nodeInputs['context']);
  const incomingContextRecord = isObjectRecord(incomingContext) ? incomingContext : null;
  const incomingMeta = coerceInput(nodeInputs['meta']);
  const incomingMetaRecord = isObjectRecord(incomingMeta) ? incomingMeta : {};

  const inputEntityId = readString(coerceInput(nodeInputs['entityId']));
  const inputEntityType = normalizeEntityType(coerceInput(nodeInputs['entityType']));

  const liveBaseContext = incomingContextRecord ?? triggerContextRecord ?? {};
  const liveEntityId =
    inputEntityId ??
    readEntityIdFromContext(incomingContextRecord) ??
    readEntityIdFromContext(triggerContextRecord);
  const liveEntityType =
    inputEntityType ??
    readEntityTypeFromContext(incomingContextRecord) ??
    readEntityTypeFromContext(triggerContextRecord) ??
    normalizeEntityType(node.config?.fetcher?.entityType);
  let liveEntity =
    readEntityObjectFromContext(incomingContextRecord) ??
    readEntityObjectFromContext(triggerContextRecord);

  if (!liveEntity && liveEntityId && liveEntityType) {
    liveEntity = await hydrateFetcherEntity({
      entityId: liveEntityId,
      entityType: liveEntityType,
      fetchEntityCached,
      toast,
      reportAiPathsError,
      node,
      sourceMode,
      phase: 'live',
    });
  }

  const configEntityId =
    readString(node.config?.fetcher?.entityId) ??
    readString(node.config?.fetcher?.productId) ??
    null;
  const configEntityType =
    normalizeEntityType(node.config?.fetcher?.entityType) ?? liveEntityType ?? 'product';

  const simulationEntityId = configEntityId ?? liveEntityId;
  const simulationEntityType = configEntityType;

  const resolved = await resolveFetcherSourceSelection({
    sourceMode,
    liveEntityId,
    liveEntityType,
    liveEntity,
    simulationEntityId,
    simulationEntityType,
    incomingContextRecord,
    triggerContextRecord,
    fetchEntityCached,
    toast,
    reportAiPathsError,
    node,
  });

  const resolvedEntityId = resolved.entityId;
  const resolvedEntityType = resolved.entityType;
  const resolvedEntity = resolved.entity;
  const sourceTag = resolved.sourceTag;
  const resolvedSource = resolved.resolvedSource;

  const hasResolvedEntity = hasResolvedFetcherEntity(resolvedEntity);
  const shouldFailMissingSimulationEntity = shouldFailMissingResolvedSimulationEntity({
    resolvedSource,
    resolvedEntityId,
    resolvedEntityType,
    sourceMode,
    strictFlowMode,
  });

  if (shouldFailMissingSimulationEntity && !hasResolvedEntity) {
    throw new Error(
      `Fetcher ${node.title ?? node.id} could not hydrate ${resolvedEntityType}:${resolvedEntityId}. Check fetcher simulation entity configuration.`
    );
  }

  const context = buildFetcherContextPayload({
    base: liveBaseContext,
    nodeTitle: node.title ?? node.id,
    nodeId: node.id,
    now,
    sourceTag,
    activePathId,
    entity: resolvedEntity,
    entityId: resolvedEntityId,
    entityType: resolvedEntityType,
  });

  const meta: Record<string, unknown> = {
    ...buildFetcherMetaPayload({
      base: incomingMetaRecord,
      now,
      sourceMode,
      resolvedSource,
      resolvedEntityId,
      resolvedEntityType,
      activePathId,
    }),
  };

  return {
    context,
    meta,
    entityId: resolvedEntityId,
    entityType: resolvedEntityType,
  };
};

import type { HttpConfig } from '@/shared/contracts/ai-paths';
import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import {
  fetchWithOutboundUrlPolicy,
  OutboundUrlPolicyError,
} from '@/shared/lib/security/outbound-url-policy';

import { getValueAtMappingPath, renderTemplate } from '../../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const handleHttp: NodeHandler = async ({
  node,
  nodeInputs,
  prevOutputs,
  executed,
  reportAiPathsError,
  abortSignal,
  sideEffectControl,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  if (executed.http.has(node.id)) return prevOutputs;

  const httpConfig: HttpConfig = node.config?.http ?? {
    url: '',
    method: 'GET',
    headers: '{}',
    bodyTemplate: '',
    responseMode: 'json',
    responsePath: '',
  };
  const resolvedUrl: string = renderTemplate(httpConfig.url ?? '', nodeInputs, '');
  if (!resolvedUrl) {
    return {
      value: null,
      bundle: { ok: false, status: 0, error: 'Missing URL' },
    };
  }
  let headers: Record<string, string> = {};
  try {
    headers = httpConfig.headers ? (JSON.parse(httpConfig.headers) as Record<string, string>) : {};
  } catch (error: unknown) {
    logClientError(error);
    reportAiPathsError(
      error,
      { action: 'parseHeaders', nodeId: node.id },
      'Invalid HTTP headers JSON:'
    );
  }
  let body: BodyInit | undefined = undefined;
  if (httpConfig.method !== 'GET' && httpConfig.method !== 'DELETE') {
    const renderedBody: string = httpConfig.bodyTemplate
      ? renderTemplate(httpConfig.bodyTemplate, nodeInputs, '')
      : '';
    if (renderedBody) {
      const trimmed: string = renderedBody.trim();
      if (
        (trimmed.startsWith('{') && trimmed.endsWith('}')) ||
        (trimmed.startsWith('[') && trimmed.endsWith(']'))
      ) {
        body = trimmed;
        if (!headers['Content-Type']) {
          headers['Content-Type'] = 'application/json';
        }
      } else {
        body = renderedBody;
        if (!headers['Content-Type']) {
          headers['Content-Type'] = 'text/plain';
        }
      }
    }
  }
  if (sideEffectControl?.idempotencyKey && !headers['Idempotency-Key']) {
    headers['Idempotency-Key'] = sideEffectControl.idempotencyKey;
  }
  const fetchInit: RequestInit = {
    method: httpConfig.method,
    headers,
  };
  if (body !== undefined) {
    fetchInit.body = body;
  }
  if (abortSignal) {
    fetchInit.signal = abortSignal;
  }
  try {
    const res: Response = await fetchWithOutboundUrlPolicy(resolvedUrl, {
      ...fetchInit,
      maxRedirects: 5,
    });
    let data: unknown = null;
    if (httpConfig.responseMode === 'status') {
      data = res.status;
    } else if (httpConfig.responseMode === 'text') {
      data = await res.text();
    } else {
      try {
        data = (await res.json()) as unknown;
      } catch (error) {
        logClientError(error);
        data = await res.text();
      }
    }
    let resolvedValue: unknown = data;
    if (httpConfig.responsePath) {
      const pathValue: unknown = getValueAtMappingPath(data, httpConfig.responsePath);
      resolvedValue = pathValue === undefined ? data : pathValue;
    }
    executed.http.add(node.id);
    return {
      value: resolvedValue,
      bundle: {
        ok: res.ok,
        status: res.status,
        url: resolvedUrl,
        data: resolvedValue,
      },
    };
  } catch (error: unknown) {
    logClientError(error);
    if (abortSignal?.aborted || (error instanceof Error && error.name === 'AbortError')) {
      throw error;
    }
    if (error instanceof OutboundUrlPolicyError) {
      reportAiPathsError(
        error,
        {
          action: 'httpOutboundPolicy',
          nodeId: node.id,
          url: resolvedUrl,
          reason: error.decision.reason,
          hostname: error.decision.hostname,
        },
        'Blocked outbound URL by policy:'
      );
      return {
        value: null,
        bundle: {
          ok: false,
          status: 0,
          url: resolvedUrl,
          route: 'blocked_outbound_url',
          error: `Blocked outbound URL (${error.decision.reason ?? 'policy_violation'})`,
        },
      };
    }
    reportAiPathsError(
      error,
      { action: 'httpFetch', url: resolvedUrl, nodeId: node.id },
      'HTTP fetch failed:'
    );
    return {
      value: null,
      bundle: {
        ok: false,
        status: 0,
        url: resolvedUrl,
        error: 'Fetch failed',
      },
    };
  }
};

import type { AiNode, Edge } from '@/shared/contracts/ai-paths';
import type { NodeHandler, NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';

import { coerceInput, safeStringify } from '../../utils';
import { buildPromptOutput } from '../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const handleNotification: NodeHandler = ({
  node,
  nodeInputs,
  prevOutputs,
  allInputs,
  edges,
  nodes,
  toast,
  reportAiPathsError,
  sideEffectControl,
}: NodeHandlerContext) => {
  if (sideEffectControl?.decision === 'skipped_policy') return prevOutputs;
  const hasMeaningfulValue = (value: unknown): boolean => {
    if (value === undefined || value === null) return false;
    if (typeof value === 'string') return value.trim().length > 0;
    if (Array.isArray(value)) return value.length > 0;
    if (typeof value === 'object') return Object.keys(value).length > 0;
    return true;
  };
  const nodeById = new Map<string, AiNode>();
  nodes.forEach((item: AiNode) => {
    nodeById.set(item.id, item);
  });
  let promptSourceNode: AiNode | null = null;
  for (const edge of edges) {
    if (edge.to !== node.id || edge.toPort !== 'prompt') continue;
    const fromNodeId = edge.from;
    if (!fromNodeId) continue;
    const fromNode = nodeById.get(fromNodeId);
    if (fromNode?.type === 'prompt') {
      promptSourceNode = fromNode;
      break;
    }
  }
  let derivedPromptMessage: string | null = null;
  if (promptSourceNode) {
    const hasUpstreamEdges = edges.some((edge: Edge): boolean => edge.to === promptSourceNode.id);
    const promptSourceInputs = allInputs[promptSourceNode.id] ?? {};
    if (hasUpstreamEdges) {
      const hasInputValue: boolean = Object.values(promptSourceInputs).some(hasMeaningfulValue);
      if (!hasInputValue) {
        return prevOutputs;
      }
    }
    const template = promptSourceNode.config?.prompt?.template ?? '';
    const templateNeedsCurrentValue =
      /{{\s*(result|value|current)\b[^}]*}}|\[\s*(result|value|current)\b[^\]]*\]/.test(template);
    if (templateNeedsCurrentValue) {
      const currentValue =
        coerceInput(promptSourceInputs['result']) ?? coerceInput(promptSourceInputs['value']);
      const hasCurrentValue =
        currentValue !== undefined &&
        currentValue !== null &&
        (typeof currentValue !== 'string' || currentValue.trim().length > 0);
      if (!hasCurrentValue) {
        return prevOutputs;
      }
    }
    try {
      const derivedPrompt: { promptOutput: string; imagesValue: unknown } = buildPromptOutput(
        promptSourceNode.config?.prompt,
        promptSourceInputs
      );
      if (derivedPrompt.promptOutput?.trim()) {
        derivedPromptMessage = derivedPrompt.promptOutput;
      }
    } catch (err) {
      logClientError(err);
      reportAiPathsError(
        err,
        {
          service: 'ai-paths-runtime',
        },
        `Prompt building failed for notification node ${node.id}`
      );
    }
  }
  const messageSource: unknown =
    derivedPromptMessage ??
    coerceInput(nodeInputs['result']) ??
    coerceInput(nodeInputs['prompt']) ??
    coerceInput(nodeInputs['value']) ??
    coerceInput(nodeInputs['bundle']) ??
    coerceInput(nodeInputs['context']) ??
    coerceInput(nodeInputs['triggerName']) ??
    coerceInput(nodeInputs['trigger']) ??
    coerceInput(nodeInputs['meta']) ??
    coerceInput(nodeInputs['entityId']) ??
    coerceInput(nodeInputs['entityType']);

  if (messageSource === undefined) {
    return prevOutputs;
  }
  const message: string = safeStringify(messageSource);
  const trimmed: string = message.trim();
  if (!trimmed) {
    return prevOutputs;
  }
  toast(trimmed, { variant: 'success' });
  return prevOutputs;
};

import type { PlaywrightConfig } from '@/shared/contracts/ai-paths';
import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { playwrightNodeApi, type PlaywrightNodeRunSnapshot } from '@/shared/lib/ai-paths/api';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { normalizePlaywrightConfig } from '../../playwright/default-config';
import { buildCaptureRouteUrl } from '../../playwright/capture-defaults';
import { coerceInput, parseJsonSafe, renderTemplate } from '../../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const parseObjectJson = (value: string | undefined, fieldName: string): Record<string, unknown> => {
  if (!value?.trim()) return {};
  const parsed = parseJsonSafe(value);
  if (!isObjectRecord(parsed)) {
    throw new Error(`${fieldName} must be a valid JSON object.`);
  }
  return parsed;
};

const buildInputPayload = (nodeInputs: RuntimePortValues): Record<string, unknown> =>
  Object.fromEntries(
    Object.entries(nodeInputs).map(([port, value]: [string, unknown]) => [port, coerceInput(value)])
  );

const normalizeCaptureConfig = (
  capture: PlaywrightConfig['capture']
): { screenshot?: boolean; html?: boolean; video?: boolean; trace?: boolean } | undefined => {
  if (!capture) return undefined;
  const normalized: { screenshot?: boolean; html?: boolean; video?: boolean; trace?: boolean } = {};
  if (typeof capture.screenshot === 'boolean') normalized.screenshot = capture.screenshot;
  if (typeof capture.html === 'boolean') normalized.html = capture.html;
  if (typeof capture.video === 'boolean') normalized.video = capture.video;
  if (typeof capture.trace === 'boolean') normalized.trace = capture.trace;
  return Object.keys(normalized).length > 0 ? normalized : undefined;
};

const PLAYWRIGHT_TERMINAL_RUN_STATUSES = new Set(['completed', 'failed']);

const isTerminalPlaywrightRun = (run: PlaywrightNodeRunSnapshot): boolean =>
  PLAYWRIGHT_TERMINAL_RUN_STATUSES.has(run.status);

const assertPlaywrightPollResponse = (
  response: Awaited<ReturnType<typeof playwrightNodeApi.poll>>
): PlaywrightNodeRunSnapshot => {
  if (!response.ok) {
    throw new Error(response.error || 'Failed to poll Playwright run.');
  }

  return response.data.run;
};

const shouldWaitForNextPollAttempt = (attempt: number, maxAttempts: number): boolean =>
  attempt < maxAttempts - 1;

const sleepForPlaywrightPoll = async (intervalMs: number): Promise<void> => {
  await new Promise<void>((resolve) => setTimeout(resolve, intervalMs));
};

export const pollPlaywrightRun = async (
  runId: string,
  options?: { intervalMs?: number; maxAttempts?: number }
): Promise<PlaywrightNodeRunSnapshot> => {
  const maxAttempts = options?.maxAttempts ?? 90;
  const intervalMs = options?.intervalMs ?? 1000;

  for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
    const run = assertPlaywrightPollResponse(await playwrightNodeApi.poll(runId));

    if (isTerminalPlaywrightRun(run)) {
      return run;
    }

    if (shouldWaitForNextPollAttempt(attempt, maxAttempts)) {
      await sleepForPlaywrightPoll(intervalMs);
    }
  }

  throw new Error('Playwright run timed out while polling.');
};

const normalizeArtifactRelativePath = (relativePath: string): string =>
  relativePath.trim().replace(/^\/+/, '');

const splitArtifactPath = (
  relativePath: string
): { file: string; runId: string } | null => {
  const parts = relativePath.split('/');

  if (parts.length < 2) {
    return null;
  }

  return {
    file: parts.slice(1).join('/').trim(),
    runId: (parts[0] ?? '').trim(),
  };
};

const isValidArtifactFile = (file: string): boolean =>
  Boolean(file) && !file.includes('/') && !file.includes('\\');

export const artifactUrlFromPath = (relativePath: string): string | null => {
  const normalized = normalizeArtifactRelativePath(relativePath);

  if (!normalized) return null;

  const resolved = splitArtifactPath(normalized);

  if (!resolved?.runId || !isValidArtifactFile(resolved?.file ?? '')) {
    return null;
  }

  return `/api/ai-paths/playwright/${encodeURIComponent(resolved.runId)}/artifacts/${encodeURIComponent(
    resolved.file
  )}`;
};

const mapArtifactsWithUrls = (
  artifacts: NonNullable<PlaywrightNodeRunSnapshot['artifacts']>
): Array<Record<string, unknown>> =>
  artifacts.map((artifact) => ({
    ...artifact,
    url: artifactUrlFromPath(artifact.path) ?? null,
  }));

const mapRunToOutputs = (run: PlaywrightNodeRunSnapshot): RuntimePortValues => {
  const resultPayload = run.result;
  const resultRecord = isObjectRecord(resultPayload) ? resultPayload : {};
  const outputPorts = isObjectRecord(resultRecord['outputs']) ? resultRecord['outputs'] : {};
  const returnValue = resultRecord['returnValue'] ?? resultPayload ?? null;
  const resultValue = outputPorts['result'] ?? returnValue;
  const valueValue = outputPorts['value'] ?? returnValue;
  return {
    ...outputPorts,
    result: resultValue,
    value: valueValue,
    status: run.status,
    jobId: run.runId,
    bundle: {
      runId: run.runId,
      status: run.status,
      result: resultPayload ?? null,
      error: run.error ?? null,
      artifacts: run.artifacts ? mapArtifactsWithUrls(run.artifacts) : [],
      logs: run.logs ?? [],
      startedAt: run.startedAt ?? null,
      completedAt: run.completedAt ?? null,
    },
  };
};

export const handlePlaywright: NodeHandler = async ({
  node,
  nodeInputs,
  prevOutputs,
  contextRegistry,
  skipAiJobs,
  executed,
  toast,
  reportAiPathsError,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  if (node.type !== 'playwright') return prevOutputs;
  if (skipAiJobs) return prevOutputs;
  if (executed.ai.has(node.id)) return prevOutputs;

  const playwrightConfig: PlaywrightConfig = normalizePlaywrightConfig(node.config?.playwright);
  const script = playwrightConfig.script?.trim();
  if (!script) {
    return {
      ...prevOutputs,
      status: 'failed',
      bundle: {
        status: 'failed',
        error: 'Playwright script is empty.',
      },
    };
  }

  const startUrlTemplate = playwrightConfig.startUrlTemplate?.trim() ?? '';
  const startUrl = startUrlTemplate ? renderTemplate(startUrlTemplate, nodeInputs, '') : undefined;

  try {
    const launchOptions = parseObjectJson(playwrightConfig.launchOptionsJson, 'Launch options');
    const contextOptions = parseObjectJson(playwrightConfig.contextOptionsJson, 'Context options');
    const settingsOverrides = isObjectRecord(playwrightConfig.settingsOverrides)
      ? playwrightConfig.settingsOverrides
      : {};
    const normalizedCapture = normalizeCaptureConfig(playwrightConfig.capture);
    const personaId = playwrightConfig.personaId?.trim();

    // Build the input payload, injecting config-defined capture routes when the
    // captures port is not wired (batch-capture nodes configured inline).
    const inputPayload = buildInputPayload(nodeInputs);
    if (!inputPayload['captures'] && playwrightConfig.captureRoutes?.length) {
      const baseUrl = playwrightConfig.captureBaseUrl?.trim() ?? '';
      inputPayload['captures'] = playwrightConfig.captureRoutes.map((route) => ({
        id: route.id,
        title: route.title,
        url: buildCaptureRouteUrl(baseUrl, route.path),
        selector: route.selector ?? null,
        selectorRole: route.selectorRole ?? null,
        waitForMs: route.waitForMs ?? null,
        waitForSelectorMs: route.waitForSelectorMs ?? null,
      }));
    }
    if (!inputPayload['appearanceMode'] && playwrightConfig.captureAppearanceMode?.trim()) {
      inputPayload['appearanceMode'] = playwrightConfig.captureAppearanceMode.trim();
    }

    const enqueueResult = await playwrightNodeApi.enqueue({
      script,
      input: inputPayload,
      ...(startUrl ? { startUrl } : {}),
      timeoutMs: playwrightConfig.timeoutMs ?? 120000,
      waitForResult: playwrightConfig.waitForResult ?? true,
      browserEngine: playwrightConfig.browserEngine ?? 'chromium',
      ...(personaId ? { personaId } : {}),
      settingsOverrides,
      launchOptions,
      contextOptions,
      ...(contextRegistry ? { contextRegistry } : {}),
      ...(normalizedCapture ? { capture: normalizedCapture } : {}),
    });

    if (!enqueueResult.ok) {
      throw new Error(enqueueResult.error || 'Failed to enqueue Playwright node run.');
    }

    const initialRun = enqueueResult.data.run;
    executed.ai.add(node.id);
    toast('Playwright run queued.', { variant: 'success' });

    if (playwrightConfig.waitForResult === false) {
      return {
        jobId: initialRun.runId,
        status: initialRun.status,
        bundle: {
          runId: initialRun.runId,
          status: initialRun.status,
          personaId: playwrightConfig.personaId ?? null,
        },
      };
    }

    if (initialRun.status === 'completed' || initialRun.status === 'failed') {
      return mapRunToOutputs(initialRun);
    }

    const completedRun = await pollPlaywrightRun(initialRun.runId);
    return mapRunToOutputs(completedRun);
  } catch (error) {
    logClientError(error);
    reportAiPathsError(
      error,
      { action: 'playwrightRun', nodeId: node.id },
      'Playwright run failed:'
    );
    toast('Playwright run failed.', { variant: 'error' });
    executed.ai.add(node.id);
    return {
      result: '',
      value: null,
      status: 'failed',
      bundle: {
        status: 'failed',
        error: error instanceof Error ? error.message : 'Playwright run failed.',
      },
    };
  }
};

import type { DbQueryConfig, PollConfig, RuntimePortValues } from '@/shared/contracts/ai-paths';
import type { NodeHandler, NodeHandlerContext } from '@/shared/contracts/ai-paths-runtime';

import { DEFAULT_DB_QUERY } from '../../constants';
import { coerceInput } from '../../utils';
import { pollDatabaseQuery, pollGraphJob } from '../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


type PollFailureClassification = {
  status: 'failed' | 'timeout' | 'canceled';
  reason:
    | 'poll_timeout'
    | 'poll_job_canceled'
    | 'poll_job_not_found'
    | 'poll_connection_error'
    | 'poll_query_failed'
    | 'poll_unknown';
  retryable: boolean;
  error: string;
};

const classifyPollError = (error: unknown, mode: 'job' | 'database'): PollFailureClassification => {
  const message = error instanceof Error ? error.message : String(error);
  const normalized = message.trim().toLowerCase();

  if (normalized.includes('timed out') || normalized.includes('timeout')) {
    return {
      status: 'timeout',
      reason: 'poll_timeout',
      retryable: true,
      error: message,
    };
  }
  if (normalized.includes('was canceled')) {
    return {
      status: 'canceled',
      reason: 'poll_job_canceled',
      retryable: false,
      error: message,
    };
  }
  if (normalized.includes('job not found')) {
    return {
      status: 'failed',
      reason: 'poll_job_not_found',
      retryable: false,
      error: message,
    };
  }
  if (normalized.includes('connection error') || normalized.includes('network')) {
    return {
      status: 'failed',
      reason: 'poll_connection_error',
      retryable: true,
      error: message,
    };
  }
  if (mode === 'database') {
    return {
      status: 'failed',
      reason: 'poll_query_failed',
      retryable: true,
      error: message,
    };
  }
  return {
    status: 'failed',
    reason: 'poll_unknown',
    retryable: true,
    error: message,
  };
};

export const handlePoll: NodeHandler = async ({
  node,
  nodeInputs,
  prevOutputs,
  deferPoll,
  executed,
  reportAiPathsError,
  abortSignal,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  if (deferPoll) {
    const existingStatus: string | null =
      typeof prevOutputs['status'] === 'string' ? prevOutputs['status'] : null;
    if (existingStatus === 'completed' || existingStatus === 'failed') {
      return prevOutputs;
    }
    const rawJobId: unknown = coerceInput(nodeInputs['jobId']);
    const jobId: string =
      typeof rawJobId === 'string' || typeof rawJobId === 'number' ? String(rawJobId).trim() : '';
    if (!jobId) {
      return prevOutputs;
    }
    const existingResult: unknown =
      prevOutputs['result'] !== undefined ? prevOutputs['result'] : null;
    executed.poll.add(node.id);
    return {
      result: existingResult,
      status: 'polling',
      jobId,
      bundle: {
        jobId,
        status: 'polling',
        result: existingResult,
      },
    };
  }
  const pollConfig: PollConfig = node.config?.poll ?? {
    intervalMs: 2000,
    maxAttempts: 30,
    mode: 'job',
  };
  const pollMode: 'job' | 'database' = pollConfig.mode ?? 'job';
  const rawJobId: unknown = coerceInput(nodeInputs['jobId']);
  const jobId: string =
    typeof rawJobId === 'string' || typeof rawJobId === 'number' ? String(rawJobId).trim() : '';
  if (pollMode === 'database') {
    const queryConfig: DbQueryConfig = { ...DEFAULT_DB_QUERY, ...((pollConfig.dbQuery as Partial<DbQueryConfig>) ?? {}) };
    try {
      const response: { result: unknown; status: string; bundle: Record<string, unknown> } =
        await pollDatabaseQuery(
          nodeInputs,
          {
            intervalMs: pollConfig.intervalMs ?? 2000,
            maxAttempts: pollConfig.maxAttempts ?? 30,
            dbQuery: queryConfig,
            successPath: pollConfig.successPath ?? 'status',
            successOperator: pollConfig.successOperator ?? 'equals',
            successValue: pollConfig.successValue ?? 'completed',
            resultPath: pollConfig.resultPath ?? 'result',
          },
          abortSignal ? { signal: abortSignal } : {}
        );
      return {
        result: response.result,
        status: response.status,
        jobId,
        bundle: {
          ...(response.bundle ?? {}),
          jobId,
          status: response.status,
          ...(response.status === 'timeout' ? { reason: 'poll_timeout', retryable: true } : {}),
        },
      };
    } catch (error: unknown) {
      logClientError(error);
      if (abortSignal?.aborted || (error instanceof Error && error.name === 'AbortError')) {
        throw error;
      }
      const classification = classifyPollError(error, 'database');
      reportAiPathsError(
        error,
        { action: 'pollDatabase', nodeId: node.id },
        'Database polling failed:'
      );
      return {
        result: null,
        status: classification.status,
        jobId,
        bundle: {
          jobId,
          status: classification.status,
          reason: classification.reason,
          retryable: classification.retryable,
          error: classification.error,
        },
      };
    }
  }
  if (!jobId) {
    return prevOutputs;
  }
  try {
    const result: unknown = await pollGraphJob(jobId, {
      intervalMs: pollConfig.intervalMs,
      maxAttempts: pollConfig.maxAttempts,
      ...(abortSignal ? { signal: abortSignal } : {}),
    });
    return {
      result,
      status: 'completed',
      jobId,
      bundle: { jobId, status: 'completed', result },
    };
  } catch (error: unknown) {
    logClientError(error);
    if (abortSignal?.aborted || (error instanceof Error && error.name === 'AbortError')) {
      throw error;
    }
    const classification = classifyPollError(error, 'job');
    reportAiPathsError(
      error,
      { action: 'pollJob', jobId, nodeId: node.id },
      'AI job polling failed:'
    );
    return {
      result: null,
      status: classification.status,
      jobId,
      bundle: {
        jobId,
        status: classification.status,
        reason: classification.reason,
        retryable: classification.retryable,
        error: classification.error,
      },
    };
  }
};

import type { DbSchemaConfig } from '@/shared/contracts/ai-paths';
import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import type { CollectionSchema } from '@/shared/contracts/database';
import type { HttpResult } from '@/shared/contracts/http';
import { dbApi } from '@/shared/lib/ai-paths/api';
import type { SchemaResponse } from '@/shared/lib/ai-paths/api/client';
import { isObjectRecord } from '@/shared/utils/object-utils';
import { extractMissingTemplatePorts } from './integration-database-mongo-update-plan-helpers';
import { coerceInput, renderJsonTemplate } from '../../utils';


// Module-scoped schema cache to avoid redundant API calls across database nodes
// within the same run. TTL ensures freshness across separate runs.
let schemaCacheResult: HttpResult<unknown> | null = null;
let schemaCacheTs = 0;
const SCHEMA_CACHE_TTL_MS = 30_000;
const DEFAULT_LIVE_CONTEXT_LIMIT = 20;
const PRODUCT_CATEGORIES_COLLECTION = 'product_categories';

type LiveContextCollection = {
  name: string;
  provider: 'mongodb';
  documents: Record<string, unknown>[];
  total: number;
  limit: number;
  skip: number;
  query: string | null;
  error?: string;
};

type LiveContextPayload = {
  fetchedAt: string;
  selectedCollections: string[];
  limitPerCollection: number;
  query: string | null;
  collections: LiveContextCollection[];
  collectionMap: Record<string, LiveContextCollection>;
  errors: Array<{ collection: string; error: string }>;
};

const isCollectionSchema = (value: unknown): value is CollectionSchema =>
  isObjectRecord(value) && typeof value['name'] === 'string' && Array.isArray(value['fields']);

const resolveCollectionList = (value: unknown): CollectionSchema[] => {
  if (Array.isArray(value)) {
    return value.filter((entry: unknown): entry is CollectionSchema => isCollectionSchema(entry));
  }
  if (isObjectRecord(value)) {
    return Object.values(value).filter((entry: unknown): entry is CollectionSchema =>
      isCollectionSchema(entry)
    );
  }
  return [];
};

const cloneSchemaResponse = (schema: SchemaResponse): SchemaResponse => {
  if (typeof globalThis.structuredClone === 'function') {
    return globalThis.structuredClone(schema);
  }
  return JSON.parse(JSON.stringify(schema)) as SchemaResponse;
};

const normalizeSelectedCollectionKey = (value: string): string => value.trim().toLowerCase();

const matchesSelectedCollection = (
  collection: CollectionSchema,
  selectedSet: Set<string>
): boolean => {
  const nameKey = normalizeSelectedCollectionKey(collection.name);
  if (selectedSet.has(nameKey)) return true;
  if (collection.provider) {
    const providerKey = normalizeSelectedCollectionKey(`${collection.provider}:${collection.name}`);
    if (selectedSet.has(providerKey)) return true;
  }
  return false;
};

const toFetchCollectionName = (value: string): string => {
  const trimmed = value.trim();
  if (!trimmed.includes(':')) return trimmed;
  return trimmed.split(':').slice(1).join(':').trim();
};

const dedupeCollectionNames = (values: string[]): string[] => {
  const seen = new Set<string>();
  const deduped: string[] = [];
  values.forEach((value: string) => {
    const normalized = normalizeSelectedCollectionKey(value);
    if (!normalized || seen.has(normalized)) return;
    seen.add(normalized);
    deduped.push(value.trim());
  });
  return deduped;
};

const resolveRecordString = (value: unknown): string => {
  if (typeof value === 'string') return value.trim();
  if (typeof value === 'number' && Number.isFinite(value)) return String(value);
  if (value && typeof value === 'object' && typeof value.toString === 'function') {
    const resolved = value.toString();
    return typeof resolved === 'string' ? resolved.trim() : '';
  }
  return '';
};

const resolveProductCategoryLeafDocuments = (
  documents: Record<string, unknown>[]
): Record<string, unknown>[] => {
  const categories = documents
    .map((document) => {
      if (!isObjectRecord(document)) return null;
      const id = resolveRecordString(document['id']) || resolveRecordString(document['_id']);
      if (!id) return null;
      const label =
        resolveRecordString(document['name_en']) ||
        resolveRecordString(document['name']) ||
        resolveRecordString(document['name_pl']) ||
        resolveRecordString(document['name_de']) ||
        id;
      return {
        id,
        label,
        parentId: resolveRecordString(document['parentId']) || null,
        raw: document,
      };
    })
    .filter(
      (
        category
      ): category is {
        id: string;
        label: string;
        parentId: string | null;
        raw: Record<string, unknown>;
      } => category !== null
    );

  const byId = new Map(categories.map((category) => [category.id, category]));
  const parentIds = new Set(
    categories
      .map((category) => category.parentId)
      .filter((parentId): parentId is string => typeof parentId === 'string' && parentId.length > 0)
  );

  const buildFullPath = (categoryId: string, seen: Set<string> = new Set()): string => {
    const category = byId.get(categoryId);
    if (!category) return '';
    if (seen.has(categoryId)) return category.label;
    const nextSeen = new Set(seen);
    nextSeen.add(categoryId);
    if (!category.parentId || !byId.has(category.parentId)) return category.label;
    const parentPath = buildFullPath(category.parentId, nextSeen);
    return parentPath ? `${parentPath} > ${category.label}` : category.label;
  };

  return categories
    .filter((category) => !parentIds.has(category.id))
    .map((category) => ({
      ...category.raw,
      id: resolveRecordString(category.raw['id']) || category.id,
      parentId: category.parentId,
      fullPath: buildFullPath(category.id),
      leafLabel: category.label,
      isLeaf: true,
    }))
    .sort((left, right) =>
      resolveRecordString(left['fullPath']).localeCompare(resolveRecordString(right['fullPath']))
    );
};

const transformLiveContextDocuments = ({
  collectionName,
  documents,
  config,
}: {
  collectionName: string;
  documents: Record<string, unknown>[];
  config: DbSchemaConfig;
}): Record<string, unknown>[] => {
  if (
    config.contextTransform === 'product_categories_leaf_only' &&
    collectionName === PRODUCT_CATEGORIES_COLLECTION
  ) {
    return resolveProductCategoryLeafDocuments(documents);
  }
  return documents;
};

type EmbeddedNormalizeCategoryLeaf = {
  id: string;
  label: string;
  fullPath: string | null;
  parentId: string | null;
  catalogId: string | null;
};

type EmbeddedNormalizeCategoryContext = {
  catalogId: string | null;
  currentCategoryId: string | null;
  currentCategory: {
    id: string;
    label: string;
    fullPath: string | null;
    isLeaf: boolean | null;
  } | null;
  leafCategories: EmbeddedNormalizeCategoryLeaf[];
  fetchedAt: string | null;
};

const asRecord = (value: unknown): Record<string, unknown> | null =>
  isObjectRecord(value) ? value : null;

const resolveEmbeddedNormalizeCategoryLeaf = (
  value: unknown
): EmbeddedNormalizeCategoryLeaf | null => {
  const record = asRecord(value);
  if (!record) return null;

  const id = resolveRecordString(record['id']) || resolveRecordString(record['_id']);
  const label = resolveRecordString(record['label']) || resolveRecordString(record['name']);
  if (!id || !label) return null;

  return {
    id,
    label,
    fullPath: resolveRecordString(record['fullPath']) || null,
    parentId: resolveRecordString(record['parentId']) || null,
    catalogId: resolveRecordString(record['catalogId']) || null,
  };
};

const resolveEmbeddedNormalizeCategoryContext = (
  value: unknown
): EmbeddedNormalizeCategoryContext | null => {
  const record = asRecord(value);
  if (!record) return null;

  const leafCategories = Array.isArray(record['leafCategories'])
    ? record['leafCategories']
        .map((entry: unknown) => resolveEmbeddedNormalizeCategoryLeaf(entry))
        .filter(
          (entry): entry is EmbeddedNormalizeCategoryLeaf => entry !== null
        )
    : [];

  const currentCategoryRecord = asRecord(record['currentCategory']);
  const currentCategoryId =
    resolveRecordString(record['currentCategoryId']) ||
    resolveRecordString(currentCategoryRecord?.['id']) ||
    null;
  const currentCategory =
    currentCategoryRecord && currentCategoryId
      ? {
          id: currentCategoryId,
          label:
            resolveRecordString(currentCategoryRecord['label']) ||
            resolveRecordString(currentCategoryRecord['name']) ||
            currentCategoryId,
          fullPath: resolveRecordString(currentCategoryRecord['fullPath']) || null,
          isLeaf:
            typeof currentCategoryRecord['isLeaf'] === 'boolean'
              ? currentCategoryRecord['isLeaf']
              : null,
        }
      : null;

  if (leafCategories.length === 0 && currentCategory === null) {
    return null;
  }

  return {
    catalogId: resolveRecordString(record['catalogId']) || null,
    currentCategoryId,
    currentCategory,
    leafCategories,
    fetchedAt: resolveRecordString(record['fetchedAt']) || null,
  };
};

const resolveEmbeddedCategoryContextFromInputs = (
  nodeInputs: RuntimePortValues
): EmbeddedNormalizeCategoryContext | null => {
  const contextRecord = asRecord(coerceInput(nodeInputs['context']));
  const bundleRecord = asRecord(coerceInput(nodeInputs['bundle']));
  const entityRecord = asRecord(coerceInput(nodeInputs['entityJson']));

  return (
    resolveEmbeddedNormalizeCategoryContext(contextRecord?.['categoryContext']) ??
    resolveEmbeddedNormalizeCategoryContext(bundleRecord?.['categoryContext']) ??
    resolveEmbeddedNormalizeCategoryContext(entityRecord?.['categoryContext']) ??
    null
  );
};

const resolveEmbeddedCategoryQueryCompatibility = (args: {
  config: DbSchemaConfig;
  selectedCollections: string[];
  query: string | null;
  embeddedContext: EmbeddedNormalizeCategoryContext;
  nodeInputs: RuntimePortValues;
}): boolean => {
  if (args.config.contextReuseMode !== 'prefer_transformed_input') {
    return false;
  }

  if (args.config.contextTransform !== 'product_categories_leaf_only') {
    return false;
  }

  const fetchedCollections = args.selectedCollections.map((value: string) =>
    toFetchCollectionName(value)
  );
  if (
    fetchedCollections.length !== 1 ||
    fetchedCollections[0] !== PRODUCT_CATEGORIES_COLLECTION
  ) {
    return false;
  }

  if (!args.query) {
    return true;
  }

  try {
    const parsedQuery = JSON.parse(args.query) as Record<string, unknown>;
    const queryKeys = Object.keys(parsedQuery);
    if (queryKeys.length !== 1 || queryKeys[0] !== 'catalogId') {
      return false;
    }

    const requestedCatalogId = resolveRecordString(parsedQuery['catalogId']);
    const contextRecord = asRecord(coerceInput(args.nodeInputs['context']));
    const inputCatalogId = resolveRecordString(contextRecord?.['catalogId']);
    const embeddedCatalogId = args.embeddedContext.catalogId ?? inputCatalogId;

    return Boolean(requestedCatalogId) && requestedCatalogId === embeddedCatalogId;
  } catch {
    return false;
  }
};

const buildLiveContextFromEmbeddedCategoryContext = (args: {
  embeddedContext: EmbeddedNormalizeCategoryContext;
  limitPerCollection: number;
  query: string | null;
}): LiveContextPayload => {
  const documentsById = new Map<string, Record<string, unknown>>();

  args.embeddedContext.leafCategories.forEach((category: EmbeddedNormalizeCategoryLeaf) => {
    documentsById.set(category.id, {
      id: category.id,
      catalogId: category.catalogId ?? args.embeddedContext.catalogId,
      parentId: category.parentId,
      name: category.label,
      name_en: category.label,
      fullPath: category.fullPath ?? category.label,
      leafLabel: category.label,
      isLeaf: true,
    });
  });

  const currentCategory = args.embeddedContext.currentCategory;
  if (currentCategory && !documentsById.has(currentCategory.id)) {
    documentsById.set(currentCategory.id, {
      id: currentCategory.id,
      catalogId: args.embeddedContext.catalogId,
      parentId: null,
      name: currentCategory.label,
      name_en: currentCategory.label,
      fullPath: currentCategory.fullPath ?? currentCategory.label,
      leafLabel: currentCategory.label,
      isLeaf: currentCategory.isLeaf ?? false,
    });
  }

  const documents = Array.from(documentsById.values()).sort((left, right) =>
    resolveRecordString(left['fullPath']).localeCompare(resolveRecordString(right['fullPath']))
  );
  const collection: LiveContextCollection = {
    name: PRODUCT_CATEGORIES_COLLECTION,
    provider: 'mongodb',
    documents,
    total: documents.length,
    limit: args.limitPerCollection,
    skip: 0,
    query: args.query,
  };

  return {
    fetchedAt: args.embeddedContext.fetchedAt ?? new Date().toISOString(),
    selectedCollections: [PRODUCT_CATEGORIES_COLLECTION],
    limitPerCollection: args.limitPerCollection,
    query: args.query,
    collections: [collection],
    collectionMap: {
      [PRODUCT_CATEGORIES_COLLECTION]: collection,
    },
    errors: [],
  };
};

export const getCachedSchema = async (): Promise<HttpResult<unknown>> => {
  const now = Date.now();
  if (schemaCacheResult && schemaCacheResult.ok && now - schemaCacheTs < SCHEMA_CACHE_TTL_MS) {
    return schemaCacheResult;
  }
  const result = await dbApi.schema();
  if (result.ok) {
    schemaCacheResult = result;
    schemaCacheTs = now;
  }
  return result;
};

const formatSchemaAsText = (schema: SchemaResponse): string => {
  const lines: string[] = [
    'DATABASE SCHEMA',
    '===============',
    `Provider: ${schema.provider}`,
    '',
  ];

  const rawCollections = schema.collections;
  const collections = resolveCollectionList(rawCollections);

  for (const collection of collections) {
    lines.push(`Collection: ${collection.name}`);
    lines.push('Fields:');
    const fields = collection.fields ?? [];
    for (const field of fields) {
      const markers: string[] = [];
      if (field.isId) markers.push('ID');
      if (field.isRequired) markers.push('required');
      if (field.isUnique) markers.push('unique');
      if (field.hasDefault) markers.push('has default');
      const markerStr = markers.length > 0 ? ` [${markers.join(', ')}]` : '';
      lines.push(`  - ${field.name} (${field.type})${markerStr}`);
    }
    const relations = collection.relations;
    if (relations && relations.length > 0) {
      lines.push(`Relations: ${relations.join(', ')}`);
    }
    lines.push('');
  }

  return lines.join('\n');
};

const filterCollections = (
  schema: SchemaResponse,
  selectedCollections: string[]
): SchemaResponse => {
  if (!selectedCollections || selectedCollections.length === 0) {
    return cloneSchemaResponse(schema);
  }
  const selectedSet = new Set(
    selectedCollections.map((c: string): string => normalizeSelectedCollectionKey(c))
  );

  const clonedSchema = cloneSchemaResponse(schema);
  const baseCollections = resolveCollectionList(clonedSchema.collections);

  if (clonedSchema.provider === 'multi') {
    const collections = baseCollections.filter((c): boolean =>
      matchesSelectedCollection(c, selectedSet)
    );
    return {
      ...clonedSchema,
      collections,
    } as SchemaResponse;
  }
  const collections = baseCollections.filter((c: CollectionSchema): boolean =>
    matchesSelectedCollection(c, selectedSet)
  );
  return {
    provider: clonedSchema.provider,
    collections,
  } as SchemaResponse;
};

const formatLiveContextAsText = (payload: LiveContextPayload): string => {
  const lines: string[] = [
    'LIVE DATABASE CONTEXT',
    '=====================',
    `Fetched At: ${payload.fetchedAt}`,
    `Selected Collections: ${payload.selectedCollections.length}`,
    `Limit Per Collection: ${payload.limitPerCollection}`,
    `Query: ${payload.query ?? '(none)'}`,
    '',
  ];

  if (payload.collections.length === 0) {
    lines.push('No live context collections selected.');
    return lines.join('\n');
  }

  payload.collections.forEach((collection: LiveContextCollection) => {
    lines.push(`Collection: ${collection.name}`);
    if (collection.error) {
      lines.push(`Error: ${collection.error}`);
      lines.push('');
      return;
    }
    lines.push(`Total Matching Documents: ${collection.total}`);
    lines.push('Documents:');
    if (collection.documents.length === 0) {
      lines.push('  []');
    } else {
      collection.documents.forEach((document: Record<string, unknown>, index: number) => {
        lines.push(`  ${index + 1}. ${JSON.stringify(document)}`);
      });
    }
    lines.push('');
  });

  return lines.join('\n');
};

const resolveLiveContextCollectionKeys = (config: DbSchemaConfig): string[] => {
  const explicit = dedupeCollectionNames(config.contextCollections ?? []);
  if (explicit.length > 0) return explicit;
  if (config.mode === 'selected') {
    return dedupeCollectionNames(config.collections ?? []);
  }
  return [];
};

const loadLiveContext = async ({
  nodeId,
  config,
  nodeInputs,
  reportAiPathsError,
}: {
  nodeId: string;
  config: DbSchemaConfig;
  nodeInputs: RuntimePortValues;
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
}): Promise<LiveContextPayload | null> => {
  const selectedCollections = resolveLiveContextCollectionKeys(config);
  if (selectedCollections.length === 0) {
    return {
      fetchedAt: new Date().toISOString(),
      selectedCollections: [],
      limitPerCollection: config.contextLimit ?? DEFAULT_LIVE_CONTEXT_LIMIT,
      query: config.contextQuery?.trim() ? config.contextQuery.trim() : null,
      collections: [],
      collectionMap: {},
      errors: [],
    };
  }

  const limitPerCollection = config.contextLimit ?? DEFAULT_LIVE_CONTEXT_LIMIT;
  const fetchedAt = new Date().toISOString();
  const rawQuery = config.contextQuery?.trim() ? config.contextQuery.trim() : null;
  const missingQueryPorts =
    rawQuery && rawQuery.length > 0 ? extractMissingTemplatePorts(rawQuery, nodeInputs) : [];
  if (missingQueryPorts.length > 0) {
    const error = `Live context query is missing connected inputs: ${missingQueryPorts.join(', ')}.`;
    reportAiPathsError(
      new Error(error),
      { action: 'fetchDbLiveContext', nodeId, missingQueryPorts },
      'Database live context query resolution failed:'
    );
    return {
      fetchedAt,
      selectedCollections: selectedCollections.map((value: string) => toFetchCollectionName(value)),
      limitPerCollection,
      query: rawQuery,
      collections: selectedCollections.map(
        (selectedKey: string): LiveContextCollection => ({
          name: toFetchCollectionName(selectedKey),
          provider: 'mongodb',
          documents: [],
          total: 0,
          limit: limitPerCollection,
          skip: 0,
          query: rawQuery,
          error,
        })
      ),
      collectionMap: Object.fromEntries(
        selectedCollections.map((selectedKey: string) => {
          const collectionName = toFetchCollectionName(selectedKey);
          return [
            collectionName,
            {
              name: collectionName,
              provider: 'mongodb',
              documents: [],
              total: 0,
              limit: limitPerCollection,
              skip: 0,
              query: rawQuery,
              error,
            } satisfies LiveContextCollection,
          ];
        })
      ),
      errors: selectedCollections.map((selectedKey: string) => ({
        collection: toFetchCollectionName(selectedKey),
        error,
      })),
    };
  }
  const query =
    rawQuery && rawQuery.length > 0
      ? renderJsonTemplate(
          rawQuery,
          nodeInputs,
          coerceInput(nodeInputs['context']) ??
            coerceInput(nodeInputs['bundle']) ??
            coerceInput(nodeInputs['value']) ??
            ''
        ).trim()
      : null;

  const embeddedCategoryContext = resolveEmbeddedCategoryContextFromInputs(nodeInputs);
  if (
    embeddedCategoryContext &&
    resolveEmbeddedCategoryQueryCompatibility({
      config,
      selectedCollections,
      query,
      embeddedContext: embeddedCategoryContext,
      nodeInputs,
    })
  ) {
    return buildLiveContextFromEmbeddedCategoryContext({
      embeddedContext: embeddedCategoryContext,
      limitPerCollection,
      query,
    });
  }

  const provider = config.provider === 'mongodb' ? 'mongodb' : 'auto';

  const collections = await Promise.all(
    selectedCollections.map(async (selectedKey): Promise<LiveContextCollection> => {
      const collectionName = toFetchCollectionName(selectedKey);
      const result = await dbApi.browse(collectionName, {
        provider,
        limit: limitPerCollection,
        ...(query ? { query } : {}),
      });

      if (!result.ok) {
        reportAiPathsError(
          new Error(result.error),
          { action: 'fetchDbLiveContext', nodeId, collection: collectionName },
          'Database live context fetch failed:'
        );
        return {
          name: collectionName,
          provider: 'mongodb',
          documents: [],
          total: 0,
          limit: limitPerCollection,
          skip: 0,
          query,
          error: result.error,
        };
      }

      const rawDocuments = result.data.documents ?? [];
      const documents = transformLiveContextDocuments({
        collectionName,
        documents: rawDocuments,
        config,
      });
      const transformedDocuments = documents !== rawDocuments;

      return {
        name: collectionName,
        provider: result.data.provider,
        documents,
        total: transformedDocuments ? documents.length : result.data.total ?? 0,
        limit: result.data.limit ?? limitPerCollection,
        skip: result.data.skip ?? 0,
        query,
      };
    })
  );

  const errors = collections
    .filter((collection: LiveContextCollection): boolean => typeof collection.error === 'string')
    .map((collection: LiveContextCollection) => ({
      collection: collection.name,
      error: collection.error as string,
    }));

  return {
    fetchedAt,
    selectedCollections: selectedCollections.map((value: string) => toFetchCollectionName(value)),
    limitPerCollection,
    query,
    collections,
    collectionMap: Object.fromEntries(
      collections.map((collection: LiveContextCollection) => [collection.name, collection])
    ),
    errors,
  };
};

export const handleDbSchema: NodeHandler = async ({
  node,
  nodeInputs,
  prevOutputs,
  executed,
  reportAiPathsError,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  if (executed.schema?.has(node.id)) return prevOutputs;

  const defaultConfig: DbSchemaConfig = {
    mode: 'all',
    collections: [],
    sourceMode: 'schema',
    contextCollections: [],
    contextQuery: '',
    contextLimit: DEFAULT_LIVE_CONTEXT_LIMIT,
    includeFields: true,
    includeRelations: true,
    formatAs: 'text',
    contextReuseMode: 'never',
  };

  const config: DbSchemaConfig = {
    ...defaultConfig,
    ...(node.config?.db_schema ?? {}),
  };

  const schemaResult = await getCachedSchema();
  if (!schemaResult.ok) {
    reportAiPathsError(
      new Error(schemaResult.error),
      { action: 'fetchDbSchema', nodeId: node.id },
      'Database schema fetch failed:'
    );
    return {
      schema: null,
      context: null,
    };
  }

  const fullSchema = cloneSchemaResponse(schemaResult.data as SchemaResponse);

  // Filter collections if mode is "selected"
  const schema =
    config.mode === 'selected'
      ? filterCollections(fullSchema, config.collections ?? [])
      : cloneSchemaResponse(fullSchema);

  // Optionally filter out fields or relations
  if (!config.includeFields || !config.includeRelations) {
    const baseCollections = resolveCollectionList(schema.collections);

    schema.collections = baseCollections.map((c): CollectionSchema => {
      const result: CollectionSchema = {
        name: c.name,
        fields: config.includeFields ? (c.fields ?? []) : [],
      };

      const relations = c.relations;
      if (config.includeRelations && relations) {
        result.relations = relations;
      }
      return result;
    });
  }

  // Format for AI consumption
  const schemaText =
    config.formatAs === 'text' ? formatSchemaAsText(schema) : JSON.stringify(schema, null, 2);
  const liveContext =
    config.sourceMode === 'live_context' || config.sourceMode === 'schema_and_live_context'
      ? await loadLiveContext({
        nodeId: node.id,
        config,
        nodeInputs,
        reportAiPathsError,
      })
      : null;
  const liveContextText =
    liveContext === null
      ? null
      : config.formatAs === 'text'
        ? formatLiveContextAsText(liveContext)
        : JSON.stringify(liveContext, null, 2);

  const contextText =
    config.sourceMode === 'live_context'
      ? liveContextText ?? ''
      : config.sourceMode === 'schema_and_live_context'
        ? config.formatAs === 'text'
          ? [schemaText, liveContextText].filter(Boolean).join('\n\n')
          : JSON.stringify(
            {
              schema,
              liveContext,
            },
            null,
            2
          )
        : schemaText;

  executed.schema?.add(node.id);

  return {
    // Keep ports strongly-typed:
    // - `schema` is the raw schema object (connect to "schema" inputs)
    // - `context` is an object containing both the raw schema + a text rendering for prompt/templates
    schema,
    context: {
      sourceMode: config.sourceMode,
      schema,
      schemaText,
      contextText,
      provider: schema.provider,
      collections: schema.collections,
      ...(liveContext ? { liveContext } : {}),
      ...(liveContextText ? { liveContextText } : {}),
    },
  };
};

import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';

import { coerceInput } from '../../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const pickString = (value: unknown): string | null =>
  typeof value === 'string' && value.trim().length > 0 ? value.trim() : null;

type SimulationConfigSnapshot = {
  entityId: string | null;
  entityType: string;
};

const resolveSimulationConfig = (node: NodeHandlerContext['node']): SimulationConfigSnapshot => {
  const simulationConfig = (node.config?.simulation ?? {}) as Record<string, unknown>;
  return {
    entityId: pickString(
      (simulationConfig['entityId'] as string) ?? (simulationConfig['productId'] as string)
    ),
    entityType: pickString(simulationConfig['entityType'] as string) ?? 'product',
  };
};

const shouldRunSimulation = (
  node: NodeHandlerContext['node'],
  nodeInputs: NodeHandlerContext['nodeInputs']
): boolean => {
  const triggerInput = coerceInput(node.inputs.includes('trigger') ? nodeInputs['trigger'] : true);
  return triggerInput !== false;
};

const reportSimulationHydrationError = (
  error: unknown,
  context: {
    nodeId: string;
    nodeType: string;
    entityId: string;
    entityType: string;
  },
  reportAiPathsError: NodeHandlerContext['reportAiPathsError']
): void => {
  logClientError(error);
  reportAiPathsError?.(
    error,
    {
      service: 'ai-paths-runtime',
      nodeId: context.nodeId,
      nodeType: context.nodeType,
      entityId: context.entityId,
      entityType: context.entityType,
    },
    `Simulation hydration failed for ${context.entityType}:${context.entityId}`
  );
};

const hydrateSimulationEntity = async (input: {
  entityId: string | null;
  entityType: string;
  fetchEntityCached: NodeHandlerContext['fetchEntityCached'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  toast: NodeHandlerContext['toast'];
  node: NodeHandlerContext['node'];
}): Promise<Record<string, unknown> | null> => {
  if (!input.entityId) return null;
  try {
    const entity = await input.fetchEntityCached(input.entityType, input.entityId);
    if (!entity) {
      input.toast?.(`No ${input.entityType} found for simulation ID ${input.entityId}.`, {
        variant: 'error',
      });
    }
    return entity;
  } catch (error) {
    reportSimulationHydrationError(
      error,
      {
        nodeId: input.node.id,
        nodeType: input.node.type,
        entityId: input.entityId,
        entityType: input.entityType,
      },
      input.reportAiPathsError
    );
    return null;
  }
};

const buildSimulationContext = (input: {
  node: NodeHandlerContext['node'];
  now: NodeHandlerContext['now'];
  activePathId: NodeHandlerContext['activePathId'];
  entityId: string | null;
  entityType: string;
  entity: Record<string, unknown> | null;
}): Record<string, unknown> => {
  const context: Record<string, unknown> = {
    source: input.node.title ?? input.node.id,
    timestamp: input.now,
    pathId: input.activePathId,
    contextSource: 'simulation',
    simulationNodeId: input.node.id,
    simulationNodeTitle: input.node.title ?? input.node.id,
    entityId: input.entityId,
    entityType: input.entityType,
    ...(input.entityId && input.entityType === 'product' ? { productId: input.entityId } : {}),
  };

  if (!input.entity) return context;
  context['entity'] = input.entity;
  context['entityJson'] = input.entity;
  if (input.entityType === 'product') {
    context['product'] = input.entity;
  }
  return context;
};

export const handleSimulation: NodeHandler = async ({
  node,
  nodeInputs,
  fetchEntityCached,
  reportAiPathsError,
  toast,
  now,
  activePathId,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  const { entityId, entityType } = resolveSimulationConfig(node);
  if (!shouldRunSimulation(node, nodeInputs)) {
    return {};
  }

  const entity = await hydrateSimulationEntity({
    entityId,
    entityType,
    fetchEntityCached,
    reportAiPathsError,
    toast,
    node,
  });
  const context = buildSimulationContext({
    node,
    now,
    activePathId,
    entityType,
    entityId,
    entity,
  });

  return {
    context,
    entityId,
    entityType,
    entityJson: entity,
  };
};

import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const pickString = (value: unknown): string | null =>
  typeof value === 'string' && value.trim().length > 0 ? value.trim() : null;

const asRecord = (value: unknown): Record<string, unknown> | null =>
  value && typeof value === 'object' && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : null;

export const handleTrigger: NodeHandler = async ({
  node,
  triggerNodeId,
  triggerEvent,
  triggerContext,
  fetchEntityCached,
  reportAiPathsError,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  if (triggerNodeId && node.id !== triggerNodeId) {
    return {};
  }

  const eventName: string = triggerEvent ?? node.config?.trigger?.event ?? 'manual';
  const triggerContextRecord = asRecord(triggerContext);
  const entityId =
    pickString(triggerContextRecord?.['productId']) ??
    pickString(triggerContextRecord?.['entityId']);
  const entityType =
    pickString(triggerContextRecord?.['entityType']) ??
    (pickString(triggerContextRecord?.['productId']) ? 'product' : null);
  const embeddedEntity =
    asRecord(triggerContextRecord?.['entityJson']) ?? asRecord(triggerContextRecord?.['entity']);

  let resolvedEntity: Record<string, unknown> | null = embeddedEntity;
  let entityFetchError: string | null = null;
  if (!resolvedEntity && entityId && entityType) {
    try {
      resolvedEntity = await fetchEntityCached(entityType, entityId);
    } catch (error) {
      logClientError(error);
      entityFetchError = error instanceof Error ? error.message : 'Entity fetch failed.';
      reportAiPathsError(
        error,
        { action: 'triggerEntityFetch', nodeId: node.id },
        'Trigger entity fetch failed:'
      );
    }
  }

  const output: RuntimePortValues = {
    trigger: true,
    triggerName: eventName,
  };

  if (triggerContextRecord) {
    output['context'] = {
      ...triggerContextRecord,
      ...(entityId ? { entityId } : {}),
      ...(entityType ? { entityType } : {}),
      ...(resolvedEntity ? { entityJson: resolvedEntity } : {}),
      ...(entityFetchError ? { entityFetchFailed: true, entityFetchError } : {}),
    };
  }
  if (entityId) output['entityId'] = entityId;
  if (entityType) output['entityType'] = entityType;
  if (resolvedEntity) output['entityJson'] = resolvedEntity;
  if (entityFetchError) {
    output['entityFetchFailed'] = true;
    output['entityFetchError'] = entityFetchError;
  }

  return output;
};

import { logClientError } from '@/shared/utils/observability/client-error-logger';
export type JsonIntegrityPolicy = 'strict' | 'repair';

export type JsonIntegrityParseState = 'not_json_like' | 'parsed' | 'repaired' | 'unparseable';

export type JsonIntegrityDiagnostic = {
  rawType: string;
  parseState: JsonIntegrityParseState;
  repairApplied: boolean;
  parseError?: string;
  truncationDetected?: boolean;
  repairSteps?: string[];
};

export type JsonIntegrityNormalizationResult = {
  value: unknown;
  state: JsonIntegrityParseState;
  repaired: boolean;
  diagnostic: JsonIntegrityDiagnostic;
};

const JSON_OBJECT_BOUNDARY_REPAIR_REGEX = /(:\s*\{[^{}]*\})(\s*,\s*\{)/g;
const TRAILING_COMMAS_BEFORE_CLOSER_REGEX = /,\s*([}\]])/g;
const MARKDOWN_FENCE_REGEX = /```(?:[A-Za-z0-9_-]+)?\s*([\s\S]*?)```/m;

const toRawType = (value: unknown): string => {
  if (Array.isArray(value)) return 'array';
  if (value === null) return 'null';
  return typeof value;
};

const looksLikeJsonContainer = (value: string): boolean => {
  return (
    (value.startsWith('{') && value.endsWith('}')) || (value.startsWith('[') && value.endsWith(']'))
  );
};

const looksJsonish = (value: string): boolean => {
  if (looksLikeJsonContainer(value)) return true;
  if (value.includes('```')) return true;
  return value.includes('{') || value.includes('[');
};

const isStructuredValue = (value: unknown): boolean => Boolean(value) && typeof value === 'object';

export const normalizeJsonIntegrityPolicy = (value: unknown): JsonIntegrityPolicy =>
  value === 'strict' ? 'strict' : 'repair';

export const repairMalformedJsonLikeString = (value: string): string => {
  let next = value;
  for (let pass = 0; pass < 3; pass += 1) {
    const repaired = next.replace(JSON_OBJECT_BOUNDARY_REPAIR_REGEX, '$1}$2');
    if (repaired === next) break;
    next = repaired;
  }
  return next;
};

const toParseError = (error: unknown): string => {
  if (error instanceof Error && error.message.trim().length > 0) {
    return error.message;
  }
  return String(error);
};

const tryParseStructuredJson = (
  candidate: string
): { ok: true; value: unknown } | { ok: false; error: string } => {
  try {
    const parsed = JSON.parse(candidate) as unknown;
    if (!isStructuredValue(parsed)) {
      return {
        ok: false,
        error: 'Parsed JSON value is not an object/array.',
      };
    }
    return { ok: true, value: parsed };
  } catch (error) {
    logClientError(error);
    return { ok: false, error: toParseError(error) };
  }
};

const stripMarkdownCodeFences = (value: string): string => {
  const fullFence = value.match(/^```(?:[A-Za-z0-9_-]+)?\s*([\s\S]*?)\s*```$/);
  if (fullFence?.[1]) {
    return fullFence[1].trim();
  }
  const snippetFence = value.match(MARKDOWN_FENCE_REGEX);
  if (snippetFence?.[1]) {
    return snippetFence[1].trim();
  }
  return value;
};

type JsonCloserScanState = {
  stack: string[];
  inString: boolean;
  escaped: boolean;
};

const isJsonContainerOpener = (char: string): boolean => char === '{' || char === '[';

const isJsonContainerCloser = (char: string): boolean => char === '}' || char === ']';

const isMatchingJsonContainerPair = (open: string | undefined, close: string): boolean =>
  (open === '{' && close === '}') || (open === '[' && close === ']');

const advanceJsonCloserStringState = (
  state: JsonCloserScanState,
  char: string
): JsonCloserScanState => {
  if (!state.inString) {
    return char === '"'
      ? { ...state, inString: true, escaped: false }
      : state;
  }
  if (state.escaped) {
    return { ...state, escaped: false };
  }
  if (char === '\\') {
    return { ...state, escaped: true };
  }
  if (char === '"') {
    return { ...state, inString: false, escaped: false };
  }
  return state;
};

const advanceJsonCloserContainerState = (
  state: JsonCloserScanState,
  char: string
): JsonCloserScanState => {
  if (state.inString) return state;
  if (isJsonContainerOpener(char)) {
    return { ...state, stack: [...state.stack, char] };
  }
  if (!isJsonContainerCloser(char)) {
    return state;
  }
  const open = state.stack[state.stack.length - 1];
  if (!isMatchingJsonContainerPair(open, char)) {
    return state;
  }
  return { ...state, stack: state.stack.slice(0, -1) };
};

const computeMissingClosers = (value: string): string => {
  let state: JsonCloserScanState = {
    stack: [],
    inString: false,
    escaped: false,
  };

  for (let index = 0; index < value.length; index += 1) {
    const char = value[index];
    if (!char) continue;
    state = advanceJsonCloserStringState(state, char);
    state = advanceJsonCloserContainerState(state, char);
  }

  if (state.stack.length === 0) return '';
  return state.stack
    .reverse()
    .map((open: string): string => (open === '{' ? '}' : ']'))
    .join('');
};

const closeUnbalancedJsonContainers = (
  value: string
): { value: string; truncationDetected: boolean } => {
  const missingClosers = computeMissingClosers(value);
  if (!missingClosers) {
    return { value, truncationDetected: false };
  }
  return {
    value: `${value}${missingClosers}`,
    truncationDetected: true,
  };
};

const stripTrailingCommasBeforeClosers = (value: string): string =>
  value.replace(TRAILING_COMMAS_BEFORE_CLOSER_REGEX, '$1');

export const normalizeJsonLikeValue = (
  value: unknown,
  policy: JsonIntegrityPolicy = 'repair'
): JsonIntegrityNormalizationResult => {
  const rawType = toRawType(value);
  if (typeof value !== 'string') {
    if (isStructuredValue(value)) {
      return {
        value,
        state: 'parsed',
        repaired: false,
        diagnostic: {
          rawType,
          parseState: 'parsed',
          repairApplied: false,
        },
      };
    }
    return {
      value,
      state: 'not_json_like',
      repaired: false,
      diagnostic: {
        rawType,
        parseState: 'not_json_like',
        repairApplied: false,
      },
    };
  }

  const trimmed = value.trim();
  if (!trimmed || !looksJsonish(trimmed)) {
    return {
      value,
      state: 'not_json_like',
      repaired: false,
      diagnostic: {
        rawType,
        parseState: 'not_json_like',
        repairApplied: false,
      },
    };
  }

  const rawAttempt = tryParseStructuredJson(trimmed);
  if (rawAttempt.ok) {
    return {
      value: rawAttempt.value,
      state: 'parsed',
      repaired: false,
      diagnostic: {
        rawType,
        parseState: 'parsed',
        repairApplied: false,
      },
    };
  }

  const buildUnparseable = (
    parseError: string,
    truncationDetected: boolean,
    repairSteps: string[]
  ): JsonIntegrityNormalizationResult => ({
    value,
    state: 'unparseable',
    repaired: false,
    diagnostic: {
      rawType,
      parseState: 'unparseable',
      repairApplied: false,
      parseError,
      truncationDetected,
      repairSteps,
    },
  });

  if (policy === 'strict') {
    return buildUnparseable(rawAttempt.error, Boolean(computeMissingClosers(trimmed)), []);
  }

  let lastParseError = rawAttempt.error;
  let truncationDetected = Boolean(computeMissingClosers(trimmed));
  const repairSteps: string[] = [];
  let working = trimmed;
  const repairCandidates: Array<{
    step: string;
    transform: (candidate: string) => { value: string; truncationDetected?: boolean };
  }> = [
    {
      step: 'strip_markdown_code_fences',
      transform: (candidate: string) => ({
        value: stripMarkdownCodeFences(candidate),
      }),
    },
    {
      step: 'repair_object_boundaries',
      transform: (candidate: string) => ({
        value: repairMalformedJsonLikeString(candidate),
      }),
    },
    {
      step: 'append_missing_container_closers',
      transform: (candidate: string) => closeUnbalancedJsonContainers(candidate),
    },
    {
      step: 'strip_trailing_commas_before_closers',
      transform: (candidate: string) => ({
        value: stripTrailingCommasBeforeClosers(candidate),
      }),
    },
  ];

  for (const candidate of repairCandidates) {
    const transformed = candidate.transform(working);
    if (transformed.value === working) continue;
    working = transformed.value;
    repairSteps.push(candidate.step);
    if (transformed.truncationDetected) {
      truncationDetected = true;
    } else if (!truncationDetected) {
      truncationDetected = Boolean(computeMissingClosers(working));
    }
    const parsedAttempt = tryParseStructuredJson(working);
    if (parsedAttempt.ok) {
      return {
        value: parsedAttempt.value,
        state: 'repaired',
        repaired: true,
        diagnostic: {
          rawType,
          parseState: 'repaired',
          repairApplied: true,
          parseError: lastParseError,
          truncationDetected,
          repairSteps,
        },
      };
    }
    lastParseError = parsedAttempt.error;
  }

  return buildUnparseable(lastParseError, truncationDetected, repairSteps);
};

import type { DatabaseConfig } from '@/shared/contracts/ai-paths';
import {
  SELECTOR_TYPES_REQUIRING_OPTIONS,
  normalizeParameterDefinitions,
  parseChecklistValues,
  resolveObjectPathValue,
} from '../database-parameter-inference-utils';
import {
  coerceParameterRecordArray,
  normalizeParameterEntries,
} from './parameter-inference.normalizer';

export class ParameterInferenceGateError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ParameterInferenceGateError';
  }
}

export const assertParameterInferenceGuardrails = (args: {
  databaseConfig: DatabaseConfig;
  definitionsValue: unknown;
  updates: Record<string, unknown>;
}): void => {
  const guard = args.databaseConfig.parameterInferenceGuard;
  if (!guard?.enabled) return;

  const definitionsPath = guard.definitionsPath ?? '';
  const definitions = normalizeParameterDefinitions(args.definitionsValue, definitionsPath);
  const targetPath = guard.targetPath ?? 'parameters';
  const updatesValue = resolveObjectPathValue(args.updates, targetPath);
  const updatedRecords = coerceParameterRecordArray(updatesValue);
  const normalizedUpdates = normalizeParameterEntries(updatedRecords, { allowEmptyValue: false });

  normalizedUpdates.forEach((update) => {
    const definition = definitions.get(update.parameterId);
    if (!definition) {
      if (guard.allowUnknownParameterIds === false) {
        throw new ParameterInferenceGateError(
          `Inferred parameter ID "${update.parameterId}" is not present in the allowed definitions list.`
        );
      }
      return;
    }

    if (guard.enforceOptionLabels !== false && SELECTOR_TYPES_REQUIRING_OPTIONS.has(definition.selectorType)) {
      const allowedLabels = new Set(
        definition.optionLabels.map((label) => label.trim().toLowerCase())
      );
      if (allowedLabels.size > 0) {
        const inferredValues =
          definition.selectorType === 'checklist'
            ? parseChecklistValues(update.value)
            : [update.value];

        inferredValues.forEach((val) => {
          if (!allowedLabels.has(val.trim().toLowerCase())) {
            throw new ParameterInferenceGateError(
              `Inferred value "${val}" for parameter "${update.parameterId}" is not among the allowed options: ${definition.optionLabels.join(', ')}.`
            );
          }
        });
      }
    }
  });
};

import type { RuntimePortValues } from '@/shared/contracts/ai-paths-runtime';
import {
  coerceArrayLike,
  normalizeNonEmptyString,
  resolveObjectPathValue,
  resolveParameterValue,
  toRecord,
} from '../database-parameter-inference-utils';
import { coerceInput } from '@/shared/lib/ai-paths/core/utils/runtime';
import { normalizeParameterEntries } from './parameter-inference.normalizer';
import { stableStringify } from '@/shared/utils/stable-stringify';

const DEFAULT_PARAMETER_INFERENCE_LANGUAGE_CODE = 'en';

export const resolveExistingParameterValueFromInputs = (
  templateInputs: RuntimePortValues,
  targetPath: string,
  options: { includeDerivedPorts?: boolean } = {}
): unknown => {
  const includeDerivedPorts = options.includeDerivedPorts !== false;
  const candidates: unknown[] = [];
  const entityLikeKeys = ['entity', 'entityJson', 'product', 'item', 'data', 'current'];
  const pushFromRecord = (value: unknown, nestedKeys: string[] = entityLikeKeys): void => {
    const record = toRecord(value);
    if (!record) return;
    candidates.push(resolveObjectPathValue(record, targetPath));
    nestedKeys.forEach((key: string) => {
      candidates.push(resolveObjectPathValue(toRecord(record[key]), targetPath));
    });
  };
  pushFromRecord(coerceInput(templateInputs['context']));
  pushFromRecord(coerceInput(templateInputs['bundle']));
  pushFromRecord(templateInputs);
  if (includeDerivedPorts) {
    pushFromRecord(coerceInput(templateInputs['value']));
    pushFromRecord(coerceInput(templateInputs['result']));
  }
  for (const candidate of candidates) {
    if (coerceArrayLike(candidate).length > 0) {
      return candidate;
    }
  }
  return undefined;
};

export const mergeParameterInferenceUpdates = (args: {
  targetPath: string;
  updates: Record<string, unknown>;
  templateInputs: RuntimePortValues;
  languageCode?: string;
}): {
  updates: Record<string, unknown>;
  applied: boolean;
  meta?: Record<string, unknown>;
} => {
  if (args.targetPath !== 'parameters') {
    return { updates: args.updates, applied: false };
  }

  const inferred = normalizeParameterEntries(args.updates[args.targetPath], {
    allowEmptyValue: false,
  });
  if (inferred.length === 0) {
    return { updates: args.updates, applied: false };
  }

  const existingSource = resolveExistingParameterValueFromInputs(
    args.templateInputs,
    args.targetPath
  );
  const existing = normalizeParameterEntries(existingSource, {
    allowEmptyValue: true,
  });
  if (existing.length === 0) {
    const nextUpdates: Record<string, unknown> = { ...args.updates };
    delete nextUpdates[args.targetPath];
    return {
      updates: nextUpdates,
      applied: true,
      meta: {
        targetPath: args.targetPath,
        existingCount: 0,
        inferredCount: inferred.length,
        finalCount: 0,
        merged: {
          filledBlank: 0,
          preservedNonEmpty: 0,
          skippedNotExisting: inferred.length,
        },
        writeCandidates: 0,
        skipped: {
          reason: 'missing_existing_parameters',
        },
      },
    };
  }

  const nextRecords = existing.map((entry) => ({ ...entry.raw }));
  const indexByParameterId = new Map<string, number>();
  existing.forEach((entry, index) => {
    indexByParameterId.set(entry.parameterId, index);
  });
  const languageCode = resolveParameterInferenceLanguageCode(args.languageCode);

  let filledBlankCount = 0;
  let filledLocalizedCount = 0;
  let preservedNonEmptyCount = 0;
  let skippedNotExistingCount = 0;

  inferred.forEach((entry) => {
    const existingIndex = indexByParameterId.get(entry.parameterId);
    if (existingIndex === undefined) {
      skippedNotExistingCount += 1;
      return;
    }
    const current = nextRecords[existingIndex] ?? {};
    const currentValue = resolveParameterValue(current['value']);
    if (currentValue && !entry.value) {
      preservedNonEmptyCount += 1;
      return;
    }
    if (currentValue) {
      preservedNonEmptyCount += 1;
    }

    const mergeResult = mergeInferredParameterValueRecord({
      current,
      parameterId: entry.parameterId,
      inferredValue: entry.value,
      languageCode,
      allowScalarFill: !currentValue,
    });
    if (stableStringify(current) === stableStringify(mergeResult.next)) {
      return;
    }

    nextRecords[existingIndex] = mergeResult.next;
    if (mergeResult.filledScalar) {
      filledBlankCount += 1;
    }
    if (mergeResult.filledLocalized) {
      filledLocalizedCount += 1;
    }
  });

  const nextUpdates: Record<string, unknown> = { ...args.updates };
  const changed = !areParameterRecordArraysEqual(
    existing.map((entry) => entry.raw),
    nextRecords
  );
  if (changed) {
    nextUpdates[args.targetPath] = nextRecords;
  } else {
    delete nextUpdates[args.targetPath];
  }
  return {
    updates: nextUpdates,
    applied: true,
    meta: {
      targetPath: args.targetPath,
      existingCount: existing.length,
      inferredCount: inferred.length,
      finalCount: nextRecords.length,
      languageCode,
      merged: {
        filledBlank: filledBlankCount,
        filledLocalized: filledLocalizedCount,
        preservedNonEmpty: preservedNonEmptyCount,
        skippedNotExisting: skippedNotExistingCount,
      },
      writeCandidates: changed ? nextRecords.length : 0,
    },
  };
};

const areParameterRecordArraysEqual = (
  left: Record<string, unknown>[],
  right: Record<string, unknown>[]
): boolean => {
  if (left.length !== right.length) return false;
  for (let index = 0; index < left.length; index += 1) {
    if (stableStringify(left[index]) !== stableStringify(right[index])) {
      return false;
    }
  }
  return true;
};

const resolveParameterInferenceLanguageCode = (value: unknown): string =>
  normalizeNonEmptyString(value)?.toLowerCase() ?? DEFAULT_PARAMETER_INFERENCE_LANGUAGE_CODE;

const mergeInferredParameterValueRecord = (args: {
  current: Record<string, unknown>;
  parameterId: string;
  inferredValue: string;
  languageCode: string;
  allowScalarFill: boolean;
}): {
  next: Record<string, unknown>;
  filledScalar: boolean;
  filledLocalized: boolean;
} => {
  const next = { ...args.current };
  let filledScalar = false;
  let filledLocalized = false;

  if (args.allowScalarFill) {
    next['value'] = args.inferredValue;
    filledScalar = true;
  }

  const valuesByLanguage = toRecord(next['valuesByLanguage']) ?? {};
  const currentLocalized = resolveLocalizedValueByLanguage(valuesByLanguage, args.languageCode);
  if (!currentLocalized) {
    next['valuesByLanguage'] = {
      ...valuesByLanguage,
      [args.languageCode]: args.inferredValue,
    };
    filledLocalized = true;
  }

  return { next, filledScalar, filledLocalized };
};

const resolveLocalizedValueByLanguage = (
  valuesByLanguage: Record<string, unknown>,
  languageCode: string
): string | null => {
  const normalizedLanguageCode = languageCode.trim().toLowerCase();
  if (!normalizedLanguageCode) return null;

  const exact = Object.entries(valuesByLanguage).find(
    ([key]): boolean => normalizeNonEmptyString(key)?.toLowerCase() === normalizedLanguageCode
  );
  if (exact) {
    return normalizeNonEmptyString(exact[1]);
  }

  const prefixed = Object.entries(valuesByLanguage).find(([key]): boolean => {
    const normalizedKey = normalizeNonEmptyString(key)?.toLowerCase() ?? '';
    return normalizedKey.startsWith(`${normalizedLanguageCode}-`);
  });
  if (prefixed) {
    return normalizeNonEmptyString(prefixed[1]);
  }
  return null;
};

import {
  coerceArrayLike,
  normalizeNonEmptyString,
  resolveParameterValue,
  toRecord,
} from '../database-parameter-inference-utils';

export const normalizeParameterId = (value: unknown): string | null => normalizeNonEmptyString(value);

export const normalizeParameterEntries = (
  value: unknown,
  options: { allowEmptyValue: boolean }
): Array<{ parameterId: string; value: string; raw: Record<string, unknown> }> => {
  const entries = coerceArrayLike(value);
  const normalized: Array<{ parameterId: string; value: string; raw: Record<string, unknown> }> =
    [];
  const seen = new Set<string>();
  entries.forEach((entry: unknown) => {
    const record = toRecord(entry);
    if (!record) return;
    const parameterId =
      normalizeParameterId(record['parameterId']) ?? normalizeParameterId(record['id']);
    if (!parameterId || seen.has(parameterId)) return;
    const resolvedValue = resolveParameterValue(record['value']);
    if (!resolvedValue && !options.allowEmptyValue) return;
    normalized.push({
      parameterId,
      value: resolvedValue ?? '',
      raw: { ...record },
    });
    seen.add(parameterId);
  });
  return normalized;
};

export const coerceParameterRecordArray = (value: unknown): Record<string, unknown>[] => {
  if (Array.isArray(value)) {
    return value
      .map((entry: unknown): Record<string, unknown> | null => toRecord(entry))
      .filter((entry: Record<string, unknown> | null): entry is Record<string, unknown> =>
        Boolean(entry)
      );
  }
  const record = toRecord(value);
  if (record && Array.isArray(record['parameters'])) {
    return record['parameters']
      .map((entry: unknown): Record<string, unknown> | null => toRecord(entry))
      .filter((entry: Record<string, unknown> | null): entry is Record<string, unknown> =>
        Boolean(entry)
      );
  }
  return coerceArrayLike(value)
    .map((entry: unknown): Record<string, unknown> | null => toRecord(entry))
    .filter((entry: Record<string, unknown> | null): entry is Record<string, unknown> =>
      Boolean(entry)
    );
};

