import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';

import { parseJsonSafe, safeStringify } from '../../utils';

const coerceNumber = (value: unknown, fallback: number): number => {
  const numeric = typeof value === 'number' ? value : Number(value);
  return Number.isFinite(numeric) ? numeric : fallback;
};

const exceedsSizeLimit = (value: unknown, maxBytes?: number | null): boolean => {
  if (!maxBytes || maxBytes <= 0) return false;
  const serialized = safeStringify(value);
  const size = typeof serialized === 'string' ? serialized.length : 0;
  return size > maxBytes;
};

export const handleStateNode: NodeHandler = ({
  node,
  nodeInputs,
  prevOutputs,
  variables,
  setVariable,
}: NodeHandlerContext): RuntimePortValues => {
  if (node.type !== 'state') return prevOutputs;

  const config = node.config?.['state'];
  const key = config?.key?.trim();
  const mode = config?.mode ?? 'read';

  if (!key) {
    return {
      ...prevOutputs,
      status: 'failed',
      error: 'State key is required.',
      errorCode: 'STATE_KEY_MISSING',
    };
  }

  const current = variables[key];
  const maxValueBytes = config?.maxValueBytes;
  const expectedType = config?.expectedType;

  const matchesExpectedType = (value: unknown): boolean => {
    if (!expectedType) return true;
    if (value === undefined) return true;
    if (value === null) return expectedType === 'object'; // null treated as object-ish here
    if (expectedType === 'array') return Array.isArray(value);
    if (expectedType === 'object') return typeof value === 'object' && !Array.isArray(value);
    return typeof value === expectedType;
  };

  const buildTypeError = (value: unknown) => {
    const actual =
      value === null
        ? 'null'
        : Array.isArray(value)
          ? 'array'
          : typeof value === 'undefined'
            ? 'undefined'
            : typeof value;
    return {
      ...prevOutputs,
      status: 'failed',
      error: `State value type mismatch: expected ${expectedType}, got ${actual}.`,
      errorCode: 'STATE_VALUE_TYPE_MISMATCH',
    } as RuntimePortValues;
  };

  if (mode === 'read') {
    let next = current;
    if (next === undefined) {
      const initial = config?.initialJson?.trim() ? parseJsonSafe(config.initialJson) : undefined;
      if (initial !== undefined) {
        if (!matchesExpectedType(initial)) {
          return buildTypeError(initial);
        }
        if (exceedsSizeLimit(initial, maxValueBytes)) {
          return {
            ...prevOutputs,
            status: 'failed',
            error: 'State initial value exceeds maxValueBytes limit.',
            errorCode: 'STATE_VALUE_TOO_LARGE',
          };
        }
        setVariable(key, initial);
        next = initial;
      } else if (nodeInputs['value'] !== undefined) {
        if (!matchesExpectedType(nodeInputs['value'])) {
          return buildTypeError(nodeInputs['value']);
        }
        if (exceedsSizeLimit(nodeInputs['value'], maxValueBytes)) {
          return {
            ...prevOutputs,
            status: 'failed',
            error: 'State value exceeds maxValueBytes limit.',
            errorCode: 'STATE_VALUE_TOO_LARGE',
          };
        }
        setVariable(key, nodeInputs['value']);
        next = nodeInputs['value'];
      }
    }
    return {
      value: next,
    };
  }

  if (mode === 'write') {
    const value = nodeInputs['value'];
    if (!matchesExpectedType(value)) {
      return buildTypeError(value);
    }
    if (exceedsSizeLimit(value, maxValueBytes)) {
      return {
        ...prevOutputs,
        status: 'failed',
        error: 'State value exceeds maxValueBytes limit.',
        errorCode: 'STATE_VALUE_TOO_LARGE',
      };
    }
    setVariable(key, value);
    return {
      value,
      previous: current,
    };
  }

  if (mode === 'increment') {
    const base = coerceNumber(current, 0);
    const delta = coerceNumber(nodeInputs['delta'] ?? 1, 1);
    const next = base + delta;
    if (exceedsSizeLimit(next, maxValueBytes)) {
      return {
        ...prevOutputs,
        status: 'failed',
        error: 'State value exceeds maxValueBytes limit.',
        errorCode: 'STATE_VALUE_TOO_LARGE',
      };
    }
    setVariable(key, next);
    return {
      value: next,
      previous: base,
      delta,
    };
  }

  return prevOutputs;
};

import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import type { SwitchConfig } from '@/shared/contracts/ai-paths';

const resolveSwitchInputPort = (config: SwitchConfig | undefined): string =>
  config?.inputPort?.trim() || 'value';

const findMatchingSwitchCaseId = (
  config: SwitchConfig | undefined,
  valueStr: string
): string | null => {
  for (const candidate of config?.cases ?? []) {
    if (!candidate) continue;
    if (String(candidate.matchValue ?? '') === valueStr) {
      return candidate.id;
    }
  }
  return null;
};

const resolveSelectedSwitchCaseId = (
  config: SwitchConfig | undefined,
  valueStr: string
): string | null => findMatchingSwitchCaseId(config, valueStr) ?? config?.defaultCaseId ?? null;

export const handleSwitchNode: NodeHandler = ({
  node,
  nodeInputs,
  prevOutputs,
}: NodeHandlerContext): RuntimePortValues => {
  if (node.type !== 'switch') return prevOutputs;

  const config = node.config?.['switch'];
  const inputPort = resolveSwitchInputPort(config);
  const rawValue = nodeInputs[inputPort];
  const valueStr = rawValue == null ? '' : String(rawValue);
  const selectedCaseId = resolveSelectedSwitchCaseId(config, valueStr);

  return {
    value: rawValue,
    caseId: selectedCaseId,
    matched: selectedCaseId !== null,
  };
};

import type {
  BoundsNormalizerConfig,
  BoundsNormalizerInputFormat,
} from '@/shared/contracts/ai-paths-core';
import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { coerceInput, getValueAtMappingPath } from '@/shared/lib/ai-paths/core/utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


// ---------------------------------------------------------------------------
// Normalised output type
// ---------------------------------------------------------------------------

type NormalisedBounds = {
  left: number;
  top: number;
  width: number;
  height: number;
  confidence: number | null;
  label: string | null;
};

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const toFinite = (v: unknown): number | null => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

/** Read a value via optional dot-path; falls back to reading key directly. */
const readField = (
  obj: unknown,
  customPath: string | undefined,
  defaultKey: string
): number | null => {
  if (obj === null || obj === undefined || typeof obj !== 'object') return null;
  const key = customPath?.trim() || defaultKey;
  return toFinite(getValueAtMappingPath(obj, key));
};

/** Traverse a dot-path into an unknown value. Returns undefined if unreachable. */
const resolvePath = (value: unknown, path: string | undefined): unknown => {
  if (!path?.trim()) return value;
  return getValueAtMappingPath(value, path.trim());
};

// ---------------------------------------------------------------------------
// Format converters
// ---------------------------------------------------------------------------

/**
 * pixels_tlwh — {left,top,width,height} (or custom field names) — pass-through.
 */
const fromPixelsTlwh = (
  raw: unknown,
  cfg: BoundsNormalizerConfig
): { left: number; top: number; width: number; height: number } | null => {
  const left = readField(raw, cfg.leftField, 'left');
  const top = readField(raw, cfg.topField, 'top');
  const width = readField(raw, cfg.widthField, 'width');
  const height = readField(raw, cfg.heightField, 'height');
  if (left === null || top === null || width === null || height === null) return null;
  if (width <= 0 || height <= 0) return null;
  return { left, top, width, height };
};

/**
 * pixels_tlbr — {x1,y1,x2,y2} (or custom field names).
 * Defaults: leftField→x1, topField→y1, widthField→x2, heightField→y2.
 */
const fromPixelsTlbr = (
  raw: unknown,
  cfg: BoundsNormalizerConfig
): { left: number; top: number; width: number; height: number } | null => {
  const x1 = readField(raw, cfg.leftField, 'x1');
  const y1 = readField(raw, cfg.topField, 'y1');
  const x2 = readField(raw, cfg.widthField, 'x2');
  const y2 = readField(raw, cfg.heightField, 'y2');
  if (x1 === null || y1 === null || x2 === null || y2 === null) return null;
  const width = x2 - x1;
  const height = y2 - y1;
  if (width <= 0 || height <= 0) return null;
  return { left: x1, top: y1, width, height };
};

const parseGeminiMillirelativeBounds = (
  raw: unknown
): { y1: number; x1: number; y2: number; x2: number } | null => {
  if (!Array.isArray(raw) || raw.length < 4) return null;
  const y1 = toFinite(raw[0]);
  const x1 = toFinite(raw[1]);
  const y2 = toFinite(raw[2]);
  const x2 = toFinite(raw[3]);
  if (y1 === null || x1 === null || y2 === null || x2 === null) return null;
  return { y1, x1, y2, x2 };
};

const toGeminiMillirelativePixels = (
  bounds: { y1: number; x1: number; y2: number; x2: number },
  imgW: number,
  imgH: number
): { left: number; top: number; width: number; height: number } => ({
  left: Math.round((bounds.x1 / 1000) * imgW),
  top: Math.round((bounds.y1 / 1000) * imgH),
  width: Math.round(((bounds.x2 - bounds.x1) / 1000) * imgW),
  height: Math.round(((bounds.y2 - bounds.y1) / 1000) * imgH),
});

/**
 * gemini_millirelative — array [y1,x1,y2,x2] on 0–1000 scale.
 * Requires image dimensions from context to convert to pixels.
 */
const fromGeminiMillirelative = (
  raw: unknown,
  imgW: number,
  imgH: number
): { left: number; top: number; width: number; height: number } | null => {
  const bounds = parseGeminiMillirelativeBounds(raw);
  if (!bounds) return null;
  const { left, top, width, height } = toGeminiMillirelativePixels(bounds, imgW, imgH);
  if (width <= 0 || height <= 0) return null;
  return { left, top, width, height };
};

/**
 * relative_xywh — array or object [cx,cy,w,h] normalised 0–1 (YOLO centre format).
 * Requires image dimensions.
 * If object, reads: cx/centerX, cy/centerY, w/width, h/height.
 */
const fromRelativeXywh = (
  raw: unknown,
  imgW: number,
  imgH: number,
  cfg: BoundsNormalizerConfig
): { left: number; top: number; width: number; height: number } | null => {
  let cx: number | null = null;
  let cy: number | null = null;
  let rw: number | null = null;
  let rh: number | null = null;

  if (Array.isArray(raw) && raw.length >= 4) {
    [cx, cy, rw, rh] = raw.map(toFinite) as [
      number | null,
      number | null,
      number | null,
      number | null,
    ];
  } else if (raw !== null && typeof raw === 'object') {
    cx =
      readField(raw, cfg.leftField, 'cx') ??
      readField(raw, undefined, 'centerX') ??
      readField(raw, undefined, 'x');
    cy =
      readField(raw, cfg.topField, 'cy') ??
      readField(raw, undefined, 'centerY') ??
      readField(raw, undefined, 'y');
    rw = readField(raw, cfg.widthField, 'w') ?? readField(raw, undefined, 'width');
    rh = readField(raw, cfg.heightField, 'h') ?? readField(raw, undefined, 'height');
  }
  if (cx === null || cy === null || rw === null || rh === null) return null;
  const width = Math.round(rw * imgW);
  const height = Math.round(rh * imgH);
  if (width <= 0 || height <= 0) return null;
  const left = Math.round(cx * imgW - width / 2);
  const top = Math.round(cy * imgH - height / 2);
  return { left, top, width, height };
};

/**
 * percentage_tlwh — {left,top,width,height} as 0–100 percent.
 * Requires image dimensions.
 */
const fromPercentageTlwh = (
  raw: unknown,
  imgW: number,
  imgH: number,
  cfg: BoundsNormalizerConfig
): { left: number; top: number; width: number; height: number } | null => {
  const left = readField(raw, cfg.leftField, 'left');
  const top = readField(raw, cfg.topField, 'top');
  const width = readField(raw, cfg.widthField, 'width');
  const height = readField(raw, cfg.heightField, 'height');
  if (left === null || top === null || width === null || height === null) return null;
  const pw = Math.round((width / 100) * imgW);
  const ph = Math.round((height / 100) * imgH);
  if (pw <= 0 || ph <= 0) return null;
  return {
    left: Math.round((left / 100) * imgW),
    top: Math.round((top / 100) * imgH),
    width: pw,
    height: ph,
  };
};

/**
 * auto — detect format by inspecting the raw value shape.
 */
const fromAuto = (
  raw: unknown,
  imgW: number | null,
  imgH: number | null,
  cfg: BoundsNormalizerConfig
): { left: number; top: number; width: number; height: number } | null => {
  // Array of 4 numbers → try Gemini millirelative first, then relative_xywh
  if (Array.isArray(raw) && raw.length === 4) {
    const vals = raw.map(toFinite);
    if (vals.every((v): v is number => v !== null)) {
      const max = Math.max(...vals);
      if (max > 1 && imgW && imgH) {
        // Gemini 0-1000 scale
        return fromGeminiMillirelative(raw, imgW, imgH);
      }
      if (max <= 1 && imgW && imgH) {
        // Relative YOLO
        return fromRelativeXywh(raw, imgW, imgH, cfg);
      }
    }
  }
  // Object — try pixels_tlwh then pixels_tlbr
  if (raw !== null && typeof raw === 'object' && !Array.isArray(raw)) {
    const rec = raw as Record<string, unknown>;
    // Check for TLBR keys
    if ('x1' in rec || 'x2' in rec) return fromPixelsTlbr(raw, cfg);
    // Default TLWH
    return fromPixelsTlwh(raw, cfg);
  }
  return null;
};

// ---------------------------------------------------------------------------
// Image dimension resolution
// ---------------------------------------------------------------------------

const resolveImageDims = (
  context: unknown,
  cfg: BoundsNormalizerConfig
): { imgW: number | null; imgH: number | null } => {
  if (context === null || context === undefined || typeof context !== 'object') {
    return { imgW: null, imgH: null };
  }
  const wPath = cfg.imageWidthPath?.trim() || 'imageWidth';
  const hPath = cfg.imageHeightPath?.trim() || 'imageHeight';
  const imgW = toFinite(getValueAtMappingPath(context, wPath));
  const imgH = toFinite(getValueAtMappingPath(context, hPath));
  return { imgW, imgH };
};

// ---------------------------------------------------------------------------
// Handler
// ---------------------------------------------------------------------------

export const handleBoundsNormalizer: NodeHandler = ({
  node,
  nodeInputs,
  toast,
  reportAiPathsError,
}: NodeHandlerContext): RuntimePortValues => {
  try {
    const cfg: BoundsNormalizerConfig = {
      inputFormat: 'pixels_tlwh',
      ...(node.config?.boundsNormalizer ?? {}),
    };

    const rawInput = coerceInput(nodeInputs['value']);
    const contextInput = coerceInput(nodeInputs['context']);

    if (rawInput === undefined || rawInput === null) return {};

    // Drill into the bounds sub-object if boundsPath is configured
    const rawBounds = resolvePath(rawInput, cfg.boundsPath);

    // Resolve image dimensions from context (needed for relative/percentage formats)
    const { imgW, imgH } = resolveImageDims(contextInput, cfg);

    const format: BoundsNormalizerInputFormat = cfg.inputFormat ?? 'pixels_tlwh';

    let converted: { left: number; top: number; width: number; height: number } | null = null;

    switch (format) {
      case 'pixels_tlwh':
        converted = fromPixelsTlwh(rawBounds, cfg);
        break;
      case 'pixels_tlbr':
        converted = fromPixelsTlbr(rawBounds, cfg);
        break;
      case 'gemini_millirelative':
        if (imgW && imgH) {
          converted = fromGeminiMillirelative(rawBounds, imgW, imgH);
        } else {
          toast(
            `Bounds Normaliser "${node.title ?? node.id}": image dimensions not available for gemini_millirelative format.`,
            { variant: 'info' }
          );
        }
        break;
      case 'relative_xywh':
        if (imgW && imgH) {
          converted = fromRelativeXywh(rawBounds, imgW, imgH, cfg);
        } else {
          toast(
            `Bounds Normaliser "${node.title ?? node.id}": image dimensions not available for relative_xywh format.`,
            { variant: 'info' }
          );
        }
        break;
      case 'percentage_tlwh':
        if (imgW && imgH) {
          converted = fromPercentageTlwh(rawBounds, imgW, imgH, cfg);
        } else {
          toast(
            `Bounds Normaliser "${node.title ?? node.id}": image dimensions not available for percentage_tlwh format.`,
            { variant: 'info' }
          );
        }
        break;
      case 'auto':
        converted = fromAuto(rawBounds, imgW, imgH, cfg);
        break;
    }

    if (!converted) {
      toast(
        `Bounds Normaliser "${node.title ?? node.id}": could not extract bounds from input using format "${format}".`,
        { variant: 'info' }
      );
      return {};
    }

    // Extract optional pass-through fields
    const confidence: number | null = cfg.confidencePath
      ? toFinite(resolvePath(rawInput, cfg.confidencePath))
      : null;
    const label: unknown = cfg.labelPath ? resolvePath(rawInput, cfg.labelPath) : null;
    const labelStr: string | null = typeof label === 'string' && label.trim() ? label.trim() : null;

    const result: NormalisedBounds = {
      ...converted,
      confidence,
      label: labelStr,
    };

    return { value: result };
  } catch (error) {
    logClientError(error);
    reportAiPathsError(
      error,
      { service: 'ai-paths-runtime', nodeId: node.id, nodeType: node.type },
      `Node ${node.id} failed`
    );
    return {};
  }
};

import type { CanvasOutputConfig } from '@/shared/contracts/ai-paths-core';
import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { coerceInput, getValueAtMappingPath } from '@/shared/lib/ai-paths/core/utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


// ---------------------------------------------------------------------------
// Helpers (mirrors bounds-normalizer-handler utilities)
// ---------------------------------------------------------------------------

const toFinite = (v: unknown): number | null => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const readField = (
  obj: unknown,
  customPath: string | undefined,
  defaultKey: string
): number | null => {
  if (obj === null || obj === undefined || typeof obj !== 'object') return null;
  const key = customPath?.trim() || defaultKey;
  return toFinite(getValueAtMappingPath(obj, key));
};

const resolvePath = (value: unknown, path: string | undefined): unknown => {
  if (!path?.trim()) return value;
  return getValueAtMappingPath(value, path.trim());
};

// ---------------------------------------------------------------------------
// Handler
// ---------------------------------------------------------------------------

/**
 * canvas_output — Image Studio terminal node.
 *
 * Reads a bounds object from the `value` input port, normalises it to
 * { left, top, width, height }, and emits it at TWO locations in the
 * return value:
 *   1. The standard `value` output port — for composability with downstream nodes.
 *   2. A named top-level key (default `image_studio_bounds`) — Image Studio
 *      detects this key in run.result and skips manual field-mapping configuration.
 *
 * Optional `confidence` and `label` inputs (or dot-paths into `value`) are
 * included in both outputs when present.
 */
export const handleCanvasOutput: NodeHandler = ({
  node,
  nodeInputs,
  toast,
  reportAiPathsError,
}: NodeHandlerContext): RuntimePortValues => {
  try {
    const cfg: CanvasOutputConfig = {
      outputKey: 'image_studio_bounds',
      ...(node.config?.canvasOutput ?? {}),
    };

    const outputKey = cfg.outputKey?.trim() || 'image_studio_bounds';

    const rawInput = coerceInput(nodeInputs['value']);
    if (rawInput === undefined || rawInput === null) return {};

    // Drill into nested bounds object via optional boundsPath
    const rawBounds = resolvePath(rawInput, cfg.boundsPath);

    // Extract the four required coordinate fields
    const left = readField(rawBounds, cfg.leftField, 'left');
    const top = readField(rawBounds, cfg.topField, 'top');
    const width = readField(rawBounds, cfg.widthField, 'width');
    const height = readField(rawBounds, cfg.heightField, 'height');

    if (left === null || top === null || width === null || height === null) {
      toast(
        `Canvas Output "${node.title ?? node.id}": could not extract left/top/width/height from input.`,
        { variant: 'info' }
      );
      return {};
    }

    if (width <= 0 || height <= 0) {
      toast(
        `Canvas Output "${node.title ?? node.id}": bounds have non-positive dimensions (width=${width}, height=${height}).`,
        { variant: 'info' }
      );
      return {};
    }

    // Optional pass-through fields —
    // prefer dedicated input ports, fall back to dot-paths into the value input.
    const confidencePort = coerceInput(nodeInputs['confidence']);
    const confidence: number | null =
      confidencePort !== undefined && confidencePort !== null
        ? (toFinite(confidencePort) ?? null)
        : cfg.confidencePath
          ? (toFinite(resolvePath(rawInput, cfg.confidencePath)) ?? null)
          : null;

    const labelPort = coerceInput(nodeInputs['label']);
    const rawLabel: unknown =
      labelPort !== undefined && labelPort !== null
        ? labelPort
        : cfg.labelPath
          ? resolvePath(rawInput, cfg.labelPath)
          : null;
    const label: string | null =
      typeof rawLabel === 'string' && rawLabel.trim() ? rawLabel.trim() : null;

    const result = {
      left,
      top,
      width,
      height,
      ...(confidence !== null ? { confidence } : {}),
      ...(label !== null ? { label } : {}),
    };

    return {
      // Standard composable output port
      value: result,
      // Named key that Image Studio reads directly from run.result
      [outputKey]: result,
    };
  } catch (error) {
    logClientError(error);
    reportAiPathsError(
      error,
      { service: 'ai-paths-runtime', nodeId: node.id, nodeType: node.type },
      `Node ${node.id} failed`
    );
    return {};
  }
};

import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { coerceInput } from '@/shared/lib/ai-paths/core/utils';

import { resolveContextPayload } from '../../utils';

export const handleContext: NodeHandler = async ({
  node,
  nodeInputs,
  fetchEntityCached,
  now,
  simulationEntityId,
  simulationEntityType,
  toast,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  const rawContext = coerceInput(nodeInputs['context']);
  const inputContext =
    rawContext && typeof rawContext === 'object' ? (rawContext as Record<string, unknown>) : null;
  const payload = await resolveContextPayload(
    node.config?.context ?? { role: 'entity' },
    inputContext,
    simulationEntityType,
    simulationEntityId,
    now,
    fetchEntityCached
  );
  if (payload.missingFetchedEntity && payload.entityId) {
    toast(`No ${payload.entityType} data found for ID ${payload.entityId}.`, {
      variant: 'error',
    });
  }
  const resolvedContext = {
    ...payload.context,
    source: (payload.context?.['source'] as string | undefined) ?? node.title,
  };
  return {
    context: resolvedContext,
    entityId: payload.entityId,
    entityType: payload.entityType,
    entityJson: payload.scopedEntity,
  };
};

import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { coerceInput, hashRuntimeValue, parseJsonSafe } from '@/shared/lib/ai-paths/core/utils';

type IteratorState = {
  advanceStamp: string;
  index: number;
  items: unknown[];
  itemsHash: string;
  lastAckHash: string;
  prevStatus: unknown;
  total: number;
};

const ITERATOR_RESULT_KEYS = ['items', 'values', 'rows', 'results'] as const;

const readNestedIteratorItems = (value: unknown): unknown[] | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return null;
  }

  const record = value as Record<string, unknown>;

  for (const key of ITERATOR_RESULT_KEYS) {
    if (Array.isArray(record[key])) {
      return record[key] as unknown[];
    }
  }

  return null;
};

const splitNewlineIteratorItems = (value: string): string[] =>
  value
    .split(/\r?\n/)
    .map((line: string) => line.trim())
    .filter(Boolean);

const coerceStringIteratorItems = (value: string): unknown[] => {
  const trimmed = value.trim();

  if (!trimmed) {
    return [];
  }

  const parsed = parseJsonSafe(trimmed);

  if (Array.isArray(parsed)) {
    return parsed;
  }

  return readNestedIteratorItems(parsed) ?? splitNewlineIteratorItems(trimmed);
};

const coerceIteratorItems = (value: unknown): unknown[] => {
  if (value === undefined || value === null) return [];
  if (Array.isArray(value)) return value as unknown[];

  if (typeof value === 'string') {
    return coerceStringIteratorItems(value);
  }

  return readNestedIteratorItems(value) ?? [value];
};

const readFiniteNumber = (value: unknown, fallback = 0): number =>
  typeof value === 'number' && Number.isFinite(value) ? value : fallback;

const readStringValue = (value: unknown): string => (typeof value === 'string' ? value : '');

const clampIteratorIndex = (index: number, total: number): number => Math.min(Math.max(index, 0), total);

const resolveIteratorState = (
  items: unknown[],
  prevOutputs: RuntimePortValues
): IteratorState => {
  const itemsHash = hashRuntimeValue(items);
  const total = items.length;
  const prevItemsHash = readStringValue(prevOutputs['itemsHash']);
  const isSameItems = Boolean(prevItemsHash) && prevItemsHash === itemsHash;
  const prevIndex = isSameItems ? readFiniteNumber(prevOutputs['index']) : 0;

  return {
    advanceStamp: isSameItems ? readStringValue(prevOutputs['advanceStamp']) : '',
    index: clampIteratorIndex(prevIndex, total),
    items,
    itemsHash,
    lastAckHash: isSameItems ? readStringValue(prevOutputs['lastAckHash']) : '',
    prevStatus: prevOutputs['status'],
    total,
  };
};

const createIteratorResult = (
  state: IteratorState,
  result: Partial<RuntimePortValues>
): RuntimePortValues => ({
  advanceStamp: '',
  done: false,
  index: state.index,
  itemsHash: state.itemsHash,
  lastAckHash: state.lastAckHash,
  total: state.total,
  value: null,
  ...result,
});

const createIdleIteratorResult = (state: IteratorState): RuntimePortValues =>
  createIteratorResult(state, {
    done: true,
    index: 0,
    status: 'idle',
  });

const createCompletedIteratorResult = (state: IteratorState): RuntimePortValues =>
  createIteratorResult(state, {
    done: true,
    status: 'completed',
  });

const createAdvancedIteratorResult = (
  state: IteratorState,
  callbackHash: string,
  now: string
): RuntimePortValues => {
  const nextIndex = state.index + 1;
  const done = nextIndex >= state.total;

  return createIteratorResult(state, {
    advanceStamp: now,
    done,
    index: nextIndex,
    lastAckHash: callbackHash,
    status: done ? 'completed' : 'advance_pending',
  });
};

const shouldAdvanceIterator = (callbackInput: unknown, lastAckHash: string): string | null => {
  if (callbackInput === undefined || callbackInput === null) {
    return null;
  }

  const callbackHash = hashRuntimeValue(callbackInput);
  return callbackHash && callbackHash !== lastAckHash ? callbackHash : null;
};

const shouldHoldAdvancedIterator = (state: IteratorState, now: string): boolean =>
  state.prevStatus === 'advance_pending' && state.advanceStamp === now;

const createHoldIteratorResult = (state: IteratorState): RuntimePortValues =>
  createIteratorResult(state, {
    advanceStamp: state.advanceStamp,
    status: 'advance_pending',
  });

const createWaitingIteratorResult = (state: IteratorState): RuntimePortValues =>
  createIteratorResult(state, {
    status: 'waiting_callback',
    value: state.items[state.index],
  });

export const handleIterator: NodeHandler = ({
  nodeInputs,
  prevOutputs,
  now,
}: NodeHandlerContext): RuntimePortValues => {
  const state = resolveIteratorState(coerceIteratorItems(nodeInputs['value']), prevOutputs);
  const callbackInput = coerceInput(nodeInputs['callback']);
  const callbackHash = shouldAdvanceIterator(callbackInput, state.lastAckHash);

  if (state.total === 0) {
    return createIdleIteratorResult(state);
  }

  if (state.index >= state.total) {
    return createCompletedIteratorResult(state);
  }

  if (callbackHash) {
    return createAdvancedIteratorResult(state, callbackHash, now);
  }

  if (shouldHoldAdvancedIterator(state, now)) {
    return createHoldIteratorResult(state);
  }

  return createWaitingIteratorResult(state);
};

import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { coerceInput, getValueAtMappingPath } from '@/shared/lib/ai-paths/core/utils';

import {
  normalizeJsonIntegrityPolicy,
  normalizeJsonLikeValue,
  type JsonIntegrityDiagnostic,
} from '../json-integrity';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

type MapperJsonIntegrityDiagnostic = JsonIntegrityDiagnostic & { port: string };

const normalizeMapperInputValue = (
  port: string,
  value: unknown,
  jsonIntegrityPolicy: ReturnType<typeof normalizeJsonIntegrityPolicy>,
  diagnostics: MapperJsonIntegrityDiagnostic[]
): unknown => {
  const normalized = normalizeJsonLikeValue(value, jsonIntegrityPolicy);
  if (normalized.state === 'repaired' || normalized.state === 'unparseable') {
    diagnostics.push({
      ...normalized.diagnostic,
      port,
    });
  }
  return normalized.value;
};

const buildMapperSources = (
  nodeInputs: NodeHandlerContext['nodeInputs'],
  jsonIntegrityPolicy: ReturnType<typeof normalizeJsonIntegrityPolicy>,
  diagnostics: MapperJsonIntegrityDiagnostic[]
): Record<'context' | 'result' | 'bundle' | 'value', unknown> => ({
  context: normalizeMapperInputValue(
    'context',
    coerceInput(nodeInputs['context']),
    jsonIntegrityPolicy,
    diagnostics
  ),
  result: normalizeMapperInputValue(
    'result',
    coerceInput(nodeInputs['result']),
    jsonIntegrityPolicy,
    diagnostics
  ),
  bundle: normalizeMapperInputValue(
    'bundle',
    coerceInput(nodeInputs['bundle']),
    jsonIntegrityPolicy,
    diagnostics
  ),
  value: normalizeMapperInputValue(
    'value',
    coerceInput(nodeInputs['value']),
    jsonIntegrityPolicy,
    diagnostics
  ),
});

const resolveMapperContextValue = (
  sources: Record<'context' | 'result' | 'bundle' | 'value', unknown>
): unknown => sources['context'] ?? sources['result'] ?? sources['bundle'] ?? sources['value'];

const MAPPER_SOURCE_PATH_PATTERN = /^(context|result|bundle|value)(?:\.|\[|$)/;

const resolveMappedValue = (
  path: string,
  sources: Record<'context' | 'result' | 'bundle' | 'value', unknown>,
  contextValue: unknown,
  jsonIntegrityPolicy: ReturnType<typeof normalizeJsonIntegrityPolicy>
): unknown => {
  if (!path) return undefined;
  if (MAPPER_SOURCE_PATH_PATTERN.test(path)) {
    return getValueAtMappingPath(sources, path, {
      jsonIntegrityPolicy,
    });
  }
  const fromContext = getValueAtMappingPath(contextValue, path, {
    jsonIntegrityPolicy,
  });
  if (fromContext !== undefined) return fromContext;
  return getValueAtMappingPath(sources, path, {
    jsonIntegrityPolicy,
  });
};

const collectConnectedOutputPorts = (nodeId: string, edges: NodeHandlerContext['edges']): Set<string> =>
  new Set<string>(
    edges
      .filter((edge) => edge.from === nodeId && typeof edge.fromPort === 'string')
      .map((edge) => edge.fromPort as string)
  );

export const handleMapper: NodeHandler = ({
  node,
  nodeInputs,
  edges,
  executed,
  runId,
  toast,
  reportAiPathsError,
}: NodeHandlerContext): RuntimePortValues => {
  try {
    const mapperConfig = node.config?.mapper ?? {
      outputs: node.outputs,
      mappings: {},
      jsonIntegrityPolicy: 'repair',
    };
    const jsonIntegrityPolicy = normalizeJsonIntegrityPolicy(mapperConfig.jsonIntegrityPolicy);
    const jsonIntegrityDiagnostics: MapperJsonIntegrityDiagnostic[] = [];
    const sources = buildMapperSources(nodeInputs, jsonIntegrityPolicy, jsonIntegrityDiagnostics);
    const contextValue = resolveMapperContextValue(sources);
    if (contextValue === undefined) return {};

    const mapped: RuntimePortValues = {};
    const unresolvedMappings: string[] = [];
    const connectedOutputPorts = collectConnectedOutputPorts(node.id, edges);

    (mapperConfig.outputs ?? []).forEach((output: string): void => {
      const mapping = mapperConfig.mappings?.[output]?.trim() ?? '';
      const value = mapping
        ? resolveMappedValue(mapping, sources, contextValue, jsonIntegrityPolicy)
        : output === 'value'
          ? contextValue
          : resolveMappedValue(output, sources, contextValue, jsonIntegrityPolicy);
      if (value !== undefined) {
        mapped[output] = value;
        return;
      }
      if (!mapping) return;
      if (connectedOutputPorts.size > 0 && connectedOutputPorts.has(output)) {
        unresolvedMappings.push(`${output} <- ${mapping}`);
      }
    });

    if (unresolvedMappings.length > 0) {
      const key = `${runId}:${node.id}:${unresolvedMappings.join('|')}`;
      if (!executed.mapper.has(key)) {
        executed.mapper.add(key);
        const preview = unresolvedMappings.slice(0, 2).join(', ');
        const suffix =
          unresolvedMappings.length > 2 ? ` and ${unresolvedMappings.length - 2} more` : '';
        toast(
          `JSON Mapper "${node.title ?? node.id}" could not resolve mapping(s): ${preview}${suffix}.`,
          { variant: 'info' }
        );
      }
    }
    if (jsonIntegrityDiagnostics.length > 0) {
      mapped['jsonIntegrity'] = jsonIntegrityDiagnostics;
      if (
        jsonIntegrityPolicy === 'strict' &&
        jsonIntegrityDiagnostics.some((diagnostic) => diagnostic.parseState === 'unparseable')
      ) {
        const unresolvedPorts = jsonIntegrityDiagnostics
          .filter((diagnostic) => diagnostic.parseState === 'unparseable')
          .map((diagnostic) => diagnostic.port);
        const uniquePorts = Array.from(new Set(unresolvedPorts));
        toast(
          `JSON Mapper "${node.title ?? node.id}" received unparseable JSON on ${uniquePorts.join(', ')} (strict mode).`,
          { variant: 'info' }
        );
      }
    }
    return mapped;
  } catch (error) {
    logClientError(error);
    reportAiPathsError(
      error,
      {
        service: 'ai-paths-runtime',
        nodeId: node.id,
        nodeType: node.type,
      },
      `Node ${node.id} failed`
    );
    return {};
  }
};

import type { StringMutatorOperation } from '@/shared/contracts/ai-paths-core/nodes';
import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import {
  cloneValue,
  coerceInput,
  getValueAtMappingPath,
  normalizeMappingPath,
  renderTemplate,
  setValueAtMappingPath,
  safeStringify,
} from '@/shared/lib/ai-paths/core/utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const handleMutator: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const contextValue = coerceInput(nodeInputs['context']) as Record<string, unknown> | undefined;
  if (!contextValue) {
    return {};
  }
  const mutatorConfigRaw = node.config?.['mutator'];
  const mutatorConfig = (mutatorConfigRaw as Record<string, unknown>) ?? {
    path: 'entity.title',
    valueTemplate: '{{value}}',
  };
  const targetPath = normalizeMappingPath((mutatorConfig['path'] as string) ?? '', contextValue);
  if (!targetPath) {
    return { context: contextValue };
  }
  const currentValue = getValueAtMappingPath(contextValue, targetPath);
  const rendered = renderTemplate(
    (mutatorConfig['valueTemplate'] as string) ?? '{{value}}',
    { ...contextValue, ...nodeInputs } as Record<string, unknown>,
    currentValue
  );
  const updated = cloneValue(contextValue);
  setValueAtMappingPath(updated, targetPath, rendered);
  return { context: updated };
};

const normalizeStringMutatorFlags = (
  flags: string | undefined,
  matchMode: 'first' | 'all' | undefined
): string => {
  const allowed = new Set(['d', 'g', 'i', 'm', 's', 'u', 'v', 'y']);
  const seen = new Set<string>();
  const base = Array.from(flags ?? '')
    .filter((ch: string) => allowed.has(ch))
    .filter((ch: string) => {
      if (seen.has(ch)) return false;
      seen.add(ch);
      return true;
    })
    .join('');
  if (matchMode === 'all') {
    return base.includes('g') ? base : `${base}g`;
  }
  if (matchMode === 'first') {
    return base.replace(/g/g, '');
  }
  return base;
};

const applyStringMutatorReplace = (
  current: string,
  operation: Extract<StringMutatorOperation, { type: 'replace' | 'remove' }>
): string => {
  const search = operation.search ?? '';
  if (!search) return current;
  const matchMode = operation.matchMode ?? 'all';
  const replacement = operation.type === 'remove' ? '' : (operation.replace ?? '');
  if (operation.useRegex) {
    const flags = normalizeStringMutatorFlags(operation.flags, matchMode);
    try {
      const regex = new RegExp(search, flags);
      return current.replace(regex, replacement);
    } catch (error) {
      logClientError(error);
      return current;
    }
  }
  if (matchMode === 'all') {
    return current.split(search).join(replacement);
  }
  return current.replace(search, replacement);
};

const applyStringMutatorTrim = (
  current: string,
  operation: Extract<StringMutatorOperation, { type: 'trim' }>
): string => {
  const mode = (operation.mode as string) ?? 'both';
  if (mode === 'start' || mode === 'left') {
    return current.trimStart();
  }
  if (mode === 'end' || mode === 'right') {
    return current.trimEnd();
  }
  return current.trim();
};

const applyStringMutatorCase = (
  current: string,
  operation: Extract<StringMutatorOperation, { type: 'case' }>
): string => {
  const mode = (operation.mode as string) ?? 'lower';
  if (mode === 'upper') {
    return current.toUpperCase();
  }
  if (mode === 'title') {
    return current.replace(
      /\w\S*/g,
      (token: string) => token.charAt(0).toUpperCase() + token.slice(1).toLowerCase()
    );
  }
  return current.toLowerCase();
};

const applyStringMutatorAppend = (
  current: string,
  operation: Extract<StringMutatorOperation, { type: 'append' }>
): string => {
  const value = operation.value ?? '';
  return operation.position === 'prefix' ? `${value}${current}` : `${current}${value}`;
};

const applyStringMutatorSlice = (
  current: string,
  operation: Extract<StringMutatorOperation, { type: 'slice' }>
): string => {
  const start = typeof operation.start === 'number' ? operation.start : undefined;
  const end = typeof operation.end === 'number' ? operation.end : undefined;
  return current.slice(start, end);
};

type StringMutatorOperationHandler = (
  current: string,
  operation: StringMutatorOperation
) => string;

const STRING_MUTATOR_OPERATION_HANDLERS: Partial<
  Record<StringMutatorOperation['type'], StringMutatorOperationHandler>
> = {
  trim: (current, operation) =>
    applyStringMutatorTrim(current, operation as Extract<StringMutatorOperation, { type: 'trim' }>),
  replace: (current, operation) =>
    applyStringMutatorReplace(
      current,
      operation as Extract<StringMutatorOperation, { type: 'replace' }>
    ),
  remove: (current, operation) =>
    applyStringMutatorReplace(
      current,
      operation as Extract<StringMutatorOperation, { type: 'remove' }>
    ),
  case: (current, operation) =>
    applyStringMutatorCase(current, operation as Extract<StringMutatorOperation, { type: 'case' }>),
  append: (current, operation) =>
    applyStringMutatorAppend(
      current,
      operation as Extract<StringMutatorOperation, { type: 'append' }>
    ),
  slice: (current, operation) =>
    applyStringMutatorSlice(current, operation as Extract<StringMutatorOperation, { type: 'slice' }>),
};

const applyStringMutatorOperation = (
  current: string,
  operation: StringMutatorOperation
): string => {
  const handler = STRING_MUTATOR_OPERATION_HANDLERS[operation.type];
  return handler ? handler(current, operation) : current;
};

export const handleStringMutator: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const rawInput = coerceInput(nodeInputs['value'] ?? nodeInputs['prompt'] ?? nodeInputs['result']);
  if (rawInput === undefined || rawInput === null) {
    return {};
  }
  const stringConfigRaw = node.config?.['stringMutator'];
  const stringConfig = (stringConfigRaw as Record<string, unknown>) ?? { operations: [] };
  const operations = Array.isArray(stringConfig['operations'])
    ? (stringConfig['operations'] as StringMutatorOperation[])
    : [];
  const value = operations.reduce(
    (current: string, operation: StringMutatorOperation) =>
      applyStringMutatorOperation(current, operation),
    safeStringify(rawInput)
  );
  return { value };
};

