import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { coerceInput, getValueAtMappingPath } from '@/shared/lib/ai-paths/core/utils';

import { extractImageUrls } from '../../utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

type ParserSourceRecord = Record<string, unknown>;

const normalizeParserOutputValue = (key: string, value: unknown): unknown => {
  const normalizedKey = key.trim().toLowerCase();
  if (normalizedKey === 'images' || normalizedKey === 'imageurls') {
    const urls = extractImageUrls(value);
    return urls.length > 0 ? urls : value;
  }
  return value;
};

const readContextEntitySource = (contextInput: unknown): ParserSourceRecord | undefined =>
  contextInput && typeof contextInput === 'object'
    ? (((contextInput as ParserSourceRecord)['entity'] as ParserSourceRecord | undefined) ??
        ((contextInput as ParserSourceRecord)['entityJson'] as ParserSourceRecord | undefined) ??
        ((contextInput as ParserSourceRecord)['product'] as ParserSourceRecord | undefined))
    : undefined;

const readParserHydrationEntityId = (contextInput: unknown): string | null => {
  if (!contextInput || typeof contextInput !== 'object') return null;
  const contextRecord = contextInput as ParserSourceRecord;
  if (typeof contextRecord['entityId'] === 'string' && contextRecord['entityId'].trim().length > 0) {
    return contextRecord['entityId'].trim();
  }
  if (typeof contextRecord['productId'] === 'string' && contextRecord['productId'].trim().length > 0) {
    return contextRecord['productId'].trim();
  }
  return null;
};

const readParserHydrationEntityType = (
  contextInput: unknown,
  simulationEntityType: string | null
): string | null => {
  if (!contextInput || typeof contextInput !== 'object') return simulationEntityType;
  const contextRecord = contextInput as ParserSourceRecord;
  if (typeof contextRecord['entityType'] === 'string' && contextRecord['entityType'].trim().length > 0) {
    return contextRecord['entityType'].trim();
  }
  return simulationEntityType;
};

const hydrateParserSourceFromContext = async (args: {
  contextInput: unknown;
  simulationEntityType: string | null;
  fetchEntityCached: NodeHandlerContext['fetchEntityCached'];
  reportAiPathsError: NodeHandlerContext['reportAiPathsError'];
  node: NodeHandlerContext['node'];
}): Promise<ParserSourceRecord | undefined> => {
  const contextEntityId = readParserHydrationEntityId(args.contextInput);
  const contextEntityType = readParserHydrationEntityType(
    args.contextInput,
    args.simulationEntityType
  );
  if (!contextEntityId || !contextEntityType) return undefined;

  try {
    const hydrated = await args.fetchEntityCached(contextEntityType, contextEntityId);
    return hydrated && typeof hydrated === 'object' ? hydrated : undefined;
  } catch (error) {
    logClientError(error);
    args.reportAiPathsError(
      error,
      {
        service: 'ai-paths-runtime',
        nodeId: args.node.id,
        nodeType: args.node.type,
        contextEntityId,
        contextEntityType,
      },
      `Parser context hydration failed for ${contextEntityType}:${contextEntityId}`
    );
    return undefined;
  }
};

const isEmptyParserValue = (value: unknown): boolean =>
  value === undefined ||
  value === null ||
  (typeof value === 'string' && value.trim() === '') ||
  (Array.isArray(value) && value.length === 0);

const fallbackParserValue = (source: ParserSourceRecord, key: string): unknown => {
  const normalized = key.trim().toLowerCase();
  if (normalized === 'catalogid') {
    if (typeof source['catalogId'] === 'string' && source['catalogId'].trim().length > 0) {
      return source['catalogId'];
    }
    if (Array.isArray(source['catalogs'])) {
      for (const entry of source['catalogs']) {
        if (!entry || typeof entry !== 'object') continue;
        const catalogId = (entry as Record<string, unknown>)['catalogId'];
        if (typeof catalogId === 'string' && catalogId.trim().length > 0) {
          return catalogId;
        }
      }
    }
    return undefined;
  }
  if (normalized === 'title' || normalized === 'name') {
    return (
      source['title'] ??
      source['name'] ??
      source['name_en'] ??
      source['name_pl'] ??
      source['label'] ??
      source['productName']
    );
  }
  if (normalized === 'images' || normalized === 'imageurls') {
    return (
      source['images'] ??
      source['imageLinks'] ??
      source['media'] ??
      source['gallery'] ??
      source['imageFiles'] ??
      source['photos']
    );
  }
  if (normalized === 'productid' || normalized === 'entityid' || normalized === 'id') {
    return source['id'] ?? source['_id'] ?? source['productId'] ?? source['entityId'];
  }
  if (normalized === 'content_en' || normalized === 'description_en') {
    return (
      source['content_en'] ??
      source['description_en'] ??
      source['description'] ??
      source['content']
    );
  }
  return undefined;
};

const resolveParserOutputValue = (
  source: ParserSourceRecord,
  outputKey: string,
  value: unknown
): unknown => {
  const resolved = isEmptyParserValue(value) ? (fallbackParserValue(source, outputKey) ?? value) : value;
  return resolved !== undefined ? normalizeParserOutputValue(outputKey, resolved) : undefined;
};

const buildParsedOutputs = (args: {
  source: ParserSourceRecord;
  mappings: Record<string, string | undefined>;
}): RuntimePortValues =>
  Object.entries(args.mappings).reduce<RuntimePortValues>(
    (acc: RuntimePortValues, [output, rawMapping]): RuntimePortValues => {
      const key = output.trim();
      if (!key) return acc;
      const mapping = rawMapping?.trim() ?? '';
      const directValue = mapping ? getValueAtMappingPath(args.source, mapping) : args.source[key];
      const resolvedValue = resolveParserOutputValue(args.source, key, directValue);
      if (resolvedValue !== undefined) {
        acc[key] = resolvedValue;
      }
      return acc;
    },
    {}
  );

const buildDeclaredOutputs = (
  outputs: string[],
  sourceRecord: ParserSourceRecord,
  source: ParserSourceRecord
): Record<string, unknown> =>
  outputs.reduce<Record<string, unknown>>(
    (acc: Record<string, unknown>, output: string): Record<string, unknown> => {
      if (output === 'bundle') return acc;
      const outputKey = output.trim();
      if (!outputKey) return acc;
      const resolvedValue = resolveParserOutputValue(source, outputKey, sourceRecord[outputKey]);
      if (resolvedValue !== undefined) {
        acc[outputKey] = resolvedValue;
      }
      return acc;
    },
    {}
  );

const normalizeParserBundle = (source: ParserSourceRecord): ParserSourceRecord => {
  const bundle = { ...source };
  if (bundle['images'] !== undefined) {
    bundle['images'] = normalizeParserOutputValue('images', bundle['images']);
  }
  if (bundle['imageUrls'] !== undefined) {
    bundle['imageUrls'] = normalizeParserOutputValue('imageUrls', bundle['imageUrls']);
  }
  return bundle;
};

const preserveBundleSourceFields = (
  source: ParserSourceRecord,
  parsed: ParserSourceRecord
): ParserSourceRecord => {
  const bundle = { ...parsed };

  if (source['categoryContext'] !== undefined && bundle['categoryContext'] === undefined) {
    bundle['categoryContext'] = source['categoryContext'];
  }

  return bundle;
};

const hasParserMappings = (mappings: Record<string, string | undefined>): boolean =>
  Object.keys(mappings).some((key: string): boolean => Boolean(key.trim()));

const buildBundleParserResult = (args: {
  source: ParserSourceRecord;
  parsed: RuntimePortValues;
  hasMappings: boolean;
  outputs: string[];
}): RuntimePortValues => {
  if (!args.hasMappings || Object.keys(args.parsed).length === 0) {
    const fullBundle = normalizeParserBundle(args.source);
    const declaredOutputs = buildDeclaredOutputs(args.outputs, fullBundle, args.source);
    return { bundle: fullBundle, ...declaredOutputs };
  }

  const preservedBundle = preserveBundleSourceFields(
    args.source,
    args.parsed as ParserSourceRecord
  );
  const extraOutputs = buildDeclaredOutputs(
    args.outputs,
    preservedBundle,
    args.source
  );
  return { bundle: preservedBundle, ...extraOutputs };
};

export const handleParser: NodeHandler = async ({
  node,
  nodeInputs,
  fetchEntityCached,
  simulationEntityType,
  resolvedEntity,
  reportAiPathsError,
}: NodeHandlerContext): Promise<RuntimePortValues> => {
  try {
    const contextInput = coerceInput(nodeInputs['context']);
    const contextEntity = readContextEntitySource(contextInput);
    let source =
      (coerceInput(nodeInputs['entityJson']) as ParserSourceRecord | undefined) ??
      contextEntity ??
      (resolvedEntity as ParserSourceRecord | undefined);

    // In strict mode, hydration by explicit context identity is allowed (not a hidden fallback).
    if (!source) {
      source = await hydrateParserSourceFromContext({
        contextInput,
        simulationEntityType,
        fetchEntityCached,
        reportAiPathsError,
        node,
      });
    }

    if (!source) {
      return {
        status: 'blocked',
        skipReason: 'missing_source',
        blockedReason: 'missing_source',
      };
    }
    const parserConfig = node.config?.parser;
    const mappings = parserConfig?.mappings ?? {};
    const outputMode = parserConfig?.outputMode ?? 'individual';
    const hasMappings = hasParserMappings(mappings);
    const parsed = buildParsedOutputs({
      source,
      mappings: mappings as Record<string, string | undefined>,
    });

    if (outputMode === 'bundle') {
      return buildBundleParserResult({
        source,
        parsed,
        hasMappings,
        outputs: node.outputs,
      });
    }
    return parsed;
  } catch (error) {
    logClientError(error);
    reportAiPathsError(
      error,
      {
        service: 'ai-paths-runtime',
        nodeId: node.id,
        nodeType: node.type,
      },
      `Node ${node.id} failed`
    );
    return {};
  }
};

import type { RegexConfig } from '@/shared/contracts/ai-paths';
import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import { cloneValue, coerceInputArray, renderTemplate, safeStringify } from '@/shared/lib/ai-paths/core/utils';

import {
  normalizeJsonIntegrityPolicy,
  normalizeJsonLikeValue,
  type JsonIntegrityDiagnostic,
  type JsonIntegrityPolicy,
} from '../json-integrity';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


type RegexMatchRecord = {
  input: string;
  match: string | null;
  index: number | null;
  captures: string[];
  groups: Record<string, string> | null;
  key: string;
  extracted: unknown;
};

type RegexJsonIntegrityDiagnostic = JsonIntegrityDiagnostic & {
  key: string;
  index: number | null;
};

const normalizeRegexFlags = (flags: string | undefined): string => {
  if (!flags) return '';
  const allowed = new Set(['d', 'g', 'i', 'm', 's', 'u', 'v', 'y']);
  const seen = new Set<string>();
  const normalized = Array.from(flags)
    .filter((ch: string) => allowed.has(ch))
    .filter((ch: string) => {
      if (seen.has(ch)) return false;
      seen.add(ch);
      return true;
    });
  // Stable-ish ordering to avoid churn.
  const order = ['d', 'g', 'i', 'm', 's', 'u', 'v', 'y'];
  normalized.sort((a: string, b: string) => order.indexOf(a) - order.indexOf(b));
  return normalized.join('');
};

const buildRegexItems = (value: unknown, splitLines: boolean): string[] => {
  const rawValues = coerceInputArray(value);
  const strings = rawValues.flatMap((item: unknown): string[] => {
    if (item === undefined || item === null) return [];
    const asString = typeof item === 'string' ? item : safeStringify(item);
    if (!asString) return [];
    if (!splitLines) return [asString];
    return asString
      .split(/\r?\n/)
      .map((line: string) => line.trim())
      .filter(Boolean);
  });
  return strings;
};

const resolveRegexSelectorKey = (selector: string | undefined): string =>
  (selector ?? 'match').trim();

const resolveRegexRawGroups = (match: RegExpExecArray): Record<string, unknown> | null =>
  match.groups && typeof match.groups === 'object'
    ? (match.groups as Record<string, unknown>)
    : null;

const normalizeRegexGroupValue = (value: unknown): string => {
  if (typeof value === 'string') return value;
  if (value === undefined || value === null) return '';
  return safeStringify(value);
};

const normalizeRegexGroups = (
  rawGroups: Record<string, unknown> | null
): Record<string, string> | null =>
  rawGroups
    ? (Object.fromEntries(
      Object.entries(rawGroups).map(([name, value]: [string, unknown]) => [
        name,
        normalizeRegexGroupValue(value),
      ])
    ) as Record<string, string>)
    : null;

const resolveRegexIndexedSelection = (
  match: RegExpExecArray,
  key: string
): { handled: boolean; value: unknown } => {
  const asIndex = Number(key);
  if (!Number.isInteger(asIndex)) return { handled: false, value: null };
  return {
    handled: true,
    value: match[asIndex] ?? null,
  };
};

const resolveRegexGroupSelection = (
  rawGroups: Record<string, unknown> | null,
  key: string
): unknown => {
  const candidate = rawGroups ? rawGroups[key] : undefined;
  if (typeof candidate === 'string') return candidate;
  if (candidate === undefined || candidate === null) return null;
  return safeStringify(candidate);
};

const resolveRegexSelection = (match: RegExpExecArray, selector: string | undefined): unknown => {
  const key = resolveRegexSelectorKey(selector);
  if (!key || key === 'match' || key === '0') {
    return match[0] ?? null;
  }
  if (key === 'captures') {
    return match.slice(1).map((value: string | undefined) => value ?? '');
  }
  const rawGroups = resolveRegexRawGroups(match);
  const groups = normalizeRegexGroups(rawGroups);
  if (key === 'groups') {
    return groups;
  }
  const indexed = resolveRegexIndexedSelection(match, key);
  if (indexed.handled) return indexed.value;
  return resolveRegexGroupSelection(rawGroups, key);
};

const parseRegexExtractedJson = (
  value: unknown,
  policy: JsonIntegrityPolicy
): { value: unknown; diagnostics: JsonIntegrityDiagnostic[] } => {
  if (Array.isArray(value)) {
    const diagnostics: JsonIntegrityDiagnostic[] = [];
    const parsed = value.map((entry: unknown): unknown => {
      const next = parseRegexExtractedJson(entry, policy);
      diagnostics.push(...next.diagnostics);
      return next.value;
    });
    return { value: parsed, diagnostics };
  }
  const normalized = normalizeJsonLikeValue(value, policy);
  const diagnostics =
    normalized.state === 'repaired' || normalized.state === 'unparseable'
      ? [normalized.diagnostic]
      : [];
  return {
    value: normalized.value,
    diagnostics,
  };
};

const resolveGroupKey = (match: RegExpExecArray, groupBy: string | undefined): string | null => {
  const selected = resolveRegexSelection(match, groupBy);
  if (selected === undefined || selected === null) return null;
  if (typeof selected === 'string') return selected;
  return safeStringify(selected);
};

const buildRegexMatchRecord = (
  input: string,
  match: RegExpExecArray | null,
  key: string,
  extracted: unknown
): RegexMatchRecord => ({
  input,
  match: match?.[0] ?? null,
  index: typeof match?.index === 'number' ? match.index : null,
  captures: match ? match.slice(1).map((value: string | undefined) => value ?? '') : [],
  groups: match ? normalizeRegexGroups(resolveRegexRawGroups(match)) : null,
  key,
  extracted,
});

export const handleRegex: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const regexConfig: RegexConfig = node.config?.regex ?? {
    pattern: '',
    flags: 'g',
    mode: 'group',
    matchMode: 'first',
    groupBy: 'match',
    outputMode: 'object',
    includeUnmatched: true,
    unmatchedKey: '__unmatched__',
    splitLines: true,
    sampleText: '',
    aiPrompt: '',
  };

  const rawInput = nodeInputs['value'] ?? nodeInputs['prompt'];
  const splitLines = regexConfig.splitLines ?? true;
  const items = buildRegexItems(rawInput, splitLines);

  const pattern = (regexConfig.pattern ?? '').trim();
  const flags = normalizeRegexFlags(regexConfig.flags);
  const mode = regexConfig.mode ?? 'group';
  const isExtractMode = mode === 'extract' || mode === 'extract_json';
  const matchMode = regexConfig.matchMode ?? 'first';
  const groupBy = regexConfig.groupBy ?? 'match';
  const includeUnmatched = regexConfig.includeUnmatched ?? true;
  const unmatchedKey = (regexConfig.unmatchedKey ?? '__unmatched__').trim() || '__unmatched__';
  const jsonIntegrityPolicy = normalizeJsonIntegrityPolicy(regexConfig.jsonIntegrityPolicy);
  const jsonIntegrityDiagnostics: RegexJsonIntegrityDiagnostic[] = [];

  const textForPrompt = typeof rawInput === 'string' ? rawInput : items.join('\n');
  const aiPromptTemplate = regexConfig.aiPrompt ?? '';
  const aiPrompt = aiPromptTemplate.trim()
    ? renderTemplate(
      aiPromptTemplate,
        { ...nodeInputs, text: textForPrompt, lines: items } as Record<string, unknown>,
        textForPrompt
    )
    : '';
  const aiAutoRun = regexConfig.aiAutoRun ?? false;

  if (!pattern) {
    const emptyGrouped = regexConfig.outputMode === 'array' ? [] : {};
    return {
      grouped: emptyGrouped,
      matches: [],
      value: isExtractMode ? null : emptyGrouped,
      ...(aiAutoRun && aiPrompt ? { aiPrompt } : {}),
    };
  }

  let compiled: RegExp;
  try {
    compiled = new RegExp(pattern, flags);
  } catch (error) {
    logClientError(error);
    const emptyGrouped = regexConfig.outputMode === 'array' ? [] : {};
    return {
      grouped: emptyGrouped,
      matches: [],
      value: isExtractMode ? null : emptyGrouped,
      ...(aiAutoRun && aiPrompt ? { aiPrompt } : {}),
    };
  }

  const matches: RegexMatchRecord[] = [];
  const groupedMap = new Map<string, RegexMatchRecord[]>();
  const nonGlobalRegex =
    matchMode === 'all'
      ? compiled
      : compiled.flags.includes('g')
        ? new RegExp(compiled.source, compiled.flags.replace('g', ''))
        : compiled;

  const pushGrouped = (key: string, record: RegexMatchRecord): void => {
    const current = groupedMap.get(key) ?? [];
    current.push(record);
    groupedMap.set(key, current);
  };
  const resolveExtractedValue = (
    selectedValue: unknown,
    context: {
      key: string;
      index: number | null;
    }
  ): unknown => {
    if (mode !== 'extract_json') return selectedValue;
    const parsed = parseRegexExtractedJson(selectedValue, jsonIntegrityPolicy);
    if (parsed.diagnostics.length > 0) {
      parsed.diagnostics.forEach((diagnostic: JsonIntegrityDiagnostic): void => {
        jsonIntegrityDiagnostics.push({
          ...diagnostic,
          key: context.key,
          index: context.index,
        });
      });
    }
    return parsed.value;
  };

  if (matchMode === 'first_overall') {
    let found = false;
    for (const input of items) {
      nonGlobalRegex.lastIndex = 0;
      const match = nonGlobalRegex.exec(input);
      if (!match) continue;
      found = true;
      const key = resolveGroupKey(match, groupBy) ?? unmatchedKey;
      const selectedValue = resolveRegexSelection(match, groupBy);
      const extracted = resolveExtractedValue(selectedValue, {
        key,
        index: typeof match.index === 'number' ? match.index : null,
      });
      const record = buildRegexMatchRecord(input, match, key, extracted);
      matches.push(record);
      pushGrouped(key, record);
      break;
    }

    if (!found && includeUnmatched && items.length > 0) {
      const record = buildRegexMatchRecord(items[0] ?? '', null, unmatchedKey, null);
      matches.push(record);
      pushGrouped(unmatchedKey, record);
    }
  } else {
    items.forEach((input: string) => {
      if (matchMode === 'all') {
        const flagsWithG = compiled.flags.includes('g') ? compiled.flags : `${compiled.flags}g`;
        const regexAll = new RegExp(compiled.source, flagsWithG);
        let found = false;
        let match: RegExpExecArray | null;
        while ((match = regexAll.exec(input)) !== null) {
          found = true;
          const key = resolveGroupKey(match, groupBy) ?? unmatchedKey;
          const selectedValue = resolveRegexSelection(match, groupBy);
          const extracted = resolveExtractedValue(selectedValue, {
            key,
            index: typeof match.index === 'number' ? match.index : null,
          });
          const record = buildRegexMatchRecord(input, match, key, extracted);
          matches.push(record);
          pushGrouped(key, record);
          // Avoid infinite loops on zero-length matches.
          if (match[0] === '') {
            regexAll.lastIndex = Math.min(input.length, regexAll.lastIndex + 1);
          }
        }
        if (!found && includeUnmatched) {
          const record = buildRegexMatchRecord(input, null, unmatchedKey, null);
          matches.push(record);
          pushGrouped(unmatchedKey, record);
        }
        return;
      }

      // matchMode === "first"
      nonGlobalRegex.lastIndex = 0;
      const match = nonGlobalRegex.exec(input);
      if (!match) {
        if (!includeUnmatched) return;
        const record = buildRegexMatchRecord(input, null, unmatchedKey, null);
        matches.push(record);
        pushGrouped(unmatchedKey, record);
        return;
      }
      const key = resolveGroupKey(match, groupBy) ?? unmatchedKey;
      const selectedValue = resolveRegexSelection(match, groupBy);
      const extracted = resolveExtractedValue(selectedValue, {
        key,
        index: typeof match.index === 'number' ? match.index : null,
      });
      const record = buildRegexMatchRecord(input, match, key, extracted);
      matches.push(record);
      pushGrouped(key, record);
    });
  }

  const groupedObject = Object.fromEntries(groupedMap.entries());
  const grouped =
    regexConfig.outputMode === 'array'
      ? Object.entries(groupedObject).map(([key, items]: [string, RegexMatchRecord[]]) => ({
        key,
        items,
      }))
      : groupedObject;
  const extractedValues = matches
    .filter((record: RegexMatchRecord): boolean => record.match !== null)
    .map((record: RegexMatchRecord): unknown => cloneValue(record.extracted));
  const extractedValue =
    extractedValues.length <= 1 ? (extractedValues[0] ?? null) : extractedValues;

  return {
    grouped,
    matches,
    value: isExtractMode ? extractedValue : grouped,
    ...(jsonIntegrityDiagnostics.length > 0 ? { jsonIntegrity: jsonIntegrityDiagnostics } : {}),
    ...(aiAutoRun && aiPrompt ? { aiPrompt } : {}),
  };
};

import type {
  NodeHandler,
  NodeHandlerContext,
  RuntimePortValues,
} from '@/shared/contracts/ai-paths-runtime';
import type {
  PromptAppliedFix,
  PromptValidationIssue,
  PromptValidationRule,
  PromptValidationScope,
} from '@/shared/contracts/prompt-engine';
import {
  coerceInput,
  getValueAtMappingPath,
  normalizeMappingPath,
  safeStringify,
} from '@/shared/lib/ai-paths/core/utils';
import {
  preparePromptValidationRuntime,
  validateProgrammaticPromptWithRuntime,
} from '@/shared/lib/prompt-engine';
import { formatProgrammaticPrompt } from '@/shared/lib/prompt-engine';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const handleValidator: NodeHandler = ({
  node,
  nodeInputs,
}: NodeHandlerContext): RuntimePortValues => {
  const contextValue = coerceInput(nodeInputs['context']) as Record<string, unknown> | undefined;
  if (!contextValue) {
    return {};
  }
  const validatorConfig = node.config?.validator ?? {
    requiredPaths: ['entity.id'],
    mode: 'all',
  };
  const required = (validatorConfig.requiredPaths ?? []).map((path: string): string | null =>
    normalizeMappingPath(path, contextValue)
  );
  const missing = required.filter((path: string | null): boolean => {
    if (!path) return false;
    const value = getValueAtMappingPath(contextValue, path);
    if (value === undefined || value === null) return true;
    if (typeof value === 'string' && value.trim() === '') return true;
    return false;
  });
  const valid =
    validatorConfig.mode === 'any' ? missing.length < required.length : missing.length === 0;
  return {
    context: contextValue,
    valid,
    errors: missing as string[],
  };
};

type ValidationPatternIssue = PromptValidationIssue;
type ValidationPatternRule = PromptValidationRule;

const VALIDATION_PATTERN_DEFAULTS = {
  source: 'global_stack',
  stackId: '',
  scope: 'global',
  includeLearnedRules: true,
  runtimeMode: 'validate_only',
  failPolicy: 'block_on_error',
  inputPort: 'auto',
  outputPort: 'value',
  maxAutofixPasses: 1,
  includeRuleIds: [] as string[],
  localListName: 'Path Local Validation List',
  localListDescription: '',
  rules: [] as ValidationPatternRule[],
  learnedRules: [] as ValidationPatternRule[],
} as const;

const VALIDATION_PATTERN_TEXT_KEYS = [
  'text',
  'prompt',
  'value',
  'result',
  'content',
  'content_en',
] as const;

const coerceValidationPatternScalar = (value: unknown): string | null => {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  return null;
};

const coerceValidationPatternText = (value: unknown): string => {
  if (value === undefined || value === null) return '';

  const scalar = coerceValidationPatternScalar(value);
  if (scalar !== null) return scalar;
  if (typeof value !== 'object') return safeStringify(value);

  const record = value as Record<string, unknown>;

  for (const key of VALIDATION_PATTERN_TEXT_KEYS) {
    const preferredText = coerceValidationPatternScalar(record[key]);
    if (preferredText !== null) {
      return preferredText;
    }
  }

  return safeStringify(value);
};

const resolveValidationPatternInput = (
  configuredPort: string | undefined,
  nodeInputs: RuntimePortValues
): { sourcePort: string; rawValue: unknown; text: string } => {
  const explicitPort = (configuredPort ?? 'auto').trim();
  const portOrder =
    explicitPort === 'auto'
      ? ['value', 'prompt', 'result', 'context']
      : [explicitPort, 'value', 'prompt', 'result', 'context'];
  for (const port of portOrder) {
    const rawValue = coerceInput(nodeInputs[port]);
    if (rawValue === undefined || rawValue === null) continue;
    return {
      sourcePort: port,
      rawValue,
      text: coerceValidationPatternText(rawValue),
    };
  }
  return {
    sourcePort: explicitPort === 'auto' ? 'value' : explicitPort,
    rawValue: undefined,
    text: '',
  };
};

const normalizeValidationPatternRules = (
  rules: ValidationPatternRule[] | undefined,
  includeRuleIds: Set<string> | null
): ValidationPatternRule[] => {
  if (!Array.isArray(rules) || rules.length === 0) return [];
  if (!includeRuleIds || includeRuleIds.size === 0) return rules;
  return rules.filter((rule: ValidationPatternRule): boolean => includeRuleIds.has(rule.id));
};

const summarizeValidationIssues = (issues: ValidationPatternIssue[]): string[] =>
  issues.map(
    (issue: ValidationPatternIssue): string =>
      `[${issue.severity}] ${issue.title}: ${issue.message}`
  );

const buildValidationPatternOutputPorts = (args: {
  outputPort: 'value' | 'result';
  inputText: string;
  outputText: string;
}): { value: string; result: string } => {
  const preferred =
    args.outputPort === 'result'
      ? { value: args.inputText, result: args.outputText }
      : { value: args.outputText, result: args.inputText };
  return preferred;
};

export const handleValidationPattern: NodeHandler = ({
  node,
  nodeInputs,
  reportAiPathsError,
}: NodeHandlerContext): RuntimePortValues => {
  const config = {
    ...VALIDATION_PATTERN_DEFAULTS,
    ...(node.config?.validationPattern ?? {}),
  };
  const resolvedInput = resolveValidationPatternInput(config.inputPort, nodeInputs);
  const sourceText = resolvedInput.text;
  const contextValue = coerceInput(nodeInputs['context']);

  if (sourceText.trim().length === 0) {
    const outputs = buildValidationPatternOutputPorts({
      outputPort: config.outputPort as 'value' | 'result',
      inputText: sourceText,
      outputText: sourceText,
    });
    return {
      ...outputs,
      ...(contextValue !== undefined ? { context: contextValue } : {}),
      valid: true,
      errors: [],
      bundle: {
        skipped: true,
        reason: 'empty_input',
        sourcePort: resolvedInput.sourcePort,
      },
    };
  }

  const includeRuleIds = (config.includeRuleIds ?? [])
    .map((value: string): string => value.trim())
    .filter(Boolean);
  const includeRuleIdSet = includeRuleIds.length > 0 ? new Set<string>(includeRuleIds) : null;
  const runtimeRules = normalizeValidationPatternRules(
    config.rules as ValidationPatternRule[],
    includeRuleIdSet
  );
  const runtimeLearnedRules =
    config.includeLearnedRules === false
      ? []
      : normalizeValidationPatternRules(
          config.learnedRules as ValidationPatternRule[],
          includeRuleIdSet
      );

  if (runtimeRules.length === 0 && runtimeLearnedRules.length === 0) {
    const outputs = buildValidationPatternOutputPorts({
      outputPort: config.outputPort as 'value' | 'result',
      inputText: sourceText,
      outputText: sourceText,
    });
    return {
      ...outputs,
      ...(contextValue !== undefined ? { context: contextValue } : {}),
      valid: true,
      errors: [],
      bundle: {
        skipped: true,
        reason: 'no_rules_configured',
        source: config.source,
        stackId: config.stackId,
        scope: config.scope,
      },
    };
  }

  const validationSettings = {
    enabled: true,
    rules: runtimeRules,
    learnedRules: runtimeLearnedRules,
  };
  const scope: PromptValidationScope = (config.scope as PromptValidationScope) ?? 'global';
  const runtime = preparePromptValidationRuntime(validationSettings, { scope });

  try {
    let workingText = sourceText;
    let issues = validateProgrammaticPromptWithRuntime(workingText, runtime);
    const appliedFixes: PromptAppliedFix[] = [];
    const maxAutofixPasses = Math.max(
      1,
      Math.min(
        10,
        typeof config.maxAutofixPasses === 'number' && Number.isFinite(config.maxAutofixPasses)
          ? Math.trunc(config.maxAutofixPasses)
          : 1
      )
    );
    if (config.runtimeMode === 'validate_and_autofix' && issues.length > 0) {
      for (let pass = 0; pass < maxAutofixPasses; pass += 1) {
        const formatted = formatProgrammaticPrompt(
          workingText,
          validationSettings,
          { scope },
          {
            preparedRuntime: runtime,
            precomputedIssuesBefore: issues,
            enableIncrementalValidation: true,
          }
        );
        if (!formatted.changed) break;
        workingText = formatted.prompt;
        if (formatted.applied.length > 0) {
          appliedFixes.push(...formatted.applied);
        }
        issues = validateProgrammaticPromptWithRuntime(workingText, runtime);
        if (issues.length === 0) break;
      }
    }

    const blockingIssueCount = issues.filter(
      (issue: ValidationPatternIssue): boolean => issue.severity === 'error'
    ).length;
    const warningIssueCount = issues.filter(
      (issue: ValidationPatternIssue): boolean => issue.severity === 'warning'
    ).length;
    const valid = config.failPolicy === 'report_only' ? true : blockingIssueCount === 0;
    const errors = summarizeValidationIssues(issues);
    const outputs = buildValidationPatternOutputPorts({
      outputPort: config.outputPort as 'value' | 'result',
      inputText: sourceText,
      outputText: workingText,
    });

    return {
      ...outputs,
      ...(contextValue !== undefined ? { context: contextValue } : {}),
      valid,
      errors,
      bundle: {
        sourcePort: resolvedInput.sourcePort,
        source: config.source,
        stackId: config.stackId,
        scope,
        runtimeMode: config.runtimeMode,
        failPolicy: config.failPolicy,
        issueCount: issues.length,
        blockingIssueCount,
        warningIssueCount,
        appliedFixes,
        issues,
        input: sourceText,
        output: workingText,
      },
    };
  } catch (error) {
    logClientError(error);
    reportAiPathsError(
      error,
      {
        service: 'ai-paths-runtime',
        nodeId: node.id,
        nodeType: node.type,
      },
      `Node ${node.id} failed`
    );
    const outputs = buildValidationPatternOutputPorts({
      outputPort: config.outputPort as 'value' | 'result',
      inputText: sourceText,
      outputText: sourceText,
    });
    return {
      ...outputs,
      ...(contextValue !== undefined ? { context: contextValue } : {}),
      valid: false,
      errors: ['Validation Pattern runtime failed.'],
      bundle: {
        sourcePort: resolvedInput.sourcePort,
        source: config.source,
        stackId: config.stackId,
        scope,
        runtimeMode: config.runtimeMode,
        failPolicy: config.failPolicy,
        issueCount: 0,
        blockingIssueCount: 0,
        warningIssueCount: 0,
        appliedFixes: [],
        issues: [],
        input: sourceText,
        output: sourceText,
      },
    };
  }
};

import type { NodeHandler } from '@/shared/contracts/ai-paths-runtime';
import nodeCodeObjectV3ContractsJson from '@docs/ai-paths/node-code-objects-v3/contracts.json';


import type { ResolveCodeObjectHandlerArgs } from './node-runtime-kernel';

export type NodeCodeObjectV3ContractEntry = {
  nodeType: string;
  codeObjectId: string;
  runtimeStrategy: string;
  executionAdapter: string;
  legacyHandlerKey: string | null;
};

export const NODE_CODE_OBJECT_V3_EXECUTION_ADAPTERS = [
  'native_handler_registry',
] as const;
export type NodeCodeObjectV3ExecutionAdapter =
  (typeof NODE_CODE_OBJECT_V3_EXECUTION_ADAPTERS)[number];

const asRecord = (value: unknown): Record<string, unknown> | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  return value as Record<string, unknown>;
};

const asTrimmedString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const parseContractEntry = ({
  nodeType,
  value,
}: {
  nodeType: string;
  value: unknown;
}): NodeCodeObjectV3ContractEntry | null => {
  const record = asRecord(value);
  if (!record) return null;
  const codeObjectId = asTrimmedString(record['codeObjectId']);
  const runtimeStrategy = asTrimmedString(record['runtimeStrategy']);
  const executionAdapter = asTrimmedString(record['executionAdapter']);
  const legacyHandlerKey = asTrimmedString(record['legacyHandlerKey']);
  if (!codeObjectId || !runtimeStrategy || !executionAdapter) return null;
  return {
    nodeType,
    codeObjectId,
    runtimeStrategy,
    executionAdapter,
    legacyHandlerKey,
  };
};

const parseContractsByCodeObjectId = (
  input: unknown
): Map<string, NodeCodeObjectV3ContractEntry> => {
  const root = asRecord(input);
  const contracts = asRecord(root?.['contracts']) ?? {};
  const entries = Object.entries(contracts)
    .map(([rawNodeType, value]): NodeCodeObjectV3ContractEntry | null => {
      const nodeType = asTrimmedString(rawNodeType);
      if (!nodeType) return null;
      return parseContractEntry({ nodeType, value });
    })
    .filter((entry): entry is NodeCodeObjectV3ContractEntry => Boolean(entry))
    .map((entry): [string, NodeCodeObjectV3ContractEntry] => [entry.codeObjectId, entry]);
  return new Map(entries);
};

const NODE_CODE_OBJECT_V3_CONTRACTS_BY_CODE_OBJECT_ID = parseContractsByCodeObjectId(
  nodeCodeObjectV3ContractsJson
);

const normalizeNodeType = (value: unknown): string =>
  typeof value === 'string' ? value.trim() : '';

const normalizeCodeObjectId = (value: unknown): string =>
  typeof value === 'string' ? value.trim() : '';

export const resolveNodeCodeObjectV3ContractByCodeObjectId = (
  codeObjectIdInput: string
): NodeCodeObjectV3ContractEntry | null => {
  const codeObjectId = normalizeCodeObjectId(codeObjectIdInput);
  if (!codeObjectId) return null;
  return NODE_CODE_OBJECT_V3_CONTRACTS_BY_CODE_OBJECT_ID.get(codeObjectId) ?? null;
};

export const listNodeCodeObjectV3NativeRegistryContracts =
  (): readonly NodeCodeObjectV3ContractEntry[] =>
    Array.from(NODE_CODE_OBJECT_V3_CONTRACTS_BY_CODE_OBJECT_ID.values())
      .filter(
        (entry: NodeCodeObjectV3ContractEntry): boolean =>
          entry.runtimeStrategy === 'code_object_v3' &&
          entry.executionAdapter === 'native_handler_registry'
      )
      .sort((left, right) => left.codeObjectId.localeCompare(right.codeObjectId));

export type CreateNodeCodeObjectV3ContractResolverArgs = {
  resolveNativeCodeObjectHandler?:
    | ((args: ResolveCodeObjectHandlerArgs) => NodeHandler | null)
    | undefined;
};

export const createNodeCodeObjectV3ContractResolver = ({
  resolveNativeCodeObjectHandler,
}: CreateNodeCodeObjectV3ContractResolverArgs): ((
  args: ResolveCodeObjectHandlerArgs
) => NodeHandler | null) => {
  return ({
    nodeType: nodeTypeInput,
    codeObjectId: codeObjectIdInput,
  }: ResolveCodeObjectHandlerArgs) => {
    const nodeType = normalizeNodeType(nodeTypeInput);
    const codeObjectId = normalizeCodeObjectId(codeObjectIdInput);
    if (!nodeType || !codeObjectId) return null;

    const contract = resolveNodeCodeObjectV3ContractByCodeObjectId(codeObjectId);
    if (!contract) return null;
    if (contract.nodeType !== nodeType) return null;
    if (contract.runtimeStrategy !== 'code_object_v3') return null;

    if (typeof resolveNativeCodeObjectHandler !== 'function') return null;
    return resolveNativeCodeObjectHandler({ nodeType, codeObjectId });
  };
};

import type {
  NodeHandler,
  NodeRuntimeResolutionSource,
  NodeRuntimeResolutionStrategy,
  NodeRuntimeResolutionTelemetry,
} from '@/shared/contracts/ai-paths-runtime';

import { resolveNodeCodeObjectV3ContractByCodeObjectId } from './node-code-object-v3-legacy-bridge';

export const NODE_RUNTIME_KERNEL_STRATEGIES = ['code_object_v3'] as const;
export type NodeRuntimeKernelStrategy = (typeof NODE_RUNTIME_KERNEL_STRATEGIES)[number];

export const NODE_RUNTIME_KERNEL_CANONICAL_NODE_TYPES = [
  'agent',
  'api_advanced',
  'audio_oscillator',
  'audio_speaker',
  'constant',
  'context',
  'bundle',
  'compare',
  'database',
  'delay',
  'db_schema',
  'fetcher',
  'gate',
  'http',
  'iterator',
  'learner_agent',
  'mapper',
  'math',
  'model',
  'mutator',
  'notification',
  'parser',
  'playwright',
  'poll',
  'prompt',
  'regex',
  'router',
  'simulation',
  'string_mutator',
  'template',
  'trigger',
  'validation_pattern',
  'validator',
  'viewer',
] as const;

export type NodeRuntimeKernelDescriptor = {
  nodeType: string;
  strategy: NodeRuntimeKernelStrategy;
  source: NodeRuntimeResolutionSource;
  codeObjectId: string | null;
  handler: NodeHandler | null;
};

export type NodeRuntimeKernel = {
  resolveDescriptor: (nodeType: string) => NodeRuntimeKernelDescriptor;
  resolveHandler: (nodeType: string) => NodeHandler | null;
};

export type ResolveCodeObjectHandlerArgs = {
  nodeType: string;
  codeObjectId: string;
};

export type CreateNodeRuntimeKernelArgs = {
  resolveLegacyHandler: (nodeType: string) => NodeHandler | null;
  resolveCodeObjectHandler?:
    | ((args: ResolveCodeObjectHandlerArgs) => NodeHandler | null)
    | undefined;
  resolveOverrideHandler?: ((nodeType: string) => NodeHandler | null) | undefined;
  runtimeKernelNodeTypes?: readonly string[] | undefined;
};

const normalizeNodeType = (nodeType: string): string =>
  typeof nodeType === 'string' ? nodeType.trim() : '';

const buildV3CodeObjectId = (nodeType: string): string =>
  `ai-paths.node-code-object.${nodeType}.v3`;

const toPublicRuntimeStrategy = (): NodeRuntimeResolutionStrategy => 'code_object_v3';

export const isNodeRuntimeKernelCanonicalType = ({
  nodeType,
  runtimeKernelNodeTypes,
}: {
  nodeType: string;
  runtimeKernelNodeTypes: Set<string>;
}): boolean => runtimeKernelNodeTypes.has(nodeType);

const isCodeObjectResolutionEnabled = ({
  nodeType,
  runtimeKernelNodeTypes,
}: {
  nodeType: string;
  runtimeKernelNodeTypes: Set<string>;
}): boolean => isNodeRuntimeKernelCanonicalType({ nodeType, runtimeKernelNodeTypes });

const resolveCodeObjectId = ({
  nodeType,
  runtimeKernelNodeTypes,
}: {
  nodeType: string;
  runtimeKernelNodeTypes: Set<string>;
}): string | null =>
  isCodeObjectResolutionEnabled({ nodeType, runtimeKernelNodeTypes })
    ? buildV3CodeObjectId(nodeType)
    : null;

const buildDescriptor = ({
  nodeType,
  handler,
  source,
  runtimeKernelNodeTypes,
}: {
  nodeType: string;
  handler: NodeHandler | null;
  source: NodeRuntimeResolutionSource;
  runtimeKernelNodeTypes: Set<string>;
}): NodeRuntimeKernelDescriptor => {
  return {
    nodeType,
    strategy: 'code_object_v3',
    source,
    codeObjectId: resolveCodeObjectId({ nodeType, runtimeKernelNodeTypes }),
    handler,
  };
};

export const toNodeRuntimeResolutionTelemetry = (
  descriptor: NodeRuntimeKernelDescriptor
): NodeRuntimeResolutionTelemetry => ({
  runtimeStrategy: toPublicRuntimeStrategy(),
  runtimeResolutionSource: descriptor.source,
  runtimeCodeObjectId: descriptor.codeObjectId,
});

type ResolveDescriptorContext = {
  nodeType: string;
  resolveCodeObjectHandler?: CreateNodeRuntimeKernelArgs['resolveCodeObjectHandler'];
  resolveLegacyHandler: CreateNodeRuntimeKernelArgs['resolveLegacyHandler'];
  resolveOverrideHandler?: CreateNodeRuntimeKernelArgs['resolveOverrideHandler'];
  runtimeKernelNodeTypes: Set<string>;
};

type BuildKernelDescriptor = (args: {
  handler: NodeHandler | null;
  nodeType: string;
  source: NodeRuntimeResolutionSource;
}) => NodeRuntimeKernelDescriptor;

const createDescriptorBuilder =
  (runtimeKernelNodeTypes: Set<string>) =>
  (
    args: {
      handler: NodeHandler | null;
      nodeType: string;
      source: NodeRuntimeResolutionSource;
    }
  ): NodeRuntimeKernelDescriptor =>
    buildDescriptor({
      ...args,
      runtimeKernelNodeTypes,
    });

const resolveOverrideDescriptor = ({
  buildDescriptor,
  nodeType,
  resolveOverrideHandler,
}: {
  buildDescriptor: BuildKernelDescriptor;
  nodeType: string;
  resolveOverrideHandler?: CreateNodeRuntimeKernelArgs['resolveOverrideHandler'];
}): NodeRuntimeKernelDescriptor | null => {
  if (typeof resolveOverrideHandler !== 'function') {
    return null;
  }

  const override = resolveOverrideHandler(nodeType);

  return override
    ? buildDescriptor({
        nodeType,
        handler: override,
        source: 'override',
      })
    : null;
};

const resolveCodeObjectDescriptor = ({
  buildDescriptor,
  nodeType,
  resolveCodeObjectHandler,
  runtimeKernelNodeTypes,
}: {
  buildDescriptor: BuildKernelDescriptor;
  nodeType: string;
  resolveCodeObjectHandler?: CreateNodeRuntimeKernelArgs['resolveCodeObjectHandler'];
  runtimeKernelNodeTypes: Set<string>;
}): NodeRuntimeKernelDescriptor | null => {
  if (
    !isCodeObjectResolutionEnabled({
      nodeType,
      runtimeKernelNodeTypes,
    })
  ) {
    return null;
  }

  const codeObjectId = buildV3CodeObjectId(nodeType);

  if (typeof resolveCodeObjectHandler === 'function') {
    const codeObjectHandler = resolveCodeObjectHandler({
      nodeType,
      codeObjectId,
    });

    if (codeObjectHandler) {
      return buildDescriptor({
        nodeType,
        handler: codeObjectHandler,
        source: 'registry',
      });
    }
  }

  return resolveNodeCodeObjectV3ContractByCodeObjectId(codeObjectId)
    ? buildDescriptor({
        nodeType,
        handler: null,
        source: 'missing',
      })
    : null;
};

const resolveLegacyDescriptor = ({
  buildDescriptor,
  nodeType,
  resolveLegacyHandler,
}: {
  buildDescriptor: BuildKernelDescriptor;
  nodeType: string;
  resolveLegacyHandler: CreateNodeRuntimeKernelArgs['resolveLegacyHandler'];
}): NodeRuntimeKernelDescriptor => {
  const handler = resolveLegacyHandler(nodeType);

  return buildDescriptor({
    nodeType,
    handler,
    source: handler ? 'registry' : 'missing',
  });
};

const resolveNodeRuntimeDescriptor = ({
  nodeType,
  resolveCodeObjectHandler,
  resolveLegacyHandler,
  resolveOverrideHandler,
  runtimeKernelNodeTypes,
}: ResolveDescriptorContext): NodeRuntimeKernelDescriptor => {
  const buildKernelDescriptor = createDescriptorBuilder(runtimeKernelNodeTypes);
  const overrideDescriptor = resolveOverrideDescriptor({
    buildDescriptor: buildKernelDescriptor,
    nodeType,
    resolveOverrideHandler,
  });

  if (overrideDescriptor) {
    return overrideDescriptor;
  }

  const codeObjectDescriptor = resolveCodeObjectDescriptor({
    buildDescriptor: buildKernelDescriptor,
    nodeType,
    resolveCodeObjectHandler,
    runtimeKernelNodeTypes,
  });

  if (codeObjectDescriptor) {
    return codeObjectDescriptor;
  }

  return resolveLegacyDescriptor({
    buildDescriptor: buildKernelDescriptor,
    nodeType,
    resolveLegacyHandler,
  });
};

export const createNodeRuntimeKernel = ({
  resolveLegacyHandler,
  resolveCodeObjectHandler,
  resolveOverrideHandler,
  runtimeKernelNodeTypes,
}: CreateNodeRuntimeKernelArgs): NodeRuntimeKernel => {
  const resolvedRuntimeKernelNodeTypes = new Set<string>(
    (runtimeKernelNodeTypes ?? NODE_RUNTIME_KERNEL_CANONICAL_NODE_TYPES)
      .map((entry: string): string => normalizeNodeType(entry))
      .filter(Boolean)
  );

  const resolveDescriptor = (nodeTypeInput: string): NodeRuntimeKernelDescriptor => {
    const nodeType = normalizeNodeType(nodeTypeInput);
    const buildKernelDescriptor = createDescriptorBuilder(resolvedRuntimeKernelNodeTypes);

    if (!nodeType) {
      return buildKernelDescriptor({
        nodeType: '',
        handler: null,
        source: 'missing',
      });
    }

    return resolveNodeRuntimeDescriptor({
      nodeType,
      resolveCodeObjectHandler,
      resolveLegacyHandler,
      resolveOverrideHandler,
      runtimeKernelNodeTypes: resolvedRuntimeKernelNodeTypes,
    });
  };

  return {
    resolveDescriptor,
    resolveHandler: (nodeType: string): NodeHandler | null => resolveDescriptor(nodeType).handler,
  };
};

import { isObjectRecord } from '@/shared/utils/object-utils';

import {
  DEPRECATED_RUNTIME_KERNEL_CONFIG_MODE_FIELD,
  DEPRECATED_RUNTIME_KERNEL_CONFIG_NODE_TYPES_FIELD,
  DEPRECATED_RUNTIME_KERNEL_CONFIG_RESOLVER_IDS_FIELD,
  DEPRECATED_RUNTIME_KERNEL_CONFIG_STRICT_ALIAS_FIELD,
  DEPRECATED_RUNTIME_KERNEL_CONFIG_STRICT_NATIVE_FIELD,
} from './runtime-kernel-legacy-aliases';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

export type RuntimeKernelConfigNormalizedField =
  | 'mode'
  | 'nodeTypes'
  | 'codeObjectResolverIds'
  | 'strictNativeRegistry';

export type RuntimeKernelValueSource = 'env' | 'path' | 'settings' | 'default';

export type NormalizeRuntimeKernelConfigRecordResult = {
  changed: boolean;
  value: Record<string, unknown>;
  changedFields: RuntimeKernelConfigNormalizedField[];
};

export const normalizeRuntimeKernelNodeTypeToken = (value: string): string =>
  value.trim().toLowerCase().replace(/\s+/g, '_');

export const normalizeRuntimeKernelResolverIdToken = (value: string): string => value.trim();

export const parseRuntimeKernelListValue = ({
  value,
  normalizeToken,
}: {
  value: unknown;
  normalizeToken: (token: string) => string;
}): string[] | undefined => {
  if (Array.isArray(value)) {
    const normalized = Array.from(
      new Set(
        value
          .filter((entry): entry is string => typeof entry === 'string')
          .map((entry: string): string => normalizeToken(entry))
          .filter(Boolean)
      )
    );
    return normalized.length > 0 ? normalized : undefined;
  }
  if (typeof value !== 'string') return undefined;
  const trimmed = value.trim();
  if (!trimmed) return undefined;

  if (trimmed.startsWith('[') && trimmed.endsWith(']')) {
    try {
      const parsed = JSON.parse(trimmed) as unknown;
      if (Array.isArray(parsed)) {
        const normalized = Array.from(
          new Set(
            parsed
              .filter((entry): entry is string => typeof entry === 'string')
              .map((entry: string): string => normalizeToken(entry))
              .filter(Boolean)
          )
        );
        return normalized.length > 0 ? normalized : undefined;
      }
    } catch (error) {
      logClientError(error);

      // Fall through to tokenized parsing.
    }
  }

  const normalized = Array.from(
    new Set(
      trimmed
        .split(/[,\n]/g)
        .map((entry: string): string => normalizeToken(entry))
        .filter(Boolean)
    )
  );
  return normalized.length > 0 ? normalized : undefined;
};

const matchesStringArray = (value: unknown, expected: string[]): boolean =>
  Array.isArray(value) &&
  value.length === expected.length &&
  value.every(
    (entry: unknown, index: number): boolean =>
      typeof entry === 'string' && entry === expected[index]
  );

const appendChangedField = (
  changedFields: RuntimeKernelConfigNormalizedField[],
  field: RuntimeKernelConfigNormalizedField
): void => {
  if (!changedFields.includes(field)) {
    changedFields.push(field);
  }
};

const removeDeprecatedRuntimeKernelField = (
  normalized: Record<string, unknown>,
  field: string,
  changedFields: RuntimeKernelConfigNormalizedField[],
  changedField: RuntimeKernelConfigNormalizedField
): void => {
  if (!(field in normalized)) return;
  delete normalized[field];
  appendChangedField(changedFields, changedField);
};

const normalizeRuntimeKernelListField = (args: {
  sourceValue: Record<string, unknown>;
  normalized: Record<string, unknown>;
  changedFields: RuntimeKernelConfigNormalizedField[];
  canonicalField: 'nodeTypes' | 'codeObjectResolverIds';
  legacyField: string;
  changedField: Extract<
    RuntimeKernelConfigNormalizedField,
    'nodeTypes' | 'codeObjectResolverIds'
  >;
  parseValue: (value: unknown) => string[] | undefined;
}): void => {
  const nextValue = args.parseValue(args.sourceValue[args.canonicalField]);

  if (nextValue) {
    if (!matchesStringArray(args.sourceValue[args.canonicalField], nextValue)) {
      args.normalized[args.canonicalField] = nextValue;
      appendChangedField(args.changedFields, args.changedField);
    }
  } else if (args.canonicalField in args.normalized) {
    delete args.normalized[args.canonicalField];
    appendChangedField(args.changedFields, args.changedField);
  }

  removeDeprecatedRuntimeKernelField(
    args.normalized,
    args.legacyField,
    args.changedFields,
    args.changedField
  );
};

export const normalizeRuntimeKernelValueSource = (
  value: unknown
): RuntimeKernelValueSource | null =>
  value === 'env' || value === 'path' || value === 'settings' || value === 'default' ? value : null;

export const parseRuntimeKernelNodeTypes = (value: unknown): string[] | undefined =>
  parseRuntimeKernelListValue({
    value,
    normalizeToken: normalizeRuntimeKernelNodeTypeToken,
  });

export const parseRuntimeKernelCodeObjectResolverIds = (value: unknown): string[] | undefined =>
  parseRuntimeKernelListValue({
    value,
    normalizeToken: normalizeRuntimeKernelResolverIdToken,
  });

export const normalizeRuntimeKernelConfigRecordDetailed = (
  value: unknown
): NormalizeRuntimeKernelConfigRecordResult | null => {
  if (!isObjectRecord(value)) return null;

  const normalized: Record<string, unknown> = { ...value };
  const changedFields: RuntimeKernelConfigNormalizedField[] = [];

  removeDeprecatedRuntimeKernelField(
    normalized,
    DEPRECATED_RUNTIME_KERNEL_CONFIG_MODE_FIELD,
    changedFields,
    'mode'
  );

  normalizeRuntimeKernelListField({
    sourceValue: value,
    normalized,
    canonicalField: 'nodeTypes',
    legacyField: DEPRECATED_RUNTIME_KERNEL_CONFIG_NODE_TYPES_FIELD,
    changedField: 'nodeTypes',
    parseValue: parseRuntimeKernelNodeTypes,
    changedFields,
  });

  normalizeRuntimeKernelListField({
    sourceValue: value,
    normalized,
    canonicalField: 'codeObjectResolverIds',
    legacyField: DEPRECATED_RUNTIME_KERNEL_CONFIG_RESOLVER_IDS_FIELD,
    changedField: 'codeObjectResolverIds',
    parseValue: parseRuntimeKernelCodeObjectResolverIds,
    changedFields,
  });

  removeDeprecatedRuntimeKernelField(
    normalized,
    DEPRECATED_RUNTIME_KERNEL_CONFIG_STRICT_NATIVE_FIELD,
    changedFields,
    'strictNativeRegistry'
  );
  removeDeprecatedRuntimeKernelField(
    normalized,
    DEPRECATED_RUNTIME_KERNEL_CONFIG_STRICT_ALIAS_FIELD,
    changedFields,
    'strictNativeRegistry'
  );

  return {
    changed: changedFields.length > 0,
    value: changedFields.length > 0 ? normalized : value,
    changedFields,
  };
};

export const normalizeRuntimeKernelConfigRecord = (
  value: unknown
): Record<string, unknown> | null => {
  const normalized = normalizeRuntimeKernelConfigRecordDetailed(value);
  return normalized?.value ?? null;
};

