import {
  findRemovedLegacyTriggerContextModesInDocument,
  formatRemovedLegacyTriggerContextModesMessage,
} from '@/shared/lib/ai-paths/core/utils/legacy-trigger-context-mode';

import { normalizeAiPathsValidationConfig } from '../validation-engine';

export const parseSemanticDocument = (input: unknown): ParseSemanticDocumentResult => {
  const removedLegacyNodes = findRemovedLegacyAiPathNodesInDocument(input);
  if (removedLegacyNodes.length > 0) {
    return {
      ok: false,
      error: formatRemovedLegacyAiPathNodesMessage(removedLegacyNodes, {
        surface: 'semantic document',
      }),
    };
  }
  const removedTriggerContextModes = findRemovedLegacyTriggerContextModesInDocument(input);
  if (removedTriggerContextModes.length > 0) {
    return {
      ok: false,
      error: formatRemovedLegacyTriggerContextModesMessage(removedTriggerContextModes, {
        surface: 'semantic document',
      }),
    };
  }
  const parsed = semanticDocumentSchema.safeParse(input);
  if (parsed.success) {
    return { ok: true, value: parsed.data };
  }
  return {
    ok: false,
    error: parsed.error.issues
      .map((issue) => `${issue.path.join('.') || 'document'}: ${issue.message}`)
      .join('; '),
  };
};

export const parseSemanticCanvasDocument = (input: unknown): ParseSemanticDocumentResult => {
  const removedLegacyNodes = findRemovedLegacyAiPathNodesInDocument(input);
  if (removedLegacyNodes.length > 0) {
    return {
      ok: false,
      error: formatRemovedLegacyAiPathNodesMessage(removedLegacyNodes, {
        surface: 'semantic document',
      }),
    };
  }
  const removedTriggerContextModes = findRemovedLegacyTriggerContextModesInDocument(input);
  if (removedTriggerContextModes.length > 0) {
    return {
      ok: false,
      error: formatRemovedLegacyTriggerContextModesMessage(removedTriggerContextModes, {
        surface: 'semantic document',
      }),
    };
  }
  const parsed = canvasSemanticDocumentSchema.safeParse(input);
  if (parsed.success) {
    return { ok: true, value: parsed.data };
  }
  return {
    ok: false,
    error: parsed.error.issues
      .map((issue) => `${issue.path.join('.') || 'document'}: ${issue.message}`)
      .join('; '),
  };
};

const toAiNode = (semanticNode: SemanticNode, fallbackTimestamp: string): AiNode => ({
  id: semanticNode.id,
  type: semanticNode.type,
  title: semanticNode.title,
  description: semanticNode.description,
  position: semanticNode.position,
  inputs: semanticNode.inputs,
  outputs: semanticNode.outputs,
  data: semanticNode.data && typeof semanticNode.data === 'object' ? semanticNode.data : {},
  createdAt: semanticNode.createdAt ?? fallbackTimestamp,
  updatedAt:
    typeof semanticNode.updatedAt === 'string' || semanticNode.updatedAt === null
      ? semanticNode.updatedAt
      : null,
  ...(semanticNode.config && typeof semanticNode.config === 'object'
    ? { config: semanticNode.config as AiNode['config'] }
    : {}),
});

const toAiEdge = (semanticEdge: SemanticEdge): Edge => ({
  id: semanticEdge.id,
  from: semanticEdge.fromNodeId,
  to: semanticEdge.toNodeId,
  ...(typeof semanticEdge.fromPort === 'string' || semanticEdge.fromPort === null
    ? {
      fromPort: semanticEdge.fromPort,
    }
    : {}),
  ...(typeof semanticEdge.toPort === 'string' || semanticEdge.toPort === null
    ? {
      toPort: semanticEdge.toPort,
    }
    : {}),
  ...(typeof semanticEdge.label === 'string' || semanticEdge.label === null
    ? { label: semanticEdge.label }
    : {}),
  ...(typeof semanticEdge.type === 'string' ? { type: semanticEdge.type } : {}),
  ...(semanticEdge.data && typeof semanticEdge.data === 'object'
    ? { data: semanticEdge.data }
    : {}),
  ...(typeof semanticEdge.createdAt === 'string' ? { createdAt: semanticEdge.createdAt } : {}),
  ...(typeof semanticEdge.updatedAt === 'string' || semanticEdge.updatedAt === null
    ? { updatedAt: semanticEdge.updatedAt }
    : {}),
});

export const deserializeSemanticCanvasToPathConfig = (
  semanticDocument: CanvasSemanticDocument
): PathConfig => {
  const now = new Date().toISOString();
  const base = createDefaultPathConfig(semanticDocument.path.id);
  const nodes = semanticDocument.nodes.map((node: SemanticNode): AiNode => toAiNode(node, now));
  const edges = semanticDocument.edges.map((edge: SemanticEdge): Edge => toAiEdge(edge));
  const runtimeState = (
    semanticDocument.execution?.runtimeState !== undefined
      ? semanticDocument.execution.runtimeState
      : (base.runtimeState as unknown)
  ) as PathConfig['runtimeState'];

  return {
    ...base,
    id: semanticDocument.path.id,
    version: semanticDocument.path.version,
    name: semanticDocument.path.name,
    description: semanticDocument.path.description,
    trigger: semanticDocument.path.trigger,
    updatedAt: semanticDocument.path.updatedAt,
    ...(typeof semanticDocument.path.executionMode === 'string'
      ? { executionMode: semanticDocument.path.executionMode }
      : {}),
    ...(typeof semanticDocument.path.flowIntensity === 'string'
      ? { flowIntensity: semanticDocument.path.flowIntensity }
      : {}),
    ...(typeof semanticDocument.path.runMode === 'string'
      ? { runMode: semanticDocument.path.runMode }
      : {}),
    ...(typeof semanticDocument.path.strictFlowMode === 'boolean'
      ? { strictFlowMode: semanticDocument.path.strictFlowMode }
      : {}),
    ...(typeof semanticDocument.path.isLocked === 'boolean'
      ? { isLocked: semanticDocument.path.isLocked }
      : {}),
    ...(typeof semanticDocument.path.isActive === 'boolean'
      ? { isActive: semanticDocument.path.isActive }
      : {}),
    nodes,
    edges,
    parserSamples:
      semanticDocument.execution?.parserSamples &&
      typeof semanticDocument.execution.parserSamples === 'object'
        ? semanticDocument.execution.parserSamples
        : {},
    updaterSamples:
      semanticDocument.execution?.updaterSamples &&
      typeof semanticDocument.execution.updaterSamples === 'object'
        ? semanticDocument.execution.updaterSamples
        : {},
    runtimeState,
    lastRunAt:
      typeof semanticDocument.execution?.lastRunAt === 'string' ||
      semanticDocument.execution?.lastRunAt === null
        ? semanticDocument.execution.lastRunAt
        : null,
    runCount:
      typeof semanticDocument.execution?.runCount === 'number'
        ? semanticDocument.execution.runCount
        : 0,
    aiPathsValidation: normalizeAiPathsValidationConfig(
      semanticDocument.validation ?? base.aiPathsValidation
    ),
    ...(semanticDocument.extensions && typeof semanticDocument.extensions === 'object'
      ? { extensions: semanticDocument.extensions }
      : {}),
    uiState: {
      selectedNodeId: nodes[0]?.id ?? null,
      configOpen: false,
    },
  };
};

export const parseAndDeserializeSemanticCanvas = (
  input: unknown
): { ok: true; value: PathConfig } | { ok: false; error: string } => {
  const parsed = parseSemanticCanvasDocument(input);
  if (!parsed.ok) {
    return parsed;
  }
  return {
    ok: true,
    value: deserializeSemanticCanvasToPathConfig(parsed.value as CanvasSemanticDocument),
  };
};

import type { AiNode, Edge, PathConfig } from '@/shared/contracts/ai-paths';
import type {
  CanvasSemanticDocument,
  SemanticEdge,
  SemanticNode,
  SemanticNodeConnections,
  SemanticPortBinding,
} from '@/shared/contracts/ai-paths-semantic-grammar';

const SEMANTIC_SPEC_VERSION = 'ai-paths.semantic-grammar.v1' as const;

export type SerializeSemanticCanvasOptions = {
  includeConnections?: boolean;
  sortById?: boolean;
  exportedAt?: string | undefined;
  exporterVersion?: string | undefined;
  workspace?: string | undefined;
};

const toEdgeFromNodeId = (edge: Edge): string =>
  typeof edge.from === 'string' ? edge.from.trim() : '';

const toEdgeToNodeId = (edge: Edge): string => (typeof edge.to === 'string' ? edge.to.trim() : '');

const toEdgeFromPort = (edge: Edge): string | null =>
  typeof edge.fromPort === 'string' ? edge.fromPort : null;

const toEdgeToPort = (edge: Edge): string | null =>
  typeof edge.toPort === 'string' ? edge.toPort : null;

const toSemanticEdge = (edge: Edge): SemanticEdge => ({
  id: edge.id,
  fromNodeId: toEdgeFromNodeId(edge),
  toNodeId: toEdgeToNodeId(edge),
  ...(toEdgeFromPort(edge) !== null ? { fromPort: toEdgeFromPort(edge) } : {}),
  ...(toEdgeToPort(edge) !== null ? { toPort: toEdgeToPort(edge) } : {}),
  ...(typeof edge.label === 'string' || edge.label === null ? { label: edge.label } : {}),
  ...(typeof edge.type === 'string' && edge.type.trim().length > 0 ? { type: edge.type } : {}),
  ...(edge.data && typeof edge.data === 'object' ? { data: edge.data } : {}),
  ...(typeof edge.createdAt === 'string' ? { createdAt: edge.createdAt } : {}),
  ...(typeof edge.updatedAt === 'string' || edge.updatedAt === null
    ? { updatedAt: edge.updatedAt }
    : {}),
});

const toPortBinding = (edge: SemanticEdge): SemanticPortBinding => ({
  edgeId: edge.id,
  fromNodeId: edge.fromNodeId,
  ...(typeof edge.fromPort === 'string' || edge.fromPort === null
    ? { fromPort: edge.fromPort }
    : {}),
  toNodeId: edge.toNodeId,
  ...(typeof edge.toPort === 'string' || edge.toPort === null ? { toPort: edge.toPort } : {}),
});

const buildNodeConnections = (
  nodeIds: string[],
  edges: SemanticEdge[]
): Map<string, SemanticNodeConnections> => {
  const byNodeId = new Map<string, SemanticNodeConnections>();
  nodeIds.forEach((nodeId: string) => {
    byNodeId.set(nodeId, {
      incoming: [],
      outgoing: [],
    });
  });
  edges.forEach((edge: SemanticEdge) => {
    const binding = toPortBinding(edge);
    const outgoing = byNodeId.get(edge.fromNodeId);
    if (outgoing) outgoing.outgoing.push(binding);
    const incoming = byNodeId.get(edge.toNodeId);
    if (incoming) incoming.incoming.push(binding);
  });
  return byNodeId;
};

const sortSemanticNodes = (nodes: SemanticNode[]): SemanticNode[] =>
  nodes
    .slice()
    .sort((left: SemanticNode, right: SemanticNode): number => left.id.localeCompare(right.id));

const sortSemanticEdges = (edges: SemanticEdge[]): SemanticEdge[] =>
  edges
    .slice()
    .sort((left: SemanticEdge, right: SemanticEdge): number => left.id.localeCompare(right.id));

export const serializePathConfigToSemanticCanvas = (
  pathConfig: PathConfig,
  options?: SerializeSemanticCanvasOptions
): CanvasSemanticDocument => {
  const includeConnections = options?.includeConnections !== false;
  const sortById = options?.sortById !== false;

  const semanticEdgesRaw = (pathConfig.edges ?? []).map(
    (edge: Edge): SemanticEdge => toSemanticEdge(edge)
  );
  const semanticEdges = sortById ? sortSemanticEdges(semanticEdgesRaw) : semanticEdgesRaw;

  const nodeConnections = buildNodeConnections(
    (pathConfig.nodes ?? []).map((node: AiNode) => node.id),
    semanticEdges
  );

  const semanticNodesRaw = (pathConfig.nodes ?? []).map((node: AiNode): SemanticNode => {
    const nodeTypeId = typeof node.nodeTypeId === 'string' ? node.nodeTypeId.trim() : '';
    const instanceId = typeof node.instanceId === 'string' ? node.instanceId.trim() : '';
    const identityExtension =
      nodeTypeId.length > 0 || instanceId.length > 0
        ? {
          aiPathsIdentity: {
            ...(nodeTypeId.length > 0 ? { nodeTypeId } : {}),
            instanceId: instanceId.length > 0 ? instanceId : node.id,
          },
        }
        : null;
    return {
      id: node.id,
      type: node.type,
      title: node.title ?? '',
      description: node.description ?? '',
      position: node.position,
      inputs: node.inputs,
      outputs: node.outputs,
      ...(node.config && typeof node.config === 'object' ? { config: node.config } : {}),
      ...(node.data && typeof node.data === 'object' ? { data: node.data } : {}),
      ...(typeof node.createdAt === 'string' ? { createdAt: node.createdAt } : {}),
      ...(typeof node.updatedAt === 'string' || node.updatedAt === null
        ? { updatedAt: node.updatedAt }
        : {}),
      ...(includeConnections
        ? { connections: nodeConnections.get(node.id) ?? { incoming: [], outgoing: [] } }
        : {}),
      ...(identityExtension ? { extensions: identityExtension } : {}),
    };
  });
  const semanticNodes = sortById ? sortSemanticNodes(semanticNodesRaw) : semanticNodesRaw;

  return {
    specVersion: SEMANTIC_SPEC_VERSION,
    kind: 'canvas',
    path: {
      id: pathConfig.id,
      version: pathConfig.version,
      name: pathConfig.name,
      description: pathConfig.description,
      trigger: pathConfig.trigger,
      updatedAt: pathConfig.updatedAt,
      ...(typeof pathConfig.executionMode === 'string'
        ? { executionMode: pathConfig.executionMode }
        : {}),
      ...(typeof pathConfig.flowIntensity === 'string'
        ? { flowIntensity: pathConfig.flowIntensity }
        : {}),
      ...(typeof pathConfig.runMode === 'string' ? { runMode: pathConfig.runMode } : {}),
      ...(typeof pathConfig.strictFlowMode === 'boolean'
        ? { strictFlowMode: pathConfig.strictFlowMode }
        : {}),
      ...(typeof pathConfig.isLocked === 'boolean' ? { isLocked: pathConfig.isLocked } : {}),
      ...(typeof pathConfig.isActive === 'boolean' ? { isActive: pathConfig.isActive } : {}),
    },
    nodes: semanticNodes,
    edges: semanticEdges,
    execution: {
      ...(pathConfig.parserSamples &&
      typeof pathConfig.parserSamples === 'object' &&
      !Array.isArray(pathConfig.parserSamples)
        ? { parserSamples: pathConfig.parserSamples }
        : {}),
      ...(pathConfig.updaterSamples &&
      typeof pathConfig.updaterSamples === 'object' &&
      !Array.isArray(pathConfig.updaterSamples)
        ? { updaterSamples: pathConfig.updaterSamples }
        : {}),
      ...(pathConfig.runtimeState !== undefined ? { runtimeState: pathConfig.runtimeState } : {}),
      ...(typeof pathConfig.lastRunAt === 'string' || pathConfig.lastRunAt === null
        ? { lastRunAt: pathConfig.lastRunAt }
        : {}),
      ...(typeof pathConfig.runCount === 'number' ? { runCount: pathConfig.runCount } : {}),
    },
    ...(pathConfig.aiPathsValidation ? { validation: pathConfig.aiPathsValidation } : {}),
    ...(pathConfig.extensions && typeof pathConfig.extensions === 'object'
      ? { extensions: pathConfig.extensions }
      : {}),
    provenance: {
      source: 'ai-paths',
      exportedAt: options?.exportedAt ?? new Date().toISOString(),
      pathId: pathConfig.id,
      ...(options?.exporterVersion ? { exporterVersion: options.exporterVersion } : {}),
      ...(options?.workspace ? { workspace: options.workspace } : {}),
    },
  };
};

import type { AiNode, Edge, PathConfig } from '@/shared/contracts/ai-paths';
import { subgraphSemanticDocumentSchema } from '@/shared/contracts/ai-paths-semantic-grammar';
import type {
  SemanticNode,
  SubgraphSemanticDocument,
  SemanticEdge,
} from '@/shared/contracts/ai-paths-semantic-grammar';

import { serializePathConfigToSemanticCanvas } from './serialize';
import { createNodeInstanceId, resolveNodeTypeId } from '../utils/node-identity';

export type BuildSemanticSubgraphOptions = {
  selectedNodeIds: string[];
  exportedAt?: string | undefined;
  exporterVersion?: string | undefined;
  workspace?: string | undefined;
};

export type ApplySemanticSubgraphOptions = {
  idPrefix?: string | undefined;
  positionOffset?: { x: number; y: number } | undefined;
};

const resolveEdgeFromNodeId = (edge: Edge): string =>
  typeof edge.from === 'string' ? edge.from.trim() : '';

const resolveEdgeToNodeId = (edge: Edge): string =>
  typeof edge.to === 'string' ? edge.to.trim() : '';

const resolveUniqueId = (desiredId: string, existingIds: Set<string>): string => {
  const trimmed = desiredId.trim();
  const base = trimmed.length > 0 ? trimmed : 'node';
  if (!existingIds.has(base)) {
    existingIds.add(base);
    return base;
  }
  let suffix = 2;
  while (suffix <= 9999) {
    const candidate = `${base}_${suffix}`;
    if (!existingIds.has(candidate)) {
      existingIds.add(candidate);
      return candidate;
    }
    suffix += 1;
  }
  const fallback = `${base}_${Date.now().toString(36)}`;
  existingIds.add(fallback);
  return fallback;
};

const resolveSemanticIdentityValue = (
  node: SemanticNode,
  key: 'nodeTypeId' | 'instanceId'
): string => {
  const extensions = node.extensions;
  if (!extensions || typeof extensions !== 'object' || Array.isArray(extensions)) {
    return '';
  }
  const identity = extensions['aiPathsIdentity'];
  if (!identity || typeof identity !== 'object' || Array.isArray(identity)) {
    return '';
  }
  const value = (identity as Record<string, unknown>)[key];
  return typeof value === 'string' ? value.trim() : '';
};

export const buildSemanticSubgraphFromPathConfig = (
  pathConfig: PathConfig,
  options: BuildSemanticSubgraphOptions
): SubgraphSemanticDocument => {
  const selected = new Set<string>(options.selectedNodeIds);
  const full = serializePathConfigToSemanticCanvas(pathConfig, {
    includeConnections: false,
    sortById: false,
    exportedAt: options.exportedAt,
    exporterVersion: options.exporterVersion,
    workspace: options.workspace,
  });
  const nodes = full.nodes.filter((node: SemanticNode): boolean => selected.has(node.id));
  const edges = full.edges.filter(
    (edge: SemanticEdge): boolean => selected.has(edge.fromNodeId) && selected.has(edge.toNodeId)
  );
  const boundaryIncoming = full.edges
    .filter(
      (edge: SemanticEdge): boolean => !selected.has(edge.fromNodeId) && selected.has(edge.toNodeId)
    )
    .map((edge: SemanticEdge) => ({
      edgeId: edge.id,
      fromNodeId: edge.fromNodeId,
      ...(edge.fromPort !== undefined ? { fromPort: edge.fromPort } : {}),
      toNodeId: edge.toNodeId,
      ...(edge.toPort !== undefined ? { toPort: edge.toPort } : {}),
    }));
  const boundaryOutgoing = full.edges
    .filter(
      (edge: SemanticEdge): boolean => selected.has(edge.fromNodeId) && !selected.has(edge.toNodeId)
    )
    .map((edge: SemanticEdge) => ({
      edgeId: edge.id,
      fromNodeId: edge.fromNodeId,
      ...(edge.fromPort !== undefined ? { fromPort: edge.fromPort } : {}),
      toNodeId: edge.toNodeId,
      ...(edge.toPort !== undefined ? { toPort: edge.toPort } : {}),
    }));

  return {
    specVersion: full.specVersion,
    kind: 'subgraph',
    pathId: full.path.id,
    selectedNodeIds: nodes.map((node) => node.id),
    nodes,
    edges,
    boundary: {
      incoming: boundaryIncoming,
      outgoing: boundaryOutgoing,
    },
    provenance: full.provenance,
  };
};

export const parseSemanticSubgraphDocument = (
  input: unknown
): { ok: true; value: SubgraphSemanticDocument } | { ok: false; error: string } => {
  const parsed = subgraphSemanticDocumentSchema.safeParse(input);
  if (parsed.success) {
    return {
      ok: true,
      value: parsed.data,
    };
  }
  return {
    ok: false,
    error: parsed.error.issues
      .map((issue) => `${issue.path.join('.') || 'document'}: ${issue.message}`)
      .join('; '),
  };
};

export const applySemanticSubgraphToPathConfig = (
  targetConfig: PathConfig,
  subgraph: SubgraphSemanticDocument,
  options?: ApplySemanticSubgraphOptions
): {
  pathConfig: PathConfig;
  nodeIdMap: Record<string, string>;
  edgeIdMap: Record<string, string>;
} => {
  const now = new Date().toISOString();
  const idPrefix =
    typeof options?.idPrefix === 'string' && options.idPrefix.trim().length > 0
      ? `${options.idPrefix.trim()}_`
      : '';
  const offset = options?.positionOffset ?? { x: 56, y: 56 };

  const existingNodeIds = new Set<string>(
    (targetConfig.nodes ?? []).map((node: AiNode): string => node.id)
  );
  const existingEdgeIds = new Set<string>(
    (targetConfig.edges ?? []).map((edge: Edge): string => edge.id)
  );
  const nodeIdMap: Record<string, string> = {};
  const edgeIdMap: Record<string, string> = {};

  const appendedNodes = subgraph.nodes.map((node: SemanticNode): AiNode => {
    const remappedId = createNodeInstanceId(existingNodeIds);
    nodeIdMap[node.id] = remappedId;
    const semanticNodeTypeId = resolveSemanticIdentityValue(node, 'nodeTypeId');
    const resolvedNodeTypeId =
      semanticNodeTypeId.length > 0
        ? semanticNodeTypeId
        : resolveNodeTypeId({
          type: node.type,
          title: node.title,
          config: node.config as AiNode['config'] | undefined,
        });
    return {
      id: remappedId,
      instanceId: remappedId,
      nodeTypeId: resolvedNodeTypeId,
      type: node.type,
      title: node.title,
      description: node.description,
      position: {
        x: node.position.x + offset.x,
        y: node.position.y + offset.y,
      },
      inputs: node.inputs,
      outputs: node.outputs,
      ...(node.config && typeof node.config === 'object'
        ? { config: node.config as AiNode['config'] }
        : {}),
      ...(node.data && typeof node.data === 'object' ? { data: node.data } : {}),
      createdAt: now,
      updatedAt: null,
    };
  });

  const appendedEdges = subgraph.edges
    .filter((edge: SemanticEdge): boolean =>
      Boolean(nodeIdMap[edge.fromNodeId] && nodeIdMap[edge.toNodeId])
    )
    .map((edge: SemanticEdge): Edge => {
      const remappedId = resolveUniqueId(`${idPrefix}${edge.id}`, existingEdgeIds);
      edgeIdMap[edge.id] = remappedId;
      const fromNodeId = nodeIdMap[edge.fromNodeId] as string;
      const toNodeId = nodeIdMap[edge.toNodeId] as string;
      return {
        id: remappedId,
        from: fromNodeId,
        to: toNodeId,
        ...(typeof edge.fromPort === 'string' || edge.fromPort === null
          ? {
            fromPort: edge.fromPort,
          }
          : {}),
        ...(typeof edge.toPort === 'string' || edge.toPort === null
          ? {
            toPort: edge.toPort,
          }
          : {}),
        ...(typeof edge.label === 'string' || edge.label === null ? { label: edge.label } : {}),
        ...(typeof edge.type === 'string' ? { type: edge.type } : {}),
        ...(edge.data && typeof edge.data === 'object' ? { data: edge.data } : {}),
        createdAt: now,
        updatedAt: null,
      };
    });

  const pathConfig: PathConfig = {
    ...targetConfig,
    nodes: [...(targetConfig.nodes ?? []), ...appendedNodes],
    edges: [...(targetConfig.edges ?? []), ...appendedEdges],
    updatedAt: now,
    uiState: {
      selectedNodeId: appendedNodes[0]?.id ?? targetConfig.uiState?.selectedNodeId ?? null,
      configOpen: targetConfig.uiState?.configOpen ?? false,
    },
  };

  return {
    pathConfig,
    nodeIdMap,
    edgeIdMap,
  };
};

export const applyParsedSemanticSubgraphToPathConfig = (
  targetConfig: PathConfig,
  input: unknown,
  options?: ApplySemanticSubgraphOptions
):
  | {
      ok: true;
      value: {
        pathConfig: PathConfig;
        nodeIdMap: Record<string, string>;
        edgeIdMap: Record<string, string>;
      };
    }
  | { ok: false; error: string } => {
  const parsed = parseSemanticSubgraphDocument(input);
  if (!parsed.ok) return parsed;
  return {
    ok: true,
    value: applySemanticSubgraphToPathConfig(targetConfig, parsed.value, options),
  };
};

export const summarizeSubgraphBoundary = (
  subgraph: SubgraphSemanticDocument
): {
  incomingCount: number;
  outgoingCount: number;
} => ({
  incomingCount: subgraph.boundary.incoming.length,
  outgoingCount: subgraph.boundary.outgoing.length,
});

export const findSubgraphDanglingEdges = (pathConfig: PathConfig): string[] =>
  (pathConfig.edges ?? [])
    .filter((edge: Edge): boolean => {
      const fromNodeId = resolveEdgeFromNodeId(edge);
      const toNodeId = resolveEdgeToNodeId(edge);
      if (!fromNodeId || !toNodeId) return true;
      const nodeIds = new Set<string>(
        (pathConfig.nodes ?? []).map((node: AiNode): string => node.id)
      );
      return !nodeIds.has(fromNodeId) || !nodeIds.has(toNodeId);
    })
    .map((edge: Edge): string => edge.id);

import type { PathConfig } from '@/shared/contracts/ai-paths';
import type { PathMeta } from '@/shared/contracts/ai-paths';
import type { AiTriggerButtonRecord } from '@/shared/contracts/ai-trigger-buttons';
import {
  applyStarterProvenance,
  materializeSemanticAsset,
} from './utils';
