const normalizeCollectionAliasKey = (value: string): string =>
  value
    .trim()
    .replace(/([a-z0-9])([A-Z])/g, '$1_$2')
    .replace(/[\s-]+/g, '_')
    .replace(/__+/g, '_')
    .toLowerCase();

export const canonicalizeAiPathsCollectionName = (collection: string): string => {
  const trimmed = typeof collection === 'string' ? collection.trim() : '';
  if (!trimmed) return collection;

  if (CANONICAL_COLLECTION_NAMES.has(trimmed)) {
    return trimmed;
  }

  const normalizedKey = normalizeCollectionAliasKey(trimmed);
  const aliasTarget = COLLECTION_NAME_ALIASES[normalizedKey];
  if (aliasTarget) {
    return aliasTarget;
  }

  if (CANONICAL_COLLECTION_NAMES.has(normalizedKey)) {
    return normalizedKey;
  }

  return trimmed;
};

export type AiPathsCollectionAliasIssue = {
  nodeId: string;
  location: 'database.query.collection';
  value: string;
  canonical: string;
};

export const findPathConfigCollectionAliasIssues = (
  pathConfig: Pick<PathConfig, 'nodes'>
): AiPathsCollectionAliasIssue[] =>
  (pathConfig.nodes ?? []).flatMap((node: AiNode): AiPathsCollectionAliasIssue[] => {
    const databaseConfig = node.config?.database;
    if (!databaseConfig || typeof databaseConfig !== 'object') return [];
    const query = databaseConfig.query;
    if (!query || typeof query.collection !== 'string') return [];
    const canonical = canonicalizeAiPathsCollectionName(query.collection);
    if (canonical === query.collection) return [];
    return [
      {
        nodeId: node.id,
        location: 'database.query.collection',
        value: query.collection,
        canonical,
      },
    ];
  });

import type { GraphCompileCode, GraphCompileFinding } from './graph';

type WarningFinding = Pick<GraphCompileFinding, 'severity' | 'message' | 'code' | 'metadata'>;

type CompileWarningReport = {
  warnings: number;
  findings: WarningFinding[];
};

const MAX_CYCLE_LABELS = 4;

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === 'string' && value.trim().length > 0;

const readCycleLabels = (metadata: Record<string, unknown> | undefined): string[] => {
  if (!metadata) return [];
  const labelsRaw = metadata['nodeLabels'];
  if (!Array.isArray(labelsRaw)) return [];
  return labelsRaw
    .filter((item: unknown): item is string => isNonEmptyString(item))
    .map((item: string) => item.trim());
};

const appendCycleDetails = (
  message: string,
  metadata: Record<string, unknown> | undefined
): string => {
  const labels = readCycleLabels(metadata);
  if (labels.length === 0 || /Affected nodes:/i.test(message)) return message;
  const summary =
    labels.length <= MAX_CYCLE_LABELS
      ? labels.join(', ')
      : `${labels.slice(0, MAX_CYCLE_LABELS).join(', ')}, +${labels.length - MAX_CYCLE_LABELS} more`;
  return `${message} Affected nodes: ${summary}.`;
};

const appendInspectorHint = (message: string): string => {
  if (/Compile Inspector/i.test(message)) return message;
  if (/\bFix:/i.test(message)) return message;
  return `${message} Open Paths Settings -> Compile Inspector for details.`;
};

const withActionableContext = (finding: WarningFinding): string | null => {
  const message = finding.message?.trim();
  if (!message) return null;
  const code = finding.code as GraphCompileCode | undefined;
  if (code === 'cycle_detected') {
    const withCycleDetails = appendCycleDetails(message, finding.metadata);
    if (/Compile Inspector/i.test(withCycleDetails)) return withCycleDetails;
    return `${withCycleDetails} Open Paths Settings -> Compile Inspector to inspect loop edges.`;
  }
  if (code === 'model_prompt_deadlock_risk') {
    if (/Compile Inspector/i.test(message)) return message;
    return `${message} Open Paths Settings -> Compile Inspector to inspect prompt loop dependencies and wait-for-input contracts.`;
  }
  if (code === 'context_cache_scope_risk') {
    if (/Compile Inspector/i.test(message)) return message;
    return `${message} Open Paths Settings -> Compile Inspector to review cache mode/scope on context-bound nodes.`;
  }
  return appendInspectorHint(message);
};

export const buildCompileWarningMessage = (compileReport: CompileWarningReport): string => {
  const warningFindings = compileReport.findings.filter(
    (finding: WarningFinding): boolean => finding.severity === 'warning'
  );
  if (warningFindings.length === 0) {
    return `Graph compile warnings detected (${compileReport.warnings}). Open Paths Settings -> Compile Inspector for details.`;
  }
  const primaryFinding = warningFindings[0];
  const primaryMessage = primaryFinding ? withActionableContext(primaryFinding) : null;
  if (!primaryMessage) {
    return `Graph compile warnings detected (${compileReport.warnings}). Open Paths Settings -> Compile Inspector for details.`;
  }
  const warningCode = primaryFinding?.code ?? 'warning';
  const moreCount = Math.max(0, warningFindings.length - 1);
  return moreCount > 0
    ? `Graph compile warning (${warningCode}): ${primaryMessage} (+${moreCount} more).`
    : `Graph compile warning (${warningCode}): ${primaryMessage}`;
};

import type { ContextConfig } from '@/shared/contracts/ai-paths';

import { CONTEXT_PRESET_FIELDS } from '../constants';
import { omitByPaths, pickByPaths } from './json';

export const getContextPresetSet = (entityType?: string): Record<string, string[]> => {
  const key = entityType === 'auto' ? '' : (entityType ?? '');
  return (CONTEXT_PRESET_FIELDS[key] ?? CONTEXT_PRESET_FIELDS['default'])!;
};

export const applyContextPreset = (
  current: ContextConfig,
  preset: 'light' | 'medium' | 'full' | 'suggested'
): ContextConfig => {
  const set = getContextPresetSet(current.entityType);
  const paths = set ? (set[preset] ?? []) : [];
  if (paths.length === 0) return { ...current, scopeMode: 'full' };
  return {
    ...current,
    scopeMode: 'include',
    includePaths: paths,
    excludePaths: [],
  };
};

export const toggleContextTarget = (current: ContextConfig, field: string): ContextConfig => {
  const isIncluded = (current.includePaths ?? []).includes(field);
  if (current.scopeMode === 'include') {
    const includePaths = current.includePaths ?? [];
    return {
      ...current,
      includePaths: isIncluded
        ? includePaths.filter((p: string) => p !== field)
        : [...includePaths, field],
    };
  }
  const excludePaths = current.excludePaths ?? [];
  const isExcluded = excludePaths.includes(field);
  return {
    ...current,
    excludePaths: isExcluded
      ? excludePaths.filter((p: string) => p !== field)
      : [...excludePaths, field],
  };
};

export const applyContextScope = (
  payload: Record<string, unknown>,
  config?: ContextConfig
): Record<string, unknown> => {
  const scopeMode = config?.scopeMode ?? 'full';
  const scopedPaths = scopeMode === 'include' ? config?.includePaths ?? [] : config?.excludePaths ?? [];
  if (scopedPaths.length === 0) return payload;
  if (scopeMode === 'include') return pickByPaths(payload, scopedPaths);
  if (scopeMode === 'exclude') return omitByPaths(payload, scopedPaths);
  return payload;
};

