const TEMPLATE_TOKEN_REGEX: RegExp = /{{\s*([^}]+)\s*}}|\[\s*([A-Za-z0-9_.$:-]+)\s*\]/g;

const TEMPLATE_SYSTEM_ROOT_PREFIXES = ['Date:', 'DB Provider:', 'Collection:'];

const normalizeNonEmptyString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const resolveEdgeFromNodeId = (edge: Edge): string | null => normalizeNonEmptyString(edge.from);

const resolveEdgeToNodeId = (edge: Edge): string | null => normalizeNonEmptyString(edge.to);

const resolveEdgeFromPort = (edge: Edge): string | null => normalizeNonEmptyString(edge.fromPort);

const resolveEdgeToPort = (edge: Edge): string | null => normalizeNonEmptyString(edge.toPort);

const resolveNodeLabel = (node: AiNode | undefined, fallbackNodeId: string): string => {
  const title =
    typeof node?.title === 'string' && node.title.trim().length > 0 ? node.title.trim() : null;
  return title ?? fallbackNodeId;
};

const parseSampleJson = (
  sample: ParserSampleState | UpdaterSampleState | null | undefined
): unknown => {
  if (!sample) return undefined;
  const raw = normalizeNonEmptyString(sample.json);
  if (!raw) return undefined;
  return parseJsonSafe(raw);
};

const isEmptyValue = (value: unknown): boolean => {
  if (value === null || value === undefined) return true;
  if (typeof value === 'string') return value.trim().length === 0;
  if (Array.isArray(value)) return value.length === 0;
  if (isObjectRecord(value)) return Object.keys(value).length === 0;
  return false;
};

const normalizeTemplateRoot = (token: string): string => {
  const rootCandidate = token.split('.')[0]?.trim() ?? '';
  return rootCandidate.replace(/\[[^\]]*\]/g, '').trim();
};

const isSystemTemplateRoot = (root: string): boolean =>
  TEMPLATE_SYSTEM_ROOT_PREFIXES.some((prefix: string): boolean => root.startsWith(prefix));

const extractTemplateTokens = (template: string): string[] => {
  const tokens = new Set<string>();
  TEMPLATE_TOKEN_REGEX.lastIndex = 0;
  let match = TEMPLATE_TOKEN_REGEX.exec(template);
  while (match) {
    const token = (match[1] ?? match[2] ?? '').trim();
    if (!token) {
      match = TEMPLATE_TOKEN_REGEX.exec(template);
      continue;
    }
    const root = normalizeTemplateRoot(token);
    if (!root || isSystemTemplateRoot(root)) {
      match = TEMPLATE_TOKEN_REGEX.exec(template);
      continue;
    }
    tokens.add(token);
    match = TEMPLATE_TOKEN_REGEX.exec(template);
  }
  return Array.from(tokens);
};

const extractTemplateRawJsonCandidate = (value: string): string => {
  const fencedMatch = value.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fencedMatch?.[1]) {
    return fencedMatch[1].trim();
  }
  return value.trim();
};

const resolveScopedRootNodeIds = (
  nodes: AiNode[],
  edges: Edge[],
  scopeRootNodeIds?: string[] | Set<string>
): string[] => {
  const nodeIdSet = new Set(nodes.map((node: AiNode): string => node.id));
  const explicitRoots = (
    Array.isArray(scopeRootNodeIds)
      ? scopeRootNodeIds
      : scopeRootNodeIds
        ? Array.from(scopeRootNodeIds)
        : []
  )
    .map((nodeId: string): string => nodeId.trim())
    .filter((nodeId: string): boolean => nodeId.length > 0 && nodeIdSet.has(nodeId));
  const uniqueRoots = Array.from(new Set(explicitRoots));
  if (uniqueRoots.length > 0) return uniqueRoots;

  const triggerRoots = nodes
    .filter((node: AiNode): boolean => node.type === 'trigger')
    .map((node: AiNode): string => node.id);
  if (triggerRoots.length > 0) return triggerRoots;

  const incomingNodeIds = new Set<string>();
  edges.forEach((edge: Edge): void => {
    const targetNodeId = resolveEdgeToNodeId(edge);
    if (!targetNodeId || !nodeIdSet.has(targetNodeId)) return;
    incomingNodeIds.add(targetNodeId);
  });

  const fallbackRoots = nodes
    .filter((node: AiNode): boolean => !incomingNodeIds.has(node.id))
    .map((node: AiNode): string => node.id);
  if (fallbackRoots.length > 0) return fallbackRoots;

  return nodes[0] ? [nodes[0].id] : [];
};

const buildReachableScope = (
  nodes: AiNode[],
  edges: Edge[],
  scopeRootNodeIds?: string[] | Set<string>
): { nodes: AiNode[]; edges: Edge[]; reachableNodeIds: Set<string> } => {
  if (nodes.length === 0) {
    return {
      nodes,
      edges,
      reachableNodeIds: new Set<string>(),
    };
  }

  const nodeIdSet = new Set(nodes.map((node: AiNode): string => node.id));
  const rootNodeIds = resolveScopedRootNodeIds(nodes, edges, scopeRootNodeIds);
  if (rootNodeIds.length === 0) {
    return {
      nodes,
      edges,
      reachableNodeIds: new Set<string>(),
    };
  }

  const adjacency = new Map<string, Set<string>>();
  edges.forEach((edge: Edge): void => {
    const fromNodeId = resolveEdgeFromNodeId(edge);
    const toNodeId = resolveEdgeToNodeId(edge);
    if (!fromNodeId || !toNodeId) return;
    if (!nodeIdSet.has(fromNodeId) || !nodeIdSet.has(toNodeId)) return;
    const next = adjacency.get(fromNodeId) ?? new Set<string>();
    next.add(toNodeId);
    adjacency.set(fromNodeId, next);
  });

  const queue = [...rootNodeIds];
  const reachableNodeIds = new Set<string>(rootNodeIds);
  while (queue.length > 0) {
    const current = queue.shift();
    if (!current) continue;
    const next = adjacency.get(current);
    if (!next) continue;
    next.forEach((nodeId: string): void => {
      if (reachableNodeIds.has(nodeId)) return;
      reachableNodeIds.add(nodeId);
      queue.push(nodeId);
    });
  }

  if (reachableNodeIds.size === 0 || reachableNodeIds.size === nodes.length) {
    return {
      nodes,
      edges,
      reachableNodeIds: new Set(nodes.map((node: AiNode): string => node.id)),
    };
  }

  const scopedNodes = nodes.filter((node: AiNode): boolean => reachableNodeIds.has(node.id));
  const scopedNodeIdSet = new Set(scopedNodes.map((node: AiNode): string => node.id));
  const scopedEdges = edges.filter((edge: Edge): boolean => {
    const fromNodeId = resolveEdgeFromNodeId(edge);
    const toNodeId = resolveEdgeToNodeId(edge);
    if (!fromNodeId || !toNodeId) return false;
    return scopedNodeIdSet.has(fromNodeId) && scopedNodeIdSet.has(toNodeId);
  });

  return {
    nodes: scopedNodes,
    edges: scopedEdges,
    reachableNodeIds,
  };
};

const getHistoryEntryValue = (
  runtimeState: RuntimeState,
  nodeId: string,
  direction: 'inputs' | 'outputs',
  port: string
): unknown => {
  const historyEntries = runtimeState.history?.[nodeId];
  if (!Array.isArray(historyEntries) || historyEntries.length === 0) {
    return undefined;
  }
  const lastEntry = historyEntries[historyEntries.length - 1];
  const source = direction === 'inputs' ? lastEntry?.inputs : lastEntry?.outputs;
  return source?.[port];
};

const getRuntimeOutputValue = (
  runtimeState: RuntimeState,
  nodeId: string,
  port: string
): unknown => {
  const direct = runtimeState.outputs?.[nodeId]?.[port];
  if (direct !== undefined) return direct;
  return getHistoryEntryValue(runtimeState, nodeId, 'outputs', port);
};

const getRuntimeInputValue = (
  runtimeState: RuntimeState,
  nodeId: string,
  port: string
): unknown => {
  const direct = runtimeState.inputs?.[nodeId]?.[port];
  if (direct !== undefined) return direct;
  return getHistoryEntryValue(runtimeState, nodeId, 'inputs', port);
};

const resolvePortRuntimeValue = (args: {
  runtimeState: RuntimeState;
  node: AiNode;
  port: string;
  incomingEdgesByPortKey: Map<string, Edge[]>;
  parserSamples: Record<string, ParserSampleState>;
  updaterSamples: Record<string, UpdaterSampleState>;
}): unknown => {
  const directInput = getRuntimeInputValue(args.runtimeState, args.node.id, args.port);
  if (directInput !== undefined) {
    return directInput;
  }

  const incomingEdges = args.incomingEdgesByPortKey.get(`${args.node.id}::${args.port}`) ?? [];
  const upstreamValues = incomingEdges
    .map((edge: Edge): unknown => {
      const fromNodeId = resolveEdgeFromNodeId(edge);
      const fromPort = resolveEdgeFromPort(edge);
      if (!fromNodeId || !fromPort) return undefined;
      return getRuntimeOutputValue(args.runtimeState, fromNodeId, fromPort);
    })
    .filter((value: unknown): boolean => value !== undefined);

  if (upstreamValues.length === 1) {
    return upstreamValues[0];
  }
  if (upstreamValues.length > 1) {
    return upstreamValues;
  }

  if (args.node.type === 'parser') {
    const sampleValue = parseSampleJson(args.parserSamples[args.node.id]);
    if (sampleValue !== undefined) {
      return sampleValue;
    }
  }

  return undefined;
};

const resolveTemplateTokenValue = (token: string, context: Record<string, unknown>): unknown => {
  const normalizedToken = token.trim();
  if (!normalizedToken) return undefined;
  if (normalizedToken === 'value') {
    return context['value'];
  }
  if (normalizedToken === 'current') {
    return context['current'] ?? context['value'];
  }
  return getValueAtMappingPath(context, normalizedToken);
};

const pushIssue = (
  issuesByKey: Map<string, DataContractPreflightIssue>,
  issue: Omit<DataContractPreflightIssue, 'id'>
): void => {
  const keyParts = [issue.code, issue.nodeId, issue.port ?? '', issue.token ?? '', issue.message];
  const key = keyParts.join('|');
  if (issuesByKey.has(key)) return;
  issuesByKey.set(key, {
    ...issue,
    id: key,
  });
};

const buildNodeTemplateContext = (args: {
  node: AiNode;
  runtimeState: RuntimeState;
  incomingEdgesByPortKey: Map<string, Edge[]>;
  parserSamples: Record<string, ParserSampleState>;
  updaterSamples: Record<string, UpdaterSampleState>;
}): Record<string, unknown> => {
  const context: Record<string, unknown> = {};
  args.node.inputs.forEach((inputPort: string): void => {
    const value = resolvePortRuntimeValue({
      runtimeState: args.runtimeState,
      node: args.node,
      port: inputPort,
      incomingEdgesByPortKey: args.incomingEdgesByPortKey,
      parserSamples: args.parserSamples,
      updaterSamples: args.updaterSamples,
    });
    if (value !== undefined) {
      context[inputPort] = value;
    }
  });

  if (context['current'] === undefined && context['value'] !== undefined) {
    context['current'] = context['value'];
  }
  return context;
};

const resolveTokenRootCandidates = (token: string): string[] => {
  const root = normalizeTemplateRoot(token);
  if (!root) return [];
  if (root === 'current') {
    return ['current', 'value'];
  }
  return [root];
};

const hasNodeInputPort = (node: AiNode, port: string): boolean =>
  node.inputs.some(
    (inputPort: string): boolean => normalizePortName(inputPort) === normalizePortName(port)
  );

const shouldDeferMissingTemplateTokenIssue = (args: {
  node: AiNode;
  token: string;
  nodeTemplateContext: Record<string, unknown>;
  runtimeState: RuntimeState;
  incomingEdgesByPortKey: Map<string, Edge[]>;
  parserSamples: Record<string, ParserSampleState>;
  updaterSamples: Record<string, UpdaterSampleState>;
}): boolean => {
  const rootCandidates = resolveTokenRootCandidates(args.token);
  if (rootCandidates.length === 0) return false;

  const hasRootContext = rootCandidates.some(
    (root: string): boolean => args.nodeTemplateContext[root] !== undefined
  );
  if (hasRootContext) return false;

  for (const root of rootCandidates) {
    if (!hasNodeInputPort(args.node, root)) continue;
    const normalizedPort = normalizePortName(root);
    const hasIncomingEdge = Boolean(
      args.incomingEdgesByPortKey.get(`${args.node.id}::${normalizedPort}`)?.length
    );
    if (!hasIncomingEdge) continue;
    const runtimeValue = resolvePortRuntimeValue({
      runtimeState: args.runtimeState,
      node: args.node,
      port: normalizedPort,
      incomingEdgesByPortKey: args.incomingEdgesByPortKey,
      parserSamples: args.parserSamples,
      updaterSamples: args.updaterSamples,
    });
    if (runtimeValue === undefined) {
      // Upstream is wired, but there is no concrete runtime/sample evidence yet.
      return true;
    }
  }

  return false;
};

const validateDatabaseMappingContract = (args: {
  node: AiNode;
  mode: DataContractPreflightMode;
  databaseConfig: Record<string, unknown> | null;
  issuesByKey: Map<string, DataContractPreflightIssue>;
}): void => {
  if (args.mode !== 'full' || !args.databaseConfig) return;
  const updatePayloadMode = normalizeNonEmptyString(args.databaseConfig['updatePayloadMode']);
  if (updatePayloadMode !== 'mapping') return;

  const mappings = args.databaseConfig['mappings'];
  if (!Array.isArray(mappings) || mappings.length === 0) {
    pushIssue(args.issuesByKey, {
      nodeId: args.node.id,
      nodeType: args.node.type,
      nodeTitle: resolveNodeLabel(args.node, args.node.id),
      severity: 'error',
      code: 'database_mapping_invalid',
      message: 'Database mapping mode requires at least one mapping entry.',
      recommendation:
        'Add one or more mappings in the node config, or switch update payload mode to custom.',
      metadata: {
        updatePayloadMode,
      },
    });
    return;
  }

  mappings.forEach((entry: unknown, index: number): void => {
    if (!isObjectRecord(entry)) {
      pushIssue(args.issuesByKey, {
        nodeId: args.node.id,
        nodeType: args.node.type,
        nodeTitle: resolveNodeLabel(args.node, args.node.id),
        severity: 'error',
        code: 'database_mapping_invalid',
        message: `Mapping #${index + 1} is invalid.`,
        recommendation: 'Each mapping must define sourcePort and targetPath as non-empty strings.',
        metadata: {
          index,
        },
      });
      return;
    }

    const sourcePort = normalizeNonEmptyString(entry['sourcePort']);
    const targetPath = normalizeNonEmptyString(entry['targetPath']);
    if (!sourcePort || !targetPath) {
      pushIssue(args.issuesByKey, {
        nodeId: args.node.id,
        nodeType: args.node.type,
        nodeTitle: resolveNodeLabel(args.node, args.node.id),
        severity: 'error',
        code: 'database_mapping_invalid',
        message: `Mapping #${index + 1} is missing sourcePort or targetPath.`,
        recommendation: 'Each mapping must define sourcePort and targetPath as non-empty strings.',
        metadata: {
          index,
          sourcePort: sourcePort ?? null,
          targetPath: targetPath ?? null,
        },
      });
      return;
    }

    if (!hasNodeInputPort(args.node, sourcePort)) {
      pushIssue(args.issuesByKey, {
        nodeId: args.node.id,
        nodeType: args.node.type,
        nodeTitle: resolveNodeLabel(args.node, args.node.id),
        severity: 'error',
        code: 'database_mapping_source_port_missing',
        port: sourcePort,
        message: `Mapping #${index + 1} references source port "${sourcePort}", but the node does not expose that input.`,
        recommendation: `Change sourcePort to a connected node input or add "${sourcePort}" to this node inputs.`,
        metadata: {
          index,
          targetPath,
        },
      });
    }
  });
};

export const evaluateDataContractPreflight = (
  args: EvaluateDataContractPreflightArgs
): DataContractPreflightReport => {
  const mode: DataContractPreflightMode = args.mode ?? 'light';
  const scopeMode: DataContractPreflightScopeMode = args.scopeMode ?? 'full';
  const parserSamples: Record<string, ParserSampleState> = args.parserSamples ?? {};
  const updaterSamples: Record<string, UpdaterSampleState> = args.updaterSamples ?? {};
  const runtimeState: RuntimeState = args.runtimeState ?? {
    status: 'idle',
    nodeStatuses: {},
    nodeOutputs: {},
    variables: {},
    events: [],
    inputs: {},
    outputs: {},
  };

  const sanitizedEdges = sanitizeEdges(args.nodes, args.edges);
  const scoped =
    scopeMode === 'reachable_from_roots'
      ? buildReachableScope(args.nodes, sanitizedEdges, args.scopeRootNodeIds)
      : {
        nodes: args.nodes,
        edges: sanitizedEdges,
        reachableNodeIds: new Set(args.nodes.map((node: AiNode): string => node.id)),
      };

  const nodes = scoped.nodes;
  const edges = scoped.edges;
  const nodeById = new Map(nodes.map((node: AiNode): [string, AiNode] => [node.id, node]));
  const issuesByKey = new Map<string, DataContractPreflightIssue>();

  const incomingEdgesByPortKey = new Map<string, Edge[]>();
  edges.forEach((edge: Edge): void => {
    const toNodeId = resolveEdgeToNodeId(edge);
    const toPortRaw = resolveEdgeToPort(edge);
    if (!toNodeId || !toPortRaw) return;
    const toPort = normalizePortName(toPortRaw);
    const key = `${toNodeId}::${toPort}`;
    const existing = incomingEdgesByPortKey.get(key) ?? [];
    existing.push(edge);
    incomingEdgesByPortKey.set(key, existing);
  });

  edges.forEach((edge: Edge): void => {
    const fromNodeId = resolveEdgeFromNodeId(edge);
    const toNodeId = resolveEdgeToNodeId(edge);
    const fromPortRaw = resolveEdgeFromPort(edge);
    const toPortRaw = resolveEdgeToPort(edge);
    if (!fromNodeId || !toNodeId || !fromPortRaw || !toPortRaw) return;
    const fromNode = nodeById.get(fromNodeId);
    const toNode = nodeById.get(toNodeId);
    if (!fromNode || !toNode) return;

    const fromPort = normalizePortName(fromPortRaw);
    const toPort = normalizePortName(toPortRaw);

    const fromTypes = getPortDataTypes(fromPort);
    const toTypes = getPortDataTypes(toPort);
    if (!arePortTypesCompatible(fromTypes, toTypes)) {
      pushIssue(issuesByKey, {
        nodeId: toNode.id,
        nodeType: toNode.type,
        nodeTitle: resolveNodeLabel(toNode, toNode.id),
        severity: 'warning',
        code: 'connection_type_mismatch',
        port: toPort,
        message: `Port type mismatch for ${toPort}: ${formatPortDataTypes(fromTypes)} -> ${formatPortDataTypes(toTypes)}.`,
        recommendation: `Rewire to a compatible input or map/cast ${fromPort} before sending to ${toPort}.`,
        metadata: {
          edgeId: edge.id,
          fromNodeId,
          fromPort,
          toNodeId,
          toPort,
        },
      });
    }

    const runtimeOutputValue = getRuntimeOutputValue(runtimeState, fromNodeId, fromPort);
    if (
      runtimeOutputValue !== undefined &&
      !isValueCompatibleWithTypes(runtimeOutputValue, toTypes)
    ) {
      const actualType = getValueTypeLabel(runtimeOutputValue);
      const severity: DataContractIssueSeverity =
        mode === 'full' && getNodeInputPortContract(toNode, toPort).required === true
          ? 'error'
          : 'warning';
      pushIssue(issuesByKey, {
        nodeId: toNode.id,
        nodeType: toNode.type,
        nodeTitle: resolveNodeLabel(toNode, toNode.id),
        severity,
        code: 'runtime_value_type_mismatch',
        port: toPort,
        message: `Runtime value for ${toPort} is ${actualType}, expected ${formatPortDataTypes(toTypes)}.`,
        recommendation: `Map the upstream value to ${toPort} shape before execution.`,
        metadata: {
          edgeId: edge.id,
          fromNodeId,
          fromPort,
          actualType,
        },
      });
    }
  });

  nodes.forEach((node: AiNode): void => {
    const requiredPorts = node.inputs.filter(
      (port: string): boolean => getNodeInputPortContract(node, port).required === true
    );

    requiredPorts.forEach((requiredPort: string): void => {
      const incomingEdges = incomingEdgesByPortKey.get(`${node.id}::${requiredPort}`) ?? [];

      if (incomingEdges.length === 0) {
        pushIssue(issuesByKey, {
          nodeId: node.id,
          nodeType: node.type,
          nodeTitle: resolveNodeLabel(node, node.id),
          severity: mode === 'full' ? 'error' : 'warning',
          code: 'required_input_unresolved',
          port: requiredPort,
          message: `Required input ${requiredPort} has no incoming edge.`,
          recommendation: `Connect a source to ${requiredPort} or disable strict requirement for this port.`,
        });
        return;
      }

      if (mode !== 'full') {
        return;
      }

      const resolvedValue = resolvePortRuntimeValue({
        runtimeState,
        node,
        port: requiredPort,
        incomingEdgesByPortKey,
        parserSamples,
        updaterSamples,
      });

      if (resolvedValue === undefined) {
        return;
      }
      if (resolvedValue === null) {
        pushIssue(issuesByKey, {
          nodeId: node.id,
          nodeType: node.type,
          nodeTitle: resolveNodeLabel(node, node.id),
          severity: 'error',
          code: 'required_input_nullish',
          port: requiredPort,
          message: `Required input ${requiredPort} resolves to null.`,
          recommendation: `Ensure upstream token mapping for ${requiredPort} resolves to a non-null value.`,
        });
        return;
      }
      if (isEmptyValue(resolvedValue)) {
        pushIssue(issuesByKey, {
          nodeId: node.id,
          nodeType: node.type,
          nodeTitle: resolveNodeLabel(node, node.id),
          severity: 'error',
          code: 'required_input_empty',
          port: requiredPort,
          message: `Required input ${requiredPort} resolves to an empty value.`,
          recommendation: `Provide a non-empty value for ${requiredPort} before execution.`,
        });
      }
    });

    if (node.type !== 'database' || mode !== 'full') {
      return;
    }

    const databaseConfig = isObjectRecord(node.config?.database)
      ? (node.config?.database as Record<string, unknown>)
      : null;
    validateDatabaseMappingContract({
      node,
      mode,
      databaseConfig,
      issuesByKey,
    });

    const nodeTemplateContext = buildNodeTemplateContext({
      node,
      runtimeState,
      incomingEdgesByPortKey,
      parserSamples,
      updaterSamples,
    });

    const identityPorts: Array<'entityId' | 'productId'> = ['entityId', 'productId'];
    identityPorts.forEach((identityPort) => {
      const identityValue = resolvePortRuntimeValue({
        runtimeState,
        node,
        port: identityPort,
        incomingEdgesByPortKey,
        parserSamples,
        updaterSamples,
      });
      if (identityValue === undefined || identityValue === null) return;
      if (typeof identityValue === 'string' || typeof identityValue === 'number') return;
      pushIssue(issuesByKey, {
        nodeId: node.id,
        nodeType: node.type,
        nodeTitle: resolveNodeLabel(node, node.id),
        severity: 'error',
        code: 'database_scalar_identity_expected',
        port: identityPort,
        message: `Database ${identityPort} expects a scalar id, but received ${getValueTypeLabel(identityValue)}.`,
        recommendation:
          'Use a mapped scalar id (for example `bundle.EntityID`) rather than passing the full bundle object.',
      });
    });

    const queryInputs: Array<'query' | 'queryCallback' | 'aiQuery'> = [
      'query',
      'queryCallback',
      'aiQuery',
    ];
    queryInputs.forEach((queryPort) => {
      const queryInputValue = resolvePortRuntimeValue({
        runtimeState,
        node,
        port: queryPort,
        incomingEdgesByPortKey,
        parserSamples,
        updaterSamples,
      });
      if (queryInputValue === undefined || queryInputValue === null) return;
      if (isObjectRecord(queryInputValue)) return;
      if (typeof queryInputValue === 'string') {
        const candidate = extractTemplateRawJsonCandidate(queryInputValue);
        const parsed = parseJsonSafe(candidate);
        if (isObjectRecord(parsed)) return;
        const severity: DataContractIssueSeverity =
          queryInputValue.includes('{{') || queryInputValue.includes('[') ? 'warning' : 'error';
        pushIssue(issuesByKey, {
          nodeId: node.id,
          nodeType: node.type,
          nodeTitle: resolveNodeLabel(node, node.id),
          severity,
          code: 'database_query_input_shape_mismatch',
          port: queryPort,
          message: `Database ${queryPort} must resolve to a JSON object query.`,
          recommendation:
            'Provide an object payload or a JSON string that parses to an object (optionally tokenized).',
        });
        return;
      }
      pushIssue(issuesByKey, {
        nodeId: node.id,
        nodeType: node.type,
        nodeTitle: resolveNodeLabel(node, node.id),
        severity: 'error',
        code: 'database_query_input_shape_mismatch',
        port: queryPort,
        message: `Database ${queryPort} received ${getValueTypeLabel(queryInputValue)}; expected object query input.`,
        recommendation: 'Map this input to an object query shape or pass a JSON object string.',
      });
    });

    const templateSources: Array<{ label: string; template: string }> = [
      {
        label: 'database.query.queryTemplate',
        template: normalizeNonEmptyString(node.config?.database?.query?.queryTemplate) ?? '',
      },
      {
        label: 'database.updateTemplate',
        template: normalizeNonEmptyString(node.config?.database?.updateTemplate) ?? '',
      },
    ].filter((entry: { label: string; template: string }): boolean => entry.template.length > 0);

    templateSources.forEach((source: { label: string; template: string }): void => {
      const tokens = extractTemplateTokens(source.template);
      tokens.forEach((token: string): void => {
        const root = normalizeTemplateRoot(token);
        if (
          root &&
          root !== 'current' &&
          !hasNodeInputPort(node, root) &&
          nodeTemplateContext[root] === undefined
        ) {
          pushIssue(issuesByKey, {
            nodeId: node.id,
            nodeType: node.type,
            nodeTitle: resolveNodeLabel(node, node.id),
            severity: 'error',
            code: 'database_template_token_root_missing',
            port: root,
            token,
            message: `${source.label} token {{${token}}} references root "${root}" that is not available on this node.`,
            recommendation:
              'Use a token root that matches a connected node input (or switch the mapping/template to a valid root).',
            metadata: { template: source.label },
          });
          return;
        }
        const value = resolveTemplateTokenValue(token, nodeTemplateContext);
        if (value === undefined) {
          if (
            shouldDeferMissingTemplateTokenIssue({
              node,
              token,
              nodeTemplateContext,
              runtimeState,
              incomingEdgesByPortKey,
              parserSamples,
              updaterSamples,
            })
          ) {
            pushIssue(issuesByKey, {
              nodeId: node.id,
              nodeType: node.type,
              nodeTitle: resolveNodeLabel(node, node.id),
              severity: 'warning',
              code: 'database_template_token_missing',
              token,
              message: `${source.label} token {{${token}}} cannot be verified at preflight (upstream connected, but no runtime/sample evidence yet).`,
              recommendation:
                'Seed parser/updater samples or run a dry simulation so template token values can be validated before execution.',
              metadata: {
                template: source.label,
                deferred: true,
              },
            });
            return;
          }
          pushIssue(issuesByKey, {
            nodeId: node.id,
            nodeType: node.type,
            nodeTitle: resolveNodeLabel(node, node.id),
            severity: 'error',
            code: 'database_template_token_missing',
            token,
            message: `${source.label} token {{${token}}} resolves to undefined.`,
            recommendation: `Connect or map token {{${token}}} before running this database node.`,
            metadata: { template: source.label },
          });
          return;
        }
        if (value === null || isEmptyValue(value)) {
          pushIssue(issuesByKey, {
            nodeId: node.id,
            nodeType: node.type,
            nodeTitle: resolveNodeLabel(node, node.id),
            severity: 'error',
            code: 'database_template_token_empty',
            token,
            message: `${source.label} token {{${token}}} resolves to null/empty.`,
            recommendation: `Ensure {{${token}}} resolves to a non-empty value before execution.`,
            metadata: { template: source.label },
          });
        }
      });
    });
  });

  const issues = Array.from(issuesByKey.values()).sort((left, right) => {
    if (left.severity !== right.severity) {
      return left.severity === 'error' ? -1 : 1;
    }
    if (left.nodeId !== right.nodeId) {
      return left.nodeId.localeCompare(right.nodeId);
    }
    return left.code.localeCompare(right.code);
  });

  const byNodeId: Record<string, DataContractNodeIssueSummary> = {};
  issues.forEach((issue: DataContractPreflightIssue): void => {
    const current = byNodeId[issue.nodeId] ?? {
      errors: 0,
      warnings: 0,
      issues: [],
    };
    if (issue.severity === 'error') {
      current.errors += 1;
    } else {
      current.warnings += 1;
    }
    current.issues.push(issue);
    byNodeId[issue.nodeId] = current;
  });

  const errors = issues.filter((issue) => issue.severity === 'error').length;
  const warnings = issues.filter((issue) => issue.severity === 'warning').length;

  return {
    mode,
    scopeMode,
    scopedNodeIds: Array.from(scoped.reachableNodeIds),
    issues,
    errors,
    warnings,
    byNodeId,
  };
};

import type {
  AiNode,
  Edge,
  DependencyRiskSeverity,
  DependencyRisk,
  DependencyReport,
  DependencyInspectorScopeMode,
  DependencyInspectorOptions,
} from '@/shared/contracts/ai-paths';
import type { LabeledOptionDto } from '@/shared/contracts/base';

export type {
  DependencyRiskSeverity,
  DependencyRisk,
  DependencyReport,
  DependencyInspectorScopeMode,
  DependencyInspectorOptions,
};

const TEMPLATE_TOKEN_REGEX: RegExp = /{{\s*([^}]+)\s*}}|\[\s*([A-Za-z0-9_.$:-]+)\s*\]/g;

const TEMPLATE_SYSTEM_ROOT_PREFIXES = ['Date:', 'DB Provider:', 'Collection:'];

const normalizeNonEmptyString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const resolveEdgeFromNodeId = (edge: Edge): string | null => normalizeNonEmptyString(edge.from);

const resolveEdgeToNodeId = (edge: Edge): string | null => normalizeNonEmptyString(edge.to);

const getIncomingPorts = (nodeId: string, edges: Edge[]): Set<string> => {
  const ports = new Set<string>();
  edges.forEach((edge: Edge): void => {
    const targetNodeId = resolveEdgeToNodeId(edge);
    if (targetNodeId !== nodeId) return;
    const toPort = normalizeNonEmptyString(edge.toPort);
    if (!toPort) return;
    ports.add(toPort);
  });
  return ports;
};

const hasAnyPort = (ports: Set<string>, candidates: string[]): boolean =>
  candidates.some((candidate: string): boolean => ports.has(candidate));

const normalizeTemplateRoot = (token: string): string => {
  const rootCandidate = token.split('.')[0]?.trim() ?? '';
  return rootCandidate.replace(/\[[^\]]*\]/g, '').trim();
};

const isSystemTemplateRoot = (root: string): boolean =>
  root === 'value' ||
  root === 'current' ||
  TEMPLATE_SYSTEM_ROOT_PREFIXES.some((prefix: string): boolean => root.startsWith(prefix));

const extractTemplateRoots = (template: string): string[] => {
  const roots = new Set<string>();
  TEMPLATE_TOKEN_REGEX.lastIndex = 0;
  let match: RegExpExecArray | null = TEMPLATE_TOKEN_REGEX.exec(template);
  while (match) {
    const token = (match[1] ?? match[2] ?? '').trim();
    if (token) {
      const root = normalizeTemplateRoot(token);
      if (root && !isSystemTemplateRoot(root)) {
        roots.add(root);
      }
    }
    match = TEMPLATE_TOKEN_REGEX.exec(template);
  }
  return Array.from(roots);
};

const collectDatabaseWriteTemplateRoots = (
  node: AiNode
): {
  roots: string[];
  templateLabels: string[];
} => {
  const dbConfig = node.config?.database;
  if (!dbConfig) {
    return { roots: [], templateLabels: [] };
  }
  const operation = dbConfig.operation ?? 'query';
  const isWriteOperation =
    operation === 'update' ||
    operation === 'insert' ||
    operation === 'delete' ||
    (dbConfig.useMongoActions &&
      (dbConfig.actionCategory === 'create' ||
        dbConfig.actionCategory === 'update' ||
        dbConfig.actionCategory === 'delete'));
  if (!isWriteOperation) {
    return { roots: [], templateLabels: [] };
  }

  const templateSources: Array<LabeledOptionDto<string>> = [
    {
      label: 'database.query.queryTemplate',
      value: normalizeNonEmptyString(dbConfig.query?.queryTemplate) ?? '',
    },
    {
      label: 'database.updateTemplate',
      value: normalizeNonEmptyString(dbConfig.updateTemplate) ?? '',
    },
  ].filter((entry: LabeledOptionDto<string>): boolean => entry.value.length > 0);

  const roots = new Set<string>();
  templateSources.forEach((entry: LabeledOptionDto<string>): void => {
    extractTemplateRoots(entry.value).forEach((root: string): void => {
      roots.add(root);
    });
  });
  return {
    roots: Array.from(roots),
    templateLabels: templateSources.map((entry: LabeledOptionDto<string>): string => entry.label),
  };
};

const pushRisk = (
  risks: DependencyRisk[],
  node: AiNode,
  category: string,
  severity: DependencyRiskSeverity,
  message: string,
  recommendation: string
): void => {
  risks.push({
    id: `${node.id}:${category}`,
    nodeId: node.id,
    nodeTitle: node.title ?? node.id,
    nodeType: node.type,
    severity,
    category,
    message,
    recommendation,
  });
};

const resolveScopedRootNodeIds = (
  nodes: AiNode[],
  edges: Edge[],
  options: DependencyInspectorOptions
): string[] => {
  const nodeIdSet = new Set(nodes.map((node: AiNode): string => node.id));
  const explicitRootIds = (
    Array.isArray(options.scopeRootNodeIds)
      ? options.scopeRootNodeIds
      : options.scopeRootNodeIds
        ? Array.from(options.scopeRootNodeIds)
        : []
  )
    .map((nodeId: string): string => nodeId.trim())
    .filter((nodeId: string): boolean => nodeId.length > 0 && nodeIdSet.has(nodeId));
  const explicitUnique = Array.from(new Set(explicitRootIds));
  if (explicitUnique.length > 0) return explicitUnique;

  const triggerRootIds = nodes
    .filter((node: AiNode): boolean => node.type === 'trigger')
    .map((node: AiNode): string => node.id);
  if (triggerRootIds.length > 0) return triggerRootIds;

  const incomingNodeIds = new Set<string>();
  edges.forEach((edge: Edge): void => {
    const toNodeId = resolveEdgeToNodeId(edge);
    if (!toNodeId || !nodeIdSet.has(toNodeId)) return;
    incomingNodeIds.add(toNodeId);
  });
  const fallbackRootIds = nodes
    .filter((node: AiNode): boolean => !incomingNodeIds.has(node.id))
    .map((node: AiNode): string => node.id);
  if (fallbackRootIds.length > 0) return fallbackRootIds;

  return nodes[0] ? [nodes[0].id] : [];
};

const buildReachableDependencyScope = (
  nodes: AiNode[],
  edges: Edge[],
  options: DependencyInspectorOptions
): { nodes: AiNode[]; edges: Edge[] } => {
  if (nodes.length === 0) return { nodes, edges };

  const nodeIdSet = new Set(nodes.map((node: AiNode): string => node.id));
  const rootNodeIds = resolveScopedRootNodeIds(nodes, edges, options);
  if (rootNodeIds.length === 0) return { nodes, edges };

  const adjacency = new Map<string, Set<string>>();
  edges.forEach((edge: Edge): void => {
    const fromNodeId = resolveEdgeFromNodeId(edge);
    const toNodeId = resolveEdgeToNodeId(edge);
    if (!fromNodeId || !toNodeId) return;
    if (!nodeIdSet.has(fromNodeId) || !nodeIdSet.has(toNodeId)) return;
    const next = adjacency.get(fromNodeId) ?? new Set<string>();
    next.add(toNodeId);
    adjacency.set(fromNodeId, next);
  });

  const queue = [...rootNodeIds];
  const reachableNodeIds = new Set<string>(rootNodeIds);
  while (queue.length > 0) {
    const current = queue.shift();
    if (!current) continue;
    const next = adjacency.get(current);
    if (!next) continue;
    next.forEach((nodeId: string): void => {
      if (reachableNodeIds.has(nodeId)) return;
      reachableNodeIds.add(nodeId);
      queue.push(nodeId);
    });
  }

  if (reachableNodeIds.size === 0 || reachableNodeIds.size === nodes.length) {
    return { nodes, edges };
  }

  const scopedNodes = nodes.filter((node: AiNode): boolean => reachableNodeIds.has(node.id));
  const scopedNodeIdSet = new Set(scopedNodes.map((node: AiNode): string => node.id));
  const scopedEdges = edges.filter((edge: Edge): boolean => {
    const fromNodeId = resolveEdgeFromNodeId(edge);
    const toNodeId = resolveEdgeToNodeId(edge);
    if (!fromNodeId || !toNodeId) return false;
    return scopedNodeIdSet.has(fromNodeId) && scopedNodeIdSet.has(toNodeId);
  });
  return {
    nodes: scopedNodes,
    edges: scopedEdges,
  };
};

export const inspectPathDependencies = (
  nodes: AiNode[],
  edges: Edge[],
  options: DependencyInspectorOptions = {}
): DependencyReport => {
  if (options.scopeMode === 'reachable_from_roots') {
    const scoped = buildReachableDependencyScope(nodes, edges, options);
    return inspectPathDependencies(scoped.nodes, scoped.edges, {
      ...options,
      scopeMode: 'full',
      scopeRootNodeIds: undefined,
    });
  }

  const risks: DependencyRisk[] = [];

  nodes.forEach((node: AiNode): void => {
    const incomingPorts = getIncomingPorts(node.id, edges);

    if (node.type === 'trigger') return;

    if (node.type === 'parser') {
      if (!incomingPorts.has('entityJson') && !incomingPorts.has('context')) {
        pushRisk(
          risks,
          node,
          'parser_entity_fallback',
          'warning',
          'Parser has no `entityJson` or `context` input and may run with empty source data.',
          'Connect `entityJson` or `context` from upstream nodes.'
        );
      }
      return;
    }

    if (node.type !== 'database') return;

    const waitForInputsEnabled = node.config?.runtime?.waitForInputs === true;
    if (!waitForInputsEnabled) {
      pushRisk(
        risks,
        node,
        'database_wait_for_inputs_disabled',
        'warning',
        'Database node runs without `waitForInputs` guard and can execute on partial data.',
        'Enable `runtime.waitForInputs` in this node configuration.'
      );
    }

    const dbConfig = node.config?.database;
    const operation = dbConfig?.operation ?? 'query';
    if (dbConfig?.updatePayloadMode === 'mapping') {
      pushRisk(
        risks,
        node,
        'database_update_mode_mapping_disallowed',
        'error',
        'Mapping-based update mode is disallowed for Database nodes.',
        'Switch database.updatePayloadMode to `custom` and define explicit query/update templates.'
      );
    }

    if (operation === 'query') {
      const queryMode = dbConfig?.query?.mode ?? 'custom';
      if (queryMode === 'preset') {
        pushRisk(
          risks,
          node,
          'database_query_mode_preset_disallowed',
          'error',
          'Preset query mode is disallowed for Database nodes. Queries must be explicit.',
          'Switch database.query.mode to `custom` and define explicit queryTemplate or query input.'
        );
      }
      const hasQueryInput = hasAnyPort(incomingPorts, ['query', 'queryCallback', 'aiQuery']);
      const queryTemplate = normalizeNonEmptyString(dbConfig?.query?.queryTemplate);
      if (!queryTemplate && !hasQueryInput) {
        pushRisk(
          risks,
          node,
          'database_query_missing_explicit_query',
          'error',
          'Database query has no explicit query template and no explicit query input wiring.',
          'Define database.query.queryTemplate or connect query/queryCallback/aiQuery.'
        );
      }
      return;
    }

    if (operation === 'update' || operation === 'delete') {
      if (
        !hasAnyPort(incomingPorts, ['entityId', 'productId', 'value', 'context', 'bundle', 'meta'])
      ) {
        pushRisk(
          risks,
          node,
          'database_write_missing_identity_inputs',
          'error',
          'Write operation has no connected identity inputs and may rely on hidden fallback IDs.',
          'Connect `entityId`/`productId` (or `value`) from explicit upstream outputs.'
        );
      }
    }

    const templateRootAnalysis = collectDatabaseWriteTemplateRoots(node);
    if (templateRootAnalysis.roots.length > 0) {
      const nodeInputPorts = new Set(
        (Array.isArray(node.inputs) ? node.inputs : [])
          .map((port: string): string => port.trim())
          .filter((port: string): boolean => port.length > 0)
      );
      const missingTemplateRoots = templateRootAnalysis.roots.filter(
        (root: string): boolean => nodeInputPorts.has(root) && !incomingPorts.has(root)
      );
      if (missingTemplateRoots.length > 0) {
        const templatesLabel =
          templateRootAnalysis.templateLabels.length > 0
            ? templateRootAnalysis.templateLabels.join(', ')
            : 'database templates';
        pushRisk(
          risks,
          node,
          'database_write_template_missing_wiring',
          'error',
          `Write template placeholders depend on unwired inputs: ${missingTemplateRoots.join(
            ', '
          )} (${templatesLabel}).`,
          `Wire incoming edges to ${missingTemplateRoots.join(
            ', '
          )}, or rewrite templates to use currently wired ports only.`
        );
      }
    }
  });

  const warnings = risks.filter(
    (risk: DependencyRisk): boolean => risk.severity === 'warning'
  ).length;
  const errors = risks.filter((risk: DependencyRisk): boolean => risk.severity === 'error').length;
  return {
    risks,
    warnings,
    errors,
    strictReady: errors === 0,
  };
};

import type { AiNode, Edge, PathConfig, PathMeta } from '@/shared/contracts/ai-paths';

import {
  STORAGE_VERSION,
  initialEdges,
  initialNodes,
  triggers,
} from '../constants';
import { sanitizeEdges } from './graph.edges';
import { cloneValue, hashString, stableStringify } from './runtime';
import { normalizeNodes } from '../normalization/normalization.nodes';
import {
  DEFAULT_AI_PATHS_VALIDATION_CONFIG,
  normalizeAiPathsValidationConfig,
} from '../validation-engine';
import { normalizeAiPathFolderPath } from './path-folders';

export const createPathId = (): string => `path_${Math.random().toString(36).slice(2, 8)}`;

export const createPresetId = (): string => `preset_${Math.random().toString(36).slice(2, 8)}`;

const createCanonicalNodeId = (seed: string): string =>
  `node-${[
    hashString(seed),
    hashString(`a:${seed}`),
    hashString(`b:${seed}`),
    hashString(`c:${seed}`),
  ]
    .join('')
    .slice(0, 24)}`;

const buildUniqueCanonicalNodeId = ({
  pathId,
  sourceId,
  node,
  index,
  usedIds,
}: {
  pathId: string;
  sourceId: string;
  node: Pick<AiNode, 'type' | 'title'>;
  index: number;
  usedIds: Set<string>;
}): string => {
  let collisionSalt = 0;
  let candidate = '';
  while (!candidate || usedIds.has(candidate)) {
    candidate = createCanonicalNodeId(
      stableStringify({
        kind: 'ai_paths_factory_node',
        pathId,
        // Keep stable seed key name for deterministic id continuity.
        legacyId: sourceId,
        type: node.type,
        title: node.title,
        index,
        collisionSalt,
      })
    );
    collisionSalt += 1;
  }
  usedIds.add(candidate);
  return candidate;
};

const remapNodeKeyedRecord = <T>(
  value: Record<string, T> | undefined,
  nodeIdMap: Map<string, string>
): Record<string, T> => {
  if (!value || typeof value !== 'object') return {};
  const next: Record<string, T> = {};
  Object.entries(value).forEach(([key, entry]: [string, T]): void => {
    const remappedKey = nodeIdMap.get(key.trim());
    if (!remappedKey) return;
    next[remappedKey] = entry;
  });
  return next;
};

const canonicalizePathNodes = ({
  pathId,
  nodes,
  edges,
  selectedNodeId,
  parserSamples,
  updaterSamples,
  timestamp,
}: {
  pathId: string;
  nodes: AiNode[];
  edges: Edge[];
  selectedNodeId?: string | null;
  parserSamples?: PathConfig['parserSamples'];
  updaterSamples?: PathConfig['updaterSamples'];
  timestamp: string;
}): {
  nodes: AiNode[];
  edges: Edge[];
  selectedNodeId: string | null;
  parserSamples: PathConfig['parserSamples'];
  updaterSamples: PathConfig['updaterSamples'];
} => {
  const usedIds = new Set<string>();
  const nodeIdMap = new Map<string, string>();
  const remappedNodes = nodes.map((node: AiNode, index: number): AiNode => {
    const sourceId = typeof node.id === 'string' ? node.id.trim() : '';
    const nextId = buildUniqueCanonicalNodeId({
      pathId,
      sourceId,
      node,
      index,
      usedIds,
    });
    if (sourceId) {
      nodeIdMap.set(sourceId, nextId);
    }
    return {
      ...node,
      id: nextId,
      instanceId: nextId,
      nodeTypeId: undefined,
      createdAt:
        typeof node.createdAt === 'string' && node.createdAt.trim().length > 0
          ? node.createdAt
          : timestamp,
      updatedAt:
        typeof node.updatedAt === 'string' && node.updatedAt.trim().length > 0
          ? node.updatedAt
          : null,
    };
  });
  const remappedEdges = edges.flatMap((edge: Edge): Edge[] => {
    const sourceId = typeof edge.from === 'string' ? edge.from.trim() : '';
    const targetId = typeof edge.to === 'string' ? edge.to.trim() : '';
    const nextFrom = nodeIdMap.get(sourceId);
    const nextTo = nodeIdMap.get(targetId);
    if (!nextFrom || !nextTo) return [];
    return [
      {
        ...edge,
        from: nextFrom,
        to: nextTo,
      },
    ];
  });
  const normalizedNodes = normalizeNodes(remappedNodes);
  const normalizedEdges = sanitizeEdges(normalizedNodes, remappedEdges);
  const remappedSelectedNodeId =
    typeof selectedNodeId === 'string' ? (nodeIdMap.get(selectedNodeId.trim()) ?? null) : null;
  return {
    nodes: normalizedNodes,
    edges: normalizedEdges,
    selectedNodeId:
      remappedSelectedNodeId &&
      normalizedNodes.some((node: AiNode): boolean => node.id === remappedSelectedNodeId)
        ? remappedSelectedNodeId
        : (normalizedNodes[0]?.id ?? null),
    parserSamples: remapNodeKeyedRecord(parserSamples, nodeIdMap),
    updaterSamples: remapNodeKeyedRecord(updaterSamples, nodeIdMap),
  };
};

export const createDefaultPathConfig = (id: string): PathConfig => {
  const now = new Date().toISOString();
  const graph = canonicalizePathNodes({
    pathId: id,
    nodes: cloneValue(initialNodes),
    edges: cloneValue(initialEdges),
    selectedNodeId: initialNodes[0]?.id ?? null,
    parserSamples: {},
    updaterSamples: {},
    timestamp: now,
  });
  const config: PathConfig = {
    id,
    version: STORAGE_VERSION,
    name: 'Description Inference Path',
    description: 'Vision + text model workflow with structured updates.',
    trigger: triggers[0] ?? 'Product Modal - Context Filter',
    executionMode: 'server',
    flowIntensity: 'medium',
    runMode: 'block',
    strictFlowMode: true,
    blockedRunPolicy: 'fail_run',
    aiPathsValidation: normalizeAiPathsValidationConfig(DEFAULT_AI_PATHS_VALIDATION_CONFIG),
    nodes: graph.nodes,
    edges: graph.edges,
    updatedAt: now,
    isLocked: false,
    isActive: true,
    parserSamples: graph.parserSamples,
    updaterSamples: graph.updaterSamples,
    runtimeState: { inputs: {}, outputs: {} },
    lastRunAt: null,
    runCount: 0,
    uiState: {
      selectedNodeId: graph.selectedNodeId,
      configOpen: false,
    },
  };
  return config;
};

export const createPathMeta = (
  config: PathConfig,
  options?: { folderPath?: string | null | undefined }
): PathMeta => {
  const fallbackName = `Path ${config.id.slice(0, 6)}`;
  const resolvedName =
    typeof config.name === 'string' && config.name.trim().length > 0
      ? config.name.trim()
      : fallbackName;
  return {
    id: config.id,
    name: resolvedName,
    folderPath: normalizeAiPathFolderPath(options?.folderPath),
    createdAt: config.updatedAt,
    updatedAt: config.updatedAt,
  };
};

export const duplicatePathConfig = ({
  sourceConfig,
  duplicateId,
  duplicateName,
  updatedAt,
}: {
  sourceConfig: PathConfig;
  duplicateId: string;
  duplicateName: string;
  updatedAt: string;
}): PathConfig => {
  const graph = canonicalizePathNodes({
    pathId: duplicateId,
    nodes: cloneValue(sourceConfig.nodes ?? []),
    edges: cloneValue(sourceConfig.edges ?? []),
    selectedNodeId: sourceConfig.uiState?.selectedNodeId ?? null,
    parserSamples: cloneValue(sourceConfig.parserSamples ?? {}) as PathConfig['parserSamples'],
    updaterSamples: cloneValue(sourceConfig.updaterSamples ?? {}) as PathConfig['updaterSamples'],
    timestamp: updatedAt,
  });

  return {
    ...sourceConfig,
    id: duplicateId,
    name: duplicateName,
    nodes: graph.nodes,
    edges: graph.edges,
    updatedAt,
    isLocked: false,
    parserSamples: graph.parserSamples,
    updaterSamples: graph.updaterSamples,
    runtimeState: {},
    lastRunAt: null,
    runCount: 0,
    uiState: {
      selectedNodeId: graph.selectedNodeId,
      configOpen: false,
    },
  };
};

import type { AiNode, Edge } from '@/shared/contracts/ai-paths';
import type { DependencyInspectorOptions as CompileGraphOptions } from '@/shared/contracts/ai-paths-core/engine';

import { sanitizeEdgesDetailed } from './graph.edges';
import {
  getNodeInputPortCardinality,
  getNodeInputPortContract,
  getResolvedNodeInputPortContract,
  getResolvedNodeOutputPortContract,
} from './graph.nodes';
import { normalizePortName } from './graph.ports';
import {
  arePortTypesCompatible,
  getPortDataTypes,
  getPortDataTypesForValueKind,
} from './port-types';

import type { GraphCompileFinding, GraphCompileReport } from './graph.types';

const resolvePortCompatibilityTypes = (
  node: AiNode,
  port: string,
  direction: 'input' | 'output'
) => {
  const contract =
    direction === 'input'
      ? getResolvedNodeInputPortContract(node, port)
      : getResolvedNodeOutputPortContract(node, port);
  if (contract.kind !== 'unknown') {
    return getPortDataTypesForValueKind(contract.kind);
  }
  return getPortDataTypes(port);
};

export const compileGraph = (
  nodes: AiNode[],
  edges: Edge[],
  options: CompileGraphOptions = {}
): GraphCompileReport => {
  const findings: GraphCompileFinding[] = [];
  const { edges: normalizedEdges, dropped: droppedEdgeFindings } = sanitizeEdgesDetailed(
    nodes,
    edges
  );
  findings.push(...droppedEdgeFindings);

  const nodeMap = new Map(nodes.map((node: AiNode) => [node.id, node]));
  const adjacency = new Map<string, string[]>();
  const inverseAdjacency = new Map<string, string[]>();
  const edgeMap = new Map<string, Edge[]>(); // toNodeId -> edges
  const outgoingEdgeMap = new Map<string, Edge[]>(); // fromNodeId -> edges

  normalizedEdges.forEach((edge: Edge) => {
    if (!edge.from || !edge.to) return;

    const targets = adjacency.get(edge.from) ?? [];
    targets.push(edge.to);
    adjacency.set(edge.from, targets);

    const sources = inverseAdjacency.get(edge.to) ?? [];
    sources.push(edge.from);
    inverseAdjacency.set(edge.to, sources);

    const nodeEdges = edgeMap.get(edge.to) ?? [];
    nodeEdges.push(edge);
    edgeMap.set(edge.to, nodeEdges);

    const outgoingEdges = outgoingEdgeMap.get(edge.from) ?? [];
    outgoingEdges.push(edge);
    outgoingEdgeMap.set(edge.from, outgoingEdges);
  });

  const triggerNode = nodes.find((node: AiNode) => node.type === 'trigger');
  const triggerNodeId = triggerNode?.id ?? null;

  const processingNodeIds = nodes
    .filter((node: AiNode) => node.type !== 'trigger' && node.type !== 'viewer')
    .map((node: AiNode) => node.id);

  const terminalNodeIds = nodes
    .filter((node: AiNode) => {
      const targets = adjacency.get(node.id) ?? [];
      return targets.length === 0;
    })
    .map((node: AiNode) => node.id);

  // Scoping logic
  let reachableNodeIds = new Set<string>(nodes.map((n) => n.id));
  if (options.scopeMode === 'reachable_from_roots' && options.scopeRootNodeIds) {
    reachableNodeIds = new Set<string>();
    const queue = [...options.scopeRootNodeIds];
    options.scopeRootNodeIds.forEach((id) => reachableNodeIds.add(id));

    while (queue.length > 0) {
      const current = queue.shift()!;
      const targets = adjacency.get(current) ?? [];
      targets.forEach((target) => {
        if (!reachableNodeIds.has(target)) {
          reachableNodeIds.add(target);
          queue.push(target);
        }
      });
    }
  }

  // 1. Fan-in validation
  nodes.forEach((node) => {
    if (!reachableNodeIds.has(node.id)) return;
    const incomingEdges = edgeMap.get(node.id) ?? [];
    const portGroups = new Map<string, Edge[]>();
    incomingEdges.forEach((edge) => {
      if (edge.toPort) {
        const group = portGroups.get(edge.toPort) ?? [];
        group.push(edge);
        portGroups.set(edge.toPort, group);
      }
    });

    portGroups.forEach((edges, port) => {
      if (edges.length > 1) {
        const cardinality = getNodeInputPortCardinality(node, port);
        if (cardinality === 'one') {
          findings.push({
            code: 'fan_in_single_port',
            severity: 'error',
            message: `Node "${node.title || node.id}" receives multiple inputs on single-cardinality port "${port}".`,
            nodeId: node.id,
            port,
          });
        }
      }
    });
  });

  // 2. Required input validation
  nodes.forEach((node) => {
    if (!reachableNodeIds.has(node.id)) return;
    if (node.type === 'trigger') return;

    const incomingPorts = new Set(
      (edgeMap.get(node.id) ?? []).map((e) => e.toPort).filter(Boolean) as string[]
    );

    (node.inputs || []).forEach((port) => {
      const contract = getNodeInputPortContract(node, port);
      if (contract.required && !incomingPorts.has(port)) {
        findings.push({
          code: 'required_input_missing_wiring',
          severity: 'error',
          message: `Node "${node.title || node.id}" is missing required input wiring for port "${port}".`,
          nodeId: node.id,
          port,
        });
      }
    });
  });

  // 3. Cycle detection (Simple DFS for cycles)
  const visited = new Set<string>();
  const recStack = new Set<string>();
  const detectCycle = (u: string, path: string[]) => {
    visited.add(u);
    recStack.add(u);
    path.push(u);

    const neighbors = adjacency.get(u) ?? [];
    for (const v of neighbors) {
      if (!visited.has(v)) {
        detectCycle(v, path);
      } else if (recStack.has(v)) {
        // Cycle detected
        const cycleNodes = path.slice(path.indexOf(v));
        const isAllowedLoop = cycleNodes.some((id) => {
          const type = nodeMap.get(id)?.type;
          return type === 'iterator' || type === 'delay' || type === 'poll';
        });

        if (isAllowedLoop) {
          findings.push({
            code: 'cycle_detected',
            severity: 'warning',
            message: `Detected a circular loop across ${cycleNodes.length} node(s). Fix: remove at least one loop edge.`,
            metadata: { nodeIds: cycleNodes },
          });

          // Also check for deadlock risk in loops
          const loopNodes = cycleNodes.map((id) => nodeMap.get(id)).filter(Boolean) as AiNode[];
          const allWait = loopNodes.every((n) => n.config?.runtime?.waitForInputs);
          if (allWait) {
            const anyExternalRequired = loopNodes.some((n) => {
              const incomingFromOutside = (edgeMap.get(n.id) ?? []).filter(
                (e) => !cycleNodes.includes(e.from || '')
              );
              const ports = new Set(
                incomingFromOutside.map((e) => e.toPort).filter(Boolean) as string[]
              );
              return (n.inputs || []).some(
                (p) => getNodeInputPortContract(n, p).required && ports.has(p)
              );
            });
            if (!anyExternalRequired) {
              findings.push({
                code: 'cycle_wait_deadlock_risk',
                severity: 'warning',
                message:
                  'This loop contains only wait-for-inputs nodes with internal dependencies. Fix: provide at least one required input from outside the loop.',
                metadata: { nodeIds: cycleNodes },
              });
            }
          }
        } else {
          findings.push({
            code: 'unsupported_cycle',
            severity: 'error',
            message:
              'Unsupported circular dependency detected. Circular loops are only allowed through Iterator, Delay, or Poll nodes.',
            metadata: { nodeIds: cycleNodes },
          });
        }
      }
    }

    recStack.delete(u);
    path.pop();
  };

  nodes.forEach((node) => {
    if (!visited.has(node.id)) {
      detectCycle(node.id, []);
    }
  });

  // 4. Incompatible wiring
  const compatibilityCheckedEdges = new Set<string>();
  normalizedEdges.forEach((edge, edgeIndex) => {
    const fromId = typeof edge.from === 'string' ? edge.from.trim() : '';
    const toId = typeof edge.to === 'string' ? edge.to.trim() : '';
    const fromPort = typeof edge.fromPort === 'string' ? normalizePortName(edge.fromPort) : '';
    const toPort = typeof edge.toPort === 'string' ? normalizePortName(edge.toPort) : '';
    if (!fromId || !toId || !fromPort || !toPort) return;
    if (!reachableNodeIds.has(fromId) || !reachableNodeIds.has(toId)) return;
    const edgeKey = edge.id || `${fromId}:${fromPort}->${toId}:${toPort}:${edgeIndex}`;
    if (compatibilityCheckedEdges.has(edgeKey)) return;
    compatibilityCheckedEdges.add(edgeKey);

    const fromNode = nodeMap.get(fromId);
    const toNode = nodeMap.get(toId);
    if (!fromNode || !toNode) return;
    if (!fromNode.outputs.includes(fromPort) || !toNode.inputs.includes(toPort)) return;

    const fromTypes = resolvePortCompatibilityTypes(fromNode, fromPort, 'output');
    const toTypes = resolvePortCompatibilityTypes(toNode, toPort, 'input');
    if (!arePortTypesCompatible(fromTypes, toTypes)) {
      const contract = getNodeInputPortContract(toNode, toPort);
      findings.push({
        code: contract.required ? 'incompatible_wiring' : 'optional_input_incompatible_wiring',
        severity: contract.required ? 'error' : 'warning',
        message: `Incompatible wiring: ${fromPort} -> ${toPort}`,
        edgeId: edge.id,
      });
    }
  });

  // 5. Context cache scope risk
  const contextBoundPorts = new Set([
    'context',
    'entityid',
    'entitytype',
    'entityjson',
    'productid',
  ]);
  nodes.forEach((node) => {
    if (!reachableNodeIds.has(node.id)) return;
    const cacheScope = node.config?.runtime?.cache?.scope;
    if (cacheScope !== 'session') return;
    const nodeHasContextInputs = (node.inputs || []).some((port) =>
      contextBoundPorts.has(normalizePortName(port).trim().toLowerCase())
    );
    if (
      node.type === 'fetcher' ||
      node.type === 'context' ||
      node.type === 'simulation' ||
      nodeHasContextInputs
    ) {
      findings.push({
        code: 'context_cache_scope_risk',
        severity: 'warning',
        message: `Node "${node.title || node.id}" uses session cache scope with context-bound inputs. Consider run-scoped cache to avoid stale context reuse.`,
        nodeId: node.id,
      });
    }
  });

  // 6. Model prompt deadlock risk
  nodes.forEach((node) => {
    if (node.type === 'model') {
      const isPromptRequired = getNodeInputPortContract(node, 'prompt').required;
      const waitForInputs = node.config?.runtime?.waitForInputs;
      if (isPromptRequired && waitForInputs) {
        // Check if prompt comes from a cycle
        const incoming = (edgeMap.get(node.id) ?? []).find((e) => e.toPort === 'prompt');
        if (incoming) {
          // Simple check: if fromPort is 'result' and fromNode is 'prompt' node which depends on us
          const source = nodeMap.get(incoming.from || '');
          if (source?.type === 'prompt') {
            const sourceIncoming = (edgeMap.get(source.id) ?? []).some((e) => e.from === node.id);
            if (sourceIncoming) {
              findings.push({
                code: 'model_prompt_deadlock_risk',
                severity: 'warning',
                message:
                  'Model prompt may never resolve because it depends on this model\'s own output in a wait-for-inputs cycle.',
                nodeId: node.id,
              });
            }
          }
        }
      }
    }
  });

  const errors = findings.filter((f) => f.severity === 'error').length;
  const warnings = findings.filter((f) => f.severity === 'warning').length;

  return {
    nodes,
    edges: normalizedEdges,
    nodeMap,
    adjacency,
    inverseAdjacency,
    triggerNodeId,
    processingNodeIds,
    terminalNodeIds,
    ok: errors === 0,
    errors,
    warnings,
    findings,
  };
};

import type {
  AiNode,
  Edge,
  ConnectionValidation,
  GraphCompileFinding,
} from '@/shared/contracts/ai-paths';

import { isValidConnection, normalizePortName } from './graph.ports';
import { arePortTypesCompatible, formatPortDataTypes, getPortDataTypes } from './port-types';

const coerceEdgeList = (edges: unknown): Edge[] => {
  return Array.isArray(edges) ? (edges as Edge[]) : [];
};

export const sanitizeEdgesDetailed = (
  nodes: AiNode[],
  edges: Edge[]
): {
  edges: Edge[];
  dropped: GraphCompileFinding[];
} => {
  const edgeList = coerceEdgeList(edges);
  const nodeMap = new Map(nodes.map((node: AiNode) => [node.id, node]));
  const seenConnections = new Set<string>();
  const canonicalEdges: Edge[] = [];
  const dropped: GraphCompileFinding[] = [];
  const resolveNodeId = (value: string | undefined): string | null => {
    const first = typeof value === 'string' ? value.trim() : '';
    return first.length > 0 ? first : null;
  };
  const resolveLegacyString = (edge: Edge, key: string): string | undefined => {
    const value = (edge as Record<string, unknown>)[key];
    if (typeof value !== 'string') return undefined;
    const normalized = value.trim();
    return normalized.length > 0 ? normalized : undefined;
  };
  const resolvePort = (value: string | null | undefined): string | null => {
    const normalized = typeof value === 'string' ? normalizePortName(value) : '';
    return normalized.length > 0 ? normalized : null;
  };
  const resolveFirstNodeId = (...values: Array<string | undefined>): string | null => {
    for (const value of values) {
      const resolved = resolveNodeId(value);
      if (resolved !== null) return resolved;
    }
    return null;
  };
  const resolveFirstPort = (...values: Array<string | null | undefined>): string | null => {
    for (const value of values) {
      const resolved = resolvePort(value);
      if (resolved !== null) return resolved;
    }
    return null;
  };
  const toCanonicalEdge = (
    edge: Edge,
    fromNodeId: string,
    toNodeId: string,
    fromPort?: string,
    toPort?: string
  ): Edge => ({
    ...edge,
    from: fromNodeId,
    to: toNodeId,
    ...(fromPort ? { fromPort } : {}),
    ...(toPort ? { toPort } : {}),
  });
  const addDroppedEdge = (
    code:
      | 'invalid_edge_missing_node'
      | 'invalid_edge_missing_port'
      | 'invalid_edge_incompatible_connection'
      | 'duplicate_edge_dropped',
    edge: Edge,
    message: string,
    resolved?: {
      fromNodeId?: string | null;
      fromPort?: string | null;
      toNodeId?: string | null;
      toPort?: string | null;
    }
  ): void => {
    dropped.push({
      code,
      severity: 'warning',
      message,
      edgeId: edge.id,
      metadata: {
        from: resolved?.fromNodeId ?? edge.from ?? edge.source ?? null,
        to: resolved?.toNodeId ?? edge.to ?? edge.target ?? null,
        fromPort: resolved?.fromPort ?? edge.fromPort ?? edge.sourceHandle ?? null,
        toPort: resolved?.toPort ?? edge.toPort ?? edge.targetHandle ?? null,
      },
    });
  };
  edgeList.forEach((edge: Edge): void => {
    const fromNodeId = resolveFirstNodeId(
      edge.from,
      edge.source,
      resolveLegacyString(edge, 'fromNodeId')
    );
    const toNodeId = resolveFirstNodeId(
      edge.to,
      edge.target,
      resolveLegacyString(edge, 'toNodeId')
    );
    if (!fromNodeId || !toNodeId) {
      addDroppedEdge(
        'invalid_edge_missing_node',
        edge,
        `Dropped edge "${edge.id}": source and target node ids must be present.`,
        { fromNodeId, toNodeId }
      );
      return;
    }
    const from = nodeMap.get(fromNodeId);
    const to = nodeMap.get(toNodeId);
    if (!from || !to) {
      addDroppedEdge(
        'invalid_edge_missing_node',
        edge,
        `Dropped edge "${edge.id}": source or target node does not exist.`,
        { fromNodeId, toNodeId }
      );
      return;
    }
    const fromPort =
      resolveFirstPort(
        edge.fromPort,
        edge.sourceHandle,
        resolveLegacyString(edge, 'sourcePort'),
        resolveLegacyString(edge, 'fromHandle')
      ) ?? undefined;
    const toPort =
      resolveFirstPort(
        edge.toPort,
        edge.targetHandle,
        resolveLegacyString(edge, 'targetPort'),
        resolveLegacyString(edge, 'toHandle')
      ) ?? undefined;

    if (!fromPort || !toPort) {
      addDroppedEdge(
        'invalid_edge_missing_port',
        edge,
        `Dropped edge "${edge.id}": source and target ports must be specified.`,
        { fromNodeId, fromPort: fromPort ?? null, toNodeId, toPort: toPort ?? null }
      );
      return;
    }

    if (!from.outputs.includes(fromPort) || !to.inputs.includes(toPort)) {
      addDroppedEdge(
        'invalid_edge_missing_port',
        edge,
        `Dropped edge "${edge.id}": source or target port does not exist on the referenced node.`,
        { fromNodeId, fromPort, toNodeId, toPort }
      );
      return;
    }

    if (!isValidConnection(from, to, fromPort, toPort)) {
      addDroppedEdge(
        'invalid_edge_incompatible_connection',
        edge,
        `Dropped edge "${edge.id}": ${from.title ?? from.id}.${fromPort} cannot connect to ${to.title ?? to.id}.${toPort}.`,
        { fromNodeId, fromPort, toNodeId, toPort }
      );
      return;
    }

    const dedupeKey = `${fromNodeId}:${fromPort}->${toNodeId}:${toPort}`;
    if (seenConnections.has(dedupeKey)) {
      addDroppedEdge(
        'duplicate_edge_dropped',
        edge,
        `Dropped duplicate edge "${edge.id}": ${fromNodeId}.${fromPort} -> ${toNodeId}.${toPort}.`,
        { fromNodeId, fromPort, toNodeId, toPort }
      );
      return;
    }

    seenConnections.add(dedupeKey);
    canonicalEdges.push(toCanonicalEdge(edge, fromNodeId, toNodeId, fromPort, toPort));
  });

  return {
    edges: canonicalEdges,
    dropped,
  };
};

export const sanitizeEdges = (nodes: AiNode[], edges: Edge[]): Edge[] => {
  return sanitizeEdgesDetailed(nodes, edges).edges;
};

export const validateConnection = (
  from: AiNode,
  to: AiNode,
  fromPort?: string,
  toPort?: string
): ConnectionValidation => {
  if (!fromPort || !toPort) {
    return { valid: false, message: 'Source and target ports must be specified.' };
  }
  if (!from.outputs.includes(fromPort)) {
    return {
      valid: false,
      message: `Node "${from.title ?? from.id}" does not have output port "${fromPort}".`,
    };
  }
  if (!to.inputs.includes(toPort)) {
    return {
      valid: false,
      message: `Node "${to.title ?? to.id}" does not have input port "${toPort}".`,
    };
  }

  const fromTypes = getPortDataTypes(fromPort);
  const toTypes = getPortDataTypes(toPort);
  const typeCompatible = arePortTypesCompatible(fromTypes, toTypes);

  if (!typeCompatible) {
    const fromLabel = formatPortDataTypes(fromTypes);
    const toLabel = formatPortDataTypes(toTypes);
    return {
      valid: false,
      message: `Port types are incompatible: ${fromLabel} \u2192 ${toLabel}.`,
    };
  }

  return { valid: true };
};

import type { AiNode, Edge } from '@/shared/contracts/ai-paths';

import type { GraphIntegrityReport, GraphIntegrityIssue } from './graph.types';

const PROCESSING_NODE_TYPES = new Set<string>([
  'fetcher',
  'parser',
  'regex',
  'iterator',
  'mapper',
  'mutator',
  'string_mutator',
  'validator',
  'validation_pattern',
  'constant',
  'math',
  'template',
  'bundle',
  'gate',
  'compare',
  'router',
  'delay',
  'poll',
  'http',
  'api_advanced',
  'playwright',
  'prompt',
  'model',
  'agent',
  'learner_agent',
  'database',
  'db_schema',
]);

export const inspectGraphIntegrity = (nodes: AiNode[], edges: Edge[]): GraphIntegrityReport => {
  const issues: GraphIntegrityIssue[] = [];
  const invalidEdgeCount = edges.filter(
    (edge: Edge): boolean =>
      !nodes.some((node: AiNode) => node.id === edge.from) ||
      !nodes.some((node: AiNode) => node.id === edge.to)
  ).length;
  if (invalidEdgeCount > 0) {
    issues.push({ kind: 'invalid_edge', count: invalidEdgeCount });
  }

  const disconnectedProcessingNodes = nodes
    .filter((node: AiNode) => PROCESSING_NODE_TYPES.has(node.type))
    .filter(
      (node: AiNode) => !edges.some((edge: Edge) => edge.from === node.id || edge.to === node.id)
    )
    .map((node: AiNode) => ({
      nodeId: node.id,
      nodeType: node.type,
      nodeTitle: node.title || node.id,
    }));

  disconnectedProcessingNodes.forEach((node) => {
    issues.push({ kind: 'disconnected_processing_node', ...node });
  });

  return {
    issues,
    invalidEdgeCount,
    disconnectedProcessingNodes,
  };
};

import type { AiNode, NodePortContract, NodePortValueKind } from '@/shared/contracts/ai-paths';

import { palette } from '../definitions';
import { normalizePortName } from './graph.ports';

type PortContract = NodePortContract;

type InputCardinality = 'one' | 'many';
type NodePortCardinality = 'single' | 'many';
type ResolvedNodePortContractSource = 'runtime' | 'node' | 'definition' | 'legacy';
type ResolvedNodePortCardinalitySource =
  | 'runtime_contract'
  | 'runtime_cardinality'
  | 'node'
  | 'definition'
  | 'legacy';

const definitionInputContractsByType = new Map<string, Record<string, PortContract>>();
const definitionOutputContractsByType = new Map<string, Record<string, PortContract>>();
const LEGACY_MANY_INPUT_PORT_NAMES = new Set(['bundle', 'result', 'context', 'images', 'imageurls']);

const canonicalizePortLookupKey = (portName: string): string =>
  normalizePortName(portName)
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]/g, '');

palette.forEach((definition): void => {
  if (!definition?.type) return;
  if (definition.inputContracts) {
    const existing = definitionInputContractsByType.get(definition.type) ?? {};
    definitionInputContractsByType.set(definition.type, {
      ...existing,
      ...definition.inputContracts,
    });
  }
  if (definition.outputContracts) {
    const existingOutputs = definitionOutputContractsByType.get(definition.type) ?? {};
    definitionOutputContractsByType.set(definition.type, {
      ...existingOutputs,
      ...definition.outputContracts,
    });
  }
});

const resolvePortContract = (
  contracts: Record<string, PortContract> | undefined,
  portName: string
): PortContract | null => {
  if (!contracts) return null;
  if (contracts[portName]) {
    return contracts[portName] ?? null;
  }
  const normalizedPortKey = canonicalizePortLookupKey(portName);
  for (const [rawKey, contract] of Object.entries(contracts)) {
    if (!contract) continue;
    const normalizedContractKey = canonicalizePortLookupKey(rawKey);
    if (normalizedContractKey === normalizedPortKey) {
      return contract;
    }
  }
  return null;
};

const normalizeNodePortCardinality = (value: unknown): NodePortCardinality | null =>
  value === 'many' ? 'many' : value === 'single' ? 'single' : null;

const readRuntimeInputCardinality = (
  node: AiNode
): Record<string, InputCardinality> | undefined =>
  (node.config?.runtime as { inputCardinality?: Record<string, InputCardinality> } | undefined)
    ?.inputCardinality;

const resolveLegacyRuntimeInputCardinality = (
  inputCardinality: Record<string, InputCardinality> | undefined,
  portName: string
): InputCardinality | null => {
  if (inputCardinality?.[portName]) {
    return inputCardinality[portName];
  }
  if (!inputCardinality) {
    return null;
  }

  const normalizedPortName = canonicalizePortLookupKey(portName);
  const matchingEntry = Object.entries(inputCardinality).find(
    ([rawKey]) => canonicalizePortLookupKey(rawKey) === normalizedPortName
  );
  return matchingEntry?.[1] ?? null;
};

const hasMatchingPortLookupKey = (
  values: Record<string, unknown> | undefined,
  portName: string
): boolean => {
  if (!values) return false;
  const lookupKey = canonicalizePortLookupKey(portName);
  return Object.keys(values).some((rawKey) => canonicalizePortLookupKey(rawKey) === lookupKey);
};

const resolveLegacyInputCardinalityFallback = (portName: string): InputCardinality =>
  LEGACY_MANY_INPUT_PORT_NAMES.has(canonicalizePortLookupKey(portName)) ? 'many' : 'one';

const normalizePortValueKind = (value: unknown): NodePortValueKind => {
  switch (value) {
    case 'string':
    case 'number':
    case 'boolean':
    case 'json':
    case 'image_url':
    case 'bundle':
    case 'job_envelope':
      return value;
    default:
      return 'unknown';
  }
};

export type ResolvedNodePortContract = {
  required: boolean;
  cardinality: NodePortCardinality;
  cardinalitySource: ResolvedNodePortCardinalitySource;
  kind: NodePortValueKind;
  schema?: Record<string, unknown> | undefined;
  schemaRef?: string | undefined;
  source: ResolvedNodePortContractSource;
  declared: boolean;
};

const buildResolvedNodePortContract = (args: {
  contract: PortContract | null;
  source: ResolvedNodePortContractSource;
  cardinalityFallback: NodePortCardinality;
  cardinalitySource: ResolvedNodePortCardinalitySource;
}): ResolvedNodePortContract => ({
  required: args.contract ? args.contract.required !== false : false,
  cardinality: normalizeNodePortCardinality(args.contract?.cardinality) ?? args.cardinalityFallback,
  cardinalitySource:
    normalizeNodePortCardinality(args.contract?.cardinality) !== null
      ? args.source === 'runtime'
        ? 'runtime_contract'
        : args.source === 'node'
          ? 'node'
          : args.source === 'definition'
            ? 'definition'
            : args.cardinalitySource
      : args.cardinalitySource,
  kind: normalizePortValueKind(args.contract?.kind),
  schema: args.contract?.schema,
  schemaRef: args.contract?.schemaRef,
  source: args.source,
  declared: args.source !== 'legacy',
});

const getLegacyInputCardinality = (node: AiNode, portName: string): InputCardinality => {
  const runtimeCardinality = resolveLegacyRuntimeInputCardinality(
    readRuntimeInputCardinality(node),
    portName
  );
  return runtimeCardinality ?? resolveLegacyInputCardinalityFallback(portName);
};

const resolveInputPortCardinalityFallback = (node: AiNode, portName: string) => {
  const runtimeInputCardinality = readRuntimeInputCardinality(node);
  const legacyCardinality = getLegacyInputCardinality(node, portName);
  return {
    cardinalityFallback: legacyCardinality === 'many' ? ('many' as const) : ('single' as const),
    cardinalitySource: hasMatchingPortLookupKey(runtimeInputCardinality, portName)
      ? ('runtime_cardinality' as const)
      : ('legacy' as const),
  };
};

const resolveInputPortContractCandidate = (
  node: AiNode,
  portName: string
): { contract: PortContract; source: ResolvedNodePortContractSource } | null => {
  const runtimeContract = resolvePortContract(node.config?.runtime?.inputContracts, portName);
  if (runtimeContract) {
    return { contract: runtimeContract, source: 'runtime' };
  }

  const nodeContract = resolvePortContract(node.inputContracts, portName);
  if (nodeContract) {
    return { contract: nodeContract, source: 'node' };
  }

  const definitionContract = resolvePortContract(
    definitionInputContractsByType.get(node.type),
    portName
  );
  if (definitionContract) {
    return { contract: definitionContract, source: 'definition' };
  }

  return null;
};

const buildLegacyResolvedNodeInputPortContract = (
  portName: string,
  cardinalityFallback: NodePortCardinality,
  cardinalitySource: ResolvedNodePortCardinalitySource
): ResolvedNodePortContract => {
  const normalizedPortName = portName.toLowerCase();
  return {
    required:
      normalizedPortName === 'trigger' ||
      normalizedPortName === 'prompt' ||
      normalizedPortName === 'value',
    cardinality: cardinalityFallback,
    cardinalitySource,
    kind: 'unknown',
    source: 'legacy',
    declared: false,
  };
};

export const getNodeInputPortCardinality = (node: AiNode, portName: string): InputCardinality => {
  const resolved = getResolvedNodeInputPortContract(node, portName);
  return resolved.cardinality === 'many' ? 'many' : 'one';
};

export const getResolvedNodeInputPortContract = (
  node: AiNode,
  portName: string
): ResolvedNodePortContract => {
  const { cardinalityFallback, cardinalitySource } = resolveInputPortCardinalityFallback(
    node,
    portName
  );
  const contractCandidate = resolveInputPortContractCandidate(node, portName);
  if (contractCandidate) {
    return buildResolvedNodePortContract({
      contract: contractCandidate.contract,
      source: contractCandidate.source,
      cardinalityFallback,
      cardinalitySource,
    });
  }

  return buildLegacyResolvedNodeInputPortContract(portName, cardinalityFallback, cardinalitySource);
};

export const getNodeInputPortContract = (node: AiNode, portName: string): { required: boolean } => {
  return { required: getResolvedNodeInputPortContract(node, portName).required };
};

export const getResolvedNodeOutputPortContract = (
  node: AiNode,
  portName: string
): ResolvedNodePortContract => {
  const nodeContract = resolvePortContract(node.outputContracts, portName);
  if (nodeContract) {
    return buildResolvedNodePortContract({
      contract: nodeContract,
      source: 'node',
      cardinalityFallback: 'single',
      cardinalitySource: 'legacy',
    });
  }
  const definitionContract = resolvePortContract(
    definitionOutputContractsByType.get(node.type),
    portName
  );
  if (definitionContract) {
    return buildResolvedNodePortContract({
      contract: definitionContract,
      source: 'definition',
      cardinalityFallback: 'single',
      cardinalitySource: 'legacy',
    });
  }
  return {
    required: false,
    cardinality: 'single',
    cardinalitySource: 'legacy',
    kind: 'unknown',
    source: 'legacy',
    declared: false,
  };
};

export const createParserMappings = (outputs: string[]): Record<string, string> =>
  outputs.reduce<Record<string, string>>((acc, port) => {
    if (port !== 'bundle') {
      acc[port] = port;
    }
    return acc;
  }, {});

export const createViewerOutputs = (inputs: string[]): Record<string, string> =>
  inputs.reduce<Record<string, string>>((acc, port) => {
    if (port !== 'trigger') {
      acc[port] = port;
    }
    return acc;
  }, {});

import type { AiNode } from '@/shared/contracts/ai-paths';

import { PORT_STACK_TOP, PORT_GAP, PORT_COMPATIBILITY } from '../constants';
import { arePortTypesCompatible, getPortDataTypes } from './port-types';

export const getPortOffsetY = (index: number, _totalPorts: number): number => {
  return PORT_STACK_TOP + index * PORT_GAP;
};

export const normalizePortName = (port: string): string => {
  const trimmed = typeof port === 'string' ? port.trim() : '';
  return trimmed;
};

export const isValidConnection = (
  from: AiNode,
  to: AiNode,
  fromPort?: string,
  toPort?: string
): boolean => {
  if (!fromPort || !toPort) return false;
  if (!from.outputs.includes(fromPort)) return false;
  if (!to.inputs.includes(toPort)) return false;

  const allowed = PORT_COMPATIBILITY[fromPort];
  const portCompatible = allowed?.includes(toPort) || fromPort === toPort;
  if (!portCompatible) return false;
  if (
    to.type === 'trigger' &&
    toPort === 'context' &&
    (from.type !== 'simulation' || fromPort !== 'context')
  ) {
    return false;
  }
  if (to.type === 'simulation' && toPort === 'trigger') {
    if (from.type !== 'trigger' || fromPort !== 'trigger') return false;
  }
  if (to.type === 'fetcher' && toPort === 'trigger') {
    if (from.type !== 'trigger' || fromPort !== 'trigger') return false;
  }
  if (to.type === 'fetcher' && from.type === 'trigger' && toPort !== 'trigger') {
    return false;
  }
  const fromTypes = getPortDataTypes(fromPort);
  const toTypes = getPortDataTypes(toPort);
  return arePortTypesCompatible(fromTypes, toTypes);
};

export const ensureUniquePorts = (ports: string[], add: string[]): string[] => {
  const set = new Set(ports);
  add.forEach((port: string) => {
    if (port) set.add(port);
  });
  return Array.from(set);
};

import type { JsonPathEntry } from '@/shared/contracts/ai-paths';

import { extractJsonPathEntries, getValueAtMappingPath } from './json';

export const looksLikeImageUrl = (value: string): boolean =>
  /(\.(png|jpe?g|webp|gif|svg)|\/uploads\/|^https?:\/\/)/i.test(value);

export const isImageLikeValue = (value: unknown): boolean => {
  if (!value) return false;
  if (typeof value === 'string') {
    return looksLikeImageUrl(value);
  }
  if (Array.isArray(value)) {
    return value.some((item: unknown) => isImageLikeValue(item));
  }
  if (typeof value === 'object') {
    const record = value as Record<string, unknown>;
    const candidates = [
      'url',
      'src',
      'thumbnail',
      'thumb',
      'imageUrl',
      'image',
      'filepath',
      'filePath',
      'path',
      'file',
      'previewUrl',
      'preview',
      'imageFile',
      'image_file',
      'media',
      'gallery',
    ];
    if (
      candidates.some((key: string) => {
        const val = record[key];
        return typeof val === 'string' ? looksLikeImageUrl(val) : isImageLikeValue(val);
      })
    ) {
      return true;
    }
    return Object.entries(record).some(([key, val]: [string, unknown]) => {
      if (typeof val === 'string') {
        if (!looksLikeImageUrl(val)) return false;
        return /(url|path|file|image|media|photo|thumb|preview)/i.test(key);
      }
      if (val && typeof val === 'object' && /(image|file|media|photo)/i.test(key)) {
        return isImageLikeValue(val);
      }
      return false;
    });
  }
  return false;
};

export const inferImageMappingPath = (value: unknown, depth: number): string | null => {
  if (!value) return null;
  const keyword = /(image|img|photo|picture|media|gallery)/i;
  const searchIn = (root: unknown, prefix: string): string | null => {
    if (!root) return null;
    const entries = extractJsonPathEntries(root, depth);
    const candidates = entries.filter((entry: JsonPathEntry) => keyword.test(entry.path));
    const resolveFullPath = (match: string): string => {
      if (!prefix) return match;
      const prefixPath = prefix.startsWith('$') ? prefix : `$.${prefix}`;
      return `${prefixPath}${match.slice(1)}`;
    };
    const checkEntry = (entry: JsonPathEntry): string | null => {
      const jsonPath = entry.path.startsWith('[') ? `$${entry.path}` : `$.${entry.path}`;
      const resolved = getValueAtMappingPath(root, jsonPath);
      if (isImageLikeValue(resolved)) return resolveFullPath(jsonPath);
      return null;
    };
    for (const entry of candidates) {
      const match = checkEntry(entry);
      if (match) return match;
    }
    for (const entry of entries) {
      const match = checkEntry(entry);
      if (match) return match;
    }
    return null;
  };
  const direct = searchIn(value, '');
  if (direct) return direct;
  const wrapperPaths = [
    'context.entity',
    'context.product',
    'simulation.entity',
    'simulation.product',
    'entity',
    'product',
    'item',
    'data',
  ];
  for (const path of wrapperPaths) {
    const wrapped = getValueAtMappingPath(value, path.startsWith('$') ? path : `$.${path}`);
    const match = searchIn(wrapped, path);
    if (match) return match;
  }
  return null;
};

import type { JsonPathEntry } from '@/shared/contracts/ai-paths';

import { cloneValue } from './runtime';
import {
  normalizeJsonLikeValue,
  type JsonIntegrityPolicy,
} from '../runtime/handlers/json-integrity';

const buildJsonPathEntry = (prefix: string, node: unknown): JsonPathEntry => {
  const isArray = Array.isArray(node);
  const isObject = !isArray && typeof node === 'object';
  return {
    path: prefix,
    type: isArray ? 'array' : isObject ? 'object' : 'value',
  };
};

const isJsonObjectLike = (value: unknown): value is Record<string, unknown> =>
  value !== null && !Array.isArray(value) && typeof value === 'object';

const walkJsonPathEntries = (
  node: unknown,
  prefix: string,
  depth: number,
  entries: JsonPathEntry[]
): void => {
  if (node === null || node === undefined || depth < 0) return;
  if (prefix) {
    entries.push(buildJsonPathEntry(prefix, node));
  }
  if (Array.isArray(node)) {
    if (node.length === 0) return;
    const arrayPrefix = prefix ? `${prefix}[0]` : '[0]';
    walkJsonPathEntries(node[0], arrayPrefix, depth - 1, entries);
    return;
  }
  if (!isJsonObjectLike(node)) return;
  Object.entries(node).forEach(([key, child]: [string, unknown]) => {
    const nextPrefix = prefix ? `${prefix}.${key}` : key;
    walkJsonPathEntries(child, nextPrefix, depth - 1, entries);
  });
};

export const extractJsonPathEntries = (value: unknown, maxDepth: number = 2): JsonPathEntry[] => {
  const entries: JsonPathEntry[] = [];
  walkJsonPathEntries(value, '', maxDepth, entries);
  return entries;
};

export const extractJsonPaths = (value: unknown, maxDepth: number = 2): string[] => {
  return extractJsonPathEntries(value, maxDepth).map((entry: JsonPathEntry) => entry.path);
};

export const buildTopLevelMappings = (value: unknown): Record<string, string> => {
  if (!value) return {} as Record<string, string>;
  let root: unknown = value;
  let prefix = '$.';
  if (Array.isArray(value)) {
    root = value[0];
    prefix = '$[0].';
  }
  if (!root || typeof root !== 'object') return {} as Record<string, string>;
  return Object.keys(root as Record<string, unknown>).reduce<Record<string, string>>(
    (acc: Record<string, string>, key: string) => {
      acc[key] = `${prefix}${key}`;
      return acc;
    },
    {}
  );
};

export const normalizeMappingPath = (path: string, root?: unknown): string => {
  if (!path) return '';
  let next = path.trim();
  if (next.startsWith('$.')) {
    next = next.slice(2);
  } else if (next.startsWith('$')) {
    next = next.slice(1);
  }
  if (next.startsWith('context.')) {
    const hasContext =
      root && typeof root === 'object' && 'context' in (root as Record<string, unknown>);
    if (!hasContext) {
      next = next.slice('context.'.length);
    }
  }
  return next;
};

export const parsePathTokens = (path: string): Array<string | number> => {
  const tokens: Array<string | number> = [];
  const regex = /([^[.\]]+)|\[(\d+)\]/g;
  let match: RegExpExecArray | null;
  while ((match = regex.exec(path))) {
    if (match[1] !== undefined) {
      tokens.push(match[1]);
    } else if (match[2] !== undefined) {
      tokens.push(Number(match[2]));
    }
  }
  return tokens;
};

export const getValueAtMappingPath = (
  obj: unknown,
  path: string,
  options?: { jsonIntegrityPolicy?: JsonIntegrityPolicy }
): unknown => {
  const normalized = normalizeMappingPath(path, obj);
  if (!normalized) return undefined;
  const jsonIntegrityPolicy: JsonIntegrityPolicy =
    options?.jsonIntegrityPolicy === 'strict' ? 'strict' : 'repair';
  const tokens = parsePathTokens(normalized);

  const readArrayToken = (
    source: unknown[],
    token: string | number,
    index: number
  ): unknown => {
    if (typeof token === 'number') {
      if (token < 0 || token >= source.length) return undefined;
      return readByTokens(source[token], index + 1);
    }
    return source.reduce<unknown>((found: unknown, item: unknown) => {
      if (found !== undefined) return found;
      return readByTokens(item, index);
    }, undefined);
  };

  const readByTokens = (source: unknown, index: number): unknown => {
    if (index >= tokens.length) return source;
    if (source === null || source === undefined) return undefined;

    const normalizedSource = normalizeJsonLikeValue(source, jsonIntegrityPolicy).value;
    const token = tokens[index];
    if (token === undefined) return undefined;

    if (Array.isArray(normalizedSource)) {
      return readArrayToken(normalizedSource, token, index);
    }

    if (typeof token === 'number' || !isJsonObjectLike(normalizedSource)) return undefined;
    return readByTokens(normalizedSource[token], index + 1);
  };

  return readByTokens(obj, 0);
};

export const buildFlattenedMappings = (
  value: unknown,
  depth: number,
  keyStyle: 'path' | 'leaf',
  includeContainers: boolean
): Record<string, string> => {
  const entries = extractJsonPathEntries(value, depth).filter((entry: JsonPathEntry) => {
    if (includeContainers) return true;
    return entry.type === 'value' || entry.type === 'array';
  });
  const mappings: Record<string, string> = {};
  const used = new Set<string>();
  entries.forEach((entry: JsonPathEntry) => {
    const path = entry.path;
    const jsonPath = path.startsWith('[') ? `$${path}` : `$.${path}`;
    const tokens = parsePathTokens(path);
    if (tokens.length === 0) return;
    const pathKey = tokens
      .map((token: string | number) => (typeof token === 'number' ? String(token) : token))
      .join('_');
    let leafKey = '';
    for (let index = tokens.length - 1; index >= 0; index -= 1) {
      const token = tokens[index];
      if (typeof token === 'string') {
        leafKey = token;
        break;
      }
    }
    const lastToken = tokens[tokens.length - 1];
    if (leafKey && typeof lastToken === 'number') {
      leafKey = `${leafKey}_${lastToken}`;
    }
    let keyBase = keyStyle === 'leaf' ? leafKey || pathKey : pathKey;
    keyBase = keyBase.replace(/[^a-zA-Z0-9_]+/g, '_').replace(/^_+|_+$/g, '');
    if (!keyBase) keyBase = 'field';
    if (/^\d/.test(keyBase)) {
      keyBase = `field_${keyBase}`;
    }
    let uniqueKey = keyBase;
    let counter = 1;
    while (used.has(uniqueKey)) {
      counter += 1;
      uniqueKey = `${keyBase}_${counter}`;
    }
    used.add(uniqueKey);
    mappings[uniqueKey] = jsonPath;
  });
  return mappings;
};

export const getValueAtPath = (obj: unknown, path: string): unknown => {
  return path.split('.').reduce<unknown>((acc: unknown, key: string) => {
    if (!acc || typeof acc !== 'object') return undefined;
    return (acc as Record<string, unknown>)[key];
  }, obj);
};

export const setValueAtPath = (
  obj: Record<string, unknown>,
  path: string,
  value: unknown
): void => {
  const keys = path.split('.');
  let current: Record<string, unknown> = obj;
  keys.forEach((key: string, index: number) => {
    if (index === keys.length - 1) {
      current[key] = value;
      return;
    }
    if (!current[key] || typeof current[key] !== 'object') {
      current[key] = {};
    }
    current = current[key] as Record<string, unknown>;
  });
};

export const setValueAtMappingPath = (
  obj: Record<string, unknown>,
  path: string,
  value: unknown
): void => {
  const normalized = normalizeMappingPath(path, obj);
  if (!normalized) return;
  const tokens = parsePathTokens(normalized);
  let current: Record<string, unknown> | unknown[] = obj;
  let parent: Record<string, unknown> | unknown[] | null = null;
  let parentKey: string | number | null = null;
  tokens.forEach((token: string | number, index: number) => {
    const isLast = index === tokens.length - 1;
    if (isLast) {
      if (typeof token === 'number') {
        if (!Array.isArray(current)) {
          const nextArray: unknown[] = [];
          if (parent && parentKey !== null) {
            if (Array.isArray(parent)) {
              parent[Number(parentKey)] = nextArray;
            } else {
              parent[String(parentKey)] = nextArray;
            }
          }
          current = nextArray;
        }
        current[token] = value;
      } else {
        (current as Record<string, unknown>)[token] = value;
      }
      return;
    }
    const nextToken = tokens[index + 1];
    if (typeof token === 'number') {
      if (!Array.isArray(current)) {
        const nextArray: unknown[] = [];
        if (parent && parentKey !== null) {
          if (Array.isArray(parent)) {
            parent[Number(parentKey)] = nextArray;
          } else {
            parent[String(parentKey)] = nextArray;
          }
        }
        current = nextArray;
      }
      const curArr = current;
      if (curArr[token] == null || typeof curArr[token] !== 'object') {
        curArr[token] = typeof nextToken === 'number' ? [] : {};
      }
      parent = current;
      parentKey = token;
      current = curArr[token] as Record<string, unknown> | unknown[];
      return;
    }
    const curObj = current as Record<string, unknown>;
    if (curObj[token] == null || typeof curObj[token] !== 'object') {
      curObj[token] = typeof nextToken === 'number' ? [] : {};
    }
    parent = current;
    parentKey = token;
    current = curObj[token] as Record<string, unknown> | unknown[];
  });
};

export const pickByPaths = (
  obj: Record<string, unknown>,
  paths: string[]
): Record<string, unknown> => {
  const result: Record<string, unknown> = {};
  paths.forEach((path: string) => {
    const value = getValueAtPath(obj, path);
    if (value !== undefined) {
      setValueAtPath(result, path, value);
    }
  });
  return result;
};

export const deletePath = (obj: Record<string, unknown>, path: string): void => {
  const keys = path.split('.');
  let current: Record<string, unknown> = obj;
  keys.forEach((key: string, index: number) => {
    if (!current || typeof current !== 'object') return;
    if (index === keys.length - 1) {
      delete current[key];
      return;
    }
    current = current[key] as Record<string, unknown>;
  });
};

export const omitByPaths = (
  obj: Record<string, unknown>,
  paths: string[]
): Record<string, unknown> => {
  const clone = cloneValue(obj);
  paths.forEach((path: string) => deletePath(clone, path));
  return clone;
};

import { isObjectRecord } from '@/shared/utils/object-utils';

// Keep this list to explicit legacy hard-cut node types that must be rejected on load/run.
export const REMOVED_LEGACY_AI_PATH_NODE_TYPES = [
  'description_updater',
] as const;

export type RemovedLegacyAiPathNodeType = (typeof REMOVED_LEGACY_AI_PATH_NODE_TYPES)[number];

export type RemovedLegacyAiPathNodeUsage = {
  index: number;
  nodeId: string | null;
  nodeTitle: string | null;
  nodeType: RemovedLegacyAiPathNodeType;
};

const REMOVED_LEGACY_AI_PATH_NODE_TYPE_SET = new Set<string>(REMOVED_LEGACY_AI_PATH_NODE_TYPES);

const asTrimmedString = (value: unknown): string =>
  typeof value === 'string' ? value.trim() : '';

export const findRemovedLegacyAiPathNodes = (
  nodes: unknown
): RemovedLegacyAiPathNodeUsage[] => {
  if (!Array.isArray(nodes)) return [];
  return nodes.flatMap((node: unknown, index: number): RemovedLegacyAiPathNodeUsage[] => {
    if (!isObjectRecord(node)) return [];
    const nodeType = asTrimmedString(node['type']);
    if (!REMOVED_LEGACY_AI_PATH_NODE_TYPE_SET.has(nodeType)) return [];
    return [
      {
        index,
        nodeId: asTrimmedString(node['id']) || null,
        nodeTitle: asTrimmedString(node['title']) || null,
        nodeType: nodeType as RemovedLegacyAiPathNodeType,
      },
    ];
  });
};

export const findRemovedLegacyAiPathNodesInDocument = (
  document: unknown
): RemovedLegacyAiPathNodeUsage[] => {
  if (!isObjectRecord(document)) return [];
  const direct = findRemovedLegacyAiPathNodes(document['nodes']);
  if (direct.length > 0) return direct;

  const semanticDocument = document['document'];
  if (isObjectRecord(semanticDocument)) {
    const nested = findRemovedLegacyAiPathNodes(semanticDocument['nodes']);
    if (nested.length > 0) return nested;
  }

  const portableEnvelope = document['package'];
  if (isObjectRecord(portableEnvelope)) {
    const nestedDocument = portableEnvelope['document'];
    if (isObjectRecord(nestedDocument)) {
      return findRemovedLegacyAiPathNodes(nestedDocument['nodes']);
    }
  }

  return [];
};

export const findRemovedLegacyAiPathNodesInPathConfig = (
  pathConfig: { nodes?: unknown } | null | undefined
): RemovedLegacyAiPathNodeUsage[] => {
  if (!pathConfig || typeof pathConfig !== 'object') return [];
  return findRemovedLegacyAiPathNodes((pathConfig as { nodes?: unknown }).nodes);
};

const formatRemovedNodeLabel = (node: RemovedLegacyAiPathNodeUsage): string => {
  const nodeId = node.nodeId ? ` (${node.nodeId})` : '';
  const nodeTitle = node.nodeTitle ? `"${node.nodeTitle}" ` : '';
  return `${nodeTitle}<${node.nodeType}>${nodeId}`;
};

const REMOVED_LEGACY_AI_PATH_NODE_REPLACEMENTS: Record<RemovedLegacyAiPathNodeType, string> = {
  description_updater:
    'Replace it with a Database node write operation that persists `description_en` explicitly.',
};

export const formatRemovedLegacyAiPathNodesMessage = (
  removedNodes: RemovedLegacyAiPathNodeUsage[],
  options?: {
    surface?: 'path config' | 'run graph' | 'semantic document' | 'portable payload';
  }
): string => {
  const surface = options?.surface ?? 'path config';
  const normalizedSurface =
    surface === 'semantic document'
      ? 'semantic document'
      : surface === 'portable payload'
        ? 'portable payload'
        : surface;
  const examples = removedNodes.slice(0, 3).map(formatRemovedNodeLabel).join(', ');
  const countLabel = removedNodes.length === 1 ? 'node' : 'nodes';
  const removedNodeTypes = Array.from(
    new Set(removedNodes.map((node: RemovedLegacyAiPathNodeUsage) => node.nodeType))
  );
  const replacementGuidance = removedNodeTypes
    .map(
      (nodeType: RemovedLegacyAiPathNodeType): string =>
        REMOVED_LEGACY_AI_PATH_NODE_REPLACEMENTS[nodeType]
    )
    .join(' ');
  return [
    `AI Paths ${normalizedSurface} contains removed legacy ${countLabel}: ${examples}.`,
    `Legacy Description node types ${removedNodeTypes.map((nodeType) => `\`${nodeType}\``).join(', ')} are no longer supported.`,
    replacementGuidance,
  ].join(' ');
};

import { isObjectRecord } from '@/shared/utils/object-utils';

export const REMOVED_LEGACY_TRIGGER_CONTEXT_MODES = [
  'simulation_preferred',
  'simulation_required',
] as const;

export type RemovedLegacyTriggerContextMode =
  (typeof REMOVED_LEGACY_TRIGGER_CONTEXT_MODES)[number];

export type RemovedLegacyTriggerContextModeUsage = {
  index: number;
  nodeId: string | null;
  nodeTitle: string | null;
  contextMode: RemovedLegacyTriggerContextMode;
};

const REMOVED_LEGACY_TRIGGER_CONTEXT_MODE_SET = new Set<string>(
  REMOVED_LEGACY_TRIGGER_CONTEXT_MODES
);

const asTrimmedString = (value: unknown): string =>
  typeof value === 'string' ? value.trim() : '';

export const findRemovedLegacyTriggerContextModes = (
  nodes: unknown
): RemovedLegacyTriggerContextModeUsage[] => {
  if (!Array.isArray(nodes)) return [];
  return nodes.flatMap(
    (node: unknown, index: number): RemovedLegacyTriggerContextModeUsage[] => {
      if (!isObjectRecord(node)) return [];
      if (asTrimmedString(node['type']) !== 'trigger') return [];
      const config = isObjectRecord(node['config']) ? node['config'] : null;
      const triggerConfig = config && isObjectRecord(config['trigger']) ? config['trigger'] : null;
      const contextMode = asTrimmedString(triggerConfig?.['contextMode']);
      if (!REMOVED_LEGACY_TRIGGER_CONTEXT_MODE_SET.has(contextMode)) return [];
      return [
        {
          index,
          nodeId: asTrimmedString(node['id']) || null,
          nodeTitle: asTrimmedString(node['title']) || null,
          contextMode: contextMode as RemovedLegacyTriggerContextMode,
        },
      ];
    }
  );
};

export const findRemovedLegacyTriggerContextModesInDocument = (
  document: unknown
): RemovedLegacyTriggerContextModeUsage[] => {
  if (!isObjectRecord(document)) return [];
  const direct = findRemovedLegacyTriggerContextModes(document['nodes']);
  if (direct.length > 0) return direct;

  const semanticDocument = document['document'];
  if (isObjectRecord(semanticDocument)) {
    const nested = findRemovedLegacyTriggerContextModes(semanticDocument['nodes']);
    if (nested.length > 0) return nested;
  }

  const portableEnvelope = document['package'];
  if (isObjectRecord(portableEnvelope)) {
    const nestedDocument = portableEnvelope['document'];
    if (isObjectRecord(nestedDocument)) {
      return findRemovedLegacyTriggerContextModes(nestedDocument['nodes']);
    }
  }

  return [];
};

export const findRemovedLegacyTriggerContextModesInPathConfig = (
  pathConfig: { nodes?: unknown } | null | undefined
): RemovedLegacyTriggerContextModeUsage[] => {
  if (!pathConfig || typeof pathConfig !== 'object') return [];
  return findRemovedLegacyTriggerContextModes((pathConfig as { nodes?: unknown }).nodes);
};

const formatRemovedLegacyTriggerContextModeUsage = (
  usage: RemovedLegacyTriggerContextModeUsage
): string => {
  const nodeId = usage.nodeId ? ` (${usage.nodeId})` : '';
  const nodeTitle = usage.nodeTitle ? `"${usage.nodeTitle}" ` : '';
  return `${nodeTitle}<trigger>${nodeId} uses \`${usage.contextMode}\``;
};

export const formatRemovedLegacyTriggerContextModesMessage = (
  removedModes: RemovedLegacyTriggerContextModeUsage[],
  options?: {
    surface?:
      | 'path config'
      | 'run graph'
      | 'semantic document'
      | 'portable payload'
      | 'trigger payload'
      | 'validation payload';
  }
): string => {
  const surface = options?.surface ?? 'path config';
  const examples = removedModes
    .slice(0, 3)
    .map(formatRemovedLegacyTriggerContextModeUsage)
    .join(', ');
  return [
    `AI Paths ${surface} contains removed legacy Trigger context modes: ${examples}.`,
    'Deprecated Trigger.contextMode values `simulation_required` and `simulation_preferred` are no longer supported.',
    'Keep Trigger in `trigger_only` mode and resolve entity context through downstream Fetcher or Simulation nodes.',
  ].join(' ');
};

import type { BrainModelDescriptor } from '@/shared/contracts/ai-brain';
import type { AiNode } from '@/shared/contracts/ai-paths';

export type VisionModelCapabilityIssue = {
  nodeId: string;
  nodeTitle: string | null;
  modelId: string;
  modality: string;
};

export const collectVisionModelCapabilityIssues = (args: {
  nodes: AiNode[];
  defaultModelId: string;
  descriptors: Record<string, BrainModelDescriptor>;
}): VisionModelCapabilityIssue[] => {
  const defaultModelId = args.defaultModelId.trim();
  return args.nodes.flatMap((node): VisionModelCapabilityIssue[] => {
    if (node.type !== 'model' || node.config?.model?.vision !== true) {
      return [];
    }

    const selectedModelId =
      typeof node.config?.model?.modelId === 'string' ? node.config.model.modelId.trim() : '';
    const runtimeModelId = selectedModelId || defaultModelId;
    if (!runtimeModelId) {
      return [];
    }

    const descriptor = args.descriptors[runtimeModelId];
    if (!descriptor || descriptor.modality === 'multimodal') {
      return [];
    }

    return [
      {
        nodeId: node.id,
        nodeTitle: typeof node.title === 'string' ? node.title : null,
        modelId: runtimeModelId,
        modality: descriptor.modality,
      },
    ];
  });
};

export const buildVisionModelCapabilityErrorMessage = (
  issue: VisionModelCapabilityIssue
): string => {
  const label = issue.nodeTitle?.trim() || issue.nodeId;
  return `Model node "${label}" has Accepts Images enabled but effective AI Brain model "${issue.modelId}" is ${issue.modality}. Choose a multimodal model or disable image input for this node.`;
};

import type { AiNode, NodeDefinition, PathConfig } from '@/shared/contracts/ai-paths';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { hashString, stableStringify } from './runtime';


type NodeIdentityLike = Pick<AiNode, 'type' | 'title'> &
  Partial<Pick<AiNode, 'config' | 'nodeTypeId'>>;

export type PathIdentityRepairWarning = {
  code: 'missing_node_id' | 'duplicate_node_id';
  message: string;
  sourceNodeId?: string;
};

export type PathIdentityRepairResult = {
  config: PathConfig;
  changed: boolean;
  warnings: PathIdentityRepairWarning[];
};

export type PathIdentityValidationIssue = {
  code:
    | 'missing_node_id'
    | 'invalid_node_id'
    | 'duplicate_node_id'
    | 'invalid_instance_id'
    | 'invalid_node_type_id'
    | 'invalid_selected_node_id'
    | 'invalid_parser_sample_node_id'
    | 'invalid_updater_sample_node_id'
    | 'invalid_runtime_state_node_id';
  message: string;
  nodeId?: string;
  expected?: string;
  location?: string;
};

type PathIdentityRepairOptions = {
  palette?: NodeDefinition[];
};

const NODE_INSTANCE_ID_PREFIX = 'node-';
const NODE_TYPE_ID_PREFIX = 'nt-';
const HASH_HEX_LENGTH = 24;
const NODE_INSTANCE_ID_HASH_PATTERN = /^node-[a-f0-9]{24}$/;
const NODE_TYPE_ID_HASH_PATTERN = /^nt-[a-f0-9]{24}$/;

const asTrimmedString = (value: unknown): string => (typeof value === 'string' ? value.trim() : '');

const getTriggerEvent = (node: NodeIdentityLike): string =>
  asTrimmedString((node.config as { trigger?: { event?: unknown } } | undefined)?.trigger?.event);

const composeHashHex = (seed: string): string => {
  const normalizedSeed = seed.trim().length > 0 ? seed : 'ai_paths';
  return [
    hashString(normalizedSeed),
    hashString(`a:${normalizedSeed}`),
    hashString(`b:${normalizedSeed}`),
    hashString(`c:${normalizedSeed}`),
  ]
    .join('')
    .slice(0, HASH_HEX_LENGTH);
};

const createHashedIdentifier = (prefix: string, seed: string): string =>
  `${prefix}${composeHashHex(seed)}`;

const isHashedNodeInstanceId = (value: string): boolean =>
  NODE_INSTANCE_ID_HASH_PATTERN.test(value);

const isHashedNodeTypeId = (value: string): boolean => NODE_TYPE_ID_HASH_PATTERN.test(value);

const createNodeTypeHashId = (args: {
  type: string;
  title: string;
  triggerEvent?: string | null;
  sourceNodeTypeId?: string | null;
  index?: number;
  collisionSalt?: number;
}): string => {
  const seed = stableStringify({
    kind: 'ai_paths_node_type',
    type: asTrimmedString(args.type) || 'unknown',
    title: asTrimmedString(args.title),
    triggerEvent: asTrimmedString(args.triggerEvent ?? ''),
    // Keep stable seed key name for deterministic id continuity.
    legacyNodeTypeId: asTrimmedString(args.sourceNodeTypeId ?? ''),
    index:
      typeof args.index === 'number' && Number.isFinite(args.index)
        ? Math.max(0, Math.trunc(args.index))
        : null,
    collisionSalt:
      typeof args.collisionSalt === 'number' && Number.isFinite(args.collisionSalt)
        ? Math.max(0, Math.trunc(args.collisionSalt))
        : 0,
  });
  return createHashedIdentifier(NODE_TYPE_ID_PREFIX, seed);
};

const createNodeInstanceIdFromSource = (
  args: {
    pathId: string;
    sourceId: string;
    node: NodeIdentityLike;
    occurrence: number;
  },
  usedIds: Set<string>
): string => {
  let collisionSalt = 0;
  let candidate = '';
  while (!candidate || usedIds.has(candidate)) {
    const seed = stableStringify({
      kind: 'ai_paths_node_instance',
      pathId: asTrimmedString(args.pathId) || 'path',
      // Keep stable seed key name for deterministic id continuity.
      legacyId: asTrimmedString(args.sourceId) || 'missing',
      type: asTrimmedString(args.node.type) || 'unknown',
      title: asTrimmedString(args.node.title),
      triggerEvent: getTriggerEvent(args.node),
      occurrence: Math.max(1, Math.trunc(args.occurrence)),
      collisionSalt,
    });
    candidate = createHashedIdentifier(NODE_INSTANCE_ID_PREFIX, seed);
    collisionSalt += 1;
  }
  usedIds.add(candidate);
  return candidate;
};

export const derivePaletteNodeTypeId = (
  definition: Pick<NodeDefinition, 'type' | 'title' | 'config'>,
  index?: number,
  collisionSalt = 0
): string => {
  return createNodeTypeHashId({
    type: definition.type,
    title: definition.title,
    triggerEvent: definition.type === 'trigger' ? getTriggerEvent(definition) : null,
    index,
    collisionSalt,
  });
};

export const createNodeInstanceId = (usedIds: Set<string> | Iterable<string>): string => {
  const used = usedIds instanceof Set ? usedIds : new Set<string>(usedIds);
  let candidate = '';
  let attempt = 0;
  while (!candidate || used.has(candidate)) {
    const entropy = globalThis.crypto?.randomUUID
      ? globalThis.crypto.randomUUID()
      : `${Date.now()}:${Math.random()}:${attempt}`;
    candidate = createHashedIdentifier(NODE_INSTANCE_ID_PREFIX, `${entropy}:${attempt}`);
    attempt += 1;
  }
  if (usedIds instanceof Set) {
    usedIds.add(candidate);
  }
  return candidate;
};

const findDefinitionForNode = (
  node: NodeIdentityLike,
  palette: NodeDefinition[]
): NodeDefinition | null => {
  if (palette.length === 0) return null;

  const exactTitle = palette.find(
    (definition: NodeDefinition): boolean =>
      definition.type === node.type && definition.title === node.title
  );
  if (exactTitle) return exactTitle;

  const nodeTriggerEvent = getTriggerEvent(node);
  if (node.type === 'trigger' && nodeTriggerEvent.length > 0) {
    const byTriggerEvent = palette.find((definition: NodeDefinition): boolean => {
      if (definition.type !== 'trigger') return false;
      return getTriggerEvent(definition) === nodeTriggerEvent;
    });
    if (byTriggerEvent) return byTriggerEvent;
  }

  return (
    palette.find((definition: NodeDefinition): boolean => definition.type === node.type) ?? null
  );
};

export const resolveNodeTypeId = (
  node: NodeIdentityLike,
  palette: NodeDefinition[] = []
): string => {
  const explicit = asTrimmedString(node.nodeTypeId);
  if (explicit.length > 0 && isHashedNodeTypeId(explicit)) return explicit;

  const definition = findDefinitionForNode(node, palette);
  if (definition) {
    const fromDefinition = asTrimmedString(definition.nodeTypeId);
    if (fromDefinition.length > 0 && isHashedNodeTypeId(fromDefinition)) {
      return fromDefinition;
    }
    return createNodeTypeHashId({
      type: definition.type,
      title: definition.title,
      triggerEvent: definition.type === 'trigger' ? getTriggerEvent(definition) : null,
      sourceNodeTypeId: fromDefinition.length > 0 ? fromDefinition : explicit,
    });
  }

  const fallbackType = asTrimmedString(node.type);
  return createNodeTypeHashId({
    type: fallbackType.length > 0 ? fallbackType : 'unknown',
    title: asTrimmedString(node.title),
    triggerEvent: node.type === 'trigger' ? getTriggerEvent(node) : null,
    sourceNodeTypeId: explicit.length > 0 ? explicit : null,
  });
};

const remapNodeKeyedRecord = (
  value: unknown,
  remapNodeId: (nodeId: string) => string
): { value: unknown; changed: boolean } => {
  if (!isObjectRecord(value)) {
    return { value, changed: false };
  }

  let changed = false;
  const next: Record<string, unknown> = {};
  for (const [key, entry] of Object.entries(value)) {
    const remappedKey = remapNodeId(key);
    if (remappedKey !== key) changed = true;

    if (!(remappedKey in next)) {
      next[remappedKey] = entry;
      continue;
    }
    changed = true;
    const existing = next[remappedKey];
    if (Array.isArray(existing) && Array.isArray(entry)) {
      const existingArray = existing as unknown[];
      const incomingArray = entry as unknown[];
      next[remappedKey] = [...existingArray, ...incomingArray];
      continue;
    }
    if (isObjectRecord(existing) && isObjectRecord(entry)) {
      next[remappedKey] = {
        ...existing,
        ...entry,
      };
      continue;
    }
  }
  return changed ? { value: next, changed: true } : { value, changed: false };
};

const remapRuntimeState = (
  runtimeState: unknown,
  remapNodeId: (nodeId: string) => string
): { runtimeState: Record<string, unknown> | string | undefined; changed: boolean } => {
  const remapRuntimeObject = (
    value: Record<string, unknown>
  ): { runtimeState: Record<string, unknown>; changed: boolean } => {
    let changed = false;
    const next = { ...value };

    (
      [
        'inputs',
        'outputs',
        'history',
        'hashes',
        'hashTimestamps',
        'nodeStatuses',
        'nodeOutputs',
      ] as const
    ).forEach((key) => {
      const remapped = remapNodeKeyedRecord(next[key], remapNodeId);
      if (!remapped.changed) return;
      next[key] = remapped.value;
      changed = true;
    });

    return { runtimeState: next, changed };
  };

  if (typeof runtimeState === 'string') {
    try {
      const parsed = JSON.parse(runtimeState) as unknown;
      if (!isObjectRecord(parsed)) {
        return {
          runtimeState: runtimeState as string | Record<string, unknown> | undefined,
          changed: false,
        };
      }
      const remapped = remapRuntimeObject(parsed);
      if (!remapped.changed) {
        return {
          runtimeState: runtimeState as string | Record<string, unknown> | undefined,
          changed: false,
        };
      }
      return {
        runtimeState: JSON.stringify(remapped.runtimeState),
        changed: true,
      };
    } catch (_error) {
      return {
        runtimeState: undefined,
        changed: true,
      };
    }
  }

  if (!isObjectRecord(runtimeState)) {
    return {
      runtimeState: runtimeState as string | Record<string, unknown> | undefined,
      changed: false,
    };
  }

  const remapped = remapRuntimeObject(runtimeState);
  return {
    runtimeState: remapped.runtimeState,
    changed: remapped.changed,
  };
};

const collectNodeKeyReferenceIssues = (
  value: unknown,
  nodeIds: Set<string>,
  location: string,
  code:
    | 'invalid_parser_sample_node_id'
    | 'invalid_updater_sample_node_id'
    | 'invalid_runtime_state_node_id'
): PathIdentityValidationIssue[] => {
  if (!isObjectRecord(value)) return [];

  const issues: PathIdentityValidationIssue[] = [];
  Object.keys(value).forEach((rawNodeId: string): void => {
    const trimmedNodeId = rawNodeId.trim();
    if (trimmedNodeId.length > 0 && rawNodeId === trimmedNodeId && nodeIds.has(trimmedNodeId)) {
      return;
    }
    issues.push({
      code,
      nodeId: rawNodeId || undefined,
      location,
      message: `Non-canonical node reference "${rawNodeId}" found at ${location}.`,
    });
  });
  return issues;
};

const parseRuntimeStateRecord = (runtimeState: unknown): Record<string, unknown> | null => {
  if (isObjectRecord(runtimeState)) return runtimeState;
  if (typeof runtimeState !== 'string' || runtimeState.trim().length === 0) return null;
  try {
    const parsed = JSON.parse(runtimeState) as unknown;
    return isObjectRecord(parsed) ? parsed : null;
  } catch {
    return null;
  }
};

export const validateCanonicalPathNodeIdentities = (
  pathConfig: PathConfig,
  options?: PathIdentityRepairOptions
): PathIdentityValidationIssue[] => {
  const palette = options?.palette ?? [];
  const issues: PathIdentityValidationIssue[] = [];
  const usedIds = new Set<string>();

  (pathConfig.nodes ?? []).forEach((node: AiNode): void => {
    const rawId = typeof node.id === 'string' ? node.id : '';
    const trimmedId = rawId.trim();
    if (!trimmedId) {
      issues.push({
        code: 'missing_node_id',
        message: `Node "${node.title || node.type}" is missing a canonical node id.`,
      });
      return;
    }

    if (rawId !== trimmedId || !isHashedNodeInstanceId(trimmedId)) {
      issues.push({
        code: 'invalid_node_id',
        nodeId: rawId,
        expected: 'node-[a-f0-9]{24}',
        message: `Node "${node.title || node.type}" uses non-canonical id "${rawId}".`,
      });
    }

    if (usedIds.has(trimmedId)) {
      issues.push({
        code: 'duplicate_node_id',
        nodeId: trimmedId,
        message: `Duplicate node id "${trimmedId}" is not supported.`,
      });
    } else {
      usedIds.add(trimmedId);
    }

    const instanceId = asTrimmedString((node as { instanceId?: unknown }).instanceId);
    if (instanceId !== trimmedId) {
      issues.push({
        code: 'invalid_instance_id',
        nodeId: trimmedId,
        expected: trimmedId,
        message: `Node "${trimmedId}" must persist instanceId "${trimmedId}".`,
      });
    }

    const expectedNodeTypeId = resolveNodeTypeId(node, palette);
    if (asTrimmedString(node.nodeTypeId) !== expectedNodeTypeId) {
      issues.push({
        code: 'invalid_node_type_id',
        nodeId: trimmedId,
        expected: expectedNodeTypeId,
        message: `Node "${trimmedId}" uses non-canonical nodeTypeId.`,
      });
    }
  });

  const selectedNodeId =
    typeof pathConfig.uiState?.selectedNodeId === 'string'
      ? pathConfig.uiState.selectedNodeId
      : null;
  if (selectedNodeId) {
    const trimmedSelectedNodeId = selectedNodeId.trim();
    if (selectedNodeId !== trimmedSelectedNodeId || !usedIds.has(trimmedSelectedNodeId)) {
      issues.push({
        code: 'invalid_selected_node_id',
        nodeId: selectedNodeId,
        location: 'uiState.selectedNodeId',
        message: `Non-canonical selected node reference "${selectedNodeId}" is not supported.`,
      });
    }
  }

  issues.push(
    ...collectNodeKeyReferenceIssues(
      pathConfig.parserSamples,
      usedIds,
      'parserSamples',
      'invalid_parser_sample_node_id'
    )
  );
  issues.push(
    ...collectNodeKeyReferenceIssues(
      pathConfig.updaterSamples,
      usedIds,
      'updaterSamples',
      'invalid_updater_sample_node_id'
    )
  );

  const runtimeState = parseRuntimeStateRecord(pathConfig.runtimeState);
  if (runtimeState) {
    (
      [
        'inputs',
        'outputs',
        'history',
        'hashes',
        'hashTimestamps',
        'nodeStatuses',
        'nodeOutputs',
      ] as const
    ).forEach((location) => {
      issues.push(
        ...collectNodeKeyReferenceIssues(
          runtimeState[location],
          usedIds,
          `runtimeState.${location}`,
          'invalid_runtime_state_node_id'
        )
      );
    });
  }

  return issues;
};

export const repairPathNodeIdentities = (
  pathConfig: PathConfig,
  options?: PathIdentityRepairOptions
): PathIdentityRepairResult => {
  const palette = options?.palette ?? [];
  const warnings: PathIdentityRepairWarning[] = [];
  const usedIds = new Set<string>();
  const firstResolvedBySourceId = new Map<string, string>();
  const duplicateCounts = new Map<string, number>();
  const sourceOccurrenceCounts = new Map<string, number>();

  const remapNodeId = (candidate: string): string => {
    const direct = firstResolvedBySourceId.get(candidate);
    if (direct) return direct;
    const trimmed = candidate.trim();
    if (!trimmed) return candidate;
    return firstResolvedBySourceId.get(trimmed) ?? candidate;
  };

  let changed = false;
  const pathIdSeed = asTrimmedString(pathConfig.id) || 'path';
  const repairedNodes = (pathConfig.nodes ?? []).map((node: AiNode): AiNode => {
    const rawSourceId = typeof node.id === 'string' ? node.id : '';
    const trimmedSourceId = rawSourceId.trim();

    let nextId: string;
    if (!trimmedSourceId) {
      nextId = createNodeInstanceId(usedIds);
      warnings.push({
        code: 'missing_node_id',
        message: `Generated a missing node id for "${node.title || node.type}".`,
      });
      changed = true;
    } else {
      const occurrence = (sourceOccurrenceCounts.get(trimmedSourceId) ?? 0) + 1;
      sourceOccurrenceCounts.set(trimmedSourceId, occurrence);
      const isDuplicateSourceId = occurrence > 1;
      const canReuseHashedSourceId =
        occurrence === 1 &&
        isHashedNodeInstanceId(trimmedSourceId) &&
        !usedIds.has(trimmedSourceId);
      if (canReuseHashedSourceId) {
        nextId = trimmedSourceId;
        usedIds.add(nextId);
      } else {
        nextId = createNodeInstanceIdFromSource(
          {
            pathId: pathIdSeed,
            sourceId: trimmedSourceId,
            node,
            occurrence,
          },
          usedIds
        );
      }
      if (isDuplicateSourceId) {
        duplicateCounts.set(trimmedSourceId, occurrence);
        warnings.push({
          code: 'duplicate_node_id',
          sourceNodeId: trimmedSourceId,
          message: `Duplicate node id "${trimmedSourceId}" detected; remapped duplicate to "${nextId}".`,
        });
      }
      if (nextId !== rawSourceId) {
        changed = true;
      }
    }

    if (!firstResolvedBySourceId.has(rawSourceId)) {
      firstResolvedBySourceId.set(rawSourceId, nextId);
    }
    if (trimmedSourceId && !firstResolvedBySourceId.has(trimmedSourceId)) {
      firstResolvedBySourceId.set(trimmedSourceId, nextId);
    }

    const nextNodeTypeId = resolveNodeTypeId(node, palette);
    const nextInstanceId = nextId;
    if (
      node.id !== nextId ||
      node.instanceId !== nextInstanceId ||
      node.nodeTypeId !== nextNodeTypeId
    ) {
      changed = true;
    }

    return {
      ...node,
      id: nextId,
      instanceId: nextInstanceId,
      nodeTypeId: nextNodeTypeId,
    };
  });

  duplicateCounts.forEach((_count: number, sourceId: string): void => {
    warnings.push({
      code: 'duplicate_node_id',
      sourceNodeId: sourceId,
      message: `Ambiguous references for duplicate id "${sourceId}" were remapped to the first kept node.`,
    });
  });

  const repairedEdges = (pathConfig.edges ?? []).map((edge) => {
    const nextFrom = typeof edge.from === 'string' ? remapNodeId(edge.from) : edge.from;
    const nextTo = typeof edge.to === 'string' ? remapNodeId(edge.to) : edge.to;
    if (nextFrom !== edge.from || nextTo !== edge.to) {
      changed = true;
      return {
        ...edge,
        ...(typeof nextFrom === 'string' ? { from: nextFrom } : {}),
        ...(typeof nextTo === 'string' ? { to: nextTo } : {}),
      };
    }
    return edge;
  });

  const selectedNodeId = pathConfig.uiState?.selectedNodeId;
  const remappedSelectedNodeId =
    typeof selectedNodeId === 'string' ? remapNodeId(selectedNodeId) : selectedNodeId;
  const nextUiState =
    pathConfig.uiState && remappedSelectedNodeId !== selectedNodeId
      ? { ...pathConfig.uiState, selectedNodeId: remappedSelectedNodeId }
      : pathConfig.uiState;
  if (nextUiState !== pathConfig.uiState) {
    changed = true;
  }

  const remappedParserSamples = remapNodeKeyedRecord(pathConfig.parserSamples, remapNodeId);
  if (remappedParserSamples.changed) {
    changed = true;
  }

  const remappedUpdaterSamples = remapNodeKeyedRecord(pathConfig.updaterSamples, remapNodeId);
  if (remappedUpdaterSamples.changed) {
    changed = true;
  }

  const remappedRuntimeState = remapRuntimeState(pathConfig.runtimeState, remapNodeId);
  if (remappedRuntimeState.changed) {
    changed = true;
  }

  const nextConfig: PathConfig = changed
    ? {
      ...pathConfig,
      nodes: repairedNodes,
      edges: repairedEdges,
      ...(nextUiState ? { uiState: nextUiState } : {}),
      ...(remappedParserSamples.changed
        ? { parserSamples: remappedParserSamples.value as PathConfig['parserSamples'] }
        : {}),
      ...(remappedUpdaterSamples.changed
        ? { updaterSamples: remappedUpdaterSamples.value as PathConfig['updaterSamples'] }
        : {}),
      ...(remappedRuntimeState.changed
        ? { runtimeState: remappedRuntimeState.runtimeState }
        : {}),
    }
    : pathConfig;

  return {
    config: nextConfig,
    changed,
    warnings,
  };
};

