import type {
  AiNode,
  DatabaseConfig,
  PathConfig,
  RuntimeHistoryEntry,
  RuntimePortValues,
  RuntimeState,
} from '@/shared/contracts/ai-paths';
import { validationError } from '@/shared/errors/app-error';

import { palette } from '../definitions';
import {
  backfillPathConfigNodeContracts,
  normalizeNodes,
} from '../normalization';
import { findPathConfigCollectionAliasIssues } from './collection-names';
import { sanitizeEdges } from './graph.edges';
import {
  findRemovedLegacyAiPathNodesInPathConfig,
  formatRemovedLegacyAiPathNodesMessage,
} from './legacy-node-removal';
import {
  findRemovedLegacyTriggerContextModesInPathConfig,
  formatRemovedLegacyTriggerContextModesMessage,
} from './legacy-trigger-context-mode';
import { validateCanonicalPathNodeIdentities } from './node-identity';
import { cloneJsonSafe, stableStringify } from './runtime';
import { parseRuntimeState } from './runtime-state';

type DatabaseOperation = 'query' | 'update' | 'insert' | 'delete';

const isDatabaseOperation = (value: unknown): value is DatabaseOperation =>
  value === 'query' || value === 'update' || value === 'insert' || value === 'delete';

const UNSUPPORTED_TRIGGER_DATA_PORTS = new Set(['context', 'meta', 'entityId', 'entityType']);

const resolveNodeCreatedAt = (value: unknown, fallbackTimestamp: string): string =>
  typeof value === 'string' && value.trim().length > 0 ? value : fallbackTimestamp;

const resolveNodeUpdatedAt = (value: unknown): string | null =>
  typeof value === 'string' && value.trim().length > 0 ? value : null;

const resolveEdgeSourceNodeId = (edge: Record<string, unknown>): string => {
  const from = typeof edge['from'] === 'string' ? edge['from'].trim() : '';
  return from;
};

const resolveEdgeSourcePort = (edge: Record<string, unknown>): string => {
  const fromPort = typeof edge['fromPort'] === 'string' ? edge['fromPort'].trim() : '';
  return fromPort;
};

const assertNoUnsupportedTriggerDataGraph = (nodes: AiNode[], edges: unknown[]): void => {
  const nodeById = new Map<string, AiNode>(
    nodes.map((node: AiNode): [string, AiNode] => [node.id, node])
  );

  nodes.forEach((node: AiNode): void => {
    if (node.type !== 'trigger') return;
    const outputs = Array.isArray(node.outputs) ? node.outputs : [];
    const unsupportedPorts = outputs.filter((port: string): boolean =>
      UNSUPPORTED_TRIGGER_DATA_PORTS.has(port)
    );
    if (unsupportedPorts.length === 0) return;
    throw validationError('AI Path config contains unsupported trigger output ports.', {
      source: 'ai_paths.path_config',
      reason: 'unsupported_trigger_outputs',
      nodeId: node.id,
      outputs: unsupportedPorts,
    });
  });

  edges.forEach((edgeValue: unknown, index: number): void => {
    if (!edgeValue || typeof edgeValue !== 'object' || Array.isArray(edgeValue)) return;
    const edge = edgeValue as Record<string, unknown>;
    const sourceNodeId = resolveEdgeSourceNodeId(edge);
    const sourcePort = resolveEdgeSourcePort(edge);
    if (!sourceNodeId || !sourcePort) return;
    const sourceNode = nodeById.get(sourceNodeId);
    if (sourceNode?.type !== 'trigger') return;
    if (!UNSUPPORTED_TRIGGER_DATA_PORTS.has(sourcePort)) return;
    throw validationError('AI Path config contains unsupported trigger data edges.', {
      source: 'ai_paths.path_config',
      reason: 'unsupported_trigger_data_edge',
      edgeIndex: index,
      edgeId: typeof edge['id'] === 'string' ? edge['id'] : null,
      sourceNodeId,
      sourcePort,
    });
  });
};

const trimRuntimeValue = (value: unknown, depth: number = 1): unknown => {
  if (value === null || value === undefined) return value;
  if (typeof value === 'string') {
    const trimmed = value.length > 1000 ? `${value.slice(0, 1000)}...` : value;
    return trimmed;
  }
  if (typeof value === 'number' || typeof value === 'boolean') return value;
  if (value instanceof Date) return value.toISOString();
  if (Array.isArray(value)) {
    if (depth <= 0) return `[Array(${value.length})]`;
    const slice = value.slice(0, 20).map((entry: unknown) => trimRuntimeValue(entry, depth - 1));
    if (value.length > 20) {
      slice.push(`...${value.length - 20} more`);
    }
    return slice;
  }
  if (typeof value === 'object') {
    if (depth <= 0) return '[Object]';
    const record = value as Record<string, unknown>;
    const entries = Object.entries(record);
    const trimmedEntries = entries
      .slice(0, 20)
      .map(([key, entryValue]: [string, unknown]) => [
        key,
        trimRuntimeValue(entryValue, depth - 1),
      ]);
    const result = Object.fromEntries(trimmedEntries) as Record<string, unknown>;
    if (entries.length > 20) {
      result['__truncated__'] = `...${entries.length - 20} more keys`;
    }
    return result;
  }
  return value;
};

const trimRuntimePorts = (ports: RuntimePortValues): RuntimePortValues => {
  const trimmed: RuntimePortValues = {};
  Object.entries(ports).forEach(([key, value]: [string, unknown]) => {
    trimmed[key] = trimRuntimeValue(value, 1);
  });
  return trimmed;
};

export const buildPersistedRuntimeState = (state: RuntimeState, graphNodes: AiNode[]): string => {
  const excludedTypes = new Set<string>(['notification', 'viewer']);
  const includeHistoryInPathConfig = false;
  const historyLimit = 5;
  const nodeIds = new Set(
    graphNodes
      .filter((node: AiNode): boolean => !excludedTypes.has(node.type))
      .map((node: AiNode) => node.id)
  );
  const inputs: Record<string, RuntimePortValues> = {};
  const outputs: Record<string, RuntimePortValues> = {};
  const history: Record<string, RuntimeHistoryEntry[]> = {};

  Object.entries(state.inputs ?? {}).forEach(([key, value]: [string, RuntimePortValues]) => {
    if (nodeIds.has(key)) {
      inputs[key] = trimRuntimePorts(value);
    }
  });
  Object.entries(state.outputs ?? {}).forEach(([key, value]: [string, RuntimePortValues]) => {
    if (nodeIds.has(key)) {
      outputs[key] = trimRuntimePorts(value);
    }
  });
  Object.entries(state.history ?? {}).forEach(([key, value]) => {
    if (!includeHistoryInPathConfig) return;
    if (!nodeIds.has(key)) return;
    const entries = Array.isArray(value) ? value : [];
    const trimmed = entries.slice(-historyLimit);
    if (trimmed.length > 0) {
      history[key] = trimmed.map((entry: RuntimeHistoryEntry): RuntimeHistoryEntry => {
        return {
          ...entry,
          inputs: entry.inputs ? trimRuntimePorts(entry.inputs) : entry.inputs,
          outputs: entry.outputs ? trimRuntimePorts(entry.outputs) : entry.outputs,
        } as RuntimeHistoryEntry;
      });
    }
  });

  const currentRun =
    state.currentRun && typeof state.currentRun.id === 'string'
      ? {
          id: state.currentRun.id,
          status: state.currentRun.status,
          startedAt: state.currentRun.startedAt ?? null,
          finishedAt: state.currentRun.finishedAt ?? null,
          pathId: state.currentRun.pathId ?? null,
          pathName: state.currentRun.pathName ?? null,
          createdAt: state.currentRun.createdAt,
          updatedAt: state.currentRun.updatedAt ?? null,
        }
      : null;
  const payload: Record<string, unknown> = {
    inputs,
    outputs,
    ...(currentRun ? { currentRun } : {}),
  };
  if (Object.keys(history).length > 0) {
    payload['history'] = history;
  }
  const safe = cloneJsonSafe(payload);
  return safe ? JSON.stringify(safe) : '';
};

export const sanitizePathConfig = (config: PathConfig): PathConfig => {
  const removedTriggerContextModes = findRemovedLegacyTriggerContextModesInPathConfig(config);
  if (removedTriggerContextModes.length > 0) {
    throw validationError(
      formatRemovedLegacyTriggerContextModesMessage(removedTriggerContextModes, {
        surface: 'path config',
      }),
      {
        source: 'ai_paths.path_config',
        reason: 'removed_trigger_context_mode',
        pathId: config.id,
        removedModes: removedTriggerContextModes,
      }
    );
  }

  const collectionAliasIssues = findPathConfigCollectionAliasIssues(config);
  if (collectionAliasIssues.length > 0) {
    throw validationError('AI Path config contains unsupported collection aliases.', {
      source: 'ai_paths.path_config',
      reason: 'unsupported_collection_aliases',
      pathId: config.id,
      issues: collectionAliasIssues,
    });
  }

  const contractBackfilled = backfillPathConfigNodeContracts(config).config;
  const removedLegacyNodes = findRemovedLegacyAiPathNodesInPathConfig(contractBackfilled);
  if (removedLegacyNodes.length > 0) {
    throw validationError(formatRemovedLegacyAiPathNodesMessage(removedLegacyNodes), {
      source: 'ai_paths.path_config',
      reason: 'removed_legacy_node_type',
      pathId: config.id,
      removedNodes: removedLegacyNodes,
    });
  }

  const sanitizedNodes = contractBackfilled.nodes.map((node: AiNode): AiNode => {
    if (node.type !== 'database' || !node.config || typeof node.config !== 'object') {
      return node;
    }
    const configRecord = node.config as Record<string, unknown>;
    const databaseConfig = configRecord['database'];
    if (!databaseConfig || typeof databaseConfig !== 'object') {
      return node;
    }
    const databaseRecord = databaseConfig as Record<string, unknown>;
    const queryConfig =
      databaseRecord['query'] && typeof databaseRecord['query'] === 'object'
        ? (databaseRecord['query'] as Record<string, unknown>)
        : null;
    if (Object.prototype.hasOwnProperty.call(databaseRecord, 'schemaSnapshot')) {
      throw validationError('AI Path config contains unsupported database schemaSnapshot.', {
        source: 'ai_paths.path_config',
        reason: 'unsupported_database_schema_snapshot',
        nodeId: node.id,
      });
    }
    const operation = databaseRecord['operation'];
    const nextDatabaseConfig = {
      ...(databaseConfig as Partial<DatabaseConfig>),
      operation: isDatabaseOperation(operation) ? operation : 'query',
      writeOutcomePolicy: {
        onZeroAffected:
          databaseRecord['writeOutcomePolicy'] &&
          typeof databaseRecord['writeOutcomePolicy'] === 'object' &&
          !Array.isArray(databaseRecord['writeOutcomePolicy']) &&
          ((databaseRecord['writeOutcomePolicy'] as Record<string, unknown>)['onZeroAffected'] ===
            'warn' ||
            (databaseRecord['writeOutcomePolicy'] as Record<string, unknown>)['onZeroAffected'] ===
              'ignore')
            ? ((databaseRecord['writeOutcomePolicy'] as Record<string, unknown>)[
                'onZeroAffected'
              ] as 'warn' | 'ignore')
            : 'fail',
      },
    } as DatabaseConfig;
    if (queryConfig) {
      const provider = queryConfig['provider'];
      if (provider === 'all') {
        throw validationError(
          'AI Path config contains unsupported database query provider "all".',
          {
            source: 'ai_paths.path_config',
            reason: 'unsupported_database_query_provider',
            nodeId: node.id,
            provider,
          }
        );
      }
      if (provider !== undefined && provider !== 'auto' && provider !== 'mongodb') {
        throw validationError('AI Path config contains invalid database query provider.', {
          source: 'ai_paths.path_config',
          reason: 'invalid_database_query_provider',
          nodeId: node.id,
          provider,
        });
      }
      nextDatabaseConfig.query = {
        provider: provider === 'mongodb' ? provider : 'auto',
        collection:
          typeof queryConfig['collection'] === 'string' ? queryConfig['collection'] : 'products',
        mode:
          queryConfig['mode'] === 'preset' || queryConfig['mode'] === 'custom'
            ? queryConfig['mode']
            : 'custom',
        preset:
          queryConfig['preset'] === 'by_id' ||
          queryConfig['preset'] === 'by_productId' ||
          queryConfig['preset'] === 'by_entityId' ||
          queryConfig['preset'] === 'by_field'
            ? queryConfig['preset']
            : 'by_id',
        field: typeof queryConfig['field'] === 'string' ? queryConfig['field'] : '_id',
        idType:
          queryConfig['idType'] === 'string' || queryConfig['idType'] === 'objectId'
            ? queryConfig['idType']
            : 'string',
        queryTemplate:
          typeof queryConfig['queryTemplate'] === 'string' ? queryConfig['queryTemplate'] : '',
        limit:
          typeof queryConfig['limit'] === 'number' && Number.isFinite(queryConfig['limit'])
            ? queryConfig['limit']
            : 20,
        sort: typeof queryConfig['sort'] === 'string' ? queryConfig['sort'] : '',
        ...(typeof queryConfig['sortPresetId'] === 'string'
          ? { sortPresetId: queryConfig['sortPresetId'] }
          : {}),
        projection: typeof queryConfig['projection'] === 'string' ? queryConfig['projection'] : '',
        ...(typeof queryConfig['projectionPresetId'] === 'string'
          ? { projectionPresetId: queryConfig['projectionPresetId'] }
          : {}),
        single: queryConfig['single'] === true,
      };
    }
    const parameterInferenceGuard =
      databaseRecord['parameterInferenceGuard'] &&
      typeof databaseRecord['parameterInferenceGuard'] === 'object' &&
      !Array.isArray(databaseRecord['parameterInferenceGuard'])
        ? (databaseRecord['parameterInferenceGuard'] as Record<string, unknown>)
        : null;
    if (parameterInferenceGuard) {
      const targetPath =
        typeof parameterInferenceGuard['targetPath'] === 'string'
          ? parameterInferenceGuard['targetPath'].trim()
          : '';
      if (targetPath.length > 0 && targetPath !== 'parameters') {
        throw validationError(
          'AI Path config contains unsupported parameter inference target path.',
          {
            source: 'ai_paths.path_config',
            reason: 'unsupported_parameter_inference_target_path',
            nodeId: node.id,
            targetPath,
          }
        );
      }
    }
    const localizedParameterMerge =
      databaseRecord['localizedParameterMerge'] &&
      typeof databaseRecord['localizedParameterMerge'] === 'object' &&
      !Array.isArray(databaseRecord['localizedParameterMerge'])
        ? (databaseRecord['localizedParameterMerge'] as Record<string, unknown>)
        : null;
    if (localizedParameterMerge) {
      const targetPath =
        typeof localizedParameterMerge['targetPath'] === 'string'
          ? localizedParameterMerge['targetPath'].trim()
          : '';
      if (targetPath.length > 0 && targetPath !== 'parameters') {
        throw validationError(
          'AI Path config contains unsupported localized parameter merge target path.',
          {
            source: 'ai_paths.path_config',
            reason: 'unsupported_localized_parameter_merge_target_path',
            nodeId: node.id,
            targetPath,
          }
        );
      }
    }
    return {
      ...node,
      config: {
        ...configRecord,
        database: nextDatabaseConfig,
      },
    };
  });

  const identityIssues = validateCanonicalPathNodeIdentities(
    {
      ...contractBackfilled,
      nodes: sanitizedNodes,
    },
    { palette }
  );
  if (identityIssues.length > 0) {
    throw validationError('AI Path config contains unsupported node identities.', {
      source: 'ai_paths.path_config',
      reason: 'unsupported_node_identities',
      pathId: config.id,
      issues: identityIssues,
    });
  }

  const normalizedNodes = normalizeNodes(sanitizedNodes);
  const rawEdges = Array.isArray(contractBackfilled.edges) ? contractBackfilled.edges : [];
  assertNoUnsupportedTriggerDataGraph(normalizedNodes, rawEdges);
  const fallbackNodeTimestamp =
    typeof contractBackfilled.updatedAt === 'string' &&
    contractBackfilled.updatedAt.trim().length > 0
      ? contractBackfilled.updatedAt
      : new Date().toISOString();
  const graphNodes = normalizeNodes(normalizedNodes).map(
    (node: AiNode): AiNode => ({
      ...node,
      createdAt: resolveNodeCreatedAt(node.createdAt, fallbackNodeTimestamp),
      updatedAt: resolveNodeUpdatedAt(node.updatedAt),
    })
  );
  const normalizedEdges = sanitizeEdges(graphNodes, rawEdges);
  if (stableStringify(normalizedEdges) !== stableStringify(rawEdges)) {
    throw validationError('AI Path config contains invalid or non-canonical edges.', {
      source: 'ai_paths.path_config',
      reason: 'invalid_edges',
      pathId: config.id,
    });
  }

  const uiState = contractBackfilled.uiState ? { ...contractBackfilled.uiState } : undefined;
  if (uiState && 'configOpen' in uiState) {
    delete (uiState as { configOpen?: boolean }).configOpen;
  }

  return {
    ...contractBackfilled,
    nodes: graphNodes,
    edges: normalizedEdges,
    uiState,
    runtimeState: buildPersistedRuntimeState(
      parseRuntimeState(contractBackfilled.runtimeState),
      graphNodes
    ),
  };
};

export const sanitizePathConfigs = (
  configs: Record<string, PathConfig>
): Record<string, PathConfig> =>
  Object.fromEntries(
    Object.entries(configs).map(([key, value]: [string, PathConfig]) => [
      key,
      sanitizePathConfig(value),
    ])
  );

export const serializePathConfigs = (configs: Record<string, PathConfig>): string =>
  stableStringify(sanitizePathConfigs(configs));

import type { NodePortValueKind } from '@/shared/contracts/ai-paths';

import { isImageLikeValue } from './image';

export type PortDataType =
  | 'string'
  | 'number'
  | 'boolean'
  | 'object'
  | 'array'
  | 'image'
  | 'id'
  | 'json'
  | 'any';

const PORT_DATA_TYPES: Record<string, PortDataType | PortDataType[]> = {
  simulation: 'object',
  trigger: 'boolean',
  triggerName: 'string',
  context: ['object', 'image'],
  meta: 'object',
  entityJson: 'object',
  entityId: 'id',
  entityType: 'string',
  productId: 'id',
  title: 'string',
  images: 'image',
  description: 'string',
  description_en: 'string',
  content_en: 'string',
  content: 'string',
  textfield: 'string',
  analysis: 'string',
  prompt: 'string',
  aiPrompt: 'string',
  bundle: 'object',
  value: 'any',
  result: 'any',
  audioSignal: 'object',
  frequency: 'number',
  waveform: 'string',
  gain: 'number',
  durationMs: 'number',
  sources: 'array',
  valid: 'boolean',
  errors: 'array',
  query: ['object', 'string'],
  queryCallback: ['object', 'string'],
  aiQuery: ['object', 'string'],
  regexCallback: ['object', 'string'],
  schema: 'object',
  grouped: 'json',
  matches: 'array',
  callback: 'any',
  index: 'number',
  total: 'number',
  done: 'boolean',
  jobId: 'id',
  status: 'string',
};

const TYPE_LABELS: Record<PortDataType, string> = {
  string: 'string',
  number: 'number',
  boolean: 'boolean',
  object: 'object',
  array: 'array',
  image: 'image list (urls/blobs)',
  id: 'id (string/number)',
  json: 'json (object/array)',
  any: 'any',
};

export const expandTypes = (types: PortDataType[]): Set<string> => {
  const expanded = new Set<string>();
  types.forEach((type: PortDataType) => {
    if (type === 'any') {
      expanded.add('any');
      return;
    }
    if (type === 'id') {
      expanded.add('string');
      expanded.add('number');
      return;
    }
    if (type === 'json') {
      expanded.add('object');
      expanded.add('array');
      return;
    }
    if (type === 'image') {
      expanded.add('image');
      expanded.add('array');
      return;
    }
    expanded.add(type);
  });
  return expanded;
};

export const getPortDataTypes = (port: string): PortDataType[] => {
  const value = PORT_DATA_TYPES[port];
  if (!value) return ['any'];
  return Array.isArray(value) ? value : [value];
};

export const getPortDataTypesForValueKind = (kind: NodePortValueKind): PortDataType[] => {
  switch (kind) {
    case 'string':
      return ['string'];
    case 'number':
      return ['number'];
    case 'boolean':
      return ['boolean'];
    case 'json':
      return ['json'];
    case 'image_url':
      return ['image'];
    case 'bundle':
    case 'job_envelope':
      return ['object'];
    case 'unknown':
    default:
      return ['any'];
  }
};

export const formatPortDataTypes = (types: PortDataType[]): string => {
  if (types.includes('any')) return TYPE_LABELS.any;
  return types.map((type: PortDataType) => TYPE_LABELS[type]).join(' | ');
};

export const getValueTypeLabel = (value: unknown): string => {
  if (value === undefined) return 'undefined';
  if (value === null) return 'null';
  if (typeof value === 'string') return 'string';
  if (typeof value === 'object' && !Array.isArray(value)) {
    const record = value as Record<string, unknown>;
    const recordHintKeys = [
      'entityId',
      'entityType',
      'productId',
      'context',
      'entity',
      'product',
      'id',
      'sku',
      'name',
      'title',
      'createdAt',
      'updatedAt',
    ];
    const imageKeyPattern =
      /(image|img|photo|picture|media|gallery|url|src|file|path|thumb|preview)/i;
    const hasRecordHint = recordHintKeys.some((key: string) => key in record);
    const keys = Object.keys(record);
    const hasNonImageKey = keys.some((key: string) => !imageKeyPattern.test(key));
    if (hasRecordHint || (keys.length > 3 && hasNonImageKey)) {
      return 'object';
    }
  }
  if (isImageLikeValue(value)) return 'image';
  if (Array.isArray(value)) return 'array';
  if (typeof value === 'number') return 'number';
  if (typeof value === 'boolean') return 'boolean';
  if (typeof value === 'object') return 'object';
  return typeof value;
};

export const isValueCompatibleWithTypes = (
  value: unknown,
  expectedTypes: PortDataType[]
): boolean => {
  if (value === undefined || value === null) return true;
  if (expectedTypes.includes('any')) return true;
  const actualType = getValueTypeLabel(value);
  const expected = expandTypes(expectedTypes);
  if (expected.has('any')) return true;
  // URL-like strings remain string-typed, but image ports should still accept them.
  if (typeof value === 'string' && expected.has('image') && isImageLikeValue(value)) return true;
  if (actualType === 'image' && expected.has('array')) return true;
  return expected.has(actualType);
};

export const arePortTypesCompatible = (
  fromTypes: PortDataType[],
  toTypes: PortDataType[]
): boolean => {
  if (fromTypes.includes('any') || toTypes.includes('any')) return true;
  const fromExpanded = expandTypes(fromTypes);
  const toExpanded = expandTypes(toTypes);
  if (fromExpanded.has('any') || toExpanded.has('any')) return true;
  for (const type of fromExpanded) {
    if (toExpanded.has(type)) return true;
  }
  return false;
};

import type { DatabaseAction, DatabaseActionCategory } from '@/shared/contracts/ai-paths';
import type { AppProviderValue as DbActionProvider } from '@/shared/contracts/system';
import type { LabeledOptionDto } from '@/shared/contracts/ui/base';

export type DbActionProviderSelection = 'auto' | 'mongodb' | undefined;
export type { DbActionProvider };

export type ProviderActionOption = LabeledOptionDto<DatabaseAction>;

const ACTION_CATEGORY_BY_ACTION: Record<DatabaseAction, DatabaseActionCategory> = {
  insertOne: 'create',
  insertMany: 'create',
  find: 'read',
  findOne: 'read',
  countDocuments: 'read',
  distinct: 'read',
  aggregate: 'aggregate',
  updateOne: 'update',
  updateMany: 'update',
  replaceOne: 'update',
  findOneAndUpdate: 'update',
  deleteOne: 'delete',
  deleteMany: 'delete',
  findOneAndDelete: 'delete',
};

const CATEGORY_OPTIONS: LabeledOptionDto<DatabaseActionCategory>[] = [
  { value: 'create', label: 'Create' },
  { value: 'read', label: 'Read' },
  { value: 'update', label: 'Update' },
  { value: 'delete', label: 'Delete' },
  { value: 'aggregate', label: 'Aggregate' },
];

const ACTION_OPTIONS_BY_CATEGORY: Record<DatabaseActionCategory, ProviderActionOption[]> = {
  create: [
    { value: 'insertOne', label: 'insertOne' },
    { value: 'insertMany', label: 'insertMany' },
  ],
  read: [
    { value: 'find', label: 'find' },
    { value: 'findOne', label: 'findOne' },
    { value: 'countDocuments', label: 'countDocuments' },
    { value: 'distinct', label: 'distinct' },
  ],
  update: [
    { value: 'updateOne', label: 'updateOne' },
    { value: 'updateMany', label: 'updateMany' },
    { value: 'replaceOne', label: 'replaceOne' },
    { value: 'findOneAndUpdate', label: 'findOneAndUpdate' },
  ],
  delete: [
    { value: 'deleteOne', label: 'deleteOne' },
    { value: 'deleteMany', label: 'deleteMany' },
    { value: 'findOneAndDelete', label: 'findOneAndDelete' },
  ],
  aggregate: [{ value: 'aggregate', label: 'aggregate' }],
};

export const resolveDbActionProvider = (
  requestedProvider: DbActionProviderSelection,
  fallbackProvider: DbActionProvider
): DbActionProvider =>
  requestedProvider === 'mongodb' ? requestedProvider : fallbackProvider;

export const getActionCategoryForAction = (action: DatabaseAction): DatabaseActionCategory =>
  ACTION_CATEGORY_BY_ACTION[action];

export const isProviderActionCategorySupported = (
  _provider: DbActionProvider,
  category: DatabaseActionCategory
): boolean => CATEGORY_OPTIONS.some((option) => option.value === category);

export const getProviderActionCategoryOptions = (
  _provider: DbActionProvider
): LabeledOptionDto<DatabaseActionCategory>[] => CATEGORY_OPTIONS;

export const getProviderActionOptions = (
  _provider: DbActionProvider,
  category: DatabaseActionCategory
): ProviderActionOption[] => ACTION_OPTIONS_BY_CATEGORY[category] ?? [];

export const isProviderActionSupported = (
  provider: DbActionProvider,
  action: DatabaseAction
): boolean => {
  const category = getActionCategoryForAction(action);
  return getProviderActionOptions(provider, category).some((option) => option.value === action);
};

export const getProviderSpecificActionLabel = (
  provider: DbActionProvider,
  action: DatabaseAction
): string => {
  const category = getActionCategoryForAction(action);
  const option = getProviderActionOptions(provider, category).find(
    (candidate) => candidate.value === action
  );
  return option?.label ?? action;
};

export const getUnsupportedProviderActionMessage = (
  provider: DbActionProvider,
  action: DatabaseAction
): string | null => {
  if (isProviderActionSupported(provider, action)) return null;
  return `MongoDB provider does not support "${action}" in this node.`;
};

export const getDefaultProviderAction = (
  provider: DbActionProvider,
  category: DatabaseActionCategory,
  single = false
): DatabaseAction => {
  const options = getProviderActionOptions(provider, category);
  if (category === 'read' && single) {
    const singleOption = options.find((option) => option.value === 'findOne');
    if (singleOption) return singleOption.value;
  }
  return options[0]?.value ?? 'find';
};

export const resolveProviderAction = (
  provider: DbActionProvider,
  category: DatabaseActionCategory,
  preferredAction: DatabaseAction | null | undefined,
  single = false
): DatabaseAction => {
  if (
    preferredAction &&
    getActionCategoryForAction(preferredAction) === category &&
    isProviderActionSupported(provider, preferredAction)
  ) {
    return preferredAction;
  }
  return getDefaultProviderAction(provider, category, single);
};

import type {
  RunPreflightBlockReason,
  RunPreflightWarning,
  RunPreflightReport,
  EvaluateRunPreflightArgs,
} from '@/shared/contracts/ai-paths';

import { evaluateDataContractPreflight } from './data-contract-preflight';
import { inspectPathDependencies } from './dependency-inspector';
import { compileGraph } from './graph';
import { normalizeAiPathsValidationConfig } from '../validation-engine/defaults';
import { evaluateAiPathsValidationPreflight } from '../validation-engine/evaluator';

export type {
  RunPreflightBlockReason,
  RunPreflightWarning,
  RunPreflightReport,
  EvaluateRunPreflightArgs,
};

export const evaluateRunPreflight = (args: EvaluateRunPreflightArgs): RunPreflightReport => {
  const validationConfig = normalizeAiPathsValidationConfig(args.aiPathsValidation);
  const nodeValidationEnabled = validationConfig.enabled !== false;
  const strictFlowMode = args.strictFlowMode !== false;
  const scopeMode = nodeValidationEnabled ? 'full' : 'reachable_from_roots';
  const scopeRootNodeIds =
    !nodeValidationEnabled && args.triggerNodeId ? [args.triggerNodeId] : undefined;

  const validationReport = evaluateAiPathsValidationPreflight({
    nodes: args.nodes,
    edges: args.edges,
    config: validationConfig,
  });

  const compileReport = nodeValidationEnabled
    ? compileGraph(args.nodes, args.edges)
    : compileGraph(args.nodes, args.edges, {
      scopeMode,
      ...(scopeRootNodeIds ? { scopeRootNodeIds } : {}),
    });

  const dependencyReport = strictFlowMode
    ? inspectPathDependencies(args.nodes, args.edges, {
      scopeMode,
      ...(scopeRootNodeIds ? { scopeRootNodeIds } : {}),
    })
    : null;

  const dataContractReport = evaluateDataContractPreflight({
    nodes: args.nodes,
    edges: args.edges,
    runtimeState: args.runtimeState,
    parserSamples: args.parserSamples,
    updaterSamples: args.updaterSamples,
    mode: args.mode ?? 'full',
    scopeMode,
    ...(scopeRootNodeIds ? { scopeRootNodeIds } : {}),
  });

  let shouldBlock = false;
  let blockReason: RunPreflightBlockReason = null;
  let blockMessage: string | null = null;

  if (nodeValidationEnabled && validationReport.blocked) {
    shouldBlock = true;
    blockReason = 'validation';
    const primaryFinding = validationReport.findings[0];
    blockMessage = primaryFinding
      ? `Validation blocked run: ${primaryFinding.ruleTitle}.`
      : `Validation blocked run: score ${validationReport.score} below threshold ${validationReport.blockThreshold}.`;
  }

  if (!shouldBlock && nodeValidationEnabled && !compileReport.ok) {
    shouldBlock = true;
    blockReason = 'compile';
    const primaryError = compileReport.findings.find(
      (finding): boolean => finding.severity === 'error'
    );
    blockMessage =
      primaryError?.message ??
      `Graph compile blocked run: ${compileReport.errors} issue(s) require fixes.`;
  }

  if (
    !shouldBlock &&
    nodeValidationEnabled &&
    strictFlowMode &&
    dependencyReport &&
    dependencyReport.errors > 0
  ) {
    shouldBlock = true;
    blockReason = 'dependency';
    blockMessage = `Strict flow blocked run: ${dependencyReport.errors} dependency error(s) detected.`;
  }

  if (!shouldBlock && nodeValidationEnabled && dataContractReport.errors > 0) {
    shouldBlock = true;
    blockReason = 'data_contract';
    const firstErrorIssue = dataContractReport.issues.find((issue) => issue.severity === 'error');
    blockMessage =
      firstErrorIssue?.message ??
      `Data contract preflight blocked run: ${dataContractReport.errors} issue(s) detected.`;
  }

  const warnings: RunPreflightWarning[] = [];

  if (validationReport.enabled && validationReport.shouldWarn) {
    warnings.push({
      source: 'validation',
      code: 'validation_warning',
      message: `Validation warning: score ${validationReport.score} with ${validationReport.failedRules} failed rule(s).`,
    });
  }

  if (compileReport.warnings > 0) {
    warnings.push({
      source: 'compile',
      code: 'compile_warning',
      message: `Graph compile reported ${compileReport.warnings} warning(s).`,
    });
  }

  if (!nodeValidationEnabled && compileReport.errors > 0) {
    warnings.push({
      source: 'compile',
      code: 'compile_errors_non_blocking',
      message: `Node Validation is disabled: ${compileReport.errors} compile error(s) are non-blocking for this run scope.`,
    });
  }

  if (dependencyReport && dependencyReport.warnings > 0) {
    warnings.push({
      source: 'dependency',
      code: 'dependency_warning',
      message: `Dependency inspector reported ${dependencyReport.warnings} warning(s).`,
    });
  }

  if (!nodeValidationEnabled && dependencyReport && dependencyReport.errors > 0) {
    warnings.push({
      source: 'dependency',
      code: 'dependency_errors_non_blocking',
      message: `Node Validation is disabled: ${dependencyReport.errors} strict-flow dependency error(s) are non-blocking for this run scope.`,
    });
  }

  if (dataContractReport.warnings > 0) {
    warnings.push({
      source: 'data_contract',
      code: 'data_contract_warning',
      message: `Data contract preflight reported ${dataContractReport.warnings} warning(s).`,
    });
  }

  if (!nodeValidationEnabled && dataContractReport.errors > 0) {
    warnings.push({
      source: 'data_contract',
      code: 'data_contract_errors_non_blocking',
      message: `Node Validation is disabled: ${dataContractReport.errors} data contract error(s) are non-blocking for this run scope.`,
    });
  }

  return {
    nodeValidationEnabled,
    shouldBlock,
    blockReason,
    blockMessage,
    validationReport,
    compileReport,
    dependencyReport,
    dataContractReport,
    warnings,
  };
};

import type { RuntimeState } from '@/shared/contracts/ai-paths';
import {
  parserSampleStateSchema,
  type ParserSampleState,
  updaterSampleStateSchema,
  type UpdaterSampleState,
} from '@/shared/contracts/ai-paths-core/nodes';
import { runtimeStateSchema } from '@/shared/contracts/ai-paths-runtime';
import { isAppError, validationError } from '@/shared/errors/app-error';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

export const EMPTY_RUNTIME_STATE: RuntimeState = {
  status: 'idle',
  nodeStatuses: {},
  nodeOutputs: {},
  variables: {},
  events: [],
  currentRun: null,
  inputs: {},
  outputs: {},
};

const assertNoUnsupportedRunIdentity = (
  record: Record<string, unknown>,
  location: string
): void => {
  const unsupportedKeys = ['runId', 'runStartedAt'].filter((key: string): boolean => key in record);
  if (unsupportedKeys.length === 0) return;
  throw validationError('AI Paths runtime state payload includes unsupported identity fields.', {
    reason: 'unsupported_runtime_identity_fields',
    keys: unsupportedKeys,
    location,
  });
};

const assertNoUnsupportedRuntimeIdentityFields = (parsed: Record<string, unknown>): void => {
  assertNoUnsupportedRunIdentity(parsed, 'runtime_state');

  const events = parsed['events'];
  if (Array.isArray(events)) {
    events.forEach((entry: unknown, index: number): void => {
      if (!entry || typeof entry !== 'object' || Array.isArray(entry)) return;
      assertNoUnsupportedRunIdentity(entry as Record<string, unknown>, `events[${index}]`);
    });
  }

  const history = parsed['history'];
  if (!history || typeof history !== 'object' || Array.isArray(history)) return;
  Object.entries(history as Record<string, unknown>).forEach(
    ([nodeId, entries]: [string, unknown]): void => {
      if (!Array.isArray(entries)) return;
      entries.forEach((entry: unknown, index: number): void => {
        if (!entry || typeof entry !== 'object' || Array.isArray(entry)) return;
        assertNoUnsupportedRunIdentity(
          entry as Record<string, unknown>,
          `history.${nodeId}[${index}]`
        );
      });
    }
  );
};

const pruneNonCanonicalRuntimeHistoryStrategy = (parsed: Record<string, unknown>): void => {
  const history = parsed['history'];
  if (!history || typeof history !== 'object' || Array.isArray(history)) return;

  Object.values(history as Record<string, unknown>).forEach((entries: unknown): void => {
    if (!Array.isArray(entries)) return;
    entries.forEach((entry: unknown): void => {
      if (!entry || typeof entry !== 'object' || Array.isArray(entry)) return;
      const record = entry as Record<string, unknown>;
      if (record['runtimeStrategy'] !== 'code_object_v3') {
        delete record['runtimeStrategy'];
      }
    });
  });
};

const normalizeParsedRuntimeState = (parsed: Record<string, unknown>): RuntimeState => {
  assertNoUnsupportedRuntimeIdentityFields(parsed);
  pruneNonCanonicalRuntimeHistoryStrategy(parsed);
  const merged = {
    ...EMPTY_RUNTIME_STATE,
    ...parsed,
  };
  const validated = runtimeStateSchema.safeParse(merged);
  if (!validated.success) {
    throw validationError('Invalid AI Paths runtime state payload.', {
      reason: 'schema_validation_failed',
      issues: validated.error.flatten(),
    });
  }
  return validated.data as RuntimeState;
};

export const parseRuntimeState = (value: unknown): RuntimeState => {
  if (!value) return EMPTY_RUNTIME_STATE;

  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value) as unknown;
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return normalizeParsedRuntimeState(parsed as Record<string, unknown>);
      }
      throw validationError('Invalid AI Paths runtime state payload.', {
        reason: 'invalid_shape',
      });
    } catch (error) {
      logClientError(error);
      if (isAppError(error)) {
        throw error;
      }
      throw validationError('Invalid AI Paths runtime state payload.', {
        reason: 'json_parse_failed',
        cause: error instanceof Error ? error.message : String(error),
      });
    }
  }

  if (typeof value === 'object' && !Array.isArray(value)) {
    return normalizeParsedRuntimeState(value as Record<string, unknown>);
  }

  throw validationError('Invalid AI Paths runtime state payload.', {
    reason: 'invalid_shape',
  });
};

const normalizeSampleRecord = <TSample>(
  value: unknown,
  parseSample: (sample: unknown) => TSample | null
): Record<string, TSample> => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return {};
  }

  const normalized: Record<string, TSample> = {};
  Object.entries(value as Record<string, unknown>).forEach(([key, sampleValue]) => {
    const normalizedKey = key.trim();
    if (!normalizedKey) return;
    const parsed = parseSample(sampleValue);
    if (!parsed) return;
    normalized[normalizedKey] = parsed;
  });
  return normalized;
};

export const normalizeParserSamples = (value: unknown): Record<string, ParserSampleState> =>
  normalizeSampleRecord(value, (sample: unknown): ParserSampleState | null => {
    const parsed = parserSampleStateSchema.safeParse(sample);
    return parsed.success ? parsed.data : null;
  });

export const normalizeUpdaterSamples = (value: unknown): Record<string, UpdaterSampleState> =>
  normalizeSampleRecord(value, (sample: unknown): UpdaterSampleState | null => {
    const parsed = updaterSampleStateSchema.safeParse(sample);
    return parsed.success ? parsed.data : null;
  });

