import { reportObservabilityInternalError } from '@/shared/utils/observability/internal-observability-fallback';

const reportRuntimeUtilsError = (
  error: unknown,
  action: string,
  context?: Record<string, unknown>
): void => {
  reportObservabilityInternalError(error, {
    source: 'ai-paths.core.runtime-utils',
    action,
    ...(context ?? {}),
  });
};

export const toNumber = (value: string, fallback: number): number => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const stringifyComplexObject = (value: object): string => {
  try {
    return JSON.stringify(value);
  } catch (error) {
    reportRuntimeUtilsError(error, 'safeStringify', {
      valueType: typeof value,
    });
    return '[Complex Object]';
  }
};

const stringifyNonObjectRuntimeValue = (value: unknown): string => {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (typeof value === 'symbol' || typeof value === 'function') {
    return value.toString();
  }
  return String(value as string);
};

export function safeStringify(value: unknown): string {
  if (value === undefined || value === null) return '';
  if (typeof value === 'object') return stringifyComplexObject(value);
  return stringifyNonObjectRuntimeValue(value);
}

const normalizeForJsonClone = (value: unknown): unknown => {
  const ancestors: object[] = [];
  const replacer = function (this: unknown, _key: string, val: unknown): unknown {
    if (typeof val === 'bigint') return val.toString();
    if (val instanceof Date) return val.toISOString();
    if (val instanceof Set) return Array.from(val.values()) as unknown[];
    if (val instanceof Map) return Object.fromEntries(val.entries()) as Record<string, unknown>;
    if (typeof val === 'function' || typeof val === 'symbol') return undefined;
    if (!val || typeof val !== 'object') return val;

    while (ancestors.length > 0 && ancestors[ancestors.length - 1] !== this) {
      ancestors.pop();
    }
    if (ancestors.includes(val)) return undefined;
    ancestors.push(val);
    return val;
  };

  return JSON.parse(JSON.stringify(value, replacer)) as unknown;
};

export const cloneJsonSafe = <T>(value: T): T | null => {
  try {
    return normalizeForJsonClone(value) as T;
  } catch (error) {
    reportRuntimeUtilsError(error, 'cloneJsonSafe');
    return null;
  }
};

export const safeJsonStringify = (value: unknown): string => {
  try {
    return JSON.stringify(normalizeForJsonClone(value)) ?? '';
  } catch (error) {
    reportRuntimeUtilsError(error, 'safeJsonStringify');
    return '';
  }
};

const NON_PRIMITIVE_HASH_VALUE = Symbol('non-primitive-hash-value');

const normalizePrimitiveForHash = (value: unknown): unknown | typeof NON_PRIMITIVE_HASH_VALUE => {
  if (value === undefined) return undefined;
  if (value === null) return null;
  if (typeof value === 'string' || typeof value === 'boolean') return value;
  if (typeof value === 'number') {
    return Number.isFinite(value) ? value : String(value);
  }
  if (typeof value === 'bigint') return value.toString();
  if (typeof value === 'symbol' || typeof value === 'function') {
    return `[${typeof value}]`;
  }
  return NON_PRIMITIVE_HASH_VALUE;
};

const normalizeHashArrayEntry = (value: unknown, seen: WeakSet<object>): unknown => {
  const normalized = normalizeForHash(value, seen);
  return normalized === undefined ? null : normalized;
};

const normalizeArrayForHash = (value: readonly unknown[], seen: WeakSet<object>): unknown[] =>
  value.map((item: unknown) => normalizeHashArrayEntry(item, seen));

const normalizeMapKeyForHash = (key: unknown): string => {
  const normalizedKey = normalizeForHash(key, new WeakSet<object>());
  return typeof key === 'string' ? key : (JSON.stringify(normalizedKey) ?? String(key));
};

const normalizeMapForHash = (
  value: Map<unknown, unknown>,
  seen: WeakSet<object>
): [string, unknown][] => {
  const entries = Array.from(value.entries()).map(
    ([key, val]: [unknown, unknown]): [string, unknown] => [
      normalizeMapKeyForHash(key),
      normalizeForHash(val, seen),
    ]
  );
  entries.sort((a: [string, unknown], b: [string, unknown]) => a[0].localeCompare(b[0]));
  return entries;
};

const normalizeSetForHash = (value: Set<unknown>, seen: WeakSet<object>): unknown[] => {
  const keyedEntries = Array.from(value.values()).map((item: unknown) => {
    const normalized = normalizeForHash(item, seen) ?? null;
    return {
      key: JSON.stringify(normalized),
      value: normalized,
    };
  });
  keyedEntries.sort((a: { key: string }, b: { key: string }) => a.key.localeCompare(b.key));
  return keyedEntries.map((item: { value: unknown }) => item.value);
};

const normalizeObjectForHash = (
  value: Record<string, unknown>,
  seen: WeakSet<object>
): Record<string, unknown> | '[Circular]' => {
  if (seen.has(value)) return '[Circular]';
  seen.add(value);
  const normalized: Record<string, unknown> = {};
  Object.keys(value)
    .sort()
    .forEach((key: string): void => {
      const next = normalizeForHash(value[key], seen);
      if (next !== undefined) normalized[key] = next;
    });
  return normalized;
};

const normalizeForHash = (value: unknown, seen: WeakSet<object>): unknown => {
  const primitive = normalizePrimitiveForHash(value);
  if (primitive !== NON_PRIMITIVE_HASH_VALUE) return primitive;
  if (value instanceof Date) return value.toISOString();
  if (Array.isArray(value)) return normalizeArrayForHash(value, seen);
  if (value instanceof Map) return normalizeMapForHash(value, seen);
  if (value instanceof Set) return normalizeSetForHash(value, seen);
  if (value && typeof value === 'object') {
    return normalizeObjectForHash(value as Record<string, unknown>, seen);
  }
  return primitive;
};

export const stableStringify = (value: unknown): string => {
  try {
    const normalized = normalizeForHash(value, new WeakSet<object>());
    if (normalized === undefined) return '';
    return JSON.stringify(normalized) ?? '';
  } catch (error) {
    reportRuntimeUtilsError(error, 'stableStringify');
    return '';
  }
};

export const hashString = (value: string): string => {
  let hash = 2166136261;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(16).padStart(8, '0');
};

export const hashRuntimeValue = (value: unknown): string => hashString(stableStringify(value));

export const formatRuntimeValue = (value: unknown): string => {
  if (value === null || value === undefined) return '—';
  if (typeof value === 'string') return value.trim() || '—';
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  try {
    const json = JSON.stringify(value, null, 2);
    if (json.length > 400) return `${json.slice(0, 400)}…`;
    return json;
  } catch (error) {
    reportRuntimeUtilsError(error, 'formatRuntimeValue');
    return '[Complex Object]';
  }
};

export const parsePathList = (value: string): string[] =>
  value
    .split('\n')
    .map((line: string) => line.trim())
    .filter(Boolean);

export const safeParseJson = <T = unknown>(value: string): { value: T; error: string } => {
  if (!value.trim()) return { value: null as T, error: '' };
  try {
    return { value: JSON.parse(value) as T, error: '' };
  } catch (error) {
    reportRuntimeUtilsError(error, 'safeParseJson', {
      valueLength: value.length,
    });
    return { value: null as T, error: 'Invalid JSON' };
  }
};

export const cloneValue = <T>(value: T): T => {
  if (typeof structuredClone === 'function') {
    return structuredClone(value);
  }
  try {
    return JSON.parse(JSON.stringify(value)) as T;
  } catch (error) {
    reportRuntimeUtilsError(error, 'cloneValue');
    return value;
  }
};

export const parseJsonSafe = (value: string): unknown => {
  if (!value.trim()) return undefined;
  try {
    return JSON.parse(value) as unknown;
  } catch (error) {
    reportRuntimeUtilsError(error, 'parseJsonSafe', {
      valueLength: value.length,
    });
    return undefined;
  }
};

export const coerceInput = <T>(value: T | T[] | undefined): T | undefined =>
  Array.isArray(value) ? value[0] : value;

export const coerceInputArray = <T>(value: T | T[] | undefined): T[] =>
  Array.isArray(value) ? value : value === undefined ? [] : [value];

export const appendInputValue = (current: unknown, value: unknown): unknown => {
  if (current === undefined) return value;
  if (Array.isArray(current)) return [...(current as unknown[]), value];
  return [current, value];
};

import { pathConfigSchema, type PathConfig } from '@/shared/contracts/ai-paths';
import { validationError } from '@/shared/errors/app-error';

import { sanitizePathConfig } from './path-config-sanitization';
import { stableStringify } from './runtime';

const throwInvalidStoredPathConfig = (args: {
  pathId: string;
  reason: string;
  cause?: string | null | undefined;
}): never => {
  throw validationError('Invalid AI Path config payload.', {
    source: 'ai_paths.path_config',
    pathId: args.pathId,
    reason: args.reason,
    ...(args.cause ? { cause: args.cause } : {}),
  });
};

export type LoadedStoredPathConfig = {
  config: PathConfig;
  changed: boolean;
};

export const loadStoredPathConfig = (args: {
  pathId: string;
  rawConfig: string;
}): LoadedStoredPathConfig => {
  let parsedConfig: unknown;
  try {
    parsedConfig = JSON.parse(args.rawConfig) as unknown;
  } catch (error) {
    throwInvalidStoredPathConfig({
      pathId: args.pathId,
      reason: 'config_invalid_json',
      cause: error instanceof Error ? error.message : 'unknown_error',
    });
  }

  const parsedPathConfigResult = pathConfigSchema.safeParse(parsedConfig);
  if (!parsedPathConfigResult.success) {
    throwInvalidStoredPathConfig({
      pathId: args.pathId,
      reason: 'config_invalid_payload',
      cause: parsedPathConfigResult.error.message,
    });
  }
  const parsedPathConfig = parsedPathConfigResult.data;
  if (!parsedPathConfig) {
    throwInvalidStoredPathConfig({
      pathId: args.pathId,
      reason: 'config_invalid_payload',
      cause: 'parsed_path_config_missing',
    });
  }

  const sanitizedConfig = sanitizePathConfig(parsedPathConfig!);
  const normalizedId =
    typeof sanitizedConfig.id === 'string' ? sanitizedConfig.id.trim() : '';
  if (!normalizedId || normalizedId !== args.pathId) {
    throw validationError('AI Path config id does not match stored path id.', {
      source: 'ai_paths.path_config',
      pathId: args.pathId,
      reason: 'config_id_mismatch',
      actualPathId: normalizedId || null,
    });
  }

  const normalizedName =
    typeof sanitizedConfig.name === 'string' ? sanitizedConfig.name.trim() : '';
  if (!normalizedName) {
    throw validationError('AI Path config name is required.', {
      source: 'ai_paths.path_config',
      pathId: args.pathId,
      reason: 'missing_path_name',
    });
  }

  return {
    config: sanitizedConfig,
    changed: stableStringify(parsedConfig) !== stableStringify(sanitizedConfig),
  };
};

export const loadCanonicalStoredPathConfig = (args: {
  pathId: string;
  rawConfig: string;
}): PathConfig => {
  const resolved = loadStoredPathConfig(args);
  if (resolved.changed) {
    throw validationError('AI Path config contains non-canonical persisted values.', {
      source: 'ai_paths.path_config',
      pathId: args.pathId,
      reason: 'non_canonical_persisted_values',
    });
  }

  return resolved.config;
};

import { getValueAtMappingPath } from './json';
import { safeStringify } from './runtime';

const resolveTemplateTokenValue = (
  key: string,
  context: Record<string, unknown>,
  currentValue: unknown
): unknown => {
  if (key === 'value' || key === 'current') {
    return currentValue;
  }
  if (key.startsWith('current.')) {
    return getValueAtMappingPath(currentValue, key.slice('current.'.length));
  }
  if (key.startsWith('value.')) {
    const resolvedFromContext = getValueAtMappingPath(context, key);
    if (resolvedFromContext !== undefined) {
      return resolvedFromContext;
    }
    return getValueAtMappingPath(currentValue, key.slice('value.'.length));
  }
  return getValueAtMappingPath(context, key);
};

export const renderTemplate = (
  template: string,
  context: Record<string, unknown>,
  currentValue: unknown
): string =>
  // Single-pass replacement prevents an inserted value (e.g. JSON arrays like `[{...}]`) from being
  // re-interpreted as another placeholder by a second `.replace()` call.
  //
  // Square-bracket placeholders are intentionally conservative so we don't accidentally treat
  // JSON arrays (or other bracketed text) as placeholders.
  template.replace(
    /{{\s*([^}]+)\s*}}|\[\s*([A-Za-z0-9_.$:-]+)\s*\]/g,
    (_match: string, curlyToken: string | undefined, bracketToken: string | undefined) => {
      const raw = curlyToken ?? bracketToken ?? '';
      const key = String(raw).trim();
      if (!key) return '';
      return safeStringify(resolveTemplateTokenValue(key, context, currentValue));
    }
  );

export const renderJsonTemplate = (
  template: string,
  context: Record<string, unknown>,
  currentValue: unknown
): string => {
  const resolveToken = (token: string): unknown =>
    resolveTemplateTokenValue(String(token).trim(), context, currentValue);
  const escapeQuoted = (input: string): string => {
    const replaceQuoted = (text: string, pattern: RegExp): string =>
      text.replace(pattern, (_match: string, token: string) => {
        const value: unknown = resolveToken(token);
        const asString: string =
          value === undefined || value === null
            ? ''
            : typeof value === 'string'
              ? value
              : JSON.stringify(value);
        return JSON.stringify(asString);
      });
    let next = replaceQuoted(input, /"{{\s*([^}]+)\s*}}"/g);
    next = replaceQuoted(next, /"\[\s*([^\]]+)\s*\]"/g);
    return next;
  };
  return renderTemplate(escapeQuoted(template), context, currentValue);
};

import type { PathConfig } from '@/shared/contracts/ai-paths';

import { triggers } from '../constants/segments/rendering';

export const LEGACY_AI_PATH_TRIGGER_LABEL = 'Product Modal - Context Grabber';
export const CANONICAL_AI_PATH_TRIGGER_LABEL = 'Product Modal - Context Filter';

const AI_PATH_TRIGGER_LABEL_RENAMES = new Map<string, string>([
  [LEGACY_AI_PATH_TRIGGER_LABEL, CANONICAL_AI_PATH_TRIGGER_LABEL],
]);

export const migrateAiPathTriggerLabel = (
  value: unknown
): {
  value: string | null;
  changed: boolean;
} => {
  const normalized = typeof value === 'string' ? value.trim() : '';
  if (normalized.length === 0) {
    return { value: null, changed: false };
  }

  const migrated = AI_PATH_TRIGGER_LABEL_RENAMES.get(normalized) ?? normalized;
  return {
    value: migrated,
    changed: migrated !== normalized,
  };
};

export const normalizeAiPathTriggerLabel = (value?: string | null): string =>
  migrateAiPathTriggerLabel(value).value ?? triggers[0] ?? CANONICAL_AI_PATH_TRIGGER_LABEL;

export const migrateAiPathConfigTriggerLabel = (
  config: PathConfig
): {
  config: PathConfig;
  changed: boolean;
} => {
  const migrated = migrateAiPathTriggerLabel(config.trigger);
  if (!migrated.changed || !migrated.value) {
    return { config, changed: false };
  }

  return {
    config: {
      ...config,
      trigger: migrated.value,
    },
    changed: true,
  };
};

import type {
  AiPathsValidationCondition,
  AiPathsValidationConfig,
  AiPathsValidationModule,
  AiPathsValidationRule,
  AiPathsValidationSeverity,
  AiPathsValidationStage,
} from '@/shared/contracts/ai-paths';

const VALIDATION_SEVERITIES: ReadonlySet<AiPathsValidationSeverity> =
  new Set<AiPathsValidationSeverity>(['error', 'warning', 'info']);

const VALIDATION_MODULES: ReadonlySet<AiPathsValidationModule> = new Set<AiPathsValidationModule>([
  'graph',
  'trigger',
  'simulation',
  'context',
  'parser',
  'database',
  'model',
  'poll',
  'router',
  'gate',
  'validation_pattern',
  'custom',
]);

const VALIDATION_STAGES: ReadonlySet<AiPathsValidationStage> = new Set<AiPathsValidationStage>([
  'graph_parse',
  'graph_bind',
  'node_pre_execute',
  'node_post_execute',
]);

const VALIDATION_RULE_INFERENCE_SOURCE_TYPES: ReadonlySet<string> = new Set([
  'manual',
  'central_docs',
]);

const VALIDATION_RULE_INFERENCE_STATUSES: ReadonlySet<string> = new Set([
  'candidate',
  'approved',
  'rejected',
  'deprecated',
]);

export const AI_PATHS_VALIDATION_SCHEMA_VERSION = 3;
export const DEFAULT_AI_PATHS_VALIDATION_SCHEMA_VERSION = AI_PATHS_VALIDATION_SCHEMA_VERSION;

const sanitizeStringArray = (value: unknown): string[] => {
  if (!Array.isArray(value)) return [];
  return Array.from(
    new Set(
      value
        .filter(
          (entry: unknown): entry is string => typeof entry === 'string' && entry.trim().length > 0
        )
        .map((entry: string): string => entry.trim())
    )
  );
};

const sanitizeCondition = (
  rawCondition: AiPathsValidationCondition,
  index: number
): AiPathsValidationCondition | null => {
  const id =
    typeof rawCondition.id === 'string' && rawCondition.id.trim().length > 0
      ? rawCondition.id.trim()
      : `condition_${index + 1}`;
  if (typeof rawCondition.operator !== 'string') {
    return null;
  }
  return {
    ...rawCondition,
    id,
  };
};

const sanitizeRuleInference = (
  value: AiPathsValidationRule['inference'] | null | undefined
): AiPathsValidationRule['inference'] | undefined => {
  if (!value || typeof value !== 'object') return undefined;
  const record = value as Record<string, unknown>;
  const sourceType =
    typeof record['sourceType'] === 'string' &&
    VALIDATION_RULE_INFERENCE_SOURCE_TYPES.has(record['sourceType'])
      ? (record['sourceType'] as NonNullable<AiPathsValidationRule['inference']>['sourceType'])
      : undefined;
  const status =
    typeof record['status'] === 'string' && VALIDATION_RULE_INFERENCE_STATUSES.has(record['status'])
      ? (record['status'] as NonNullable<AiPathsValidationRule['inference']>['status'])
      : undefined;
  const assertionId =
    typeof record['assertionId'] === 'string' && record['assertionId'].trim().length > 0
      ? record['assertionId'].trim()
      : undefined;
  const sourcePath =
    typeof record['sourcePath'] === 'string' && record['sourcePath'].trim().length > 0
      ? record['sourcePath'].trim()
      : undefined;
  const sourceHash =
    typeof record['sourceHash'] === 'string' && record['sourceHash'].trim().length > 0
      ? record['sourceHash'].trim()
      : undefined;
  const docsSnapshotHash =
    typeof record['docsSnapshotHash'] === 'string' && record['docsSnapshotHash'].trim().length > 0
      ? record['docsSnapshotHash'].trim()
      : undefined;
  const confidence =
    typeof record['confidence'] === 'number' && Number.isFinite(record['confidence'])
      ? Math.max(0, Math.min(1, record['confidence']))
      : undefined;
  const compilerVersion =
    typeof record['compilerVersion'] === 'string' && record['compilerVersion'].trim().length > 0
      ? record['compilerVersion'].trim()
      : undefined;
  const inferredAt =
    typeof record['inferredAt'] === 'string' && record['inferredAt'].trim().length > 0
      ? record['inferredAt'].trim()
      : undefined;
  const approvedAt =
    typeof record['approvedAt'] === 'string' && record['approvedAt'].trim().length > 0
      ? record['approvedAt'].trim()
      : undefined;
  const approvedBy =
    typeof record['approvedBy'] === 'string' && record['approvedBy'].trim().length > 0
      ? record['approvedBy'].trim()
      : undefined;
  const reviewNote =
    typeof record['reviewNote'] === 'string' && record['reviewNote'].trim().length > 0
      ? record['reviewNote'].trim()
      : undefined;
  const tags = sanitizeStringArray(record['tags']);
  const deprecates = sanitizeStringArray(record['deprecates']);

  const normalized: NonNullable<AiPathsValidationRule['inference']> = {
    ...(sourceType ? { sourceType } : {}),
    ...(status ? { status } : {}),
    ...(assertionId ? { assertionId } : {}),
    ...(sourcePath ? { sourcePath } : {}),
    ...(sourceHash ? { sourceHash } : {}),
    ...(docsSnapshotHash ? { docsSnapshotHash } : {}),
    ...(confidence !== undefined ? { confidence } : {}),
    ...(compilerVersion ? { compilerVersion } : {}),
    ...(inferredAt ? { inferredAt } : {}),
    ...(approvedAt ? { approvedAt } : {}),
    ...(approvedBy ? { approvedBy } : {}),
    ...(reviewNote ? { reviewNote } : {}),
    ...(tags.length > 0 ? { tags } : {}),
    ...(deprecates.length > 0 ? { deprecates } : {}),
  };
  return Object.keys(normalized).length > 0 ? normalized : undefined;
};

const sanitizeRule = (
  rawRule: AiPathsValidationRule,
  index: number
): AiPathsValidationRule | null => {
  const id =
    typeof rawRule.id === 'string' && rawRule.id.trim().length > 0 ? rawRule.id.trim() : '';
  const title =
    typeof rawRule.title === 'string' && rawRule.title.trim().length > 0
      ? rawRule.title.trim()
      : '';
  if (!id || !title) return null;

  const module = VALIDATION_MODULES.has(rawRule.module) ? rawRule.module : 'custom';
  const severity = VALIDATION_SEVERITIES.has(rawRule.severity) ? rawRule.severity : 'warning';
  const sequence =
    typeof rawRule.sequence === 'number' && Number.isFinite(rawRule.sequence)
      ? Math.trunc(rawRule.sequence)
      : (index + 1) * 10;
  const conditions = Array.isArray(rawRule.conditions)
    ? rawRule.conditions
      .map((condition: AiPathsValidationCondition, conditionIndex: number) =>
        sanitizeCondition(condition, conditionIndex)
      )
      .filter(
        (condition: AiPathsValidationCondition | null): condition is AiPathsValidationCondition =>
          Boolean(condition)
      )
    : [];

  if (conditions.length === 0) return null;

  const appliesToNodeTypes = sanitizeStringArray(rawRule.appliesToNodeTypes);
  const appliesToStages = sanitizeStringArray(rawRule.appliesToStages).filter(
    (stage): stage is AiPathsValidationStage =>
      VALIDATION_STAGES.has(stage as AiPathsValidationStage)
  );
  const docsBindings = sanitizeStringArray(rawRule.docsBindings);
  const inference = sanitizeRuleInference(rawRule.inference);

  return {
    ...rawRule,
    id,
    title,
    enabled: rawRule.enabled !== false,
    module,
    severity,
    sequence,
    conditionMode: rawRule.conditionMode === 'any' ? 'any' : 'all',
    appliesToNodeTypes: appliesToNodeTypes.length > 0 ? appliesToNodeTypes : undefined,
    appliesToStages: appliesToStages.length > 0 ? appliesToStages : undefined,
    docsBindings: docsBindings.length > 0 ? docsBindings : undefined,
    ...(inference ? { inference } : {}),
    conditions,
  };
};

const dedupeRuleIds = (rules: AiPathsValidationRule[]): AiPathsValidationRule[] => {
  const seen = new Set<string>();
  return rules.filter((rule: AiPathsValidationRule): boolean => {
    const id = (rule.id ?? '').trim();
    if (!id || seen.has(id)) return false;
    seen.add(id);
    return true;
  });
};

const sanitizeRules = (rules: AiPathsValidationRule[]): AiPathsValidationRule[] =>
  dedupeRuleIds(
    rules
      .map((rule: AiPathsValidationRule, index: number) => sanitizeRule(rule, index))
      .filter((rule: AiPathsValidationRule | null): rule is AiPathsValidationRule => Boolean(rule))
  );

const DATABASE_WRITE_EXPLICIT_IDENTITY_PORTS = [
  'id',
  'entityId',
  'productId',
  'value',
  'context',
  'bundle',
  'meta',
];

const DATABASE_WRITE_EXPLICIT_IDENTITY_CONDITION_IDS: Record<string, string> = {
  bundle: 'database-write-has-incoming-bundle-port',
  context: 'database-write-has-incoming-context-port',
  entityId: 'database-write-has-incoming-entity-id-port',
  id: 'database-write-has-incoming-record-id-port',
  meta: 'database-write-has-incoming-meta-port',
  productId: 'database-write-has-incoming-product-id-port',
  value: 'database-write-has-incoming-value-port',
};

const normalizeDatabaseWriteIdentityCondition = (
  condition: AiPathsValidationCondition
): AiPathsValidationCondition => {
  if (
    condition.operator !== 'has_incoming_port' ||
    typeof condition.port !== 'string' ||
    condition.port.trim().length === 0
  ) {
    return condition;
  }
  const normalizedPort = condition.port.trim();
  const normalizedId = DATABASE_WRITE_EXPLICIT_IDENTITY_CONDITION_IDS[normalizedPort];
  return normalizedId
    ? {
        ...condition,
        id: normalizedId,
        port: normalizedPort,
      }
    : condition;
};

const dedupeDatabaseWriteIdentityConditions = (
  conditions: AiPathsValidationCondition[]
): AiPathsValidationCondition[] => {
  const seenIncomingPorts = new Set<string>();
  return conditions.filter((condition: AiPathsValidationCondition): boolean => {
    if (
      condition.operator !== 'has_incoming_port' ||
      typeof condition.port !== 'string' ||
      condition.port.trim().length === 0
    ) {
      return true;
    }
    const normalizedPort = condition.port.trim();
    if (seenIncomingPorts.has(normalizedPort)) return false;
    seenIncomingPorts.add(normalizedPort);
    return true;
  });
};

const upgradeDatabaseWriteIdentityRule = (
  rule: AiPathsValidationRule
): AiPathsValidationRule => {
  if (rule.id !== 'database.update.identity_wired') return rule;
  const existingConditions = (rule.conditions ?? []).map(normalizeDatabaseWriteIdentityCondition);
  const existingIncomingPorts = new Set(
    existingConditions
      .filter(
        (condition: AiPathsValidationCondition): boolean =>
          condition.operator === 'has_incoming_port' &&
          typeof condition.port === 'string' &&
          condition.port.trim().length > 0
      )
      .map((condition: AiPathsValidationCondition): string => condition.port?.trim() ?? '')
  );
  const missingIncomingPortConditions = DATABASE_WRITE_EXPLICIT_IDENTITY_PORTS.filter(
    (port: string): boolean => !existingIncomingPorts.has(port)
  ).map(
    (port: string): AiPathsValidationCondition => ({
      id:
        DATABASE_WRITE_EXPLICIT_IDENTITY_CONDITION_IDS[port] ??
        `database-write-has-incoming-${port.toLowerCase()}-port`,
      operator: 'has_incoming_port',
      port,
    })
  );
  if (missingIncomingPortConditions.length === 0) return rule;
  return {
    ...rule,
    conditions: dedupeDatabaseWriteIdentityConditions([
      ...existingConditions,
      ...missingIncomingPortConditions,
    ]),
    severity: 'warning',
    weight: 0,
    recommendation:
      'Wire Parser/Context output into Database.id, entityId, productId, value, context, bundle, or meta for deterministic writes.',
  };
};

const upgradePersistedValidationRules = (
  rules: AiPathsValidationRule[]
): AiPathsValidationRule[] => rules.map(upgradeDatabaseWriteIdentityRule);

export const normalizeAiPathsValidationRules = (
  rules: AiPathsValidationRule[] | null | undefined
): AiPathsValidationRule[] =>
  Array.isArray(rules) && rules.length > 0
    ? upgradePersistedValidationRules(sanitizeRules(rules))
    : [];

const sanitizeDocsSyncState = (
  value: AiPathsValidationConfig['docsSyncState'] | null | undefined
): AiPathsValidationConfig['docsSyncState'] => {
  if (!value || typeof value !== 'object') {
    return {
      lastSyncStatus: 'idle',
      lastSyncWarnings: [],
      sourceCount: 0,
      candidateCount: 0,
    };
  }
  const record = value as Record<string, unknown>;
  const lastSnapshotHash =
    typeof record['lastSnapshotHash'] === 'string' && record['lastSnapshotHash'].trim().length > 0
      ? record['lastSnapshotHash'].trim()
      : undefined;
  const lastSyncedAt =
    typeof record['lastSyncedAt'] === 'string' && record['lastSyncedAt'].trim().length > 0
      ? record['lastSyncedAt'].trim()
      : undefined;
  const lastSyncStatus =
    record['lastSyncStatus'] === 'success' ||
    record['lastSyncStatus'] === 'warning' ||
    record['lastSyncStatus'] === 'error' ||
    record['lastSyncStatus'] === 'idle'
      ? (record['lastSyncStatus'] as NonNullable<
          AiPathsValidationConfig['docsSyncState']
        >['lastSyncStatus'])
      : 'idle';
  const sourceCount =
    typeof record['sourceCount'] === 'number' && Number.isFinite(record['sourceCount'])
      ? Math.max(0, Math.trunc(record['sourceCount']))
      : 0;
  const candidateCount =
    typeof record['candidateCount'] === 'number' && Number.isFinite(record['candidateCount'])
      ? Math.max(0, Math.trunc(record['candidateCount']))
      : 0;
  const lastSyncWarnings = sanitizeStringArray(record['lastSyncWarnings']);
  return {
    ...(lastSnapshotHash ? { lastSnapshotHash } : {}),
    ...(lastSyncedAt ? { lastSyncedAt } : {}),
    lastSyncStatus,
    sourceCount,
    candidateCount,
    lastSyncWarnings,
  };
};

export const createAiPathsValidationRuleId = (
  title: string,
  existingRuleIds: Iterable<string>
): string => {
  const normalizedBase = title
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 64);
  const base = normalizedBase.length > 0 ? normalizedBase : 'rule';
  const existing = new Set<string>();
  for (const entry of existingRuleIds) {
    if (typeof entry === 'string' && entry.trim().length > 0) {
      existing.add(entry.trim());
    }
  }
  if (!existing.has(base)) return base;

  let suffix = 2;
  while (suffix <= 9999) {
    const candidate = `${base}_${suffix}`;
    if (!existing.has(candidate)) return candidate;
    suffix += 1;
  }

  return `${base}_${Date.now().toString(36)}`;
};

export const createAiPathsValidationConditionId = (
  operator: string,
  existingConditionIds: Iterable<string>
): string => {
  const normalizedOperator = operator
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 64);
  const base = normalizedOperator.length > 0 ? normalizedOperator : 'condition';

  const existing = new Set<string>();
  for (const entry of existingConditionIds) {
    if (typeof entry === 'string' && entry.trim().length > 0) {
      existing.add(entry.trim());
    }
  }
  if (!existing.has(base)) return base;

  let suffix = 2;
  while (suffix <= 9999) {
    const candidate = `${base}_${suffix}`;
    if (!existing.has(candidate)) return candidate;
    suffix += 1;
  }

  return `${base}_${Date.now().toString(36)}`;
};

