const clampScore = (value: number): number => Math.max(0, Math.min(100, Math.trunc(value)));

const normalizePathToken = (value: string): string =>
  value.trim().replace(/^\$\./, '').replace(/^\$\[/, '[');

const resolvePathValue = (input: unknown, path: string | undefined): unknown => {
  if (!path?.trim()) return input;
  const normalizedPath = normalizePathToken(path);
  if (!normalizedPath) return input;

  const tokens = normalizedPath
    .replace(/\[(\d+)\]/g, '.$1')
    .split('.')
    .map((token) => token.trim())
    .filter(Boolean);

  let cursor: unknown = input;
  for (const token of tokens) {
    if (cursor === null || cursor === undefined) return undefined;
    if (typeof cursor !== 'object') return undefined;
    const record = cursor as Record<string, unknown>;
    cursor = record[token];
  }
  return cursor;
};

const toText = (value: unknown): string => {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (value === null || value === undefined) return '';
  try {
    return JSON.stringify(value);
  } catch (error) {
    logClientError(error);
    return '';
  }
};

const hasMeaningfulValue = (value: unknown): boolean => {
  if (value === null || value === undefined) return false;
  if (typeof value === 'string') return value.trim().length > 0;
  if (typeof value === 'number') return Number.isFinite(value);
  if (typeof value === 'boolean') return true;
  if (Array.isArray(value)) return value.length > 0;
  if (typeof value === 'object') {
    return Object.keys(value as Record<string, unknown>).length > 0;
  }
  return false;
};

const buildGraphContext = (
  nodes: AiNode[],
  edges: Edge[]
): {
  counts: {
    nodes: number;
    edges: number;
    byType: Record<string, number>;
  };
} => {
  const countsByType = nodes.reduce<Record<string, number>>(
    (acc: Record<string, number>, node: AiNode): Record<string, number> => {
      const key = node.type;
      acc[key] = (acc[key] ?? 0) + 1;
      return acc;
    },
    {}
  );
  return {
    counts: {
      nodes: nodes.length,
      edges: edges.length,
      byType: countsByType,
    },
  };
};

const normalizeEntityType = (value: unknown): string => {
  const normalized = toText(value).trim().toLowerCase();
  if (!normalized) return 'product';
  if (normalized === 'products') return 'product';
  if (normalized === 'notes') return 'note';
  return normalized;
};

const readEdgeString = (edge: Edge, key: string): string | null => {
  const value = (edge as Record<string, unknown>)[key];
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

const edgeToNodeId = (edge: Edge): string | null => {
  return readEdgeString(edge, 'to') ?? readEdgeString(edge, 'target') ?? readEdgeString(edge, 'toNodeId');
};

const edgeFromNodeId = (edge: Edge): string | null => {
  return (
    readEdgeString(edge, 'from') ??
    readEdgeString(edge, 'source') ??
    readEdgeString(edge, 'fromNodeId')
  );
};

const edgeToPort = (edge: Edge): string | null => {
  return (
    readEdgeString(edge, 'toPort') ??
    readEdgeString(edge, 'targetHandle') ??
    readEdgeString(edge, 'targetPort') ??
    readEdgeString(edge, 'toHandle')
  );
};

const edgeFromPort = (edge: Edge): string | null => {
  return (
    readEdgeString(edge, 'fromPort') ??
    readEdgeString(edge, 'sourceHandle') ??
    readEdgeString(edge, 'sourcePort') ??
    readEdgeString(edge, 'fromHandle')
