const isDatabaseWriteNode = (node: AiNode): boolean => {
  const databaseConfig = (node.config as Record<string, unknown> | undefined)?.['database'];
  if (databaseConfig === null || typeof databaseConfig !== 'object' || Array.isArray(databaseConfig)) {
    return false;
  }
  const operation = (databaseConfig as Record<string, unknown>)['operation'];
  return operation === 'update' || operation === 'delete';
};

const isRecord = (value: unknown): value is Record<string, unknown> =>
  value !== null && typeof value === 'object' && !Array.isArray(value);

const databaseQueryTemplateHasExplicitIdentity = (node: AiNode): boolean => {
  const databaseConfig = (node.config as Record<string, unknown> | undefined)?.['database'];
  if (!isRecord(databaseConfig)) return false;
  const queryConfig = databaseConfig['query'];
  if (!isRecord(queryConfig)) return false;
  const queryTemplate = queryConfig['queryTemplate'];
  if (typeof queryTemplate !== 'string') return false;
  const normalizedTemplate = queryTemplate.trim();
  if (normalizedTemplate.length === 0 || normalizedTemplate === '{}') return false;
  return (
    normalizedTemplate.includes('{{context.') ||
    normalizedTemplate.includes('{{value.') ||
    normalizedTemplate.includes('{{entityId') ||
    normalizedTemplate.includes('{{productId') ||
    normalizedTemplate.includes('{{id')
  );
};

const databaseWriteHasCustomQueryAndUpdateTemplates = (node: AiNode): boolean => {
  const databaseConfig = (node.config as Record<string, unknown> | undefined)?.['database'];
  if (!isRecord(databaseConfig)) return false;
  const queryConfig = databaseConfig['query'];
  if (!isRecord(queryConfig)) return false;
  const queryTemplate =
    typeof queryConfig['queryTemplate'] === 'string' ? queryConfig['queryTemplate'].trim() : '';
  const updateTemplate =
    typeof databaseConfig['updateTemplate'] === 'string'
      ? databaseConfig['updateTemplate'].trim()
      : '';
  return queryTemplate.length > 0 && queryTemplate !== '{}' && updateTemplate.length > 0;
};

const databaseWriteTargetsFilemakerJobApplications = (node: AiNode): boolean => {
  const databaseConfig = (node.config as Record<string, unknown> | undefined)?.['database'];
  if (!isRecord(databaseConfig)) return false;
  const queryConfig = databaseConfig['query'];
  if (!isRecord(queryConfig)) return false;
  return queryConfig['collection'] === 'filemaker_job_applications';
};

const nodeDeclaresExplicitDatabaseWriteInput = (node: AiNode): boolean =>
  (node.inputs ?? []).some((port: string): boolean => DATABASE_WRITE_EXPLICIT_WIRING_PORTS.has(port));

const nodeHasTemplateBackedDatabaseWriteIdentity = (node: AiNode): boolean =>
  isDatabaseWriteNode(node) &&
  nodeDeclaresExplicitDatabaseWriteInput(node) &&
  (databaseQueryTemplateHasExplicitIdentity(node) ||
    (databaseWriteTargetsFilemakerJobApplications(node) &&
      databaseWriteHasCustomQueryAndUpdateTemplates(node)));

const isDatabaseWriteIdentityRule = (rule: AiPathsValidationRule): boolean => {
  const haystack = [rule.id, rule.title, rule.description]
    .filter((value: string | undefined): value is string => typeof value === 'string')
    .join(' ')
    .toLowerCase();
  return (
    haystack.includes('database.update.identity_wired') ||
    haystack.includes('explicit identity wiring') ||
    haystack.includes('hidden fallback updates')
  );
};

const incomingPortSatisfiesCondition = (
  node: AiNode,
  actualPort: string | null,
  expectedPort: string,
  ruleId?: string
): boolean => {
  if (actualPort === expectedPort) return true;
  if (!isDatabaseWriteNode(node)) return false;
  if (
    ruleId === 'database.update.identity_wired' &&
    actualPort !== null &&
    DATABASE_WRITE_EXPLICIT_WIRING_PORTS.has(actualPort)
  ) {
    return true;
  }
  if (!DATABASE_WRITE_IDENTITY_RULE_PORTS.has(expectedPort)) return false;
  return actualPort !== null && DATABASE_WRITE_EXPLICIT_WIRING_PORTS.has(actualPort);
};

const isAllowedCollection = (value: string): boolean => {
  const normalized = value.trim();
  if (!normalized) return false;
  if (COLLECTION_ALLOWLIST.has(normalized)) return true;
  if (COLLECTION_ALLOWLIST.has('custom')) return normalized.length > 0;
  return false;
};

const doEdgeEndpointsResolve = (edges: Edge[], nodesById: Map<string, AiNode>): boolean =>
  edges.every((edge: Edge): boolean => {
    const fromNodeId = edgeFromNodeId(edge);
    const toNodeId = edgeToNodeId(edge);
    if (!fromNodeId || !toNodeId) return false;
    return nodesById.has(fromNodeId) && nodesById.has(toNodeId);
  });

const doEdgePortsMatchNodeDeclarations = (edges: Edge[], nodesById: Map<string, AiNode>): boolean =>
  edges.every((edge: Edge): boolean => {
    const fromNodeId = edgeFromNodeId(edge);
    const toNodeId = edgeToNodeId(edge);
    if (!fromNodeId || !toNodeId) return false;
    const sourceNode = nodesById.get(fromNodeId);
    const targetNode = nodesById.get(toNodeId);
    if (!sourceNode || !targetNode) return false;
    const fromPort = edgeFromPort(edge);
    const toPort = edgeToPort(edge);
    const sourcePortValid =
      !fromPort || (Array.isArray(sourceNode.outputs) && sourceNode.outputs.includes(fromPort));
    const targetPortValid =
      !toPort || (Array.isArray(targetNode.inputs) && targetNode.inputs.includes(toPort));
    return sourcePortValid && targetPortValid;
  });

const doNodeTypesKnown = (nodes: AiNode[], allowedTypes?: string[]): boolean => {
  const normalizedAllowed =
    Array.isArray(allowedTypes) && allowedTypes.length > 0
      ? new Set(allowedTypes.map((type) => toText(type).trim()).filter((type) => type.length > 0))
      : KNOWN_NODE_TYPES;
  if (normalizedAllowed.size === 0) return false;
  return nodes.every((node: AiNode): boolean => normalizedAllowed.has(node.type));
};

const doNodeIdsUnique = (nodes: AiNode[]): boolean => {
  const seen = new Set<string>();
  for (const node of nodes) {
    const id = toText(node.id).trim();
    if (!id || seen.has(id)) return false;
    seen.add(id);
  }
  return true;
};

const doEdgeIdsUnique = (edges: Edge[]): boolean => {
  const seen = new Set<string>();
  for (const edge of edges) {
    const id = toText(edge.id).trim();
    if (!id || seen.has(id)) return false;
    seen.add(id);
  }
  return true;
};

const doNodePositionsFinite = (nodes: AiNode[]): boolean =>
  nodes.every(
    (node: AiNode): boolean =>
      Number.isFinite(node.position?.x) && Number.isFinite(node.position?.y)
  );

const evaluateCondition = (args: {
  condition: AiPathsValidationCondition;
  rule: AiPathsValidationRule;
  node: AiNode | null;
  nodes: AiNode[];
  nodesById: Map<string, AiNode>;
  edges: Edge[];
  graphContext: Record<string, unknown>;
  config: AiPathsValidationConfig;
}): boolean => {
  const { condition, rule, node, nodes, nodesById, edges, graphContext, config } = args;

  const evaluate = (): boolean => {
    switch (condition.operator) {
      case 'exists': {
        if (rule.module === 'graph') {
          return (
            resolvePathValue(graphContext, condition.valuePath ?? condition.field) !== undefined
          );
        }
        if (!node) return false;
        return resolvePathValue(node, condition.valuePath ?? condition.field) !== undefined;
      }
      case 'non_empty': {
        if (rule.module === 'graph') {
          return hasMeaningfulValue(
            resolvePathValue(graphContext, condition.valuePath ?? condition.field)
          );
        }
        if (!node) return false;
        return hasMeaningfulValue(resolvePathValue(node, condition.valuePath ?? condition.field));
      }
      case 'equals': {
        if (rule.module === 'graph') {
          return (
            resolvePathValue(graphContext, condition.valuePath ?? condition.field) ===
            condition.expected
          );
        }
        if (!node) return false;
        return (
          resolvePathValue(node, condition.valuePath ?? condition.field) === condition.expected
        );
      }
      case 'in': {
        const list = Array.isArray(condition.list)
          ? condition.list
          : Array.isArray(condition.expected)
            ? (condition.expected as string[])
            : [];
        if (list.length === 0) return false;
        const value =
          rule.module === 'graph'
            ? resolvePathValue(graphContext, condition.valuePath ?? condition.field)
            : node
              ? resolvePathValue(node, condition.valuePath ?? condition.field)
              : undefined;
        return list.includes(toText(value));
      }
      case 'matches_regex': {
        const pattern =
          typeof condition.expected === 'string'
            ? condition.expected
            : Array.isArray(condition.list) && condition.list.length > 0
              ? condition.list[0]
              : '';
        if (!pattern) return false;
        let regex: RegExp;
        try {
          regex = new RegExp(pattern, condition.flags);
        } catch (error) {
          logClientError(error);
          return false;
        }
        const value =
          rule.module === 'graph'
            ? resolvePathValue(graphContext, condition.valuePath ?? condition.field)
            : node
              ? resolvePathValue(node, condition.valuePath ?? condition.field)
              : undefined;
        return regex.test(toText(value));
      }
      case 'jsonpath_exists': {
        const value = resolvePathValue(
          rule.module === 'graph' ? graphContext : node,
          condition.valuePath ?? condition.field
        );
        return value !== undefined;
      }
      case 'jsonpath_equals': {
        const value = resolvePathValue(
          rule.module === 'graph' ? graphContext : node,
          condition.valuePath ?? condition.field
        );
        if (typeof condition.expected === 'number' && typeof value === 'number') {
          return value >= condition.expected;
        }
        return value === condition.expected;
      }
      case 'has_incoming_port': {
        if (!node) return false;
        const hasMatchingEdge = edges.some((edge: Edge): boolean => {
          if (edgeToNodeId(edge) !== node.id) return false;
          if (!condition.port) return true;
          return incomingPortSatisfiesCondition(node, edgeToPort(edge), condition.port, rule.id);
        });
        if (hasMatchingEdge) return true;
        return (
          isDatabaseWriteIdentityRule(rule) &&
          nodeHasTemplateBackedDatabaseWriteIdentity(node)
        );
      }
      case 'has_outgoing_port': {
        if (!node) return false;
        return edges.some((edge: Edge): boolean => {
          if (edgeFromNodeId(edge) !== node.id) return false;
          if (!condition.port) return true;
          return edgeFromPort(edge) === condition.port;
        });
      }
      case 'wired_from': {
        if (!node) return false;
        if (condition.fromNodeType === 'simulation') {
          const hasSourceType = nodes.some(
            (candidate: AiNode): boolean => candidate.type === condition.fromNodeType
          );
          if (!hasSourceType) return true;
        }
        return edges.some((edge: Edge): boolean => {
          if (edgeToNodeId(edge) !== node.id) return false;
          if (condition.toPort && edgeToPort(edge) !== condition.toPort) return false;
          if (condition.fromPort && edgeFromPort(edge) !== condition.fromPort) return false;
          const sourceId = edgeFromNodeId(edge);
          if (!sourceId) return false;
          if (condition.sourceNodeId && sourceId !== condition.sourceNodeId) return false;
          if (condition.fromNodeType) {
            const sourceNode = nodesById.get(sourceId);
            if (sourceNode?.type !== condition.fromNodeType) return false;
          }
          return true;
        });
      }
      case 'wired_to': {
        if (!node) return false;
        if (condition.toNodeType === 'simulation') {
          const hasTargetType = nodes.some(
            (candidate: AiNode): boolean => candidate.type === condition.toNodeType
          );
          if (!hasTargetType) return true;
        }
        return edges.some((edge: Edge): boolean => {
          if (edgeFromNodeId(edge) !== node.id) return false;
          if (condition.fromPort && edgeFromPort(edge) !== condition.fromPort) return false;
          if (condition.toPort && edgeToPort(edge) !== condition.toPort) return false;
          const targetId = edgeToNodeId(edge);
          if (!targetId) return false;
          if (condition.targetNodeId && targetId !== condition.targetNodeId) return false;
          if (condition.toNodeType) {
            const targetNode = nodesById.get(targetId);
            if (targetNode?.type !== condition.toNodeType) return false;
          }
          return true;
        });
      }
      case 'collection_exists': {
        if (!node) return false;
        const raw = resolvePathValue(
          node,
          condition.field ?? condition.valuePath ?? 'config.database.query.collection'
        );
        return isAllowedCollection(toText(raw));
      }
      case 'entity_collection_resolves': {
        if (!node) return false;
        const entityType = normalizeEntityType(
          resolvePathValue(node, 'config.simulation.entityType')
        );
        const entityId =
          toText(resolvePathValue(node, 'config.simulation.entityId')).trim() ||
          toText(resolvePathValue(node, 'config.simulation.productId')).trim();
        const collectionMap =
          config.collectionMap && typeof config.collectionMap === 'object'
            ? config.collectionMap
            : {};
        const mappedCollection = toText(collectionMap[entityType]).trim();
        return entityId.length > 0 && mappedCollection.length > 0;
      }
      case 'edge_endpoints_resolve': {
        return doEdgeEndpointsResolve(edges, nodesById);
      }
      case 'edge_ports_declared': {
        return doEdgePortsMatchNodeDeclarations(edges, nodesById);
      }
      case 'node_types_known': {
        return doNodeTypesKnown(nodes, condition.list);
      }
      case 'node_ids_unique': {
        return doNodeIdsUnique(nodes);
      }
      case 'edge_ids_unique': {
        return doEdgeIdsUnique(edges);
      }
      case 'node_positions_finite': {
        return doNodePositionsFinite(nodes);
      }
      default:
        return false;
    }
  };

  const result = evaluate();
  return condition.negate ? !result : result;
};

const matchesRuleNode = (rule: AiPathsValidationRule, node: AiNode): boolean => {
  if (rule.module === 'graph') return false;
  if (rule.module !== 'custom' && node.type !== rule.module) {
    if (
      !Array.isArray(rule.appliesToNodeTypes) ||
      rule.appliesToNodeTypes.length === 0 ||
      !rule.appliesToNodeTypes.includes(node.type)
    ) {
      return false;
    }
  }
  if (!Array.isArray(rule.appliesToNodeTypes) || rule.appliesToNodeTypes.length === 0) {
    return true;
  }
  return rule.appliesToNodeTypes.includes(node.type);
};

const evaluateRuleForNode = (args: {
  rule: AiPathsValidationRule;
  node: AiNode | null;
  nodes: AiNode[];
  nodesById: Map<string, AiNode>;
  edges: Edge[];
  graphContext: Record<string, unknown>;
  config: AiPathsValidationConfig;
}): { passed: boolean; failedConditions: string[] } => {
  const { rule, node, nodes, nodesById, edges, graphContext, config } = args;
  const mode = rule.conditionMode === 'any' ? 'any' : 'all';
  const checks = rule.conditions.map((condition: AiPathsValidationCondition): boolean =>
    evaluateCondition({
      condition,
      rule,
      node,
      nodes,
      nodesById,
      edges,
      graphContext,
      config,
    })
  );
  const passed =
    mode === 'any'
      ? checks.some((value: boolean): boolean => value)
      : checks.every((value: boolean): boolean => value);
  const failedConditions = rule.conditions
    .filter((_condition: AiPathsValidationCondition, index: number): boolean => !checks[index])
    .map((condition: AiPathsValidationCondition): string => condition.id);
  return { passed, failedConditions };
};

const createEmptySeverityCounts = (): Record<'error' | 'warning' | 'info', number> => ({
  error: 0,
  warning: 0,
  info: 0,
});

const createEmptyModuleImpact = (module: string): AiPathsValidationModuleImpact => ({
  module,
  rulesEvaluated: 0,
  failedRules: 0,
  scorePenalty: 0,
  severityCounts: createEmptySeverityCounts(),
});

const shouldEvaluateRuleAtRuntime = (rule: AiPathsValidationRule): boolean => {
  if (rule.enabled === false) return false;
  const inference = rule.inference;
  if (!inference) return true;
  if (
    inference.status === 'candidate' ||
    inference.status === 'rejected' ||
    inference.status === 'deprecated'
  ) {
    return false;
  }
  if (inference.sourceType === 'central_docs') {
    return inference.status === 'approved';
  }
  return true;
};

const DEFAULT_STAGE_WHEN_UNSPECIFIED: AiPathsValidationStage = 'graph_parse';

export type EvaluateAiPathsValidationAtStageInput = EvaluateAiPathsValidationInput & {
  stage: AiPathsValidationStage;
  node?: AiNode | null | undefined;
};

const isNodeStage = (stage: AiPathsValidationStage | undefined): boolean =>
  stage === 'node_pre_execute' || stage === 'node_post_execute';

export const doesAiPathsValidationRuleApplyToStage = (
  rule: AiPathsValidationRule,
  stage: AiPathsValidationStage | undefined
): boolean => {
  if (!stage) return true;
  if (!Array.isArray(rule.appliesToStages) || rule.appliesToStages.length === 0) {
    return stage === DEFAULT_STAGE_WHEN_UNSPECIFIED;
  }
  return rule.appliesToStages.includes(stage);
};

const evaluateAiPathsValidation = ({
  nodes,
  edges,
  config,
  stage,
  node,
}: EvaluateAiPathsValidationInput & {
  stage?: AiPathsValidationStage | undefined;
  node?: AiNode | null | undefined;
}): AiPathsValidationReport => {
  const targetNode = node ?? null;
  const normalizedConfig = normalizeAiPathsValidationConfig(config);
  const policy = normalizedConfig.policy ?? 'block_below_threshold';
  const baseScore =
    typeof normalizedConfig.baseScore === 'number' ? clampScore(normalizedConfig.baseScore) : 100;

  const evaluatedAt = new Date().toISOString();
  const graphContext = buildGraphContext(nodes, edges);

  if (!normalizedConfig.enabled) {
    return {
      schemaVersion: normalizedConfig.schemaVersion ?? AI_PATHS_VALIDATION_SCHEMA_VERSION,
      evaluatedAt,
      enabled: false,
      policy,
      score: 100,
      blocked: false,
      shouldWarn: false,
      warnThreshold: normalizedConfig.warnThreshold ?? 70,
      blockThreshold: normalizedConfig.blockThreshold ?? 50,
      rulesEvaluated: 0,
      failedRules: 0,
      findings: [],
      recommendations: [],
      severityCounts: createEmptySeverityCounts(),
      graphStats: {
        nodes: graphContext.counts.nodes,
        edges: graphContext.counts.edges,
        byType: graphContext.counts.byType,
      },
      moduleImpact: {},
      appliedRuleIds: [],
      skippedRuleIds: [],
    };
  }

  const nodesById = new Map<string, AiNode>(
    nodes.map((node: AiNode): [string, AiNode] => [node.id, node])
  );
  const findings: AiPathsValidationFinding[] = [];
  const moduleImpactMap = new Map<string, AiPathsValidationModuleImpact>();
  const appliedRuleIds = new Set<string>();
  const skippedRuleIds = new Set<string>();
  const orderedRules = (normalizedConfig.rules ?? [])
    .filter(
      (rule: AiPathsValidationRule): boolean =>
        shouldEvaluateRuleAtRuntime(rule) && doesAiPathsValidationRuleApplyToStage(rule, stage)
    )
    .slice()
    .sort((a: AiPathsValidationRule, b: AiPathsValidationRule): number => {
      const left = typeof a.sequence === 'number' ? a.sequence : 0;
      const right = typeof b.sequence === 'number' ? b.sequence : 0;
      if (left !== right) return left - right;
      return a.id.localeCompare(b.id);
    });
  (normalizedConfig.rules ?? []).forEach((rule: AiPathsValidationRule): void => {
    if (!shouldEvaluateRuleAtRuntime(rule) || !doesAiPathsValidationRuleApplyToStage(rule, stage)) {
      skippedRuleIds.add(rule.id);
    }
  });
  let score = baseScore;
  let rulesEvaluated = 0;
  let failedRules = 0;

  const evaluateAndCollectFinding = (rule: AiPathsValidationRule, node: AiNode | null): void => {
    rulesEvaluated += 1;
    appliedRuleIds.add(rule.id);

    const moduleKey = rule.module ?? 'custom';
    const moduleImpact = moduleImpactMap.get(moduleKey) ?? createEmptyModuleImpact(moduleKey);
    moduleImpact.rulesEvaluated += 1;

    const evaluation = evaluateRuleForNode({
      rule,
      node,
      nodes,
      nodesById,
      edges,
      graphContext,
      config: normalizedConfig,
    });
    if (evaluation.passed) {
      moduleImpactMap.set(moduleKey, moduleImpact);
      return;
    }

    failedRules += 1;
    moduleImpact.failedRules += 1;

    const severity = isDatabaseWriteIdentityRule(rule) ? 'warning' : rule.severity ?? 'warning';
    const weight =
      isDatabaseWriteIdentityRule(rule)
        ? 0
        :
      typeof rule.weight === 'number' && Number.isFinite(rule.weight)
        ? Math.max(0, Math.trunc(rule.weight))
        : DEFAULT_SEVERITY_WEIGHT[severity];

    score = clampScore(score - weight);
    moduleImpact.scorePenalty += weight;
    moduleImpact.severityCounts[severity] += 1;

    if (
      typeof rule.forceProbabilityIfFailed === 'number' &&
      Number.isFinite(rule.forceProbabilityIfFailed)
    ) {
      score = Math.min(score, clampScore(rule.forceProbabilityIfFailed));
    }

    findings.push({
      id: `${rule.id}:${node?.id ?? 'graph'}`,
      ruleId: rule.id,
      ruleTitle: rule.title,
      severity,
      module: rule.module,
      ...(stage ? { stage } : {}),
      nodeId: node?.id ?? null,
      nodeTitle: node?.title ?? null,
      message: rule.description?.trim() || `${rule.title} validation failed.`,
      recommendation: rule.recommendation?.trim() || null,
      docsBindings: Array.isArray(rule.docsBindings) ? rule.docsBindings : [],
      failedConditionIds: evaluation.failedConditions,
    });

    moduleImpactMap.set(moduleKey, moduleImpact);
  };

  orderedRules.forEach((rule: AiPathsValidationRule): void => {
    if (rule.module === 'graph') {
      if (targetNode || isNodeStage(stage)) {
        skippedRuleIds.add(rule.id);
        return;
      }
      evaluateAndCollectFinding(rule, null);
      return;
    }

    const matchingNodes = targetNode
      ? matchesRuleNode(rule, targetNode)
        ? [targetNode]
        : []
      : nodes.filter((candidate: AiNode): boolean => matchesRuleNode(rule, candidate));
    if (matchingNodes.length === 0) {
      skippedRuleIds.add(rule.id);
      return;
    }
    matchingNodes.forEach((node: AiNode): void => {
      evaluateAndCollectFinding(rule, node);
    });
  });

  const severityCounts = findings.reduce<Record<'error' | 'warning' | 'info', number>>(
    (acc: Record<'error' | 'warning' | 'info', number>, finding: AiPathsValidationFinding) => {
      const key = finding.severity;
      acc[key] = (acc[key] ?? 0) + 1;
      return acc;
    },
    createEmptySeverityCounts()
  );

  const recommendations = findings
    .filter(
      (
        finding: AiPathsValidationFinding
      ): finding is AiPathsValidationFinding & { recommendation: string } =>
        typeof finding.recommendation === 'string' && finding.recommendation.trim().length > 0
    )
    .map(
      (
        finding: AiPathsValidationFinding & { recommendation: string }
      ): AiPathsValidationRecommendation => ({
        id: `${finding.ruleId}:${finding.nodeId ?? 'graph'}:${finding.stage ?? 'all'}:recommendation`,
        ruleId: finding.ruleId,
        module: finding.module,
        severity: finding.severity,
        message: finding.message,
        recommendation: finding.recommendation,
        nodeId: finding.nodeId,
        nodeTitle: finding.nodeTitle,
      })
    );

  const warnThreshold = normalizedConfig.warnThreshold ?? 70;
  const blockThreshold = normalizedConfig.blockThreshold ?? 50;
  const blocked = policy === 'block_below_threshold' ? score < blockThreshold : false;
  const shouldWarn =
    policy === 'warn_below_threshold'
      ? score < warnThreshold || severityCounts.warning > 0 || severityCounts.error > 0
      : policy === 'block_below_threshold'
        ? !blocked && (score < warnThreshold || severityCounts.warning > 0)
        : severityCounts.warning > 0 || severityCounts.error > 0;

  return {
    schemaVersion: normalizedConfig.schemaVersion ?? AI_PATHS_VALIDATION_SCHEMA_VERSION,
    evaluatedAt,
    enabled: true,
    policy,
    score,
    blocked,
    shouldWarn,
    warnThreshold,
    blockThreshold,
    rulesEvaluated,
    failedRules,
    findings,
    recommendations,
    severityCounts,
    graphStats: {
      nodes: graphContext.counts.nodes,
      edges: graphContext.counts.edges,
      byType: graphContext.counts.byType,
    },
    moduleImpact: Object.fromEntries(moduleImpactMap.entries()),
    appliedRuleIds: Array.from(appliedRuleIds),
    skippedRuleIds: Array.from(skippedRuleIds),
  };
};

export const evaluateAiPathsValidationPreflight = ({
  nodes,
  edges,
  config,
}: EvaluateAiPathsValidationInput): AiPathsValidationReport =>
  evaluateAiPathsValidation({
    nodes,
    edges,
    config,
  });

export const evaluateAiPathsValidationAtStage = ({
  nodes,
  edges,
  config,
  stage,
  node,
}: EvaluateAiPathsValidationAtStageInput): AiPathsValidationReport =>
  evaluateAiPathsValidation({
    nodes,
    edges,
    config,
    stage,
    ...(node ? { node } : {}),
  });

import 'server-only';

import {
  CRITICAL_CONFIG_FIELD_PATTERN,
  NODE_DOCS_CATALOG_SOURCE_PATH,
} from '../docs-registry-adapter.constants';
import {
  hashText,
  inferEnumListFromDescription,
  shouldInferRequiredBooleanFromDefault,
  toModuleFromNodeType,
} from '../docs-registry-adapter.helpers';
import type {
  AiPathsDocAssertion,
} from '../docs-registry-adapter.types';
import { AI_PATHS_NODE_DOCS } from '../../docs/node-docs';

export const buildNodeDocsCatalogAssertions = (): AiPathsDocAssertion[] => {
  const sourcePath = NODE_DOCS_CATALOG_SOURCE_PATH;
  const sourceHash = hashText(JSON.stringify(AI_PATHS_NODE_DOCS));
  const assertions: AiPathsDocAssertion[] = [];
  const seenIds = new Set<string>();

  const pushAssertion = (assertion: AiPathsDocAssertion): void => {
    if (seenIds.has(assertion.id)) return;
    seenIds.add(assertion.id);
    assertions.push(assertion);
  };

  AI_PATHS_NODE_DOCS.forEach((doc) => {
    doc.config.forEach((field: { path: string; description: string; defaultValue?: string }) => {
      const normalizedPath = field.path.replace(/[^a-z0-9]+/gi, '_').toLowerCase();
      const conditionField = `config.${field.path}`;
      const isCritical = CRITICAL_CONFIG_FIELD_PATTERN.test(field.path);
      if (isCritical) {
        pushAssertion({
          id: `catalog.${doc.type}.${normalizedPath}.non_empty`,
          title: `${doc.title}: ${field.path} should be configured`,
          module: toModuleFromNodeType(doc.type),
          severity: /entityid|collection|modelid|event/i.test(field.path) ? 'error' : 'warning',
          description: field.description,
          recommendation: `Set ${conditionField} in ${doc.title} configuration.`,
          appliesToNodeTypes: [doc.type],
          sequenceHint: 260,
          confidence: 0.55,
          sourcePath,
          sourceType: 'node_docs_catalog',
          sourceHash,
          docsBindings: [sourcePath],
          conditions: [
            {
              operator: 'non_empty',
              field: conditionField,
            },
          ],
        });
      }

      const enumValues = inferEnumListFromDescription(
        field.path,
        field.description,
        field.defaultValue
      );
      if (enumValues.length >= 2) {
        pushAssertion({
          id: `catalog.${doc.type}.${normalizedPath}.allowed_values`,
          title: `${doc.title}: ${field.path} uses documented values`,
          module: toModuleFromNodeType(doc.type),
          severity:
            /(provider|event|operation|runtimeMode|failPolicy|actionCategory|action)$/i.test(
              field.path
            )
              ? 'error'
              : 'warning',
          description: `${field.description} Allowed values inferred from docs: ${enumValues.join(', ')}.`,
          recommendation: `Set ${conditionField} to one of: ${enumValues.join(', ')}.`,
          appliesToNodeTypes: [doc.type],
          sequenceHint: 262,
          confidence: 0.5,
          sourcePath,
          sourceType: 'node_docs_catalog',
          sourceHash,
          docsBindings: [sourcePath],
          conditions: [
            {
              operator: 'in',
              field: conditionField,
              list: enumValues,
            },
          ],
        });
      }

      if (shouldInferRequiredBooleanFromDefault(field.path, field.defaultValue)) {
        pushAssertion({
          id: `catalog.${doc.type}.${normalizedPath}.exists`,
          title: `${doc.title}: ${field.path} flag explicitly set`,
          module: toModuleFromNodeType(doc.type),
          severity: 'info',
          description: `${field.description} Documentation indicates this flag should be explicit for predictable runtime behavior.`,
          recommendation: `Set ${conditionField} explicitly (true/false).`,
          appliesToNodeTypes: [doc.type],
          sequenceHint: 264,
          confidence: 0.45,
          sourcePath,
          sourceType: 'node_docs_catalog',
          sourceHash,
          docsBindings: [sourcePath],
          conditions: [
            {
              operator: 'exists',
              field: conditionField,
            },
          ],
        });
      }
    });
  });
  return assertions;
};

