    const result = z.array(semanticNodeIndexRowSchema).safeParse(parsed);
    if (!result.success) {
      warnings.push(`${source.path}: semantic nodes catalog schema validation failed.`);
      return {
        hash: hashText(`parse_error:${source.path}`),
        assertions: [],
      };
