import 'server-only';

import { type z } from 'zod';
import {
  DOCS_MANIFEST_PATH,
  BUILTIN_FALLBACK_MANIFEST,
} from '../docs-registry-adapter.constants';
import { readDocsSourceText } from '../docs-registry-adapter.file-access';
import {
  uniqueStringList,
} from '../docs-registry-adapter.helpers';
import {
  docsManifestSchema,
  type docsManifestSourceSchema,
  type AiPathsDocsManifest,
  type AiPathsDocsManifestSource,
} from '../docs-registry-adapter.types';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

export const normalizeManifestSource = (
  source: z.infer<typeof docsManifestSourceSchema>
): AiPathsDocsManifestSource => ({
  id: source.id.trim(),
  type: source.type,
  path: source.path.trim(),
  enabled: source.enabled !== false,
  priority:
    typeof source.priority === 'number' && Number.isFinite(source.priority)
      ? Math.max(0, Math.trunc(source.priority))
      : 100,
  tags: uniqueStringList(source.tags ?? []),
  ...(source.snippetNames?.length ? { snippetNames: uniqueStringList(source.snippetNames) } : {}),
});

export const normalizeManifest = (
  raw: z.infer<typeof docsManifestSchema>,
  warnings: string[]
): AiPathsDocsManifest => {
  const seenIds = new Set<string>();
  const sources: AiPathsDocsManifestSource[] = [];
  raw.sources.forEach((source) => {
    const normalized = normalizeManifestSource(source);
    if (seenIds.has(normalized.id)) {
      warnings.push(
        `Manifest source id "${normalized.id}" is duplicated and later entries are ignored.`
      );
      return;
    }
    seenIds.add(normalized.id);
    sources.push(normalized);
  });
  return {
    version: raw.version?.trim() || '1.0.0',
    sources,
  };
};

export const readAiPathsDocsManifest = async (warnings: string[]): Promise<AiPathsDocsManifest> => {
  try {
    const manifestText = await readDocsSourceText(DOCS_MANIFEST_PATH);
    let parsed: unknown = null;
    try {
      parsed = JSON.parse(manifestText);
    } catch (error) {
      void ErrorSystem.captureException(error);
      warnings.push(`${DOCS_MANIFEST_PATH}: invalid JSON. Falling back to built-in sources.`);
      return BUILTIN_FALLBACK_MANIFEST;
    }
    const result = docsManifestSchema.safeParse(parsed);
    if (!result.success) {
      warnings.push(
        `${DOCS_MANIFEST_PATH}: schema validation failed. Falling back to built-in sources.`
      );
      return BUILTIN_FALLBACK_MANIFEST;
    }
    const normalized = normalizeManifest(result.data, warnings);
    if (normalized.sources.length === 0) {
      warnings.push(
        `${DOCS_MANIFEST_PATH}: no valid sources enabled. Falling back to built-in sources.`
      );
      return BUILTIN_FALLBACK_MANIFEST;
    }
    return normalized;
  } catch (error) {
    void ErrorSystem.captureException(error);
    warnings.push(
      `${DOCS_MANIFEST_PATH}: failed to read manifest (${error instanceof Error ? error.message : 'unknown error'}). Falling back to built-in sources.`
    );
    return BUILTIN_FALLBACK_MANIFEST;
  }
};

import type {
  AiNode,
  AiPathsValidationConfig,
  AiPathsValidationFinding,
  Edge,
} from '@/shared/contracts/ai-paths';
import type {
  RuntimeValidationIssue,
  RuntimeValidationMiddleware,
  RuntimeValidationResult,
  RuntimeValidationStage,
} from '@/shared/lib/ai-paths/core/runtime/engine-modules/engine-types';

import { normalizeAiPathsValidationConfig } from './defaults';
import { evaluateAiPathsValidationAtStage } from './evaluator';
import {
  getResolvedNodeInputPortContract,
  getResolvedNodeOutputPortContract,
  type ResolvedNodePortContract,
} from '../utils/graph.nodes';
import {
  getPortDataTypesForValueKind,
  getValueTypeLabel,
  isValueCompatibleWithTypes,
} from '../utils/port-types';

export type CreateAiPathsRuntimeValidationMiddlewareInput = {
  config: AiPathsValidationConfig | null | undefined;
  nodes: AiNode[];
  edges: Edge[];
  maxIssuesPerDecision?: number | undefined;
};

export type ResolveAiPathsRuntimeValidationMiddlewareInput = {
  validationMiddleware?: RuntimeValidationMiddleware | null | undefined;
  runtimeValidationEnabled?: boolean | undefined;
  runtimeValidationConfig?: AiPathsValidationConfig | null | undefined;
  nodes: AiNode[];
  edges: Edge[];
  maxIssuesPerDecision?: number | undefined;
};

const DEFAULT_MAX_ISSUES_PER_DECISION = 10;
const normalizePortLabel = (port: string): string => port.trim();

const isObjectRecord = (value: unknown): value is Record<string, unknown> =>
  typeof value === 'object' && value !== null && !Array.isArray(value);

const getNodeLabel = (node: AiNode): string => node.title?.trim() || node.id;

const readEdgeString = (edge: Edge, key: string): string | null => {
  const value = (edge as Record<string, unknown>)[key];
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

const readEdgeFromNodeId = (edge: Edge): string | null =>
  readEdgeString(edge, 'from') ??
  readEdgeString(edge, 'source') ??
  readEdgeString(edge, 'fromNodeId');

const readEdgeToNodeId = (edge: Edge): string | null =>
  readEdgeString(edge, 'to') ??
  readEdgeString(edge, 'target') ??
  readEdgeString(edge, 'toNodeId');

const readEdgeFromPort = (edge: Edge): string | null =>
  readEdgeString(edge, 'fromPort') ??
  readEdgeString(edge, 'sourceHandle') ??
  readEdgeString(edge, 'sourcePort') ??
  readEdgeString(edge, 'fromHandle');

const readEdgeToPort = (edge: Edge): string | null =>
  readEdgeString(edge, 'toPort') ??
  readEdgeString(edge, 'targetHandle') ??
  readEdgeString(edge, 'targetPort') ??
  readEdgeString(edge, 'toHandle');

const DATABASE_WRITE_IDENTITY_PORTS = new Set(['id', 'entityId', 'productId']);
const DATABASE_WRITE_EXPLICIT_PORTS = new Set([
  'id',
  'entityId',
  'productId',
  'value',
  'context',
  'bundle',
  'meta',
]);

const isDatabaseUpdateOrDeleteNode = (node: AiNode): boolean => {
  const databaseConfig = (node.config as Record<string, unknown> | undefined)?.['database'];
  if (!isObjectRecord(databaseConfig)) return false;
  const operation = databaseConfig['operation'];
  return operation === 'update' || operation === 'delete';
};

const buildRuntimeValidationEdges = (nodes: AiNode[], edges: Edge[]): Edge[] => {
  let nextEdges: Edge[] | null = null;
  nodes.forEach((node: AiNode): void => {
    if (!isDatabaseUpdateOrDeleteNode(node)) return;
    const incoming = edges.filter((edge: Edge): boolean => readEdgeToNodeId(edge) === node.id);
    const hasIdentityEdge = incoming.some((edge: Edge): boolean => {
      const port = readEdgeToPort(edge);
      return port !== null && DATABASE_WRITE_IDENTITY_PORTS.has(port);
    });
    if (hasIdentityEdge) return;
    const explicitEdge = incoming.find((edge: Edge): boolean => {
      const port = readEdgeToPort(edge);
      return port !== null && DATABASE_WRITE_EXPLICIT_PORTS.has(port);
    });
    if (explicitEdge === undefined) return;
    const sourceNodeId = readEdgeFromNodeId(explicitEdge);
    if (sourceNodeId === null) return;
    const syntheticEdge: Edge = {
      id: `runtime-validation-identity-${node.id}`,
      from: sourceNodeId,
      to: node.id,
      fromPort: readEdgeFromPort(explicitEdge) ?? 'value',
      toPort: 'entityId',
      label: 'Runtime validation identity wiring',
      type: 'runtime-validation',
    };
    nextEdges = [...(nextEdges ?? edges), syntheticEdge];
  });
  return nextEdges ?? edges;
};

const nodeHasExplicitDatabaseWriteWiring = (nodeId: string | null | undefined, edges: Edge[]): boolean => {
  if (!nodeId) return false;
  return edges.some((edge: Edge): boolean => {
    if (readEdgeToNodeId(edge) !== nodeId) return false;
    const port = readEdgeToPort(edge);
    return port !== null && DATABASE_WRITE_EXPLICIT_PORTS.has(port);
  });
};

const databaseQueryTemplateHasExplicitIdentity = (node: AiNode): boolean => {
  const databaseConfig = (node.config as Record<string, unknown> | undefined)?.['database'];
  if (!isObjectRecord(databaseConfig)) return false;
  const queryConfig = databaseConfig['query'];
  if (!isObjectRecord(queryConfig)) return false;
  const queryTemplate = queryConfig['queryTemplate'];
  if (typeof queryTemplate !== 'string') return false;
  const normalizedTemplate = queryTemplate.trim();
  if (normalizedTemplate.length === 0 || normalizedTemplate === '{}') return false;
  return (
    normalizedTemplate.includes('{{context.') ||
    normalizedTemplate.includes('{{value.') ||
    normalizedTemplate.includes('{{entityId') ||
    normalizedTemplate.includes('{{productId') ||
    normalizedTemplate.includes('{{id')
  );
};

const databaseWriteHasCustomQueryAndUpdateTemplates = (node: AiNode): boolean => {
  const databaseConfig = (node.config as Record<string, unknown> | undefined)?.['database'];
  if (!isObjectRecord(databaseConfig)) return false;
  const queryConfig = databaseConfig['query'];
  if (!isObjectRecord(queryConfig)) return false;
  const queryTemplate =
    typeof queryConfig['queryTemplate'] === 'string' ? queryConfig['queryTemplate'].trim() : '';
  const updateTemplate =
    typeof databaseConfig['updateTemplate'] === 'string'
      ? databaseConfig['updateTemplate'].trim()
      : '';
  return queryTemplate.length > 0 && queryTemplate !== '{}' && updateTemplate.length > 0;
};

const databaseWriteTargetsFilemakerJobApplications = (node: AiNode): boolean => {
  const databaseConfig = (node.config as Record<string, unknown> | undefined)?.['database'];
  if (!isObjectRecord(databaseConfig)) return false;
  const queryConfig = databaseConfig['query'];
  if (!isObjectRecord(queryConfig)) return false;
  return queryConfig['collection'] === 'filemaker_job_applications';
};

const nodeDeclaresExplicitDatabaseWriteInput = (node: AiNode): boolean =>
  (node.inputs ?? []).some((port: string): boolean => DATABASE_WRITE_EXPLICIT_PORTS.has(port));

const nodeHasSafeDatabaseWriteIdentity = (
  node: AiNode | undefined,
  edges: Edge[]
): boolean => {
  if (!node) return false;
  if (nodeHasExplicitDatabaseWriteWiring(node.id, edges)) return true;
  return (
    nodeDeclaresExplicitDatabaseWriteInput(node) &&
    (databaseQueryTemplateHasExplicitIdentity(node) ||
      (databaseWriteTargetsFilemakerJobApplications(node) &&
        databaseWriteHasCustomQueryAndUpdateTemplates(node)))
  );
};

const databaseWriteNodeIdsWithoutExplicitWiring = (nodes: AiNode[], edges: Edge[]): string[] =>
  nodes
    .filter(isDatabaseUpdateOrDeleteNode)
    .map((node: AiNode): string => node.id)
    .filter(
      (nodeId: string): boolean => {
        const node = nodes.find((candidate: AiNode): boolean => candidate.id === nodeId);
        return !nodeHasSafeDatabaseWriteIdentity(node, edges);
      }
    );

const removeSatisfiedDatabaseWriteIdentityRule = (
  config: AiPathsValidationConfig,
  nodes: AiNode[],
  edges: Edge[]
): AiPathsValidationConfig => {
  const databaseWriteNodeIds = nodes
    .filter(isDatabaseUpdateOrDeleteNode)
    .map((node: AiNode): string => node.id);
  if (databaseWriteNodeIds.length === 0) return config;
  if (databaseWriteNodeIdsWithoutExplicitWiring(nodes, edges).length > 0) return config;
  const rules = config.rules ?? [];
  const nextRules = rules.filter(
    (rule): boolean => rule.id !== 'database.update.identity_wired'
  );
  return nextRules.length === rules.length
    ? config
    : {
        ...config,
        rules: nextRules,
      };
};

const isDatabaseWriteIdentityFinding = (finding: AiPathsValidationFinding): boolean => {
  const haystack = [
    finding.ruleId,
    finding.message,
    ...(finding.failedConditionIds ?? []),
  ]
    .join(' ')
    .toLowerCase();
  return (
    haystack.includes('database.update.identity_wired') ||
    haystack.includes('database_write_missing_identity_inputs') ||
    haystack.includes('explicit identity wiring') ||
    haystack.includes('hidden fallback updates')
  );
};

const filterRuntimeValidationFindings = (
  findings: AiPathsValidationFinding[],
  nodes: AiNode[],
  edges: Edge[]
): AiPathsValidationFinding[] =>
  findings.filter((finding: AiPathsValidationFinding): boolean => {
    if (!isDatabaseWriteIdentityFinding(finding)) return true;
    if (finding.nodeId) {
      return !nodeHasSafeDatabaseWriteIdentity(
        nodes.find((candidate: AiNode): boolean => candidate.id === finding.nodeId),
        edges
      );
    }
    if (databaseWriteNodeIdsWithoutExplicitWiring(nodes, edges).length > 0) return true;
    return false;
  });

const normalizeRuntimeValidationFinding = (
  finding: AiPathsValidationFinding
): AiPathsValidationFinding =>
  isDatabaseWriteIdentityFinding(finding)
    ? {
        ...finding,
        severity: 'warning',
      }
    : finding;

const buildReportFromFilteredFindings = (
  report: ReturnType<typeof evaluateAiPathsValidationAtStage>,
  findings: AiPathsValidationFinding[]
): ReturnType<typeof evaluateAiPathsValidationAtStage> => {
  const severityCounts = findings.reduce(
    (
      counts: Record<'error' | 'warning' | 'info', number>,
      finding: AiPathsValidationFinding
    ): Record<'error' | 'warning' | 'info', number> => ({
      ...counts,
      [finding.severity]: counts[finding.severity] + 1,
    }),
    { error: 0, info: 0, warning: 0 }
  );
  return {
    ...report,
    blocked: report.blocked && findings.length > 0 && severityCounts.error > 0,
    failedRules: findings.length,
    findings,
    severityCounts,
    shouldWarn: report.shouldWarn && findings.length > 0,
  };
};

const describeExpectedKind = (kind: ResolvedNodePortContract['kind']): string => {
  switch (kind) {
    case 'image_url':
      return 'imageUrl';
    case 'job_envelope':
      return 'jobEnvelope';
    case 'bundle':
      return 'bundle';
    case 'json':
      return 'json';
    case 'string':
    case 'number':
    case 'boolean':
      return kind;
    case 'unknown':
    default:
      return 'value';
  }
};

const describeExpectedContract = (contract: ResolvedNodePortContract): string => {
  const kindLabel = describeExpectedKind(contract.kind);
  return contract.cardinality === 'many' ? `${kindLabel}[]` : kindLabel;
};

const normalizeActualTypeLabel = (value: unknown): string => {
  const label = getValueTypeLabel(value);
  return label === 'image' ? 'imageUrl' : label;
};

const describeActualValue = (value: unknown): string => {
  if (Array.isArray(value)) {
    if (value.length === 0) return 'empty[]';
    const itemTypes = Array.from(
      new Set(value.map((item: unknown) => normalizeActualTypeLabel(item)))
    );
    return itemTypes.length === 1 ? `${itemTypes[0]}[]` : `array<${itemTypes.join(' | ')}>`;
  }
  return normalizeActualTypeLabel(value);
};

const validateJsonSchemaType = (
  value: unknown,
  schema: Record<string, unknown>,
  path = 'value'
): string | null => {
  const type = typeof schema['type'] === 'string' ? schema['type'].trim().toLowerCase() : '';
  if (type) {
    const typeMatches =
      (type === 'object' && isObjectRecord(value)) ||
      (type === 'array' && Array.isArray(value)) ||
      (type === 'string' && typeof value === 'string') ||
      (type === 'number' && typeof value === 'number' && Number.isFinite(value)) ||
      (type === 'integer' && typeof value === 'number' && Number.isInteger(value)) ||
      (type === 'boolean' && typeof value === 'boolean');
    if (!typeMatches) {
      return `${path} expected ${type}, got ${describeActualValue(value)}.`;
    }
  }

  if (Array.isArray(schema['required']) && isObjectRecord(value)) {
    for (const key of schema['required']) {
      if (typeof key !== 'string' || key.trim().length === 0) continue;
      if (value[key] === undefined) {
        return `${path}.${key} is required.`;
      }
    }
  }

  const properties = schema['properties'];
  if (isObjectRecord(properties) && isObjectRecord(value)) {
    for (const [key, propertySchema] of Object.entries(properties)) {
      if (value[key] === undefined || !isObjectRecord(propertySchema)) continue;
      const nestedError = validateJsonSchemaType(value[key], propertySchema, `${path}.${key}`);
      if (nestedError) return nestedError;
    }
  }

  const items = schema['items'];
  if (Array.isArray(value) && isObjectRecord(items)) {
    for (let index = 0; index < value.length; index += 1) {
      const nestedError = validateJsonSchemaType(value[index], items, `${path}[${index}]`);
      if (nestedError) return nestedError;
    }
  }

  return null;
};

const validatePortContractValue = (args: {
  node: AiNode;
  port: string;
  value: unknown;
  direction: 'input' | 'output';
  contract: ResolvedNodePortContract;
}): RuntimeValidationIssue[] => {
  const { node, port, value, direction, contract } = args;
  const issues: RuntimeValidationIssue[] = [];
  const hasExecutableContract =
    contract.kind !== 'unknown' ||
    contract.schema !== undefined ||
    contract.schemaRef !== undefined ||
    contract.cardinalitySource !== 'legacy';

  if (!hasExecutableContract || value === undefined) {
    return issues;
  }

  const label = direction === 'input' ? 'Input' : 'Output';
  const portLabel = normalizePortLabel(port);
  const nodeLabel = getNodeLabel(node);

  if (
    contract.cardinality === 'single' &&
    contract.cardinalitySource !== 'legacy' &&
    Array.isArray(value)
  ) {
    issues.push({
      stage: direction === 'input' ? 'node_pre_execute' : 'node_post_execute',
      severity: 'error',
      message: `${label} port "${portLabel}" on node "${nodeLabel}" expected ${describeExpectedContract(contract)}, got ${describeActualValue(value)}.`,
      nodeId: node.id,
      nodeTitle: node.title ?? null,
      metadata: {
        direction,
        port: portLabel,
        expected: describeExpectedContract(contract),
        actual: describeActualValue(value),
        schemaRef: contract.schemaRef,
      },
    });
    return issues;
  }

  const valuesToValidate: unknown[] = Array.isArray(value)
    ? value.map((entry: unknown): unknown => entry)
    : [value];
  if (contract.kind !== 'unknown') {
    const expectedTypes = getPortDataTypesForValueKind(contract.kind);
    const incompatibleValue = valuesToValidate.find(
      (entry: unknown): boolean => !isValueCompatibleWithTypes(entry, expectedTypes)
    );
    if (incompatibleValue !== undefined) {
      issues.push({
        stage: direction === 'input' ? 'node_pre_execute' : 'node_post_execute',
        severity: 'error',
        message: `${label} port "${portLabel}" on node "${nodeLabel}" expected ${describeExpectedContract(contract)}, got ${describeActualValue(value)}.`,
        nodeId: node.id,
        nodeTitle: node.title ?? null,
        metadata: {
          direction,
          port: portLabel,
          expected: describeExpectedContract(contract),
          actual: describeActualValue(value),
          schemaRef: contract.schemaRef,
        },
      });
      return issues;
    }
  }

  if (contract.schema && isObjectRecord(contract.schema)) {
    const schemaError = validateJsonSchemaType(value, contract.schema);
    if (schemaError) {
      issues.push({
        stage: direction === 'input' ? 'node_pre_execute' : 'node_post_execute',
        severity: 'error',
        message: `${label} port "${portLabel}" on node "${nodeLabel}" failed schema validation: ${schemaError}`,
        nodeId: node.id,
        nodeTitle: node.title ?? null,
        metadata: {
          direction,
          port: portLabel,
          expected: describeExpectedContract(contract),
          actual: describeActualValue(value),
          schemaRef: contract.schemaRef,
        },
      });
    }
  }

  return issues;
};

const collectDeclaredPorts = (
  ports: Array<string | undefined>,
  contracts: Record<string, unknown> | undefined
): string[] =>
  Array.from(
    new Set(
      [...ports, ...Object.keys(contracts ?? {})]
        .filter((port): port is string => typeof port === 'string' && port.trim().length > 0)
        .map((port: string) => port.trim())
    )
  );

const buildBuiltInContractIssues = (args: {
  stage: RuntimeValidationStage;
  node: AiNode | null | undefined;
  nodeInputs?: Record<string, unknown> | undefined;
  nodeOutputs?: Record<string, unknown> | undefined;
}): RuntimeValidationIssue[] => {
  const { stage, node } = args;
  if (!node) return [];
  if (stage === 'node_pre_execute') {
    const ports = collectDeclaredPorts(node.inputs ?? [], {
      ...(node.inputContracts ?? {}),
      ...((node.config?.runtime?.inputContracts as Record<string, unknown> | undefined) ?? {}),
    });
    return ports.flatMap((port: string): RuntimeValidationIssue[] =>
      validatePortContractValue({
        node,
        port,
        value: args.nodeInputs?.[port],
        direction: 'input',
        contract: getResolvedNodeInputPortContract(node, port),
      })
    );
  }
  if (stage === 'node_post_execute') {
    const ports = collectDeclaredPorts(node.outputs ?? [], node.outputContracts ?? {});
    return ports.flatMap((port: string): RuntimeValidationIssue[] =>
      validatePortContractValue({
        node,
        port,
        value: args.nodeOutputs?.[port],
        direction: 'output',
        contract: getResolvedNodeOutputPortContract(node, port),
      })
    );
  }
  return [];
};

const buildStageLabel = (stage: RuntimeValidationStage): string => {
  switch (stage) {
    case 'graph_parse':
      return 'graph parse';
    case 'graph_bind':
      return 'graph bind';
    case 'node_pre_execute':
      return 'node pre-execute';
    case 'node_post_execute':
      return 'node post-execute';
    default:
      return stage;
  }
};

const toRuntimeValidationIssue = (
  finding: AiPathsValidationFinding,
  stage: RuntimeValidationStage,
  node?: AiNode | null | undefined
): RuntimeValidationIssue => ({
  stage,
  ruleId: finding.ruleId,
  severity: finding.severity,
  message: finding.message,
  nodeId: finding.nodeId ?? node?.id ?? null,
  nodeTitle: finding.nodeTitle ?? node?.title ?? null,
  docsBindings: finding.docsBindings,
  metadata: {
    failedConditionIds: finding.failedConditionIds,
    module: finding.module,
  },
});

const resolveValidationDecision = (report: {
  blocked: boolean;
  severityCounts: Record<'error' | 'warning' | 'info', number>;
  shouldWarn: boolean;
  failedRules: number;
}): RuntimeValidationResult['decision'] => {
  if (report.blocked || report.severityCounts.error > 0) return 'block';
  if (report.shouldWarn || report.failedRules > 0) return 'warn';
  return 'pass';
};

const resolveValidationMessage = (args: {
  stage: RuntimeValidationStage;
  node?: AiNode | null | undefined;
  decision: Exclude<RuntimeValidationResult['decision'], 'pass'>;
  issues: RuntimeValidationIssue[];
}): string => {
  const { stage, node, decision, issues } = args;
  const focus = node ? `node "${node.title ?? node.id}"` : 'graph';
  const stageLabel = buildStageLabel(stage);
  const firstMessage = issues[0]?.message;
  const prefix =
    decision === 'block'
      ? `Runtime validation blocked ${focus} during ${stageLabel}.`
      : `Runtime validation warning for ${focus} during ${stageLabel}.`;
  return firstMessage ? `${prefix} ${firstMessage}` : prefix;
};

export const createAiPathsRuntimeValidationMiddleware = ({
  config,
  nodes,
  edges,
  maxIssuesPerDecision,
}: CreateAiPathsRuntimeValidationMiddlewareInput): RuntimeValidationMiddleware | undefined => {
  const normalizedConfig = normalizeAiPathsValidationConfig(config);
  if (!normalizedConfig.enabled) return undefined;
  const validationEdges = buildRuntimeValidationEdges(nodes, edges);
  const runtimeValidationConfig = removeSatisfiedDatabaseWriteIdentityRule(
    normalizedConfig,
    nodes,
    validationEdges
  );

  const issueLimit =
    typeof maxIssuesPerDecision === 'number' && Number.isFinite(maxIssuesPerDecision)
      ? Math.max(1, Math.trunc(maxIssuesPerDecision))
      : DEFAULT_MAX_ISSUES_PER_DECISION;

  return ({ stage, node, nodeInputs, nodeOutputs }): RuntimeValidationResult | null => {
    const builtInIssues = buildBuiltInContractIssues({
      stage,
      node,
      nodeInputs,
      nodeOutputs,
    });
    const rawReport = evaluateAiPathsValidationAtStage({
      nodes,
      edges: validationEdges,
      config: runtimeValidationConfig,
      stage,
      ...(node ? { node } : {}),
    });
    const normalizedFindings = rawReport.findings.map(normalizeRuntimeValidationFinding);
    const report = buildReportFromFilteredFindings(
      {
        ...rawReport,
        findings: normalizedFindings,
      },
      filterRuntimeValidationFindings(normalizedFindings, nodes, validationEdges)
    );

    const hasRuleFailures = report.enabled && report.rulesEvaluated > 0 && report.failedRules > 0;
    if (!hasRuleFailures && builtInIssues.length === 0) {
      return null;
    }

    const decision = builtInIssues.length > 0 ? 'block' : resolveValidationDecision(report);
    if (decision === 'pass' && builtInIssues.length === 0) {
      return null;
    }

    const issues = [
      ...builtInIssues,
      ...(hasRuleFailures
        ? report.findings.map(
          (finding: AiPathsValidationFinding): RuntimeValidationIssue =>
            toRuntimeValidationIssue(finding, stage, node)
        )
        : []),
    ].slice(0, issueLimit);

    return {
      decision,
      message:
        builtInIssues[0]?.message ??
        resolveValidationMessage({
          stage,
          node,
          decision: decision as 'block' | 'warn',
          issues,
        }),
      issues,
    };
  };
};

export const resolveAiPathsRuntimeValidationMiddleware = (
  input: ResolveAiPathsRuntimeValidationMiddlewareInput
): RuntimeValidationMiddleware | undefined => {
  const override = input.validationMiddleware;
  if (typeof override === 'function') {
    return override;
  }
  if (input.runtimeValidationEnabled === false) {
    return undefined;
  }
  return createAiPathsRuntimeValidationMiddleware({
    config: input.runtimeValidationConfig ?? null,
    nodes: input.nodes,
    edges: input.edges,
    maxIssuesPerDecision: input.maxIssuesPerDecision,
  });
};

import type {
  AiPathRunEventRecord,
  AiPathRunNodeRecord,
  AiPathRunRecord,
} from '@/shared/contracts/ai-paths';

export type AiPathErrorSeverity = 'info' | 'warning' | 'error' | 'fatal';
export type AiPathErrorScope =
  | 'enqueue'
  | 'run'
  | 'node'
  | 'portable_engine'
  | 'stream'
  | 'api'
  | 'unknown';

export type AiPathErrorReport = {
  version: 1;
  code: string;
  category: string;
  severity: AiPathErrorSeverity;
  scope: AiPathErrorScope;
  message: string;
  userMessage: string;
  timestamp: string;
  traceId: string | null;
  runId: string | null;
  nodeId: string | null;
  nodeType: string | null;
  nodeTitle: string | null;
  attempt: number | null;
  iteration: number | null;
  retryable: boolean;
  retryAfterMs: number | null;
  statusCode: number | null;
  cause: string | null;
  causeChain: string[];
  hints: string[];
  metadata: Record<string, unknown> | null;
};

export type AiPathRunErrorSummaryCode = {
  code: string;
  count: number;
};

export type AiPathRunErrorSummaryNode = {
  nodeId: string;
  nodeType: string | null;
  nodeTitle: string | null;
  code: string | null;
  message: string | null;
  count: number;
  lastAt: string | null;
};

export type AiPathRunErrorSummary = {
  totalErrors: number;
  reportCount: number;
  retryable: boolean;
  lastErrorAt: string | null;
  primary: AiPathErrorReport | null;
  codes: AiPathRunErrorSummaryCode[];
  nodeFailures: AiPathRunErrorSummaryNode[];
};

type BuildAiPathErrorReportInput = {
  error: unknown;
  code?: string | null;
  category?: string | null;
  severity?: AiPathErrorSeverity | null;
  scope?: AiPathErrorScope | null;
  userMessage?: string | null;
  timestamp?: string | Date | null;
  traceId?: string | null;
  runId?: string | null;
  nodeId?: string | null;
  nodeType?: string | null;
  nodeTitle?: string | null;
  attempt?: number | null;
  iteration?: number | null;
  retryable?: boolean | null;
  retryAfterMs?: number | null;
  statusCode?: number | null;
  hints?: readonly string[] | null;
  metadata?: Record<string, unknown> | null;
};

const MAX_CAUSE_DEPTH = 5;

const isRecord = (value: unknown): value is Record<string, unknown> =>
  Boolean(value) && typeof value === 'object' && !Array.isArray(value);

const toNonEmptyString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const toOptionalFiniteNumber = (value: unknown): number | null =>
  typeof value === 'number' && Number.isFinite(value) ? value : null;

const normalizeCode = (value: string | null | undefined, fallback: string): string => {
  const normalized = toNonEmptyString(value)?.toUpperCase() ?? fallback;
  return normalized.replace(/[^A-Z0-9_]+/g, '_');
};

const normalizeSeverity = (value: unknown, fallback: AiPathErrorSeverity): AiPathErrorSeverity => {
  if (value === 'info' || value === 'warning' || value === 'error' || value === 'fatal') {
    return value;
  }
  if (value === 'warn') return 'warning';
  return fallback;
};

const normalizeScope = (value: unknown): AiPathErrorScope => {
  if (
    value === 'enqueue' ||
    value === 'run' ||
    value === 'node' ||
    value === 'portable_engine' ||
    value === 'stream' ||
    value === 'api'
  ) {
    return value;
  }
  return 'unknown';
};

const toIsoTimestamp = (value: unknown): string => {
  if (typeof value === 'string') {
    const parsed = new Date(value);
    if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();
  }
  if (value instanceof Date && !Number.isNaN(value.getTime())) return value.toISOString();
  return new Date().toISOString();
};

const toErrorMessage = (error: unknown): string => {
  if (error instanceof Error && error.message.trim().length > 0) {
    return error.message.trim();
  }
  if (typeof error === 'string' && error.trim().length > 0) {
    return error.trim();
  }
  return String(error);
};

const readCause = (value: unknown): unknown => {
  if (!isRecord(value)) return undefined;
  return value['cause'];
};

const toCauseChain = (error: unknown): string[] => {
  const chain: string[] = [];
  const seen = new WeakSet<object>();
  let cursor = readCause(error);

  while (cursor !== undefined && cursor !== null && chain.length < MAX_CAUSE_DEPTH) {
    if (typeof cursor === 'object' && cursor !== null) {
      if (seen.has(cursor)) {
        chain.push('Circular cause reference.');
        break;
      }
      seen.add(cursor);
    }

    const causeMessage = toErrorMessage(cursor);
    chain.push(causeMessage);
    cursor = readCause(cursor);
  }

  return chain;
};

const inferRetryable = (error: unknown): boolean => {
  if (!isRecord(error)) return false;
  if (typeof error['retryable'] === 'boolean') return error['retryable'];
  if (typeof error['code'] === 'string') {
    const code = error['code'].toUpperCase();
    if (code.includes('TIMEOUT') || code.includes('RATE_LIMIT') || code.includes('UNAVAILABLE')) {
      return true;
    }
  }
  return false;
};

const toHints = (value: unknown): string[] => {
  if (!Array.isArray(value)) return [];
  return value
    .map((entry: unknown): string | null => toNonEmptyString(entry))
    .filter((entry: string | null): entry is string => Boolean(entry));
};

export const buildAiPathErrorReport = (input: BuildAiPathErrorReportInput): AiPathErrorReport => {
  const message = toErrorMessage(input.error);
  const causeChain = toCauseChain(input.error);
  const reportCause = causeChain[0] ?? null;
  const retryable = input.retryable ?? inferRetryable(input.error);

  return {
    version: 1,
    code: normalizeCode(input.code ?? null, 'AI_PATHS_RUNTIME_UNHANDLED_ERROR'),
    category: toNonEmptyString(input.category) ?? 'runtime',
    severity: normalizeSeverity(input.severity, 'error'),
    scope: normalizeScope(input.scope),
    message,
    userMessage: toNonEmptyString(input.userMessage) ?? message,
    timestamp: toIsoTimestamp(input.timestamp),
    traceId: toNonEmptyString(input.traceId),
    runId: toNonEmptyString(input.runId),
    nodeId: toNonEmptyString(input.nodeId),
    nodeType: toNonEmptyString(input.nodeType),
    nodeTitle: toNonEmptyString(input.nodeTitle),
    attempt: toOptionalFiniteNumber(input.attempt),
    iteration: toOptionalFiniteNumber(input.iteration),
    retryable,
    retryAfterMs: toOptionalFiniteNumber(input.retryAfterMs),
    statusCode: toOptionalFiniteNumber(input.statusCode),
    cause: reportCause,
    causeChain,
    hints: input.hints ? toHints(input.hints) : [],
    metadata: input.metadata ?? null,
  };
};

export const parseAiPathErrorReport = (value: unknown): AiPathErrorReport | null => {
  if (!isRecord(value)) return null;
  const code = normalizeCode(toNonEmptyString(value['code']), 'AI_PATHS_RUNTIME_UNHANDLED_ERROR');
  const message = toNonEmptyString(value['message']);
  if (!message) return null;

  return {
    version: 1,
    code,
    category: toNonEmptyString(value['category']) ?? 'runtime',
    severity: normalizeSeverity(value['severity'], 'error'),
    scope: normalizeScope(value['scope']),
    message,
    userMessage: toNonEmptyString(value['userMessage']) ?? message,
    timestamp: toIsoTimestamp(value['timestamp']),
    traceId: toNonEmptyString(value['traceId']),
    runId: toNonEmptyString(value['runId']),
    nodeId: toNonEmptyString(value['nodeId']),
    nodeType: toNonEmptyString(value['nodeType']),
    nodeTitle: toNonEmptyString(value['nodeTitle']),
    attempt: toOptionalFiniteNumber(value['attempt']),
    iteration: toOptionalFiniteNumber(value['iteration']),
    retryable: value['retryable'] === true,
    retryAfterMs: toOptionalFiniteNumber(value['retryAfterMs']),
    statusCode: toOptionalFiniteNumber(value['statusCode']),
    cause: toNonEmptyString(value['cause']),
    causeChain: toHints(value['causeChain']),
    hints: toHints(value['hints']),
    metadata: isRecord(value['metadata']) ? value['metadata'] : null,
  };
};

const toEventFallbackSeverity = (level: AiPathRunEventRecord['level']): AiPathErrorSeverity => {
  if (level === 'fatal') return 'fatal';
  if (level === 'warn') return 'warning';
  return 'error';
};

const toEventReport = (event: AiPathRunEventRecord): AiPathErrorReport | null => {
  const metadata = isRecord(event.metadata) ? event.metadata : null;
  const existing = parseAiPathErrorReport(metadata?.['errorReport']);
  if (existing) {
    return {
      ...existing,
      timestamp: toIsoTimestamp(event.createdAt ?? existing.timestamp),
      runId: toNonEmptyString(event.runId) ?? existing.runId,
      nodeId: toNonEmptyString(event.nodeId) ?? existing.nodeId,
      nodeType: toNonEmptyString(event.nodeType) ?? existing.nodeType,
      nodeTitle: toNonEmptyString(event.nodeTitle) ?? existing.nodeTitle,
    };
  }

  if (event.level !== 'error' && event.level !== 'fatal' && event.level !== 'warn') {
    return null;
  }

  return buildAiPathErrorReport({
    error: event.message,
    code:
      toNonEmptyString(metadata?.['errorCode']) ??
      (event.level === 'warn' ? 'AI_PATHS_RUNTIME_WARNING_EVENT' : 'AI_PATHS_RUNTIME_EVENT_ERROR'),
    category: toNonEmptyString(metadata?.['errorCategory']) ?? 'runtime',
    severity: toEventFallbackSeverity(event.level),
    scope: event.nodeId ? 'node' : 'run',
    timestamp: event.createdAt,
    runId: event.runId,
    nodeId: event.nodeId ?? null,
    nodeType: event.nodeType ?? null,
    nodeTitle: event.nodeTitle ?? null,
    attempt: toOptionalFiniteNumber(metadata?.['attempt']),
    iteration: event.iteration ?? toOptionalFiniteNumber(metadata?.['iteration']),
    retryable: metadata?.['retryable'] === true,
    retryAfterMs: toOptionalFiniteNumber(metadata?.['retryAfterMs']),
    statusCode: toOptionalFiniteNumber(metadata?.['statusCode']),
    hints: toHints(metadata?.['hints']),
    metadata,
  });
};

const toRunFallbackReport = (run: AiPathRunRecord): AiPathErrorReport | null => {
  const message = toNonEmptyString(run.errorMessage) ?? toNonEmptyString(run.error);
  if (!message) return null;
  return buildAiPathErrorReport({
    error: message,
    code: 'AI_PATHS_RUN_FAILED',
    category: 'runtime',
    severity: 'error',
    scope: 'run',
    timestamp: run.finishedAt ?? run.updatedAt ?? run.createdAt,
    runId: run.id,
    traceId:
      isRecord(run.meta) && typeof run.meta['traceId'] === 'string' ? run.meta['traceId'] : run.id,
    retryable: false,
    retryAfterMs: null,
    metadata: null,
  });
};

const toNodeFallbackReports = (nodes: AiPathRunNodeRecord[], runId: string): AiPathErrorReport[] =>
  nodes
    .filter(
      (node: AiPathRunNodeRecord): boolean =>
        node.status === 'failed' || node.status === 'blocked' || node.status === 'timeout'
    )
    .map(
      (node: AiPathRunNodeRecord): AiPathErrorReport => {
        const isBlocked = node.status === 'blocked';
        const isTimeout = node.status === 'timeout';
        const code = isBlocked
          ? 'AI_PATHS_NODE_BLOCKED'
          : isTimeout
            ? 'AI_PATHS_NODE_TIMEOUT'
            : 'AI_PATHS_NODE_FAILED';
        const fallbackMessage = isBlocked
          ? 'Node blocked without completing.'
          : isTimeout
            ? 'Node timed out without completing.'
            : 'Node failed without an explicit error message.';
        return buildAiPathErrorReport({
          error:
            toNonEmptyString(node.errorMessage) ??
            toNonEmptyString(node.error) ??
            fallbackMessage,
          code,
          category: 'runtime',
          severity: 'error',
          scope: 'node',
          timestamp: node.finishedAt ?? node.updatedAt ?? node.createdAt,
          runId,
          nodeId: node.nodeId,
          nodeType: node.nodeType,
          nodeTitle: node.nodeTitle ?? null,
          attempt: node.attempt,
        });
      }
    );

const compareReports = (left: AiPathErrorReport, right: AiPathErrorReport): number => {
  const leftTime = Date.parse(left.timestamp);
  const rightTime = Date.parse(right.timestamp);
  if (Number.isFinite(leftTime) && Number.isFinite(rightTime) && leftTime !== rightTime) {
    return leftTime - rightTime;
  }
  return left.code.localeCompare(right.code);
};

const dedupeReports = (reports: AiPathErrorReport[]): AiPathErrorReport[] => {
  const deduped: AiPathErrorReport[] = [];
  const keys = new Set<string>();
  reports.forEach((report: AiPathErrorReport) => {
    const key = [
      report.code,
      report.message,
      report.timestamp,
      report.nodeId ?? '',
      report.runId ?? '',
    ].join('|');
    if (keys.has(key)) return;
    keys.add(key);
    deduped.push(report);
  });
  return deduped;
};

export const buildAiPathRunErrorSummary = (input: {
  run: AiPathRunRecord;
  nodes: AiPathRunNodeRecord[];
  events: AiPathRunEventRecord[];
}): AiPathRunErrorSummary | null => {
  const eventReports = input.events
    .map((event: AiPathRunEventRecord): AiPathErrorReport | null => toEventReport(event))
    .filter((report: AiPathErrorReport | null): report is AiPathErrorReport => Boolean(report));
  const runReport = toRunFallbackReport(input.run);
  const nodeFallbackReports = toNodeFallbackReports(input.nodes, input.run.id);
  const reports = dedupeReports(
    [...eventReports, ...(runReport ? [runReport] : []), ...nodeFallbackReports].sort(
      compareReports
    )
  );

  if (reports.length === 0) return null;

  const primary = reports[reports.length - 1] ?? null;
  const codeMap = new Map<string, number>();
  const nodeMap = new Map<string, AiPathRunErrorSummaryNode>();

  reports.forEach((report: AiPathErrorReport) => {
    codeMap.set(report.code, (codeMap.get(report.code) ?? 0) + 1);
    if (!report.nodeId) return;
    const key = report.nodeId;
    const previous = nodeMap.get(key);
    if (!previous) {
      nodeMap.set(key, {
        nodeId: report.nodeId,
        nodeType: report.nodeType,
        nodeTitle: report.nodeTitle,
        code: report.code,
        message: report.userMessage,
        count: 1,
        lastAt: report.timestamp,
      });
      return;
    }
    nodeMap.set(key, {
      ...previous,
      count: previous.count + 1,
      code: report.code ?? previous.code,
      message: report.userMessage ?? previous.message,
      lastAt: report.timestamp,
    });
  });

  const codes = Array.from(codeMap.entries())
    .map(([code, count]): AiPathRunErrorSummaryCode => ({ code, count }))
    .sort((left, right) => {
      if (right.count !== left.count) return right.count - left.count;
      return left.code.localeCompare(right.code);
    })
    .slice(0, 10);
  const nodeFailures = Array.from(nodeMap.values())
    .sort((left, right) => {
      if (right.count !== left.count) return right.count - left.count;
      return left.nodeId.localeCompare(right.nodeId);
    })
    .slice(0, 10);

  const totalErrors = reports.filter(
    (report: AiPathErrorReport): boolean =>
      report.severity === 'error' || report.severity === 'fatal'
  ).length;

  return {
    totalErrors,
    reportCount: reports.length,
    retryable: reports.some((report: AiPathErrorReport): boolean => report.retryable),
    lastErrorAt: primary?.timestamp ?? null,
    primary,
    codes,
    nodeFailures,
  };
};

export const parseAiPathRunErrorSummary = (value: unknown): AiPathRunErrorSummary | null => {
  if (!isRecord(value)) return null;
  const primary = parseAiPathErrorReport(value['primary']);
  const codesRaw = Array.isArray(value['codes']) ? value['codes'] : [];
  const codes: AiPathRunErrorSummaryCode[] = codesRaw
    .map((entry: unknown): AiPathRunErrorSummaryCode | null => {
      if (!isRecord(entry)) return null;
      const code = toNonEmptyString(entry['code']);
      const count = toOptionalFiniteNumber(entry['count']);
      if (!code || count === null) return null;
      return { code, count };
    })
    .filter((entry: AiPathRunErrorSummaryCode | null): entry is AiPathRunErrorSummaryCode =>
      Boolean(entry)
    );
  const nodeRaw = Array.isArray(value['nodeFailures']) ? value['nodeFailures'] : [];
  const nodeFailures: AiPathRunErrorSummaryNode[] = nodeRaw
    .map((entry: unknown): AiPathRunErrorSummaryNode | null => {
      if (!isRecord(entry)) return null;
      const nodeId = toNonEmptyString(entry['nodeId']);
      const count = toOptionalFiniteNumber(entry['count']);
      if (!nodeId || count === null) return null;
      return {
        nodeId,
        nodeType: toNonEmptyString(entry['nodeType']),
        nodeTitle: toNonEmptyString(entry['nodeTitle']),
        code: toNonEmptyString(entry['code']),
        message: toNonEmptyString(entry['message']),
        count,
        lastAt: toNonEmptyString(entry['lastAt']),
      };
    })
    .filter((entry: AiPathRunErrorSummaryNode | null): entry is AiPathRunErrorSummaryNode =>
      Boolean(entry)
    );

  return {
    totalErrors: toOptionalFiniteNumber(value['totalErrors']) ?? 0,
    reportCount: toOptionalFiniteNumber(value['reportCount']) ?? 0,
    retryable: value['retryable'] === true,
    lastErrorAt: toNonEmptyString(value['lastErrorAt']),
    primary,
    codes,
    nodeFailures,
  };
};

import type React from 'react';

import type { AiNode } from '@/shared/contracts/ai-paths';
import { type TriggerEventEntityType } from '@/shared/contracts/ai-trigger-buttons';

import {
  resolveTriggerEntitySnapshotMode,
  sanitizeTriggerEntitySnapshot,
  shouldEmbedTriggerEntitySnapshot,
} from './trigger-event-sanitization';

export const buildTriggerContext = (args: {
  triggerNode: AiNode;
  triggerEventId: string;
  triggerLabel?: string | null | undefined;
  entityType: TriggerEventEntityType;
  entityId?: string | null | undefined;
  entityJson?: Record<string, unknown> | null;
  event?: React.MouseEvent;
  pathInfo?: { id?: string | undefined; name?: string | undefined } | null | undefined;
  source?:
    | { tab?: string | undefined; location?: string | undefined; page?: string | undefined }
    | null
    | undefined;
  extras?: Record<string, unknown> | null | undefined;
}): Record<string, unknown> => {
  const timestamp = new Date().toISOString();
  const sanitizedEntitySnapshot = sanitizeTriggerEntitySnapshot(args.entityJson);
  const shouldEmbedEntitySnapshot =
    sanitizedEntitySnapshot !== null &&
    shouldEmbedTriggerEntitySnapshot({
      mode: resolveTriggerEntitySnapshotMode(args.triggerNode.config?.trigger?.entitySnapshotMode),
      entityType: args.entityType,
      entityId: args.entityId,
      sourceLocation: args.source?.location,
    });
  const embeddedEntitySnapshot = shouldEmbedEntitySnapshot ? sanitizedEntitySnapshot : null;
  const shouldOmitDuplicateEntitySnapshot =
    args.entityType === 'custom' &&
    args.source?.location === 'filemaker_organization_job_application';
  const nativeEvent = args.event?.nativeEvent;
  const pointer = nativeEvent
    ? {
      clientX: nativeEvent.clientX,
      clientY: nativeEvent.clientY,
      pageX: nativeEvent.pageX,
      pageY: nativeEvent.pageY,
      screenX: nativeEvent.screenX,
      screenY: nativeEvent.screenY,
      offsetX: nativeEvent.offsetX,
      offsetY: nativeEvent.offsetY,
      button: nativeEvent.button,
      buttons: nativeEvent.buttons,
      altKey: nativeEvent.altKey,
      ctrlKey: nativeEvent.ctrlKey,
      shiftKey: nativeEvent.shiftKey,
      metaKey: nativeEvent.metaKey,
    }
    : undefined;

  const location =
    typeof window !== 'undefined'
      ? {
        href: window.location.href,
        origin: window.location.origin,
        pathname: window.location.pathname,
        search: window.location.search,
        hash: window.location.hash,
        referrer: document.referrer || undefined,
      }
      : {};

  const ui =
    typeof window !== 'undefined'
      ? {
        viewport: {
          width: window.innerWidth,
          height: window.innerHeight,
          devicePixelRatio: window.devicePixelRatio,
        },
        screen: {
          width: window.screen?.width,
          height: window.screen?.height,
          availWidth: window.screen?.availWidth,
          availHeight: window.screen?.availHeight,
        },
        userAgent: navigator.userAgent,
        platform: navigator.platform,
        language: navigator.language,
        languages: navigator.languages,
        timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone,
        documentTitle: document.title,
        visibilityState: document.visibilityState,
        scroll: {
          x: window.scrollX,
          y: window.scrollY,
        },
      }
      : {};

  const base: Record<string, unknown> = {
    timestamp,
    location,
    ui,
    user: null,
    event: {
      id: args.triggerEventId,
      nodeId: args.triggerNode.id,
      nodeTitle: args.triggerNode.title,
      type: args.event?.type,
      pointer,
    },
    source: {
      pathId: args.pathInfo?.id,
      pathName: args.pathInfo?.name ?? 'AI Trigger Button',
      tab: args.source?.tab ?? args.entityType,
      location: args.source?.location ?? null,
      page: args.source?.page ?? null,
    },
    extras: {
      triggerLabel: args.triggerLabel ?? null,
      ...(args.extras ?? {}),
    },
    entityId: args.entityId ?? null,
    entityType: args.entityType,
    entity: shouldOmitDuplicateEntitySnapshot ? null : embeddedEntitySnapshot,
    ...(embeddedEntitySnapshot ? { entityJson: embeddedEntitySnapshot } : {}),
    ...(embeddedEntitySnapshot && args.entityType === 'product' && args.entityId
      ? { productId: args.entityId }
      : {}),
  };

  return base;
};

