import { type QueryClient } from '@tanstack/react-query';

import type { AiPathRunRecord } from '@/shared/contracts/ai-paths';
import { type TriggerEventEntityType } from '@/shared/contracts/ai-trigger-buttons';
import {
  invalidateAiPathQueue,
  invalidateNotes,
  notifyAiPathRunEnqueued,
  invalidateProductDetail,
  invalidateIntegrationJobs,
} from '@/shared/lib/query-invalidation';

const buildAiPathTriggerNotificationPayload = (args: {
  entityId: string | null | undefined;
  entityType: TriggerEventEntityType;
  run?: AiPathRunRecord | null;
}) => ({
  entityId: args.entityId ?? null,
  entityType: args.entityType,
  run: args.run ?? null,
});

const invalidateAiPathTriggerEntity = (
  queryClient: QueryClient,
  entityType: TriggerEventEntityType,
  entityId: string | null | undefined
): void => {
  if (entityType === 'product' && entityId) {
    void invalidateProductDetail(queryClient, entityId);
    return;
  }
  if (entityType === 'note') {
    void invalidateNotes(queryClient);
    return;
  }

  // @ts-ignore - integration is a valid entity type in the contract but TypeScript is being overly restrictive here.
  if (entityType === 'integration') {
    void invalidateIntegrationJobs(queryClient);
  }
};

export const handleAiPathTriggerInvalidation = async (args: {
  queryClient: QueryClient;
  runId: string;
  run?: AiPathRunRecord | null;
  entityType: TriggerEventEntityType;
  entityId: string | null | undefined;
}): Promise<void> => {
  const { queryClient, runId, run, entityType, entityId } = args;

  void invalidateAiPathQueue(queryClient);

  notifyAiPathRunEnqueued(
    runId,
    buildAiPathTriggerNotificationPayload({ entityId, entityType, run })
  );
  invalidateAiPathTriggerEntity(queryClient, entityType, entityId);
};

import type { TriggerEntitySnapshotMode } from '@/shared/contracts/ai-paths-core/nodes-primitives';
import { type TriggerEventEntityType } from '@/shared/contracts/ai-trigger-buttons';

import { toRecord } from './trigger-event-utils';

export const TRIGGER_ENTITY_SNAPSHOT_MAX_DEPTH = 10;
export const TRIGGER_ENTITY_OMITTED_VALUE = '[omitted_large_field]';
export const TRIGGER_ENTITY_HEAVY_KEY_PATTERNS: RegExp[] = [
  /^imagebase64s?$/i,
  /^base64s?$/i,
  /(?:^|[_-])base64(?:$|[_-])/i,
  /(?:^|[_-])binary(?:$|[_-])/i,
  /(?:^|[_-])buffer(?:$|[_-])/i,
  /(?:^|[_-])blob(?:$|[_-])/i,
  /(?:^|[_-])arraybuffer(?:$|[_-])/i,
];

export const shouldOmitTriggerEntityKey = (key: string): boolean =>
  TRIGGER_ENTITY_HEAVY_KEY_PATTERNS.some((pattern) => pattern.test(key));

export const isBase64DataUrl = (value: string): boolean =>
  /^data:[^;]+;base64,/i.test(value.trim());

export const sanitizeTriggerEntityValue = (
  value: unknown,
  depth: number,
  key?: string
): unknown => {
  if (value === null || value === undefined) return value;
  if (typeof value === 'string') {
    if ((key && shouldOmitTriggerEntityKey(key)) || isBase64DataUrl(value)) {
      return TRIGGER_ENTITY_OMITTED_VALUE;
    }
    return value;
  }
  if (typeof value === 'number' || typeof value === 'boolean') return value;
  if (Array.isArray(value)) {
    return value
      .map((item: unknown) => sanitizeTriggerEntityValue(item, depth + 1, key))
      .filter((item: unknown) => item !== undefined);
  }
  if (typeof value !== 'object') return undefined;
  if (depth >= TRIGGER_ENTITY_SNAPSHOT_MAX_DEPTH) {
    return {};
  }

  const next: Record<string, unknown> = {};
  Object.entries(value as Record<string, unknown>).forEach(([entryKey, entryValue]) => {
    if (shouldOmitTriggerEntityKey(entryKey)) return;
    const sanitized = sanitizeTriggerEntityValue(entryValue, depth + 1, entryKey);
    if (sanitized !== undefined) {
      next[entryKey] = sanitized;
    }
  });
  return next;
};

export const sanitizeTriggerEntitySnapshot = (
  entityJson?: Record<string, unknown> | null
): Record<string, unknown> | null => {
  if (!entityJson) return null;
  return toRecord(sanitizeTriggerEntityValue(entityJson, 0));
};

export const resolveTriggerEntitySnapshotMode = (
  value: unknown
): TriggerEntitySnapshotMode => {
  if (value === 'always' || value === 'never' || value === 'auto') {
    return value;
  }
  return 'auto';
};

export const shouldEmbedTriggerEntitySnapshot = (args: {
  mode?: TriggerEntitySnapshotMode | null | undefined;
  entityType: TriggerEventEntityType;
  entityId?: string | null | undefined;
  sourceLocation?: string | null | undefined;
}): boolean => {
  const mode = resolveTriggerEntitySnapshotMode(args.mode);
  if (mode === 'always') return true;
  if (mode === 'never') return false;

  const normalizedSourceLocation =
    typeof args.sourceLocation === 'string' ? args.sourceLocation.trim().toLowerCase() : null;
  if (args.entityType === 'custom') return true;
  if (
    normalizedSourceLocation === 'product_modal' ||
    normalizedSourceLocation === 'product_row' ||
    normalizedSourceLocation === 'product_marketplace_copy_row' ||
    normalizedSourceLocation === 'product_parameter_row' ||
    normalizedSourceLocation === 'note_modal'
  ) {
    return true;
  }
  return typeof args.entityId !== 'string' || args.entityId.trim().length === 0;
};

import type { AiNode, PathConfig } from '@/shared/contracts/ai-paths';
import {
  AI_PATHS_UI_STATE_KEY,
  PATH_CONFIG_PREFIX,
  TRIGGER_EVENTS,
} from '@/shared/lib/ai-paths/core/constants';
import { safeParseJson } from '@/shared/lib/ai-paths/core/utils/runtime';

import { loadPathConfigsFromSettings, loadTriggerPathConfigCached } from './trigger-event-settings';

export type TriggerSelectionCandidate = Pick<PathConfig, 'id' | 'isActive'>;

const parseUiState = (
  settingsData: Array<{ key: string; value: string }>
): Record<string, unknown> | null => {
  const map = new Map<string, string>(
    settingsData.map((item: { key: string; value: string }) => [item.key, item.value])
  );
  const uiStateRaw = map.get(AI_PATHS_UI_STATE_KEY);
  const uiStateEnvelope = uiStateRaw ? safeParseJson<{ value?: unknown }>(uiStateRaw).value : null;
  const uiStateParsed =
    uiStateEnvelope && typeof uiStateEnvelope === 'object' ? uiStateEnvelope['value'] : null;
  return uiStateParsed && typeof uiStateParsed === 'object'
    ? (uiStateParsed as Record<string, unknown>)
    : null;
};

const matchesTriggerEvent = (config: PathConfig, triggerEventId: string): boolean => {
  const fallbackTriggerEventId = (TRIGGER_EVENTS[0]?.id as string) ?? 'manual';
  return Array.isArray(config?.nodes)
    ? config.nodes.some((node: AiNode) => {
      if (node.type !== 'trigger') return false;
      const configuredEvent = node.config?.trigger?.event ?? fallbackTriggerEventId;
      return configuredEvent === triggerEventId;
    })
    : false;
};

export const selectTriggerCandidates = <T extends TriggerSelectionCandidate>(args: {
  triggerCandidates: T[];
  preferredPathId: string | null;
  activePathId: string | null;
}): {
  activeTriggerCandidates: T[];
  selectedConfig: T | null;
  missingPreferredPathId: string | null;
} => {
  const { triggerCandidates, preferredPathId, activePathId } = args;
  const activeTriggerCandidates: T[] = triggerCandidates.filter(
    (config: T): boolean => config.isActive !== false
  );

  const preferredByButton = preferredPathId
    ? (triggerCandidates.find((config: T): boolean => config.id === preferredPathId) ?? null)
    : null;

  if (preferredPathId) {
    if (preferredByButton) {
      return {
        activeTriggerCandidates,
        selectedConfig: preferredByButton,
        missingPreferredPathId: null,
      };
    }

    return {
      activeTriggerCandidates,
      selectedConfig: null,
      missingPreferredPathId: preferredPathId,
    };
  }

  const preferredByActivePath = activePathId
    ? (activeTriggerCandidates.find((config: T): boolean => config.id === activePathId) ?? null)
    : null;

  if (activeTriggerCandidates.length > 1 && !preferredByActivePath) {
    return {
      activeTriggerCandidates,
      selectedConfig: null,
      missingPreferredPathId: null,
    };
  }

  return {
    activeTriggerCandidates,
    selectedConfig:
      preferredByActivePath ?? activeTriggerCandidates[0] ?? triggerCandidates[0] ?? null,
    missingPreferredPathId: null,
  };
};

export const resolveTriggerSelection = async (
  settingsData: Array<{ key: string; value: string }>,
  triggerEventId: string,
  options?: {
    preferredPathId?: string | null | undefined;
    preferredActivePathId?: string | null | undefined;
  }
): Promise<{
  triggerCandidates: PathConfig[];
  activeTriggerCandidates: PathConfig[];
  selectedConfig: PathConfig | null;
  uiState: Record<string, unknown> | null;
  missingPreferredPathId: string | null;
}> => {
  const preferredPathId =
    typeof options?.preferredPathId === 'string' && options.preferredPathId.trim().length > 0
      ? options.preferredPathId.trim()
      : null;
  const uiState = parseUiState(settingsData);

  if (preferredPathId) {
    const configKey = `${PATH_CONFIG_PREFIX}${preferredPathId}`;
    const configRaw =
      settingsData.find((item: { key: string }) => item.key === configKey)?.value ?? null;
    if (!configRaw?.trim()) {
      return {
        triggerCandidates: [],
        activeTriggerCandidates: [],
        selectedConfig: null,
        uiState,
        missingPreferredPathId: preferredPathId,
      };
    }

    const selectedConfig = loadTriggerPathConfigCached({
      pathId: preferredPathId,
      rawConfig: configRaw,
    });
    const triggerCandidates = matchesTriggerEvent(selectedConfig, triggerEventId)
      ? [selectedConfig]
      : [];

    return {
      triggerCandidates,
      activeTriggerCandidates:
        selectedConfig.isActive !== false && triggerCandidates.length > 0 ? [selectedConfig] : [],
      selectedConfig: triggerCandidates[0] ?? null,
      uiState,
      missingPreferredPathId: triggerCandidates.length > 0 ? null : preferredPathId,
    };
  }

  const activePathId =
    (typeof options?.preferredActivePathId === 'string' &&
    options.preferredActivePathId.trim().length > 0
      ? options.preferredActivePathId.trim()
      : null) ??
    (typeof uiState?.['activePathId'] === 'string' && uiState['activePathId'].trim().length > 0
      ? uiState['activePathId'].trim()
      : null);

  const { configs, settingsPathOrder } = await loadPathConfigsFromSettings(settingsData);
  const configsList: PathConfig[] = Object.values(configs);
  const pathOrder: string[] = settingsPathOrder;
  const orderedConfigs: PathConfig[] = pathOrder.length
    ? pathOrder
      .map((id: string) => configs[id])
      .filter((config: PathConfig | undefined): config is PathConfig => Boolean(config))
    : configsList;
  const triggerCandidates = orderedConfigs.filter((config: PathConfig) =>
    matchesTriggerEvent(config, triggerEventId)
  );
  const selection = selectTriggerCandidates<PathConfig>({
    triggerCandidates,
    preferredPathId: null,
    activePathId,
  });

  return {
    triggerCandidates,
    activeTriggerCandidates: selection.activeTriggerCandidates,
    selectedConfig: selection.selectedConfig,
    uiState,
    missingPreferredPathId: selection.missingPreferredPathId,
  };
};

import type { PathConfig, PathMeta } from '@/shared/contracts/ai-paths';
import type { RuntimeState } from '@/shared/contracts/ai-paths-runtime';
import { isAppError, validationError } from '@/shared/errors/app-error';
import {
  AI_PATHS_HISTORY_RETENTION_KEY,
  AI_PATHS_UI_STATE_KEY,
  PATH_CONFIG_PREFIX,
  PATH_INDEX_KEY,
} from '@/shared/lib/ai-paths/core/constants';
import {
  normalizeLoadedPathMetas,
  sanitizeTriggerPathConfig,
} from '@/shared/lib/ai-paths/core/normalization/trigger-normalization';
import { materializeStoredTriggerPathConfig } from '@/shared/lib/ai-paths/core/normalization/stored-trigger-path-config';
import {
  fetchAiPathsSettingsCached,
  fetchAiPathsSettingsByKeysCached,
} from '@/shared/lib/ai-paths/settings-store-client';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

export const TRIGGER_SETTINGS_PRELOAD_TIMEOUT_MS = 8_000;
const TRIGGER_PATH_CONFIG_CACHE_MAX_ENTRIES = 64;
const triggerPathConfigCache = new Map<string, { rawConfig: string; config: PathConfig }>();

const readTriggerPathConfigCache = (pathId: string, rawConfig: string): PathConfig | null => {
  const cached = triggerPathConfigCache.get(pathId) ?? null;
  if (cached?.rawConfig !== rawConfig) {
    return null;
  }
  triggerPathConfigCache.delete(pathId);
  triggerPathConfigCache.set(pathId, cached);
  return cached.config;
};

const writeTriggerPathConfigCache = (
  pathId: string,
  rawConfig: string,
  config: PathConfig
): void => {
  if (triggerPathConfigCache.has(pathId)) {
    triggerPathConfigCache.delete(pathId);
  }
  triggerPathConfigCache.set(pathId, { rawConfig, config });
  if (triggerPathConfigCache.size <= TRIGGER_PATH_CONFIG_CACHE_MAX_ENTRIES) {
    return;
  }
  const oldestKey = triggerPathConfigCache.keys().next().value;
  if (typeof oldestKey === 'string') {
    triggerPathConfigCache.delete(oldestKey);
  }
};

export const __resetTriggerPathConfigCacheForTests = (): void => {
  triggerPathConfigCache.clear();
};

export const loadTriggerPathConfigCached = (args: {
  pathId: string;
  rawConfig: string;
}): PathConfig => {
  const cached = readTriggerPathConfigCache(args.pathId, args.rawConfig);
  if (cached) {
    return cached;
  }
  const config = materializeStoredTriggerPathConfig({
    pathId: args.pathId,
    rawConfig: args.rawConfig,
    fallbackName: args.pathId,
    applyStarterWorkflowUpgrade: true,
  }).config;
  writeTriggerPathConfigCache(args.pathId, args.rawConfig, config);
  return config;
};

export const resolveRuntimeStateHint = (value: unknown): RuntimeState | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return null;
  }
  return value as RuntimeState;
};

export const coerceSampleStateMap = <T>(value: unknown): Record<string, T> | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return null;
  }
  return value as Record<string, T>;
};

export const resolvePreferredPathId = (value: string | null | undefined): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

export const buildSelectiveTriggerSettingsData = async (
  preferredPathId: string
): Promise<Array<{ key: string; value: string }>> => {
  const preferredConfigKey = `${PATH_CONFIG_PREFIX}${preferredPathId}`;
  const selectiveRecords = await fetchAiPathsSettingsByKeysCached(
    [AI_PATHS_HISTORY_RETENTION_KEY, AI_PATHS_UI_STATE_KEY, preferredConfigKey],
    { bypassCache: true, timeoutMs: TRIGGER_SETTINGS_PRELOAD_TIMEOUT_MS }
  );
  const configRecord =
    selectiveRecords.find((item: { key: string }) => item.key === preferredConfigKey) ?? null;
  if (!configRecord || typeof configRecord.value !== 'string' || configRecord.value.length === 0) {
    throw validationError(
      `Trigger button is bound to missing AI Path "${preferredPathId}". Update the button configuration.`,
      {
        source: 'ai_paths.trigger_payload',
        reason: 'preferred_path_config_missing',
        preferredPathId,
      }
    );
  }
  return selectiveRecords.filter(
    (item: { key: string }) =>
      item.key === AI_PATHS_HISTORY_RETENTION_KEY ||
      item.key === AI_PATHS_UI_STATE_KEY ||
      item.key === preferredConfigKey
  );
};

export const loadTriggerSettingsData = async (args: {
  preferredPathId?: string | null | undefined;
}): Promise<{
  mode: 'selective' | 'full';
  settingsData: Array<{ key: string; value: string }>;
}> => {
  const preferredPathId = resolvePreferredPathId(args.preferredPathId ?? null);
  if (!preferredPathId) {
    return {
      mode: 'full',
      settingsData: await fetchAiPathsSettingsCached(),
    };
  }

  try {
    return {
      mode: 'selective',
      settingsData: await buildSelectiveTriggerSettingsData(preferredPathId),
    };
  } catch (error) {
    if (isAppError(error)) {
      throw error;
    }
    logClientCatch(error, {
      source: 'useAiPathTriggerEvent',
      action: 'selectiveSettingsFallback',
      preferredPathId,
    });
    return {
      mode: 'full',
      settingsData: await fetchAiPathsSettingsCached(),
    };
  }
};

export const sanitizeLoadedPathConfig = (config: PathConfig): PathConfig =>
  sanitizeTriggerPathConfig(config);

export const loadPathConfigsFromSettings = async (
  settingsData?: Array<{ key: string; value: string }>
): Promise<{
  configs: Record<string, PathConfig>;
  settingsPathOrder: string[];
}> => {
  const data =
    settingsData ??
    (await (async (): Promise<Array<{ key: string; value: string }> | null> => {
      return await fetchAiPathsSettingsCached();
    })()) ??
    [];
  if (!data.length) return { configs: {}, settingsPathOrder: [] };

  const map = new Map<string, string>(
    data.map((item: { key: string; value: string }) => [item.key, item.value])
  );
  const indexRaw = map.get(PATH_INDEX_KEY);
  if (!indexRaw?.trim()) {
    return { configs: {}, settingsPathOrder: [] };
  }

  let parsedIndex: unknown;
  try {
    parsedIndex = JSON.parse(indexRaw) as unknown;
  } catch (error) {
    logClientCatch(error, {
      source: 'useAiPathTriggerEvent',
      action: 'parseSettingsIndex',
      indexKey: PATH_INDEX_KEY,
    });
    throw validationError('Invalid AI Paths index payload.', {
      source: 'ai_paths.trigger_payload',
      reason: 'index_invalid_json',
      cause: error instanceof Error ? error.message : 'unknown_error',
    });
  }
  if (!Array.isArray(parsedIndex)) {
    throw validationError('Invalid AI Paths index payload.', {
      source: 'ai_paths.trigger_payload',
      reason: 'index_not_array',
    });
  }

  const metas = parsedIndex.map((meta: unknown, index: number): PathMeta => {
    if (!meta || typeof meta !== 'object' || Array.isArray(meta)) {
      throw validationError('Invalid AI Paths index entry.', {
        source: 'ai_paths.trigger_payload',
        reason: 'index_entry_not_object',
        index,
      });
    }
    return meta as PathMeta;
  });
  const normalizedMetas = normalizeLoadedPathMetas(metas);
  const configs: Record<string, PathConfig> = {};
  const retainedMetas: PathMeta[] = [];
  let removedMissingConfigEntries = false;

  normalizedMetas.forEach((meta: PathMeta): void => {
    if (!meta?.id) return;
    const configKey = `${PATH_CONFIG_PREFIX}${meta.id}`;
    const configRaw = map.get(configKey);
    if (!configRaw?.trim()) {
      removedMissingConfigEntries = true;
      return;
    }

    const normalizedConfig = loadTriggerPathConfigCached({
      pathId: meta.id,
      rawConfig: configRaw,
    });

    configs[meta.id] = normalizedConfig;
    retainedMetas.push(meta);
  });

  const settingsPathOrder = (removedMissingConfigEntries ? retainedMetas : normalizedMetas)
    .map((meta: PathMeta) => meta?.id)
    .filter((id: string | undefined): id is string => typeof id === 'string' && id.length > 0);

  return { configs, settingsPathOrder };
};

import { type TriggerEventEntityType } from '@/shared/contracts/ai-trigger-buttons';

const MAX_TRIGGER_REQUEST_ID_LENGTH = 200;
const MIN_TRIGGER_ENTITY_PART_LENGTH = 16;

export const isTimeoutMessage = (message: string | null | undefined): boolean => {
  if (!message || typeof message !== 'string') return false;
  const normalized = message.toLowerCase();
  return normalized.includes('timed out') || normalized.includes('timeout');
};

const compactRequestIdPart = (value: string, maxLength: number): string => {
  if (value.length <= maxLength) return value;
  if (maxLength <= MIN_TRIGGER_ENTITY_PART_LENGTH) return value.slice(0, maxLength);
  const headLength = Math.ceil((maxLength - 2) * 0.6);
  const tailLength = Math.max(0, maxLength - headLength - 2);
  return `${value.slice(0, headLength)}--${value.slice(-tailLength)}`;
};

export const createAiPathTriggerRequestId = (args: {
  pathId: string;
  triggerEventId: string;
  entityType: TriggerEventEntityType;
  entityId?: string | null | undefined;
}): string => {
  const randomPart =
    typeof globalThis.crypto?.randomUUID === 'function'
      ? globalThis.crypto.randomUUID().replace(/-/g, '')
      : `${Math.random().toString(36).slice(2)}${Date.now().toString(36)}`;
  const entityPart =
    typeof args.entityId === 'string' && args.entityId.trim().length > 0
      ? args.entityId.trim()
      : 'entity';
  const prefix = `trigger:${args.pathId}:${args.triggerEventId}:${args.entityType}:`;
  const suffix = `:${randomPart}`;
  const entityPartMaxLength = Math.max(
    MIN_TRIGGER_ENTITY_PART_LENGTH,
    MAX_TRIGGER_REQUEST_ID_LENGTH - prefix.length - suffix.length
  );
  const requestId = `${prefix}${compactRequestIdPart(entityPart, entityPartMaxLength)}${suffix}`;
  if (requestId.length <= MAX_TRIGGER_REQUEST_ID_LENGTH) return requestId;
  return `${requestId.slice(
    0,
    Math.max(0, MAX_TRIGGER_REQUEST_ID_LENGTH - suffix.length)
  )}${suffix}`;
};

export const toNonEmptyString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

export const toRecord = (value: unknown): Record<string, unknown> | null =>
  value && typeof value === 'object' && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : null;

