  const updatedAt =
    typeof args.selectedConfig.updatedAt === 'string' && args.selectedConfig.updatedAt.trim().length > 0
      ? args.selectedConfig.updatedAt.trim()
      : 'unknown';
  return `${args.selectedConfig.id}::${updatedAt}::${args.triggerNodeId}`;
};

const readCachedPreflight = (
  cache: Map<string, CachedPreflightReport>,
  cacheKey: string
): CachedPreflightReport | null => {
  const cached = cache.get(cacheKey) ?? null;
  if (!cached) return null;
  cache.delete(cacheKey);
  cache.set(cacheKey, cached);
  return cached;
};

const writeCachedPreflight = (
  cache: Map<string, CachedPreflightReport>,
  cacheKey: string,
  report: CachedPreflightReport
): void => {
  if (cache.has(cacheKey)) {
    cache.delete(cacheKey);
  }
  cache.set(cacheKey, report);
  if (cache.size <= PREFLIGHT_CACHE_MAX_ENTRIES) {
    return;
  }
  const oldestKey = cache.keys().next().value;
  if (typeof oldestKey === 'string') {
    cache.delete(oldestKey);
  }
};

export function useAiPathTriggerEvent(): {
  fireAiPathTriggerEvent: (args: FireAiPathTriggerEventArgs) => Promise<void>;
  } {
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const pageContextRegistry = useOptionalContextRegistryPageEnvelope();
  const preflightCacheRef = useRef<Map<string, CachedPreflightReport>>(new Map());

  const resolvePreferredActivePathId = useCallback((): string | null => {
    const cachedPreferences = queryClient.getQueryData<{ aiPathsActivePathId?: unknown }>(
      QUERY_KEYS.userPreferences.all
    );
    return resolvePreferredPathId(
      typeof cachedPreferences?.aiPathsActivePathId === 'string'
        ? cachedPreferences.aiPathsActivePathId
        : null
    );
  }, [queryClient]);

  const fireAiPathTriggerEvent = useCallback(
    async (args: FireAiPathTriggerEventArgs): Promise<void> => {
      const finishLaunch = (): void => {
        args.onFinished?.();
      };
      const reportLaunchError = (payload: {
        toastMessage?: string | null | undefined;
        toastVariant?: 'default' | 'info' | 'warning' | 'error';
        errorCode: string;
        progressMessage?: string | null | undefined;
      }): void => {
        const toastMessage =
          typeof payload.toastMessage === 'string' ? payload.toastMessage.trim() : '';
        const progressMessage =
          typeof payload.progressMessage === 'string' ? payload.progressMessage.trim() : '';
        const callbackMessage = progressMessage || toastMessage || payload.errorCode;

        if (toastMessage.length > 0) {
          toast(toastMessage, { variant: payload.toastVariant ?? 'error' });
        }
        args.onError?.(callbackMessage);
        args.onProgress?.({
          status: 'error',
          error: payload.errorCode,
          ...(progressMessage.length > 0 ? { message: progressMessage } : {}),
          progress: 0,
          completedNodes: 0,
          totalNodes: 1,
          node: null,
        });
        finishLaunch();
      };

      const triggerEventId = args.triggerEventId.trim();
      if (!triggerEventId) {
        reportLaunchError({
          toastMessage: 'Missing trigger id.',
          toastVariant: 'error',
          errorCode: 'missing_trigger_id',
        });
        return;
      }

      try {
        toast(`Preparing AI Path run: ${args.triggerLabel?.trim() || triggerEventId}`, {
          variant: 'info',
        });
        args.onProgress?.({
          status: 'running',
          progress: 0,
          completedNodes: 0,
          totalNodes: 1,
          node: null,
        });

        const phaseStartedAt = performance.now();
        const preferredPathStartedAt = performance.now();
        const preferredActivePathId = resolvePreferredActivePathId();
        const resolvePreferredPathMs = performance.now() - preferredPathStartedAt;

        const settingsStartedAt = performance.now();
        let settingsData: Array<{ key: string; value: string }> = [];
        let settingsLoadMode: 'selective' | 'full' = 'full';
        try {
          const settingsLoad = await loadTriggerSettingsData({
            preferredPathId: args.preferredPathId ?? null,
          });
          settingsData = settingsLoad.settingsData;
          settingsLoadMode = settingsLoad.mode;
        } catch (settingsError) {
          const errorMessage =
            settingsError instanceof Error ? settingsError.message : String(settingsError);
          const timeoutCode = isTimeoutMessage(errorMessage) ? 'settings_preload_timeout' : null;
          const appErrorMeta =
            isAppError(settingsError) && settingsError.meta ? settingsError.meta : null;
          const preferredPathSettingsMissing =
            appErrorMeta?.['reason'] === 'preferred_path_config_missing';
          logClientCatch(settingsError, {
            source: 'useAiPathTriggerEvent',
            action: 'loadTriggerSettingsData',
            timeoutCode,
            preferredPathId: args.preferredPathId ?? null,
          });
          reportLaunchError({
            toastMessage: timeoutCode
              ? 'Failed to prepare AI Path run (settings_preload_timeout). Please retry.'
              : preferredPathSettingsMissing
                ? errorMessage
                : 'Failed to load AI Path settings. Please retry.',
            toastVariant: 'error',
            errorCode:
              timeoutCode ||
              (preferredPathSettingsMissing ? 'preferred_path_missing' : 'settings_load_error'),
            progressMessage: preferredPathSettingsMissing ? errorMessage : null,
          });
          return;
        }
        const settingsDurationMs = performance.now() - settingsStartedAt;

        const selectionStartedAt = performance.now();
        let triggerCandidates: PathConfig[] = [];
        let activeTriggerCandidates: PathConfig[] = [];
        let selectedConfig: PathConfig | null = null;
        let uiState: Record<string, unknown> | null = null;
        let missingPreferredPathId: string | null = null;
        try {
          const selection = await resolveTriggerSelection(settingsData, triggerEventId, {
            preferredPathId: args.preferredPathId,
            preferredActivePathId,
          });
          triggerCandidates = selection.triggerCandidates;
          activeTriggerCandidates = selection.activeTriggerCandidates;
          selectedConfig = selection.selectedConfig;
          uiState = selection.uiState;
          missingPreferredPathId = selection.missingPreferredPathId;
        } catch (selectionError) {
          const message =
            selectionError instanceof Error
              ? selectionError.message
              : 'AI Path trigger settings are invalid.';
          logClientCatch(selectionError, {
            source: 'useAiPathTriggerEvent',
            action: 'resolveTriggerSelection',
            triggerEventId,
          });
          reportLaunchError({
            toastMessage: message,
            toastVariant: 'error',
            errorCode: 'trigger_settings_invalid',
            progressMessage: message,
          });
          return;
        }
        const selectionDurationMs = performance.now() - selectionStartedAt;

        if (!selectedConfig) {
          if (missingPreferredPathId) {
            const missingPreferredMessage = `Trigger button is bound to missing AI Path "${missingPreferredPathId}". Update the button configuration.`;
            reportLaunchError({
              toastMessage: missingPreferredMessage,
              toastVariant: 'error',
              errorCode: 'preferred_path_missing',
              progressMessage: missingPreferredMessage,
            });
            return;
          }
          if (triggerCandidates.length === 0) {
            reportLaunchError({
              toastMessage: `No AI Path configured for trigger: ${triggerEventId}`,
              toastVariant: 'warning',
              errorCode: 'no_path_configured',
            });
            return;
          }
          if (activeTriggerCandidates.length === 0) {
            reportLaunchError({
              toastMessage: 'All AI Paths for this trigger are disabled.',
              toastVariant: 'warning',
              errorCode: 'path_disabled',
            });
            return;
          }
          reportLaunchError({
            toastMessage: 'Multiple active paths for trigger. Please specify preferredPathId.',
            toastVariant: 'warning',
            errorCode: 'ambiguous_path_selection',
          });
          return;
        }

        const historyRetentionPasses = resolveHistoryRetentionPasses(settingsData);
        const triggerNode = selectedConfig.nodes.find((node: AiNode) => {
          if (node.type !== 'trigger') return false;
          const configuredEvent = node.config?.trigger?.event ?? 'manual';
          return configuredEvent === triggerEventId;
        });

        if (!triggerNode) {
          reportLaunchError({
            toastMessage: `Trigger node not found in path: ${selectedConfig.name}`,
            toastVariant: 'error',
            errorCode: 'trigger_node_not_found',
          });
          return;
        }

        let entityJson: Record<string, unknown> | null = null;
        if (
          typeof args.getEntityJson === 'function' &&
          shouldEmbedTriggerEntitySnapshot({
            mode: triggerNode.config?.trigger?.entitySnapshotMode,
            entityType: args.entityType,
            entityId: args.entityId,
            sourceLocation: args.source?.location,
          })
        ) {
          try {
            entityJson = args.getEntityJson();
          } catch (entityJsonError) {
            logClientCatch(entityJsonError, {
              source: 'useAiPathTriggerEvent',
              action: 'getEntityJson',
              triggerEventId,
            });
          }
        }

        const savedDefaultModelWarning = resolveSavedDefaultModelWarning({
          entityType: args.entityType,
          source: args.source,
          selectedConfig,
        });
        if (savedDefaultModelWarning) {
          toast(savedDefaultModelWarning, { variant: 'info' });
        }

        const preflightStartedAt = performance.now();
        const validationConfig = normalizeAiPathsValidationConfig(
          selectedConfig.aiPathsValidation ?? null
        );
        const runtimeStateHint = resolveRuntimeStateHint(selectedConfig.runtimeState);
        const parserSamples = coerceSampleStateMap<ParserSampleState>(selectedConfig.parserSamples);
        const updaterSamples = coerceSampleStateMap<UpdaterSampleState>(
          selectedConfig.updaterSamples
        );
        const preflightCacheKey = resolvePreflightCacheKey({
          selectedConfig,
          triggerNodeId: triggerNode.id,
        });
        const preflight =
          readCachedPreflight(preflightCacheRef.current, preflightCacheKey) ??
          (() => {
            const computed = evaluateRunPreflight({
              nodes: selectedConfig.nodes,
              edges: selectedConfig.edges,
              aiPathsValidation: validationConfig,
              strictFlowMode: selectedConfig.strictFlowMode ?? true,
              triggerNodeId: triggerNode.id,
              ...(parserSamples ? { parserSamples } : {}),
              ...(updaterSamples ? { updaterSamples } : {}),
              mode: 'full',
            });
            writeCachedPreflight(preflightCacheRef.current, preflightCacheKey, computed);
            return computed;
          })();
        const preflightDurationMs = performance.now() - preflightStartedAt;

        if (preflight.shouldBlock) {
          const preflightMessage = preflight.blockMessage ?? 'Unknown preflight error.';
          reportLaunchError({
            toastMessage: `Path validation failed: ${preflightMessage}`,
            toastVariant: 'error',
            errorCode: 'preflight_failed',
            progressMessage: preflightMessage,
          });
          return;
        }

        const contextStartedAt = performance.now();
        const triggerContext = buildTriggerContext({
          triggerNode,
          triggerEventId,
          triggerLabel: args.triggerLabel,
          entityType: args.entityType,
          entityId: args.entityId,
          entityJson,
          event: args.event,
          pathInfo: { id: selectedConfig.id, name: selectedConfig.name },
          source: args.source,
          extras: args.extras,
        });
        const contextDurationMs = performance.now() - contextStartedAt;

        const apiStartedAt = performance.now();
        const requestId = createAiPathTriggerRequestId({
          pathId: selectedConfig.id,
          triggerEventId,
          entityType: args.entityType,
          entityId: args.entityId,
        });
        const runResult = await enqueueAiPathRun(
          {
            pathId: selectedConfig.id,
            pathName: selectedConfig.name,
            triggerEvent: triggerEventId,
            triggerNodeId: triggerNode.id,
            triggerContext,
            entityId: args.entityId,
            entityType: args.entityType,
            requestId,
            meta: {
              source: 'trigger_button',
              requestId,
              historyRetentionPasses,
              strictFlowMode: selectedConfig.strictFlowMode !== false,
              aiPathsValidation: normalizeAiPathsValidationConfig(
                selectedConfig.aiPathsValidation ?? null
              ),
              preflightRuntimeHints: {
                ...(selectedConfig.parserSamples
                  ? { parserSamples: selectedConfig.parserSamples }
                  : {}),
                ...(selectedConfig.updaterSamples
                  ? { updaterSamples: selectedConfig.updaterSamples }
                  : {}),
                ...(runtimeStateHint ? { runtimeState: runtimeStateHint } : {}),
              },
              clientMetadata: {
                source: 'useAiPathTriggerEvent',
                triggerEventId,
                requestId,
                triggerLabel: args.triggerLabel ?? null,
                entityType: args.entityType,
                entityId: args.entityId ?? null,
                preferredPathId: args.preferredPathId ?? null,
                settingsLoadMode,
                performance: {
                  totalPrepMs: performance.now() - phaseStartedAt,
                  resolvePreferredPathMs,
                  settingsDurationMs,
                  selectionDurationMs,
                  preflightDurationMs,
                  contextDurationMs,
                },
              },
            },
            ...(pageContextRegistry ? { contextRegistry: pageContextRegistry } : {}),
          },
          { timeoutMs: TRIGGER_ENQUEUE_TIMEOUT_MS }
        );
        const apiDurationMs = performance.now() - apiStartedAt;

        let runId: string | null = null;
        let runRecord: AiPathRunRecord | null = null;

        if (!runResult.ok && !runId) {
          reportLaunchError({
            toastMessage: `Failed to start AI Path: ${runResult.error || 'API Error'}`,
            toastVariant: 'error',
            errorCode: 'api_error',
            progressMessage: runResult.error as string | undefined,
          });
          return;
        }

        if (runResult.ok && !runId) {
          const resolved = resolveAiPathRunFromEnqueueResponseData(runResult.data);
          runId = resolved.runId;
          runRecord = resolved.runRecord;
        }

        if (!runId) {
          reportLaunchError({
            toastMessage: 'Failed to start AI Path: invalid run identifier from API.',
            toastVariant: 'error',
            errorCode: 'api_error',
            progressMessage: 'Invalid run identifier returned by enqueue endpoint.',
          });
          return;
        }

        const totalPrepMs = performance.now() - phaseStartedAt;

        logClientError(new Error(`AI Path started: ${selectedConfig.name} (${runId})`), {
          context: {
            source: 'useAiPathTriggerEvent',
            action: 'fireSuccess',
            level: 'info',
            pathId: selectedConfig.id,
            runId,
            requestId,
            triggerEventId,
            totalPrepMs,
            performance: {
              resolvePreferredPathMs,
              settingsDurationMs,
              selectionDurationMs,
              preflightDurationMs,
              contextDurationMs,
              apiDurationMs,
            },
          },
        });

        const queuedRunFallback: AiPathRunRecord = {
          id: runId,
          pathId: selectedConfig.id,
          pathName: selectedConfig.name,
          status: 'queued',
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
          requestId,
          triggerNodeId: triggerNode.id,
          triggerEvent: triggerEventId,
          entityId: args.entityId ?? null,
          entityType: args.entityType,
          meta: {
            source: 'trigger_button',
            requestId,
          },
        };
        const queuedRunForCache = mergeEnqueuedAiPathRunForCache({
          fallbackRun: queuedRunFallback,
          runId,
          runRecord,
        });
        const effectiveQueuedEntityId =
          typeof queuedRunForCache.entityId === 'string' &&
          queuedRunForCache.entityId.trim().length > 0
            ? queuedRunForCache.entityId.trim()
            : (args.entityId ?? null);
        optimisticallyInsertAiPathRunInQueueCache(queryClient, queuedRunForCache);

        await handleAiPathTriggerInvalidation({
          queryClient,
          runId,
          run: queuedRunForCache,
          entityType: args.entityType,
          entityId: effectiveQueuedEntityId,
        });
        notifyAiPathRunEnqueued(runId, {
          entityId: effectiveQueuedEntityId,
          entityType: args.entityType,
          run: queuedRunForCache,
        });

        const currentActivePathId = resolveCurrentActivePathId({
          preferredActivePathId,
          uiState,
        });

        if (selectedConfig.id !== currentActivePathId) {
          const nextUiState = {
            ...(uiState ?? {}),
            activePathId: selectedConfig.id,
          };
          await updateAiPathsSetting(AI_PATHS_UI_STATE_KEY, JSON.stringify({ value: nextUiState }));
          void invalidateAiPathSettings(queryClient);
          invalidateAiPathsSettingsCache();
        }

        args.onSuccess?.(runId);
        args.onProgress?.({
          status: 'running',
          progress: 0.1,
          completedNodes: 0,
          totalNodes: 1,
          node: null,
        });
        finishLaunch();
      } catch (error) {
        const message =
          error instanceof Error && error.message.trim().length > 0
            ? error.message
            : 'An unexpected error occurred while starting AI Path.';
        logClientCatch(error, {
          source: 'useAiPathTriggerEvent',
          action: 'fireError',
          triggerEventId,
        });
        reportLaunchError({
          toastMessage: message,
          toastVariant: 'error',
          errorCode: 'unexpected_error',
          progressMessage: message,
        });
      }
    },
    [pageContextRegistry, queryClient, toast, resolvePreferredActivePathId]
  );

  return { fireAiPathTriggerEvent };
}

'use client';

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import type {
  AiTriggerButtonLocation,
  AiTriggerButtonRecord,
} from '@/shared/contracts/ai-trigger-buttons';
import {
  type TrackedAiPathRunSnapshot,
  subscribeToTrackedAiPathRun,
} from '@/shared/lib/ai-paths/client-run-tracker';
import {
  clearTriggerButtonRunFeedback,
  isTriggerButtonRunFeedbackTerminal,
  persistTriggerButtonRunFeedback,
  readTriggerButtonRunFeedback,
  type TriggerButtonRunFeedbackSnapshot,
} from '@/shared/lib/ai-paths/trigger-button-run-feedback';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import { useAiPathsTriggerButtonsQuery } from './useAiPathQueries';
import { useAiPathTriggerEvent } from './useAiPathTriggerEvent';


const TOGGLE_STORAGE_KEY = 'aiPathsTriggerButtonToggles';
const SUCCESS_STORAGE_KEY = 'aiPathsTriggerButtonSuccess';
const EMPTY_TRIGGER_BUTTONS: AiTriggerButtonRecord[] = [];

type TriggerRunState = {
  status: 'idle' | 'running' | 'success' | 'error';
  progress: number;
};

export type TriggerButtonLastRun = TriggerButtonRunFeedbackSnapshot;
export type TriggerButtonRunSnapshotArgs = {
  button: AiTriggerButtonRecord;
  entityId?: string | null | undefined;
  entityType: 'product' | 'note' | 'custom';
  snapshot: TrackedAiPathRunSnapshot;
};

const areTriggerButtonLastRunsEqual = (
  left: TriggerButtonLastRun | undefined,
  right: TriggerButtonLastRun | undefined
): boolean => {
  if (left === right) return true;
  if (!left || !right) return false;
  return (
    left.runId === right.runId &&
    left.status === right.status &&
    left.updatedAt === right.updatedAt &&
    left.finishedAt === right.finishedAt &&
    left.errorMessage === right.errorMessage
  );
};

const areTriggerButtonLastRunMapsEqual = (
  left: Record<string, TriggerButtonLastRun>,
  right: Record<string, TriggerButtonLastRun>
): boolean => {
  const leftKeys = Object.keys(left);
  const rightKeys = Object.keys(right);
  if (leftKeys.length !== rightKeys.length) return false;

  return leftKeys.every((key) => areTriggerButtonLastRunsEqual(left[key], right[key]));
};

const toTrackedRunInitialSnapshot = (
  lastRun: TriggerButtonLastRun,
  context: {
    entityId: string | null;
    entityType: 'product' | 'note' | 'custom';
  }
): Partial<TrackedAiPathRunSnapshot> | undefined => {
  if (lastRun.status === 'waiting') return undefined;
  return {
    runId: lastRun.runId,
    status: lastRun.status,
    updatedAt: lastRun.updatedAt,
    finishedAt: lastRun.finishedAt,
    errorMessage: lastRun.errorMessage,
    entityId: context.entityId,
    entityType: context.entityType,
  };
};

const readMapFromStorage = (key: string): Record<string, boolean> => {
  if (typeof window === 'undefined') return {};
  try {
    const raw = window.localStorage.getItem(key);
    if (!raw) return {};
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== 'object') return {};
    return parsed as Record<string, boolean>;
  } catch (error) {
    logClientCatch(error, {
      source: 'useTriggerButtons',
      action: 'readMapFromStorage',
      storageKey: key,
    });
    return {};
  }
};

const writeMapToStorage = (key: string, value: Record<string, boolean>): void => {
  if (typeof window === 'undefined') return;
  try {
    window.localStorage.setItem(key, JSON.stringify(value));
  } catch (error) {
    logClientCatch(error, {
      source: 'useTriggerButtons',
      action: 'writeMapToStorage',
      storageKey: key,
      entryCount: Object.keys(value).length,
    });

    // ignore
  }
};

const normalizeOptionalEntityId = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const resolveTriggerEntityId = (
  explicitEntityId: string | null | undefined,
  getEntityJson?: (() => Record<string, unknown> | null) | undefined
): string | null => {
  const normalizedExplicitEntityId = normalizeOptionalEntityId(explicitEntityId);
  if (normalizedExplicitEntityId) return normalizedExplicitEntityId;
  if (!getEntityJson) return null;
  const entityJson = getEntityJson();
  if (!entityJson) return null;
  return (
    normalizeOptionalEntityId(entityJson['id']) ??
    normalizeOptionalEntityId(entityJson['_id']) ??
    normalizeOptionalEntityId(entityJson['productId']) ??
    null
  );
};

interface UseTriggerButtonsOptions {
  location: AiTriggerButtonLocation;
  entityType: 'product' | 'note' | 'custom';
  entityId?: string | null | undefined;
  getEntityJson?: ((button?: AiTriggerButtonRecord) => Record<string, unknown> | null) | undefined;
  getTriggerExtras?: ((button?: AiTriggerButtonRecord) => Record<string, unknown> | null) | undefined;
  onRunQueued?:
    | ((args: {
        button: AiTriggerButtonRecord;
        runId: string;
        entityId?: string | null | undefined;
        entityType: 'product' | 'note' | 'custom';
      }) => void)
    | undefined;
  onRunSnapshot?: ((args: TriggerButtonRunSnapshotArgs) => void) | undefined;
}

export function useTriggerButtons({
  location,
  entityType,
  entityId,
  getEntityJson,
  getTriggerExtras,
  onRunQueued,
  onRunSnapshot,
}: UseTriggerButtonsOptions) {
  const { toast } = useToast();
  const { fireAiPathTriggerEvent } = useAiPathTriggerEvent();
  const feedbackEntityId = useMemo(
    () => resolveTriggerEntityId(entityId, getEntityJson),
    [entityId, getEntityJson]
  );
  const feedbackScopeKey = `${entityType}::${feedbackEntityId ?? '__none__'}`;

  const [toggleMap, setToggleMap] = useState<Record<string, boolean>>(() =>
    readMapFromStorage(TOGGLE_STORAGE_KEY)
  );
  const [successMap, setSuccessMap] = useState<Record<string, boolean>>(() =>
    readMapFromStorage(SUCCESS_STORAGE_KEY)
  );
  const [runStates, setRunStates] = useState<Record<string, TriggerRunState>>({});
  const [lastRuns, setLastRuns] = useState<Record<string, TriggerButtonLastRun>>({});
  const runSubscriptionsRef = useRef<Map<string, () => void>>(new Map());
  const previousFeedbackScopeKeyRef = useRef<string | null>(null);

  const triggerButtonsQuery = useAiPathsTriggerButtonsQuery();
  const allButtons = triggerButtonsQuery.data ?? EMPTY_TRIGGER_BUTTONS;

  const buttons = useMemo(() => {
    const seen = new Set<string>();
    const sourceIndexById = new Map<string, number>();
    allButtons.forEach((button: AiTriggerButtonRecord, index: number) => {
      if (!button.id || sourceIndexById.has(button.id)) return;
      sourceIndexById.set(button.id, index);
    });

    return allButtons
      .filter((button: AiTriggerButtonRecord) => {
        if (button.enabled === false) return false;
        if (!(button.locations ?? []).includes(location)) return false;
        if (!button.id || seen.has(button.id)) return false;
        seen.add(button.id);
        return true;
      })
      .sort((a: AiTriggerButtonRecord, b: AiTriggerButtonRecord) => {
        const left = sourceIndexById.get(a.id) ?? Number.MAX_SAFE_INTEGER;
        const right = sourceIndexById.get(b.id) ?? Number.MAX_SAFE_INTEGER;
        return left - right;
      });
  }, [allButtons, location]);

  const stopRunSubscription = useCallback((buttonId: string): void => {
    const unsubscribe = runSubscriptionsRef.current.get(buttonId);
    if (!unsubscribe) return;
    runSubscriptionsRef.current.delete(buttonId);
    unsubscribe();
  }, []);

  const startRunSubscription = useCallback(
    (
      buttonId: string,
      runId: string,
      options: {
        entityId: string | null;
        entityType: 'product' | 'note' | 'custom';
        pathId?: string | null | undefined;
        initialSnapshot?: Partial<TrackedAiPathRunSnapshot> | undefined;
        onSnapshot?: ((snapshot: TrackedAiPathRunSnapshot) => void) | undefined;
      }
    ): void => {
      stopRunSubscription(buttonId);
      let didStop = false;
      const unsubscribe = subscribeToTrackedAiPathRun(
        runId,
        (snapshot: TrackedAiPathRunSnapshot): void => {
          const nextLastRun: TriggerButtonLastRun = {
            runId: snapshot.runId,
            status: snapshot.status,
            updatedAt: snapshot.updatedAt,
            finishedAt: snapshot.finishedAt,
            errorMessage: snapshot.errorMessage,
          };
          setLastRuns((prev) => ({
            ...prev,
            [buttonId]: nextLastRun,
          }));
          persistTriggerButtonRunFeedback({
            buttonId,
            pathId: options.pathId,
            location,
            entityId: options.entityId ?? snapshot.entityId ?? null,
            entityType: options.entityType,
            run: nextLastRun,
          });
          options.onSnapshot?.(snapshot);

          if (snapshot.trackingState !== 'stopped' || didStop) return;
          didStop = true;
          stopRunSubscription(buttonId);
        },
        options.initialSnapshot ? { initialSnapshot: options.initialSnapshot } : undefined
      );
      runSubscriptionsRef.current.set(buttonId, unsubscribe);
    },
    [location, stopRunSubscription]
  );

  useEffect(() => {
    const currentButtonIds = new Set<string>(
      buttons
        .map((button: AiTriggerButtonRecord) => button.id)
        .filter((buttonId): buttonId is string => typeof buttonId === 'string' && buttonId.length > 0)
    );
    const scopeChanged = previousFeedbackScopeKeyRef.current !== feedbackScopeKey;
    previousFeedbackScopeKeyRef.current = feedbackScopeKey;

    Array.from(runSubscriptionsRef.current.keys()).forEach((buttonId: string) => {
      if (scopeChanged || !currentButtonIds.has(buttonId)) {
        stopRunSubscription(buttonId);
      }
    });

    const restoredRuns: Record<string, TriggerButtonLastRun> = {};
    buttons.forEach((button: AiTriggerButtonRecord) => {
      if (!button.id) return;
      const restoredRun = readTriggerButtonRunFeedback({
        buttonId: button.id,
        pathId: button.pathId ?? null,
        entityType,
        entityId: feedbackEntityId,
      });
      if (!restoredRun) return;
      restoredRuns[button.id] = restoredRun;
      if (
        !runSubscriptionsRef.current.has(button.id) &&
        !isTriggerButtonRunFeedbackTerminal(restoredRun.status)
      ) {
        const initialSnapshot = toTrackedRunInitialSnapshot(restoredRun, {
          entityId: feedbackEntityId,
          entityType,
        });
        startRunSubscription(button.id, restoredRun.runId, {
          entityId: feedbackEntityId,
          entityType,
          pathId: button.pathId ?? null,
          ...(initialSnapshot ? { initialSnapshot } : {}),
          onSnapshot: (snapshot: TrackedAiPathRunSnapshot): void => {
            onRunSnapshot?.({
              button,
              entityId: feedbackEntityId,
              entityType,
              snapshot,
            });
          },
        });
      }
    });

    setLastRuns((prev) => {
      const source = scopeChanged ? {} : prev;
      const next: Record<string, TriggerButtonLastRun> = {};
      currentButtonIds.forEach((buttonId: string) => {
        const existing = source[buttonId];
        const restored = restoredRuns[buttonId];
        if (existing) {
          next[buttonId] = existing;
          return;
        }
        if (restored) {
          next[buttonId] = restored;
        }
      });
      return areTriggerButtonLastRunMapsEqual(prev, next) ? prev : next;
    });
  }, [
    buttons,
    entityType,
    feedbackEntityId,
    feedbackScopeKey,
    onRunSnapshot,
    startRunSubscription,
    stopRunSubscription,
  ]);

  useEffect(() => {
    return () => {
      Array.from(runSubscriptionsRef.current.keys()).forEach((buttonId: string) => {
        stopRunSubscription(buttonId);
      });
    };
  }, [stopRunSubscription]);

  const handleTrigger = useCallback(
    async (
      button: AiTriggerButtonRecord,
      options: { mode: 'click' | 'toggle'; checked?: boolean; event?: React.MouseEvent }
    ) => {
      if (!button.id) {
        toast('Missing trigger id.', { variant: 'error' });
        return;
      }

      if (options.mode === 'toggle') {
        setToggleMap((prev) => {
          const nextToggleMap = { ...prev, [button.id]: options.checked ?? false };
          writeMapToStorage(TOGGLE_STORAGE_KEY, nextToggleMap);
          return nextToggleMap;
        });
      }

      let gotProgress = false;
      setRunStates((prev) => ({
        ...prev,
        [button.id]: { status: 'running', progress: 0 },
      }));
      const getButtonEntityJson = getEntityJson
        ? (): Record<string, unknown> | null => getEntityJson(button)
        : undefined;
      const resolvedEntityId = resolveTriggerEntityId(entityId, getButtonEntityJson);
      const buttonContextTemplate =
        button.contextTemplate &&
        typeof button.contextTemplate === 'object' &&
        !Array.isArray(button.contextTemplate)
          ? button.contextTemplate
          : null;
      let customExtras: Record<string, unknown> | null = buttonContextTemplate;

      // Guard: if the caller signals an entity context (via explicit entityId prop or getEntityJson)
      // but resolution yields null, abort early rather than firing with no entity context.
      // 'custom' entityType is exempt — those triggers intentionally have no entity.
      if (
        resolvedEntityId === null &&
        entityType !== 'custom' &&
        (entityId !== undefined || getEntityJson !== undefined)
      ) {
        toast(
          'Could not resolve entity ID for this AI Path trigger. Ensure the product has a valid ID.',
          { variant: 'warning' }
        );
        setRunStates((prev) => ({ ...prev, [button.id]: { status: 'idle', progress: 0 } }));
        return;
      }

      if (getTriggerExtras) {
        try {
          const resolvedTriggerExtras = getTriggerExtras(button);
          if (resolvedTriggerExtras === null) {
            toast('Trigger context is not ready for this AI Path trigger.', {
              variant: 'warning',
            });
            setRunStates((prev) => ({ ...prev, [button.id]: { status: 'idle', progress: 0 } }));
            return;
          }
          if (
            resolvedTriggerExtras &&
            typeof resolvedTriggerExtras === 'object' &&
            !Array.isArray(resolvedTriggerExtras)
          ) {
            customExtras = {
              ...(buttonContextTemplate ?? {}),
              ...resolvedTriggerExtras,
            };
          }
        } catch (error) {
          logClientCatch(error, {
            source: 'useTriggerButtons',
            action: 'getTriggerExtras',
            buttonId: button.id,
            pathId: button.pathId,
            location,
            entityType,
          });
          toast('Could not build trigger context for this AI Path trigger.', {
            variant: 'error',
          });
          setRunStates((prev) => ({ ...prev, [button.id]: { status: 'idle', progress: 0 } }));
          return;
        }
      }

      try {
        const waitingRun: TriggerButtonLastRun = {
          runId: `waiting:${button.id}:${Date.now()}`,
          status: 'waiting',
          updatedAt: new Date().toISOString(),
          finishedAt: null,
          errorMessage: null,
        };
        setLastRuns((prev) => ({
          ...prev,
          [button.id]: waitingRun,
        }));
        clearTriggerButtonRunFeedback({
          buttonId: button.id,
          pathId: button.pathId ?? null,
          location,
          entityId: resolvedEntityId,
          entityType,
        });

        await fireAiPathTriggerEvent({
          triggerEventId: button.id,
          triggerLabel: button.name,
          preferredPathId: button.pathId ?? null,
          entityType,
          entityId: resolvedEntityId,
          ...(getButtonEntityJson ? { getEntityJson: getButtonEntityJson } : {}),
          event: options.event,
          source: { tab: entityType, location },
          extras: {
            ...(customExtras ?? {}),
            mode: options.mode,
            ...(options.mode === 'toggle' ? { checked: options.checked } : {}),
          },
          onSuccess: (runId: string): void => {
            const queuedRun = {
              runId,
              status: 'queued',
              updatedAt: new Date().toISOString(),
              finishedAt: null,
              errorMessage: null,
            } satisfies TriggerButtonLastRun;
            persistTriggerButtonRunFeedback({
              buttonId: button.id,
              pathId: button.pathId ?? null,
              location,
              entityId: resolvedEntityId,
              entityType,
              run: queuedRun,
            });
            setLastRuns((prev) => ({
              ...prev,
              [button.id]: queuedRun,
            }));
            const initialSnapshot = toTrackedRunInitialSnapshot(queuedRun, {
              entityId: resolvedEntityId,
              entityType,
            });
            startRunSubscription(button.id, runId, {
              entityId: resolvedEntityId,
              entityType,
              pathId: button.pathId ?? null,
              ...(initialSnapshot ? { initialSnapshot } : {}),
              onSnapshot: (snapshot: TrackedAiPathRunSnapshot): void => {
                onRunSnapshot?.({
                  button,
                  entityId: resolvedEntityId,
                  entityType,
                  snapshot,
                });
              },
            });
            onRunQueued?.({
              button,
              runId,
              entityId: resolvedEntityId,
              entityType,
            });
          },
          onError: (): void => {
            setLastRuns((prev) => {
              if (prev[button.id]?.status !== 'waiting') return prev;
              const next = { ...prev };
              delete next[button.id];
              return next;
            });
          },
          onProgress: (payload: {
            status: 'running' | 'success' | 'error';
            progress: number;
          }): void => {
            const { status, progress } = payload;
            gotProgress = true;

            if (status === 'success') {
              setSuccessMap((prev) => {
                const nextMap = { ...prev, [button.id]: true };
                writeMapToStorage(SUCCESS_STORAGE_KEY, nextMap);
                return nextMap;
              });
              setRunStates((prev) => ({
                ...prev,
                [button.id]: { status: 'idle', progress: 0 },
              }));
              return;
            }

            if (status === 'error') {
              setRunStates((prev) => ({
                ...prev,
                [button.id]: { status: 'idle', progress: 0 },
              }));
              return;
            }

            setRunStates((prev) => ({
              ...prev,
              [button.id]: { status, progress },
            }));
          },
        });
      } catch (error) {
        logClientCatch(error, {
          source: 'useTriggerButtons',
          action: 'handleTrigger',
          buttonId: button.id,
          pathId: button.pathId,
          location,
          entityType,
        });
        const message = error instanceof Error ? error.message : 'Unknown error';
        setLastRuns((prev) => {
          if (prev[button.id]?.status !== 'waiting') return prev;
          const next = { ...prev };
          delete next[button.id];
          return next;
        });
        toast(String(message), { variant: 'error' });
      } finally {
        if (!gotProgress) {
          setRunStates((prev) => ({
            ...prev,
            [button.id]: { status: 'idle', progress: 0 },
          }));
        } else {
          setRunStates((prev) => {
            const state = prev[button.id];
            if (state?.status !== 'running') return prev;
            return { ...prev, [button.id]: { status: 'idle', progress: 0 } };
          });
        }
      }
    },
    [
      entityId,
      entityType,
      fireAiPathTriggerEvent,
      getEntityJson,
      getTriggerExtras,
      location,
      onRunQueued,
      onRunSnapshot,
      startRunSubscription,
      toast,
    ]
  );

  return {
    buttons,
    toggleMap,
    successMap,
    runStates,
    lastRuns,
    handleTrigger,
    isLoading: triggerButtonsQuery.isLoading,
  };
}

import type { AiPathLocalRunStatus, AiPathLocalRunRecord } from '@/shared/contracts/ai-paths';
import {
  fetchAiPathsSettingsCached,
  invalidateAiPathsSettingsCache,
  updateAiPathsSetting,
} from '@/shared/lib/ai-paths/settings-store-client';
import { logClientCatch, logClientError } from '@/shared/utils/observability/client-error-logger';

import { AI_PATHS_LOCAL_RUNS_KEY } from './core/constants';

const MAX_LOCAL_RUNS = 200;

const toIsoString = (value: unknown): string | null => {
  if (typeof value === 'string' && value.trim().length > 0) {
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? null : date.toISOString();
  }
  if (value instanceof Date) {
    return Number.isNaN(value.getTime()) ? null : value.toISOString();
  }
  return null;
};

const normalizeRecord = (value: unknown): AiPathLocalRunRecord | null => {
  if (!value || typeof value !== 'object') return null;
  const raw = value as Record<string, unknown>;
  const id = typeof raw['id'] === 'string' && raw['id'].trim().length > 0 ? raw['id'].trim() : null;
  const status =
    raw['status'] === 'success' || raw['status'] === 'error'
      ? (raw['status'] as AiPathLocalRunStatus)
      : null;
  const startedAt = toIsoString(raw['startedAt']);
  const finishedAt = toIsoString(raw['finishedAt']);
  if (!id || !status || !startedAt || !finishedAt) return null;
  const durationMs =
    typeof raw['durationMs'] === 'number' && Number.isFinite(raw['durationMs'])
      ? raw['durationMs']
      : null;
  const nodeCount =
    typeof raw['nodeCount'] === 'number' && Number.isFinite(raw['nodeCount'])
      ? raw['nodeCount']
      : null;
  const rawNodeDurations = raw['nodeDurations'];
  const nodeDurations: Record<string, number> | null =
    rawNodeDurations && typeof rawNodeDurations === 'object' && !Array.isArray(rawNodeDurations)
      ? Object.fromEntries(
          Object.entries(rawNodeDurations as Record<string, unknown>).filter(
            ([, v]) => typeof v === 'number' && Number.isFinite(v)
          ) as [string, number][]
      )
      : null;

  return {
    id,
    status,
    startedAt,
    finishedAt,
    durationMs,
    nodeCount,
    nodeDurations: nodeDurations && Object.keys(nodeDurations).length > 0 ? nodeDurations : null,
    pathId: typeof raw['pathId'] === 'string' ? raw['pathId'] : null,
    pathName: typeof raw['pathName'] === 'string' ? raw['pathName'] : null,
    triggerEvent: typeof raw['triggerEvent'] === 'string' ? raw['triggerEvent'] : null,
    triggerLabel: typeof raw['triggerLabel'] === 'string' ? raw['triggerLabel'] : null,
    entityType: typeof raw['entityType'] === 'string' ? raw['entityType'] : null,
    entityId: typeof raw['entityId'] === 'string' ? raw['entityId'] : null,
    error: typeof raw['error'] === 'string' ? raw['error'] : null,
    source: typeof raw['source'] === 'string' ? raw['source'] : null,
  };
};

export const parseLocalRuns = (raw?: string | null): AiPathLocalRunRecord[] => {
  if (!raw) return [];
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((entry: unknown) => normalizeRecord(entry))
      .filter((entry: AiPathLocalRunRecord | null): entry is AiPathLocalRunRecord =>
        Boolean(entry)
      );
  } catch (error) {
    logClientError(error);
    return [];
  }
};

const buildLocalRunId = (): string => {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }
  return `local_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
};

export const appendLocalRun = async (
  record: Omit<AiPathLocalRunRecord, 'id'> & { id?: string }
): Promise<AiPathLocalRunRecord | null> => {
  const id = record.id && record.id.trim().length > 0 ? record.id : buildLocalRunId();
  const normalized: AiPathLocalRunRecord = {
    ...record,
    id,
  };

  try {
    const settings = await fetchAiPathsSettingsCached({ bypassCache: true });
    const map = new Map(settings.map((item) => [item.key, item.value]));
    const existing = parseLocalRuns(map.get(AI_PATHS_LOCAL_RUNS_KEY));
    const next = [normalized, ...existing].slice(0, MAX_LOCAL_RUNS);
    const payload = JSON.stringify(next);
    await updateAiPathsSetting(AI_PATHS_LOCAL_RUNS_KEY, payload);
    invalidateAiPathsSettingsCache();
    if (typeof window !== 'undefined') {
      window.dispatchEvent(
        new CustomEvent('ai-paths:settings:updated', { detail: { scope: 'ai-paths' } })
      );
    }
    return normalized;
  } catch (error) {
    logClientCatch(error, { source: 'ai-paths-local-runs', action: 'appendLocalRun' });
    return null;
  }
};

'use client';

import {
  aiPathRunStatusSchema,
  type AiPathRunListResult,
  type AiPathRunRecord,
} from '@/shared/contracts/ai-paths';
import { logger } from '@/shared/utils/logger';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import { AI_PATHS_RUN_SOURCE_VALUES } from './run-sources';


const STORAGE_KEY = 'ai-paths-optimistic-run-queue';
const DEFAULT_RUN_TTL_MS = 60_000;
const ACTIVE_RUN_TTL_MS = 10 * 60_000;
const MAX_QUEUE_SIZE = 50;
const MAX_QUEUE_SIZE_ON_QUOTA_RETRY = 25;
const MAX_QUEUE_SIZE_MINIMUM_FALLBACK = 10;
const AI_PATHS_NODE_SOURCES = new Set<string>(AI_PATHS_RUN_SOURCE_VALUES);
const ACTIVE_RUN_STATUSES = new Set<AiPathRunRecord['status']>([
  'queued',
  'running',
]);

type StoredOptimisticRun = {
  expiresAt: number;
  run: AiPathRunRecord;
};

export type OptimisticRunFilters = {
  pathId?: string;
  source?: string;
  sourceMode?: 'include' | 'exclude';
  status?: string;
  query?: string;
};

const inMemoryOptimisticRunQueue = new Map<string, StoredOptimisticRun>();

const canUseStorage = (): boolean =>
  typeof window !== 'undefined' && typeof window.localStorage !== 'undefined';

const normalizeString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim().toLowerCase();
  return normalized.length > 0 ? normalized : null;
};

const normalizeRunId = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const toTimestamp = (value: unknown): number => {
  if (typeof value !== 'string') return 0;
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : 0;
};

const compareRuns = (left: AiPathRunRecord, right: AiPathRunRecord): number => {
  const leftTimestamp = Math.max(toTimestamp(left.createdAt), toTimestamp(left.updatedAt));
  const rightTimestamp = Math.max(toTimestamp(right.createdAt), toTimestamp(right.updatedAt));
  if (rightTimestamp !== leftTimestamp) return rightTimestamp - leftTimestamp;
  return (right.id ?? '').localeCompare(left.id ?? '');
};

const isActiveRun = (run: Pick<AiPathRunRecord, 'status'>): boolean =>
  ACTIVE_RUN_STATUSES.has(run.status);

const readMetaRecord = (meta: AiPathRunRecord['meta']): Record<string, unknown> | null => {
  if (!meta || typeof meta !== 'object' || Array.isArray(meta)) return null;
  return meta;
};

const resolveRunSource = (run: AiPathRunRecord): string | null => {
  const meta = readMetaRecord(run.meta as Record<string, unknown>);
  if (!meta) return null;
  return normalizeString(meta['source']);
};

const compactRunMetaForStorage = (meta: AiPathRunRecord['meta']): Record<string, unknown> | null => {
  const parsed = readMetaRecord(meta);
  if (!parsed) return null;

  const compact: Record<string, unknown> = {};

  const source = normalizeString(parsed['source']);
  if (source) compact['source'] = source;

  const executionMode = normalizeString(parsed['executionMode']);
  if (executionMode) compact['executionMode'] = executionMode;

  const runtime =
    parsed['runtime'] && typeof parsed['runtime'] === 'object' && !Array.isArray(parsed['runtime'])
      ? (parsed['runtime'] as Record<string, unknown>)
      : null;
  const runtimeExecutionMode =
    runtime && typeof runtime['executionMode'] === 'string'
      ? normalizeString(runtime['executionMode'])
      : null;
  if (runtimeExecutionMode) {
    compact['runtime'] = { executionMode: runtimeExecutionMode };
  }

  return Object.keys(compact).length === 0 ? null : compact;
};

const compactOptimisticRunForStorage = (run: AiPathRunRecord): AiPathRunRecord => ({
  id: run.id,
  status: run.status,
  pathId: run.pathId,
  pathName: run.pathName,
  createdAt: run.createdAt,
  updatedAt: run.updatedAt,
  requestId: run.requestId,
  triggerEvent: run.triggerEvent,
  triggerNodeId: run.triggerNodeId,
  errorMessage: run.errorMessage,
  entityId: run.entityId,
  entityType: run.entityType,
  meta: compactRunMetaForStorage(run.meta),
});

const isAiPathsNodeSource = (source: string | null): boolean => {
  if (!source) return false;
  return AI_PATHS_NODE_SOURCES.has(source);
};

const matchesSourceFilter = (
  run: AiPathRunRecord,
  sourceFilter: string | null,
  sourceMode: 'include' | 'exclude'
): boolean => {
  if (!sourceFilter) return true;
  const runSource = resolveRunSource(run);

  if (sourceMode === 'exclude') {
    if (sourceFilter === 'ai_paths_ui') {
      return !isAiPathsNodeSource(runSource);
    }
    return runSource !== sourceFilter;
  }

  if (sourceFilter === 'ai_paths_ui') {
    return isAiPathsNodeSource(runSource);
  }
  return runSource === sourceFilter;
};

const matchesQueryFilter = (run: AiPathRunRecord, query: string | null): boolean => {
  if (!query) return true;
  const haystack = [run.id, run.pathId, run.pathName, run.entityId, run.errorMessage]
    .map((item: unknown) => (typeof item === 'string' ? item.toLowerCase() : ''))
    .join(' ');
  return haystack.includes(query);
};

export const aiPathRunMatchesFilters = (
  run: AiPathRunRecord,
  filters?: OptimisticRunFilters
): boolean => {
  const statusFilter = normalizeString(filters?.status);
  if (statusFilter && statusFilter !== 'all') {
    const runStatus = normalizeString(run.status);
    if (runStatus !== statusFilter) return false;
  }

  const pathFilter = normalizeString(filters?.pathId);
  if (pathFilter) {
    const runPathId = normalizeString(run.pathId);
    if (runPathId !== pathFilter) return false;
  }

  const sourceFilter = normalizeString(filters?.source);
  const sourceMode = filters?.sourceMode === 'exclude' ? 'exclude' : 'include';
  if (!matchesSourceFilter(run, sourceFilter, sourceMode)) return false;

  const queryFilter = normalizeString(filters?.query);
  return matchesQueryFilter(run, queryFilter);
};

const safeLocalStorageGet = (key: string): string | null => {
  try {
    return window.localStorage.getItem(key);
  } catch (error) {
    logClientCatch(error, {
      source: 'optimistic-run-queue',
      action: 'localStorageGet',
      storageKey: key,
    });
    return null;
  }
};

const safeLocalStorageSet = (key: string, value: string): boolean => {
  try {
    window.localStorage.setItem(key, value);
    return true;
  } catch (error) {
    logClientCatch(error, {
      source: 'optimistic-run-queue',
      action: 'localStorageSet',
      storageKey: key,
      valueLength: value.length,
    });
    return false;
  }
};

const safeLocalStorageRemove = (key: string): void => {
  try {
    window.localStorage.removeItem(key);
  } catch (error) {
    logClientCatch(error, {
      source: 'optimistic-run-queue',
      action: 'localStorageRemove',
      storageKey: key,
    });

    // Ignore storage failures.
  }
};

const limitEntries = (entries: StoredOptimisticRun[], max: number): StoredOptimisticRun[] => {
  const capped = Math.max(1, max);
  return entries.length <= capped ? entries : entries.slice(0, capped);
};

const ensureSortedQueueEntries = (entries: StoredOptimisticRun[]): StoredOptimisticRun[] => {
  const valid = entries.filter((entry) => normalizeRunId(entry.run.id));
  return [...valid].sort((left, right) => compareRuns(left.run, right.run));
};

const syncInMemoryQueue = (entries: StoredOptimisticRun[]): void => {
  inMemoryOptimisticRunQueue.clear();
  for (const entry of entries) {
    const runId = normalizeRunId(entry.run.id);
    if (!runId) continue;
    inMemoryOptimisticRunQueue.set(runId, entry);
  }
};

const mergeQueueEntries = (
  left: StoredOptimisticRun[],
  right: StoredOptimisticRun[]
): StoredOptimisticRun[] => {
  const map = new Map<string, StoredOptimisticRun>();
  for (const entry of [...left, ...right]) {
    const runId = normalizeRunId(entry.run.id);
    if (!runId) continue;
    const existing = map.get(runId);
    if (!existing || entry.expiresAt >= existing.expiresAt) {
      map.set(runId, entry);
    }
  }
  return ensureSortedQueueEntries(Array.from(map.values()));
};

const writeEntries = (entries: StoredOptimisticRun[]): void => {
  const normalizedEntries = limitEntries(ensureSortedQueueEntries(entries), MAX_QUEUE_SIZE);
  syncInMemoryQueue(normalizedEntries);

  if (!canUseStorage()) return;

  if (normalizedEntries.length === 0) {
    safeLocalStorageRemove(STORAGE_KEY);
    return;
  }

  const variants = [
    normalizedEntries,
    limitEntries(normalizedEntries, MAX_QUEUE_SIZE_ON_QUOTA_RETRY),
    limitEntries(normalizedEntries, MAX_QUEUE_SIZE_MINIMUM_FALLBACK),
  ];

  for (const variant of variants) {
    const compacted = variant.map((entry: StoredOptimisticRun) => ({
      expiresAt: entry.expiresAt,
      run: compactOptimisticRunForStorage(entry.run),
    }));
    if (safeLocalStorageSet(STORAGE_KEY, JSON.stringify(compacted))) {
      if (variant.length !== normalizedEntries.length) {
        logger.warn('[ai-paths-optimistic-run-queue] trimmed optimistic runs before storage persist', {
          event: 'trimmed',
          normalizedCount: normalizedEntries.length,
          persistedCount: variant.length,
        });
      }
      return;
    }
  }

  logger.warn('[ai-paths-optimistic-run-queue] falling back to in-memory optimistic run queue', {
    event: 'fallback',
    requestedCount: normalizedEntries.length,
  });
  // Keep memory copy for current session when persistence cannot be written.
};

const readEntries = (): StoredOptimisticRun[] => {
  const now = Date.now();
  const parsedEntries: StoredOptimisticRun[] = [];
  let persistedCount = 0;
  let hasStoragePayload = false;

  if (canUseStorage()) {
    const raw = safeLocalStorageGet(STORAGE_KEY);
    if (raw) {
      hasStoragePayload = true;
      try {
        const parsed: unknown = JSON.parse(raw);
        if (Array.isArray(parsed)) {
          persistedCount = parsed.length;
          parsedEntries.push(
            ...parsed
              .map((entry: unknown) => normalizeStoredEntry(entry))
              .filter(
                (entry: StoredOptimisticRun | null): entry is StoredOptimisticRun =>
                  entry !== null && entry.expiresAt > now
              )
          );
        } else {
          logger.warn(
            '[ai-paths-optimistic-run-queue] invalid stored payload (non-array), clearing storage',
            {
              event: 'storage-invalid',
              source: 'non-array-payload',
            }
          );
          safeLocalStorageRemove(STORAGE_KEY);
        }
      } catch (error) {
        logClientCatch(error, {
          source: 'optimistic-run-queue',
          action: 'parseStoredQueue',
          storageKey: STORAGE_KEY,
        });
        logger.warn('[ai-paths-optimistic-run-queue] invalid stored payload (json parse failure)', {
          event: 'storage-invalid',
          source: 'invalid-json',
        });
        safeLocalStorageRemove(STORAGE_KEY);
      }
    }
  }

  const mergedEntries = mergeQueueEntries(
    parsedEntries,
    Array.from(inMemoryOptimisticRunQueue.values())
  ).filter((entry: StoredOptimisticRun) => entry.expiresAt > now);
  const normalizedEntries = limitEntries(ensureSortedQueueEntries(mergedEntries), MAX_QUEUE_SIZE);
  syncInMemoryQueue(normalizedEntries);

  if (canUseStorage() && hasStoragePayload && persistedCount !== normalizedEntries.length) {
    logger.warn('[ai-paths-optimistic-run-queue] normalized stored payload before persisting', {
      event: 'normalized',
      persistedCount,
      normalizedCount: normalizedEntries.length,
    });
    writeEntries(normalizedEntries);
  }

  return normalizedEntries;
};

const normalizeStoredRun = (value: unknown): AiPathRunRecord | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  const record = value as Record<string, unknown>;
  const id = normalizeRunId(record['id']);
  const status = aiPathRunStatusSchema.safeParse(record['status']);
  if (!id || !status.success) return null;

  return compactOptimisticRunForStorage({
    ...(record as AiPathRunRecord),
    id,
    status: status.data,
  });
};

const normalizeStoredEntry = (value: unknown): StoredOptimisticRun | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  const record = value as Record<string, unknown>;
  const expiresAt =
    typeof record['expiresAt'] === 'number' && Number.isFinite(record['expiresAt'])
      ? record['expiresAt']
      : null;
  const run = normalizeStoredRun(record['run']);
  if (!expiresAt || !run) return null;
  return { expiresAt, run };
};

const replaceEntry = (
  entries: StoredOptimisticRun[],
  run: AiPathRunRecord,
  expiresAt: number
): StoredOptimisticRun[] => {
  const normalizedRun = normalizeStoredRun(run);
  if (!normalizedRun) return entries;
  const nextEntries = entries.filter((entry) => entry.run.id !== normalizedRun.id);
  nextEntries.push({ expiresAt, run: compactOptimisticRunForStorage(normalizedRun) });
  return ensureSortedQueueEntries(nextEntries);
};

export const rememberOptimisticAiPathRun = (
  run: AiPathRunRecord,
  options?: { ttlMs?: number }
): void => {
  const normalizedRun = normalizeStoredRun(run);
  if (!normalizedRun) return;

  const ttlMs = Math.max(
    1_000,
    options?.ttlMs ?? (isActiveRun(normalizedRun) ? ACTIVE_RUN_TTL_MS : DEFAULT_RUN_TTL_MS)
  );
  const entries = readEntries();
  const nextEntries = replaceEntry(entries, normalizedRun, Date.now() + ttlMs);
  writeEntries(nextEntries);
};

export const removeOptimisticAiPathRun = (runId: string): void => {
  const normalizedRunId = normalizeRunId(runId);
  if (!normalizedRunId) return;

  const entries = readEntries();
  const nextEntries = entries.filter((entry) => entry.run.id !== normalizedRunId);
  if (nextEntries.length === entries.length) return;
  writeEntries(nextEntries);
};

export const removeOptimisticAiPathRuns = (runIds: Iterable<string>): void => {
  const normalizedIds = new Set<string>();
  for (const runId of runIds) {
    const normalizedRunId = normalizeRunId(runId);
    if (normalizedRunId) normalizedIds.add(normalizedRunId);
  }
  if (normalizedIds.size === 0) return;

  const entries = readEntries();
  const nextEntries = entries.filter((entry) => !normalizedIds.has(entry.run.id));
  if (nextEntries.length === entries.length) return;
  writeEntries(nextEntries);
};

export const listOptimisticAiPathRuns = (filters?: OptimisticRunFilters): AiPathRunRecord[] => {
  return readEntries()
    .map((entry) => entry.run)
    .filter((run) => aiPathRunMatchesFilters(run, filters));
};

export const previewAiPathQueuePayloadWithOptimisticRuns = (
  payload: AiPathRunListResult,
  options?: OptimisticRunFilters & {
    limit?: number;
    offset?: number;
  }
): AiPathRunListResult => {
  const currentRuns = Array.isArray(payload.runs) ? payload.runs : [];
  const offset = typeof options?.offset === 'number' ? options.offset : 0;
  if (offset > 0) return payload;

  const currentRunIds = new Set<string>();
  currentRuns.forEach((run) => {
    const runId = normalizeRunId(run?.id);
    if (runId) currentRunIds.add(runId);
  });

  const optimisticRuns = listOptimisticAiPathRuns(options).filter((run) => !currentRunIds.has(run.id));
  if (optimisticRuns.length === 0) return payload;

  const combinedRuns = [...optimisticRuns, ...currentRuns];
  const limit = typeof options?.limit === 'number' ? options.limit : null;

  return {
    runs: limit && limit > 0 ? combinedRuns.slice(0, limit) : combinedRuns,
    total: payload.total + optimisticRuns.length,
  };
};

export const mergeAiPathQueuePayloadWithOptimisticRuns = (
  payload: AiPathRunListResult,
  options?: OptimisticRunFilters & {
    limit?: number;
    offset?: number;
  }
): AiPathRunListResult => {
  const serverRuns = Array.isArray(payload.runs) ? payload.runs : [];
  const serverRunIds = new Set<string>();
  serverRuns.forEach((run) => {
    const runId = normalizeRunId(run?.id);
    if (runId) serverRunIds.add(runId);
  });
  if (serverRunIds.size > 0) {
    const terminalRunIds: string[] = [];
    serverRuns.forEach((run) => {
      const runId = normalizeRunId(run?.id);
      if (!runId) return;
      if (isActiveRun(run)) {
        rememberOptimisticAiPathRun(run);
        return;
      }
      terminalRunIds.push(runId);
    });
    if (terminalRunIds.length > 0) {
      removeOptimisticAiPathRuns(terminalRunIds);
    }
  }
  return previewAiPathQueuePayloadWithOptimisticRuns(payload, options);
};

export const patchQueuedCountWithOptimisticRuns = <T extends { queuedCount?: number | null }>(
  status: T
): T => {
  const optimisticQueuedCount = listOptimisticAiPathRuns({ status: 'queued' }).length;
  if (optimisticQueuedCount === 0) return status;

  const queuedCount =
    typeof status.queuedCount === 'number' && Number.isFinite(status.queuedCount)
      ? status.queuedCount
      : 0;
  if (queuedCount > 0) return status;

  return {
    ...status,
    queuedCount: optimisticQueuedCount,
  };
};

import nodeCodeObjectContractsJson from '@docs/ai-paths/node-code-objects-v2/contracts.json';

export type PortableNodeCodeObjectContractEntry = {
  objectId: string;
  title: string;
  objectHashAlgorithm: 'sha256';
  objectHash: string;
};

export type PortableNodeCodeObjectContractsCatalog = {
  schemaVersion: string;
  generatedAt: string;
  specVersion: string;
  totalContracts: number;
  contracts: Record<string, PortableNodeCodeObjectContractEntry>;
  contractsHashAlgorithm: 'sha256';
  contractsHash: string;
};

const asRecord = (value: unknown): Record<string, unknown> | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  return value as Record<string, unknown>;
};

const asTrimmedString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const asSha256Hex = (value: unknown): string | null => {
  const parsed = asTrimmedString(value);
  if (!parsed) return null;
  return /^[a-f0-9]{64}$/i.test(parsed) ? parsed : null;
};

const parseContractEntry = (value: unknown): PortableNodeCodeObjectContractEntry | null => {
  const record = asRecord(value);
  if (!record) return null;
  const objectId = asTrimmedString(record['objectId']);
  const title = asTrimmedString(record['title']);
  const objectHashAlgorithm = record['objectHashAlgorithm'];
  const objectHash = asSha256Hex(record['objectHash']);
  if (!objectId || !title || objectHashAlgorithm !== 'sha256' || !objectHash) return null;
  return {
    objectId,
    title,
    objectHashAlgorithm: 'sha256',
    objectHash: objectHash.toLowerCase(),
  };
};

const parseContractsCatalog = (input: unknown): PortableNodeCodeObjectContractsCatalog => {
  const record = asRecord(input);
  if (!record) {
    return {
      schemaVersion: 'invalid',
      generatedAt: new Date(0).toISOString(),
      specVersion: 'unknown',
      totalContracts: 0,
      contracts: {},
      contractsHashAlgorithm: 'sha256',
      contractsHash: '0'.repeat(64),
    };
  }
  const contractsRecord = asRecord(record['contracts']) ?? {};
  const contracts = Object.fromEntries(
    Object.entries(contractsRecord)
      .map(([nodeType, entry]): [string, PortableNodeCodeObjectContractEntry] | null => {
        const normalizedType = asTrimmedString(nodeType);
        if (!normalizedType) return null;
        const parsedEntry = parseContractEntry(entry);
        if (!parsedEntry) return null;
        return [normalizedType, parsedEntry];
      })
      .filter((row): row is [string, PortableNodeCodeObjectContractEntry] => Boolean(row))
      .sort(([left], [right]) => left.localeCompare(right))
  );
  const schemaVersion = asTrimmedString(record['schemaVersion']) ?? 'invalid';
  const generatedAt = asTrimmedString(record['generatedAt']) ?? new Date(0).toISOString();
  const specVersion = asTrimmedString(record['specVersion']) ?? 'unknown';
  const totalContracts = Number.isFinite(record['totalContracts'])
    ? Math.max(0, Math.trunc(record['totalContracts'] as number))
    : Object.keys(contracts).length;
  const contractsHash = asSha256Hex(record['contractsHash']) ?? '0'.repeat(64);
  return {
    schemaVersion,
    generatedAt,
    specVersion,
    totalContracts,
    contracts,
    contractsHashAlgorithm: 'sha256',
    contractsHash: contractsHash.toLowerCase(),
  };
};

const PORTABLE_NODE_CODE_OBJECT_CONTRACTS: PortableNodeCodeObjectContractsCatalog =
  parseContractsCatalog(nodeCodeObjectContractsJson);

export const getPortableNodeCodeObjectContractsCatalog =
  (): PortableNodeCodeObjectContractsCatalog => ({
    ...PORTABLE_NODE_CODE_OBJECT_CONTRACTS,
    contracts: { ...PORTABLE_NODE_CODE_OBJECT_CONTRACTS.contracts },
  });

export const getPortableNodeCodeObjectContractsHash = (): string =>
  PORTABLE_NODE_CODE_OBJECT_CONTRACTS.contractsHash;

import type { CodeMessageIssueDto } from '@/shared/contracts/base';

import { getPortableNodeCodeObjectContractsCatalog } from './node-code-objects-v2-contracts';

export const PORTABLE_NODE_CODE_OBJECT_MANIFEST_METADATA_KEY = 'aiPathsNodeCodeObjectsV2' as const;
export const PORTABLE_NODE_CODE_OBJECT_MANIFEST_SCHEMA_VERSION =
  'ai-paths.node-code-object-manifest.v1' as const;

export const PORTABLE_NODE_CODE_OBJECT_HASH_VERIFICATION_MODES = ['off', 'warn', 'strict'] as const;
export type PortableNodeCodeObjectHashVerificationMode =
  (typeof PORTABLE_NODE_CODE_OBJECT_HASH_VERIFICATION_MODES)[number];

export type PortableNodeCodeObjectManifestEntry = {
  nodeType: string;
  objectHashAlgorithm: 'sha256';
  objectHash: string;
};

export type PortableNodeCodeObjectManifest = {
  schemaVersion: typeof PORTABLE_NODE_CODE_OBJECT_MANIFEST_SCHEMA_VERSION;
  contractsSchemaVersion: string;
  contractsHashAlgorithm: 'sha256';
  contractsHash: string;
  generatedAt: string;
  entries: PortableNodeCodeObjectManifestEntry[];
};

export type PortableNodeCodeObjectManifestWarningCode =
  | 'node_code_object_manifest_invalid'
  | 'node_code_object_hash_missing'
  | 'node_code_object_hash_mismatch'
  | 'node_code_object_hash_unknown_node_type';

export type PortableNodeCodeObjectManifestWarning =
  CodeMessageIssueDto<PortableNodeCodeObjectManifestWarningCode>;

const asRecord = (value: unknown): Record<string, unknown> | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  return value as Record<string, unknown>;
};

const asTrimmedString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const asSha256Hex = (value: unknown): string | null => {
  const parsed = asTrimmedString(value);
  if (!parsed) return null;
  return /^[a-f0-9]{64}$/i.test(parsed) ? parsed : null;
};

const resolveUniqueNodeTypes = (nodeTypes: string[]): string[] =>
  Array.from(
    new Set(
      nodeTypes
        .map((nodeType: string): string => (typeof nodeType === 'string' ? nodeType.trim() : ''))
        .filter(Boolean)
    )
  ).sort((left, right) => left.localeCompare(right));

const parseManifestEntry = (value: unknown): PortableNodeCodeObjectManifestEntry | null => {
  const record = asRecord(value);
  if (!record) return null;
  const nodeType = asTrimmedString(record['nodeType']);
  const objectHashAlgorithm = record['objectHashAlgorithm'];
  const objectHash = asSha256Hex(record['objectHash']);
  if (!nodeType || objectHashAlgorithm !== 'sha256' || !objectHash) return null;
  return {
    nodeType,
    objectHashAlgorithm: 'sha256',
    objectHash: objectHash.toLowerCase(),
  };
};

const parseManifest = (value: unknown): PortableNodeCodeObjectManifest | null => {
  const record = asRecord(value);
  if (!record) return null;
  const schemaVersion = asTrimmedString(record['schemaVersion']);
  if (schemaVersion !== PORTABLE_NODE_CODE_OBJECT_MANIFEST_SCHEMA_VERSION) return null;
  const contractsSchemaVersion = asTrimmedString(record['contractsSchemaVersion']);
  const contractsHashAlgorithm = record['contractsHashAlgorithm'];
  const contractsHash = asSha256Hex(record['contractsHash']);
  const generatedAt = asTrimmedString(record['generatedAt']);
  const entriesRaw = Array.isArray(record['entries']) ? record['entries'] : null;
  if (
    !contractsSchemaVersion ||
    contractsHashAlgorithm !== 'sha256' ||
    !contractsHash ||
    !generatedAt ||
    !entriesRaw
  ) {
    return null;
  }
  const entries = entriesRaw
    .map((entry: unknown): PortableNodeCodeObjectManifestEntry | null => parseManifestEntry(entry))
    .filter((entry): entry is PortableNodeCodeObjectManifestEntry => Boolean(entry))
    .sort((left, right) => left.nodeType.localeCompare(right.nodeType));
  return {
    schemaVersion: PORTABLE_NODE_CODE_OBJECT_MANIFEST_SCHEMA_VERSION,
    contractsSchemaVersion,
    contractsHashAlgorithm: 'sha256',
    contractsHash: contractsHash.toLowerCase(),
    generatedAt,
    entries,
  };
};

const formatVerificationError = (warning: PortableNodeCodeObjectManifestWarning): string =>
  `Portable node code object verification failed: ${warning.message}`;

const finalizeVerification = (
  mode: PortableNodeCodeObjectHashVerificationMode,
  warnings: PortableNodeCodeObjectManifestWarning[]
):
  | { ok: true; warnings: PortableNodeCodeObjectManifestWarning[] }
  | { ok: false; error: string; warnings: PortableNodeCodeObjectManifestWarning[] } => {
  if (warnings.length === 0 || mode !== 'strict') {
    return { ok: true, warnings };
  }
  return {
    ok: false,
    error: formatVerificationError(warnings[0]!),
    warnings,
  };
};

export const buildPortableNodeCodeObjectManifest = (
  nodeTypes: string[]
): PortableNodeCodeObjectManifest => {
  const contractsCatalog = getPortableNodeCodeObjectContractsCatalog();
  const entries = resolveUniqueNodeTypes(nodeTypes)
    .map((nodeType: string): PortableNodeCodeObjectManifestEntry | null => {
      const contract = contractsCatalog.contracts[nodeType];
      if (!contract) return null;
      return {
        nodeType,
        objectHashAlgorithm: contract.objectHashAlgorithm,
        objectHash: contract.objectHash,
      };
    })
    .filter((entry): entry is PortableNodeCodeObjectManifestEntry => Boolean(entry));
  return {
    schemaVersion: PORTABLE_NODE_CODE_OBJECT_MANIFEST_SCHEMA_VERSION,
    contractsSchemaVersion: contractsCatalog.schemaVersion,
    contractsHashAlgorithm: contractsCatalog.contractsHashAlgorithm,
    contractsHash: contractsCatalog.contractsHash,
    generatedAt: new Date().toISOString(),
    entries,
  };
};

export const withPortableNodeCodeObjectManifest = (
  metadata: Record<string, unknown> | undefined,
  nodeTypes: string[]
): Record<string, unknown> => ({
  ...(metadata ?? {}),
  [PORTABLE_NODE_CODE_OBJECT_MANIFEST_METADATA_KEY]: buildPortableNodeCodeObjectManifest(nodeTypes),
});

export const verifyPortableNodeCodeObjectManifest = ({
  metadata,
  nodeTypes,
  mode,
}: {
  metadata: Record<string, unknown> | undefined;
  nodeTypes: string[];
  mode: PortableNodeCodeObjectHashVerificationMode;
}):
  | { ok: true; warnings: PortableNodeCodeObjectManifestWarning[] }
  | { ok: false; error: string; warnings: PortableNodeCodeObjectManifestWarning[] } => {
  if (mode === 'off') {
    return { ok: true, warnings: [] };
  }
  const manifestRaw = metadata?.[PORTABLE_NODE_CODE_OBJECT_MANIFEST_METADATA_KEY];
  if (manifestRaw === undefined || manifestRaw === null) {
    return { ok: true, warnings: [] };
  }

  const parsedManifest = parseManifest(manifestRaw);
  if (!parsedManifest) {
    return finalizeVerification(mode, [
      {
        code: 'node_code_object_manifest_invalid',
        message:
          'Portable package metadata contains an invalid node code object manifest (aiPathsNodeCodeObjectsV2).',
      },
    ]);
  }

  const manifestEntryByNodeType = new Map<string, PortableNodeCodeObjectManifestEntry>(
    parsedManifest.entries.map((entry) => [entry.nodeType, entry])
  );
  const contractsCatalog = getPortableNodeCodeObjectContractsCatalog();
  const warnings: PortableNodeCodeObjectManifestWarning[] = [];
  for (const nodeType of resolveUniqueNodeTypes(nodeTypes)) {
    const contract = contractsCatalog.contracts[nodeType];
    if (!contract) {
      warnings.push({
        code: 'node_code_object_hash_unknown_node_type',
        message: `Node type "${nodeType}" is not present in local node code object contracts.`,
      });
      continue;
    }
    const entry = manifestEntryByNodeType.get(nodeType);
    if (!entry) {
      warnings.push({
        code: 'node_code_object_hash_missing',
        message: `Node type "${nodeType}" is missing from package node code object manifest.`,
      });
      continue;
    }
    if (
      entry.objectHashAlgorithm !== contract.objectHashAlgorithm ||
      entry.objectHash.toLowerCase() !== contract.objectHash.toLowerCase()
    ) {
      warnings.push({
        code: 'node_code_object_hash_mismatch',
        message: `Node type "${nodeType}" manifest hash does not match local node code object contracts.`,
      });
    }
  }

  return finalizeVerification(mode, warnings);
};

import { z } from 'zod';

import { type PathConfig, pathConfigSchema } from '@/shared/contracts/ai-paths';
import { canvasSemanticDocumentSchema } from '@/shared/contracts/ai-paths-semantic-grammar';
import { serializePathConfigToSemanticCanvas } from '@/shared/lib/ai-paths/core/semantic-grammar';

import { withPortableNodeCodeObjectManifest } from './node-code-objects-v2-manifest';
import {
  AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION,
  type AiPathPortablePackage,
  type BuildPortablePathPackageOptions,
  PORTABLE_PATH_JSON_SCHEMA_KINDS,
  type PortablePathJsonSchemaCatalog,
  type PortablePathJsonSchemaDiffEntry,
  type PortablePathJsonSchemaDiffReport,
  aiPathPortablePackageEnvelopeSchema,
  aiPathPortablePackageSchema,
} from './portable-engine-contract';
import { buildPortablePathJsonSchemaHash } from './portable-engine-integrity-support';


export const buildPortablePathPackage = (
  pathConfig: PathConfig,
  options?: BuildPortablePathPackageOptions
): AiPathPortablePackage => {
  const createdAt = options?.createdAt ?? new Date().toISOString();
  const nodeTypes = (pathConfig.nodes ?? [])
    .map((node) => (typeof node?.type === 'string' ? node.type.trim() : ''))
    .filter((nodeType): nodeType is string => nodeType.length > 0);
  const metadata = withPortableNodeCodeObjectManifest(options?.metadata, nodeTypes);
  const semanticDocument = serializePathConfigToSemanticCanvas(pathConfig, {
    includeConnections: options?.includeConnections !== false,
    exportedAt: createdAt,
    exporterVersion: options?.exporterVersion,
    workspace: options?.workspace,
  });
  return {
    specVersion: AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION,
    kind: 'path_package',
    createdAt,
    pathId: pathConfig.id,
    name: pathConfig.name,
    document: semanticDocument,
    ...(Object.keys(metadata).length > 0 ? { metadata } : {}),
  };
};

export const serializePortablePathPackage = (
  pathConfig: PathConfig,
  options?: BuildPortablePathPackageOptions
): string => JSON.stringify(buildPortablePathPackage(pathConfig, options), null, 2);

const toJsonSchemaRecord = (schema: z.ZodTypeAny): Record<string, unknown> =>
  z.toJSONSchema(schema, {
    // Portable contracts should describe the accepted payload shape, even when
    // some internal branches normalize values with transforms.
    io: 'input',
    unrepresentable: 'any',
  }) as Record<string, unknown>;

export const buildPortablePathJsonSchemaCatalog = (): PortablePathJsonSchemaCatalog => ({
  portable_envelope: toJsonSchemaRecord(aiPathPortablePackageEnvelopeSchema),
  portable_package: toJsonSchemaRecord(aiPathPortablePackageSchema),
  semantic_canvas: toJsonSchemaRecord(canvasSemanticDocumentSchema),
  path_config: toJsonSchemaRecord(pathConfigSchema),
});

export const buildPortablePathJsonSchemaCatalogVNextPreview = (): PortablePathJsonSchemaCatalog =>
  buildPortablePathJsonSchemaCatalog();

export const buildPortablePathJsonSchemaDiffReport = (): PortablePathJsonSchemaDiffReport => {
  const currentCatalog = buildPortablePathJsonSchemaCatalog();
  const vNextCatalog = buildPortablePathJsonSchemaCatalogVNextPreview();
  const entries: PortablePathJsonSchemaDiffEntry[] = PORTABLE_PATH_JSON_SCHEMA_KINDS.map((kind) => {
    const currentSchema = currentCatalog[kind];
    const vNextSchema = vNextCatalog[kind];
    const currentHash = buildPortablePathJsonSchemaHash(currentSchema);
    const vNextHash = buildPortablePathJsonSchemaHash(vNextSchema);
    return {
      kind,
      changed: currentHash !== vNextHash,
      currentHash,
      vNextHash,
    };
  });
  const changedKinds = entries.filter((entry) => entry.changed).map((entry) => entry.kind);
  return {
    baseline: 'current',
    target: 'vnext_preview',
    hasChanges: changedKinds.length > 0,
    changedKinds,
    entries,
  };
};

