import { dispatchPortablePathEnvelopeVerificationAuditSinks } from './portable-engine-envelope-audit-sinks';

import type { PortablePathEnvelopeSignatureVerificationMode } from './portable-engine-resolution-types';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export type PortablePathEnvelopeVerificationOutcome =
  | 'signature_missing'
  | 'key_missing'
  | 'async_required'
  | 'unsupported_algorithm'
  | 'verification_unavailable'
  | 'mismatch'
  | 'verified';

export type PortablePathEnvelopeVerificationStatus = 'verified' | 'warned' | 'rejected';

export type PortablePathEnvelopeVerificationAuditEvent = {
  at: string;
  phase: 'sync' | 'async';
  mode: PortablePathEnvelopeSignatureVerificationMode;
  algorithm: string | null;
  keyId: string | null;
  candidateSecretCount: number;
  matchedSecretIndex: number | null;
  outcome: PortablePathEnvelopeVerificationOutcome;
  status: PortablePathEnvelopeVerificationStatus;
};

export type PortablePathEnvelopeVerificationObservabilityByKeyId = {
  events: number;
  verified: number;
  warned: number;
  rejected: number;
  lastOutcome: PortablePathEnvelopeVerificationOutcome | null;
  lastSeenAt: string | null;
  lastAlgorithm: string | null;
};

export type PortablePathEnvelopeVerificationObservabilitySnapshot = {
  totals: {
    events: number;
    verified: number;
    warned: number;
    rejected: number;
  };
  byKeyId: Record<string, PortablePathEnvelopeVerificationObservabilityByKeyId>;
  recentEvents: PortablePathEnvelopeVerificationAuditEvent[];
};

export type PortablePathEnvelopeVerificationObservabilityHook = (
  event: PortablePathEnvelopeVerificationAuditEvent,
  snapshot: PortablePathEnvelopeVerificationObservabilitySnapshot
) => void;

const MAX_PORTABLE_PATH_ENVELOPE_VERIFICATION_EVENTS = 100;
const PORTABLE_PATH_ENVELOPE_KEY_ID_UNSPECIFIED = '(none)';

const createEmptyPortablePathEnvelopeVerificationObservabilityState =
  (): PortablePathEnvelopeVerificationObservabilitySnapshot => ({
    totals: {
      events: 0,
      verified: 0,
      warned: 0,
      rejected: 0,
    },
    byKeyId: {},
    recentEvents: [],
  });

let portablePathEnvelopeVerificationObservabilityState =
  createEmptyPortablePathEnvelopeVerificationObservabilityState();
const portablePathEnvelopeVerificationObservabilityHooks =
  new Set<PortablePathEnvelopeVerificationObservabilityHook>();

const clonePortablePathEnvelopeVerificationObservabilitySnapshot = (
  snapshot: PortablePathEnvelopeVerificationObservabilitySnapshot
): PortablePathEnvelopeVerificationObservabilitySnapshot => ({
  totals: { ...snapshot.totals },
  byKeyId: Object.fromEntries(
    Object.entries(snapshot.byKeyId).map(([keyId, stats]) => [keyId, { ...stats }])
  ),
  recentEvents: snapshot.recentEvents.map((event) => ({ ...event })),
});

export const getPortablePathEnvelopeVerificationObservabilitySnapshot =
  (): PortablePathEnvelopeVerificationObservabilitySnapshot =>
    clonePortablePathEnvelopeVerificationObservabilitySnapshot(
      portablePathEnvelopeVerificationObservabilityState
    );

const emitPortablePathEnvelopeVerificationObservabilityEvent = (
  event: PortablePathEnvelopeVerificationAuditEvent,
  snapshot: PortablePathEnvelopeVerificationObservabilitySnapshot
): void => {
  if (portablePathEnvelopeVerificationObservabilityHooks.size === 0) return;
  for (const hook of portablePathEnvelopeVerificationObservabilityHooks) {
    try {
      hook(event, snapshot);
    } catch (error) {
      logClientError(error);

      // Observability hooks must not break verification flow.
    }
  }
};

const resolvePortablePathEnvelopeVerificationKeyIdBucket = (keyId: string | null): string => {
  if (typeof keyId !== 'string') return PORTABLE_PATH_ENVELOPE_KEY_ID_UNSPECIFIED;
  const normalized = keyId.trim();
  return normalized.length > 0 ? normalized : PORTABLE_PATH_ENVELOPE_KEY_ID_UNSPECIFIED;
};

const ensurePortablePathEnvelopeVerificationByKeyId = (
  keyId: string
): PortablePathEnvelopeVerificationObservabilityByKeyId => {
  if (!portablePathEnvelopeVerificationObservabilityState.byKeyId[keyId]) {
    portablePathEnvelopeVerificationObservabilityState.byKeyId[keyId] = {
      events: 0,
      verified: 0,
      warned: 0,
      rejected: 0,
      lastOutcome: null,
      lastSeenAt: null,
      lastAlgorithm: null,
    };
  }
  return portablePathEnvelopeVerificationObservabilityState.byKeyId[keyId];
};

export const recordPortablePathEnvelopeVerificationEvent = (
  event: Omit<PortablePathEnvelopeVerificationAuditEvent, 'at'>
): void => {
  const finalizedEvent: PortablePathEnvelopeVerificationAuditEvent = {
    ...event,
    at: new Date().toISOString(),
  };
  portablePathEnvelopeVerificationObservabilityState.totals.events += 1;
  switch (finalizedEvent.status) {
    case 'verified':
      portablePathEnvelopeVerificationObservabilityState.totals.verified += 1;
      break;
    case 'warned':
      portablePathEnvelopeVerificationObservabilityState.totals.warned += 1;
      break;
    case 'rejected':
      portablePathEnvelopeVerificationObservabilityState.totals.rejected += 1;
      break;
    default:
      break;
  }
  const keyIdBucket = resolvePortablePathEnvelopeVerificationKeyIdBucket(finalizedEvent.keyId);
  const byKeyIdStats = ensurePortablePathEnvelopeVerificationByKeyId(keyIdBucket);
  byKeyIdStats.events += 1;
  switch (finalizedEvent.status) {
    case 'verified':
      byKeyIdStats.verified += 1;
      break;
    case 'warned':
      byKeyIdStats.warned += 1;
      break;
    case 'rejected':
      byKeyIdStats.rejected += 1;
      break;
    default:
      break;
  }
  byKeyIdStats.lastOutcome = finalizedEvent.outcome;
  byKeyIdStats.lastSeenAt = finalizedEvent.at;
  byKeyIdStats.lastAlgorithm = finalizedEvent.algorithm;

  portablePathEnvelopeVerificationObservabilityState.recentEvents.push(finalizedEvent);
  if (
    portablePathEnvelopeVerificationObservabilityState.recentEvents.length >
    MAX_PORTABLE_PATH_ENVELOPE_VERIFICATION_EVENTS
  ) {
    portablePathEnvelopeVerificationObservabilityState.recentEvents.shift();
  }
  const snapshot = getPortablePathEnvelopeVerificationObservabilitySnapshot();
  emitPortablePathEnvelopeVerificationObservabilityEvent(finalizedEvent, snapshot);
  dispatchPortablePathEnvelopeVerificationAuditSinks(finalizedEvent, snapshot);
};

export const registerPortablePathEnvelopeVerificationObservabilityHook = (
  hook: PortablePathEnvelopeVerificationObservabilityHook
): (() => void) => {
  portablePathEnvelopeVerificationObservabilityHooks.add(hook);
  return () => {
    portablePathEnvelopeVerificationObservabilityHooks.delete(hook);
  };
};

export const resetPortablePathEnvelopeVerificationObservabilitySnapshot = (): void => {
  portablePathEnvelopeVerificationObservabilityState =
    createEmptyPortablePathEnvelopeVerificationObservabilityState();
};

export {
  getPortablePathEnvelopeVerificationAuditSinkSnapshot,
  listPortablePathEnvelopeVerificationAuditSinkIds,
  registerPortablePathEnvelopeVerificationAuditSink,
  resetPortablePathEnvelopeVerificationAuditSinkSnapshot,
  unregisterPortablePathEnvelopeVerificationAuditSink,
} from './portable-engine-envelope-audit-sinks';

export type {
  PortablePathEnvelopeVerificationAuditSink,
  PortablePathEnvelopeVerificationAuditSinkById,
  PortablePathEnvelopeVerificationAuditSinkFailureTelemetry,
  PortablePathEnvelopeVerificationAuditSinkSnapshot,
} from './portable-engine-envelope-audit-sinks';

import { stableStringify } from '@/shared/lib/ai-paths/core/utils/runtime';

import {
  AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION,
  type AiPathPortablePackage,
  type AiPathPortablePackageEnvelope,
  type BuildPortablePathPackageEnvelopeOptions,
  type PortablePathEnvelopeSignature,
} from './portable-engine-contract';
import {
  computeHmacSha256Hex,
  createStableHashHex,
  normalizeOptionalSecret,
  normalizePortableEnvelopeSignatureInput,
} from './portable-engine-integrity-support';

export const computePortablePathEnvelopeSignatureSync = (
  input: unknown,
  options?: Pick<BuildPortablePathPackageEnvelopeOptions, 'secret' | 'keyId'>
): PortablePathEnvelopeSignature => {
  const normalized = stableStringify(normalizePortableEnvelopeSignatureInput(input));
  const secret = normalizeOptionalSecret(options?.secret);
  const stableInput = secret ? `${secret}:${normalized}` : normalized;
  return {
    algorithm: 'stable_hash_v1',
    value: createStableHashHex(stableInput),
    ...(options?.keyId ? { keyId: options.keyId } : {}),
  };
};

export const computePortablePathEnvelopeSignature = async (
  input: unknown,
  options?: Pick<BuildPortablePathPackageEnvelopeOptions, 'secret' | 'keyId'>
): Promise<PortablePathEnvelopeSignature> => {
  const normalized = stableStringify(normalizePortableEnvelopeSignatureInput(input));
  const secret = normalizeOptionalSecret(options?.secret);
  if (secret) {
    const hmac = await computeHmacSha256Hex(normalized, secret);
    if (hmac) {
      return {
        algorithm: 'hmac_sha256',
        value: hmac,
        ...(options?.keyId ? { keyId: options.keyId } : {}),
      };
    }
  }
  return computePortablePathEnvelopeSignatureSync(input, options);
};

export const buildPortablePathPackageEnvelope = async (
  portablePackage: AiPathPortablePackage,
  options?: BuildPortablePathPackageEnvelopeOptions
): Promise<AiPathPortablePackageEnvelope> => {
  const envelope: Omit<AiPathPortablePackageEnvelope, 'signature'> = {
    specVersion: AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION,
    kind: 'path_package_envelope',
    signedAt: options?.signedAt ?? new Date().toISOString(),
    package: portablePackage,
    ...(options?.metadata ? { metadata: options.metadata } : {}),
  };
  const signature = await computePortablePathEnvelopeSignature(envelope, {
    secret: options?.secret,
    keyId: options?.keyId,
  });
  return {
    ...envelope,
    signature,
  };
};

export const serializePortablePathPackageEnvelope = async (
  portablePackage: AiPathPortablePackage,
  options?: BuildPortablePathPackageEnvelopeOptions
): Promise<string> =>
  JSON.stringify(await buildPortablePathPackageEnvelope(portablePackage, options), null, 2);

import { stableStringify } from '@/shared/lib/ai-paths/core/utils/runtime';

import { computePortablePathEnvelopeSignatureSync } from './portable-engine-envelope-signing';
import {
  acceptPortablePathEnvelopeVerification,
  createPortablePathEnvelopeSignatureAsyncUnsupportedAlgorithmWarning,
  createPortablePathEnvelopeSignatureKeyMissingWarning,
  createPortablePathEnvelopeSignatureMismatchWarning,
  createPortablePathEnvelopeSignatureMissingWarning,
  createPortablePathEnvelopeSignatureVerificationUnavailableWarning,
  warnOrRejectPortablePathEnvelopeVerification,
  type PortablePathEnvelopeVerificationResult,
} from './portable-engine-envelope-verification-support';
import {
  type PortablePathEnvelopeSignatureVerificationOptions,
  computeHmacSha256Hex,
  normalizePortableEnvelopeSignatureInput,
  resolveEnvelopeSignatureSecrets,
} from './portable-engine-integrity-support';

import type { AiPathPortablePackageEnvelopeVersioned } from './portable-engine-contract';
import type { PortablePathEnvelopeSignatureVerificationMode } from './portable-engine-resolution-types';

const rejectAsyncEnvelopeVerification = (
  mode: PortablePathEnvelopeSignatureVerificationMode,
  signature: AiPathPortablePackageEnvelopeVersioned['signature'],
  outcome: Parameters<typeof warnOrRejectPortablePathEnvelopeVerification>[3],
  candidateSecretCount: number,
  warning: Parameters<typeof warnOrRejectPortablePathEnvelopeVerification>[6]
): PortablePathEnvelopeVerificationResult =>
  warnOrRejectPortablePathEnvelopeVerification(
    'async',
    mode,
    signature,
    outcome,
    candidateSecretCount,
    null,
    warning
  );

const acceptAsyncEnvelopeVerification = (
  mode: PortablePathEnvelopeSignatureVerificationMode,
  signature: NonNullable<AiPathPortablePackageEnvelopeVersioned['signature']>,
  candidateSecretCount: number,
  matchedSecretIndex: number | null
): PortablePathEnvelopeVerificationResult =>
  acceptPortablePathEnvelopeVerification(
    'async',
    mode,
    signature,
    candidateSecretCount,
    matchedSecretIndex
  );

const resolveAsyncSignatureSecrets = (
  mode: PortablePathEnvelopeSignatureVerificationMode,
  options: PortablePathEnvelopeSignatureVerificationOptions | undefined,
  signature: NonNullable<AiPathPortablePackageEnvelopeVersioned['signature']>
): string[] =>
  resolveEnvelopeSignatureSecrets(options, {
    phase: 'async',
    mode,
    algorithm: signature.algorithm,
    keyId: signature.keyId ?? null,
  });

const verifyStableHashEnvelopeSignatureAsync = (
  portableEnvelope: AiPathPortablePackageEnvelopeVersioned,
  mode: PortablePathEnvelopeSignatureVerificationMode,
  options: PortablePathEnvelopeSignatureVerificationOptions | undefined,
  signature: NonNullable<AiPathPortablePackageEnvelopeVersioned['signature']>
): PortablePathEnvelopeVerificationResult => {
  const candidateSecrets = resolveAsyncSignatureSecrets(mode, options, signature);
  const expectedSignature = computePortablePathEnvelopeSignatureSync(portableEnvelope, {
    secret: candidateSecrets[0],
    keyId: signature.keyId,
  });
  if (signature.value !== expectedSignature.value) {
    return rejectAsyncEnvelopeVerification(
      mode,
      signature,
      'mismatch',
      candidateSecrets.length,
      createPortablePathEnvelopeSignatureMismatchWarning()
    );
  }
  return acceptAsyncEnvelopeVerification(mode, signature, candidateSecrets.length, candidateSecrets.length > 0 ? 0 : null);
};

const findMatchingHmacSecretIndex = async (
  normalizedEnvelope: string,
  candidateSecrets: string[],
  signatureValue: string
): Promise<{ hasRuntimeVerification: boolean; matchedSecretIndex: number | null }> => {
  let hasRuntimeVerification = false;
  let matchedSecretIndex: number | null = null;
  for (let index = 0; index < candidateSecrets.length; index += 1) {
    const secret = candidateSecrets[index]!;
    const hmac = await computeHmacSha256Hex(normalizedEnvelope, secret);
    if (!hmac) continue;
    hasRuntimeVerification = true;
    if (hmac === signatureValue) {
      matchedSecretIndex = index;
      break;
    }
  }
  return { hasRuntimeVerification, matchedSecretIndex };
};

const verifyHmacEnvelopeSignatureAsync = async (
  portableEnvelope: AiPathPortablePackageEnvelopeVersioned,
  mode: PortablePathEnvelopeSignatureVerificationMode,
  options: PortablePathEnvelopeSignatureVerificationOptions | undefined,
  signature: NonNullable<AiPathPortablePackageEnvelopeVersioned['signature']>
): Promise<PortablePathEnvelopeVerificationResult> => {
  const candidateSecrets = resolveAsyncSignatureSecrets(mode, options, signature);
  if (candidateSecrets.length === 0) {
    return rejectAsyncEnvelopeVerification(
      mode,
      signature,
      'key_missing',
      0,
      createPortablePathEnvelopeSignatureKeyMissingWarning()
    );
  }

  const normalized = stableStringify(normalizePortableEnvelopeSignatureInput(portableEnvelope));
  const { hasRuntimeVerification, matchedSecretIndex } = await findMatchingHmacSecretIndex(
    normalized,
    candidateSecrets,
    signature.value
  );
  if (!hasRuntimeVerification) {
    return rejectAsyncEnvelopeVerification(
      mode,
      signature,
      'verification_unavailable',
      candidateSecrets.length,
      createPortablePathEnvelopeSignatureVerificationUnavailableWarning()
    );
  }
  if (matchedSecretIndex === null) {
    return rejectAsyncEnvelopeVerification(
      mode,
      signature,
      'mismatch',
      candidateSecrets.length,
      createPortablePathEnvelopeSignatureMismatchWarning()
    );
  }
  return acceptAsyncEnvelopeVerification(mode, signature, candidateSecrets.length, matchedSecretIndex);
};

export const verifyPortablePathPackageEnvelopeSignatureAsync = async (
  portableEnvelope: AiPathPortablePackageEnvelopeVersioned,
  mode: PortablePathEnvelopeSignatureVerificationMode,
  options?: PortablePathEnvelopeSignatureVerificationOptions
): Promise<PortablePathEnvelopeVerificationResult> => {
  if (mode === 'off') {
    return { ok: true, warnings: [] };
  }

  const signature = portableEnvelope.signature;
  if (!signature) {
    return rejectAsyncEnvelopeVerification(
      mode,
      signature,
      'signature_missing',
      0,
      createPortablePathEnvelopeSignatureMissingWarning()
    );
  }

  if (signature.algorithm === 'stable_hash_v1') {
    return verifyStableHashEnvelopeSignatureAsync(portableEnvelope, mode, options, signature);
  }

  if (signature.algorithm === 'hmac_sha256') {
    return verifyHmacEnvelopeSignatureAsync(portableEnvelope, mode, options, signature);
  }

  return rejectAsyncEnvelopeVerification(
    mode,
    signature,
    'unsupported_algorithm',
    0,
    createPortablePathEnvelopeSignatureAsyncUnsupportedAlgorithmWarning(signature.algorithm)
  );
};

import { recordPortablePathEnvelopeVerificationEvent } from './portable-engine-envelope-observability';

import type { AiPathPortablePackageEnvelopeVersioned } from './portable-engine-contract';
import type {
  PortablePathEnvelopeVerificationOutcome,
  PortablePathEnvelopeVerificationStatus,
} from './portable-engine-envelope-observability';
import type { PortablePathMigrationWarning } from './portable-engine-migration-types';
import type { PortablePathEnvelopeSignatureVerificationMode } from './portable-engine-resolution-types';

export type PortablePathEnvelopeVerificationPhase = 'sync' | 'async';

export type PortablePathEnvelopeVerificationResult =
  | { ok: true; warnings: PortablePathMigrationWarning[] }
  | { ok: false; error: string; warnings: PortablePathMigrationWarning[] };

const formatEnvelopeVerificationError = (warning: PortablePathMigrationWarning): string =>
  `Portable package envelope verification failed: ${warning.message}`;

export const recordPortablePathEnvelopeVerificationResult = (
  phase: PortablePathEnvelopeVerificationPhase,
  mode: PortablePathEnvelopeSignatureVerificationMode,
  signature: AiPathPortablePackageEnvelopeVersioned['signature'],
  outcome: PortablePathEnvelopeVerificationOutcome,
  status: PortablePathEnvelopeVerificationStatus,
  candidateSecretCount: number,
  matchedSecretIndex: number | null
): void => {
  recordPortablePathEnvelopeVerificationEvent({
    phase,
    mode,
    algorithm: signature?.algorithm ?? null,
    keyId: signature?.keyId ?? null,
    candidateSecretCount,
    matchedSecretIndex,
    outcome,
    status,
  });
};

export const warnOrRejectPortablePathEnvelopeVerification = (
  phase: PortablePathEnvelopeVerificationPhase,
  mode: PortablePathEnvelopeSignatureVerificationMode,
  signature: AiPathPortablePackageEnvelopeVersioned['signature'],
  outcome: PortablePathEnvelopeVerificationOutcome,
  candidateSecretCount: number,
  matchedSecretIndex: number | null,
  warning: PortablePathMigrationWarning
): PortablePathEnvelopeVerificationResult => {
  if (mode === 'strict') {
    recordPortablePathEnvelopeVerificationResult(
      phase,
      mode,
      signature,
      outcome,
      'rejected',
      candidateSecretCount,
      matchedSecretIndex
    );
    return {
      ok: false,
      error: formatEnvelopeVerificationError(warning),
      warnings: [warning],
    };
  }
  recordPortablePathEnvelopeVerificationResult(
    phase,
    mode,
    signature,
    outcome,
    'warned',
    candidateSecretCount,
    matchedSecretIndex
  );
  return { ok: true, warnings: [warning] };
};

export const acceptPortablePathEnvelopeVerification = (
  phase: PortablePathEnvelopeVerificationPhase,
  mode: PortablePathEnvelopeSignatureVerificationMode,
  signature: AiPathPortablePackageEnvelopeVersioned['signature'],
  candidateSecretCount: number,
  matchedSecretIndex: number | null
): PortablePathEnvelopeVerificationResult => {
  recordPortablePathEnvelopeVerificationResult(
    phase,
    mode,
    signature,
    'verified',
    'verified',
    candidateSecretCount,
    matchedSecretIndex
  );
  return { ok: true, warnings: [] };
};

export const createPortablePathEnvelopeSignatureMissingWarning =
  (): PortablePathMigrationWarning => ({
    code: 'package_envelope_signature_missing',
    message: 'Portable package envelope signature is missing.',
  });

export const createPortablePathEnvelopeSignatureKeyMissingWarning =
  (): PortablePathMigrationWarning => ({
    code: 'package_envelope_signature_key_missing',
    message:
      'Portable package envelope hmac signature requires a verification secret/key. Provide envelopeSignatureSecret, envelopeSignatureSecretsByKeyId, envelopeSignatureFallbackSecrets, or envelopeSignatureKeyResolver.',
  });

export const createPortablePathEnvelopeSignatureAsyncRequiredWarning =
  (): PortablePathMigrationWarning => ({
    code: 'package_envelope_signature_async_required',
    message:
      'Portable package envelope hmac signature requires asynchronous verification. Use resolvePortablePathInputAsync for strict verification.',
  });

export const createPortablePathEnvelopeSignatureSyncUnsupportedAlgorithmWarning = (
  algorithm: string
): PortablePathMigrationWarning => ({
  code: 'package_envelope_signature_unsupported_algorithm',
  message: `Portable package envelope signature algorithm "${algorithm}" cannot be synchronously verified during import.`,
});

export const createPortablePathEnvelopeSignatureAsyncUnsupportedAlgorithmWarning = (
  algorithm: string
): PortablePathMigrationWarning => ({
  code: 'package_envelope_signature_unsupported_algorithm',
  message: `Portable package envelope signature algorithm "${algorithm}" is not supported for verification.`,
});

export const createPortablePathEnvelopeSignatureMismatchWarning =
  (): PortablePathMigrationWarning => ({
    code: 'package_envelope_signature_mismatch',
    message: 'Portable package envelope signature does not match envelope contents.',
  });

export const createPortablePathEnvelopeSignatureVerificationUnavailableWarning =
  (): PortablePathMigrationWarning => ({
    code: 'package_envelope_signature_verification_unavailable',
    message:
      'Portable package envelope hmac signature verification is unavailable in this runtime (crypto.subtle not available).',
  });

import { computePortablePathEnvelopeSignatureSync } from './portable-engine-envelope-signing';
import {
  acceptPortablePathEnvelopeVerification,
  createPortablePathEnvelopeSignatureAsyncRequiredWarning,
  createPortablePathEnvelopeSignatureKeyMissingWarning,
  createPortablePathEnvelopeSignatureMismatchWarning,
  createPortablePathEnvelopeSignatureMissingWarning,
  createPortablePathEnvelopeSignatureSyncUnsupportedAlgorithmWarning,
  warnOrRejectPortablePathEnvelopeVerification,
  type PortablePathEnvelopeVerificationResult,
} from './portable-engine-envelope-verification-support';
import {
  type PortablePathEnvelopeSignatureVerificationOptions,
  resolveEnvelopeSignatureSecrets,
} from './portable-engine-integrity-support';

import type { AiPathPortablePackageEnvelopeVersioned } from './portable-engine-contract';
import type { PortablePathEnvelopeSignatureVerificationMode } from './portable-engine-resolution-types';

const rejectSyncEnvelopeVerification = (
  mode: PortablePathEnvelopeSignatureVerificationMode,
  signature: AiPathPortablePackageEnvelopeVersioned['signature'],
  outcome: Parameters<typeof warnOrRejectPortablePathEnvelopeVerification>[3],
  candidateSecretCount: number,
  warning: Parameters<typeof warnOrRejectPortablePathEnvelopeVerification>[6]
): PortablePathEnvelopeVerificationResult =>
  warnOrRejectPortablePathEnvelopeVerification(
    'sync',
    mode,
    signature,
    outcome,
    candidateSecretCount,
    null,
    warning
  );

const acceptSyncEnvelopeVerification = (
  mode: PortablePathEnvelopeSignatureVerificationMode,
  signature: NonNullable<AiPathPortablePackageEnvelopeVersioned['signature']>,
  candidateSecretCount: number
): PortablePathEnvelopeVerificationResult =>
  acceptPortablePathEnvelopeVerification(
    'sync',
    mode,
    signature,
    candidateSecretCount,
    candidateSecretCount > 0 ? 0 : null
  );

const resolveSyncSignatureSecrets = (
  mode: PortablePathEnvelopeSignatureVerificationMode,
  options: PortablePathEnvelopeSignatureVerificationOptions | undefined,
  signature: NonNullable<AiPathPortablePackageEnvelopeVersioned['signature']>
): string[] =>
  resolveEnvelopeSignatureSecrets(options, {
    phase: 'sync',
    mode,
    algorithm: signature.algorithm,
    keyId: signature.keyId ?? null,
  });

const verifyStableHashEnvelopeSignatureSync = (
  portableEnvelope: AiPathPortablePackageEnvelopeVersioned,
  mode: PortablePathEnvelopeSignatureVerificationMode,
  options: PortablePathEnvelopeSignatureVerificationOptions | undefined,
  signature: NonNullable<AiPathPortablePackageEnvelopeVersioned['signature']>
): PortablePathEnvelopeVerificationResult => {
  const candidateSecrets = resolveSyncSignatureSecrets(mode, options, signature);
  const expectedSignature = computePortablePathEnvelopeSignatureSync(portableEnvelope, {
    secret: candidateSecrets[0],
    keyId: signature.keyId,
  });
  if (signature.value !== expectedSignature.value) {
    return rejectSyncEnvelopeVerification(
      mode,
      signature,
      'mismatch',
      candidateSecrets.length,
      createPortablePathEnvelopeSignatureMismatchWarning()
    );
  }
  return acceptSyncEnvelopeVerification(mode, signature, candidateSecrets.length);
};

const verifyHmacEnvelopeSignatureSync = (
  mode: PortablePathEnvelopeSignatureVerificationMode,
  options: PortablePathEnvelopeSignatureVerificationOptions | undefined,
  signature: NonNullable<AiPathPortablePackageEnvelopeVersioned['signature']>
): PortablePathEnvelopeVerificationResult => {
  const candidateSecrets = resolveSyncSignatureSecrets(mode, options, signature);
  if (candidateSecrets.length === 0) {
    return rejectSyncEnvelopeVerification(
      mode,
      signature,
      'key_missing',
      0,
      createPortablePathEnvelopeSignatureKeyMissingWarning()
    );
  }
  return rejectSyncEnvelopeVerification(
    mode,
    signature,
    'async_required',
    candidateSecrets.length,
    createPortablePathEnvelopeSignatureAsyncRequiredWarning()
  );
};

export const verifyPortablePathPackageEnvelopeSignature = (
  portableEnvelope: AiPathPortablePackageEnvelopeVersioned,
  mode: PortablePathEnvelopeSignatureVerificationMode,
  options?: PortablePathEnvelopeSignatureVerificationOptions
): PortablePathEnvelopeVerificationResult => {
  if (mode === 'off') {
    return { ok: true, warnings: [] };
  }

  const signature = portableEnvelope.signature;
  if (!signature) {
    return rejectSyncEnvelopeVerification(
      mode,
      signature,
      'signature_missing',
      0,
      createPortablePathEnvelopeSignatureMissingWarning()
    );
  }

  if (signature.algorithm === 'hmac_sha256') {
    return verifyHmacEnvelopeSignatureSync(mode, options, signature);
  }

  if (signature.algorithm !== 'stable_hash_v1') {
    return rejectSyncEnvelopeVerification(
      mode,
      signature,
      'unsupported_algorithm',
      0,
      createPortablePathEnvelopeSignatureSyncUnsupportedAlgorithmWarning(signature.algorithm)
    );
  }

  return verifyStableHashEnvelopeSignatureSync(portableEnvelope, mode, options, signature);
};

import type { RuntimeState } from '@/shared/contracts/ai-paths-runtime';
import { evaluateGraphClient } from '@/shared/lib/ai-paths/core/runtime/engine-client';
import type {
  EvaluateGraphOptions,
  RuntimeValidationMiddleware,
} from '@/shared/lib/ai-paths/core/runtime/engine-modules/engine-types';
import { resolveAiPathsRuntimeValidationMiddleware } from '@/shared/lib/ai-paths/core/validation-engine';

import {
  recordPortablePathRunExecutionAttempt,
  recordPortablePathRunExecutionFailure,
  recordPortablePathRunExecutionSuccess,
} from './portable-engine-observability';
import { resolvePortablePathInputAsync } from './portable-engine-resolvers';
import {
  type PortablePathRunOptions,
  type PortablePathRunResult,
  type PortablePathValidationMode,
} from './portable-engine-runtime-types';
import { normalizePortablePathSigningPolicySurface } from './portable-engine-signing-policy';
import {
  PortablePathValidationError,
  validatePortablePathConfig,
} from './portable-engine-validation';

import type { PortablePathInputSource } from './portable-engine-contract';
