export const runPortablePathClient = async (
  input: unknown,
  options: PortablePathRunOptions = {}
): Promise<PortablePathRunResult> => {
  const {
    validateBeforeRun = true,
    validationMode = 'standard',
    validationTriggerNodeId = null,
    runtimeValidationEnabled = true,
    runtimeValidationConfig,
    validationMiddleware,
    signingPolicyProfile,
    signingPolicyTelemetrySurface = 'canvas',
    enforcePayloadLimits = true,
    limits,
    fingerprintVerificationMode,
    envelopeSignatureVerificationMode,
    nodeCodeObjectHashVerificationMode,
    envelopeSignatureSecret,
    envelopeSignatureSecretsByKeyId,
    envelopeSignatureFallbackSecrets,
    envelopeSignatureKeyResolver,
    reportAiPathsError,
    ...engineOptions
  } = options;
  const runStartedAt = Date.now();
  const validationModeForTelemetry: PortablePathValidationMode | null = validateBeforeRun
    ? validationMode
    : null;
  const telemetrySurface = normalizePortablePathSigningPolicySurface(signingPolicyTelemetrySurface);
  let resolvedSourceForTelemetry: PortablePathInputSource | null = null;
  const getDurationMs = (): number => Date.now() - runStartedAt;
  recordPortablePathRunExecutionAttempt({
    runner: 'client',
    surface: telemetrySurface,
  });

  const resolved = await resolvePortablePathInputAsync(input, {
    signingPolicyProfile,
    signingPolicyTelemetrySurface,
    includeConnections: false,
    enforcePayloadLimits,
    limits,
    fingerprintVerificationMode,
    envelopeSignatureVerificationMode,
    nodeCodeObjectHashVerificationMode,
    envelopeSignatureSecret,
    envelopeSignatureSecretsByKeyId,
    envelopeSignatureFallbackSecrets,
    envelopeSignatureKeyResolver,
  });
  if (!resolved.ok) {
    const resolveError = `Invalid AI-Path payload: ${resolved.error}`;
    recordPortablePathRunExecutionFailure({
      runner: 'client',
      surface: telemetrySurface,
      source: null,
      validateBeforeRun,
      validationMode: validationModeForTelemetry,
      durationMs: getDurationMs(),
      failureStage: 'resolve',
      error: resolveError,
    });
    throw new Error(resolveError);
  }
  resolvedSourceForTelemetry = resolved.value.source;

  const validation = validateBeforeRun
    ? validatePortablePathConfig(resolved.value.pathConfig, {
      mode: validationMode,
      triggerNodeId: validationTriggerNodeId,
    })
    : null;
  if (validation && !validation.ok) {
    const validationError = new PortablePathValidationError(validation);
    recordPortablePathRunExecutionFailure({
      runner: 'client',
      surface: telemetrySurface,
      source: resolvedSourceForTelemetry,
      validateBeforeRun,
      validationMode: validationModeForTelemetry,
      durationMs: getDurationMs(),
      failureStage: 'validation',
      error: validationError,
    });
    throw validationError;
  }

  const runtimeValidationMiddleware: EvaluateGraphOptions['validationMiddleware'] =
    resolveAiPathsRuntimeValidationMiddleware({
      validationMiddleware: validationMiddleware as RuntimeValidationMiddleware | null,
      runtimeValidationEnabled: Boolean(runtimeValidationEnabled),
      runtimeValidationConfig:
        runtimeValidationConfig ?? resolved.value.pathConfig.aiPathsValidation ?? null,
      nodes: resolved.value.pathConfig.nodes,
      edges: resolved.value.pathConfig.edges,
    }) ?? (runtimeValidationEnabled === false ? undefined : () => null);

  let runtimeState: RuntimeState;
  try {
    runtimeState = await evaluateGraphClient({
      nodes: resolved.value.pathConfig.nodes,
      edges: resolved.value.pathConfig.edges,
      ...engineOptions,
      ...(runtimeValidationMiddleware ? { validationMiddleware: runtimeValidationMiddleware } : {}),
      reportAiPathsError: reportAiPathsError ?? (() => {}),
    });
  } catch (error) {
    logClientError(error);
    recordPortablePathRunExecutionFailure({
      runner: 'client',
      surface: telemetrySurface,
      source: resolvedSourceForTelemetry,
      validateBeforeRun,
      validationMode: validationModeForTelemetry,
      durationMs: getDurationMs(),
      failureStage: 'runtime',
      error,
    });
    throw error;
  }
  recordPortablePathRunExecutionSuccess({
    runner: 'client',
    surface: telemetrySurface,
    source: resolvedSourceForTelemetry,
    validateBeforeRun,
    validationMode: validationModeForTelemetry,
    durationMs: getDurationMs(),
  });

  return {
    resolved: resolved.value,
    validation,
    runtimeState,
  };
};

import { stableStringify } from '@/shared/lib/ai-paths/core/utils/runtime';

import {
  createStableHashHex,
  normalizePortableFingerprintInput,
  toHex,
} from './portable-engine-integrity-support';

import type { AiPathPortablePackage, PortablePathFingerprint } from './portable-engine-contract';
import type { PortablePathMigrationWarning } from './portable-engine-migration-types';
import type { PortablePathFingerprintVerificationMode } from './portable-engine-resolution-types';

export const computePortablePathFingerprintSync = (input: unknown): PortablePathFingerprint => {
  const normalized = stableStringify(normalizePortableFingerprintInput(input));
  return {
    algorithm: 'stable_hash_v1',
    value: createStableHashHex(normalized),
  };
};

export const computePortablePathFingerprint = async (
  input: unknown
): Promise<PortablePathFingerprint> => {
  const stableFingerprint = computePortablePathFingerprintSync(input);
  const normalized = stableStringify(normalizePortableFingerprintInput(input));
  if (globalThis.crypto?.subtle && typeof TextEncoder === 'function') {
    const digest = await globalThis.crypto.subtle.digest(
      'SHA-256',
      new TextEncoder().encode(normalized)
    );
    return {
      algorithm: 'sha256',
      value: toHex(new Uint8Array(digest)),
    };
  }
  return stableFingerprint;
};

export const verifyPortablePackageFingerprint = (
  portablePackage: AiPathPortablePackage,
  mode: PortablePathFingerprintVerificationMode
):
  | { ok: true; warnings: PortablePathMigrationWarning[] }
  | { ok: false; error: string; warnings: PortablePathMigrationWarning[] } => {
  if (mode === 'off') {
    return { ok: true, warnings: [] };
  }

  const fingerprint = portablePackage.fingerprint;
  if (!fingerprint) {
    const warning: PortablePathMigrationWarning = {
      code: 'package_fingerprint_missing',
      message: 'Portable package fingerprint is missing.',
    };
    if (mode === 'strict') {
      return {
        ok: false,
        error: `Portable package fingerprint verification failed: ${warning.message}`,
        warnings: [warning],
      };
    }
    return { ok: true, warnings: [warning] };
  }

  if (fingerprint.algorithm === 'sha256') {
    const warning: PortablePathMigrationWarning = {
      code: 'package_fingerprint_async_required',
      message:
        'Portable package sha256 fingerprint requires asynchronous verification. Use resolvePortablePathInputAsync for strict verification.',
    };
    if (mode === 'strict') {
      return {
        ok: false,
        error: `Portable package fingerprint verification failed: ${warning.message}`,
        warnings: [warning],
      };
    }
    return { ok: true, warnings: [warning] };
  }

  if (fingerprint.algorithm !== 'stable_hash_v1') {
    const warning: PortablePathMigrationWarning = {
      code: 'package_fingerprint_unsupported_algorithm',
      message: `Portable package fingerprint algorithm "${fingerprint.algorithm}" cannot be synchronously verified during import.`,
    };
    if (mode === 'strict') {
      return {
        ok: false,
        error: `Portable package fingerprint verification failed: ${warning.message}`,
        warnings: [warning],
      };
    }
    return { ok: true, warnings: [warning] };
  }

  const expectedFingerprint = computePortablePathFingerprintSync(portablePackage);
  if (fingerprint.value !== expectedFingerprint.value) {
    const warning: PortablePathMigrationWarning = {
      code: 'package_fingerprint_mismatch',
      message: 'Portable package fingerprint does not match package contents.',
    };
    if (mode === 'strict') {
      return {
        ok: false,
        error: `Portable package fingerprint verification failed: ${warning.message}`,
        warnings: [warning],
      };
    }
    return { ok: true, warnings: [warning] };
  }

  return { ok: true, warnings: [] };
};

export const verifyPortablePackageFingerprintAsync = async (
  portablePackage: AiPathPortablePackage,
  mode: PortablePathFingerprintVerificationMode
): Promise<
  | { ok: true; warnings: PortablePathMigrationWarning[] }
  | { ok: false; error: string; warnings: PortablePathMigrationWarning[] }
> => {
  if (mode === 'off') {
    return { ok: true, warnings: [] };
  }

  const fingerprint = portablePackage.fingerprint;
  if (!fingerprint) {
    const warning: PortablePathMigrationWarning = {
      code: 'package_fingerprint_missing',
      message: 'Portable package fingerprint is missing.',
    };
    if (mode === 'strict') {
      return {
        ok: false,
        error: `Portable package fingerprint verification failed: ${warning.message}`,
        warnings: [warning],
      };
    }
    return { ok: true, warnings: [warning] };
  }

  if (fingerprint.algorithm === 'stable_hash_v1') {
    const expectedFingerprint = computePortablePathFingerprintSync(portablePackage);
    if (fingerprint.value !== expectedFingerprint.value) {
      const warning: PortablePathMigrationWarning = {
        code: 'package_fingerprint_mismatch',
        message: 'Portable package fingerprint does not match package contents.',
      };
      if (mode === 'strict') {
        return {
          ok: false,
          error: `Portable package fingerprint verification failed: ${warning.message}`,
          warnings: [warning],
        };
      }
      return { ok: true, warnings: [warning] };
    }
    return { ok: true, warnings: [] };
  }

  if (fingerprint.algorithm === 'sha256') {
    const expectedFingerprint = await computePortablePathFingerprint(portablePackage);
    if (expectedFingerprint.algorithm !== 'sha256') {
      const warning: PortablePathMigrationWarning = {
        code: 'package_fingerprint_verification_unavailable',
        message:
          'Portable package sha256 fingerprint verification is unavailable in this runtime (crypto.subtle not available).',
      };
      if (mode === 'strict') {
        return {
          ok: false,
          error: `Portable package fingerprint verification failed: ${warning.message}`,
          warnings: [warning],
        };
      }
      return { ok: true, warnings: [warning] };
    }
    if (fingerprint.value !== expectedFingerprint.value) {
      const warning: PortablePathMigrationWarning = {
        code: 'package_fingerprint_mismatch',
        message: 'Portable package fingerprint does not match package contents.',
      };
      if (mode === 'strict') {
        return {
          ok: false,
          error: `Portable package fingerprint verification failed: ${warning.message}`,
          warnings: [warning],
        };
      }
      return { ok: true, warnings: [warning] };
    }
    return { ok: true, warnings: [] };
  }

  const warning: PortablePathMigrationWarning = {
    code: 'package_fingerprint_unsupported_algorithm',
    message: `Portable package fingerprint algorithm "${fingerprint.algorithm}" is not supported for verification.`,
  };
  if (mode === 'strict') {
    return {
      ok: false,
      error: `Portable package fingerprint verification failed: ${warning.message}`,
      warnings: [warning],
    };
  }
  return { ok: true, warnings: [warning] };
};

export const addPortablePathPackageFingerprint = async (
  portablePackage: AiPathPortablePackage
): Promise<AiPathPortablePackage> => {
  const fingerprint = await computePortablePathFingerprint(portablePackage);
  return {
    ...portablePackage,
    fingerprint,
  };
};

import { hashString, stableStringify } from '@/shared/lib/ai-paths/core/utils/runtime';

import { AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION } from './portable-engine-contract';

import type { PortablePathEnvelopeSignatureKeyResolverContext } from './portable-engine-resolution-types';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const createStableHashHex = (value: string): string =>
  [
    hashString(value),
    hashString(`a:${value}`),
    hashString(`b:${value}`),
    hashString(`c:${value}`),
  ].join('');

export const buildPortablePathJsonSchemaHash = (schema: Record<string, unknown>): string =>
  createStableHashHex(stableStringify(schema));

export const normalizeOptionalSecret = (value: string | undefined): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

export const normalizeOptionalSecretList = (value: string[] | undefined): string[] => {
  if (!Array.isArray(value) || value.length === 0) return [];
  return value
    .map((item) => normalizeOptionalSecret(item))
    .filter((item): item is string => item !== null);
};

export type PortablePathEnvelopeSignatureVerificationOptions = Pick<
  {
    envelopeSignatureSecret?: string;
    envelopeSignatureSecretsByKeyId?: Record<string, string>;
    envelopeSignatureFallbackSecrets?: string[];
    envelopeSignatureKeyResolver?: (
      context: PortablePathEnvelopeSignatureKeyResolverContext
    ) => string | string[] | null | undefined;
  },
  | 'envelopeSignatureSecret'
  | 'envelopeSignatureSecretsByKeyId'
  | 'envelopeSignatureFallbackSecrets'
  | 'envelopeSignatureKeyResolver'
>;

const collectOptionalSecret = (candidates: string[], value: string | undefined): void => {
  const normalized = normalizeOptionalSecret(value);
  if (normalized) candidates.push(normalized);
};

const collectOptionalSecretList = (candidates: string[], value: string[] | undefined): void => {
  candidates.push(...normalizeOptionalSecretList(value));
};

const collectResolverSecrets = (
  candidates: string[],
  options: PortablePathEnvelopeSignatureVerificationOptions | undefined,
  context: PortablePathEnvelopeSignatureKeyResolverContext
): void => {
  if (!options?.envelopeSignatureKeyResolver) return;
  const resolverResult = options.envelopeSignatureKeyResolver(context);
  if (typeof resolverResult === 'string') {
    collectOptionalSecret(candidates, resolverResult);
    return;
  }
  if (Array.isArray(resolverResult)) {
    collectOptionalSecretList(candidates, resolverResult);
  }
};

const collectKeyIdSecret = (
  candidates: string[],
  options: PortablePathEnvelopeSignatureVerificationOptions | undefined,
  keyId: string | null
): void => {
  if (!keyId || !options?.envelopeSignatureSecretsByKeyId) return;
  collectOptionalSecret(candidates, options.envelopeSignatureSecretsByKeyId[keyId]);
};

export const resolveEnvelopeSignatureSecrets = (
  options: PortablePathEnvelopeSignatureVerificationOptions | undefined,
  context: PortablePathEnvelopeSignatureKeyResolverContext
): string[] => {
  const candidates: string[] = [];
  collectResolverSecrets(candidates, options, context);
  collectKeyIdSecret(candidates, options, context.keyId ?? null);
  collectOptionalSecret(candidates, options?.envelopeSignatureSecret);
  collectOptionalSecretList(candidates, options?.envelopeSignatureFallbackSecrets);
  return Array.from(new Set(candidates));
};

const removeTopLevelFingerprint = (input: unknown): unknown => {
  if (!input || typeof input !== 'object' || Array.isArray(input)) return input;
  const record = input as Record<string, unknown>;
  if (record['specVersion'] !== AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION) return input;
  if (record['kind'] !== 'path_package') return input;
  const { fingerprint: _fingerprint, ...rest } = record;
  return rest;
};

export const normalizePortableFingerprintInput = (input: unknown): unknown => {
  const withoutFingerprint = removeTopLevelFingerprint(input);
  try {
    return JSON.parse(JSON.stringify(withoutFingerprint)) as unknown;
  } catch (error) {
    logClientError(error);
    return withoutFingerprint;
  }
};

const removeTopLevelEnvelopeSignature = (input: unknown): unknown => {
  if (!input || typeof input !== 'object' || Array.isArray(input)) return input;
  const record = input as Record<string, unknown>;
  if (record['kind'] !== 'path_package_envelope') return input;
  const { signature: _signature, ...rest } = record;
  return rest;
};

export const normalizePortableEnvelopeSignatureInput = (input: unknown): unknown => {
  const withoutSignature = removeTopLevelEnvelopeSignature(input);
  try {
    return JSON.parse(JSON.stringify(withoutSignature)) as unknown;
  } catch (error) {
    logClientError(error);
    return withoutSignature;
  }
};

export const toHex = (bytes: Uint8Array): string =>
  Array.from(bytes)
    .map((byte: number): string => byte.toString(16).padStart(2, '0'))
    .join('');

export const computeHmacSha256Hex = async (
  message: string,
  secret: string
): Promise<string | null> => {
  if (!globalThis.crypto?.subtle || typeof TextEncoder !== 'function') {
    return null;
  }
  const encoder = new TextEncoder();
  const key = await globalThis.crypto.subtle.importKey(
    'raw',
    encoder.encode(secret),
    {
      name: 'HMAC',
      hash: 'SHA-256',
    },
    false,
    ['sign']
  );
  const signature = await globalThis.crypto.subtle.sign('HMAC', key, encoder.encode(message));
  return toHex(new Uint8Array(signature));
};

import { type z } from 'zod';

import { pathConfigSchema } from '@/shared/contracts/ai-paths';
import { parseAndDeserializeSemanticCanvas } from '@/shared/lib/ai-paths/core/semantic-grammar';
import {
  findRemovedLegacyAiPathNodesInDocument,
  formatRemovedLegacyAiPathNodesMessage,
} from '@/shared/lib/ai-paths/core/utils/legacy-node-removal';
import {
  findRemovedLegacyTriggerContextModesInDocument,
  formatRemovedLegacyTriggerContextModesMessage,
} from '@/shared/lib/ai-paths/core/utils/legacy-trigger-context-mode';

import { aiPathPortablePackageVersionedSchema } from './portable-engine-contract';
import {
  beginPortablePathMigratorAttempt,
  markPortablePathMigratorFailure,
  markPortablePathMigratorSuccess,
  recordPortablePathMigratorSource,
} from './portable-engine-migrator-observability';
import { applyPortablePathPackageMigrator } from './portable-engine-package-migrators';
import {
  buildCanonicalPackageFromPathConfig,
  normalizePathConfigEdges,
} from './portable-engine-path-canonicalization';

import type {
  MigratePortablePathInputResult,
  PortablePathMigrationWarning,
} from './portable-engine-migration-types';
import type { ResolvePortablePathInputOptions } from './portable-engine-resolution-types';

const formatZodError = (error: z.ZodError): string =>
  error.issues.map((issue) => `${issue.path.join('.') || 'document'}: ${issue.message}`).join('; ');

const isRecord = (value: unknown): value is Record<string, unknown> =>
  value !== null && typeof value === 'object' && !Array.isArray(value);

const hasNonCanonicalPathConfigEdgeAliases = (input: unknown): boolean => {
  if (!isRecord(input) || !Array.isArray(input['edges'])) {
    return false;
  }

  return input['edges'].some((entry: unknown): boolean => {
    if (!isRecord(entry)) return false;
    return (
      entry['source'] !== undefined ||
      entry['target'] !== undefined ||
      entry['sourceHandle'] !== undefined ||
      entry['targetHandle'] !== undefined ||
      entry['fromNodeId'] !== undefined ||
      entry['toNodeId'] !== undefined
    );
  });
};

const normalizeLegacyWriteOutcomePolicy = (input: unknown): unknown => {
  if (Array.isArray(input)) {
    return input.map((entry) => normalizeLegacyWriteOutcomePolicy(entry));
  }

  if (!isRecord(input)) {
    return input;
  }

  const next: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(input)) {
    next[key] = normalizeLegacyWriteOutcomePolicy(value);
  }

  const databaseConfig = input['database'];
  if (isRecord(databaseConfig)) {
    const writeOutcomePolicy = databaseConfig['writeOutcomePolicy'];
    if (isRecord(writeOutcomePolicy) && writeOutcomePolicy['onZeroAffected'] === 'pass') {
      next['database'] = {
        ...(next['database'] as Record<string, unknown>),
        writeOutcomePolicy: {
          ...(next['database'] && isRecord(next['database'])
            ? (next['database']['writeOutcomePolicy'] as Record<string, unknown>)
            : {}),
          onZeroAffected: 'warn',
        },
      };
    }
  }

  return next;
};

export const migratePortablePathInput = (
  input: unknown,
  options?: Pick<ResolvePortablePathInputOptions, 'includeConnections'>
): MigratePortablePathInputResult => {
  const removedLegacyNodes = findRemovedLegacyAiPathNodesInDocument(input);
  if (removedLegacyNodes.length > 0) {
    return {
      ok: false,
      error: formatRemovedLegacyAiPathNodesMessage(removedLegacyNodes, {
        surface: 'portable payload',
      }),
    };
  }
  const removedTriggerContextModes = findRemovedLegacyTriggerContextModesInDocument(input);
  if (removedTriggerContextModes.length > 0) {
    return {
      ok: false,
      error: formatRemovedLegacyTriggerContextModesMessage(removedTriggerContextModes, {
        surface: 'portable payload',
      }),
    };
  }

  const migrationWarnings: PortablePathMigrationWarning[] = [];
  const migratedInput = normalizeLegacyWriteOutcomePolicy(input);

  const packageParsed = aiPathPortablePackageVersionedSchema.safeParse(migratedInput);
  if (packageParsed.success) {
    beginPortablePathMigratorAttempt(packageParsed.data.specVersion);
    const migratedPackage = applyPortablePathPackageMigrator(packageParsed.data);
    if (!migratedPackage.ok) {
      markPortablePathMigratorFailure(
        migratedPackage.specVersion,
        migratedPackage.reason,
        migratedPackage.error
      );
      return {
        ok: false,
        error: migratedPackage.error,
      };
    }
    const packageMigrationWarnings: PortablePathMigrationWarning[] = [
      ...migrationWarnings,
      ...migratedPackage.value.migrationWarnings,
    ];
    const pathId = migratedPackage.value.portablePackage.pathId?.trim();
    const packageName = migratedPackage.value.portablePackage.name?.trim();
    const documentPathId = migratedPackage.value.portablePackage.document.path.id.trim();
    const documentName = migratedPackage.value.portablePackage.document.path.name.trim();

    if (pathId && pathId !== documentPathId) {
      packageMigrationWarnings.push({
        code: 'package_path_id_mismatch',
        message: `Portable package pathId "${pathId}" differs from document path id "${documentPathId}". Document id is used.`,
      });
    }
    if (packageName && packageName !== documentName) {
      packageMigrationWarnings.push({
        code: 'package_name_mismatch',
        message: `Portable package name "${packageName}" differs from document path name "${documentName}". Document name is used.`,
      });
    }
    recordPortablePathMigratorSource('portable_package');
    markPortablePathMigratorSuccess({
      specVersion: migratedPackage.value.specVersion,
      warningCount: packageMigrationWarnings.length,
    });
    return {
      ok: true,
      value: {
        source: 'portable_package',
        portablePackage: migratedPackage.value.portablePackage,
        migrationWarnings: packageMigrationWarnings,
      },
    };
  }

  const semanticParsed = parseAndDeserializeSemanticCanvas(migratedInput);
  if (semanticParsed.ok) {
    recordPortablePathMigratorSource('semantic_canvas');
    return {
      ok: true,
      value: {
        source: 'semantic_canvas',
        portablePackage: buildCanonicalPackageFromPathConfig(semanticParsed.value, options),
        migrationWarnings: [
          ...migrationWarnings,
          {
            code: 'semantic_canvas_upgraded',
            message: 'Semantic canvas payload upgraded to portable package v1.',
          },
        ],
      },
    };
  }

  if (hasNonCanonicalPathConfigEdgeAliases(migratedInput)) {
    return {
      ok: false,
      error: 'Path config payload contains unsupported legacy edge alias fields.',
    };
  }

  const pathConfigParsed = pathConfigSchema.safeParse(migratedInput);
  if (pathConfigParsed.success) {
    const normalizedPathConfig = normalizePathConfigEdges(pathConfigParsed.data);
    recordPortablePathMigratorSource('path_config');
    return {
      ok: true,
      value: {
        source: 'path_config',
        portablePackage: buildCanonicalPackageFromPathConfig(normalizedPathConfig, options),
        migrationWarnings: [
          ...migrationWarnings,
          {
            code: 'path_config_upgraded',
            message: 'Path config payload upgraded to portable package v1.',
          }
        ],
      },
    };
  }

  return {
    ok: false,
    error: [
      'Input does not match a supported AI-Path payload.',
      `portable package parse error: ${formatZodError(packageParsed.error)}`,
      `semantic canvas parse error: ${semanticParsed.error}`,
      `path config parse error: ${formatZodError(pathConfigParsed.error)}`,
    ].join(' '),
  };
};

