import type { PortablePathInputSource } from './portable-engine-contract';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export type PortablePathMigratorFailureReason = 'missing_migrator' | 'migrator_error';

export type PortablePathMigratorObservabilityByVersion = {
  attempts: number;
  successes: number;
  failures: number;
  lastError: string | null;
  lastMigratedAt: string | null;
};

export type PortablePathMigratorFailureTelemetry = {
  specVersion: string;
  reason: PortablePathMigratorFailureReason;
  error: string;
  at: string;
};

export type PortablePathMigratorObservabilitySnapshot = {
  totals: {
    registrationCount: number;
    unregistrationCount: number;
    migrationAttempts: number;
    migrationSuccesses: number;
    migrationFailures: number;
  };
  sourceCounts: Record<PortablePathInputSource, number>;
  bySpecVersion: Record<string, PortablePathMigratorObservabilityByVersion>;
  recentFailures: PortablePathMigratorFailureTelemetry[];
};

export type PortablePathMigratorObservabilityEvent =
  | { type: 'migrator_registered'; specVersion: string }
  | { type: 'migrator_unregistered'; specVersion: string }
  | { type: 'migration_succeeded'; specVersion: string; warningCount: number }
  | {
      type: 'migration_failed';
      specVersion: string;
      reason: PortablePathMigratorFailureReason;
      error: string;
    }
  | { type: 'source_migrated'; source: PortablePathInputSource };

export type PortablePathMigratorObservabilityHook = (
  event: PortablePathMigratorObservabilityEvent,
  snapshot: PortablePathMigratorObservabilitySnapshot
) => void;

const MAX_PORTABLE_PATH_MIGRATOR_FAILURE_EVENTS = 25;

const createEmptyPortablePathSourceCounts = (): Record<PortablePathInputSource, number> => ({
  portable_package: 0,
  portable_envelope: 0,
  semantic_canvas: 0,
  path_config: 0,
});

const createEmptyPortablePathMigratorObservabilityState =
  (): PortablePathMigratorObservabilitySnapshot => ({
    totals: {
      registrationCount: 0,
      unregistrationCount: 0,
      migrationAttempts: 0,
      migrationSuccesses: 0,
      migrationFailures: 0,
    },
    sourceCounts: createEmptyPortablePathSourceCounts(),
    bySpecVersion: {},
    recentFailures: [],
  });

let portablePathMigratorObservabilityState = createEmptyPortablePathMigratorObservabilityState();
const portablePathMigratorObservabilityHooks = new Set<PortablePathMigratorObservabilityHook>();

const clonePortablePathMigratorObservabilitySnapshot = (
  snapshot: PortablePathMigratorObservabilitySnapshot
): PortablePathMigratorObservabilitySnapshot => ({
  totals: { ...snapshot.totals },
  sourceCounts: { ...snapshot.sourceCounts },
  bySpecVersion: Object.fromEntries(
    Object.entries(snapshot.bySpecVersion).map(([specVersion, stats]) => [
      specVersion,
      { ...stats },
    ])
  ),
  recentFailures: snapshot.recentFailures.map((failure) => ({ ...failure })),
});

const emitPortablePathMigratorObservabilityEvent = (
  event: PortablePathMigratorObservabilityEvent
): void => {
  if (portablePathMigratorObservabilityHooks.size === 0) return;
  const snapshot = clonePortablePathMigratorObservabilitySnapshot(
    portablePathMigratorObservabilityState
  );
  for (const hook of portablePathMigratorObservabilityHooks) {
    try {
      hook(event, snapshot);
    } catch (error) {
      logClientError(error);

      // Observability hooks must not break migration flow.
    }
  }
};

const ensurePortablePathMigratorVersionStats = (
  specVersion: string
): PortablePathMigratorObservabilityByVersion => {
  if (!portablePathMigratorObservabilityState.bySpecVersion[specVersion]) {
    portablePathMigratorObservabilityState.bySpecVersion[specVersion] = {
      attempts: 0,
      successes: 0,
      failures: 0,
      lastError: null,
      lastMigratedAt: null,
    };
  }
  return portablePathMigratorObservabilityState.bySpecVersion[specVersion];
};

export const markPortablePathMigratorRegistration = (specVersion: string): void => {
  portablePathMigratorObservabilityState.totals.registrationCount += 1;
  ensurePortablePathMigratorVersionStats(specVersion);
  emitPortablePathMigratorObservabilityEvent({
    type: 'migrator_registered',
    specVersion,
  });
};

export const markPortablePathMigratorUnregistration = (specVersion: string): void => {
  portablePathMigratorObservabilityState.totals.unregistrationCount += 1;
  emitPortablePathMigratorObservabilityEvent({
    type: 'migrator_unregistered',
    specVersion,
  });
};

export const beginPortablePathMigratorAttempt = (specVersion: string): void => {
  portablePathMigratorObservabilityState.totals.migrationAttempts += 1;
  const stats = ensurePortablePathMigratorVersionStats(specVersion);
  stats.attempts += 1;
};

export const markPortablePathMigratorSuccess = (input: {
  specVersion: string;
  warningCount: number;
}): void => {
  portablePathMigratorObservabilityState.totals.migrationSuccesses += 1;
  const stats = ensurePortablePathMigratorVersionStats(input.specVersion);
  stats.successes += 1;
  stats.lastError = null;
  stats.lastMigratedAt = new Date().toISOString();
  emitPortablePathMigratorObservabilityEvent({
    type: 'migration_succeeded',
    specVersion: input.specVersion,
    warningCount: input.warningCount,
  });
};

export const recordPortablePathMigratorSource = (source: PortablePathInputSource): void => {
  portablePathMigratorObservabilityState.sourceCounts[source] += 1;
  emitPortablePathMigratorObservabilityEvent({
    type: 'source_migrated',
    source,
  });
};

export const markPortablePathMigratorFailure = (
  specVersion: string,
  reason: PortablePathMigratorFailureReason,
  error: string
): void => {
  portablePathMigratorObservabilityState.totals.migrationFailures += 1;
  const stats = ensurePortablePathMigratorVersionStats(specVersion);
  stats.failures += 1;
  stats.lastError = error;
  const telemetry: PortablePathMigratorFailureTelemetry = {
    specVersion,
    reason,
    error,
    at: new Date().toISOString(),
  };
  portablePathMigratorObservabilityState.recentFailures.push(telemetry);
  if (
    portablePathMigratorObservabilityState.recentFailures.length >
    MAX_PORTABLE_PATH_MIGRATOR_FAILURE_EVENTS
  ) {
    portablePathMigratorObservabilityState.recentFailures.shift();
  }
  emitPortablePathMigratorObservabilityEvent({
    type: 'migration_failed',
    specVersion,
    reason,
    error,
  });
};

export const registerPortablePathMigratorObservabilityHook = (
  hook: PortablePathMigratorObservabilityHook
): (() => void) => {
  portablePathMigratorObservabilityHooks.add(hook);
  return () => {
    portablePathMigratorObservabilityHooks.delete(hook);
  };
};

export const getPortablePathMigratorObservabilitySnapshot =
  (): PortablePathMigratorObservabilitySnapshot =>
    clonePortablePathMigratorObservabilitySnapshot(portablePathMigratorObservabilityState);

export const resetPortablePathMigratorObservabilitySnapshot = (): void => {
  portablePathMigratorObservabilityState = createEmptyPortablePathMigratorObservabilityState();
};

import { type z } from 'zod';

import {
  AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION,
  type AiPathPortablePackage,
  type AiPathPortablePackageVersioned,
  aiPathPortablePackageSchema,
  portablePathPackageVersionedSpecVersionSchema,
} from './portable-engine-contract';
import {
  markPortablePathMigratorRegistration,
  markPortablePathMigratorUnregistration,
} from './portable-engine-migrator-observability';

import type { PortablePathMigrationWarning } from './portable-engine-migration-types';

type PortablePathPackageMigrationResult =
  | {
      ok: true;
      value: {
        portablePackage: AiPathPortablePackage;
        migrationWarnings: PortablePathMigrationWarning[];
      };
    }
  | { ok: false; error: string };

export type PortablePathPackageMigrator = (
  input: AiPathPortablePackageVersioned
) => PortablePathPackageMigrationResult;

type ApplyPortablePathPackageMigratorResult =
  | {
      ok: true;
      value: {
        specVersion: string;
        portablePackage: AiPathPortablePackage;
        migrationWarnings: PortablePathMigrationWarning[];
      };
    }
  | {
      ok: false;
      specVersion: string;
      reason: 'missing_migrator' | 'migrator_error';
      error: string;
    };

const PORTABLE_PACKAGE_SPEC_V2 = 'ai-paths.portable-engine.v2' as const;

const formatZodError = (error: z.ZodError): string =>
  error.issues.map((issue) => `${issue.path.join('.') || 'document'}: ${issue.message}`).join('; ');

const normalizeVersionedPortablePackageToV1 = (
  input: AiPathPortablePackageVersioned
): PortablePathPackageMigrationResult => {
  const migrationWarnings: PortablePathMigrationWarning[] = [];
  if (input.specVersion !== AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION) {
    migrationWarnings.push({
      code: 'portable_package_version_upgraded',
      message: `Portable package spec "${input.specVersion}" was upgraded to "${AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION}" during import.`,
    });
  }

  const normalizedFingerprint =
    input.fingerprint &&
    (input.fingerprint.algorithm === 'stable_hash_v1' || input.fingerprint.algorithm === 'sha256')
      ? {
        algorithm: input.fingerprint.algorithm,
        value: input.fingerprint.value,
      }
      : null;

  if (input.fingerprint && !normalizedFingerprint) {
    migrationWarnings.push({
      code: 'package_fingerprint_unsupported_algorithm',
      message: `Portable package fingerprint algorithm "${input.fingerprint.algorithm}" is not supported in portable package v1 and was removed during migration.`,
    });
  }

  const candidate: unknown = {
    ...input,
    specVersion: AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION,
    ...(normalizedFingerprint ? { fingerprint: normalizedFingerprint } : {}),
    ...(!normalizedFingerprint ? { fingerprint: undefined } : {}),
  };

  const parsed = aiPathPortablePackageSchema.safeParse(candidate);
  if (!parsed.success) {
    return {
      ok: false,
      error: `Portable package migration failed: ${formatZodError(parsed.error)}`,
    };
  }
  return {
    ok: true,
    value: {
      portablePackage: parsed.data,
      migrationWarnings,
    },
  };
};

const portablePathPackageMigrationRegistry = new Map<string, PortablePathPackageMigrator>([
  [AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION, normalizeVersionedPortablePackageToV1],
  [PORTABLE_PACKAGE_SPEC_V2, normalizeVersionedPortablePackageToV1],
]);

const BUILTIN_PORTABLE_PATH_MIGRATOR_VERSIONS = new Set<string>([
  AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION,
  PORTABLE_PACKAGE_SPEC_V2,
]);

const normalizePortablePathMigratorSpecVersion = (specVersion: string): string => {
  const normalized = specVersion.trim();
  const parsed = portablePathPackageVersionedSpecVersionSchema.safeParse(normalized);
  if (!parsed.success) {
    throw new Error(`Invalid portable package spec version "${specVersion}".`);
  }
  return parsed.data;
};

export const registerPortablePathPackageMigrator = (
  specVersion: string,
  migrator: PortablePathPackageMigrator
): void => {
  const normalizedVersion = normalizePortablePathMigratorSpecVersion(specVersion);
  portablePathPackageMigrationRegistry.set(normalizedVersion, migrator);
  markPortablePathMigratorRegistration(normalizedVersion);
};

export const listPortablePathPackageMigratorVersions = (): string[] =>
  Array.from(portablePathPackageMigrationRegistry.keys()).sort();

export const unregisterPortablePathPackageMigrator = (specVersion: string): boolean => {
  const normalizedVersion = normalizePortablePathMigratorSpecVersion(specVersion);
  if (BUILTIN_PORTABLE_PATH_MIGRATOR_VERSIONS.has(normalizedVersion)) {
    throw new Error(`Cannot unregister built-in portable package migrator "${normalizedVersion}".`);
  }
  const deleted = portablePathPackageMigrationRegistry.delete(normalizedVersion);
  if (deleted) {
    markPortablePathMigratorUnregistration(normalizedVersion);
  }
  return deleted;
};

export const applyPortablePathPackageMigrator = (
  input: AiPathPortablePackageVersioned
): ApplyPortablePathPackageMigratorResult => {
  const specVersion = input.specVersion;
  const migrator = portablePathPackageMigrationRegistry.get(specVersion);
  if (!migrator) {
    return {
      ok: false,
      specVersion,
      reason: 'missing_migrator',
      error: `Unsupported portable package spec version "${specVersion}". Supported versions: ${listPortablePathPackageMigratorVersions().join(', ')}`,
    };
  }

  const migratedPackage = migrator(input);
  if (!migratedPackage.ok) {
    return {
      ok: false,
      specVersion,
      reason: 'migrator_error',
      error: migratedPackage.error,
    };
  }

  return {
    ok: true,
    value: {
      specVersion,
      portablePackage: migratedPackage.value.portablePackage,
      migrationWarnings: migratedPackage.value.migrationWarnings,
    },
  };
};

import { type Edge, type PathConfig } from '@/shared/contracts/ai-paths';
import { serializePathConfigToSemanticCanvas } from '@/shared/lib/ai-paths/core/semantic-grammar';
import type { PathIdentityRepairWarning } from '@/shared/lib/ai-paths/core/utils/node-identity';

import {
  AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION,
  type AiPathPortablePackage,
  type AiPathPortablePackageEnvelope,
  type PortablePathInputSource,
} from './portable-engine-contract';
import { resolvePayloadLimits } from './portable-engine-resolution-support';

import type { PortablePathMigrationWarning } from './portable-engine-migration-types';
import type {
  PortablePayloadLimits,
  ResolvePortablePathInputOptions,
} from './portable-engine-resolution-types';
import type { ResolvePortablePathInputResult } from './portable-engine-runtime-types';

const asTrimmedString = (value: unknown): string | undefined => {
  if (typeof value !== 'string') return undefined;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : undefined;
};

const resolveEdgePort = (
  edge: Edge,
  canonicalKey: 'fromPort' | 'toPort'
): string | null | undefined => {
  const canonicalValue = edge[canonicalKey];
  if (canonicalValue === undefined) return undefined;
  if (canonicalValue === null) return null;
  if (typeof canonicalValue !== 'string') return null;
  const trimmed = canonicalValue.trim();
  return trimmed.length > 0 ? trimmed : null;
};

export const normalizePathConfigEdges = (pathConfig: PathConfig): PathConfig => {
  let changed = false;
  const nextEdges = (pathConfig.edges ?? []).map((edge: Edge): Edge => {
    const legacyEdge = edge as Edge & { fromNodeId?: unknown; toNodeId?: unknown };
    const resolvedFrom = asTrimmedString(edge.from);
    const resolvedTo = asTrimmedString(edge.to);
    const resolvedFromPort = resolveEdgePort(edge, 'fromPort');
    const resolvedToPort = resolveEdgePort(edge, 'toPort');

    const edgeChanged =
      resolvedFrom !== edge.from ||
      resolvedTo !== edge.to ||
      resolvedFromPort !== edge.fromPort ||
      resolvedToPort !== edge.toPort ||
      edge.source !== undefined ||
      edge.target !== undefined ||
      edge.sourceHandle !== undefined ||
      edge.targetHandle !== undefined ||
      legacyEdge.fromNodeId !== undefined ||
      legacyEdge.toNodeId !== undefined;

    if (!edgeChanged) return edge;
    changed = true;
    return {
      id: edge.id,
      ...(resolvedFrom !== undefined ? { from: resolvedFrom } : {}),
      ...(resolvedTo !== undefined ? { to: resolvedTo } : {}),
      ...(resolvedFromPort !== undefined ? { fromPort: resolvedFromPort } : {}),
      ...(resolvedToPort !== undefined ? { toPort: resolvedToPort } : {}),
      ...(typeof edge.label === 'string' || edge.label === null ? { label: edge.label } : {}),
      ...(typeof edge.type === 'string' ? { type: edge.type } : {}),
      ...(edge.data && typeof edge.data === 'object' ? { data: edge.data } : {}),
      ...(typeof edge.createdAt === 'string' ? { createdAt: edge.createdAt } : {}),
      ...(typeof edge.updatedAt === 'string' || edge.updatedAt === null
        ? { updatedAt: edge.updatedAt }
        : {}),
    };
  });

  return changed ? { ...pathConfig, edges: nextEdges } : pathConfig;
};

const enforceResolvedGraphLimits = (
  pathConfig: PathConfig,
  limits: PortablePayloadLimits
): string | null => {
  const nodeCount = Array.isArray(pathConfig.nodes) ? pathConfig.nodes.length : 0;
  if (nodeCount > limits.maxNodeCount) {
    return `Payload graph exceeds max node count (${limits.maxNodeCount}).`;
  }
  const edgeCount = Array.isArray(pathConfig.edges) ? pathConfig.edges.length : 0;
  if (edgeCount > limits.maxEdgeCount) {
    return `Payload graph exceeds max edge count (${limits.maxEdgeCount}).`;
  }
  return null;
};

export const buildCanonicalPackageFromPathConfig = (
  pathConfig: PathConfig,
  options?: Pick<ResolvePortablePathInputOptions, 'includeConnections'>
): AiPathPortablePackage => {
  const createdAt = new Date().toISOString();
  return {
    specVersion: AI_PATH_PORTABLE_PACKAGE_SPEC_VERSION,
    kind: 'path_package',
    createdAt,
    pathId: pathConfig.id,
    name: pathConfig.name,
    document: serializePathConfigToSemanticCanvas(pathConfig, {
      includeConnections: options?.includeConnections !== false,
      exportedAt: createdAt,
    }),
  };
};

export const finalizeResolvedPath = ({
  source,
  pathConfig,
  portablePackage,
  portableEnvelope,
  options,
  migrationWarnings,
  payloadByteSize,
}: {
  source: PortablePathInputSource;
  pathConfig: PathConfig;
  portablePackage: AiPathPortablePackage;
  portableEnvelope: AiPathPortablePackageEnvelope | null;
  options?: ResolvePortablePathInputOptions;
  migrationWarnings: PortablePathMigrationWarning[];
  payloadByteSize: number | null;
}): ResolvePortablePathInputResult => {
  const limits = resolvePayloadLimits(options?.limits);
  const normalizedPath = normalizePathConfigEdges(pathConfig);
  const identityWarnings: PathIdentityRepairWarning[] = [];

  if (options?.enforcePayloadLimits !== false) {
    const limitError = enforceResolvedGraphLimits(normalizedPath, limits);
    if (limitError) {
      return { ok: false, error: limitError };
    }
  }

  const semanticDocument = serializePathConfigToSemanticCanvas(normalizedPath, {
    includeConnections: options?.includeConnections !== false,
  });

  return {
    ok: true,
    value: {
      source,
      pathConfig: normalizedPath,
      semanticDocument,
      portablePackage:
        source === 'portable_package' || source === 'portable_envelope' ? portablePackage : null,
      portableEnvelope: source === 'portable_envelope' ? portableEnvelope : null,
      canonicalPackage: {
        ...portablePackage,
        document: semanticDocument,
        pathId: normalizedPath.id,
        name: normalizedPath.name,
      },
      identityRepaired: false,
      identityWarnings,
      migrationWarnings,
      payloadByteSize,
    },
  };
};

import {
  DEFAULT_PORTABLE_PAYLOAD_LIMITS,
  type PortablePayloadLimits,
} from './portable-engine-resolution-types';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const UNSAFE_OBJECT_KEYS = new Set(['__proto__', 'prototype', 'constructor']);

export const resolvePayloadLimits = (
  limits?: Partial<PortablePayloadLimits>
): PortablePayloadLimits => ({
  ...DEFAULT_PORTABLE_PAYLOAD_LIMITS,
  ...(limits ?? {}),
});

const getUtf8ByteSize = (value: string): number => {
  if (typeof TextEncoder === 'function') {
    return new TextEncoder().encode(value).length;
  }
  // Fallback approximation in environments without TextEncoder.
  return value.length * 2;
};

export const decodePortablePayload = (
  input: unknown
): { ok: true; value: unknown; payloadByteSize: number | null } | { ok: false; error: string } => {
  if (typeof input !== 'string') {
    return { ok: true, value: input, payloadByteSize: null };
  }
  try {
    return {
      ok: true,
      value: JSON.parse(input) as unknown,
      payloadByteSize: getUtf8ByteSize(input),
    };
  } catch (error) {
    logClientError(error);
    const message = error instanceof Error ? error.message : String(error);
    return { ok: false, error: `Invalid JSON payload: ${message}` };
  }
};

export const estimatePayloadByteSize = (
  value: unknown
): { ok: true; value: number } | { ok: false; error: string } => {
  try {
    const serialized = JSON.stringify(value);
    if (typeof serialized !== 'string') {
      return {
        ok: false,
        error: 'Payload cannot be serialized to JSON for size validation.',
      };
    }
    return { ok: true, value: getUtf8ByteSize(serialized) };
  } catch (error) {
    logClientError(error);
    const message = error instanceof Error ? error.message : String(error);
    return {
      ok: false,
      error: `Payload cannot be serialized to JSON for size validation: ${message}`,
    };
  }
};

export const validatePayloadObjectSafety = (
  value: unknown,
  limits: PortablePayloadLimits,
  depth = 0,
  path = 'payload',
  ancestors: WeakSet<object> = new WeakSet()
): string | null => {
  if (depth > limits.maxDepth) {
    return `Payload exceeds maximum depth (${limits.maxDepth}) at ${path}.`;
  }
  if (typeof value === 'string' && value.length > limits.maxStringLength) {
    return `Payload string is too long at ${path} (max ${limits.maxStringLength} chars).`;
  }
  if (!value || typeof value !== 'object') {
    return null;
  }
  const objectValue = value;
  if (ancestors.has(objectValue)) {
    return `Payload contains circular reference at ${path}.`;
  }
  ancestors.add(objectValue);
  if (Array.isArray(value)) {
    try {
      if (value.length > limits.maxArrayLength) {
        return `Payload array is too large at ${path} (max ${limits.maxArrayLength} items).`;
      }
      for (let index = 0; index < value.length; index += 1) {
        const issue = validatePayloadObjectSafety(
          value[index],
          limits,
          depth + 1,
          `${path}[${index}]`,
          ancestors
        );
        if (issue) return issue;
      }
      return null;
    } finally {
      ancestors.delete(objectValue);
    }
  }
  try {
    const record = value as Record<string, unknown>;
    const keys = Object.keys(record);
    if (keys.length > limits.maxObjectKeys) {
      return `Payload object has too many keys at ${path} (max ${limits.maxObjectKeys}).`;
    }
    for (const key of keys) {
      if (UNSAFE_OBJECT_KEYS.has(key)) {
        return `Payload contains unsafe key "${key}" at ${path}.`;
      }
      const issue = validatePayloadObjectSafety(
        record[key],
        limits,
        depth + 1,
        `${path}.${key}`,
        ancestors
      );
      if (issue) return issue;
    }
    return null;
  } finally {
    ancestors.delete(objectValue);
  }
};

import { parseAndDeserializeSemanticCanvas } from '@/shared/lib/ai-paths/core/semantic-grammar';

import { verifyPortableNodeCodeObjectManifest } from './node-code-objects-v2-manifest';
import {
  type AiPathPortablePackage,
  type AiPathPortablePackageEnvelope,
  type PortablePathInputSource,
  aiPathPortablePackageEnvelopeSchema,
  aiPathPortablePackageEnvelopeVersionedSchema,
} from './portable-engine-contract';
import { verifyPortablePathPackageEnvelopeSignatureAsync } from './portable-engine-envelope-verification-async';
import { verifyPortablePathPackageEnvelopeSignature } from './portable-engine-envelope-verification-sync';
import {
  verifyPortablePackageFingerprint,
  verifyPortablePackageFingerprintAsync,
} from './portable-engine-fingerprints';
import { migratePortablePathInput } from './portable-engine-migration';
import { finalizeResolvedPath } from './portable-engine-path-canonicalization';
import {
  decodePortablePayload,
  estimatePayloadByteSize,
  resolvePayloadLimits,
  validatePayloadObjectSafety,
} from './portable-engine-resolution-support';
import { resolvePortablePathVerificationModes } from './portable-engine-signing-policy';

import type { PortablePathMigrationWarning } from './portable-engine-migration-types';
import type {
  ResolvePortablePathInputInternalOptions,
  ResolvePortablePathInputOptions,
} from './portable-engine-resolution-types';
import type { ResolvePortablePathInputResult } from './portable-engine-runtime-types';

type PortablePayloadDecodeSuccess = Extract<
  ReturnType<typeof decodePortablePayload>,
  { ok: true }
>;

type PortableMigrationSuccess = Extract<
  ReturnType<typeof migratePortablePathInput>,
  { ok: true }
>['value'];

type DeserializedPortablePathConfig = Extract<
  ReturnType<typeof parseAndDeserializeSemanticCanvas>,
  { ok: true }
>['value'];

type PortableEnvelopeResolution = {
  envelopePayload: unknown;
  envelopeWarnings: PortablePathMigrationWarning[];
  resolvedSourceFromEnvelope: boolean;
  envelopeData: AiPathPortablePackageEnvelope | null;
};

const resolvePortablePayloadByteSize = (
  decoded: PortablePayloadDecodeSuccess,
  options: ResolvePortablePathInputOptions | undefined
): { ok: true; payloadByteSize: number | null } | { ok: false; error: string } => {
  let payloadByteSize = decoded.payloadByteSize;
  if (options?.enforcePayloadLimits === false) {
    return { ok: true, payloadByteSize };
  }

  const limits = resolvePayloadLimits(options?.limits);
  if (payloadByteSize !== null && payloadByteSize > limits.maxPayloadBytes) {
    return {
      ok: false,
      error: `Payload exceeds max size (${limits.maxPayloadBytes} bytes).`,
    };
  }

  const safetyIssue = validatePayloadObjectSafety(decoded.value, limits);
  if (safetyIssue) {
    return { ok: false, error: safetyIssue };
  }

  if (payloadByteSize !== null) {
    return { ok: true, payloadByteSize };
  }

  const estimated = estimatePayloadByteSize(decoded.value);
  if (!estimated.ok) {
    return { ok: false, error: estimated.error };
  }
  if (estimated.value > limits.maxPayloadBytes) {
    return {
      ok: false,
      error: `Payload exceeds max size (${limits.maxPayloadBytes} bytes).`,
    };
  }
  payloadByteSize = estimated.value;
  return { ok: true, payloadByteSize };
};

const resolveVerifiedEnvelopePayload = (
  decodedValue: unknown,
  options: ResolvePortablePathInputOptions | undefined,
  envelopeSignatureVerificationMode: NonNullable<
    ReturnType<typeof resolvePortablePathVerificationModes>['envelopeSignatureVerificationMode']
  >
): { ok: true; value: PortableEnvelopeResolution } | { ok: false; error: string } => {
  const envelopeParsed = aiPathPortablePackageEnvelopeVersionedSchema.safeParse(decodedValue);
  if (!envelopeParsed.success) {
    return {
      ok: true,
      value: {
        envelopePayload: decodedValue,
        envelopeWarnings: [],
        resolvedSourceFromEnvelope: false,
        envelopeData: null,
      },
    };
  }

  const envelopeVerification = verifyPortablePathPackageEnvelopeSignature(
    envelopeParsed.data,
    envelopeSignatureVerificationMode,
    {
      envelopeSignatureSecret: options?.envelopeSignatureSecret,
      envelopeSignatureSecretsByKeyId: options?.envelopeSignatureSecretsByKeyId,
      envelopeSignatureFallbackSecrets: options?.envelopeSignatureFallbackSecrets,
      envelopeSignatureKeyResolver: options?.envelopeSignatureKeyResolver,
    }
  );
  if (!envelopeVerification.ok) {
    return { ok: false, error: envelopeVerification.error };
  }

  const signature = envelopeParsed.data.signature;
  const canonicalEnvelope =
    signature && (signature.algorithm === 'hmac_sha256' || signature.algorithm === 'stable_hash_v1')
      ? aiPathPortablePackageEnvelopeSchema.parse({
          ...envelopeParsed.data,
          specVersion: 'ai-paths.portable-engine.v1',
          kind: 'path_package_envelope',
          package: {
            ...envelopeParsed.data.package,
            specVersion: 'ai-paths.portable-engine.v1',
            kind: 'path_package',
          },
          signature,
        })
      : null;

  return {
    ok: true,
    value: {
      envelopePayload: canonicalEnvelope?.package ?? envelopeParsed.data.package,
      envelopeWarnings: envelopeVerification.warnings,
      resolvedSourceFromEnvelope: true,
      envelopeData: canonicalEnvelope,
    },
  };
};

const resolvePortableInputSource = (
  resolvedSourceFromEnvelope: boolean,
  migratedSource: PortablePathInputSource
): PortablePathInputSource =>
  resolvedSourceFromEnvelope && migratedSource === 'portable_package'
    ? 'portable_envelope'
    : migratedSource;

const buildPortableEnvelopeForResult = (input: {
  resolvedSource: PortablePathInputSource;
  envelopeData: AiPathPortablePackageEnvelope | null;
  portablePackage: PortableMigrationSuccess['portablePackage'];
}): AiPathPortablePackageEnvelope | null => {
  if (input.resolvedSource !== 'portable_envelope' || !input.envelopeData) {
    return null;
  }
  const signature = input.envelopeData.signature;
  if (
    !signature ||
    (signature.algorithm !== 'hmac_sha256' && signature.algorithm !== 'stable_hash_v1')
  ) {
    return null;
  }
  const portablePackage: AiPathPortablePackage = {
    ...input.portablePackage,
    specVersion: 'ai-paths.portable-engine.v1',
    kind: 'path_package',
  };
  return aiPathPortablePackageEnvelopeSchema.parse({
    specVersion: 'ai-paths.portable-engine.v1',
    kind: 'path_package_envelope',
    signedAt: input.envelopeData.signedAt,
    package: portablePackage,
    signature: {
      algorithm: signature.algorithm,
      value: signature.value,
      ...(signature.keyId ? { keyId: signature.keyId } : {}),
    },
    ...(input.envelopeData.metadata ? { metadata: input.envelopeData.metadata } : {}),
  });
};

const verifyPortablePackageFingerprintSyncIfNeeded = (input: {
  migrated: PortableMigrationSuccess;
  fingerprintVerificationMode: NonNullable<
    ReturnType<typeof resolvePortablePathVerificationModes>['fingerprintVerificationMode']
  >;
}): { ok: true; warnings: PortablePathMigrationWarning[] } | { ok: false; error: string } => {
  if (input.migrated.source !== 'portable_package') {
    return { ok: true, warnings: [] };
  }
  const verification = verifyPortablePackageFingerprint(
    input.migrated.portablePackage,
    input.fingerprintVerificationMode
  );
  if (!verification.ok) {
    return { ok: false, error: verification.error };
  }
  return { ok: true, warnings: verification.warnings };
};

const deserializePortablePathConfig = (
  portablePackage: PortableMigrationSuccess['portablePackage']
):
  | { ok: true; value: DeserializedPortablePathConfig }
  | { ok: false; error: string } => {
  const deserialized = parseAndDeserializeSemanticCanvas(portablePackage.document);
  if (!deserialized.ok) {
    return {
      ok: false,
      error: `Portable package contains invalid semantic canvas document: ${deserialized.error}`,
    };
  }
  return { ok: true, value: deserialized.value };
};

const verifyPortableNodeCodeObjects = (input: {
  portablePackage: PortableMigrationSuccess['portablePackage'];
  nodeTypes: string[];
  nodeCodeObjectHashVerificationMode: NonNullable<
    ResolvePortablePathInputOptions['nodeCodeObjectHashVerificationMode']
  >;
}): { ok: true; warnings: PortablePathMigrationWarning[] } | { ok: false; error: string } => {
  const verification = verifyPortableNodeCodeObjectManifest({
    metadata:
      input.portablePackage.metadata &&
      typeof input.portablePackage.metadata === 'object' &&
      !Array.isArray(input.portablePackage.metadata)
        ? input.portablePackage.metadata
        : undefined,
    nodeTypes: input.nodeTypes,
    mode: input.nodeCodeObjectHashVerificationMode,
  });
  if (!verification.ok) {
    return { ok: false, error: verification.error };
  }
  return { ok: true, warnings: verification.warnings };
};

const buildResolvedWarningsResult = (
  resolved: Extract<ResolvePortablePathInputResult, { ok: true }>,
  migrationWarnings: PortablePathMigrationWarning[]
): ResolvePortablePathInputResult =>
  migrationWarnings.length === resolved.value.migrationWarnings.length
    ? resolved
    : {
        ok: true,
        value: {
          ...resolved.value,
          migrationWarnings,
        },
      };

const verifyPortableEnvelopeAsyncIfNeeded = async (
  input: unknown,
  options: ResolvePortablePathInputOptions | undefined,
  envelopeSignatureVerificationMode: NonNullable<
    ReturnType<typeof resolvePortablePathVerificationModes>['envelopeSignatureVerificationMode']
  >
): Promise<{ ok: true; warnings: PortablePathMigrationWarning[] } | { ok: false; error: string }> => {
  if (envelopeSignatureVerificationMode === 'off') {
    return { ok: true, warnings: [] };
  }
  const decoded = decodePortablePayload(input);
  if (!decoded.ok) return decoded;
  const envelopeParsed = aiPathPortablePackageEnvelopeVersionedSchema.safeParse(decoded.value);
  if (!envelopeParsed.success) {
    return { ok: true, warnings: [] };
  }
  const verification = await verifyPortablePathPackageEnvelopeSignatureAsync(
    envelopeParsed.data,
    envelopeSignatureVerificationMode,
    {
      envelopeSignatureSecret: options?.envelopeSignatureSecret,
      envelopeSignatureSecretsByKeyId: options?.envelopeSignatureSecretsByKeyId,
      envelopeSignatureFallbackSecrets: options?.envelopeSignatureFallbackSecrets,
      envelopeSignatureKeyResolver: options?.envelopeSignatureKeyResolver,
    }
  );
  if (!verification.ok) {
    return { ok: false, error: verification.error };
  }
  return { ok: true, warnings: verification.warnings };
};

const verifyPortableFingerprintAsyncIfNeeded = async (
  resolved: Extract<ResolvePortablePathInputResult, { ok: true }>,
  fingerprintVerificationMode: NonNullable<
    ReturnType<typeof resolvePortablePathVerificationModes>['fingerprintVerificationMode']
  >
): Promise<{ ok: true; warnings: PortablePathMigrationWarning[] } | { ok: false; error: string }> => {
  if (
    fingerprintVerificationMode === 'off' ||
    (resolved.value.source !== 'portable_package' &&
      resolved.value.source !== 'portable_envelope') ||
    !resolved.value.portablePackage
  ) {
    return { ok: true, warnings: [] };
  }

  const verification = await verifyPortablePackageFingerprintAsync(
    resolved.value.portablePackage,
    fingerprintVerificationMode
  );
  if (!verification.ok) {
    return { ok: false, error: verification.error };
  }
  return { ok: true, warnings: verification.warnings };
};

export const resolvePortablePathInput = (
  input: unknown,
  options?: ResolvePortablePathInputOptions
): ResolvePortablePathInputResult => {
  const internalOptions = options as ResolvePortablePathInputInternalOptions | undefined;
  const verificationModes = resolvePortablePathVerificationModes(options, {
    skipUsageTelemetry: internalOptions?.__skipSigningPolicyUsageTelemetry === true,
  });
  const nodeCodeObjectHashVerificationMode = options?.nodeCodeObjectHashVerificationMode ?? 'warn';
  const decoded = decodePortablePayload(input);
  if (!decoded.ok) return decoded;
  const payloadByteSizeResult = resolvePortablePayloadByteSize(decoded, options);
  if (!payloadByteSizeResult.ok) return payloadByteSizeResult;

  const envelopeResolution = resolveVerifiedEnvelopePayload(
    decoded.value,
    options,
    verificationModes.envelopeSignatureVerificationMode
  );
  if (!envelopeResolution.ok) return envelopeResolution;

  const migrated = migratePortablePathInput(envelopeResolution.value.envelopePayload, options);
  if (!migrated.ok) {
    return migrated;
  }
  const migrationWarnings = [
    ...envelopeResolution.value.envelopeWarnings,
    ...migrated.value.migrationWarnings,
  ];
  const resolvedSource = resolvePortableInputSource(
    envelopeResolution.value.resolvedSourceFromEnvelope,
    migrated.value.source
  );
  const portableEnvelopeForResult = buildPortableEnvelopeForResult({
    resolvedSource,
    envelopeData: envelopeResolution.value.envelopeData,
    portablePackage: migrated.value.portablePackage,
  });
  const fingerprintVerification = verifyPortablePackageFingerprintSyncIfNeeded({
    migrated: migrated.value,
    fingerprintVerificationMode: verificationModes.fingerprintVerificationMode,
  });
  if (!fingerprintVerification.ok) return fingerprintVerification;
  migrationWarnings.push(...fingerprintVerification.warnings);

  const deserialized = deserializePortablePathConfig(migrated.value.portablePackage);
  if (!deserialized.ok) return deserialized;

  const nodeCodeObjectVerification = verifyPortableNodeCodeObjects({
    portablePackage: migrated.value.portablePackage,
    nodeTypes: (deserialized.value.nodes ?? []).map((node) => node.type),
    nodeCodeObjectHashVerificationMode,
  });
  if (!nodeCodeObjectVerification.ok) return nodeCodeObjectVerification;
  migrationWarnings.push(...nodeCodeObjectVerification.warnings);

  return finalizeResolvedPath({
    source: resolvedSource,
    pathConfig: deserialized.value,
    portablePackage: migrated.value.portablePackage,
    portableEnvelope: portableEnvelopeForResult,
    options,
    migrationWarnings,
    payloadByteSize: payloadByteSizeResult.payloadByteSize,
  });
};

export const resolvePortablePathInputAsync = async (
  input: unknown,
  options?: ResolvePortablePathInputOptions
): Promise<ResolvePortablePathInputResult> => {
  const verificationModes = resolvePortablePathVerificationModes(options);
  const resolved = resolvePortablePathInput(input, {
    ...options,
    envelopeSignatureVerificationMode: 'off',
    fingerprintVerificationMode: 'off',
    __skipSigningPolicyUsageTelemetry: true,
  } as ResolvePortablePathInputInternalOptions);
  if (!resolved.ok) return resolved;

  const migrationWarnings = [...resolved.value.migrationWarnings];
  const envelopeVerification = await verifyPortableEnvelopeAsyncIfNeeded(
    input,
    options,
    verificationModes.envelopeSignatureVerificationMode
  );
  if (!envelopeVerification.ok) return envelopeVerification;
  migrationWarnings.push(...envelopeVerification.warnings);

  const fingerprintVerification = await verifyPortableFingerprintAsyncIfNeeded(
    resolved,
    verificationModes.fingerprintVerificationMode
  );
  if (!fingerprintVerification.ok) return fingerprintVerification;
  migrationWarnings.push(...fingerprintVerification.warnings);

  return buildResolvedWarningsResult(resolved, migrationWarnings);
};

import { logClientError } from '@/shared/utils/observability/client-error-logger';
const MAX_PORTABLE_PATH_RUN_EXECUTION_ERROR_MESSAGE_LENGTH = 320;

const normalizePortablePathRunExecutionErrorText = (value: unknown): string | null => {
  if (typeof value === 'string') {
    const normalized = value.trim();
    return normalized.length > 0 ? normalized : null;
  }
  if (typeof value === 'number' || typeof value === 'boolean' || typeof value === 'bigint') {
    return String(value);
  }
  return null;
};

const truncatePortablePathRunExecutionErrorMessage = (value: string): string => {
  if (value.length <= MAX_PORTABLE_PATH_RUN_EXECUTION_ERROR_MESSAGE_LENGTH) return value;
  return `${value.slice(0, MAX_PORTABLE_PATH_RUN_EXECUTION_ERROR_MESSAGE_LENGTH - 3)}...`;
};

const toPortablePathRunExecutionErrorMessageFromRecord = (
  value: Record<string, unknown>
): string | null => {
  const name = normalizePortablePathRunExecutionErrorText(value['name']);
  const code = normalizePortablePathRunExecutionErrorText(value['code']);
  const message =
    normalizePortablePathRunExecutionErrorText(value['message']) ??
    normalizePortablePathRunExecutionErrorText(value['reason']) ??
    normalizePortablePathRunExecutionErrorText(value['error']) ??
    normalizePortablePathRunExecutionErrorText(value['detail']) ??
    null;
  if (!name && !code && !message) return null;
  const detail = message ?? 'Unknown portable engine runtime failure.';
  const namePrefix = name && name !== 'Error' && !detail.startsWith(`${name}:`) ? `${name}: ` : '';
  const codeSuffix = code ? ` (code: ${code})` : '';
  return `${namePrefix}${detail}${codeSuffix}`;
};

export const toPortablePathRunExecutionErrorMessage = (value: unknown): string => {
  if (value instanceof Error) {
    const extendedError = value as Error & {
      code?: unknown;
      reason?: unknown;
      error?: unknown;
      detail?: unknown;
    };
    const recordValue: Record<string, unknown> = {
      name: extendedError.name,
      code: extendedError.code,
      message: extendedError.message,
      reason: extendedError.reason,
      error: extendedError.error,
      detail: extendedError.detail,
    };
    const normalized =
      toPortablePathRunExecutionErrorMessageFromRecord(recordValue) ??
      normalizePortablePathRunExecutionErrorText(value.message) ??
      normalizePortablePathRunExecutionErrorText(value.name) ??
      'Unknown portable engine runtime failure.';
    return truncatePortablePathRunExecutionErrorMessage(normalized);
  }
  const direct = normalizePortablePathRunExecutionErrorText(value);
  if (direct) {
    return truncatePortablePathRunExecutionErrorMessage(direct);
  }
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    const fromRecord = toPortablePathRunExecutionErrorMessageFromRecord(
      value as Record<string, unknown>
    );
    if (fromRecord) {
      return truncatePortablePathRunExecutionErrorMessage(fromRecord);
    }
    try {
      const serialized = JSON.stringify(value);
      if (typeof serialized === 'string' && serialized.length > 0) {
        return truncatePortablePathRunExecutionErrorMessage(serialized);
      }
    } catch (error) {
      logClientError(error);
      return 'Unserializable portable engine runtime error object.';
    }
  }
  const fallback = String(value);
  return truncatePortablePathRunExecutionErrorMessage(
    fallback.trim().length > 0 ? fallback : 'Unknown portable engine runtime failure.'
  );
};

import { toPortablePathRunExecutionErrorMessage } from './portable-engine-run-error-normalization';

import type { PortablePathInputSource } from './portable-engine-contract';
import type { PortablePathSigningPolicySurface } from './portable-engine-resolution-types';
import type { PortablePathValidationMode } from './portable-engine-runtime-types';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export type PortablePathRunExecutionRunner = 'client' | 'server';
export type PortablePathRunExecutionFailureStage = 'resolve' | 'validation' | 'runtime';

export type PortablePathRunExecutionCounts = {
  attempts: number;
  successes: number;
  failures: number;
};

export type PortablePathRunExecutionEvent = {
  at: string;
  runner: PortablePathRunExecutionRunner;
  surface: PortablePathSigningPolicySurface;
  source: PortablePathInputSource | null;
  validateBeforeRun: boolean;
  validationMode: PortablePathValidationMode | null;
  durationMs: number;
  outcome: 'success' | 'failure';
  failureStage: PortablePathRunExecutionFailureStage | null;
  error: string | null;
};

export type PortablePathRunExecutionSnapshot = {
  totals: PortablePathRunExecutionCounts;
  byRunner: Record<PortablePathRunExecutionRunner, PortablePathRunExecutionCounts>;
  bySurface: Record<PortablePathSigningPolicySurface, PortablePathRunExecutionCounts>;
  bySource: Record<PortablePathInputSource, PortablePathRunExecutionCounts>;
  failureStageCounts: Record<PortablePathRunExecutionFailureStage, number>;
  recentEvents: PortablePathRunExecutionEvent[];
};

export type PortablePathRunExecutionHook = (
  event: PortablePathRunExecutionEvent,
  snapshot: PortablePathRunExecutionSnapshot
) => void;

const MAX_PORTABLE_PATH_RUN_EXECUTION_EVENTS = 100;

const createEmptyPortablePathRunExecutionCounts = (): PortablePathRunExecutionCounts => ({
  attempts: 0,
  successes: 0,
  failures: 0,
});

const createEmptyPortablePathRunExecutionState = (): PortablePathRunExecutionSnapshot => ({
  totals: createEmptyPortablePathRunExecutionCounts(),
  byRunner: {
    client: createEmptyPortablePathRunExecutionCounts(),
    server: createEmptyPortablePathRunExecutionCounts(),
  },
  bySurface: {
    canvas: createEmptyPortablePathRunExecutionCounts(),
    product: createEmptyPortablePathRunExecutionCounts(),
    api: createEmptyPortablePathRunExecutionCounts(),
  },
  bySource: {
    portable_package: createEmptyPortablePathRunExecutionCounts(),
    portable_envelope: createEmptyPortablePathRunExecutionCounts(),
    semantic_canvas: createEmptyPortablePathRunExecutionCounts(),
    path_config: createEmptyPortablePathRunExecutionCounts(),
  },
  failureStageCounts: {
    resolve: 0,
    validation: 0,
    runtime: 0,
  },
  recentEvents: [],
});

let portablePathRunExecutionState = createEmptyPortablePathRunExecutionState();
const portablePathRunExecutionHooks = new Set<PortablePathRunExecutionHook>();

const clonePortablePathRunExecutionSnapshot = (
  snapshot: PortablePathRunExecutionSnapshot
): PortablePathRunExecutionSnapshot => ({
  totals: { ...snapshot.totals },
  byRunner: {
    client: { ...snapshot.byRunner.client },
    server: { ...snapshot.byRunner.server },
  },
  bySurface: {
    canvas: { ...snapshot.bySurface.canvas },
    product: { ...snapshot.bySurface.product },
    api: { ...snapshot.bySurface.api },
  },
  bySource: {
    portable_package: { ...snapshot.bySource.portable_package },
    portable_envelope: { ...snapshot.bySource.portable_envelope },
    semantic_canvas: { ...snapshot.bySource.semantic_canvas },
    path_config: { ...snapshot.bySource.path_config },
  },
  failureStageCounts: { ...snapshot.failureStageCounts },
  recentEvents: snapshot.recentEvents.map((event) => ({ ...event })),
});

const emitPortablePathRunExecutionEvent = (event: PortablePathRunExecutionEvent): void => {
  if (portablePathRunExecutionHooks.size === 0) return;
  const snapshot = clonePortablePathRunExecutionSnapshot(portablePathRunExecutionState);
  for (const hook of portablePathRunExecutionHooks) {
    try {
      hook(event, snapshot);
    } catch (error) {
      logClientError(error);

      // Observability hooks must not break runtime execution.
    }
  }
};

const incrementPortablePathRunExecutionAttempt = (input: {
  runner: PortablePathRunExecutionRunner;
  surface: PortablePathSigningPolicySurface;
}): void => {
  portablePathRunExecutionState.totals.attempts += 1;
  portablePathRunExecutionState.byRunner[input.runner].attempts += 1;
  portablePathRunExecutionState.bySurface[input.surface].attempts += 1;
};

const pushPortablePathRunExecutionEvent = (event: PortablePathRunExecutionEvent): void => {
  portablePathRunExecutionState.recentEvents.push(event);
  if (portablePathRunExecutionState.recentEvents.length > MAX_PORTABLE_PATH_RUN_EXECUTION_EVENTS) {
    portablePathRunExecutionState.recentEvents.shift();
  }
  emitPortablePathRunExecutionEvent(event);
};

export const recordPortablePathRunExecutionAttempt = (input: {
  runner: PortablePathRunExecutionRunner;
  surface: PortablePathSigningPolicySurface;
}): void => {
  incrementPortablePathRunExecutionAttempt(input);
};

export const recordPortablePathRunExecutionSuccess = (input: {
  runner: PortablePathRunExecutionRunner;
  surface: PortablePathSigningPolicySurface;
  source: PortablePathInputSource;
  validateBeforeRun: boolean;
  validationMode: PortablePathValidationMode | null;
  durationMs: number;
}): void => {
  portablePathRunExecutionState.totals.successes += 1;
  portablePathRunExecutionState.byRunner[input.runner].successes += 1;
  portablePathRunExecutionState.bySurface[input.surface].successes += 1;
  portablePathRunExecutionState.bySource[input.source].attempts += 1;
  portablePathRunExecutionState.bySource[input.source].successes += 1;
  const event: PortablePathRunExecutionEvent = {
    at: new Date().toISOString(),
    runner: input.runner,
    surface: input.surface,
    source: input.source,
    validateBeforeRun: input.validateBeforeRun,
    validationMode: input.validationMode,
    durationMs: Math.max(0, Math.round(input.durationMs)),
    outcome: 'success',
    failureStage: null,
    error: null,
  };
  pushPortablePathRunExecutionEvent(event);
};

export const recordPortablePathRunExecutionFailure = (input: {
  runner: PortablePathRunExecutionRunner;
  surface: PortablePathSigningPolicySurface;
  source: PortablePathInputSource | null;
  validateBeforeRun: boolean;
  validationMode: PortablePathValidationMode | null;
  durationMs: number;
  failureStage: PortablePathRunExecutionFailureStage;
  error: unknown;
}): void => {
  const errorMessage = toPortablePathRunExecutionErrorMessage(input.error);
  portablePathRunExecutionState.totals.failures += 1;
  portablePathRunExecutionState.byRunner[input.runner].failures += 1;
  portablePathRunExecutionState.bySurface[input.surface].failures += 1;
  if (input.source) {
    portablePathRunExecutionState.bySource[input.source].attempts += 1;
    portablePathRunExecutionState.bySource[input.source].failures += 1;
  }
  portablePathRunExecutionState.failureStageCounts[input.failureStage] += 1;
  const event: PortablePathRunExecutionEvent = {
    at: new Date().toISOString(),
    runner: input.runner,
    surface: input.surface,
    source: input.source,
    validateBeforeRun: input.validateBeforeRun,
    validationMode: input.validationMode,
    durationMs: Math.max(0, Math.round(input.durationMs)),
    outcome: 'failure',
    failureStage: input.failureStage,
    error: errorMessage,
  };
  pushPortablePathRunExecutionEvent(event);
};

export const registerPortablePathRunExecutionHook = (
  hook: PortablePathRunExecutionHook
): (() => void) => {
  portablePathRunExecutionHooks.add(hook);
  return () => {
    portablePathRunExecutionHooks.delete(hook);
  };
};

export const getPortablePathRunExecutionSnapshot = (): PortablePathRunExecutionSnapshot =>
  clonePortablePathRunExecutionSnapshot(portablePathRunExecutionState);

export const resetPortablePathRunExecutionSnapshot = (): void => {
  portablePathRunExecutionState = createEmptyPortablePathRunExecutionState();
};

