import 'server-only';

import type { AiPathRunRepository } from '@/shared/contracts/ai-paths';
import {
  getCollectionProvider,
  getCollectionRouteMap,
} from '@/shared/lib/db/collection-provider-map';
import type { DatabaseEngineProvider } from '@/shared/lib/db/database-engine-constants';

import {
  claimRunForProcessing,
  createRun,
  deleteRun,
  findRunById,
  getRunByRequestId,
  updateRun,
  updateRunIfStatus,
} from './methods';
import {
  AI_PATHS_MONGO_INDEXES,
  mongoPathRunRepository,
} from './mongo-path-run-repository';

export const AI_PATH_RUNS_COLLECTION = 'ai_path_runs';

export type PathRunRepositorySelection = {
  collection: typeof AI_PATH_RUNS_COLLECTION;
  provider: 'mongodb';
  repo: AiPathRunRepository;
  routeMode: 'explicit' | 'fallback';
};

export type PersistedRunRepositorySelection = {
  collection: string | null;
  provider: 'mongodb' | null;
  routeMode: 'explicit' | 'fallback' | null;
  selectedAt: string | null;
};

const hasExplicitCollectionRoute = (
  routeMap: Record<string, DatabaseEngineProvider>
): boolean => {
  if (AI_PATH_RUNS_COLLECTION in routeMap) return true;
  const normalizedCollection = AI_PATH_RUNS_COLLECTION.trim().toLowerCase();
  return Object.keys(routeMap).some((collectionName) => {
    return collectionName.trim().toLowerCase() === normalizedCollection;
  });
};

const asRecord = (value: unknown): Record<string, unknown> | null =>
  value && typeof value === 'object' && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : null;

const asProvider = (value: unknown): 'mongodb' | null => (value === 'mongodb' ? value : null);

const asRouteMode = (value: unknown): 'explicit' | 'fallback' | null =>
  value === 'explicit' || value === 'fallback' ? value : null;

const asOptionalString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

export const readPersistedRunRepositorySelection = (
  meta: unknown
): PersistedRunRepositorySelection | null => {
  const metaRecord = asRecord(meta);
  const runRepository = asRecord(metaRecord?.['runRepository']);
  if (!runRepository) return null;

  const selection: PersistedRunRepositorySelection = {
    collection: asOptionalString(runRepository['collection']),
    provider: asProvider(runRepository['provider']),
    routeMode: asRouteMode(runRepository['routeMode']),
    selectedAt: asOptionalString(runRepository['selectedAt']),
  };

  if (!selection.collection && !selection.provider && !selection.routeMode && !selection.selectedAt) {
    return null;
  }
  return selection;
};

export const hasRunRepositorySelectionMismatch = (
  persisted: PersistedRunRepositorySelection | null,
  current: Pick<PathRunRepositorySelection, 'collection' | 'provider' | 'routeMode'>
): boolean => {
  if (!persisted) return false;
  if (persisted.collection && persisted.collection !== current.collection) return true;
  if (persisted.provider && persisted.provider !== current.provider) return true;
  if (persisted.routeMode && persisted.routeMode !== current.routeMode) return true;
  return false;
};

export const resolvePathRunRepository = async (): Promise<PathRunRepositorySelection> => {
  const [provider, routeMap] = await Promise.all([
    getCollectionProvider(AI_PATH_RUNS_COLLECTION),
    getCollectionRouteMap(),
  ]);
  return {
    collection: AI_PATH_RUNS_COLLECTION,
    provider,
    repo: mongoPathRunRepository,
    routeMode: hasExplicitCollectionRoute(routeMap) ? 'explicit' : 'fallback',
  };
};

export const resolveAlternatePathRunRepository = async (
  currentProvider: 'mongodb'
): Promise<
  | {
      collection: typeof AI_PATH_RUNS_COLLECTION;
      provider: 'mongodb';
      repo: AiPathRunRepository;
    }
  | null
> => {
  void currentProvider;
  return null;
};

export const getPathRunRepository = async (): Promise<AiPathRunRepository> => {
  return (await resolvePathRunRepository()).repo;
};

export {
  AI_PATHS_MONGO_INDEXES,
  claimRunForProcessing,
  createRun,
  deleteRun,
  findRunById,
  mongoPathRunRepository,
  getRunByRequestId,
  updateRun,
  updateRunIfStatus,
};

import { getMongoDb } from '@/shared/lib/db/mongo-client';
import { randomUUID } from 'node:crypto';
import type { AiPathRunCreateInput, AiPathRunRecord } from '@/shared/contracts/ai-paths';
import {
  ensureIndexes,
  RUNS_COLLECTION,
  toRunRecord,
  type RunDocument,
} from './shared';

export const createRun = async (input: AiPathRunCreateInput): Promise<AiPathRunRecord> => {
  await ensureIndexes();
  const db = await getMongoDb();
  const now = new Date();
  const id = randomUUID();
  const document: RunDocument = {
    _id: id,
    id,
    userId: input.userId ?? null,
    pathId: input.pathId ?? null,
    pathName: input.pathName ?? null,
    status: input.status ?? 'queued',
    triggerEvent: input.triggerEvent ?? null,
    triggerNodeId: input.triggerNodeId ?? null,
    triggerContext: input.triggerContext ?? null,
    graph: (input.graph as Record<string, unknown>) ?? null,
    runtimeState: (input.runtimeState as Record<string, unknown>) ?? null,
    meta: input.meta ?? null,
    entityId: input.entityId ?? null,
    entityType: input.entityType ?? null,
    errorMessage: null,
    retryCount: input.retryCount ?? 0,
    maxAttempts: input.maxAttempts ?? 3,
    nextRetryAt: input.nextRetryAt ? new Date(input.nextRetryAt) : null,
    createdAt: now,
    updatedAt: now,
    startedAt: null,
    finishedAt: null,
  };

  await db.collection<RunDocument>(RUNS_COLLECTION).insertOne(document);
  return toRunRecord(document);
};

import { getMongoDb } from '@/shared/lib/db/mongo-client';
import type { AiPathRunRecord } from '@/shared/contracts/ai-paths';
import { ensureIndexes, RUNS_COLLECTION, toRunRecord, type RunDocument } from './shared';
import type { Filter } from 'mongodb';

export const findRunById = async (runId: string): Promise<AiPathRunRecord | null> => {
  await ensureIndexes();
  const db = await getMongoDb();
  const collection = db.collection<RunDocument>(RUNS_COLLECTION);
  const filter: Filter<RunDocument> = { $or: [{ _id: runId }, { id: runId }] as any };
  const doc = await collection.findOne(filter);

  if (doc === null) return null;
  return toRunRecord(doc);
};

import type { AiPathRunEventListOptions, AiPathRunEventRecord } from '@/shared/contracts/ai-paths';
import { getMongoDb } from '@/shared/lib/db/mongo-client';

import {
  ensureIndexes,
  EVENTS_COLLECTION,
  toEventRecord,
  type EventDocument,
} from './shared';

export const listRunEvents = async (
  runId: string,
  options: AiPathRunEventListOptions = {}
): Promise<AiPathRunEventRecord[]> => {
  await ensureIndexes();
  const db = await getMongoDb();
  const filter: Record<string, unknown> = { runId };

  const sinceValue = options.since ? new Date(options.since) : null;
  const since = sinceValue !== null && !Number.isNaN(sinceValue.getTime()) ? sinceValue : null;

  const afterDateValue = options.after?.createdAt ? new Date(options.after.createdAt) : null;
  const afterDate =
    afterDateValue !== null && !Number.isNaN(afterDateValue.getTime()) ? afterDateValue : null;
  const afterId =
    typeof options.after?.id === 'string' && options.after.id.trim().length > 0
      ? options.after.id.trim()
      : null;

  if (afterDate !== null && afterId !== null) {
    filter['$or'] = [
      { createdAt: { $gt: afterDate } },
      {
        createdAt: afterDate,
        $or: [{ _id: { $gt: afterId } }, { id: { $gt: afterId } }],
      },
    ];
  } else if (since !== null) {
    filter['createdAt'] = { $gt: since };
  }

  const cursor = db
    .collection<EventDocument>(EVENTS_COLLECTION)
    .find(filter)
    .sort({ createdAt: 1, _id: 1 });

  if (typeof options.limit === 'number') {
    cursor.limit(options.limit);
  }
  const docs = await cursor.toArray();

  return docs.map(toEventRecord);
};

import type { AiPathRunListOptions, AiPathRunRecord } from '@/shared/contracts/ai-paths';
import { getMongoDb } from '@/shared/lib/db/mongo-client';

import {
  appendRunIdConstraint,
  buildRunFilter,
  resolveRunIdsForNodeFilter,
  RUN_LIST_PROJECTION,
} from './run-query-helpers';
import {
  ensureIndexes,
  RUNS_COLLECTION,
  toRunRecord,
  type RunDocument,
} from './shared';

const getSortDirection = (_options: AiPathRunListOptions): Record<string, 1 | -1> => {
  return { createdAt: -1 };
};

export const listRuns = async (
  options: AiPathRunListOptions = {}
): Promise<{ runs: AiPathRunRecord[]; total: number }> => {
  await ensureIndexes();
  const db = await getMongoDb();
  let filter = buildRunFilter(options);
  const nodeId = options.nodeId !== null && options.nodeId !== undefined ? options.nodeId.trim() : undefined;

  if (nodeId !== undefined && nodeId !== '') {
    const runIds = await resolveRunIdsForNodeFilter(db, nodeId);
    if (runIds.length === 0) return { runs: [], total: 0 };
    filter = appendRunIdConstraint(filter, runIds);
  }

  const cursor = db
    .collection<RunDocument>(RUNS_COLLECTION)
    .find(filter, { projection: RUN_LIST_PROJECTION })
    .sort(getSortDirection(options))
    .allowDiskUse(true);

  if (typeof options.offset === 'number') cursor.skip(options.offset);
  if (typeof options.limit === 'number') cursor.limit(options.limit);

  const docs = await cursor.toArray();
  const includeTotal = options.includeTotal ?? true;
  const total = includeTotal 
    ? await db.collection<RunDocument>(RUNS_COLLECTION).countDocuments(filter)
    : docs.length;

  return { runs: docs.map(toRunRecord), total };
};

import type { AiPathRunListOptions, AiPathRunQueueStatsOptions } from '@/shared/contracts/ai-paths';
import { AI_PATHS_RUN_SOURCE_VALUES } from '@/shared/lib/ai-paths/run-sources';

import type { Db } from 'mongodb';

import {
  NODES_COLLECTION,
  type NodeDocument,
} from './shared';

const escapeRegex = (value: string): string => value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const parseFilterDate = (value: Date | string | null | undefined): Date | null => {
  if (!value) return null;
  const date = typeof value === 'string' ? new Date(value) : value;
  return Number.isNaN(date.getTime()) ? null : date;
};

export const RUN_LIST_PROJECTION = {
  _id: 1,
  id: 1,
  userId: 1,
  pathId: 1,
  pathName: 1,
  status: 1,
  triggerEvent: 1,
  triggerNodeId: 1,
  meta: 1,
  entityId: 1,
  entityType: 1,
  errorMessage: 1,
  retryCount: 1,
  maxAttempts: 1,
  nextRetryAt: 1,
  createdAt: 1,
  updatedAt: 1,
  startedAt: 1,
  finishedAt: 1,
} as const;

export const buildRunFilter = (options: AiPathRunListOptions = {}): Record<string, unknown> => {
  const andFilters: Record<string, unknown>[] = [];
  if (options.id) {
    andFilters.push({ $or: [{ id: options.id }, { _id: options.id }] });
  }
  if (options.userId) {
    andFilters.push({ userId: options.userId });
  }
  if (options.pathId) {
    andFilters.push({ pathId: options.pathId });
  }
  if (options.requestId?.trim()) {
    andFilters.push({ 'meta.requestId': options.requestId.trim() });
  }
  const statuses = Array.isArray(options.statuses) ? options.statuses.filter(Boolean) : [];
  if (statuses.length > 0) {
    andFilters.push({ status: { $in: statuses } });
  } else if (options.status) {
    andFilters.push({ status: options.status });
  }
  const source = options.source?.trim();
  const sourceMode = options.sourceMode ?? 'include';
  if (source) {
    if (sourceMode === 'exclude') {
      if (source === 'ai_paths_ui') {
        andFilters.push({ 'meta.source': { $nin: [...AI_PATHS_RUN_SOURCE_VALUES] } });
      } else {
        andFilters.push({ 'meta.source': { $ne: source } });
      }
    } else if (source === 'ai_paths_ui') {
      andFilters.push({ 'meta.source': { $in: [...AI_PATHS_RUN_SOURCE_VALUES] } });
    } else {
      andFilters.push({ 'meta.source': source });
    }
  }
  const query = options.query?.trim();
  if (query) {
    const regex = new RegExp(escapeRegex(query), 'i');
    andFilters.push({
      $or: [
        { id: { $regex: regex } },
        { _id: { $regex: regex } },
        { pathId: { $regex: regex } },
        { pathName: { $regex: regex } },
        { entityId: { $regex: regex } },
        { errorMessage: { $regex: regex } },
      ],
    });
  }
  const createdAfter = parseFilterDate(options.createdAfter);
  const createdBefore = parseFilterDate(options.createdBefore);
  if (createdAfter || createdBefore) {
    andFilters.push({
      createdAt: {
        ...(createdAfter ? { $gte: createdAfter } : {}),
        ...(createdBefore ? { $lte: createdBefore } : {}),
      },
    });
  }
  return andFilters.length > 0 ? { $and: andFilters } : {};
};

const buildRunIdConstraint = (runIds: string[]): Record<string, unknown> => ({
  $or: [{ _id: { $in: runIds } }, { id: { $in: runIds } }],
});

export const appendRunIdConstraint = (
  filter: Record<string, unknown>,
  runIds: string[]
): Record<string, unknown> => {
  const runIdConstraint = buildRunIdConstraint(runIds);
  const existingAnd = Array.isArray(filter['$and'])
    ? (filter['$and'] as Record<string, unknown>[])
    : null;
  if (existingAnd) {
    return { $and: [...existingAnd, runIdConstraint] };
  }
  if (Object.keys(filter).length === 0) return runIdConstraint;
  return { $and: [filter, runIdConstraint] };
};

export const resolveRunIdsForNodeFilter = async (db: Db, nodeId: string): Promise<string[]> => {
  const runIds = await db.collection<NodeDocument>(NODES_COLLECTION).distinct('runId', { nodeId });
  return runIds.filter(
    (value: unknown): value is string => typeof value === 'string' && value.trim().length > 0
  );
};

export const buildQueueStatsFilter = (
  options: AiPathRunQueueStatsOptions = {}
): Record<string, unknown> => {
  const now = new Date();
  const baseFilter = buildRunFilter({
    ...(options.userId ? { userId: options.userId } : {}),
    ...(options.pathId ? { pathId: options.pathId } : {}),
    ...(options.source ? { source: options.source, sourceMode: options.sourceMode } : {}),
    status: 'queued',
  });
  const retryFilter = {
    $or: [{ nextRetryAt: null }, { nextRetryAt: { $lte: now } }],
  };

  return Object.keys(baseFilter).length > 0
    ? { $and: [baseFilter, retryFilter] }
    : { status: 'queued', ...retryFilter };
};

