import 'server-only';

import type { Redis } from 'ioredis';

import { getRedisConnection } from '@/shared/lib/queue';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

import { keyRuns, keyTotals, keyDurations, keyNodes, keyBrain } from './config';
import {
  toTimestampMs,
  pruneBefore,
  buildEventMember,
  buildDurationMember,
  resolveRuntimeAnalyticsNodeStatusKey,
} from './utils';

const isRedisReady = (redis: ReturnType<typeof getRedisConnection>): redis is Redis =>
  Boolean(redis?.status === 'ready');

export const recordRuntimeRunQueued = async (input: {
  runId: string;
  timestamp?: Date | string | number | null;
}): Promise<void> => {
  try {
    const redis = getRedisConnection();
    if (!isRedisReady(redis) || !input.runId) return;
    const timestampMs = toTimestampMs(input.timestamp);
    const pruneTo = pruneBefore(timestampMs);
    const multi = redis.multi();
    multi.zadd(
      keyRuns('all'),
      String(timestampMs),
      buildEventMember('run_queued', input.runId, timestampMs)
    );
    multi.zadd(
      keyRuns('queued'),
      String(timestampMs),
      buildEventMember('queued', input.runId, timestampMs)
    );
    multi.zremrangebyscore(keyRuns('all'), 0, pruneTo);
    multi.zremrangebyscore(keyRuns('queued'), 0, pruneTo);
    multi.hincrby(keyTotals(), 'runs_total', 1);
    multi.hincrby(keyTotals(), 'runs_queued', 1);
    await multi.exec();
  } catch (error) {
    void ErrorSystem.captureException(error);
    void ErrorSystem.logWarning('Failed to record run queued analytics', {
      service: 'ai-paths-analytics',
      error,
      runId: input.runId,
    });
  }
};

export const recordRuntimeRunStarted = async (input: {
  runId: string;
  timestamp?: Date | string | number | null;
}): Promise<void> => {
  try {
    const redis = getRedisConnection();
    if (!isRedisReady(redis) || !input.runId) return;
    const timestampMs = toTimestampMs(input.timestamp);
    const pruneTo = pruneBefore(timestampMs);
    const multi = redis.multi();
    multi.zadd(
      keyRuns('started'),
      String(timestampMs),
      buildEventMember('started', input.runId, timestampMs)
    );
    multi.zremrangebyscore(keyRuns('started'), 0, pruneTo);
    multi.hincrby(keyTotals(), 'runs_started', 1);
    await multi.exec();
  } catch (error) {
    void ErrorSystem.captureException(error);
    void ErrorSystem.logWarning('Failed to record run started analytics', {
      service: 'ai-paths-analytics',
      error,
      runId: input.runId,
    });
  }
};

export const recordRuntimeRunBlockedOnLease = (input: {
  runId: string;
  timestamp?: Date | string | number | null;
}): Promise<void> => {
  void input;
  return Promise.resolve();
};

export const recordRuntimeRunHandoffReady = (input: {
  runId: string;
  timestamp?: Date | string | number | null;
}): Promise<void> => {
  void input;
  return Promise.resolve();
};

export const recordRuntimeRunFinished = async (input: {
  runId: string;
  status: 'completed' | 'failed' | 'canceled';
  durationMs?: number | null;
  timestamp?: Date | string | number | null;
}): Promise<void> => {
  try {
    const redis = getRedisConnection();
    if (!isRedisReady(redis) || !input.runId) return;
    const timestampMs = toTimestampMs(input.timestamp);
    const pruneTo = pruneBefore(timestampMs);
    const runStatusKey = keyRuns(input.status);
    const multi = redis.multi();
    multi.zadd(
      runStatusKey,
      String(timestampMs),
      buildEventMember(input.status, input.runId, timestampMs)
    );
    multi.zremrangebyscore(runStatusKey, 0, pruneTo);
    multi.hincrby(keyTotals(), `runs_${input.status}`, 1);

    const durationMs =
      typeof input.durationMs === 'number' && Number.isFinite(input.durationMs)
        ? Math.max(0, Math.round(input.durationMs))
        : null;
    if (durationMs !== null) {
      multi.zadd(
        keyDurations(),
        String(timestampMs),
        buildDurationMember(input.runId, durationMs, timestampMs)
      );
      multi.zremrangebyscore(keyDurations(), 0, pruneTo);
      multi.hincrby(keyTotals(), 'runs_duration_count', 1);
      multi.hincrby(keyTotals(), 'runs_duration_total_ms', durationMs);
    }
    await multi.exec();
  } catch (error) {
    void ErrorSystem.captureException(error);
    void ErrorSystem.logWarning('Failed to record run finished analytics', {
      service: 'ai-paths-analytics',
      error,
      runId: input.runId,
    });
  }
};

export const recordRuntimeNodeStatus = async (input: {
  runId: string;
  nodeId: string;
  status: unknown;
  timestamp?: Date | string | number | null;
}): Promise<void> => {
  try {
    const redis = getRedisConnection();
    if (!isRedisReady(redis) || !input.runId || !input.nodeId) return;
    const statusKey = resolveRuntimeAnalyticsNodeStatusKey(input.status);
    if (!statusKey) return;

    const timestampMs = toTimestampMs(input.timestamp);
    const pruneTo = pruneBefore(timestampMs);
    const multi = redis.multi();
    multi.zadd(
      keyNodes(statusKey),
      String(timestampMs),
      buildEventMember(`node_${statusKey}`, `${input.runId}:${input.nodeId}`, timestampMs)
    );
    multi.zremrangebyscore(keyNodes(statusKey), 0, pruneTo);
    multi.hincrby(keyTotals(), `nodes_${statusKey}`, 1);
    await multi.exec();
  } catch (error) {
    void ErrorSystem.captureException(error);
    void ErrorSystem.logWarning('Failed to record node status analytics', {
      service: 'ai-paths-analytics',
      error,
      runId: input.runId,
      nodeId: input.nodeId,
    });
  }
};

export const recordBrainInsightAnalytics = async (input: {
  type: 'analytics' | 'logs' | 'generation';
  status: 'success' | 'error' | 'warning';
  metadata?: Record<string, unknown>;
  timestamp?: Date | string | number | null;
}): Promise<void> => {
  try {
    const redis = getRedisConnection();
    if (!redis) return;
    const timestampMs = toTimestampMs(input.timestamp);
    const pruneTo = pruneBefore(timestampMs);
    const multi = redis.multi();
    const eventType = `brain_${input.type}_${input.status}`;
    const member = buildEventMember(eventType, JSON.stringify(input.metadata ?? {}), timestampMs);

    multi.zadd(keyBrain('all'), String(timestampMs), member);
    multi.zremrangebyscore(keyBrain('all'), 0, pruneTo);

    if (input.type === 'analytics') {
      multi.zadd(keyBrain('analytics'), String(timestampMs), member);
      multi.zremrangebyscore(keyBrain('analytics'), 0, pruneTo);
    } else if (input.type === 'logs') {
      multi.zadd(keyBrain('logs'), String(timestampMs), member);
      multi.zremrangebyscore(keyBrain('logs'), 0, pruneTo);
    }

    if (input.status === 'warning') {
      multi.zadd(keyBrain('warning'), String(timestampMs), member);
      multi.zremrangebyscore(keyBrain('warning'), 0, pruneTo);
    } else if (input.status === 'error') {
      multi.zadd(keyBrain('error'), String(timestampMs), member);
      multi.zremrangebyscore(keyBrain('error'), 0, pruneTo);
    }

    multi.hincrby(keyTotals(), `brain_${input.type}_${input.status}`, 1);
    await multi.exec();
  } catch (error) {
    void ErrorSystem.captureException(error);
    void ErrorSystem.logWarning('Failed to record Brain insight analytics', {
      service: 'ai-paths-analytics',
      error,
    });
  }
};

import 'server-only';

import type {
  AiPathRuntimeAnalyticsRange,
  AiPathRuntimeAnalyticsSummary,
} from '@/shared/contracts/ai-paths';
import { getRedisConnection } from '@/shared/lib/queue';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

import { getRuntimeAnalyticsAvailability } from './availability';
import {
  buildSummaryCacheKey,
  readCachedSummary,
  readStaleSummary,
  setCachedSummary,
  summaryInFlight,
} from './cache';
import {
  DURATION_SAMPLE_LIMIT,
  SUMMARY_QUERY_TIMEOUT_MS,
  keyBrain,
  keyDurations,
  keyNodes,
  keyRuns,
} from './config';
import { emptySummary, emptyTraceAnalytics, loadRuntimeTraceAnalytics } from './trace';
import {
  clampRate,
  parseDurationMember,
  toPipelineCount,
  toPipelineStrings,
  withTimeout,
} from './utils';

export type RuntimeAnalyticsSummaryInput = {
  from: Date;
  to: Date;
  range?: AiPathRuntimeAnalyticsRange | 'custom';
  includeTraces?: boolean;
};

export const resolveRuntimeAnalyticsRangeWindow = (
  range: AiPathRuntimeAnalyticsRange
): { from: Date; to: Date } => {
  const to = new Date();
  const msByRange: Record<AiPathRuntimeAnalyticsRange, number> = {
    '1h': 60 * 60 * 1000,
    '24h': 24 * 60 * 60 * 1000,
    '7d': 7 * 24 * 60 * 60 * 1000,
    '30d': 30 * 24 * 60 * 60 * 1000,
  };
  return {
    from: new Date(to.getTime() - msByRange[range]),
    to,
  };
};

export const getRuntimeAnalyticsSummaryBase = async (
  input: RuntimeAnalyticsSummaryInput
): Promise<AiPathRuntimeAnalyticsSummary> => {
  const from = input.from;
  const to = input.to;
  const range = input.range ?? 'custom';
  const includeTraces = input.includeTraces !== false;
  const availability = await getRuntimeAnalyticsAvailability();
  if (!availability.enabled) {
    return emptySummary(from, to, range);
  }
  const redis = getRedisConnection();
  if (!redis) {
    return emptySummary(from, to, range);
  }

  const fromMs = from.getTime();
  const toMs = to.getTime();
  const cacheKey = buildSummaryCacheKey(fromMs, toMs, range);
  const now = Date.now();
  const cached = readCachedSummary(cacheKey, now);
  if (cached) return cached;

  const inFlight = summaryInFlight.get(cacheKey);
  if (inFlight) return inFlight;

  const loadPromise = (async (): Promise<AiPathRuntimeAnalyticsSummary> => {
    const runtimeTracePromise = includeTraces
      ? loadRuntimeTraceAnalytics({ from, to })
      : Promise.resolve(emptyTraceAnalytics());
    try {
      const pipeline = redis.pipeline();
      pipeline.zcount(keyRuns('all'), fromMs, toMs);
      pipeline.zcount(keyRuns('queued'), fromMs, toMs);
      pipeline.zcount(keyRuns('started'), fromMs, toMs);
      pipeline.zcount(keyRuns('completed'), fromMs, toMs);
      pipeline.zcount(keyRuns('failed'), fromMs, toMs);
      pipeline.zcount(keyRuns('canceled'), fromMs, toMs);
      pipeline.zcount(keyNodes('started'), fromMs, toMs);
      pipeline.zcount(keyNodes('completed'), fromMs, toMs);
      pipeline.zcount(keyNodes('failed'), fromMs, toMs);
      pipeline.zcount(keyNodes('queued'), fromMs, toMs);
      pipeline.zcount(keyNodes('running'), fromMs, toMs);
      pipeline.zcount(keyNodes('polling'), fromMs, toMs);
      pipeline.zcount(keyNodes('cached'), fromMs, toMs);
      pipeline.zcount(keyNodes('waiting_callback'), fromMs, toMs);
      pipeline.zcount(keyBrain('analytics'), fromMs, toMs);
      pipeline.zcount(keyBrain('logs'), fromMs, toMs);
      pipeline.zcount(keyBrain('all'), fromMs, toMs);
      pipeline.zcount(keyBrain('warning'), fromMs, toMs);
      pipeline.zcount(keyBrain('error'), fromMs, toMs);
      pipeline.zrangebyscore(keyDurations(), fromMs, toMs, 'LIMIT', 0, DURATION_SAMPLE_LIMIT);

      const results =
        (await withTimeout(
          pipeline.exec(),
          SUMMARY_QUERY_TIMEOUT_MS,
          'ai-paths runtime analytics summary'
        )) ?? [];
      for (const result of results) {
        if (Array.isArray(result) && result[0]) {
          throw result[0];
        }
      }

      const readCountAt = (index: number): number =>
        toPipelineCount(Array.isArray(results[index]) ? results[index]?.[1] : 0);
      const durationMembers = toPipelineStrings(Array.isArray(results[19]) ? results[19]?.[1] : []);
      const durations = durationMembers
        .map(parseDurationMember)
        .filter((value: number | null): value is number => value !== null)
        .sort((a: number, b: number) => a - b);
      const avgDurationMs =
        durations.length > 0
          ? Math.round(
            durations.reduce((sum: number, value: number) => sum + value, 0) / durations.length
          )
          : null;
      const p95DurationMs =
        durations.length > 0
          ? durations[
            Math.min(durations.length - 1, Math.max(0, Math.ceil(durations.length * 0.95) - 1))
          ]!
          : null;

      const runsCompleted = readCountAt(3);
      const runsFailed = readCountAt(4);
      const runsCanceled = readCountAt(5);
      const terminalRuns = runsCompleted + runsFailed + runsCanceled;
      const successRate = terminalRuns > 0 ? clampRate((runsCompleted / terminalRuns) * 100) : 0;
      const failureRate =
        terminalRuns > 0
          ? clampRate(((runsFailed + runsCanceled) / terminalRuns) * 100)
          : 0;
      const traces = await runtimeTracePromise;

      const summary: AiPathRuntimeAnalyticsSummary = {
        from: from.toISOString(),
        to: to.toISOString(),
        range,
        storage: 'redis',
        runs: {
          total: readCountAt(0),
          queued: readCountAt(1),
          started: readCountAt(2),
          completed: runsCompleted,
          failed: runsFailed,
          canceled: runsCanceled,
          successRate,
          failureRate,
          avgDurationMs,
          p95DurationMs,
        },
        nodes: {
          started: readCountAt(6),
          completed: readCountAt(7),
          failed: readCountAt(8),
          queued: readCountAt(9),
          running: readCountAt(10),
          polling: readCountAt(11),
          cached: readCountAt(12),
          waitingCallback: readCountAt(13),
        },
        brain: {
          analyticsReports: readCountAt(14),
          logReports: readCountAt(15),
          totalReports: readCountAt(16),
          warningReports: readCountAt(17),
          errorReports: readCountAt(18),
        },
        traces,
        generatedAt: new Date().toISOString(),
      };
      setCachedSummary(cacheKey, summary, Date.now());
      return summary;
    } catch (error) {
      void ErrorSystem.captureException(error);
      void ErrorSystem.logWarning('Failed to load runtime analytics summary', {
        service: 'ai-paths-analytics',
        error,
        range,
      });
      const stale = readStaleSummary(cacheKey);
      if (stale) return stale;
      const fallback = emptySummary(from, to, range);
      fallback.traces = includeTraces ? await runtimeTracePromise : emptyTraceAnalytics();
      return fallback;
    }
  })();

  summaryInFlight.set(cacheKey, loadPromise);
  try {
    return await loadPromise;
  } finally {
    summaryInFlight.delete(cacheKey);
  }
};

import 'server-only';

import {
  type AiPathRunRecord,
  type AiPathRuntimeTraceAnalytics,
  type AiPathRuntimeAnalyticsRange,
  type AiPathRuntimeAnalyticsSummary,
} from '@/shared/contracts/ai-paths';
import { getPathRunRepository } from '@/shared/lib/ai-paths/services/path-run-repository';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

import {
  TRACE_NODE_HIGHLIGHT_LIMIT,
  TRACE_RUN_SAMPLE_LIMIT,
  SUMMARY_QUERY_TIMEOUT_MS,
} from './config';
import { asRecord, toNonEmptyString, toFiniteDurationMs, withTimeout } from './utils';

export const extractRuntimeTraceNodeSpans = (run: AiPathRunRecord): unknown[] => {
  const meta = asRecord(run.meta);
  if (!meta) return [];
  const runtimeTrace = asRecord(meta['runtimeTrace']);
  if (!runtimeTrace) return [];
  const spans = runtimeTrace['spans'];
  if (Array.isArray(spans)) return spans;
  const profile = asRecord(runtimeTrace['profile']);
  if (!profile) return [];
  const nodeSpans = profile['nodeSpans'];
  return Array.isArray(nodeSpans) ? nodeSpans : [];
};

export const emptyTraceAnalytics = (): AiPathRuntimeTraceAnalytics => ({
  source: 'none',
  sampledRuns: 0,
  sampledSpans: 0,
  completedSpans: 0,
  failedSpans: 0,
  cachedSpans: 0,
  avgDurationMs: null,
  p95DurationMs: null,
  slowestSpan: null,
  topSlowNodes: [],
  topFailedNodes: [],
  kernelParity: {
    sampledRuns: 0,
    runsWithKernelParity: 0,
    sampledHistoryEntries: 0,
    strategyCounts: {
      code_object_v3: 0,
      compatibility: 0,
      unknown: 0,
    },
    resolutionSourceCounts: {
      override: 0,
      registry: 0,
      missing: 0,
      unknown: 0,
    },
    codeObjectIds: [],
  },
  truncated: false,
});

const normalizeNonNegativeInteger = (value: unknown): number =>
  typeof value === 'number' && Number.isFinite(value) && value >= 0 ? Math.round(value) : 0;

const extractRuntimeTraceKernelParity = (
  run: AiPathRunRecord
): AiPathRuntimeTraceAnalytics['kernelParity'] | null => {
  const meta = asRecord(run.meta);
  if (!meta) return null;
  const runtimeTrace = asRecord(meta['runtimeTrace']);
  if (!runtimeTrace) return null;
  const kernelParity = asRecord(runtimeTrace['kernelParity']);
  if (!kernelParity) return null;

  const strategyCounts = asRecord(kernelParity['strategyCounts']);
  const resolutionSourceCounts = asRecord(kernelParity['resolutionSourceCounts']);
  const rawCodeObjectIds = Array.isArray(kernelParity['codeObjectIds'])
    ? kernelParity['codeObjectIds']
    : [];

  return {
    sampledRuns: 0,
    runsWithKernelParity: 0,
    sampledHistoryEntries: normalizeNonNegativeInteger(kernelParity['sampledHistoryEntries']),
    strategyCounts: {
      code_object_v3: normalizeNonNegativeInteger(strategyCounts?.['code_object_v3']),
      compatibility: normalizeNonNegativeInteger(strategyCounts?.['compatibility']),
      unknown: normalizeNonNegativeInteger(strategyCounts?.['unknown']),
    },
    resolutionSourceCounts: {
      override: normalizeNonNegativeInteger(resolutionSourceCounts?.['override']),
      registry: normalizeNonNegativeInteger(resolutionSourceCounts?.['registry']),
      missing: normalizeNonNegativeInteger(resolutionSourceCounts?.['missing']),
      unknown: normalizeNonNegativeInteger(resolutionSourceCounts?.['unknown']),
    },
    codeObjectIds: rawCodeObjectIds
      .filter(
        (entry: unknown): entry is string => typeof entry === 'string' && entry.trim().length > 0
      )
      .map((entry: string) => entry.trim())
      .slice(0, 25),
  };
};

type NodeAggregate = {
  nodeId: string;
  nodeType: string;
  spanCount: number;
  failedCount: number;
  durationCount: number;
  totalDurationMs: number;
  maxDurationMs: number;
};

type RuntimeTraceSummaryState = {
  durations: number[];
  nodeAggregates: Map<string, NodeAggregate>;
  sampledSpans: number;
  completedSpans: number;
  failedSpans: number;
  cachedSpans: number;
  slowestSpan: AiPathRuntimeTraceAnalytics['slowestSpan'];
  kernelParity: AiPathRuntimeTraceAnalytics['kernelParity'];
  codeObjectIdSet: Set<string>;
};

const createRuntimeTraceSummaryState = (
  sampledRuns: number
): RuntimeTraceSummaryState => ({
  durations: [],
  nodeAggregates: new Map<string, NodeAggregate>(),
  sampledSpans: 0,
  completedSpans: 0,
  failedSpans: 0,
  cachedSpans: 0,
  slowestSpan: null,
  kernelParity: {
    sampledRuns,
    runsWithKernelParity: 0,
    sampledHistoryEntries: 0,
    strategyCounts: {
      code_object_v3: 0,
      compatibility: 0,
      unknown: 0,
    },
    resolutionSourceCounts: {
      override: 0,
      registry: 0,
      missing: 0,
      unknown: 0,
    },
    codeObjectIds: [],
  },
  codeObjectIdSet: new Set<string>(),
});

const mergeRuntimeTraceKernelParity = (
  state: RuntimeTraceSummaryState,
  parity: NonNullable<ReturnType<typeof extractRuntimeTraceKernelParity>>
): void => {
  state.kernelParity.runsWithKernelParity += 1;
  state.kernelParity.sampledHistoryEntries += parity.sampledHistoryEntries;
  state.kernelParity.strategyCounts.code_object_v3 += parity.strategyCounts.code_object_v3;
  state.kernelParity.strategyCounts.compatibility += parity.strategyCounts.compatibility;
  state.kernelParity.strategyCounts.unknown += parity.strategyCounts.unknown;
  state.kernelParity.resolutionSourceCounts.override += parity.resolutionSourceCounts.override;
  state.kernelParity.resolutionSourceCounts.registry += parity.resolutionSourceCounts.registry;
  state.kernelParity.resolutionSourceCounts.missing += parity.resolutionSourceCounts.missing;
  state.kernelParity.resolutionSourceCounts.unknown += parity.resolutionSourceCounts.unknown;
  parity.codeObjectIds.forEach((codeObjectId: string) => {
    state.codeObjectIdSet.add(codeObjectId);
  });
};

const resolveRuntimeTraceNodeAggregate = (
  state: RuntimeTraceSummaryState,
  nodeId: string,
  nodeType: string
): NodeAggregate => {
  const aggregateKey = `${nodeId}::${nodeType}`;
  return (
    state.nodeAggregates.get(aggregateKey) ?? {
      nodeId,
      nodeType,
      spanCount: 0,
      failedCount: 0,
      durationCount: 0,
      totalDurationMs: 0,
      maxDurationMs: 0,
    }
  );
};

const updateRuntimeTraceSlowestSpan = (
  state: RuntimeTraceSummaryState,
  run: AiPathRunRecord,
  span: Record<string, unknown>,
  input: {
    nodeId: string;
    nodeType: string;
    status: string;
    durationMs: number;
  }
): void => {
  if (state.slowestSpan && input.durationMs <= state.slowestSpan.durationMs) {
    return;
  }

  state.slowestSpan = {
    runId: toNonEmptyString(run.id) ?? 'unknown',
    spanId: toNonEmptyString(span['spanId']) ?? 'unknown',
    nodeId: input.nodeId,
    nodeType: input.nodeType,
    status: input.status,
    durationMs: input.durationMs,
  };
};

const collectRuntimeTraceSpan = (
  state: RuntimeTraceSummaryState,
  run: AiPathRunRecord,
  spanValue: unknown
): void => {
  const span = asRecord(spanValue);
  if (!span) return;

  state.sampledSpans += 1;
  const nodeId = toNonEmptyString(span['nodeId']) ?? 'unknown';
  const nodeType = toNonEmptyString(span['nodeType']) ?? 'unknown';
  const status = toNonEmptyString(span['status']) ?? 'unknown';
  if (status === 'completed') state.completedSpans += 1;
  if (status === 'failed') state.failedSpans += 1;
  if (status === 'cached') state.cachedSpans += 1;

  const aggregateKey = `${nodeId}::${nodeType}`;
  const aggregate = resolveRuntimeTraceNodeAggregate(state, nodeId, nodeType);
  aggregate.spanCount += 1;
  if (status === 'failed') {
    aggregate.failedCount += 1;
  }

  const durationMs = toFiniteDurationMs(span['durationMs'], span['startedAt'], span['finishedAt']);
  if (durationMs !== null) {
    state.durations.push(durationMs);
    aggregate.durationCount += 1;
    aggregate.totalDurationMs += durationMs;
    aggregate.maxDurationMs = Math.max(aggregate.maxDurationMs, durationMs);
    updateRuntimeTraceSlowestSpan(state, run, span, { nodeId, nodeType, status, durationMs });
  }

  state.nodeAggregates.set(aggregateKey, aggregate);
};

const buildTopSlowNodes = (nodeAggregates: Map<string, NodeAggregate>) =>
  Array.from(nodeAggregates.values())
    .filter((aggregate) => aggregate.durationCount > 0)
    .map((aggregate) => ({
      nodeId: aggregate.nodeId,
      nodeType: aggregate.nodeType,
      spanCount: aggregate.spanCount,
      avgDurationMs: Math.round(aggregate.totalDurationMs / aggregate.durationCount),
      maxDurationMs: aggregate.maxDurationMs,
      totalDurationMs: aggregate.totalDurationMs,
    }))
    .sort((left, right) => {
      if (right.totalDurationMs !== left.totalDurationMs) {
        return right.totalDurationMs - left.totalDurationMs;
      }
      return right.maxDurationMs - left.maxDurationMs;
    })
    .slice(0, TRACE_NODE_HIGHLIGHT_LIMIT);

const buildTopFailedNodes = (nodeAggregates: Map<string, NodeAggregate>) =>
  Array.from(nodeAggregates.values())
    .filter((aggregate) => aggregate.failedCount > 0)
    .map((aggregate) => ({
      nodeId: aggregate.nodeId,
      nodeType: aggregate.nodeType,
      failedCount: aggregate.failedCount,
      spanCount: aggregate.spanCount,
    }))
    .sort((left, right) => {
      if (right.failedCount !== left.failedCount) {
        return right.failedCount - left.failedCount;
      }
      return right.spanCount - left.spanCount;
    })
    .slice(0, TRACE_NODE_HIGHLIGHT_LIMIT);

export const summarizeRuntimeTraceAnalytics = (input: {
  runs: AiPathRunRecord[];
  total?: number;
}): AiPathRuntimeTraceAnalytics => {
  const runs = input.runs ?? [];
  const state = createRuntimeTraceSummaryState(runs.length);

  runs.forEach((run: AiPathRunRecord): void => {
    const parity = extractRuntimeTraceKernelParity(run);
    if (parity) {
      mergeRuntimeTraceKernelParity(state, parity);
    }

    const spans = extractRuntimeTraceNodeSpans(run);
    spans.forEach((spanValue: unknown): void => collectRuntimeTraceSpan(state, run, spanValue));
  });

  state.durations.sort((a: number, b: number): number => a - b);
  const avgDurationMs =
    state.durations.length > 0
      ? Math.round(
        state.durations.reduce((sum: number, value: number) => sum + value, 0) /
          state.durations.length
      )
      : null;
  const p95DurationMs =
    state.durations.length > 0
      ? state.durations[
          Math.min(
            state.durations.length - 1,
            Math.max(0, Math.ceil(state.durations.length * 0.95) - 1)
          )
      ]!
      : null;
  const topSlowNodes = buildTopSlowNodes(state.nodeAggregates);
  const topFailedNodes = buildTopFailedNodes(state.nodeAggregates);

  const total = typeof input.total === 'number' ? Math.max(0, input.total) : runs.length;
  const sampledRuns = runs.length;
  state.kernelParity.codeObjectIds = Array.from(state.codeObjectIdSet).slice(0, 25);
  return {
    source: 'db_sample',
    sampledRuns,
    sampledSpans: state.sampledSpans,
    completedSpans: state.completedSpans,
    failedSpans: state.failedSpans,
    cachedSpans: state.cachedSpans,
    avgDurationMs,
    p95DurationMs,
    slowestSpan: state.slowestSpan,
    topSlowNodes,
    topFailedNodes,
    kernelParity: state.kernelParity,
    truncated: total > sampledRuns,
  };
};

export const loadRuntimeTraceAnalytics = async (input: {
  from: Date;
  to: Date;
}): Promise<AiPathRuntimeTraceAnalytics> => {
  try {
    const repo = await getPathRunRepository();
    const result = await withTimeout(
      repo.listRuns({
        statuses: ['completed', 'failed', 'canceled'],
        createdAfter: input.from.toISOString(),
        createdBefore: input.to.toISOString(),
        limit: TRACE_RUN_SAMPLE_LIMIT,
        offset: 0,
        includeTotal: false,
      }),
      SUMMARY_QUERY_TIMEOUT_MS,
      'ai-paths runtime trace analytics query'
    );
    return summarizeRuntimeTraceAnalytics({
      runs: result.runs,
      total: result.total,
    });
  } catch (error) {
    void ErrorSystem.captureException(error);
    void ErrorSystem.logWarning('Failed to load runtime trace analytics sample', {
      service: 'ai-paths-analytics',
      error,
    });
    return emptyTraceAnalytics();
  }
};

export const emptySummary = (
  from: Date,
  to: Date,
  range: AiPathRuntimeAnalyticsRange | 'custom'
): AiPathRuntimeAnalyticsSummary => ({
  from: from.toISOString(),
